        private static void PostRegisterTranslations()
        {
            Debug.Log("Post Register Translations");
            var field1 = typeof(CardManager).GetField("NewCards", BindingFlags.NonPublic | BindingFlags.Static);
            var newCards = field1.GetValue(null) as ObservableCollection<CardInfo>;
            var cards = CachePostRegisterCardData(newCards);

            // BittysChallenges
            Debug.Log("Post Register Translations for BittysChallenges");
            foreach (var value in cards)
            {
                if (!value.HasDisplayedNameEnglish) continue;
                Translate(GUID, null, "Weak " + value.DisplayedNameEnglish, "弱" + value.DisplayedNameLocalized, Language.ChineseSimplified);
            }

            // NevernamedsSigilarium
            Debug.Log("Post Register Translations for NevernamedsSigilarium");
            Dictionary<GemType, string> gemTypesEn = new Dictionary<GemType, string>
            {
                { GemType.Orange, "橙色" },
                { GemType.Blue, "蓝色" },
                { GemType.Green, "绿色" },
            };
            Dictionary<GemType, string> gemTypes = new Dictionary<GemType, string>
            {
                { GemType.Orange, "橙" },
                { GemType.Blue, "蓝" },
                { GemType.Green, "绿" },
            };
            foreach (var value in cards)
            {
                if (!value.HasDisplayedNameEnglish) continue;
                foreach (var gemType in gemTypes.Keys)
                {
                    Translate(GUID, null, "You need two " + HintsHandler.GetColorCodeForGem(gemType) + gemTypesEn[gemType] + " </color> gems to play that " + value.DisplayedNameLocalized, "需二" + HintsHandler.GetColorCodeForGem(gemType) + gemTypes[gemType] + "</color>玉，方能行此" + value.DisplayedNameLocalized, Language.ChineseSimplified);
                }
                Translate(GUID, null, "Your [c:bR]" + value.DisplayedName + "[c:] seems empowered by your sacrifice.", "汝之[c:bR]" + value.DisplayedNameLocalized + "[c:]因牲祀而强。", Language.ChineseSimplified);
                Translate(GUID, null, "Your " + value.DisplayedName + " was empowered!", "汝之" + value.DisplayedNameLocalized + "已强！", Language.ChineseSimplified);
                Translate(GUID, null, "Your [c:bR]" + value.DisplayedName + "[c:] seems bolstered by your sacrifice.", "汝之[c:bR]" + value.DisplayedNameLocalized + "[c:]因牲祀而固。", Language.ChineseSimplified);
                Translate(GUID, null, "Your " + value.DisplayedName + " was bolstered!", "汝之" + value.DisplayedNameLocalized + "已固！", Language.ChineseSimplified);
                Translate(GUID, null, "You don't have enough gems to play that " + value.DisplayedNameLocalized + "!", "玉不足，无以行此" + value.DisplayedNameLocalized + "！", Language.ChineseSimplified);
            }

            // P03InKCM
            Debug.Log("Post Register Translations for P03InKCM");
            foreach (var value in cards)
            {
                if (!value.HasDisplayedNameEnglish) continue;
                string name;
                string nameLoc;
                if (value.DisplayedNameEnglish.ToLowerInvariant().Contains("skel-e"))
                {
                    name = "Skel-E-" + value.DisplayedNameEnglish.Replace(" ", "-");
                    nameLoc = value.DisplayedNameLocalized + "骷髅";
                }
                else
                {
                    name = "Skele " + value.DisplayedNameEnglish;
                    nameLoc = value.DisplayedNameLocalized + "外甲";
                }
                Translate(GUID, null, name, nameLoc, Language.ChineseSimplified);
                for (int score = 0; score <= 10; score++)
                {
                    Translate(GUID, null, value.DisplayedNameEnglish + " " + score.ToString() + ".0", value.DisplayedNameLocalized + " " + score.ToString() + ".0", Language.ChineseSimplified);
                }
            }

            // IGCC
            Debug.Log("Post Register Translations for InGame_Card_Creator");
            foreach (var value in AbilitiesUtil.AllData)
            {
                if (value.SafeIsUnityNull() || value.rulebookName != null)
                {
                    Translate(GUID, null, "sigil of " + value.rulebookName, Localization.Translate(value.rulebookName) + "之印契", Language.ChineseSimplified);
                }
                else
                {
                    Translate(GUID, null, "sigil of " + value.name, Localization.Translate(value.name) + "之印契", Language.ChineseSimplified);
                }
            }
            foreach (var value in cards)
            {
                if (!value.HasDisplayedNameEnglish) continue;
                Translate(GUID, null, "A special [c:bR]Power of " + value.DisplayedNameEnglish + "[c:].", "特殊之[c:bR]" + value.DisplayedNameLocalized + "印技[c:]。", Language.ChineseSimplified);
                Translate(GUID, null, "A portrait of [c:bR]" + value.DisplayedNameEnglish + "[c:].", "[c:bR]" + value.DisplayedNameLocalized + "[c:]之像。", Language.ChineseSimplified);
                if (value.IsBaseGameCard)
                {
                    Translate(GUID, null, "A [c:bR]" + value.DisplayedNameEnglish + "[c:] card.", "[c:bR]" + value.DisplayedNameLocalized + "[c:]之牌。", Language.ChineseSimplified);
                    Translate(GUID, null, "A complexity of [c:bR]" + value.DisplayedNameEnglish + "[c:].", "[c:bR]" + value.DisplayedNameLocalized + "[c:]之繁简。", Language.ChineseSimplified);
                }
                Translate(GUID, null, "An evolution to [c:bR]" + value.DisplayedNameEnglish + "[c:].", "[c:bR]" + value.DisplayedNameLocalized + "[c:]之演化。", Language.ChineseSimplified);
                Translate(GUID, null, "[c:bR]" + value.DisplayedNameEnglish + "[c:]?", "[c:bR]" + value.DisplayedNameLocalized + "[c:]？", Language.ChineseSimplified);
            }
            foreach (CardComplexity value in Enum.GetValues(typeof(CardComplexity)))
            {
                Translate(GUID, null, "A complexity of [c:bR]" + value.ToString() + "[c:].", "[c:bR]" + Localization.Translate(value.ToString()) + "[c:]之繁简。", Language.ChineseSimplified);
            }

            // Lobotomy
            Debug.Log("Post Register Translations for WhistleWind_Lobotomy_Mod");
            foreach (var value in cards)
            {
                if (value.IsBaseGameCard ? !value.HasDisplayedName : !value.HasDisplayedNameEnglish) continue;
                Translate(GUID, null, value.DisplayedName + " in a Bottle", "瓶中" + value.DisplayedNameLocalized, Language.ChineseSimplified);
                string text2 = "A";
                string text2Loc = "手中将得";
                string text3 = "[define:" + value.Name + "]";
                string text3Loc = "[define:" + value.Name + "]";
                if (NameStartsWithVowel(value.DisplayedName))
                {
                    text2 = "An";
                    string text4 = "";
                    string text4Loc = "";
                    foreach (Ability ability in value.Abilities)
                    {
                        text4 = text4 + ", " + AbilitiesUtil.GetInfo(ability).rulebookName;
                        text4Loc = text4Loc + "，" + Localization.Translate(AbilitiesUtil.GetInfo(ability).rulebookName);
                    }
                    text4 += ".";
                    text4Loc += "。";
                    text3 = string.Format("An {0} is defined as: {1} Power, {2} Health", value.DisplayedName, value.Attack, value.Health) + text4;
                    text3Loc = string.Format("{{0}}：威{{1}}，命{{2}}{{3}}。", value.DisplayedName, value.Attack, value.Health) + text4Loc;
                }
                string text5 = string.Concat(new string[] { text2, " ", value.DisplayedName, " is created in your hand. ", text3 });
                string text5LocCardName = value.IsBaseGameCard ? value.DisplayedNameLocalized : value.DisplayedName;
                string text5Loc = string.Concat(new string[] { text2Loc, " ", text5LocCardName, "牌。", text3Loc });
                Translate(GUID, null, text5, text5Loc, Language.ChineseSimplified);
                Translate(GUID, null, "While " + value.DisplayedNameLocalized + " is on the board, remove ally Terrain and Pelt cards and transform the rest into random Apostles.", value.DisplayedNameLocalized + "在场时，去友方地形与裘革，余牌随机化使徒。", Language.ChineseSimplified);
                Translate(GUID, null, "[c:bR]The Clock[c:] and your [c:bR]" + value.DisplayedNameLocalized + "[c:] will remain in that abandoned time.", "[c:bR]时钟[c:]与汝之[c:bR]" + value.DisplayedNameLocalized + "[c:]，将留于弃时之中。", Language.ChineseSimplified);
                Translate(GUID, null, "False " + value.DisplayedNameLocalized, "伪" + value.DisplayedNameLocalized, Language.ChineseSimplified);
                Translate(GUID, null, "[c:bB]That " + value.DisplayedNameLocalized + " costs more energy than you have.[c:]", "[c:bB]能不足，无以行" + value.DisplayedNameLocalized + "。[c:]", Language.ChineseSimplified);
            }
            for (int max = 1; max <= 10; max++)
            {
                Translate(GUID, null, "[c:bB]Do you still not get it? It costs " + max.ToString() + " energy and you don't have enough.[c:]", "[c:bB]汝尚未悟乎？需能" + max.ToString() + "。汝能不足。[c:]", Language.ChineseSimplified);
                for (int count = 0; count < max; count++)
                {
                    Translate(GUID, null, "[c:bB]That costs " + max.ToString() + " energy and you have " + count.ToString() + ".[c:]", "[c:bB]需能" + max.ToString() + "，汝仅有" + count.ToString() + "。[c:]", Language.ChineseSimplified);
                }
            }

            // LifeCostAPI
            Debug.Log("Post Register Translations for LifeCostAPI");
            foreach (var value in cards)
            {
                if (!value.HasDisplayedNameEnglish) continue;
                Translate(GUID, null, "Your [c:bG]Scales[c:] are too tipped to play [c:bG]" + value.DisplayedNameLocalized + "[c:].", "汝之[c:bG]衡[c:]已斜太甚，无以陈[c:bG]" + value.DisplayedNameLocalized + "[c:]。", Language.ChineseSimplified);
                Translate(GUID, null, "[c:bG]" + value.DisplayedNameLocalized + "[c:] requires you to pay in life, in which you can not fullfill without killing yourself.", "陈[c:bG]" + value.DisplayedNameLocalized + "[c:]耗命。不自尽，汝无以陈此牌。", Language.ChineseSimplified);
                Translate(GUID, null, "You would kill yourself if you played [c:bG]" + value.DisplayedNameLocalized + "[c:]. Your [c:bG]Scales[c:] are too tipped", "陈[c:bG]" + value.DisplayedNameLocalized + "[c:]，汝将自戕。汝之[c:bG]衡[c:]已斜太甚。", Language.ChineseSimplified);
                Translate(GUID, null, "Your [c:bG]Scales[c:] are too tipped and you lack the [c:gray]Foils[c:] to play " + value.DisplayedNameLocalized + ".", "汝之[c:bG]衡[c:]已斜太甚，又乏[c:gray]箔[c:]，无以陈" + value.DisplayedNameLocalized + "。", Language.ChineseSimplified);
                Translate(GUID, null, "You lack the foils to play that [c:gray]" + value.DisplayedNameLocalized + "[c:].", "乏箔，无以陈[c:gray]" + value.DisplayedNameLocalized + "[c:]。", Language.ChineseSimplified);
                for (int count = 0; count <= 20; count++)
                {
                    Translate(GUID, null, "[c:gray]" + value.DisplayedNameLocalized + "[c:] requires you pay it's cost in [c:gray]foils[c:], that which you have [c:gray]" + count.ToString() + "[c:].", "[c:gray]" + value.DisplayedNameLocalized + "[c:]之陈需[c:gray]箔[c:]，汝仅有[c:gray]" + count.ToString() + "[c:]箔。", Language.ChineseSimplified);
                    Translate(GUID, null, "That [c:gray]" + value.DisplayedNameLocalized + "[c:] has the cost of [c:gray]" + count.ToString() + "[c:] foils, which you do not have.", "[c:gray]" + value.DisplayedNameLocalized + "[c:]直[c:gray]" + count.ToString() + "[c:]箔，汝乏之。", Language.ChineseSimplified);
                }
            }

            Debug.Log("Post Register Translations Ended");
        }

        private static List<PostRegisterCardData> CachePostRegisterCardData(IEnumerable<CardInfo> newCards)
        {
            var cards = new List<PostRegisterCardData>();
            AddPostRegisterCardData(cards, CardManager.BaseGameCards, true);
            AddPostRegisterCardData(cards, newCards, false);
            return cards;
        }

        private static void AddPostRegisterCardData(List<PostRegisterCardData> cards, IEnumerable<CardInfo> source, bool isBaseGameCard)
        {
            foreach (var card in source)
            {
                if (card.SafeIsUnityNull()) continue;
                cards.Add(new PostRegisterCardData(card, isBaseGameCard));
            }
        }

        private static bool NameStartsWithVowel(string name)
        {
            if (name.Length == 0) return false;
            char c = name.ToLowerInvariant()[0];
            return c == 'a' || c == 'e' || c == 'i' || c == 'o' || c == 'u';
        }

        private sealed class PostRegisterCardData
        {
            public PostRegisterCardData(CardInfo card, bool isBaseGameCard)
            {
                IsBaseGameCard = isBaseGameCard;
                DisplayedNameEnglish = card.DisplayedNameEnglish;
                DisplayedNameLocalized = card.DisplayedNameLocalized;
                DisplayedName = card.displayedName;
                Name = card.name;
                Attack = card.Attack;
                Health = card.Health;
                Abilities = card.Abilities?.ToArray();
            }

            public bool IsBaseGameCard { get; }
            public string DisplayedNameEnglish { get; }
            public string DisplayedNameLocalized { get; }
            public string DisplayedName { get; }
            public string Name { get; }
            public int Attack { get; }
            public int Health { get; }
            public Ability[] Abilities { get; }
            public bool HasDisplayedNameEnglish => DisplayedNameEnglish != null;
            public bool HasDisplayedName => DisplayedName != null;
        }

        private static void FixSimplifiedChineseFonts()
        {
            Debug.Log("Fixing Simplified Chinese Fonts");
            FontReplacement DAGGERSQUAREReplacement =
                Resources.Load<FontReplacement>("data/localization/fontreplacement/DAGGERSQUARE_to_SC-SANS");
            FontReplacement MISC3DReplacement =
                Resources.Load<FontReplacement>("data/localization/fontreplacement/MISC3D_to_SC-SCRIPT");
            if (FontBundle == null)
            {
                string[] foundBundles =
                    Directory.GetFiles(Paths.PluginPath, "chinese_font", SearchOption.AllDirectories);
                if (foundBundles.Length > 0)
                {
                    string bundlePath = foundBundles[0];
                    var bundle = AssetBundle.LoadFromFile(bundlePath);
                    if (bundle == null)
                    {
                        Debug.LogError("字体AssetBundle加载失败！");
                        return;
                    }

                    FontBundle = bundle;
                }
                else
                {
                    Debug.LogError("字体AssetBundle加载失败！");
                    return;
                }
            }

            TMP_FontAsset NotoSans =
                FontBundle.LoadAsset<TMP_FontAsset>("assets/textmesh pro/fonts/notosans_sc sdf.asset");
            TMP_FontAsset NotoSerif =
                FontBundle.LoadAsset<TMP_FontAsset>("assets/textmesh pro/fonts/notoserif_sc sdf.asset");
            SetPrivateTMPFont(DAGGERSQUAREReplacement, NotoSans);
            SetPrivateTMPFont(MISC3DReplacement, NotoSerif);
        }

        private static void SetPrivateTMPFont(FontReplacement replacement, TMP_FontAsset fontAsset)
        {
            if (replacement == null)
            {
                Debug.LogError("FontReplacement为空，无法设置字体！");
                return;
            }

            var type = typeof(FontReplacement);
            var field = type.GetField("replacementTMPFont", BindingFlags.NonPublic | BindingFlags.Instance);
            if (field == null)
            {
                Debug.LogError("找不到replacementTMPFont字段，无法替换字体！");
                return;
            }

            field.SetValue(replacement, fontAsset);
            Debug.Log($"成功替换{replacement.name}的TMP字体为{fontAsset.name}");
        }
    }

