            // 灵感
            AddTranslation("Inspiration", "灵悟");
            // 凝聚了橙蓝绿大师精髓的结晶。
            AddTranslation("A culmination of the great Master Orlu's essence.", "橙蓝大师精粹之会也。");
            // 怒火
            AddTranslation("Rage", "怒");
            // 顽强不屈的绿橙蓝大师的具现化。
            AddTranslation("The embodiement of the tenacious Master Goranj.", "绿橙大师坚忍之形也。");
            // 微积
            AddTranslation("Calculus", "筹算");
            // 勇者蓝绿橙大师的精魂。
            AddTranslation("The spirit of the brave Master Bleene.", "勇者蓝绿大师之魂也。");
            // 火球术
            AddTranslation("Fireball", "火丸");
            // 召唤火球并射向敌人。
            AddTranslation("Conjure up a fireball, and shoot it towards your enemy.", "召火丸而射敌。");
            // 魔药
            AddTranslation("Potion", "药");
            // 召唤一枚火球，射向你的敌人。
            AddTranslation("Conjure up a fireball, and shoot it towards your enemy.", "召火丸而射敌。");
            // 侏儒
            AddTranslation("Gnome", "侏");
            // 乔姆
            AddTranslation("joem", "乔姆");
            // 潜水侏儒
            AddTranslation("Scuba Gnome", "潜侏");
            // 胡伯
            AddTranslation("Huber", "胡伯");
            // 蓝宝石卡包
            AddTranslation("Cardpack sapphire", "蓝玉牌韬");
            // 红宝石卡包
            AddTranslation("Cardpack ruby", "红玉牌韬");
            // 绿宝石卡包
            AddTranslation("Cardpack emerald", "绿玉牌韬");
            // 填充小地图
            AddTranslation("Fill In Minimap", "补小图");

            // Achievement
            // 蔓尼菲科模组成就
            AddTranslation("Magnificus Mod Achievements", "蔓尼菲科补缀功成录");
            // 魔法迷宫
            AddTranslation("Magical Labyrinth", "术迷宫");
            // 击败最终首领
            AddTranslation("Defeat the final boss.", "败终魁。");
            // 水晶头骨
            AddTranslation("Crystal Skull", "晶颅");
            // 在激活所有挑战且无反挑战的情况下完成一轮游戏（可使用地图）
            AddTranslation("Complete a run with every challenge active, and no anti challenges. (You may use the map)", "尽启诸角竞，而无反角竞，以毕一局。（可用图）");
            // 人形黏液
            AddTranslation("Humanoid Slime", "人形胶");
