            AddTranslation("[c:g2]PLEASE, CHALLENGER,[c:] YOU HAVE TO GET ME-", "[c:g2]求子，角者，[c:]子须携吾—");
            // 肃静
            AddTranslation("Hush.", "默。");
            // 嗯？
            AddTranslation("Hmm?", "唔？");
            // 你以为我会修复你的[c:g1]生命画作[c:]？
            AddTranslation("Did you expect me to restore your [c:g1]life painting[c:]?", "子谓吾将复乃[c:g1]命画[c:]乎？");
            // 唔……这里的规则可非如此，挑战者……
            AddTranslation("Hmm.. That's not how it works here, challenger..", "唔……此间之法不尔，角者……");
            // 漂白之痕难以复原
            AddTranslation("Bleach is not easily restorable.", "素痕难复。");
            // 你只能选择一张[c:g3]稀有卡牌[c:]
            AddTranslation("You may only pick a [c:g3]rare card[c:].", "子唯得择一[c:g3]罕有牌[c:]。");
            // 当你投入战斗时，注意到周围浮现出虚幻的符文……
            AddTranslation("As you engage in combat, you notice ethereal runes surrounding you..", "子方角时，见虚符周子……");
            // 这些符文似乎正在对你施加[c:g2]契约[c:]……
            AddTranslation("It seems as though they were placing a [c:g2]pact[c:] on you..", "若将加[c:g2]契[c:]于子……");
            // 你原有的印记在这场战斗中毫无用处
            AddTranslation("Your olden sigils shant be of any use in this battle.", "乃旧印于此战无益。");
            // 当战斗的硝烟散去，神秘的符文在你面前显现。
            AddTranslation("As the smoke of combat clears, the mysterious runes reveal themselves to you.", "战烟既歇，神符乃见于子。");
            // 啊，但这张可引不起符文的兴趣。
            AddTranslation("Ah, but this one does not interest the runes.", "噫，此牌不为群符所嗜。");
            // 印记已被替换，福祸难料。
            AddTranslation("The sigil, replaced, for better or for worse.", "印既易矣，休咎未可知也。");
            // [c:g3]唔…？[c:][c:g1]又来[c:][c:g3]一个[c:][c:g1]学徒？[c:]
            AddTranslation("[c:g3]Hmm..?[c:] [c:g1]Another[c:] [c:g3]student[c:] [c:g1]here?[c:]", "[c:g3]唔……？[c:] [c:g1]又一[c:] [c:g3]学徒[c:] [c:g1]至此乎？[c:]");
            // [c:g3]是[c:][c:g1]来[c:][c:g3]协助[c:][c:g1]我[c:][c:g3]研习[c:][c:g1]的吗？[c:]
            AddTranslation("[c:g3]Have[c:] [c:g1]you[c:] [c:g3]come[c:] [c:g1]to[c:] [c:g3]assist[c:] [c:g1]my[c:] [c:g3]studies?[c:]", "[c:g3]子[c:] [c:g1]来[c:] [c:g3]佐[c:] [c:g1]吾[c:] [c:g3]学[c:] [c:g1]乎？[c:]");
            // [c:g3]唔……[c:][c:g1]是时候[c:][c:g3]再[c:][c:g1]玩些……[c:][c:g3]禁书[c:][c:g1]了[c:]
            AddTranslation("[c:g3]Hmm..[c:] [c:g1]I[c:] [c:g3]think[c:] [c:g1]it's[c:] [c:g3]time[c:] [c:g1]to[c:] [c:g3]play[c:] [c:g1]some[c:] [c:g3]more...[c:]  [c:g2]forbidden[c:] [c:g1]books[c:]", "[c:g3]唔……[c:] [c:g1]时至[c:] [c:g3]更戏[c:] [c:g1]若干……[c:] [c:g2]禁[c:] [c:g1]书矣[c:]");
            // [c:g3]大师[c:][c:g1]的[c:][c:g3]杰作[c:][c:g1]肖像[c:]
            AddTranslation("[c:g3]An[c:] [c:g1]excellent[c:] [c:g3]portrait[c:] [c:g1]by[c:] [c:g3]the[c:] [c:g1]Master.[c:]", "[c:g3]大师[c:] [c:g1]之[c:] [c:g3]善像[c:] [c:g1]也。[c:]");
            // [c:g3]看来[c:][c:g1]你[c:][c:g3]也[c:][c:g1]有[c:][c:g3]自己[c:][c:g1]的[c:][c:g3]猎犬[c:][c:g1]了[c:]
            AddTranslation("[c:g3]Looks[c:] [c:g1]like[c:] [c:g3]you[c:] [c:g1]got[c:] [c:g3]a[c:] [c:g1]hound[c:] [c:g3]of[c:] [c:g1]your[c:] [c:g3]own![c:]", "[c:g3]子[c:] [c:g1]亦有[c:] [c:g3]己[c:] [c:g1]之[c:] [c:g3]犬[c:] [c:g1]矣。[c:]");
            // [c:g3]啊[c:][c:g1]没错，[c:][c:g3]我[c:][c:g1]确实[c:][c:g3]喜欢[c:][c:g1]读[c:][c:g3]好[c:][c:g1]书[c:]
            AddTranslation("[c:g3]Oh[c:] [c:g1]yes,[c:] [c:g3]I[c:] [c:g1]do[c:] [c:g3]love[c:] [c:g1]a[c:] [c:g3]good[c:] [c:g1]book.[c:]", "[c:g3]然[c:] [c:g1]也，[c:] [c:g3]吾[c:] [c:g1]爱[c:] [c:g3]善书[c:] [c:g1]甚矣。[c:]");
            // [c:g3]让[c:][c:g1]我[c:][c:g3]来[c:][c:g1]分享[c:][c:g3]几本[c:][c:g1]我[c:][c:g3]最爱[c:][c:g1]的[c:][c:g3]作品[c:][c:g1]吧[c:]
            AddTranslation("[c:g3]Let[c:] [c:g1]me[c:] [c:g3]share[c:] [c:g1]some[c:] [c:g3]of[c:] [c:g1]my[c:] [c:g3]favourites[c:] [c:g1]with[c:] [c:g3]you.[c:]", "[c:g3]请[c:] [c:g1]使吾[c:] [c:g3]以[c:] [c:g1]所爱[c:] [c:g3]数书[c:] [c:g1]分[c:] [c:g3]诸子[c:] [c:g1]焉。[c:]");
            // ……想象你是一个冰块，在热锅上慢慢融化……
            AddTranslation("Just imagine.. You are an ice cube, slowly melting in a hot pan..", "姑试思之……汝为冰块，徐融于热釜之上……");
            // 这些附魔长矛可不只是摧毁你的卡牌……
            AddTranslation("These enchanted spears won't just damage your cards..", "此诸祝矛，非徒伤乃牌耳……");
            // 哈！用我自己的法术来对付我？
            AddTranslation("Hah! Using one of my own spells against me?", "哈！以吾术反攻吾乎？");
            // 你不觉得这些卡牌有点太强了吗？
            AddTranslation("Don't you think those cards are a little too powerful?", "子不觉此诸牌太强乎？");
            // 这样好多了
            AddTranslation("That's better.", "是为善矣。");
            // [c:g1]你是怎么得到这个的？[c:]
            AddTranslation("[c:g1]How did you get that?[c:]", "[c:g1]子何自得此？[c:]");
            // ……我的[c:g1]黏液法师[c:]到底在哪？
            AddTranslation(".. Where on earth is my [c:g1]Goo Mage[c:]?", "……吾之[c:g1]胶巫[c:]安在哉？");
            // 莫非是你的…模组把他移除了？
            AddTranslation("Have your.. Modifications removed him?", "抑乃……补缀去之乎？");
            // 这般篡改持续太久了。我绝不会再容忍。
            AddTranslation("This tampering has gone on for far too long. I shall not allow it anymore.", "此窜改久矣。吾不容之复然。");
            // 待我们对决时，我绝不会手下留情。
            AddTranslation("When we face off, I won't be holding myself back.", "及与子角，吾必不复自抑。");
            // [c:g1]止步！[c:][c:g2]竟有[c:][c:g1]挑战者[c:][c:g2]胆敢[c:][c:g1]近前？！[c:]
            AddTranslation("[c:g1]Halt![c:] [c:g2]A[c:] [c:g1]challenger[c:] [c:g2]dare[c:] [c:g1]approach?![c:]", "[c:g1]止！[c:] [c:g2]乃有[c:] [c:g1]角者[c:] [c:g2]敢[c:] [c:g1]前乎？！[c:]");
            // [c:g1]可笑，[c:][c:g2]我[c:][c:g1]必将[c:][c:g2]把[c:][c:g1]你[c:][c:g2]剁[c:][c:g1]成[c:][c:g2]肉[c:][c:g1]酱[c:]
            AddTranslation("[c:g1]Quaint,[c:] [c:g2]I[c:] [c:g1]shall[c:] [c:g2]make[c:] [c:g1]mince[c:] [c:g2]meat[c:] [c:g1]out[c:] [c:g2]of[c:] [c:g1]you.[c:]", "[c:g1]可笑，[c:] [c:g2]吾[c:] [c:g1]必[c:] [c:g2]斫[c:] [c:g1]子[c:] [c:g2]为[c:] [c:g1]肉糜[c:]。");
            // [c:g1]恼人的是，[c:][c:g2]你[c:][c:g1]执意如此。[c:][c:g2]你[c:][c:g1]已[c:][c:g2]逼得[c:][c:g1]我[c:][c:g2]必须[c:][c:g1]出剑。[c:]
            AddTranslation("[c:g1]Irritating,[c:] [c:g2]you[c:] [c:g1]persist.[c:] [c:g2]You[c:] [c:g1]have[c:] [c:g2]bound[c:] [c:g1]me[c:] [c:g2]to[c:] [c:g1]excert[c:] [c:g2]my[c:] [c:g1]blade.[c:]", "[c:g1]恼哉，[c:] [c:g2]子[c:] [c:g1]犹执。[c:] [c:g2]子[c:] [c:g1]逼[c:] [c:g2]吾[c:] [c:g1]出剑[c:]。");
            // [c:g1]嗯？[c:][c:g2]某种[c:][c:g1]拙劣地[c:][c:g2]模仿[c:][c:g1]我[c:][c:g2]的[c:][c:g1]东西[c:][c:g2]吗？[c:]
            AddTranslation("[c:g1]Eh?[c:] [c:g2]Some[c:] [c:g1]sort[c:] [c:g2]of[c:] [c:g1]immitation[c:] [c:g2]of[c:] [c:g1]me?[c:]", "[c:g1]噫？[c:] [c:g2]某[c:] [c:g1]肖[c:] [c:g2]吾[c:] [c:g1]之伪物[c:] [c:g2]乎？[c:]");
            // [c:g1]可悲。[c:] [c:g2]我的[c:][c:g1]巨龙[c:][c:g2]可比[c:][c:g1]那个[c:][c:g2]宏伟[c:][c:g1]多了。[c:]
            AddTranslation("c:g1]Pathetic.[c:] [c:g2]My[c:] [c:g1]Drake[c:] [c:g2]was[c:] [c:g1]much[c:] [c:g2]grander[c:] [c:g1]than[c:] [c:g2]that.[c:]", "[c:g1]可悲。[c:] [c:g2]吾[c:] [c:g1]龙[c:] [c:g2]远[c:] [c:g1]伟[c:] [c:g2]于彼[c:]。");
            // 什…什么？挑战者？
            AddTranslation("W-What? A challenger?", "何……何？角者乎？");
            // 终于！！来点刺激的！
            AddTranslation("FINALLY!! STIMULATION!", "终于！！有激矣！");
            // 我还不够兴奋！！
            AddTranslation("I'M STILL NOT STIMULATED ENOUGH!!", "吾犹未足激也！！");
            // 我忍不住想翻卡堆了！
            AddTranslation("I HAVE THE URGE TO SEARCH A CARD PILE!", "吾欲翻牌积矣！");
            // 我已经失去耐心了！ / 我需要更多刺激！！
            AddTranslation("I'M GROWING IMPATIENT!\nI NEED MORE STIMULATION!!", "吾已不耐！\n吾须更多激！！");
            // 哇哦！！我记得调制过这个！
            AddTranslation("WOW!! I REMEMBER BREWING THAT!", "噫！！吾记尝酿此！");
            // 嘿……你一张牌都不剩了？
            AddTranslation("HEY.. YOU DON'T HAVE ANY CARDS LEFT?", "噫……子一牌亦无乎？");
            // 无聊！
            AddTranslation("BORING!", "鄙哉！");
            // 哇！好酷的卡牌！！
            AddTranslation("WOW! COOL CARD!!", "噫！此牌伟哉！！");
            // 谁捡到归谁！
            AddTranslation("FINDERS KEEPERS!", "得者有之！");
            // 恐怕你把我们所有人都祸害了，挑战者……
            AddTranslation("I'm afraid you've doomed us all, challenger..", "角者，恐子已祸我众矣……");
            // 或许我确实是年岁渐长，动作迟缓了……
            AddTranslation("Perhaps I am slowing down with age..", "或吾以年老而迟矣……");
            // 我必须再次动用画笔的力量了。
            AddTranslation("I must use the brush to my advantage yet again.", "吾须复藉笔势。");
            // 你令我刮目相看，确实如此……
            AddTranslation("You have impressed me, you truly have..", "子诚使吾异视之……");
            // 已失两条性命。
            AddTranslation("2 lives down now.", "今已失二命。");
            // 可惜你算漏了，我尚有几招未出。
            AddTranslation("Unfortunately for you, I still have a few tricks up my sleeve.", "惜乎，于子不利；吾犹藏数伎。");
            // 我绝不会让自己这么轻易倒下。
            AddTranslation("I could never allow myself to go down that easily.", "吾必不使己若是易仆。");
            // 愚蠢至极……竟寻求外援？
            AddTranslation("Utter folly.. Getting outside assitance, are we?", "愚甚矣……乃求外助乎？");
            // 自由之足
            AddTranslation("Free Legs", "释足");
            // 解封之躯
            AddTranslation("Unsealed Body", "启躯");
            // 解放之臂
            AddTranslation("Released Arms", "释臂");
            // 解缚的暴君
            AddTranslation("Unleashed Tyrant", "纵暴君");
            // 你以为你在干什么？
            AddTranslation("Just what do you think you're doing?", "子谓己何为哉？");
            // 住手
            AddTranslation("Do not.", "止。");
            // 竟敢耍这种下作把戏
            AddTranslation("Trying to pull a trick as dirty as that..", "乃敢弄此下伎乎……");
            // ……
            AddTranslation("...", "……");
            // 真令人沮丧。我似乎要输了。
            AddTranslation("Upsetting. I seem to be losing.", "可恼。吾似将败。");
            // 不如来条新规则。
            AddTranslation("How about a new rule.", "盍立新律。");
            // 每当[c:g2]你[c:]打出玛珂牌，[c:g2]我[c:]就恢复1点生命。
            AddTranslation("Everytime [c:g2]you[c:] play a mox, [c:g2]I[c:] restore 1 health.", "凡[c:g2]子[c:]陈一玛珂，[c:g2]吾[c:]复一命。");
            // 太糟了。我不得不用最后手段了。
            AddTranslation("Frustrating. I must use my last resort.", "可恼。吾不得不用末策。");
            // [c:g1]我们[c:][c:g2]成[c:][c:g3]了[c:]四个！
            AddTranslation("[c:g1]We[c:] [c:g2]have[c:] [c:g3]become[c:] four!", "[c:g1]吾曹[c:] [c:g2]今[c:] [c:g3]为四矣！[c:]");
            // [c:g2]嗯？[c:][c:g3]一个[c:][c:g2]对手…？[c:]
            AddTranslation("[c:g2]Hmm?[c:] [c:g3]An[c:] [c:g2]opponent..?[c:]", "[c:g2]嗯？[c:] [c:g3]敌[c:] [c:g2]乎？[c:]");
            // [c:g2]我[c:][c:g3]已经[c:][c:g2]有[c:][c:g3]一个[c:][c:g2]世纪[c:][c:g3]没有[c:][c:g2]对决[c:][c:g3]过了！[c:]
            AddTranslation("[c:g2]I[c:] [c:g3]haven't[c:] [c:g2]had[c:] [c:g3]a[c:] [c:g2]duel[c:] [c:g3]in[c:] [c:g2]a[c:] [c:g3]century![c:]", "[c:g2]吾[c:] [c:g3]百年[c:] [c:g2]未[c:] [c:g3]尝[c:] [c:g2]角[c:]矣！[c:]");
            // [c:g2]接[c:][c:g3]招[c:][c:g2]吧！[c:]
            AddTranslation("[c:g2]Have[c:] [c:g3]at[c:] [c:g2]thee![c:]", "[c:g2]来[c:] [c:g3]战[c:] [c:g2]乎！[c:]");
            // [c:g2]真[c:][c:g3]是个[c:][c:g2]难缠[c:][c:g3]的[c:][c:g2]对手！[c:]
            AddTranslation("[c:g2]A[c:] [c:g3]fierce[c:] [c:g2]opponent[c:] [c:g3]you[c:] [c:g2]are![c:]", "[c:g2]子[c:] [c:g3]诚[c:] [c:g2]劲敌[c:]！");
            // [c:g2]看来[c:][c:g3]得[c:][c:g2]用些[c:][c:g3]下三滥[c:][c:g2]的[c:][c:g3]手段[c:][c:g2]才能[c:][c:g3]打败[c:][c:g2]你[c:][c:g3]了！[c:]
            AddTranslation("[c:g2]I'll[c:] [c:g3]just[c:] [c:g2]have[c:] [c:g3]to[c:] [c:g2]use[c:] [c:g3]some[c:] [c:g2]more[c:] [c:g3]dirty[c:] [c:g2]tricks[c:] [c:g3]to[c:] [c:g2]beat[c:] [c:g3]you![c:]", "[c:g2]然则[c:] [c:g3]吾[c:] [c:g2]须[c:] [c:g3]更[c:] [c:g2]以秽术[c:] [c:g3]胜[c:] [c:g2]子[c:]矣！");
            // [c:g2]再[c:][c:g3]来点[c:][c:g2]别的[c:][c:g3]花样[c:][c:g2]也[c:][c:g3]未尝不可[c:]
            AddTranslation("[c:g2]And[c:] [c:g3]something[c:] [c:g2]else,[c:] [c:g3]why[c:] [c:g2]not.[c:]", "[c:g2]更[c:] [c:g3]加[c:] [c:g2]他戏，[c:] [c:g3]亦[c:] [c:g2]无妨[c:]。");
            // [c:g2]噢！[c:][c:g3]多么[c:][c:g2]绝妙的[c:][c:g3]肖像画[c:][c:g2]啊！[c:]
            AddTranslation("[c:g2]Ooh![c:] [c:g3]What[c:] [c:g2]a[c:] [c:g3]great[c:] [c:g2]portrait![c:]", "[c:g2]噫！[c:] [c:g3]美[c:] [c:g2]像[c:]！");
            // [c:g2]这是[c:][c:g3]我[c:][c:g2]忠诚的[c:][c:g3]凤凰[c:][c:g2]的[c:][c:g3]复制品，[c:][c:g2]难道[c:][c:g3]她不[c:][c:g2]美得[c:][c:g3]惊心动魄吗？[c:]
            AddTranslation("[c:g2]A[c:] [c:g3]replica[c:] [c:g2]of[c:] [c:g3]my[c:] [c:g2]loyal[c:] [c:g3]phoenix,[c:] [c:g2]isn't[c:] [c:g3]she[c:] [c:g2]absolutely[c:] [c:g3]stunning?[c:]", "[c:g2]此[c:] [c:g3]乃[c:] [c:g2]吾忠凤之摹[c:]，[c:g3]岂[c:] [c:g2]不绝艳[c:]乎？");
            // [c:g2]我[c:][c:g3]看[c:][c:g2]你[c:][c:g3]打出[c:][c:g2]了[c:][c:g3]不少[c:][c:g2]伤害！[c:]
            AddTranslation("[c:g2]I[c:] [c:g3]see[c:] [c:g2]you've[c:] [c:g3]done[c:] [c:g2]a[c:] [c:g3]fair[c:] [c:g2]bit[c:] [c:g3]of[c:] [c:g2]damage![c:]", "[c:g2]观[c:] [c:g3]子[c:] [c:g2]所致之伤[c:] [c:g3]颇[c:] [c:g2]多[c:]！");
            // [c:g2]不[c:][c:g3]介意[c:][c:g2]我[c:][c:g3]放些[c:][c:g2]小偷[c:][c:g3]吧……[c:]
            AddTranslation("[c:g2]Don't[c:] [c:g3]mind[c:] [c:g2]if[c:] [c:g3]I[c:] [c:g2]just[c:] [c:g3]place[c:] [c:g2]my[c:] [c:g3]thieves..[c:]", "[c:g2]吾[c:] [c:g3]置[c:] [c:g2]吾盗[c:] [c:g3]于此[c:]，[c:g2]可[c:]乎……？");
            // 没牌了……
            AddTranslation("Out of cards..", "牌尽矣……");
            // 真令人失望。我曾对你寄予厚望。
            AddTranslation("Dissapointing. I had high hopes for you.", "可惋。吾尝厚望于子。");
            // 就这点可怜的卡牌……
            AddTranslation("Such a tiny collection of cards..", "牌藏何其寡也……");
            // 我严重怀疑你能赢
            AddTranslation("I highly doubt you will win.", "吾甚疑子能胜。");
            // 在魔法的烈焰中，你终结了战斗。你造成的伤害远超所需。
            AddTranslation("With a blaze of Magick, you end the battle. You managed to deal more damage than needed.", "术焰既炽，战遂终焉。子所致之伤，已过所须。");
            // 溢出的魔法能量将转化为[c:g3]水晶[c:]。你可以在遇到的任何商店中使用它们。
            AddTranslation("The excess Magick you cast turns into [c:g3] Crystals. [c:] You may spend them at any meek store you happen to find.", "溢术化为[c:g3]晶[c:]。后遇小肆，可费之。");
            // 欢迎回来。
            AddTranslation("Welcome back.", "子复来矣。");
            // 许久未见能走到这一步的挑战者了。
            AddTranslation("You're the first in a while to get this far.", "久矣，始见有至此者。");
            // 现在，我将授予你至高无上的荣耀。
            AddTranslation("I will now bestow upon you, the highest honour I can possibly give.", "今吾将授子吾所能授之至荣。");
            // 以画笔将你永恒铭刻，化作一张卡牌。
            AddTranslation("To be painted, and immortalised forever, as a card.", "受画而永存，为一牌。");
            // 假人毫无生气地回瞪着你。
            AddTranslation("The dummy stares lifelessly back at you.", "偶人无生而反视子。");
            // 然后，它突然动了起来！
            AddTranslation("Then, suddenly it springs to motion!", "俄而骤动！");
            // 假人的铰链吱吱嘎嘎地回归原位，恢复了毫无生气的茫然凝视状态。
            AddTranslation("The dummy's hinges creak back into position, and it returns to it's lifeless stare.", "其枢吱然复位，而复无生以视。");
            // 你终于来了……
            AddTranslation("So you finally arrive..", "子终至矣……");
            // 但愿你已经做好充分准备来面对魔法冥刻者了
            AddTranslation("Hopefully you have prepared yourself well enough to face the Scrybe of Magicks.", "愿子已备足以当术之司锲。");
            // 这将是你最终的考验
            AddTranslation("This will be your final exam.", "此乃子终试。");
            // 该我们起舞了
            AddTranslation("Let us dance.", "与子舞。");
            // [c:g2]你[c:]终于现身了
            AddTranslation("[c:g2]You[c:] are finally here.", "[c:g2]子[c:]终至矣。");
            // 希望你明白这次是真正的终局
            AddTranslation("I hope you realise that this is truly it.", "愿子知此真终矣。");
            // 你或许移除了我学生的战斗
            AddTranslation("You may have removed my student's battles,", "子或已削我弟子诸战，");
            // 你或许篡改了我的整个游戏
            AddTranslation("You may have tampered with my entire game..", "或已窜我全戏……");
            // 是时候了
            AddTranslation("It is time.", "时至矣。");
            // 向你问候，挑战者。
            AddTranslation("Greetings, challenger.", "角者，见礼。");
            // 看来你的所有玛珂都被抹除了。
            AddTranslation("It appears that all of your mox has been erased.", "子诸玛珂，似尽见削。");
            // 好奇心害死猫……
            AddTranslation("Curiosity killed the cat..", "好奇取祸……");
            // 真遗憾你这么快就败下阵来……
            AddTranslation("It's a shame you got defeated so early..", "败之甚早，可惜也……");
            // 真遗憾你如此轻易就被击败了。
            AddTranslation("It's a shame you got defeated so easily.", "败之甚易，可惜也。");
            // 真遗憾你在深入之际落败。
            AddTranslation("It's a shame you got defeated so far in.", "既深入而败，可惜也。");
            // 我曾寄予厚望，可你辜负了一切……
            AddTranslation("I had such high hopes, but you lost it all..", "吾尝厚望，而子尽失之……");
            // 看来我的黏液法师技高一筹。真令人失望。
            AddTranslation("It seems my slime mage got the best of you. How dissapointing.", "乃为我胶巫所胜。可惋。");
            // 看来我的长矛法师用战术解决了你……
            AddTranslation("It looks like my pike mage tactically took you out..", "似我矛巫以术败子……");
            // 看来那位孤独的巫师得手了……
            AddTranslation("Looks like that lonely mage got to you..", "似彼孤巫所乘……");
            // 不过无所谓了。
            AddTranslation("Though it does not matter.", "然无足论。");
            // 你对我已无价值。
            AddTranslation("I do not have any more use for you.", "子于我已无所用。");
            // 请自行离开吧。
            AddTranslation("Please, take your leave.", "请去。");
            // 在找什么东西吗？
            AddTranslation("Looking for something?", "有所索乎？");
            // 恐怕你要找的东西已经……[c:g1]转移他处[c:]……
            AddTranslation("I'm afraid the object you seek has been.. [c:g1]relocated[c:]..", "子所索之物，恐已……[c:g1]徙他所[c:]……");
            // 看看你都释放了些什么……
            AddTranslation("Look at what you've unleashed..", "观子所纵者……");
            // 这真的值得寻找吗？
            AddTranslation("Was it truly worth finding?", "求之诚值乎？");
            // 哼……我本没打算让你走到这一步……
            AddTranslation("Hmph.. I did not intend for you to get out here..", "哼……吾本不欲子出至此……");
            // 不过我已预见了。尽管竭力阻拦，你仍执意前行。
            AddTranslation("I have forseen it though. Despite my best attempts you persist.", "然吾已先见之。虽极力阻子，子犹前。");
            // 我们就在此决斗吧……
            AddTranslation("We shall duel here..", "吾曹即此而角……");
            // 但这次，我们加点赌注。
            AddTranslation("Though, lets up the stakes.", "然且益其注。");
            // 若你败北，你的全部[c:g1]生命画作[c:]都将被漂白……
            AddTranslation("If you lose here, your entire [c:g1]life painting[c:] will get bleached..", "子若败于此，则子之全[c:g1]生画[c:]皆将漂……");
            // 若敢应战，便上前来。
            AddTranslation("Step forth if you dare.", "子敢则前。");
            // 你还要继续？
            AddTranslation("You persist again?", "子又来乎？");
            // 原来如此……
            AddTranslation("I see..", "然则……");
            // 我们再来一局！
            AddTranslation("We shall duel again!", "复与子角！");
            // 啊……你终于来了。
            AddTranslation("Ah.. Finally, you arrive.", "噫……子终至矣。");
            // 我在此处俯瞰着你全部的旅程。
            AddTranslation("I've been watching you from up here, for your entire journey.", "吾自上尽观子来涂。");
            // 挑战者，你已跋涉甚远。
            AddTranslation("You've come a long way, challenger.", "角者，子来亦远矣。");
            // 可惜这一切都将在此时终结。
            AddTranslation("Unfortunately, that will all come to an end here.", "惜乎，至此而终。");
            // 最后一战，决定你的命运……
            AddTranslation("One last duel, to decide your fate..", "更一角，以定子命……");
            // 是时候终结你这[c:g1]愚行[c:]了。
            AddTranslation("It is time to put an end to this.. [c:g1]foolery[c:] of yours.", "今当终子此[c:g1]愚戏[c:]。");
            // 若你视这些作弊手段为公平，那我不妨也动用些自己的伎俩。
            AddTranslation("If you consider these cheats fair, then I might as well use some cheats of my own.", "子既以诸诈为公，吾亦可用吾诈。");
            // 按常理我该当场将你除名……不过今日我格外宽容。
            AddTranslation("Normally, I would have you expelled right on the spot.. But I'm feeling generous.", "常则吾当即黜子；今姑宽之。");
            // 开始对决吧。
            AddTranslation("Let us duel.", "其角。");
            // 怎么了？卡住了？
            AddTranslation("Whats the matter? Stumped?", "何如？穷乎？");
            // 在地牢里再找找……你可能漏掉了一些[c:g1]标记[c:]……
            AddTranslation("Try searching around the dungeon.. There may be certain [c:g1]markings[c:] you missed..", "更索诸狱……或有若干[c:g1]记[c:]为子所遗……");
            // 嗯？
            AddTranslation("Hmm?", "唔？");
            // 在好奇这本书的用途吗？
            AddTranslation("Are you wondering what this book is for?", "怪此书何用乎？");
            // 这是你的[c:g1]法术书[c:]，可用它抽取一张[c:g3]法术牌[c:]
            AddTranslation("That is your [c:g1]spell book[c:]. You may use it to draw one of your [c:g3]spell cards[c:].", "此乃子之[c:g1]咒书[c:]。可藉之引一[c:g3]咒牌[c:]。");
            // 但每回合仅限[c:g1]一次[c:]……
            AddTranslation("But only [c:g1]one[c:] per turn..", "然每合惟[c:g1]一[c:]耳……");
            // 你跌入一滩黏稠的黏液，延伸向看似无尽的虚空……
            AddTranslation("You land in a sticky puddle of goo, stretching out into what seems like an endless void..", "子坠于一滩稠胶，延入若无穷之虚……");
            // 断裂的立柱与古老墙壁充斥视野，又被更多黏液吞没……
            AddTranslation("Ruined pillars and ancient walls surround your vision, overtaken by yet more slime..", "断柱古垣环目，而又尽为胶所没……");
            // 头顶闪烁的天穹向你投下耀眼辉光
            AddTranslation("The glistening heavens above shine brightly unto you.", "上有烂然之穹，明辉下烛。");
            // 你抵达了……
            AddTranslation("You arrive in the..", "子至于……");
            // 突如其来的热浪将你包围……
            AddTranslation("A sudden influx of heat surrounds you..", "热浪骤至，周子……");
            // 昏暗肮脏的厅室在视野中无尽延展
            AddTranslation("Dimly lit and dingy chambers spread out as far as you can see.", "昏黯秽室，极目而延。");
            // 远古比斗的回响在厅内萦绕不绝
            AddTranslation("Long forgotten echoes of ancient sparring fill the room.", "古角余响，久湮而满室。");
            // 你发现自己置身于……
            AddTranslation("You find yourself in the..", "子乃在……");
            // 陈腐的尘埃气息涌入鼻腔……
            AddTranslation("A dusty old smell fills your nostrills..", "陈尘之气，满子鼻……");
            // 沉寂的景致中，无数书墙已尘封万古
            AddTranslation("Hundreds of walls containing books, laying untouched for eons, fill the quiet landscape.", "百堵书壁，万古未触，充乎寂景。");
            // 蕴含禁忌知识的缥缈符文将你环绕
            AddTranslation("Ethereal runes, containing lost, forbidden knowledge surround you.", "载亡佚禁知之虚符，环子。");
            // 你苏醒于……
            AddTranslation("You awake in the..", "子寤于……");
            // 嗯。看来又有新学徒被绘入我的画布了。
            AddTranslation("Hmmm. It seems a new student is woven onto my canvas.", "似又有新弟子缀入我画缣。");
            // 若你回头望去，或能看见一间[c:g1]商店[c:]。
            AddTranslation("If you look behind yourself, you may see a [c:g1]shop[c:].", "子若顾后，或见一[c:g1]肆[c:]。");
            // 你可以查看牌组并调整副牌组。
            AddTranslation("You may view your deck and rearange your side deck.", "可观牌列，并易副牌列。");
            // 不过莫要惊慌，冒险途中自会遇到商店。
            AddTranslation("Though, do not be alarmed. You may find a shop later on your adventures.", "然毋惧。后于行中，自可遇肆。");
            // 若你已准备就绪，便可踏入未知之境。
            AddTranslation("If you are ready to proceed, you may step forth and enter into the unknown.", "若已备，可前而入于未知。");
            // 唔……又来了个年轻学徒，
            AddTranslation("Hmm.. A young student appears,", "唔……少弟子又至，");
            // 愚不可及，你的前辈连我的[c:g1]黏液法师[c:]都未能击败。
            AddTranslation("So foolish, your predesscor didn't even manage to get past my [c:g1]Goo Mage[c:].", "愚哉，乃前人尚不能过我[c:g1]胶巫[c:]。");
            // 也罢……或许你能创造此等壮举。
            AddTranslation("Ah well.. Maybe you will manage such a feat.", "然或子能成此举。");
            // 又来一个。
            AddTranslation("Another appears.", "又一人至。");
            // 兴许你能比前人走得更远。
            AddTranslation("Maybe you will manage to get further than those before you.", "或子能逾前人。");
            // 你们这些年轻学徒还有太多要学。
            AddTranslation("You young understudies still have much to learn.", "尔诸少徒，所学尚多。");
            // 啊，我对前任法师寄予厚望，
            AddTranslation("Ah. I had expectations for my previous mage,", "噫，吾尝望我前巫，");
            // 他们甚至击败了我的[c:g2]长矛法师[c:]。
            AddTranslation("They even managed to get past my [c:g2]Pike Mage[c:].", "彼甚至过我[c:g2]矛巫[c:]。");
            // 了不起的壮举，现在该你追随其脚步了……
            AddTranslation("A great feat, it seems now you must follow in their footsteps...", "斯诚壮举，今子宜蹑其迹……");
            // 那么，又一位自荐成为我的学徒之人。
            AddTranslation("So, yet another steps up to be my student.", "然则，又一人进为我弟子。");
            // 你需自行领悟，方能跨越我设下的重重考验。
            AddTranslation("You must learn yourself, to overcome my many obstacles and challenges.", "子当自学，以越我众阻与诸试。");
            // 若你真能成功，我自会赐予你无上荣耀……
            AddTranslation("If you do succeed, I shall bestow upon you a great honour..", "子若竟成，吾必赐子大荣……");
            // 唔…有些不对劲……
            AddTranslation("Hmm.. Something feels off..", "唔……有不协者……");
            // 挑战者，你可是[c:g1]修改了[c:]我的游戏？
            AddTranslation("Have you [c:g1]modded[c:] my game, challenger?", "角者，子其[c:g1]补缀[c:]我戏乎？");
            // 哼！何等无礼！
            AddTranslation("Hmph! How disrespectful!", "哼！无礼甚矣！");
            // 莫非我的游戏还不足以满足你？
            AddTranslation("Was my game not enough for you?", "我戏不足于子邪？");
            // 唉，我也只能听之任之……
            AddTranslation("Alas, I have no choice but to allow it..", "嗟，吾亦不得不听之……");
            // 这是怎么回事…？
            AddTranslation("Just what is going on here..?", "此何为也……？");
            // 这些卡牌，
            AddTranslation("These cards,", "此诸牌，");
            // 那个[c:g2]肮脏的小东西…[c:]闯进来了…？
            AddTranslation("Did that [c:g2]foul little..[c:] get in here..?", "彼[c:g2]秽小物……[c:]入此邪……？");
            // 挑战者，你恐怕来错地方了。
            AddTranslation("I believe you are in the wrong place, challenger.", "角者，子误至矣。");
            // 别动
            AddTranslation("Hold still.", "止。");
            // 指望天平？你可真天真。
            AddTranslation("You are a simpleton for expecting scales.", "望衡，子诚昧也。");
            // 这不过是场看谁先归零的简单竞赛。
            AddTranslation("This is a simple race to 0.", "此直争先归零耳。");
            // 现在该让我施展酿造魔法了！！
            AddTranslation("NOW ITS TIME FOR ME TO PRACTICE MY BREWING MAGICKS!!", "今当吾试吾酿术矣！！");
            // 完成了！！！快去拿吧！！
            AddTranslation("IT IS DONE!!! GO TAKE IT!!", "已成矣！！！往取之！！");
            // 快走！！
            AddTranslation("GO!!", "去！！");
            // [c:g2]给我滚出去！！[c:]
            AddTranslation("[c:g2]GET OUT OF HERE!![c:]", "[c:g2]速出此！！[c:]");
            // 哇哦！看来你往药剂里加的东西让它有点……[c:g1]贵[c:]……
            AddTranslation("WOAH! LOOKS LIKE SOMETHING YOU PUT INTO THE POTION MADE IT A BIT.. [c:g1]PRICY[c:]..", "噫！子所投于药者，似使之稍……[c:g1]贵[c:]……");
            // 什…什么？我终于自由了吗？
            AddTranslation("W-What? Am I finally free?", "何……吾终得释乎？");
            // 从那无尽黑暗中解脱了？
            AddTranslation("A break from that endless darkness?", "脱彼无穷之冥乎？");
            // 算了…不过是调制药水罢了……
            AddTranslation("Nevermind.. It's just potion making..", "已矣……特调药耳……");
            // 噢，你好啊挑战者！！
            AddTranslation("Oh, Hi Challenger!!", "噫，角者！！");
            // 哇，新面孔！！
            AddTranslation("Wow, someone new!!", "噫，新人！！");
            // 给我两张你的卡牌，咱们就能调制药水啦！！
            AddTranslation("Just give me two cards of yours and we'll make a potion out of them!!", "但予我二牌，则可和药矣！！");
            // 之后你可以把药水赋予卡牌，让它们获得些有趣的效果！
            AddTranslation("You can later give this potion to your cards and they gain some silly effects!", "后可以此药授子牌，则彼得若干谲效！");
            // 来吧！！可好玩了！！
            AddTranslation("Come on!! It will be fun!!", "来！！其甚乐！！");
            // 而且超刺激……
            AddTranslation("And stimulating..", "且激哉……");
            // 太刺激了
            AddTranslation("So stimulating", "甚激哉");
            // 嘿你好啊挑战者！！
            AddTranslation("Hello there challenger!!", "嗟，角者！！");
            // 现在你懂流程了吧
            AddTranslation("You know how this works now", "今子知其法矣");
            // 随便给我两张卡就能调制药水！
            AddTranslation("Just give me two cards and we'll make a potion!", "但予我二牌，则可和药！");
            // 哇哦…这是…什么地方？
            AddTranslation("Woah.. What.. Is this place?", "噫……此何地？");
            // 好亮啊……
            AddTranslation("So bright..", "何其明也……");
            // 噢，你好呀！！
            AddTranslation("Oh, Hi there!!", "噫，子来矣！！");
            // 咱们来调制药水吧！！
            AddTranslation("Let's make some potions!!", "其和药！！");
            // 递给我两张卡就完事……
            AddTranslation("Just hand over two cards and we'll be done with it..", "但予我二牌，则可毕矣……");
            // 等等！！你的法术书满了！
            AddTranslation("WAIT!! YOUR SPELLBOOK IS FULL", "止！！子之咒书盈矣！");
            // 先丢弃一个法术，否则你拿不走我们的药水！！
            AddTranslation("GET RID OF ONE OF YOUR SPELLS, OR YOU WONT BE ABLE TO TAKE OUR POTION!!", "先去一咒，不然不得取吾药！！");
            // 你的卡牌消耗已经更改……
            AddTranslation("Your card's cost has been changed..", "子牌之直已易……");
            // 你有对费用不满意的卡牌吗？
            AddTranslation("Do you have a card that has a cost you are unsatisfied with?", "子有不惬其直之牌乎？");
            // 看来没有。
            AddTranslation("No. It appears not.", "无。似无之。");
            // 让我看看……
            AddTranslation("LETS SEE HERE..", "且视之……");
            // 嗯？
            AddTranslation("HMM?", "嗯？");
            // 你觉得呢？
            AddTranslation("WHAT DO YOU THINK?", "子以为如何？");
            // 怎么样？
            AddTranslation("WELL?", "何如？");
            // 大师会怎么想？
            AddTranslation("WHAT WOULD THE MASTER THINK?", "大师将何思？");
            // 大师会为我骄傲吗？
            AddTranslation("WOULD THE MASTER BE PROUD?", "大师将以吾为荣乎？");
            // 这样行吗？
            AddTranslation("IS IT GOOD?", "善乎？");
            // 向挑战者致意！
            AddTranslation("GRREETINGS CHALLENGER!", "角者，见礼！");
            // 你竟已至此？
            AddTranslation("YOU'RE ALREADY HERE?", "子已至此乎？");
            // 我确实不记得与你交战过……
            AddTranslation("I DON'T REALLY RECALL US BATTLING..", "吾实不记与子尝战……");
            // 总之…我该拿哪张牌练习？
            AddTranslation("WELL ANYWAYS.. WHAT CARD WHOULD I PRACTICE ON?", "然则……当习何牌？");
            // 看来你已使我蒙羞！
            AddTranslation("IT WOULD SEEM THAT YOU HAVE DISGRACED ME!", "子已辱我！");
            // 不过无妨，我宽恕你
            AddTranslation("BUT IT IS ALRIGHT, I FORGIVE YOU.", "然无伤，吾恕子。");
            // 听着挑战者，我想练习我的[c:g2]美术[c:]……
            AddTranslation("SAY, CHALLENGER, I WOULD LIKE TO PRACTICE MY [c:g2]ART[c:]..", "角者，吾欲习我[c:g2]画[c:]……");
            // 终有一日我将比肩大师！
            AddTranslation("ONE DAY I MIGHT EVEN BE AS GOOD AS THE MASTER!", "异日吾或可比肩大师！");
            // 你不介意给我张牌对吧？
            AddTranslation("YOU WOULDN'T MIND GIVING ME ONE OF YOUR THERE CARDS, RIGHT?", "子不介予我一牌乎？");
            // 我该练习哪张牌？
            AddTranslation("WHAT CARD SHOULD I PRACTICE ON?", "当习何牌？");
            // 我需要张牌来磨砺技艺
            AddTranslation("I'LL NEED A CARD TO HONE MY SKILLS ON.", "吾须一牌以砺吾技。");
            // 我们素未谋面！
            AddTranslation("I DON'T THINK WE'VE MET BEFORE!", "吾曹未尝相见！");
            // 你本不该此时见我，但……
            AddTranslation("YOU ARENT SUPPOSED TO SEE ME UNTILL LATER, BUT..", "子本不当早见吾，然……");
            // ..看来你已无物可供……
            AddTranslation(".. It appears you have nothing else to offer..", "似子已无他物可供……");
            // 或者根据[c:g1]虚空印记[c:]的指引，献祭它以强化附魔效果
            AddTranslation("Or you can slaughter it to improve the enchantment, dictated by the [c:g1]Ethereal Sigils[c:].", "抑可循[c:g1]虚印契[c:]之指，杀之以益其附。");
            // 选择权在你手中
            AddTranslation("The choice is yours.", "择在子。");
            // [c:g1]虚空印记[c:]在场地周围浮动
            AddTranslation("[c:g1]Ethereal Sigils[c:] hover around the grounds.", "[c:g1]虚印契[c:]浮于地上。");
            // 你可以借此预判可能的结果……
            AddTranslation("You may use them to predict a possible outcome..", "子可藉之先见其果……");
            // [c:g1]献祭之地[c:]矗立眼前。 / 传说在特定条件下，卡牌能在此获得指数级的力量提升……
            AddTranslation("The [c:g1]Sacrifical Grounds[c:] stand before you.\nLegends tell of cards growing exponentially in power here, under the right circumstances..", "[c:g1]祀地[c:]立于子前。\n传曰，牌于其时若宜，则威可倍长于此……");
            // ……但看来你并未携带适合这片附魔之地的祭品
            AddTranslation(".. However, it appears that you don't have anything to offer to the enchanted grounds..", "……然子似无物可供此附地。");
            // 附魔之地似乎略有擢升。
            AddTranslation("The Enchanted Grounds seem to be slightly improved.", "附地似少进矣。");
            // 附魔之地显得不太满意……
            AddTranslation("The Enchanted Grounds are unsatisfied..", "附地未惬……");
            // 附魔之地因献祭能量而微微发亮。
            AddTranslation("The Enchanted Grounds dimly light up with sacrifical energy.", "附地缘祀气而微明。");
            // 附魔之地显得很不悦……
            AddTranslation("The Enchanted Grounds are displeased..", "附地不悦……");
            // 附魔之地因超凡能量而闪耀。
            AddTranslation("The Enchanted Grounds light up with supernatural energy.", "附地缘神异之气而耀。");
            // 附魔之地被激怒了。
            AddTranslation("The Enchanted Grounds are angered..", "附地怒矣……");
            // 附魔之地因献祭能量而剧烈翻腾。
            AddTranslation("The Enchanted Grounds The Enchanted Grounds are absolutely bursting with sacrifical energy.", "附地祀气充溢，几将迸矣。");
            // 附魔之地震怒不已……
            AddTranslation("The Enchanted Grounds The Enchanted Grounds are furious.", "附地震怒不已……");
            // 呃..这地方真恶心……
            AddTranslation("Eurgh.. This place is disgusting..", "呃……此地秽甚……");
            // 看来我被迫要在这儿练习法术了
            AddTranslation("Seems like I'm forced to train spellcasting in here.", "吾似见迫而习咒于此。");
            // 给我一个你的[c:g1]法术[c:]，动作快点
            AddTranslation("Give me a [c:g1]spell[c:] of yours, and make it quick.", "予我子之一[c:g1]咒[c:]，亟之。");
            // 你好……
            AddTranslation("Greetings..", "见礼……");
            // 给我一个你的[c:g1]法术[c:]
            AddTranslation("Give me one of your [c:g1]spells[c:]", "予我子之一[c:g1]咒[c:]");
            // 给我一个你的[c:g1]法术[c:]
            AddTranslation("Give me one of your [c:g1]spells[c:].", "予我子之一[c:g1]咒[c:]。");
            // 哦…你好……我们似乎还没正式认识……
            AddTranslation("Oh.. Greetings... I don't believe we've been introduced..", "噫……见礼……吾曹似未尝正相见……");
            // 我被强制…呃…受邀来这儿练习法术
            AddTranslation("I've been force- er.. asked to train my spellcasting here.", "吾见迫……呃……受命来此习咒。");
            // 不如给我些你的[c:g1]法术[c:]如何？
            AddTranslation("Why don't you give me some of your [c:g1]spells[c:]?", "盍予我若干子之[c:g1]咒[c:]？");
            // 嗯？哦，又见面了…我们还没正式介绍过
            AddTranslation("Hm? Oh, hello again.. We still haven't been formally introduced.", "嗯？噫，又见矣……吾曹犹未正相介也。");
            // 我需要一个你的[c:g1]法术[c:]来训练……
            AddTranslation("I'll need one of your [c:g1]spells[c:] for my training..", "吾须子之一[c:g1]咒[c:]以习之……");
            // 哦…你好啊
            AddTranslation("Oh.. Hello there.", "噫……见礼。");
            // 大师让我来练习法术……
            AddTranslation("The master asked me to practice my spellcasting..", "大师使吾来习咒……");
            // 哦…法术练习。对……
            AddTranslation("Oh.. Spellcasting. Right..", "噫……习咒。然……");
            // 什么？哦…这一定是…[c:g3]他[c:]的地盘……
            AddTranslation("What? Oh.. This must be.. [c:g3]his[c:] area..", "何？噫……此必……[c:g3]彼[c:]之地……");
            // 好吧不管怎样…大师让我来练习法术……
            AddTranslation("Well, anyway.. The master asked me to train my spellcasting.", "然无论何如……大师使吾来习咒。");
            // 唔……？
            AddTranslation("Hmm..?", "唔……？");
            // 这么快？我们还没对战过……
            AddTranslation("Here already? We haven't even battled..", "已至此乎？吾曹犹未尝战……");
            // 总之，交出一个[c:g1]法术[c:]就行……
            AddTranslation("Well anyways, just hand over a [c:g1]spell[c:].", "然则，但出一[c:g1]咒[c:]可也……");
            // 哦…你一个法术都没有吗？
            AddTranslation("Oh.. You don't have any spells?", "噫……子一咒亦无乎？");
            // 也许我可以给你一个强化过的…希望我的这些足够强……
            AddTranslation("I guess I could give you one of my upgraded ones.. Hopefully they're good.", "吾或可予子一吾所益强者……愿其足良……");
            // 现在，你的法术将永世长存……
            AddTranslation("Now your spell will last forever..", "今子之咒将永存……");
            // 所以，你当真要释放那个暴君……
            AddTranslation("So, you truly wish to release that tyrant..", "然则，子诚欲纵彼暴君……");
            // 希望你明白自己正在染指何种力量……
            AddTranslation("I hope you understand the type of power you are dealing with..", "愿子知所干者何等之力……");
            // 唔……该印记的精髓与你的卡牌并不契合……
            AddTranslation("Hmm.. The essence of that sigil does not resonate with your card..", "唔……彼印之精，与子牌不谐……");
            // ……看来一无所获
            AddTranslation("..It appears nothing was gained", "……似无所得。");
            // 印记的精髓使卡牌获得了更多能量
            AddTranslation("The essence of the sigil has imbued the card with more power.", "印之精已益其牌以威。");
            // 印记的精髓使卡牌获得了更多脑瓜
            AddTranslation("The essence of the sigil has imbued the card with more gourd.", "印之精已益其牌以智。");
            // 印记的精髓使卡牌获得了更多力量
            AddTranslation("The essence of the sigil has imbued the card with more strength.", "印之精已益其牌以力。");
            // 哼……我的漂白剂……失效了？
            AddTranslation("Hmph.. My bleach.. failed?", "哼……吾之漂液……失其验乎？");
            // 这是你的手笔吗，挑战者？
            AddTranslation("Was this your doing, challenger?", "此子所为乎，角者？");
            // 哼……
            AddTranslation("Hmph..", "哼……");
            // 选择一张卡牌漂白印记，并灌注等同于已失去印记的力量……
            AddTranslation("Select a card to imbue with a lost sigils strength..", "择一牌，以其所亡之印力灌之……");
            // 在此我将允许你[c:g1]漂白[c:]一张卡牌的某个印记……
            AddTranslation("Here I will allow you to [c:g1]bleach[c:] a card of one of its sigils..", "于此吾将许子[c:g1]漂[c:]一牌之一印……");
            // 被漂白后，该卡牌将继承已失去印记的力量，
            AddTranslation("When bleached, the card will imbue the power of its lost sigil,", "既漂，则其牌受其亡印之力，");
            // 并根据印记的原始强度变得[c:g2]更强[c:]。
            AddTranslation("and get much [c:g2]stronger[c:] depending on the sigils raw strength.", "而因彼印本强，益为[c:g2]强[c:]。");
            // 啊，但你的[c:g1]法术书[c:]已经满了……
            AddTranslation("Ah, but your [c:g1]spell book[c:] is full...", "噫，然子之[c:g1]咒书[c:]已盈……");
            // 你踏入一家小店…漫长旅途中的短暂休憩
            AddTranslation("You step foot into a small store.. A brief respite from your winding travels.", "子履一小肆……曲途之中，少憩耳。");
            // 你踏入一家小店……
            AddTranslation("You step foot into a small store...", "子履一小肆……");
            // 你的[c:g1]牌组[c:]存放在这堆卡牌中……
            AddTranslation("Your [c:g1]deck[c:] is stored in this pile.. ", "子之[c:g1]牌列[c:]藏于此积……");
            // ……而你的[c:g1]副牌组[c:]存放在此，可随时调整
            AddTranslation(".. And your [c:g1]side deck[c:] is stored here, where you can adjust it as you see fit. ", "……而子之[c:g1]副牌列[c:]藏于此，可随意更之。");
            // …哼，看来缘分未到……
            AddTranslation(".. Hmmph, I guess it was not meant to be..", "……哼，盖未当其时也……");
            // 在真菌的扭曲与侵蚀下，一张新卡牌诞生了。唯有经历痛苦，方能成长……
            AddTranslation("Twisted and warped by the fungi, a new card emerges. Only through pain can one grow…", "为菌所扭所蚀，而新牌生焉。惟历苦，乃能长……");
            // 现在蘑菇们需要一张卡牌来寄生…从而提升宿主的属性
            AddTranslation("Now the mushrooms require a card that they will attach.. Increasing the stats of the host.", "今菌须一牌以附……而益宿主之数。");
            // 你遭遇了侵染地牢的异常恶心的真菌
            AddTranslation("You encounter the abnormally disgusting fungi that infests this dungeon.", "子逢染此狱之异秽真菌。");
            // 据说它们具有奇特的性质……
            AddTranslation("It is said to possess strange properties..", "传其性甚奇……");
            // 这些蘑菇渴望找到一张能作为…[c:g1]宿主[c:]的卡牌
            AddTranslation("The mushrooms yearn for a card they can use as a.. [c:g1]host[c:] of sorts.", "此菌渴得一牌，可权为其……[c:g1]宿[c:]者。");
            // 它们将依附其上
            AddTranslation("One that they will attack to.", "菌将附其上。");
            // 你再次遭遇了那些恶心的真菌
            AddTranslation("You encounter the disgusting fungi yet again..", "子复逢彼秽菌……");
            // 真菌渴求着能作为[c:g1]宿主[c:]…来依附的卡牌
            AddTranslation("The fungi yearn for a card they can use as a [c:g1]host[c:].. to attach to.", "菌渴得一牌，可为[c:g1]宿[c:]……以附之。");
            // 然而……你似乎没有两张值得真菌触碰的卡牌。真扫兴
            AddTranslation("Yet... It seems you do not have two cards worthy of the fungi's touch. Wearisome.", "然……子似无二牌堪菌所触。可厌。");
            // 命名权就交给你了
            AddTranslation("You have the honours of naming it.", "名之之荣，归子。");
            // 完成了吗？
            AddTranslation("Finished?", "毕乎？");
            // [c:g1]费用[c:]和[c:g2]肖像[c:]由我来处理
            AddTranslation("The [c:g1]cost[c:] and [c:g2]portrait[c:] I will handle myself..", "[c:g1]直[c:]与[c:g2]像[c:]，吾自为之……");
            // 很高兴认识你，我的学徒
            AddTranslation("It was nice meeting you, my student.", "得识子，吾弟子，亦可乐也。");
            // 但此刻我们该道别了……
            AddTranslation("But this is where we say farewell..", "然今当别矣……");
            // 保持片刻别动
            AddTranslation("Just hold still for a second.", "且少止。");
            // 我会根据你牌组里的卡牌来决定。
            AddTranslation("I will base it off of cards in your deck.", "吾将本于子牌列中诸牌而定之。");
            // 首先，是属性。
            AddTranslation("First, the stats.", "先其数。");
            // 然后是[c:g1]印记[c:]。
            AddTranslation("The [c:g1]sigils[c:].", "次其[c:g1]印契[c:]。");
            // 唔……你的颜料用完了。
            AddTranslation("Hmm.. You're out of paint.", "唔……子之丹尽矣。");
            // 你可以漂白画作……或者就此收笔。
            AddTranslation("You can bleach your drawing.. or consider it finished.", "子可漂其画……抑以为已毕。");
            // 每位学徒的必修课都包含美术训练……
            AddTranslation("A neccesary part of each student's training is art..", "凡弟子之学，画为其常课……");
            // 先从肖像画开始吧……
            AddTranslation("Let's start with the portrait..", "先始于像……");
            // 左侧的漂白剂可用来擦除作品……
            AddTranslation("You can use the bleach on the left to wipe your work..", "左之漂液，可拭子作……");
            // 你正握着[c:g1]仿制画笔[c:]……若需要更细的笔，可取用右侧那支
            AddTranslation("You are currently holding a [c:g1]replica brush[c:].. If you feel you need a smaller one, you can grab the one on the right.", "子今执[c:g1]摹笔[c:]……若欲其细，则取右者。");
            // 用后排那支笔切换颜色
            AddTranslation("Use that brush in the back to change your color.", "以后列之笔易其色。");
            // 学徒们的肖像总能取悦我……
            AddTranslation("My pupil's portraits never fail to amuse me..", "吾弟子之像，恒足娱吾……");
            // 现在选择要为哪张卡的[c:g1]属性[c:]注入魔力
            AddTranslation("Now let's choose which card's [c:g1]stats[c:] to imbue.", "今择何牌之[c:g1]数[c:]以灌之。");
            // 现在，是[c:g1]印记[c:]。
            AddTranslation("Now, the [c:g1]sigils[c:].", "今其[c:g1]印契[c:]。");
            // 啊，但你的法术书已经满了……
            AddTranslation("Ah, but your spell book is full..", "噫，然子之咒书已盈……");
            // 要么丢弃这张……
            AddTranslation("Either discard this one...", "则弃此一……");
            // 要么移除你的一张法术……
            AddTranslation("Or, remove one of your spells..", "抑去子之一咒……");
            // 没有可施加[c:g1]药剂[c:]的卡牌
            AddTranslation("You don't have any cards to use that [c:g1]potion[c:] on.", "子无牌可受此[c:g1]药[c:]。");
            // 你已无卡牌可施法。
            AddTranslation("You won't have any cards to use that spell on.", "子已无牌可施此咒。");
            // 该单位未持有任何魔力。
            AddTranslation("That doesn't have any mana.", "彼无术力。");
            // 你无法从中汲取魔力。
            AddTranslation("You can not draw mana from that.", "子不得自彼汲术力。");
            // 穿越这幅画作与幻象的迷宫，或有存在愿屈尊加入你的牌组 / 认真选吧
            AddTranslation("Through this maze of paintings and illusions, there may be some that deign to join your deck.\nChoose carefully.", "由此画与幻之迷，或有物肯屈而入子牌列。\n审择之。");
            // ……有点意思
            AddTranslation("... Curious.", "……异哉。");
            // 我还以为我已经彻底清除了这…[c:g2]污秽[c:]。
            AddTranslation("I thought I had completely removed this.. [c:g2]filth[c:].", "吾谓已尽去此……[c:g2]秽[c:]矣。");
            // 你倒挺会逗我开心啊，挑战者……
            AddTranslation("You humor me challenger..", "角者，子颇能娱吾……");
            // 你以为区区[c:g1]锤子[c:]能对[c:g1]衔宝蛇[c:]起作用？
            AddTranslation("Did you expect your measely [c:g1]hammer[c:] to work on such a creature as the [c:g1]ouroberyl[c:]?", "子谓区区[c:g1]锤[c:]可加于[c:g1]衔玉蛇[c:]乎？");
            // 何其愚蠢。
            AddTranslation("How foolish.", "愚何甚也。");
            // 你的锤子现已[c:g1]损毁[c:]，本场战斗无法再使用。
            AddTranslation("Your hammer is now [c:g1]broken[c:], and may not be used for the remainder of the battle.", "子之锤今已[c:g1]毁[c:]，此战余时，不得复用。");
            // 看来你输了……
            AddTranslation("It seems that you lost..", "子似已败……");
            // 看到这幅肖像了吗？
            AddTranslation("See this portrait?", "见此像乎？");
            // 这幅肖像将作为你的生命计数器。
            AddTranslation("This portrait will act as your life counter.", "此像将为子命之计。");
            // 当所有[c:g1]玛[c:][c:g2]珂[c:][c:g3]宝[c:][c:g1]石[c:]熄灭时…你就输了。
            AddTranslation("Once all the [c:g1]m[c:][c:g2]o[c:][c:g3]x[c:] [c:g1]g[c:][c:g2]e[c:][c:g3]m[c:][c:g1]s[c:] go out.. You lose the game.", "诸[c:g1]玛[c:][c:g2]珂[c:][c:g3]玉[c:] [c:g1]既[c:] [c:g2]尽[c:] [c:g3]熄[c:]……子则败。");
            // 既然你输了…我得移除一颗宝石。
            AddTranslation("Since you lost.. I will have to remove one gem.", "子既败……吾须去一玉。");
            // 事情已成定局。
            AddTranslation("The deed has been done.", "事已定矣。");
            // 看来你被对手击倒了。
            AddTranslation("Looks like you have been knocked down by your opponent.", "子似为敌所仆。");
            // 挺直腰杆，继续前进。
            AddTranslation("Stand tall, and continue forth.", "正身而前。");
            // 看来你该好好研究下玛珂了。
            AddTranslation("It seems as though you should study up on mox.", "子似当更学玛珂。");
            // 但别绝望，你还有两次机会。
            AddTranslation("Though you should not lose hope, as you still have 2 more lives.", "然毋绝望，子尚有二命。");
            // 你做了最后挣扎却仍失败。看来你又输了。
            AddTranslation("You make a last effort to succeed, yet fail. It seems you lose, again.", "子尽其末力而犹败。似复失矣。");
            // 你应当继续前进。
            AddTranslation("You shall continue forward.", "子当复前。");
            // 再受一击你就会倒下。
            AddTranslation("It takes just one more blow for you to fall to the ground.", "更一击，子即仆地。");
            // 失去一条命后，你必须继续前进。
            AddTranslation("Losing a life, you must continue forward.", "既失一命，子犹须前。");
            // 看来表演该落幕了…暂时如此……
            AddTranslation("It seems the show shall end… for now..", "戏似当终……姑如此耳……");
            // 这到底是怎么回事？
            AddTranslation("Just what is going on here?", "此终何为也？");
            // “至尊大师”……
            AddTranslation("'Master Magnus'..", "“至尊大师”……");
            // 根本[c:g2]没有[c:]这号大师！
            AddTranslation("There is [c:g2]NO[c:] such master!", "本[c:g2]无[c:]此大师！");
            // 呃……若你执意要玩这些把戏，我确实无力阻止。
            AddTranslation("Argh.. I guess, if you truly wish to play with such additions, I am truly unable to stop you.", "呃……子若诚欲戏此等增物，吾实不能止子。");
            // 但我绝不认可这种行为。
            AddTranslation("Though, I do NOT approve of this.", "然吾绝不许之。");
            // 看来那个虚构的至尊大师现身了。
            AddTranslation("It appears that the ficticious Master Magnus has showed itself.", "彼虚妄之至尊大师，似已自见。");
            // 那[c:g1]怪物[c:]正探出它丑陋的脑袋。
            AddTranslation("That horrid [c:g1]thing[c:] rears it's ugly head.", "彼[c:g1]怪物[c:]出其丑首矣。");
            // 解缚的至尊大师正在逼近。
            AddTranslation("The released Master Magnus approaches.", "纵释之至尊大师正前。");
            // 当心，那个可怕的大师来了。
            AddTranslation("Careful. That horrible master is here.", "慎之。彼可畏之大师至矣。");
            // 至尊大师已至，务必小心
            AddTranslation("Master Magnus has arrived. Be cautious.", "至尊大师已至，慎之。");

            // ShowThenClear
            // 认真选吧
            AddTranslation("Choose wisely.", "审择之。");
            // 呃啊！！！
            AddTranslation("ARRGH!!!", "呃啊！！！");
            // [c:g1]攻击！[c:]
            AddTranslation("[c:g1]STRIKE![c:]", "[c:g1]击！[c:]");
            // [c:g2]攻击！[c:]
            AddTranslation("[c:g2]STRIKE![c:]", "[c:g2]击！[c:]");
            // 永别了
            AddTranslation("Au Revoir", "永诀。");
            // 真是鲁莽。
            AddTranslation("How reckless.", "鲁哉。");
            // 唔……我明白了。
            AddTranslation("Hmm.. I see..", "唔……吾知之矣。");
            // 但你[c:g2]永远[c:]无法删除我——魔法冥刻者！
            AddTranslation("But you'll [c:g2]NEVER[c:] delete me, the Scrybe of Magicks!", "然子[c:g2]终不[c:]能削我——术之司锲！");
            // 嘎啊啊啊！！
            AddTranslation("GRRAHH!!", "嘎啊啊啊！！");

            // ShowMessage
            // 咋了
            AddTranslation("whats up", "何哉");
            // 我的[c:g1]黏液法师[c:]败于你手……我本对他期望更高些……
            AddTranslation("My [c:g1]Goo Mage[c:] falls by your hands.. I expected more from him..", "我[c:g1]胶巫[c:]败于子手……吾本望之更厚……");
            // 哼……我的[c:g1]黏液法师[c:]又一次让我失望……
            AddTranslation("Hmph.. My [c:g1]Goo Mage[c:] dissapoints me again..", "哼……我[c:g1]胶巫[c:]复令吾失望……");
            // 再一次，我可怜的[c:g1]黏液法师[c:]倒下了……
            AddTranslation("Yet again, my pathetic [c:g1]Goo Mage[c:] falls..", "复矣，我可悯之[c:g1]胶巫[c:]又仆……");
            // [c:g1]什么……？[c:][c:g2]我，[c:][c:g1]败了……？[c:]
            AddTranslation("[c:g1]What..?[c:] [c:g2]Me,[c:] [c:g1]defeated..?[c:]", "[c:g1]何……？[c:][c:g2]吾，[c:][c:g1]败矣……？[c:]");
            // [c:g1]呃啊……[c:][c:g2]我[c:][c:g1]被[c:][c:g2]你[c:][c:g1]击败了？？[c:]
            AddTranslation("[c:g1]Blargh..[c:] [c:g2]I've[c:] [c:g1]been[c:] [c:g2]taken[c:] [c:g1]out[c:] [c:g2]by[c:] [c:g1]you??[c:] ", "[c:g1]呃啊……[c:][c:g2]吾[c:][c:g1]竟[c:][c:g2]为[c:][c:g1]子[c:][c:g2]所败[c:]？？");
            // [c:g1]不可能……[c:][c:g2]我[c:][c:g1]居然[c:][c:g2]输了……[c:]
            AddTranslation("[c:g1]Impossible..[c:] [c:g2]I've[c:] [c:g1]been[c:] [c:g2]defeated..[c:]", "[c:g1]不可……[c:][c:g2]吾[c:][c:g1]竟[c:][c:g2]败矣……[c:]");
            // 啊……看来你打败了我的[c:g2]长矛法师[c:]……
            AddTranslation("Ahh.. I see you've defeated my [c:g2]Pike Mage[c:]..", "噫……子已败我[c:g2]矛巫[c:]矣……");
            // 我的[c:g2]长矛法师[c:]倒下了……真令人失望
            AddTranslation("My [c:g2]Pike Mage[c:] falls.. Dissapointing.", "我[c:g2]矛巫[c:]既仆……可惋。");
            // 我承认挑战者……你比大多数人都走得更远
            AddTranslation("I'll admit challenger.. You've gotten farther than most.", "角者，吾认之……子逾众人远矣。");
            // [c:g2]真是[c:][c:g3]一场[c:][c:g2]精彩[c:][c:g3]对决[c:][c:g2]啊！[c:]
            AddTranslation("[c:g2]A[c:] [c:g3]fantastic[c:] [c:g2]duel[c:] [c:g3]we[c:] [c:g2]had![c:]", "[c:g2]此[c:] [c:g3]诚[c:] [c:g2]妙[c:] [c:g3]角[c:] [c:g2]也！[c:]");
            // [c:g2]这[c:][c:g3]是[c:][c:g2]场[c:][c:g3]绝妙[c:][c:g2]战斗[c:]
            AddTranslation("[c:g2]'Twas[c:] [c:g3]an[c:] [c:g2]excellent[c:] [c:g3]battle.[c:]", "[c:g2]此[c:] [c:g3]诚[c:] [c:g2]善战[c:]。");
            // [c:g2]打[c:][c:g3]得[c:][c:g2]漂亮[c:][c:g3]年轻法师[c:]
            AddTranslation("[c:g2]Great[c:] [c:g3]fighting,[c:] [c:g2]young[c:] [c:g3]mage.[c:]", "[c:g2]战[c:] [c:g3]善矣，[c:] [c:g2]少巫[c:]。");
            // 很好挑战者……既然你已击败[c:g3]孤独巫师[c:]，现在可以面对我了
            AddTranslation("Well challenger.. Now that you have defeated the [c:g3]Lonely Mage[c:]. You may now face me.", "然矣，角者……子既败[c:g3]孤巫[c:]，今可当吾。");
            // 你已击败我所有学徒……我将恭候你的到来
            AddTranslation("You've defeated all my students.. I will await your arrival.", "子已败我诸弟子……吾将待子之至。");
            // 我的[c:g3]孤独巫师[c:]败北了……出乎意料……但现在，我静候你的到来
            AddTranslation("My [c:g3]Lonely Mage[c:] falls.. this is unexpected.. But now, I await your arrival.", "我[c:g3]孤巫[c:]既败……此出吾料外……然今吾待子来。");
            // [c:g3]真是[c:][c:g1]场[c:][c:g3]精彩[c:][c:g1]较量！[c:]
            AddTranslation("[c:g3]An[c:] [c:g1]excellent[c:] [c:g3]fight![c:]", "[c:g3]善[c:] [c:g1]角[c:]！");
            // [c:g3]即便[c:][c:g1]动用[c:][c:g3]最致命的[c:][c:g1]典籍，[c:][c:g3]你仍[c:][c:g1]获胜了！[c:]
            AddTranslation("[c:g3]Despite[c:] [c:g1]my[c:] [c:g3]deadliest[c:] [c:g1]books,[c:] [c:g3]you[c:] [c:g1]still[c:] [c:g3]won![c:]", "[c:g3]虽[c:] [c:g1]吾[c:] [c:g3]尽用[c:] [c:g1]最毒之书，[c:] [c:g3]子[c:] [c:g1]犹胜[c:]！");
            // [c:g3]你竟[c:][c:g1]能[c:][c:g3]破解[c:][c:g1]我最[c:][c:g3]致命的[c:][c:g1]魔典，[c:][c:g3]令人[c:][c:g1]印象深刻！[c:]
            AddTranslation("[c:g3]You[c:] [c:g1]managed[c:] [c:g3]to[c:] [c:g1]overcome[c:] [c:g3]my[c:] [c:g1]deadliest[c:] [c:g3]tomes,[c:] [c:g1]impressive![c:]", "[c:g3]子[c:] [c:g1]竟能[c:] [c:g3]胜[c:] [c:g1]吾最毒之典，[c:] [c:g3]异哉！[c:]");
            // [c:g3]哎哟！[c:][c:g1]看来[c:][c:g3]你[c:][c:g1]得[c:][c:g3]好好[c:][c:g1]钻研[c:][c:g3]玛珂[c:][c:g1]了[c:]
            AddTranslation("[c:g3]Whoops![c:] [c:g1]Looks[c:] [c:g3]you[c:] [c:g1]need[c:] [c:g3]to[c:] [c:g1]study[c:] [c:g3]up[c:] [c:g1]on[c:] [c:g3]mox.[c:]", "[c:g3]噫！[c:] [c:g1]子[c:] [c:g3]尚须[c:] [c:g1]深学[c:] [c:g3]玛珂[c:]。");
            // 我的长矛法师又击败了一个对手……
            AddTranslation("My Pike Mage bests another opponent...", "我矛巫复胜一敌……");
            // 太令人失望了……
            AddTranslation("Dissapointing...", "可惋……");
            // [c:g1]又[c:][c:g2]一个[c:][c:g1]灵魂[c:][c:g2]归[c:][c:g1]我[c:][c:g2]所有[c:][c:g1]了。[c:][c:g2]滚[c:][c:g1]去[c:][c:g2]深渊[c:][c:g1]吧，[c:][c:g2]永远[c:][c:g1]别[c:][c:g2]回来[c:]
            AddTranslation("[c:g1]Yet[c:] [c:g2]another[c:] [c:g1]soul[c:] [c:g2]I[c:] [c:g1]claim.[c:] [c:g2]Banish[c:] [c:g1]yourself[c:] [c:g2]to[c:] [c:g1]the[c:] [c:g2]depths,[c:] [c:g1]and[c:] [c:g2]do[c:] [c:g1]not[c:] [c:g2]return.[c:]", "[c:g1]又[c:] [c:g2]一[c:] [c:g1]魂[c:] [c:g2]归[c:] [c:g1]吾[c:]矣。[c:] [c:g2]自逐[c:] [c:g1]于深渊[c:]，[c:g2]毋[c:] [c:g1]复来[c:]。");
            // 又一位学徒，被我的孤独巫师偷袭得手……
            AddTranslation("Yet another student, hit off guard by my Lonely Mage..", "又一弟子，为我孤巫所乘……");
            // 你都走到这一步了……
            AddTranslation("You got so far.....", "子已行至此……");
            // 真弱。
            AddTranslation("Weak.", "弱哉。");
            // [c:g2]再会了，[c:][c:g3]年轻的[c:][c:g2]法师！[c:][c:g3]真是[c:][c:g2]一场[c:][c:g3]精彩[c:][c:g2]对决。[c:]
            AddTranslation("[c:g2]Farewell,[c:] [c:g3]young[c:] [c:g2]mage![c:] [c:g3]'Twas[c:] [c:g2]a[c:] [c:g3]fantastic[c:] [c:g2]duel.[c:]", "[c:g2]别矣，[c:] [c:g3]少巫[c:]！[c:g2]此[c:] [c:g3]诚[c:] [c:g2]妙角[c:]。");
            // ~ 黏液地牢 ~
            AddTranslation("~ Goo Dungeon ~", "~ 胶狱 ~");
            // ~ 熔岩地牢 ~
            AddTranslation("~ Lava Dungeon ~", "~ 熔狱 ~");
            // ~ 虚空地牢 ~
            AddTranslation("~ Void Dungeon ~", "~ 虚狱 ~");
            // ~ 魔法之塔 ~
            AddTranslation("~ Tower of Magicks ~", "~ 术塔 ~");

            // Challenge
            // 空白玛珂
            AddTranslation("Blank Mox", "虚玛珂");
            // 你的副牌组玛珂效果完全随机
            AddTranslation("Your sidedeck's mox is completely random.", "子副牌列之玛珂，皆偶然也。");
            // 弱漂白剂
            AddTranslation("Weaker Bleach", "弱漂液");
            // 漂白事件将不再能移除负面印记
            AddTranslation("The Bleaching Event can no longer remove negative sigils.", "漂事不复能去负印。");
            // 回合崩盘
            AddTranslation("Turn Wipeout", "合崩");
            // 若在第6回合后（首领战为第12回合）敲换手铃，你将受到1点伤害
            AddTranslation("When you ring the bell past turn 6 (12 on bosses) you take 1 damage.", "六合后（魁战则十二合）鸣铃，则子受一伤。");
            // 更强对手
            AddTranslation("Stronger Opponent", "强敌");
            // 对战对手初始额外获得5点生命值
            AddTranslation("Your battle opponent starts with 5 extra health points.", "战敌始得外加五命。");
            // 微型法术书
            AddTranslation("Tiny Spellbook", "小咒书");
            // 你的法术书只能容纳4个法术，而非8个
            AddTranslation("Your spellbook can only hold 4 spells instead of 8.", "子之咒书惟容四咒，不及八。");
            // 怨灵缠身
            AddTranslation("Displeased Spirits", "怨灵缠身");
            // 这片被诅咒的土地永远充满怨念
            AddTranslation("The enchanted grounds will always be displeased.", "此附地常不悦。");
            // 坚甲之壳
            AddTranslation("Armored Shell", "坚甲");
            // 每回合敌方最多承受4点伤害
            AddTranslation("Your opponent cant take more than 4 damage per turn.", "每合敌所受伤不过四。");
            // 铁处女
            AddTranslation("Iron Maiden", "铁闺");
            // 每回合开始时，持牌人侧牌桌上的每张玛珂牌会受到1点伤害
            AddTranslation("Every turn, each mox on your side of the board takes 1 damage.", "每合，子侧局上诸玛珂各受一伤。");
            // 魔法涂料
            AddTranslation("Magickal Paint", "术丹");
            // 待出卡牌偶尔会被额外绘制上印记
            AddTranslation("Queued cards will occasionally get additional sigils painted on them.", "待陈之牌，间见加绘其印。");
            // 转瞬生命
            AddTranslation("Fleeting Life", "浮命");
            // 初始生命值为75，但战斗间不会恢复
            AddTranslation("You have 75 health, but it does not replenish inbetween battles.", "子始有七十五命，然战间不复。");
            // 侵扰之影
            AddTranslation("Intrusive Presence", "侵影");
            // 不受欢迎的存在将跟随你进入卡牌对战
            AddTranslation("An unwelcome prescence will follow you into card battles.", "不速之在，将从子入牌战。");
            // 大师头目
            AddTranslation("Master Bosses", "大师诸魁");
            // 所有头目战都会替换为玛珂大师之一
            AddTranslation("Every bossfight is replaced with one of the Mox Masters.", "诸魁战皆易为诸玛珂大师之一。");
            // 宝石依赖的开局
            AddTranslation("Gem Dependant Starters", "依玉初牌");
            // 起始手牌中的卡牌均带有宝石依赖印记
            AddTranslation("Cards in your starting deck have the gem dependant sigil.", "子初牌列诸牌皆负依玉之印。");
            // 蔓尼菲科挑战关卡：{0}
            AddTranslation("Magnificus Challenge Level: {0}", "蔓尼菲科角竞阶：{0}");
            // 蔓尼菲科挑战点数：{0}
            AddTranslation("Magnificus Challenge Points: {0}", "蔓尼菲科角竞点：{0}");
        }

    }

    public class UndeadTempleINKCMMod
    {
        public static void RegisterTranslations()
        {
            // Card
            // 觉醒的女妖
            AddTranslation("Awakened Banshee", "觉女妖");
            // 一堆骨头，用骨头换取力量。
            AddTranslation("A pile of bones, paying for bones in exchange for strength.", "堆骨也，费骨以易威。");
            // 觉醒的骨堆
            AddTranslation("Awakened Bone Heap", "觉积骨");
            // 觉醒的寻骨猎犬
            AddTranslation("Awakened Bonehound", "觉寻骨犬");
            // 即使死了，它仍然忠诚。
            AddTranslation("Even after being dead, it remains loyal.", "虽死，犹忠。");
            // 觉醒的死人手
            AddTranslation("Awakened Dead Hand", "觉死手");
            // 死亡之手，却于苍生长存。
            AddTranslation("The hand of death, but with life.", "死之手，而犹有生。");
            // 觉醒的尸鬼
            AddTranslation("Awakened Draugr", "觉尸鬼");
            // 冰封的恶魔，出来吧。
            AddTranslation("Frozen ghouls, break and come out.", "冰鬼破而出。");
            // 觉醒的淹死鬼
            AddTranslation("Awakened DrownedSoul", "觉溺魂");
            // 溺水的灵魂带着怨恨在水中游荡。
            AddTranslation("The drowned soul wanders with resentment in the water.", "溺魂怀怨，而游于水。");
            // 觉醒的行师走人
            AddTranslation("Awakened Family", "觉行尸");
            // 意外死亡的家庭。
            AddTranslation("A family that died unexpectedly.", "横死之一家。");
            // 科学怪人。
            AddTranslation("Frankenstein.", "科学怪人。");
            // 产生源源不断的骷髅的幽灵船。
            AddTranslation("A ghost ship that produces a steady stream of skeletons.", "鬼舟绵生枯骨。");
            // 觉醒的幽灵船
            AddTranslation("Awakened Ghost Ship", "觉鬼舟");
            // 觉醒的弗兰肯和斯坦
            AddTranslation("Awakened Frank & Stein", "觉弗兰克与斯坦");
            // 觉醒的掘墓人
            AddTranslation("Awakened Gravedigger", "觉掘冢者");
            // 作为一个勤劳的掘墓人，他不断地提供骨头。
            AddTranslation("A diligent gravedigger, he constantly supplies bones.", "掘冢勤者，恒给以骨。");
            // 死亡骑士，地狱中的刺客。
            AddTranslation("Death Knight, the assassin in hell.", "死骑，狱中之刺者。");
            // 觉醒骑士
            AddTranslation("Awakened Knight", "觉骑士");
            // 觉醒的号角
            AddTranslation("Awakened Horn", "觉号");
            // 骨王摆脱了它的旧角，开始了自己的魔生，有朝一日将篡夺其主。
            AddTranslation("the bonelord sheds its old horns, they take on a life of their own, to one day usurp their masters.", "骨王脱其旧角，角乃自生，终将夺其主。");
            // 木乃伊之神
            AddTranslation("Mummy God", "木乃伊神");
            // 此乃恐怖之王。
            AddTranslation("The King of Terror.", "恐之王也。");
            // 觉醒的死灵法师
            AddTranslation("Awakened Necromancer", "觉死灵巫");
            // 生来就是为了复仇。
            AddTranslation("Born solely for revenge.", "生唯为雠。");
            // 觉醒的复生亡灵
            AddTranslation("Awakened Revenant", "觉逆生魂");
            // 一个可怕的石棺，里面封印着恶魔。
            AddTranslation("A formidable sarcophagus with terrifying creations sealed inside.", "可畏之石椁，内缄恶魅。");
            // 一堆骨头
            AddTranslation("Bone Pile", "堆骨");
            // 觉醒的一堆骨头
            AddTranslation("Awakened Bone Pile", "觉堆骨");
            // 觉醒的盗墓贼
            AddTranslation("Awakened Tomb Robber", "觉盗冢者");
            // 即使死了，仍然盗墓。
            AddTranslation("Even if he dies, he still robs tombs.", "虽死，犹盗冢。");
            // 一个绝望之人
            AddTranslation("A desperate man.", "绝望之人。");
            // 觉醒的丧尸
            AddTranslation("Awakened Zombie", "觉僵尸");
            // 噬魂亡灵
            AddTranslation("Devouring Soul", "噬魂");
            // 一个噬魂的骷髅。
            AddTranslation("A skeleton devouring the soul.", "噬魂之枯骨也。");
            // 觉醒的噬魂亡灵
            AddTranslation("Awakened Devouring Soul", "觉噬魂");
            // 觉醒的死人眼
            AddTranslation("Awakened Dead Eye", "觉死目");
            // 与死人手一同，犹如某个神的一部分身体。
            AddTranslation("Both Deadeye and Dead Hand are said to be body parts of the same, now dead, god.", "死目与死手，并为一已亡之神之体。");
            // 渡灵骨鸦
            AddTranslation("Ferry Crow", "渡灵鸦");
            // 觉醒的渡灵骨鸦
            AddTranslation("Awakened Ferry Crow", "觉渡灵鸦");
            // 死亡的灵鸦，俯视众生的哀嚎
            AddTranslation("The mournful cry of looking down upon the undead after death.", "死鸦下瞰亡者而哀号。");
            // 墓碑
            AddTranslation("Grave", "墓");
            // 我希望不会有人来打扰它
            AddTranslation("I hope no one will disturb it.", "愿无人扰之。");
            // 无头人
            AddTranslation("Headless Man", "无首人");
            // 一个不称职的无头人，好像在寻找他丢失的东西。
            AddTranslation("An incompetent headless person, as if searching for something he had lost.", "无首而拙者，若索其所失。");
            // 觉醒的犬舍
            AddTranslation("Awakened Kennel", "觉犬舍");
            // 一个犬舍，希望没人会打扰里面的东西。
            AddTranslation("A dog house, hopefully no one will mess with the things inside.", "犬舍也，愿无人扰其中物。");
            // 药剂师
            AddTranslation("Pharmacist", "药师");
            // 觉醒的药剂师
            AddTranslation("Awakened Pharmacist", "觉药师");
            // 一个死去的药剂师，他将毒死所有反对他的造物。
            AddTranslation("A dead pharmacist who poisons all creations that oppose him.", "死药师也，凡逆己之物，尽毒之。");


            // Ability / Pack
            // 亡灵领袖
            AddTranslation("Skeleader", "骨魁");
            // 亡灵领袖一旦上场，便会被骷髅包围。
            AddTranslation("A skeleton leader, once on stage, is surrounded by skeletons.", "骨魁一陈，即为枯骨所环。");
            // 觉醒的亡灵领袖
            AddTranslation("Awakened Skeleader", "觉骨魁");
            // 骷髅狙击手
            AddTranslation("Skeleton Sniper", "枯骨狙者");
            // 一位死去的狙击手。
            AddTranslation("A dead sniper.", "死狙者也。");
            // 觉醒的骷髅狙击手
            AddTranslation("Awakened Skeleton Sniper", "觉枯骨狙者");
            // 欺诈者
            AddTranslation("Threaded Skeleton", "悬丝骨");
            // 有些人生来就是傀儡，有些人死后仍掌控他人。
            AddTranslation("Some people are born puppets, while others still control others after death.", "或生而为傀，或死而犹制人。");
            // 觉醒的欺诈者
            AddTranslation("Awakened Threaded Skeleton", "觉悬丝骨");
            // 不死麋鹿
            AddTranslation("Undead Elk", "尸麋");
            // 不死麋鹿，生前的躯壳。
            AddTranslation("The undead elk, a former husk of of what it once was.", "尸麋者，其故壳耳。");
            // 不死小麋鹿
            AddTranslation("Undead Elk Cub", "尸麋仔");
            // 甚至死后也带着活力和欲望。
            AddTranslation("Even death carries vitality and desire.", "虽死，犹挟生气与欲。");
            // 不死驼鹿
            AddTranslation("Undead Moose", "尸驼鹿");
            // 一具久已逝去的雄伟野兽腐烂的尸体。
            AddTranslation("A rotting carcass of a long-departed imposing beast.", "雄兽久逝之腐骸也。");
            // 觉醒的不死驼鹿
            AddTranslation("Awakened Undead Moose", "觉尸驼鹿");
            // 劫掠亡灵
            AddTranslation("Undead Predator", "亡猎者");
            // 在战争中牺牲的战士永远不会屈服。
            AddTranslation("Warriors who die in war will never bow down.", "战而死之士，永不屈。");
            // 觉醒的劫掠亡灵
            AddTranslation("Awakened Undead Predator", "觉亡猎者");
            // 不死红鹿
            AddTranslation("Undead RedHart", "尸红鹿");
            // 它腐朽的心灵保留着牺牲的力量。
            AddTranslation("its decaying mind retains the strength of sacrifice.", "其腐心犹存祀力。");
            // 觉醒的不死红鹿
            AddTranslation("Awakened Undead RedHart", "觉尸红鹿");
            // 鳄龟残骸
            AddTranslation("Undead Snapper", "鳄龟骸");
            // 觉醒的鳄龟残骸
            AddTranslation("Awakened Undead Snapper", "觉鳄龟骸");
            // 僵硬的陆地造物的尸体。
            AddTranslation("The corpse of a stiff terrestrial creation.", "陆生之物僵骸也。");
            // 亡灵领袖
            AddTranslation("Skeleader", "骨魁");
            // 当放置[creature]时，骷髅牌将出现在相邻的空位。骷髅有：1力量，1生命，脆骨。
            AddTranslation("When placing [creature], skeleton cards will appear in nearby empty spaces. Skeleton has: 1 power, 1 health, Brittle.", "[creature]既陈，相邻空处皆生枯骨牌。枯骨者：1威、1命、脆骨。");
            // 原版亡灵族群卡牌
            AddTranslation("Original Undead Card", "原版亡族牌");
            // 原版第二幕中的亡灵族群卡包。
            AddTranslation("The cards for the Undead Tribe are in the original game.(ACT2)", "原戏第二幕之亡族牌包。");
            // 非原版亡灵族群卡包
            AddTranslation("NonOriginal Undead Card", "补缀亡族牌包");
            // 由模组作者原创的非原版亡灵族群卡包。
            AddTranslation("The expansion cards for the Undead Tribe are not in the original game.", "亡族增牌，非原戏所有。");
        }

    }

    public class WildernessLegendMod
    {
        public static void RegisterTranslations()
        {
            // Card
            // 缝合兽幼崽
            AddTranslation("Amalgam Pup", "缝兽仔");
            // 当其长大之后，你便能知晓其可怕之处。
            AddTranslation("When you grow up, you can see that it is terrible.", "及其长，乃知其可畏。");
            // 鸡
            AddTranslation("Chicken", "鸡");
            // 废物蛋
            AddTranslation("Dud Egg", "废卵");
            // 一颗无法成长的蛋？你能帮帮它吗？
            AddTranslation("An egg that doesn't grow? Maybe you can help it.", "卵而不长，汝其能相之乎？");
            // 有趣的鸡
            AddTranslation("Funny chiking", "谐鸡");
            // 一只很臭的鸡，但它有着锋利的喙。
            AddTranslation("A very stinky chicken, but it has a sharp beak.", "此鸡甚臭，然其喙甚利。");
            // 大鹏
            AddTranslation("Roc", "鹏");
            // 臭鸡丁
            AddTranslation("Stinky Chiking", "臭鸡");
            // 每一只小鸡都有梦想。
            AddTranslation("Every chicken has a dream.", "凡鸡皆有其愿。");
            // 神烦狗
            AddTranslation("Annoying Dog", "烦犬");
            // 这样一只讨厌的狗，也许是某个像素游戏的作者。
            AddTranslation("Such an annoying dog, perhaps, is the author of a certain pixel game.", "此烦犬者，或某像素戏之作者也。");
            // 北极狐
            AddTranslation("Arctic Fox", "北狐");
            // 一只孤独的、具有神力的北极狐。
            AddTranslation("A solitary Vulpes lagopus with great strength.", "孤北狐也，而有神力。");
            // 寻骨小狗
            AddTranslation("Bone Dog", "寻骨狗");
            // 跑来跑去，只为了找到它的骨头。
            AddTranslation("Running and running, just to find its bones.", "往来奔驰，惟求其骨。");
            // 狐狸
            AddTranslation("Fox", "狐");
            // 鬣狗
            AddTranslation("Hyena", "鬣犬");
            // 荒野中的寻骨强盗。
            AddTranslation("Bone seeking bandits in the wilderness.", "荒野之寻骨寇也。");
            // 狼王洛基
            AddTranslation("The Loky", "洛基狼王");
            // 狼中之王，非常非常强大。
            AddTranslation("The king of the whole pack of wolves, very, very powerful.", "群狼之王，甚强。");
            // 中华田园犬
            AddTranslation("Pastoral Dog", "田园犬");
            // 忠诚的中华田园犬，守卫和保护主人的房子。
            AddTranslation("Loyal Chinese pastoral dogs, they guard and protect their owners' houses.", "田园犬忠，守卫其主之庐。");
            // 斑鬣狗
            AddTranslation("Spotted Hyena", "斑鬣犬");
            // 斑鬣狗寻找骨头，它们因渴望血液而变得更强壮。
            AddTranslation("Spotted hyenas searching for bones, they grow stronger with their thirst for blood.", "斑鬣求骨，嗜血而益壮。");
            // 狮子
            AddTranslation("Lion", "狮");
            // 攻击力相当强的健壮狮子。
            AddTranslation("A strong lion with a fairly strong attack.", "壮狮也，其攻甚强。");
            // 雌狮
            AddTranslation("Lioness", "雌狮");
            // 守护狮子群的母狮总是警惕外来入侵。
            AddTranslation("The lioness guarding the lion herd are always on guard against external invasions.", "守群之雌狮，常备外侮。");
            // 猞猁
            AddTranslation("Lynx", "猞猁");
            // 孤独的猞猁用锋利的爪子和牙齿攻击。
            AddTranslation("The solitary Lynx attacks with its sharp claws and teeth.", "猞猁孤行，以利爪利齿攻。");
            // 美洲狮
            AddTranslation("Puma", "山狮");
            // 强壮的美洲狮，猫科动物中的领头。
            AddTranslation("Strong Puma, the leader among feline animals.", "山狮壮，为诸猫之魁。");
            // 美洲狮幼崽
            AddTranslation("Puma Cub", "山狮仔");
            // 幼年的美洲狮幼崽。它一回合就会长成一只美洲狮。
            AddTranslation("The immature Puma cub. It will grow into a Puma after a turn.", "幼山狮也，一回而成山狮。");
            // 雷虎
            AddTranslation("Thunder Tiger", "雷虎");
            // 它随雷声而来，然后忽的离去。
            AddTranslation("They came with thunder and then suddenly left.", "乘雷而来，忽然而去。");
            // 美西螈
            AddTranslation("Axolotl", "美西螈");
            // 这个可爱的小家伙有一条非常特别的尾巴。
            AddTranslation("This cute little guy has a very special tail.", "此小物可爱，而其尾殊异。");
            // 美西螈尾巴
            AddTranslation("Axolotl Tail", "螈尾");
            // 鲤鱼
            AddTranslation("Carp", "鲤");
            // 中国图腾中的鲤鱼据说有着不可估量的力量。
            AddTranslation("The fish in the Chinese totem is said to have unfathomable powers.", "图腾之鲤，据云其力难测。");
            // 珊瑚虫
            AddTranslation("Coral Polyp", "珊虫");
            // 它们与地形相伴相生。
            AddTranslation("They coexist with the terrain.", "与地势相生。");
            // 河豚
            AddTranslation("Globefish", "河鲀");
            // 任何想伤害它的造物都会后悔的。
            AddTranslation("Any creature that dreams of harming it will regret it.", "凡欲伤之者，后必悔。");
            // 鲨鱼蛋
            AddTranslation("Shark Egg", "鲨卵");
            // 我从来没见过鲨鱼蛋，原来长这样。
            AddTranslation("I've never seen a shark egg look like this before.", "我未尝见鲨卵如是。");
            // 鱿鱼
            AddTranslation("Squidge", "乌贼");
            // 这个小家伙会长成什么样的造物？
            AddTranslation("What kind of creature will the little one grow into?", "此小物长将为何类？");
            // 可怜的小家伙们……
            AddTranslation("Poor little ones......", "哀哉，此小物也……");
            // 约安尼斯
            AddTranslation("Joannes", "约安尼斯");
            // 一种只存在于噩梦中的奇特造物。
            AddTranslation("A peculiar creature that only exists in nightmares.", "惟见于恶梦之异物也。");
            // 约安尼斯神
            AddTranslation("God Joannes", "约安尼斯神");
            // 方法放寒假
            AddTranslation("Miemie Method", "方法放寒假");
            // 一只会写代码的小可爱。
            AddTranslation("A little cute who can write code.", "一能书代码之小可爱。");
            // 土豆鹿
            AddTranslation("Potato Elk", "薯麋");
            // 如今土豆已经发芽了。
            AddTranslation("The potatoes have sprouted.", "今薯已萌。");
            // 土豆小鹿
            AddTranslation("Potato Elk Cub", "薯麋仔");
            // 一只鹿角上有土豆的小鹿，看起来土豆才是它的主人。
            AddTranslation("A deer with potatoes on its antlers, it seems that the potato is the owner.", "角生薯之小麋也，若薯乃其主。");
            // 马鹿
            AddTranslation("Wapiti", "马鹿");
            // 强壮而有活力的鹿。
            AddTranslation("A strong and vital deer.", "壮而有生气之鹿也。");
            // 蝉
            AddTranslation("Cicada", "蝉");
            // 它们聚在一起，走亲访友，这很烦人。
            AddTranslation("They gather in groups, calling on friends, which is annoying.", "群聚相呼，甚烦。");
            // 蜻蜓
            AddTranslation("Dragonfly", "蜻蜓");
            // 指哪打哪的蜻蜓。
            AddTranslation("Dragonflies that point to where to hit.", "指所击之蜻蜓。");
            // 巨人蜈蚣
            AddTranslation("Giant Centipede", "巨蜈蚣");
            // 隐藏在地下深处的巨型蜈蚣用锋利的尖牙保卫自己的领地。
            AddTranslation("The giant centipedes hidden deep underground use their sharp fangs to defend their territory.", "潜地下深处之巨蜈蚣，以利牙守其境。");
            // 切叶蚁
            AddTranslation("Leafcutter ant", "切叶蚁");
            // 它们有锋利的爪子。
            AddTranslation("They have sharp claws.", "有利爪。");
            // 蝗虫群
            AddTranslation("Locust swarms", "蝗群");
            // 大批蝗虫飞来，对农民来说是一场灾难。
            AddTranslation("A large number of locusts swept in, and it was a disaster for the peasants.", "群蝗骤至，农人之灾也。");
            // 臭蝽
            AddTranslation("Shield bug", "臭蝽");
            // 恶心的臭蝽，没人想接近它们。
            AddTranslation("Disgusting stink bugs, no one wants to approach them.", "臭蝽可恶，无人欲近。");
            // 军蚁
            AddTranslation("Soldier Ant", "兵蚁");
            // 指哪打哪的军蚁。
            AddTranslation("Soldier Ant that point to where to hit.", "指所击之兵蚁。");
            // 橡果
            AddTranslation("Acorn", "橡实");
            // 犰狳
            AddTranslation("Armadillo", "犰狳");
            // 荒野中的“坚盾矮人”，蜷缩在一起时攻防兼备。
            AddTranslation("The 'Shield Dwarves' of the wilderness have both offense and defense when curled up.", "荒野所谓“坚盾矮人”者，蜷则攻守兼备。");
            // 西部牛仔
            AddTranslation("CowBoy", "牛仔");
            // 百发百中的神枪手牛仔。
            AddTranslation("The skilled marksman cowboy who hits every shot.", "百发百中之牛仔也。");
            // 大象
            AddTranslation("Elephant", "象");
            // 陆地上最大的创造物，它有顽强的生命力和防御力。
            AddTranslation("The largest creation on land, it has tenacious vitality and defense.", "陆生之物至大者也，命坚而善守。");
            // 灰熊幼崽
            AddTranslation("Grizzly Cub", "灰熊仔");
            // 小熊还没有长大，但它已经准备好面对黑暗。
            AddTranslation("The little bear has not yet grown up, but it is already prepared to face the darkness.", "熊仔未壮，而已备当黑暗。");
            // 蜜獾
            AddTranslation("Honey badger", "蜜獾");
            // 复仇心强的蜜獾从不畏惧。
            AddTranslation("The vengeful honey badgers never feel afraid.", "怀雠之蜜獾未尝惧。");
            // 猫鼬
            AddTranslation("Meerkat", "猫鼬");
            // 警惕的猫鼬，一旦发现威胁就迅速攻击。
            AddTranslation("The watchful Meerkat, it attacks swiftly upon detecting a threat.", "警猫鼬见胁则骤击。");
            // 狐獴
            AddTranslation("Mongoose", "狐獴");
            // 永不腐败的狐獴对大多数毒素都有抵抗力。
            AddTranslation("The incorruptable Mongoose is resistent to most toxins.", "狐獴不坏，多毒不能中。");
            // 弱熊
            AddTranslation("Stunted Grizzly", "瘠熊");
            // 这么一只可怜的、伤痕累累的野兽，它怎么了？
            AddTranslation("Such a poor, scarred beast- what must have befallen it?", "此兽贫而多创，其所遭何如？");
            // 小毛球
            AddTranslation("Uri", "乌里");
            // 被遗弃的孩子将在野外学会独立。
            AddTranslation("Abandoned children learn to be independent outside.", "弃子居野，乃学自立。");
            // 野人
            AddTranslation("Uryli", "乌里利");
            // 学会了独立的野人。
            AddTranslation("A wild man who has learned to be independent.", "已学自立之野人也。");
            // 花栗鼠
            AddTranslation("Chipmunk", "栗鼠");
            // 森林中的一种带条纹的小啮齿动物，带着橡子作为食物。
            AddTranslation("A small striped rodent of the forest, carrying an acorn with it as a meal.", "林间小兽也，有文，负橡实以为食。");
            // 推推鼠
            AddTranslation("Pushing Mouse", "推鼠");
            // 一只巨大的南方老鼠。
            AddTranslation("A huge southern mouse.", "南土巨鼠也。");
            // 鼠崽
            AddTranslation("Rat Cub", "鼠仔");
            // 弱小的老鼠可以成长为高贵的鼠王。
            AddTranslation("A weak rat can grow into a noble rat king.", "弱鼠可长为贵鼠王。");
            // 变异牛蛙
            AddTranslation("Buff Frog", "异蛙");
            // 获得力量的变异青蛙。
            AddTranslation("A mutated frog that has gained power.", "得威之异蛙也。");
            // 变异牛蛙神
            AddTranslation("God Frog", "蛙神");
            // 苦力怕
            AddTranslation("Creeper", "苦力怕");
            // 我的世界里的可怕造物。
            AddTranslation("A terrifying creature from the world of Minecraft.", "《我的世界》之可畏造物也。");
            // 鳄鱼
            AddTranslation("Crocodile", "鳄");
            // 有很强咬合力的动物。
            AddTranslation("An animal with a strong biting force.", "其啮甚劲之兽也。");
            // 响尾蛇蛋
            AddTranslation("Rattler egg", "响尾卵");
            // 即将孵化的蛇卵，虽然很脆弱。
            AddTranslation("A snake egg that is about to hatch, although it is very fragile.", "将孵之蛇卵也，虽甚脆。");
            // 大海龟
            AddTranslation("Sea Turtle", "海龟");
            // 生命力顽强的海龟即使被献祭也不会死亡。
            AddTranslation("Vibrant sea turtles will not die even after being sacrificed.", "海龟命坚，虽见祀亦不死。");
            // 刺蜥
            AddTranslation("Thorny Devil", "刺蜥");
            // 这家伙的性格和名字一模一样。
            AddTranslation("This guy's characteristics are just like its name.", "其性若其名。");
            // 刺蜥的尾巴
            AddTranslation("Thorny Devil Tail", "刺蜥尾");
            // 免费响尾蛇蛋
            AddTranslation("Free Rattler egg", "无费响尾卵");
            // 缝合蛋
            AddTranslation("Amalgam Egg", "缝卵");
            // 走石
            AddTranslation("Walking Stone", "行石");
            // 跋山涉水的走石。
            AddTranslation("A stone that has traveled over mountains and rivers.", "跋山涉水之行石也。");
            // 石鹿
            AddTranslation("Stone Deer", "石鹿");
            // 由能工巧匠雕刻而成的石鹿。
            AddTranslation("A stone deer statue carved by skilled craftsmen.", "能工所镌之石鹿也。");
            // 石狼
            AddTranslation("Stone Wolf", "石狼");
            // 由能工巧匠雕刻而成的石狼。
            AddTranslation("A stone wolf statue carved by skilled craftsmen.", "能工所镌之石狼也。");

            // Other
            // 荒野传说
            AddTranslation("Wilderness Legend", "荒野传奇");
            // 在原有印记的基础上添加一些简单的卡牌。
            AddTranslation("Add some simple cards based on the original imprint.", "本旧印，益以数简牌。");
            // 找寻橡果
            AddTranslation("Acorns", "求橡实");
            // 当放置[creature]时，获得一张橡果卡牌。
            AddTranslation("When placing [creature], draw an acorn.", "[creature]既陈，抽一橡实。");
            // 剪翼者
            AddTranslation("Cutting Wings", "翦翼");
            // 被[creature]击中的带有空袭印记的造物每次宣告攻击时将受到1点伤害，并使其空袭印记失效。
            AddTranslation("Flying cards struck by [creature] will take 1 damage each time it declares an attack, and renders their wings useless.", "凡为[creature]所击之空袭牌，每其宣攻，各受伤一，且其翼俱废。");
            // 鸣蝉之夏
            AddTranslation("Swarm", "蝉聚");
            // 当[creature]被放置时，持牌人一侧的剩余空位将被蝉群填满。
            AddTranslation("when [creature] is placed, the remaining slots on the owner's side are filled with cicadas", "[creature]既陈，持牌者一侧余空皆以蝉充。");
            // 地形创建者
            AddTranslation("Terrain Creator", "造地");
            // 将[creature]放置到场上时，随机抽取一张地形卡。
            AddTranslation("When placing [creature] on the field, randomly draw a terrain card.", "[creature]既陈于场，随机抽一地形牌。");

            // WLD-DLC
            // 青龙
            AddTranslation("Azure Dragon", "青龙");
            // 四神兽之首，具有绝对的压制力。
            AddTranslation("The head of the four divine beasts, it has absolute suppressive power.", "四灵之长，威足尽压。");
            // 中国龙
            AddTranslation("Chinese Loong", "华龙");
            // 神话之龙，乃万物之主宰。
            AddTranslation("The Chinese Loong in myths and legends is the master of all things.", "神话之龙，乃万物之主。");
            // 降世神龙
            AddTranslation("God long", "神龙");
            // 安德雷安富
            AddTranslation("Andrealphus", "安德雷安富");
            // 所罗门王的第六十五位门徒。
            AddTranslation("The sixty-fifth demon god of King Solomon.", "所罗门王第六十五魔神也。");
            // 觉醒的鸵鸟
            AddTranslation("Awakened Ostrich", "觉鸵鸟");
            // 黑尾鸥
            AddTranslation("Black-tailed Gull", "黑尾鸥");
            // 码头的黑尾鸥会把自己的灵魂托付给下一个命定之人。
            AddTranslation("The black tailed gull at the dock will entrust its soul to the next destined person.", "埠头黑尾鸥，以其魂托诸后之命定者。");
            // 码头的黑尾鸥
            AddTranslation("Black tailed gulls at the dock", "埠头黑尾鸥");
            // 不死鸟蛋
            AddTranslation("Burning Egg", "凤卵");
            // 孵化之后，便是永恒。
            AddTranslation("After hatching, there is eternity.", "既孵，乃永。");
            // 猎鹰
            AddTranslation("Eagle", "鹰");
            // 一只雄伟的猎鹰俯瞰着大地。
            AddTranslation("A powerful eagle overlooking the underground.", "雄鹰俯瞰大地。");
            // 游隼
            AddTranslation("Falcon", "隼");
            // 迫捷的游隼，一上场就会立即攻击。
            AddTranslation("Eager peregrine falcons, they attack as soon as they are laid down.", "捷隼一陈，即攻。");
            // 辣鸡
            AddTranslation("Hot Chiking", "炎鸡");
            // 一只即将成神的鸡。
            AddTranslation("The chicken that is about to become a god.", "将神之鸡也。");
            // 翎羽
            AddTranslation("Ling Bird", "翎鸟");
            // 翱翔的神鸟会庇护友方造物，其死后继承它的属性。
            AddTranslation("A soaring divine bird will bless a friend to inherit its attributes after death.", "翔天神鸟庇其友物，其死则承其属性。");
            // 夜枭
            AddTranslation("Night Owl", "夜鸮");
            // 它们面对力量时，也会变得更加强大。
            AddTranslation("They become stronger when faced with strength.", "临强则益强。");
            // 鸵鸟
            AddTranslation("Ostrich", "鸵鸟");
            // 鸵鸟四处奔跑，其行为变幻莫测。
            AddTranslation("The ostrich running around, its behavior is unpredictable.", "鸵鸟四驰，其行难测。");
            // 鹈鹕
            AddTranslation("Pelican", "鹈鹕");
            // 贪得无厌的鹈鹕会吞下整个造物，但不消化它。
            AddTranslation("The insatiable pelican swallowed the entire creation without digesting it.", "贪而无厌之鹈鹕吞物尽体，而不化之。");
            // 鸽子
            AddTranslation("Pigeon", "鸽");
            // 鸽子象征着和平，它的危害取决于场上的鸟类。
            AddTranslation("The dove symbolizes peace, and its harm depends on the birds on the field.", "鸽象和，其害视场上鸟数而定。");
            // 朱雀
            AddTranslation("Rosefinch", "朱雀");
            // 中国神话中的四大神兽之一，不断自我燃烧。
            AddTranslation("One of the four great mythical beasts in Chinese mythology, constantly burning itself.", "中国四灵之一，恒自焚。");
            // 火神朱雀
            AddTranslation("Fire God Rosefinch", "火神朱雀");
            // 不死鸟
            AddTranslation("Secular Bird", "不死鸟");
            // 不死神鸟
            AddTranslation("God Secular Bird", "不死神鸟");
            // 超级鸡
            AddTranslation("Super Chiking", "成神鸡");
            // 一只已经成神的鸡。
            AddTranslation("The chicken that became a god.", "既神之鸡也。");
            // 神之鸡
            AddTranslation("God Chiking", "神鸡");
            // 破碎鹰
            AddTranslation("Broken Hawk", "残鹰");
            // 这些破碎的牌让我想起了前世的记忆，尽管它们比普通卡牌弱得多。
            AddTranslation("These broken cards remind me of my past life, even though they are far weaker than regular cards.", "此残牌使我忆前生，虽远弱于常牌。");
            // 破碎渡鸦
            AddTranslation("Broken Raven", "残渡鸦");
            // 破碎灰熊
            AddTranslation("Broken Grizzly", "残灰熊");
            // 破碎灰熊幼崽
            AddTranslation("Broken Grizzly Cub", "残灰熊仔");
            // 破碎猎人
            AddTranslation("Broken Hunter", "残猎者");
            // 破碎白鼬
            AddTranslation("Broken Stoat", "残白鼬");
            // 破碎狼
            AddTranslation("Broken Wolf", "残狼");
            // 破碎狼崽
            AddTranslation("Broken Wolf Cub", "残狼仔");
            // 破碎麋鹿
            AddTranslation("Broken Elk", "残麋");
            // 破碎蝰蛇
            AddTranslation("Broken Adder", "残蝰");
            // 犬魔
            AddTranslation("Barghest", "犬魔");
            // 来自地狱的犬魔喜欢见血。
            AddTranslation("The Barghest from hell love to see blood.", "狱中犬魔喜见血。");
            // 地狱犬魔
            AddTranslation("Hell Barghest", "狱犬魔");
            // 毛茸茸的人
            AddTranslation("Furry Man", "毛人");
            // 这家伙为什么毛茸茸的？
            AddTranslation("Why is this guy furry?", "此人何以多毛？");
            // 逆天
            AddTranslation("ikungagaga", "逆天");
            // 一只拥有永恒力量和领导力的优秀之狗。
            AddTranslation("An excellent dog with eternal strengthening and leadership.", "永益而善率众之犬也。");
            // 逆天神犬
            AddTranslation("Ni Tian God Dog", "逆天神犬");
            // 孤狼
            AddTranslation("Lone Wolf", "孤狼");
            // 一只脱离狼群的狼，但孤独会给它力量。
            AddTranslation("A wolf who is out of the pack, but loneliness will give him strength.", "离群之狼也，而孤能予其力。");
            // 捣蛋狗
            AddTranslation("Naughty dog", "顽犬");
            // 一只淘气的小狗，如果对面没有造物，它就会跑到对面去。
            AddTranslation("A mischievous little dog, if there is no creation on the other side, he will run to the other side.", "顽犬也，若对面无物，则趋彼侧。");
            // 疯狗
            AddTranslation("Rabid Dog", "狂犬");
            // 愤怒的狗，谁敢惹它，都会被双倍奉还。
            AddTranslation("Angry dogs, whoever dares to provoke him will be doubly rewarded.", "怒犬也，谁犯之，则倍报。");
            // 狼人
            AddTranslation("Werewolf", "狼人");
            // 大佐狗
            AddTranslation("Zuo Dog", "佐犬");
            // 骨与血都是其必需品。
            AddTranslation("Bones and blood are both essential for it.", "骨与血，二者皆其所必需。");
            // 俊佐狗
            AddTranslation("Jun Zuo Dog", "俊佐犬");
            // 猎豹
            AddTranslation("Cheetah", "猎豹");
            // 敏捷的猎豹一上场就会立刻攻击。
            AddTranslation("Agile cheetahs will attack immediately upon their appearance.", "捷猎豹一陈，即攻。");
            // 花喵
            AddTranslation("Hua Miao", "花喵");
            // 熟练掌握全挑战的神秘之猫，一切尽在其掌握之中。
            AddTranslation("The Dark One who masters the full challenge proficiently, everything is under his control.", "通全挑战之玄猫，万事尽在其掌。");
            // 花豹
            AddTranslation("Leopard", "豹");
            // 凶猛的花豹，速度快，伤害高。
            AddTranslation("A ferocious Leopard with speed and damage.", "豹也，猛而捷，伤亦高。");
            // 剑齿虎
            AddTranslation("Smilodon", "剑齿虎");
            // 剑齿虎，一种起源于史前的野兽。
            AddTranslation("The smilodon, a beast of prehistoric origin.", "剑齿虎，史前之兽也。");
            // 剑齿虎幼崽
            AddTranslation("Smilodon Cub", "剑齿虎仔");
            // 脆弱的剑齿虎幼崽，它们帮助母亲收集骨头。
            AddTranslation("Weak saber toothed tiger cubs, they help their mother collect bones.", "弱剑齿虎仔，助其母敛骨。");
            // 白虎
            AddTranslation("White Tiger", "白虎");
            // 四神兽之一，拥有最珍贵的血液。
            AddTranslation("One of the four divine beasts, it has the most precious blood.", "四灵之一，而血至珍。");
            // 寅虎
            AddTranslation("Yin Tiger", "寅虎");
            // 一只强壮的老虎，擅长从后方狩猎。
            AddTranslation("A strong tiger that is good at hunting from behind.", "壮虎善自后猎。");
            // 觉醒的寅虎
            AddTranslation("Awakened Yin Tiger", "觉寅虎");
            // 子淇猫
            AddTranslation("Ziqi Cat", "子淇猫");
            // 辅助能力最强的猫，乃猫中霸主。
            AddTranslation("A cat with strong auxiliary abilities is the overlord of cats.", "辅力最强之猫，猫中霸主也。");
            // 子淇神猫
            AddTranslation("Ziqi God Cat", "子淇神猫");
            // 帕派瑞斯
            AddTranslation("Papyrus", "帕派瑞斯");
            // 来自地下世界的小天使。
            AddTranslation("A little angel from the underworld.", "冥土小天使也。");
            // 杉斯
            AddTranslation("Sans", "杉斯");
            // 一个懒骨头和它的地狱冷笑话。
            AddTranslation("A lazy bone and its hellish joke.", "懒骨头与其地狱冷笑话。");
            // 毁灭海参
            AddTranslation("Doom Trepang", "灭海参");
            // 毁灭海参的爆炸总是毁灭性的。
            AddTranslation("An exploding Doom Trepang has always been devastating.", "灭海参之爆，恒为大祸。");
            // 电鳗
            AddTranslation("Electric Eel", "电鳗");
            // 电鳗会对攻击其位置的生物造成伤害。
            AddTranslation("Electric eels can cause damage to creations that attack their location.", "凡攻其位者，电鳗皆伤之。");
            // 座头鲸
            AddTranslation("Humpback", "座头鲸");
            // 在水中拥有绝对力量的造物。
            AddTranslation("Those who possess absolute power in water.", "水中绝力之物也。");
            // 纸船
            AddTranslation("Paper Boat", "纸舟");
            // 一艘满载骨头的纸船足以让所有造物垂涎。
            AddTranslation("A paper boat full of bones is enough to make all animals salivate.", "满载骨之纸舟，足令群物垂涎。");
            // 败客
            AddTranslation("Biker", "败客");
            // 旗鱼
            AddTranslation("Sailfish", "旗鱼");
            // 迫不及待的旗鱼一上场就会立刻攻击。
            AddTranslation("The sailfish that can't wait will attack as soon as they get on the field.", "急旗鱼一陈，即攻。");
            // 敦煌神鹿
            AddTranslation("Dunhuang deer", "敦煌神鹿");
            // 来自东方的敦煌神鹿。
            AddTranslation("Dunhuang deer from the East.", "来自东方之敦煌神鹿。");
            // 无限增殖的鹿角兔乃生态的破坏者。
            AddTranslation("The Jackalop with unlimited appreciation is a destroyer of ecology.", "无穷孳生之角兔，生态之贼也。");
            // 盘羊
            AddTranslation("Ovis Ammon", "盘羊");
            // 撼地的盘羊杀死它撞到的造物以换取力量。
            AddTranslation("The earth shaking ram kills its creations in exchange for power.", "撼地之盘羊，杀其所触之物以易威。");
            // 绵羊
            AddTranslation("Ovis Aries", "绵羊");
            // 虚弱的绵羊会吸引其他捕食者狩猎。
            AddTranslation("Weak sheep attract other predators to hunt.", "弱绵羊招群猎。");
            // 犀牛
            AddTranslation("Rhinoceros", "犀");
            // 它们的皮很厚，难以被普通的造物破坏。
            AddTranslation("They carry thick skin, which is not easily damaged by ordinary creations.", "皮厚，常物难伤。");
            // 藏羚
            AddTranslation("Tibetan Antelope", "藏羚");
            // 强壮的藏羚乃高原的舞者。
            AddTranslation("The strong Tibetan antelope is a dancer on the plateau.", "壮藏羚，高原之舞者也。");
            // 藏羚神
            AddTranslation("God Antelope", "藏羚神");
            // 角马
            AddTranslation("Wildebeest", "角马");
            // 成群的角马，它们联合起来抵抗捕食者。
            AddTranslation("Herd wildebeest, they unite to resist predators.", "群角马并力拒猎者。");
            // 蚁王
            AddTranslation("Ant King", "蚁王");
            // 指挥蚂蚁大军的蚂蚁王。
            AddTranslation("The ant king who commands the army of ants.", "率蚁军之王也。");
            // 郑老板
            AddTranslation("Boss Z", "郑老板");
            // 这家伙贪婪却无私。
            AddTranslation("This guy is greedy but selfless.", "此人贪而无私。");
            // 大郑老板
            AddTranslation("Big Boss Z", "大郑老板");
            // 蝴蝶
            AddTranslation("Butterfly", "蝴蝶");
            // 爱花的蝴蝶，到处飞。
            AddTranslation("Butterflies that love flowers, they fly everywhere.", "爱花之蝶，四方飞扬。");
            // 源石虫
            AddTranslation("Rockivores", "食石虫");
            // 这种昆虫可以以地形为食。
            AddTranslation("This insect can feed on terrain.", "此虫食地形。");
            // 三叶虫
            AddTranslation("Trilobite", "三叶虫");
            // 分泌酸液的古三叶虫。
            AddTranslation("The ancient trilobites secreted acid.", "古三叶虫，泌酸液。");
            // 暴食白鼬
            AddTranslation("Gluttonous Stoat", "饕白鼬");
            // 继续吃，继续吃。
            AddTranslation("Keep eating and eating.", "惟食而已。");
            // 豪毛毛
            AddTranslation("Hao Maomao", "豪毛毛");
            // 敏捷的猴子善于模仿。
            AddTranslation("Agile monkeys are good at imitating.", "捷猴善效。");
            // 豪吉吉
            AddTranslation("Hao Jiji", "豪吉吉");
            // 以撒
            AddTranslation("Isaac", "以撒");
            // 在另一个世界经历悲剧和痛苦。
            AddTranslation("The tragedy and suffering experienced in another world.", "异世所经之悲苦也。");
            // 麒麟
            AddTranslation("Kylin", "麒麟");
            // 麒麟踏祥云，人间百难消。
            AddTranslation("Kylin steps on auspicious clouds, which are difficult to dispel in the human world.", "麒麟履祥云，人间百难消。");
            // 猛犸
            AddTranslation("Mammoths", "猛犸");
            // 冰河世纪的可怕造物。
            AddTranslation("A terrifying artifact from ancient times.", "古世可畏之物也。");
            // 小人物大生活
            AddTranslation("Man with Big Life", "小身大命");
            // 一位小人物，拥有大生活。
            AddTranslation("As a small person, having a big life.", "身虽小，而命甚大。");
            // 微型月亮
            AddTranslation("Mini Moon", "微月");
            // 哦！这么小的月亮是怎么来的？
            AddTranslation("Oh! How did such a tiny moon come about?", "嗟乎！此月何其小也？");
            // 神之月
            AddTranslation("God Moon", "神月");
            // 月之碎片
            AddTranslation("Lunar debris", "月屑");
            // 大熊猫
            AddTranslation("Panda", "熊猫");
            // 中国的国家保护动物，有稀有的血液，也有懒惰的天性。
            AddTranslation("China's nationally protected animal, with rare blood, as well as its lazy nature.", "中国国护之兽，血稀而性惰。");
            // 挑剔熊
            AddTranslation("Picky Bear", "择食熊");
            // 一只挑食的熊。
            AddTranslation("A picky eating grizzly bear.", "择食之熊也。");
            // 龙猫
            AddTranslation("Chinchilla", "绒鼠");
            // 可爱的龙猫，攻击它的生物会感到内疚。
            AddTranslation("Cute Chinchilla, attacking its creatures will make it feel guilty.", "娇美之绒鼠，击厥物者，令人惭愧。");
            // 仓鼠
            AddTranslation("Hamster", "仓鼠");
            // 可爱的仓鼠会邀请亲朋好友。
            AddTranslation("The cute hamster invites friends.", "娇美之仓鼠，能招朋引类。");
            // 肌肉鼠
            AddTranslation("Muscle Mouse", "壮鼠");
            // 如果你有困难，它会来帮助你的。
            AddTranslation("If you have difficulties, it will come to help you.", "汝若有难，彼来相助。");
            // 鼠后
            AddTranslation("Rat Queen", "鼠后");
            // 它们成群结队地聚集在一起，服从鼠后的命令。
            AddTranslation("They gather in groups and obey the commands of the Rat Queen.", "群聚成队，禀鼠后之令。");
            // 科学家鼠
            AddTranslation("Scientist Rat", "博士鼠");
            // 这位科学家发现了一种寻找族群的方法。
            AddTranslation("This scientist discovered a method to search for tribes.", "此博士得寻属之法。");
            // 食蛇鼠
            AddTranslation("Snake Eater", "食蛇鼠");
            // 甚至猎物也能成为猎人。
            AddTranslation("Even prey can become hunters.", "猎物亦能为猎者。");
            // 玄武
            AddTranslation("Black Tortoise", "玄武");
            // 防御力最强的四神兽之一。
            AddTranslation("One of the four divine beasts with the strongest defense.", "四神兽中，守御最固者也。");
            // 神玄武
            AddTranslation("God Tortoise", "神玄武");
            // 短吻鳄
            AddTranslation("Alligator", "短吻鳄");
            // 吃得越多，它就越强壮。
            AddTranslation("The more eat, the stronger it becomes.", "食愈多，则愈强。");
            // 海蛇
            AddTranslation("Hydrophis", "海蛇");
            // 海里致命的毒蛇。
            AddTranslation("A deadly venomous snake in the sea.", "海中致命之毒蛇。");
            // 蛇眼
            AddTranslation("Snake Eye", "蛇眼");
            // 运气也是实力的一部分。
            AddTranslation("Luck is also part of strength.", "运亦力之一也。");
            // 豺狼
            AddTranslation("Jackal", "豺狼");
            // 只要它在狼群中，就有强大的力量。
            AddTranslation("As long as it is in the wolf pack, it has great power.", "苟在狼群，有大威。");
            // 逃避者
            AddTranslation("Avoider", "遁者");
            // 生存还是死亡，这是个问题。
            AddTranslation("Survival or death, that's the question.", "生乎？死乎？此问也。");
            // 觉醒的逃避者
            AddTranslation("Awakened Avoider", "觉遁者");
            // 血莲
            AddTranslation("Blood Lotus", "血莲");
            // 一朵即将绽放的奇特血莲。
            AddTranslation("A unique blood lotus about to bloom.", "奇血莲，将绽矣。");
            // 予你成歌
            AddTranslation("Make a song for you", "为汝成歌");
            // 渔猫
            AddTranslation("Fishing Cat", "渔猫");
            // 一切潜水的造物都逃不过它的眼睛。
            AddTranslation("All diving creatures cannot escape its eyes.", "凡潜之物，难逃厥目。");
            // 云豹
            AddTranslation("Cloud Leopard", "云豹");
            // 它们乃猫中之医学者。
            AddTranslation("They are doctors among feline animals.", "乃猫属之医者也。");
            // 黑豹
            AddTranslation("Panther", "黑豹");
            // 贪得无厌的黑豹无骨则亡。
            AddTranslation("The greedy black panther will perish without bones.", "黑豹贪而无厌，无骨则亡。");
            // 匪徒鹦鹉
            AddTranslation("Bandit Parrot", "贼鹦");
            // 丧尸鹦鹉生前的模样...它们与海盗为伍，四处烧杀抢掠。
            AddTranslation("The appearance of a skeleton parrot before its death They burned, killed, and looted everywhere together with pirates.", "此乃枯骨鹦鹉生前之貌……与海寇为伍，处处烧杀劫掠。");
            // 卡皮巴拉
            AddTranslation("Capybara", "水豚");
            // 温顺的小家伙们不喜欢打架。
            AddTranslation("The docile little ones don't like to fight.", "驯顺之小物，不喜争斗。");
            // 黑眉锦蛇
            AddTranslation("Elaphe Taeniura", "黑眉锦蛇");
            // 喜欢松鼠的黑眉锦蛇,投其所好便可释放其真正的力量。
            AddTranslation("The black browed snake, who loves squirrels, can unleash its true power by catering to its preferences.", "好松鼠之黑眉锦蛇，投厥所好，可发厥真威。");
            // 胡鹫雏鸟
            AddTranslation("Juvenile Lammergeier", "胡鹫雏");
            // 雄心勃勃的胡鹫幼鸟储存食物，未来可期。
            AddTranslation("The ambitious Juvenile Lammergeier store food and have a promising future ahead.", "壮志之胡鹫雏，储食备日，前途可期。");
            // 突变仓鼠
            AddTranslation("Mutated Hamster", "异仓鼠");
            // 玥猫
            AddTranslation("Moon Cat", "玥猫");
            // 额头上写着东方神秘文字的玥猫。
            AddTranslation("The moon cat with mysterious words on its forehead.", "玥猫，额有东方秘文。");
            // 狼鹊
            AddTranslation("Wolf Magpie", "狼鹊");
            // 狼魄鹊姿，它们集勇猛与灵动与一身。
            AddTranslation("The physique of wolves and the posture of magpies combine bravery and agility.", "狼魄鹊姿，勇猛机捷，兼而有之。");
            // 骷髅灰熊
            AddTranslation("Skeleton Grizzly", "枯骨灰熊");
            // 不知为何，即便死亡也无法阻挡它对食物与血液的渴望。
            AddTranslation("For some reason, even death cannot stop its thirst for food and blood.", "不知何故，纵死，不能止厥食血之渴。");
            // 觉醒的骷髅灰熊
            AddTranslation("Awakened Skeleton Grizzly", "觉枯骨灰熊");
            // 没有名字的死亡之人，还会有人来怜悯吗？
            AddTranslation("Will there still be people who sympathize with the nameless dead?", "无名之死者，尚有人悯之乎？");
            // 无名亡者
            AddTranslation("Nameless Dead", "无名亡者");
            // 名字
            AddTranslation("Name", "名");
            // 慢冷滞骸
            AddTranslation("Slow Cooling Bone", "慢冷滞骸");
            // 觉醒的慢冷滞骸
            AddTranslation("Awakened Slow Cooling Bone", "觉慢冷滞骸");
            // 谁能领悟死亡的真谛呢？即便是格里魔拉也无法参透。
            AddTranslation("Who can comprehend the true meaning of death? Even Grimora cannot comprehend it.", "谁能悟死之真谛乎？即格里魔拉，亦难以参透。");
            // 森蚺
            AddTranslation("Green Anaconda", "森蚺");
            // 能够孤雌生殖的森蚺，它们巨可吞人。
            AddTranslation("The parthenogenetic Green Anaconda can swallow humans.", "无雄而能孕之森蚺，巨可吞人。");
            // 恶灵骑士
            AddTranslation("Ghost Rider", "恶灵骑士");
            // 讲究杀戮正义的恶灵骑士，它将用愤怒燃尽万物的罪孽。
            AddTranslation("The Ghost Rider who emphasizes killing justice will burn away the sins of all things with anger.", "重杀戮之义，以怒燃尽万物之罪。");
            // 觉醒的恶灵骑士
            AddTranslation("Awakened Ghost Rider", "觉恶灵骑士");
            // 幽冥火
            AddTranslation("Ghost Fire", "幽冥火");
            // 觉醒的幽冥火
            AddTranslation("Awakened Ghost Fire", "觉幽冥火");
            // 大黑耗子
            AddTranslation("Big Black Mouse", "大黑鼠");
            // 四海为家的大黑耗子，它们如墙头草一般无依无靠。
            AddTranslation("The big black rats, who are home everywhere, are insatiable and helpless like weeds on the wall.", "四海为家之大黑鼠，如墙头草，无所凭倚。");
            // 骆驼
            AddTranslation("Camel", "骆驼");
            // 任劳任怨的骆驼，乃丝绸之路之常客。
            AddTranslation("Camels who work tirelessly are frequent visitors on the Silk Road.", "任劳任怨之骆驼，丝路之常客也。");
            // 嶙峋骆驼
            AddTranslation("Thin Camel", "嶙峋骆驼");
            // 一只瘦的不成样子的嶙峋骆驼，不知这画作出自何人。
            AddTranslation("A thin and shapeless camel, I don't know who could draw such a picture.", "骨瘦嶙峋之骆驼，不知此画出自何人。");
            // 觉醒的嶙峋骆驼
            AddTranslation("Awakened Thin Camel", "觉嶙峋骆驼");
            // 木板触手
            AddTranslation("Board Tentacle", "板触");
            // 我不曾记得拍过这张。
            AddTranslation("I don't remember taking a photo of it.", "余不记曾摄此。");
            // 金之触手
            AddTranslation("Golden Tentacle", "金触");
            // 它们以触手换取死亡。
            AddTranslation("They traded death for their hands.", "以触手易死。");
            // 道具触手
            AddTranslation("Item Tentacle", "器触");
            // 它们看到道具时异常兴奋。
            AddTranslation("They become excited when they see props.", "见器则大喜。");
            // 比例触手
            AddTranslation("Scaleten Tentacle", "比触");
            // 内脏触手
            AddTranslation("Viscera Tentacle", "脏腑触");
            // 强化猎鹰
            AddTranslation("Strengthen Eagle", "壮鹰");
            // 炸弹机械犬
            AddTranslation("Bomb Mechanical Dog", "爆机犬");
            // 为不值一提的事牺牲自己的性命，终是机械被创造的宿命吗？
            AddTranslation("Is sacrificing one's life for something insignificant the purpose of creating machinery?", "以身殉微末之事，岂机械之所以作乎？");
            // 炸弹机械犬2.0
            AddTranslation("Bomb Mechanical Dog 2.0", "爆机犬二");
            // 咸鱼
            AddTranslation("Salt Fish", "咸鱼");
            // 不过一条死鱼罢了...
            AddTranslation("It's just a dead fish...", "特死鱼耳……");
            // 翻身咸鱼
            AddTranslation("Turning over salt fish", "反身咸鱼");
            // 冰鳞玄蛇
            AddTranslation("Ice scaled Snow Snake", "冰鳞玄蛇");
            // 冰冻的蛇鳞，凛冽的蛇心。
            AddTranslation("Ice cast scales, cold snake hearts.", "鳞凝于冰，心寒若蛇。");
            // 悦狼
            AddTranslation("Joyful Wolf", "悦狼");
            // 它们脸上总带着诡异的笑容。
            AddTranslation("They always have a strange smile on their faces.", "常含诡笑于面。");
            // 科学怪羊
            AddTranslation("Frankenstein's Sheep", "怪羊");
            // 极具攻击性的科学怪羊，它们眼中也许只有杀戮。
            AddTranslation("Highly aggressive scientific monsters, as if their eyes are only focused on killing.", "怪羊攻性甚烈，其目若惟见杀戮。");
            // 雾隐暗骑
            AddTranslation("Smoke Knight", "烟骑");
            // 不断变化的雾隐暗骑，也许那个老女人说的没错，死亡并不是终结。
            AddTranslation("The ever-changing Smoke Knight, perhaps the old woman is right, death is not the end.", "烟骑变幻无常，彼老妇之言或是：死非终也。");
            // 觉醒的雾隐暗骑
            AddTranslation("Awakened Smoke Knight", "觉烟骑");
            // 招财猫
            AddTranslation("Maneki-neko", "招财猫");
            // 海盗蟹
            AddTranslation("Pirate Crab", "盗蟹");
            // 优秀的海盗从不怀疑自己的价值。
            AddTranslation("Excellent pirates never doubt their own value.", "良盗未尝疑其身价。");
            // 耄耋残像
            AddTranslation("Echo of MaoDie", "耄耋余响");
            // 有人在它的墓志铭上找到了一句不明所以的话：“哈基米南北绿豆。”
            AddTranslation("Someone found an inexplicable sentence in its epitaph: \"Hakimi's green beans from north to south\".", "有人得其墓志一语，莫知所谓：“哈基米南北绿豆。”");
            // 杀手蜂巢
            AddTranslation("Killer Beehive", "杀蜂巢");
            // 它们将无穷无尽。
            AddTranslation("It's endless, endless.", "无穷，无穷。");
            // 血狼
            AddTranslation("Blood Wolf", "血狼");
            // 这只狼疯狂渴求血液，已经到了危及生命的程度。
            AddTranslation("This wolf is crazily craving for blood, to the point of endangering its life.", "此狼狂嗜于血，几至危生。");
            // 倒下的胡加格
            AddTranslation("Fallen Hugag", "仆胡加格");
            // 胡加格
            AddTranslation("Hugag", "胡加格");
            // 身形头重脚轻的家伙，倒过来可能就判若两人了。
            AddTranslation("The top-heavy guy may not be the same when it is reversed.", "此物头重脚轻，若颠之，殆判若异物。");
            // 世界龟
            AddTranslation("World Turtle", "负世龟");
            // 三只泥龟支撑着地球。
            AddTranslation("Three mud turtles support the earth.", "三泥龟共负地。");
            // 它只是一只普通的松鼠吗？
            AddTranslation("Is it just an ordinary squirrel?", "此特常松鼠乎？");
            // 柴犬
            AddTranslation("Shiba Inu", "柴犬");
            // 地狱三头犬
            AddTranslation("Cerberus", "三头狱犬");
            // 冥界的守护者，生人勿近，亡灵难出。
            AddTranslation("Guardian of the Underworld—no living soul may enter, no dead soul may leave.", "守冥者也：生魂不得入，亡魂不得出。");
            // 貔貅
            AddTranslation("Pi Xiu", "貔貅");
            // 前有挚兽，则载貔貅。
            AddTranslation("If fierce beasts lie ahead, carry the Pi Xiu as your guardians.", "前有猛兽，则载貔貅以为卫。");
            // 海胆
            AddTranslation("Sea Urchin", "海胆");
            // 若你无意间触碰此物，或许会追悔莫及。
            AddTranslation("If you accidentally stumble upon this, you might regret it.", "误触此物，后悔或无及。");
            // 鹅与鸭
            AddTranslation("Goose and Duck", "鹅鸭");
            // 旁人所言，它们充耳不闻。鹅同鸭讲，有时候无用的矛盾就是莫名其妙。
            AddTranslation("They turn a deaf ear to others' words.Talking past each other—sometimes useless conflicts are just senseless.", "于人言充耳不闻。鹅鸭异讲，徒争多无端耳。");
            // 地狱猫
            AddTranslation("Hellcat", "狱猫");
            // 燃狱之猫，踏火而行，凡敌所见，皆成焦土。
            AddTranslation("A cat of blazing hell, it walks upon fire;All foes who gaze upon it shall be reduced to scorched earth.", "燃狱之猫，蹈火而行；凡敌见之，皆为焦土。");
            // 仙人掌猫
            AddTranslation("Cactus cat", "仙掌猫");
            // 这种无法描述的造物注定无法与人类亲近。
            AddTranslation("Such indescribable creations are destined to be inaccessible to humans.", "此不可状之物，终不亲于人。");
            // 长老鹅与长老鸭
            AddTranslation("Elder Goose and Elder Duck", "长老鹅鸭");
            // 炼狱猫
            AddTranslation("Purgatory Cat", "炼狱猫");
            // 斗笠熊猫
            AddTranslation("Bamboo Hat Panda", "笠熊猫");
            // 不问世事，只醉竹香，斗笠下是熊猫的慵懒江湖。
            AddTranslation("Ignoring the affairs of the world, I only revel in the fragrance of bamboo; beneath the bamboo hat lies the panda's lazy jianghu.", "不问世事，惟醉竹香；笠下熊猫，自有慵江湖。");
            // 尝弃今昔
            AddTranslation("Chang Qi Jin Xi", "尝弃今昔");
            // 幽林狼
            AddTranslation("ShadoWood Wolf", "幽林狼");
            // 幽影潜行于林，风声即是它的脚步。
            AddTranslation("Shadows creep through the woods; the wind is its stride.", "幽影潜林，风即其步。");
            // 独角仙
            AddTranslation("Rhinoceros Beetle", "独角仙");
            // 铁甲覆身，双叉为锋，丛林中的无畏战将。
            AddTranslation("Clad in iron armor, armed with twin prongs,a fearless warrior of the woods.", "铁甲被身，双叉为锋，林中无畏之将也。");
            // 蚁卵
            AddTranslation("Ant Egg", "蚁卵");
            // 一枚被遗弃的蚁卵，一旦孵化，便能重返巢穴。
            AddTranslation("An abandoned ant egg, once hatched, can return to its home.", "弃蚁卵也，既孵，则可归巢。");
            // 白羽蟒
            AddTranslation("Feathered Serpent", "羽蛇");
            // 这蛇不来自于传统的世界，它的虚幻与存在难以辨别。
            AddTranslation("This snake does not belong to the ordinary world; its illusory nature and existence are indistinguishable.", "此蛇不属于凡世，其虚其实，莫可辨也。");
            // 羽蛇神
            AddTranslation("Quetzalcoatl", "羽蛇神");
            // 双生巨蜥
            AddTranslation("Twin Varanoids", "双生巨蜥");
            // 一对凶悍的巨型孪生蜥蜴，协同狩猎，带来双倍恐惧。
            AddTranslation("A matched pair of savage giant lizards, hunting together and bringing double the terror.", "双生巨蜥，并猎而倍其怖。");
            // 腾蛇
            AddTranslation("Aether Serpent", "腾蛇");
            // 翱翔于云海之间的仙兽灵蛇，不受凡俗束缚
            AddTranslation("Celestial serpent that soars through the clouds, untethered by earthly bounds.", "腾蛇凌云，不系尘壤。");
            // 菜喵喵
            AddTranslation("VeggieMew", "菜喵");
            // 谁家的小宠物跑出来了？
            AddTranslation("Whose pet is this that ran out?", "谁家小宠逸出乎？");
            // 菜呆呆
            AddTranslation("VeggieDull", "菜呆");

            // WLDLC-other
            // 胆小水松鼠
            AddTranslation("Cowardly Aquasquirrel", "怯水松鼠");
            // 脆弱松鼠
            AddTranslation("Frail Squirrel", "脆松鼠");
            // 病患山羊
            AddTranslation("Injured Goat", "伤羊");
            // 传说松鼠
            AddTranslation("Legendary Squirrel", "传奇松鼠");
            // 梦魇水松鼠
            AddTranslation("Nightmare Aquasquirrel", "魇水松鼠");
            // 荒野传说DLC：璀璨童话
            AddTranslation("DLC_Fairy_Tale", "荒野传奇DLC：绮童话");
            // 添加了一些基于神话、传说和虚构元素的卡牌。
            AddTranslation("Added some cards based on myths, legends, and fictional elements.", "益数牌，本乎神话、传说与虚构诸物。");
        }

    }

