            AddTranslation("eater", "食者");
            // 威克
            AddTranslation("wick", "威克");
            // 耶尔
            AddTranslation("yer", "耶尔");
            // 亚尔
            AddTranslation("yar", "亚尔");
            // 琼斯
            AddTranslation(" Jones", "琼斯");
            // 掘者
            AddTranslation("digger", "掘者");
            // 伊什
            AddTranslation("ish", "伊什");
            // 埃拉
            AddTranslation("erra", "埃拉");
            // 伊库斯
            AddTranslation("icus", "伊库斯");
            // 伊卡
            AddTranslation("ica", "伊卡");
            // 饥渴
            AddTranslation("starved", "饥");
            // 口
            AddTranslation("mouth", "口");
            // 吸盘
            AddTranslation("sucker", "吸者");
            // 大师
            AddTranslation("meister", "师");
            // 胡须
            AddTranslation("beard", "髯");
            // 树皮
            AddTranslation("bark", "木皮");
            // 肖
            AddTranslation("shaw", "肖");
            // 颌
            AddTranslation("jaw", "颌");
            // 牙齿
            AddTranslation("tooth", "齿");
            // 奥利
            AddTranslation("oli", "奥利");
            // 奥拉斯
            AddTranslation("olas", "奥拉斯");

            // Opponent
            // 朦胧的身影
            AddTranslation("Shadowy Figure", "幽影");
            // 钓鱼人
            AddTranslation("Angler", "渔父");
            // 毛皮商
            AddTranslation("Trader", "贾妇");
            // 猎人
            AddTranslation("Trapper", "猎夫");
            // 莱西
            AddTranslation("Leshy", "莱西");
            // 蔓尼菲科
            AddTranslation("Magnificus", "蔓尼菲科");
            // 格里魔拉
            AddTranslation("Grimora", "格里魔拉");
            // 索耶
            AddTranslation("Sawyer", "索耶");
            // 凯茜
            AddTranslation("Kaycee", "凯茜");
            // 罗亚尔
            AddTranslation("Royal", "罗亚尔");
            // 训练假人
            AddTranslation("Training Dummy", "习偶");
            // 沽伯特
            AddTranslation("Goobert", "黏伯特");
            // 长矛法师
            AddTranslation("Pike Mage", "矛巫");
            // 孤独巫师
            AddTranslation("Lonely Wizard", "孤巫");
            // 检查员
            AddTranslation("Inspector", "察者");
            // 熔炼员
            AddTranslation("Melter", "冶者");
            // 挖泥工
            AddTranslation("Dredger", "浚夫");
            // 矿工
            AddTranslation("Prospector", "采夫");
            // 钓鱼人
            AddTranslation("Angler", "渔父");
            // 猎人
            AddTranslation("Trapper", "猎夫");
            // 宝石质疑者印记阻止你使用该宝石
            AddTranslation("The gem skeptic sigil prevents you from playing that gem.", "疑玉之印，止汝陈彼玉。");
            // 生命值剩余3点及以下时才能使用此牌
            AddTranslation("You can't play that until you're 3 off dying.", "汝未去败三伤之内，不得陈此牌。");
            // 想用这张牌？先掉点血吧
            AddTranslation("You want to play that? Start losing.", "欲陈此牌乎？先自损。");
            // 天才，这牌不能用
            AddTranslation("You can't play it, genius.", "智者，此牌不可陈。");
            // 当前天平状态下无法使用此牌
            AddTranslation("You cannot play that card with the scales in this state.", "衡势如此，不得陈此牌。");
            // 此牌不可使用
            AddTranslation("You can't play that one.", "此牌不可陈。");
            // 恐怕这张牌被禁止了，亲爱的
            AddTranslation("I'm afraid that one's forbidden, dear.", "恐此牌已禁矣。");
            // 我不会允许你使用这张牌
            AddTranslation("I won't allow you to play that card.", "余不许汝陈此牌。");
            // 场上有宝石质疑者印记的造物时无法使用宝石牌！
            AddTranslation("You can't play a gem card while a creature with the Gem Skeptic sigil is on your side of the board!", "汝侧局有负疑玉印之物，则玉牌不可陈！");
            // 再受到3点或更少伤害即败北时才能使用此牌！
            AddTranslation("This card cannot be played unless you are three or less damage from losing!", "非汝去败三伤之内，此牌不可陈！");
            // 此牌无法使用
            AddTranslation("This card cannot be played.", "此牌不可陈。");
            // 两侧都被挡上了……
            AddTranslation("Blocked on both sides...", "左右皆塞……");

            // Ability
            // 吸收者
            AddTranslation("Absorber", "承伤者");
            // 若[creature]相邻的造物受到攻击，[creature]将获得等同于所受伤害值的生命。
            AddTranslation("If a creature adjacent to [creature] is struck, [creature] will gain health equal to the amount of damage dealt.", "邻[creature]之物见击，[creature]得命如所受之伤。");
            // [creature]不会主动攻击，除非被其他效果强制攻击
            AddTranslation("[creature] will not attack unless forced to attack by another effect.", "[creature]非为他效所迫，不击。");
            // 道具商
            AddTranslation("Trinket Bearer", "负器者");
            // 使用[creature]时，将为持牌人随机提供一个道具
            AddTranslation("When [creature] is played, it grants it's owner a random item.", "[creature]既陈，予厥主一偶器。");
            // [creature]掏出了一个随机道具
            AddTranslation("[creature] pulls out a random item.", "[creature]取出一偶器。");
            // 血之饵
            AddTranslation("Bloodbait", "血饵");
            // 消耗1点血量将[creature]收回手牌。
            AddTranslation("Pay 1 blood to return [creature] to your hand.", "费一血，返[creature]于汝手。");
            // 骨饲
            AddTranslation("Bonefed", "骨饲");
            // 消耗2根骨头为[creature]恢复最多3点生命值。
            AddTranslation("Pay 2 bones to heal [creature] for up to 3 health.", "费二骨，疗[creature]，命至多益三。");
            // 骨驱打击
            AddTranslation("Bone Strike", "骨击");
            // 消耗2根骨头对[creature]对面的造物造成1点伤害。
            AddTranslation("Pay 2 bones to deal 1 damage to the creature opposing [creature].", "费二骨，伤[creature]所对之物一。");
            // 盛宴之巢
            AddTranslation("Broodfeast", "巢宴");
            // 每回合限一次，消耗1点血量，在手牌中创造一张与[creature]完全相同的牌。
            AddTranslation("Once per turn, pay 1 blood to create a copy of [creature] in your hand.", "一合一度，费一血，于汝手生[creature]同牌。");
            // 食肉动物
            AddTranslation("Carnivore", "食肉");
            // 消耗2点血量使[creature]的力量增加3点。
            AddTranslation("Pay 2 blood to increase the power of [creature] by 3.", "费二血，使[creature]威益三。");
            // 因果关系
            AddTranslation("Causality", "因果");
            // 消耗1点货币触发随机效果：无效果、直接对对手造成1点伤害、使你一张卡牌的攻击力增加1，或使你一张卡牌的生命值增加1。
            AddTranslation("Pay 1 currency to trigger a random effect.", "费一币，发偶效：或无效，或直伤敌一，或使乃一牌威益一，或命益一。");
            // 宇宙似乎已然和谐……毫无变化。
            AddTranslation("The universe seems in harmony already... nothing changes.", "天地已和……无易也。");
            // 无事发生……
            AddTranslation("Nothing happened...", "无事……");
            // 没效果？哼，真扫兴。
            AddTranslation("Nothing? Huh, that's disappointing.", "无效乎？哼，可惋。");
            // 力量增益，算你走运……
            AddTranslation("Power buff, lucky you...", "威益，汝幸矣……");
            // 生命增益，本可以更强些……
            AddTranslation("Health buff, could be a lot better...", "命益，尚非上也……");
            // 你已重创了我……
            AddTranslation("You have dealt me a blow...", "汝已挫我……");
            // 你造成了1点直接伤害！
            AddTranslation("You dealt one direct damage!", "汝直伤我一！");
            // 看来完美操作也敌不过付费制胜机制
            AddTranslation("Guess playing a perfect game is no match for pay to win mechanics.", "无失之弈，亦不敌输财取胜之法。");
            // 精力费尽
            AddTranslation("Deadbeat", "力竭");
            // 选择牌桌上同侧的一只造物，该造物将当场阵亡。
            AddTranslation("Choose a creature on the same side of the board. That creature will perish.", "择局上同侧一物，彼物即死。");
            // 牌库汲取
            AddTranslation("Deck Drain", "汲牌");
            // 每回合最多3次，消耗1点血量从牌组随机抽取一张卡牌。
            AddTranslation("Up to 3 times per turn, pay 1 blood to draw a random card from your deck.", "一合至三度，费一血，自牌列偶引一牌。");
            // 疏浚囤积
            AddTranslation("Dredge", "疏浚");
            // 消耗4根骨头来搜索牌组中的任意卡牌并加入手牌。
            AddTranslation("Pay 4 Bones to search your deck for any card, and add it to your hand.", "费四骨，索乃牌列任一牌，入汝手。");
            // 逃脱
            AddTranslation("Escape", "逃");
            // 若你拥有一颗绿宝石，可将[creature]收回手牌。
            AddTranslation("If you have a green gem, return [creature] to your hand.", "若汝有绿玉，返[creature]于汝手。");
            // 永恒疾驰
            AddTranslation("Eternal Gallop", "永奔");
            // 使[creature]沿印记标注的方向移动。
            AddTranslation("Move [creature] in the direction inscribed on the sigil.", "令[creature]循印所志之向而移。");
            // 崇高古文
            AddTranslation("Exalted Rune", "崇文");
            // 消耗1点血量在手牌中生成“玛珂支柱”。玛珂支柱具有：0点力量，4点生命，玛珂印记，高跳。
            AddTranslation("Pay 1 blood to create a 'Mox Pillar' in your hand. A mox pillar is defined as: 0 power, 4 health, Mox Sigil, Mighty Leap.", "费一血，于汝手生“玛珂柱”。玛珂柱者：威零，命四，玛珂印，高跃。");
            // 公平交易
            AddTranslation("Fair Trade", "公易");
            // 消耗1张毛皮，移除对手场上的一个造物并加入你的手牌。
            AddTranslation("Pay 1 pelt to remove an opponent's creature from the board, and add it to your hand.", "费一革，去敌局上一物，入汝手。");
            // 骨驱冲刺
            AddTranslation("Fetch", "骨驱");
            // 消耗1根骨头使[creature]向印记标注的方向移动。
            AddTranslation("Pay 1 Bone to make [creature] move in the direction inscribed in the sigil.", "费一骨，令[creature]循印所志之向而移。");
            // 赌博按钮
            AddTranslation("Flip", "博命");
            // 50%概率消灭[creature]或使其力量与生命各+1。
            AddTranslation("50/50 chance to either kill [creature] or give it +1 power and health.", "五五之机，或杀[creature]，或使其威命各益一。");
            // 暴食
            AddTranslation("Gorge", "饱食");
            // 若[creature]生命值低于10点，消耗1点血量使其生命值+3。
            AddTranslation("If [creature] has less than 10 health, pay 1 blood to grant it +3 health.", "若[creature]命未十，费一血，使其命益三。");
            // 你已耗尽最后的箔片！
            AddTranslation("You spent the last of your foils!.", "乃末箔已费尽！");
            // 你还剩0张箔片
            AddTranslation("You have 0 foil remaining.", "汝余箔零。");
            // 你还剩1张箔片
            AddTranslation("You have 1 foil remaining.", "汝余一箔。");
            // 你的牙齿不够。
            AddTranslation("You do not have enough teeth.", "乃齿不足。");
            // 需要更多牙齿才能使用该能力。
            AddTranslation("You need more teeth to use that ability.", "齿尚不足以施此技。");
            // 你付不起这个代价
            AddTranslation("You cannot pay the cost", "汝无以偿此直。");
            // 你聋了吗？去赚点机器币。
            AddTranslation("Are you deaf? Get more Robobucks.", "汝聋乎？且多取机币。");
            // 我这里不是慈善机构，多带点钱来。
            AddTranslation("I'm not running a charity, get more money.", "余非施惠之所，多赍钱来。");
            // 没钱就别想要印记。
            AddTranslation("No robobucks, no sigil.", "无机币，则无印。");
            // 没门。
            AddTranslation("No dice.", "不可。");
            // 唔。
            AddTranslation("Hmm.", "唔。");
            // 你的牙齿不足以支付这个代价。
            AddTranslation("You do not have enough teeth to pay the cost.", "乃齿不足以偿此直。");
            // 想在战斗中使用这个能力，你得表现得更好些。
            AddTranslation("You'll need to perform better in battle if you wish to use that ability.", "欲施此技，战中当更善。");
            // 呃。
            AddTranslation("Ugh.", "呃。");
            // 想用那个印记就多带点机器币来，我这里概不赊账。
            AddTranslation("You need more Robobucks to use that sigil, and I don't give credit.", "欲施彼印，须益赍机币；余不贷。");
            // 等你稍微……嗯……阔绰些再来吧。
            AddTranslation("Come back when you're a little... mmm... richer.", "俟汝稍……嗯……富，乃复来。");
            // 挑食者
            AddTranslation("Picky Eater", "择食");
            // 消耗1点血量，抽取等同于被献祭造物生命值的骨头。
            AddTranslation("Pay 1 blood to draw bones equal to the health of the sacrificed creature.", "费一血，引骨，其数如所祀之物命。");
            // 沙包
            AddTranslation("Punching Bag", "沙囊");
            // 每回合可选择任意造物，该造物会对本卡造成1点伤害，随后本卡恢复1点生命。
            AddTranslation("Once per turn, choose any creature. That creature will strike this card for 1 damage. Afterwards, this card regains 1 health.", "一合一度，择任一物；彼物击此牌，伤一。其后此牌复一命。");
            // 移除按钮
            AddTranslation("Remove", "除");
            // 消灭[creature]。
            AddTranslation("Kill [creature].", "杀[creature]。");
            // 磨砺
            AddTranslation("Sharpen", "砺");
            // 若你拥有橙色玛珂，可献祭它使[creature]获得+1攻击力
            AddTranslation("If you have an orange mox gem, sacrifice it to give [creature] +1 attack power.", "若汝有橙玛珂，可祀之，使[creature]威加一。");
            // [creature]献祭橙色玛珂以磨砺其攻击！
            AddTranslation("[creature] sacrifices an orange gem to sharpen it's attack!", "[creature]祀橙玉，以砺其击！");
            // 咒术之剑
            AddTranslation("Spellsword", "术剑");
            // 与[creature]同侧的牌桌上所有宝石获得2点力量、发动攻击后阵亡。
            AddTranslation("All gems on the same side of the board as[creature] gain 2 power, attack, and perish.", "与[creature]同侧局上诸玉，威益二，出击而死。");
            // 飞行能手
            AddTranslation("Trained Flier", "习翔");
            // 使[creature]获得空袭印记效果直至下次维持阶段。若该卡已具有空袭印记，则暂时移除该效果直至下次维持阶段。
            AddTranslation("Grant [creature] the effect of the Airborne sigil until next upkeep. If the card already has Airborne, this will remove it's effect until next upkeep.", "使[creature]至次合始得翔袭印契；若此牌素有之，则反去其效至次合始。");
            // 游泳能手
            AddTranslation("Trained Swimmer", "习潜");
            // 该造物将获得水袭印记的效果，持续一回合。
            AddTranslation("Creature will gain the effect of the Waterborne sigil for one turn.", "[creature]一合得潜袭印契。");
            // 升级子程序
            AddTranslation("Upgrade Subroutine", "升程");
            // 当[creature]摧毁其他机器人时，可获得1点升级点数。激活时，持牌人可从三个印记中选择一个永久强化该卡牌。选择印记会消耗点数，激活时积累的点数越多，提供的印记品质越高。
            AddTranslation("When[creature] destroys another bot, this gains 1 point. When activated, the owner is presented with a choice of three sigils to permanently augment the card. Selecting a sigil spends points, and the more points accumulated when the sigil is activated, the higher quality the presented sigils will be.", "凡[creature]毁他机人，则积一点。启之，则持牌者于三印契中择一，以永益此牌。择印耗点；积点愈多，则所示印契愈良。");
            // 蛰刺握
            AddTranslation("Aculeate Grip", "螫攫");
            // 当有造物被放置在与[creature]同侧的牌桌时，[creature]会尽可能向其移动，对其造成1点伤害并增加自身1点生命值。
            AddTranslation("When a creature is played on the same side of the board as [creature], [creature] will move towards them as far as possible, dealing them one damage and increasing it's own health by 1.", "他物既陈于与[creature]同侧之局，[creature]即尽所能趋之，伤彼一，而自命益一。");
            // 媚骨天生
            AddTranslation("Allure", "媚引");
            // 回合结束时，[creature]会将对方造物吸引至自己正前方。
            AddTranslation("At the end of the round, [creature] will draw opposing creatures in front of itself.", "每轮终，[creature]引敌物于其前。");
            // 湮灭
            AddTranslation("Annihilation", "殄灭");
            // 当[creature]阵亡时，牌桌上所有造物均受到10点伤害
            AddTranslation("When [creature] perishes, all creatures on the board are dealt 10 damage.", "[creature]死，则局上诸物皆受十伤。");
            // 蚂蚁守护者
            AddTranslation("Ant Guardian", "护蚁");
            // 当友方蚂蚁遭受攻击时，[creature]会以自身攻击力对攻击者造成等量伤害。
            AddTranslation("[creature] will deal damage equal to it's attack power to any card which strikes a friendly ant.", "己蚁见击，则[creature]以其威伤击者。");
            // 反魔法
            AddTranslation("Antimagic", "反术");
            // 当[creature]在场时，任何打出的玛珂宝石会立即消亡。[creature]会移动到被摧毁宝石的位置，获得1点生命值并立即攻击。
            AddTranslation("Any mox gems played while [creature] is on the board will immediately perish. [creature] will move to the position of the destroyed gem, gain 1 health, and immediately attack.", "凡[creature]在局，所陈玛珂玉即死。[creature]移据其毁玉之处，命益一，而即击。");
            // [creature]摧毁了打出的宝石！
            AddTranslation("[creature] destroys the played gem!", "[creature]毁其所陈之玉！");
            // 装甲化
            AddTranslation("Armortify", "被甲");
            // 当[creature]击杀对面造物时，该卡牌将获得身披坚甲印记。
            AddTranslation("When [creature] attacks an opposing creature and it perishes, this card gains the armored sigil.", "[creature]击杀敌物，则此牌得坚甲印契。");
            // 艺术许可
            AddTranslation("Artistic License", "艺纵");
            // 当打出[creature]时，其对面的造物将失去所有印记。
            AddTranslation("When [creature] is played, the creature opposing it loses all sigils.", "[creature]既陈，其对物失其诸印。");
            // 想偷老子的印记？你这扫兴的混账！
            AddTranslation("Trying to plunder me sigils? Yer a sour spoilsport!", "欲掠我印耶？汝真败兴之徒！");
            // 纵使技艺精湛，月之魂仍不可撼动……
            AddTranslation("Despite your artistry, the soul of the moon is impervious...", "虽工于艺，然月魂不可犯……");
            // 数据备份
            AddTranslation("Backup", "后继");
            // 当[creature]在战斗中阵亡时，其持有者手牌中的第一张卡牌将自动补位。
            AddTranslation("When [creature] perishes by combat, the first card in it's owner's hand is played in it's place.", "[creature]战死，则持牌者手中首牌代居其处。");
            // [creature]呼叫了后备支援
            AddTranslation("[creature] calls in backup.", "[creature]召后继矣。");
            // 绷带编织者
            AddTranslation("Bandage Weaver", "纫帛者");
            // 回合结束时，[creature]会为左右两侧的卡牌各恢复1点生命值。
            AddTranslation("At the end of the turn,[creature] will heal the cards to it's left and right for 1 health.", "合终，[creature]疗左右诸牌各一命。");
            // 堡垒
            AddTranslation("Bastion", "垒");
            // 当[creature]受到伤害时，实际承受的伤害值减半（向上取整）。
            AddTranslation("When [creature] recieves damage, it only takes half the damage it normally would, rounded up.", "[creature]受伤，所受惟常半，分奇则进一。");
            // 批量删除
            AddTranslation("Batch Delete", "并删");
            // 当[creature]击杀目标造物时，牌桌上所有与该目标费用相同的造物都会阵亡。
            AddTranslation("When [creature] strikes a creature and it perishes, any creatures on the board which share the same cost as the target perish also.", "[creature]击物而杀之，则局上凡与其同直之物亦皆死。");
            // [creature]会粉碎所有与受害者费用相同的卡牌。
            AddTranslation("[creature] shreds any other cards with the same cost as it's victim...", "[creature]尽裂诸与所害者同直之牌……");
            // 宝石迷阵
            AddTranslation("Bejeweled", "连玉");
            // 当[creature]在场时，若同色宝石三连成线，则移除这些宝石。与之对阵的造物也将被移除，对手将受到等同于这些造物总攻击力的直接伤害。
            AddTranslation("While [creature] is on the field, lining up three gems of the same colour will remove those gems from the field. Any creatures which opposed those gems will be removed as well, and the opponent will take damage directly equal to their combined attack power. ", "凡[creature]在局，三同色之玉若成列，则去此诸玉。凡与之相对之物亦去之；敌并直受其合威之伤。");
            // 扑朔迷离
            AddTranslation("Bewilder", "惑");
            // 当使用[creature]时，其持牌人可选择任意造物，互换该造物的力量与生命。
            AddTranslation("When [creature] is played, it's owner may choose any creature. Swap that creatures power and health.", "[creature]既陈，持牌者可择一物，而易其威与命。");
            // 橙色兵分
            AddTranslation("Bifurcated When Gempowered", "得玉歧击");
            // 若持牌人拥有橙宝石，[creature]会攻击正对面的左右两侧位置各一次。
            AddTranslation("If its owner has an Orange Gem, [creature] will strike each opposing space to the left and right of the space across from it.", "若持牌者有橙玉，[creature]击其正对之左与右。");
            // 二分法
            AddTranslation("Bisection", "二裂");
            // 当[creature]击杀其他造物时，会在持牌人手中生成两张力量归零、生命值减半的受害者复制卡牌。
            AddTranslation("When [creature] kills another creature, two copies of the victim are created in the owner's hand with zero power and halved health.", "[creature]杀他物，则持牌者手中生受害者之同牌二，威皆为零，而命半之。");
            // 漂白剂
            AddTranslation("Bleach", "漂液");
            // 当[creature]被打出时，所有敌方造物将失去全部印记。
            AddTranslation("When [creature] is played, all opponent creatures lose all sigils.", "[creature]既陈，敌诸物尽失其诸印。");
            // 肥美多汁
            AddTranslation("Bloated", "丰血");
            // [creature]在献祭时可算作等同于其生命值的血量。
            AddTranslation("[creature] is worth blood equal to its health when sacrificed.", "[creature]祀时，其值血如其命。");
            // 血液艺术家
            AddTranslation("Blood Artist", "血绘者");
            // 当牌桌上有[creature]时，每有三张卡牌因战斗阵亡，[creature]将为持牌人制作一张由这些造物的费用、属性和印记构成的死亡卡。
            AddTranslation("Every three cards which perish by combat while [creature] is on the board, [creature] will give it's owner a deathcard constructed from the cost, stats, and sigils of those creatures.", "凡[creature]在局，战死之牌每三，则[creature]为持牌者作一死牌，因其诸物之直、数与印契而成之。");
            // [creature]会根据先前阵亡造物制作死亡卡……
            AddTranslation("[creature] constructs a deathcard from previous creatures deaths...", "[creature]因先死诸物而作一死牌……");
            // 当[creature]被献祭时，它会切换形态而非阵亡。
            AddTranslation("When [creature] is sacrificed, it transforms to or from it's alternate form instead of perishing.", "[creature]祀之，则不死，而与其异相相易。");
            // 血液依赖
            AddTranslation("Blood Dependent", "恃血");
            // 若[creature]在攻击阶段未能击中其他造物，则会在持牌人下个回合开始时阵亡。
            AddTranslation("If [creature] does not strike another creature during the attack phase, it will perish at the start of the owner's next turn.", "若[creature]攻时不击他物，则持牌者次合始必死。");
            // 石中取血
            AddTranslation("Blood From Stone", "石出血");
            // 你可以献祭地形卡来打出[creature]。
            AddTranslation("You may sacrifice terrain cards in order to play [creature].", "可祀地形牌，以陈[creature]。");
            // 鲜血喷涌
            AddTranslation("Blood Gusher", "涌血");
            // 当[creature]击杀对面造物时，该卡牌及其左右相邻的造物各恢复1点生命。
            AddTranslation("When [creature] attacks an opposing creature and it perishes, this card, as well as creatures to the left and right of this card, gain 1 health.", "[creature]击杀敌物，则此牌与左右邻物各命益一。");
            // 鲜血吞噬者
            AddTranslation("Blood Guzzler", "嗜血");
            // 当[creature]对造物造成伤害时，每造成1点伤害即恢复1点生命。
            AddTranslation("When[creature] deals damage to a creature, it gains 1 Health for each damage dealt.", "[creature]出伤之时，每伤一，则命益一。");
            // [creature]吸食着猎物的鲜血！
            AddTranslation("[creature] consumes the blood of its prey!", "[creature]饮其猎之血！");
            // 血魔法
            AddTranslation("Blood Magic", "血术");
            // 当[creature]在场时，其持牌人可以献祭任意宝石，即使这些宝石通常无法被献祭。
            AddTranslation("While [creature] is on the field, its owner may sacrifice any gems, even if those gems normally cannot be sacrificed.", "凡[creature]在局，持牌者可祀诸玉；纵其常不可祀，亦可。");
            // 血行者
            AddTranslation("Bloodrunner", "血行");
            // 当[creature]对造物造成伤害时，它将朝印记标注的方向移动。
            AddTranslation("When [creature] deals damage to a creature, it will move in the direction inscribed in the sigil.", "[creature]伤物，则循印所志之向而移。");
            // 蓝色灵感
            AddTranslation("Blue Inspiration", "蓝悟");
            // 当牌桌上有[creature]时，所有以蓝宝石为费用的友方造物登场时将获得随机印记。
            AddTranslation("While [creature] is on the board, all friendly creatures which cost a blue gem will gain a random sigil when played.", "凡[creature]在局，己物凡直蓝玉者既陈，皆得一偶印契。");
            // [creature]为以蓝宝石为费用的造物赋予随机印记！
            AddTranslation("[creature] empowers the Blue Gem cost creature with a random sigil!", "[creature]使一直蓝玉之物得一偶印契！");
            // 爆弹咒
            AddTranslation("Bombjuration", "爆召");
            // 使用[creature]时，持牌人可选择牌桌任意一侧的空位，在该位置生成一枚魔法爆弹。
            AddTranslation("When [creature] is played, it's owner may choose an empty slot on either side of the board. A magic bomb is created in the chosen slot.", "[creature]既陈，持牌者可择局中一空位，生一法爆于其所。");
            // 炸弹空投
            AddTranslation("Bombs Away", "投爆");
            // 使用[creature]时，对面位置会出现一个有效载荷。[define:SigilNevernamed Payload]
            AddTranslation("When [creature] is played, a Payload is created in the opposing slot. [define:SigilNevernamed Payload]", "[creature]既陈，则其对位生一载荷。[define:SigilNevernamed Payload]");
            // [creature]向对面位置空投了一个有效载荷！
            AddTranslation("[creature] drops a payload into the opposing slot!", "[creature]投一载荷于其对位！");
            // 骨头依赖
            AddTranslation("Bone Dependent", "恃骨");
            // 若使用者骨头数为零，[creature]将立即阵亡。
            AddTranslation("If the user has 0 Bones, [creature] will perish.", "若持牌者无骨，[creature]即死。");
            // 骨公爵
            AddTranslation("Bone Duke", "骨公");
            // [creature]死亡时，原本获得的1根骨头将变为3根。
            AddTranslation("When [creature] dies, 3 Bones are awarded instead of 1.", "[creature]死，则所得之骨不一而三。");
            // 骨欲
            AddTranslation("Bonelust", "嗜骨");
            // 当[creature]击杀其他造物时，为持牌人生成3根骨头。
            AddTranslation("When [creature] kills another creature, it generates 3 bones for its owner.", "[creature]杀他物，则为持牌者生三骨。");
            // 骨刺
            AddTranslation("Bone Spurs", "骨刺");
            // [creature]被攻击时，将为持牌人产生1根骨头。
            AddTranslation("When [creature] is struck, it generates a bone for it's owner.", "[creature]见击，则为持牌者生一骨。");
            // [creature]会在攻击时优先选择对面力量最低的卡牌。
            AddTranslation("[creature] will target the least powerful opposing card when it attacks.", "[creature]攻时，先击敌牌威最寡者。");
            // 燃烧
            AddTranslation("Burning", "焚");
            // 持牌人回合结束时，[creature]会受到1点伤害。此外，当[creature]被攻击时，攻击者会获得该印记。
            AddTranslation("At the end of the owner's turn, [creature] takes 1 damage. Also, when [creature] is struck, the striker gains this sigil.", "持牌者合终，[creature]受一伤；其见击也，击者亦得此印契。");
            // 蜉蝣冲击
            AddTranslation("Buzz Off", "遗蜉");
            // 持牌人回合结束时，[creature]将向印记标注的方向移动，并在原地留下一只蜉蝣。蜉蝣定义为1点力量、1点生命值、具有飞行与脆弱特性。
            AddTranslation("At the end of the owner's turn, [creature] will move in the direction inscribed in the sigil and leave a mayfly in it's old place. A mayfly is defined as 1 power, 1 health, airborne, brittle.", "持牌者合终，[creature]循印所志之向而移，并遗一蜉蝣于故处。蜉蝣者：1威、1命、翔袭、脆骨。");
            // 号召行动
            AddTranslation("Call To Arms", "号战");
            // 当使用[creature]时，其左右两侧的造物会立即发起攻击。
            AddTranslation("When [creature] is played, the creatures to it's left and right will immediately attack.", "[creature]既陈，其左右之物即击。");
            // 牌堆剥离者
            AddTranslation("Card Shedder", "遗牌");
            // 持牌人回合结束时，[creature]将向印记标注的方向移动，并在其经过之处留下一张卡牌。
            AddTranslation("At the end of the owner's turn, [creature] will move in the direction inscribed in the sigil and leave a card in it's wake.", "持牌者合终，[creature]循印所志之向而移，并遗一牌于其后。");
            // 物腐毒生
            AddTranslation("Caustic", "腐毒");
            // 当[creature]阵亡时，击杀它的造物也会随之阵亡。
            AddTranslation("When [creature] perishes, it's killer perishes as well.", "[creature]死，则杀之者亦死。");
            // 中心打击
            AddTranslation("Center Strike", "中击");
            // [creature]会攻击除最左和最右路线外的所有对手位置。
            AddTranslation("[creature] will attack all opponent slots except for those in the leftmost and rightmost lanes.", "[creature]击诸敌位，惟最左与最右之列不击。");
            // 混沌打击
            AddTranslation("Chaos Strike", "乱击");
            // 抽到[creature]时，此印记将被随机替换为一个打击强化类印记。
            AddTranslation("When [creature] is drawn, this sigil is replaced by a random strike modifier sigil.", "[creature]既引，此印契偶易为一击类印契。");
            // 欺诈者
            AddTranslation("Cheater", "诈者");
            // 当[creature]击杀对面造物时，对手将受到1点伤害。
            AddTranslation("When [creature] attacks an opposing creature and it perishes, the opponent is dealt 1 damage.", "[creature]攻敌物而杀之，则其主受1伤。");
            // 电路绘制
            AddTranslation("Circuit Maker", "成路");
            // 使用[creature]时，其左右两侧会各生成一张导线卡牌。
            AddTranslation("When [creature] is played, a conduit card is created to its left and right.", "[creature]既陈，左右各生一渠牌。");
            // 利爪
            AddTranslation("Claw", "爪");
            // 若[creature]未与带有利喙尖爪印记的卡牌直接相邻，将失去所有攻击力。
            AddTranslation("[creature] will lose all attack power if it is not directly adjacent to a card bearing the clawed sigil.", "若[creature]不与负爪印之牌邻，则尽失其威。");
            // 利喙尖爪
            AddTranslation("Clawed", "生爪");
            // 当打出[creature]时，会在左右两侧生成利爪，该位置的任何造物将被消灭。
            AddTranslation("When [creature] is played, claws are created to the left and right. Any creatures in those spaces will be killed.", "[creature]既陈，左右生爪；其位凡物，皆死。");
            // 利爪之手
            AddTranslation("Clawing Hand", "爪手");
            // 当[creature]被攻击时，攻击者会受到等同于持牌人手牌数的伤害。
            AddTranslation("When [creature] is struck, the striker is dealt damage equal to the number of cards in the owner's hand.", "[creature]受击，则击者受持牌者手牌数之伤。");
            // 劈裂
            AddTranslation("Cleaving", "劈裂");
            // 当[creature]攻击另一只造物时，该造物会被劈成两半。其中一半会向右移动，另一半则留在原位。
            AddTranslation("When [creature] strikes another creature, that creature will be cut in half. Half of the creature will move to the right, while the other half remains in place.", "[creature]击物，则劈之为二：其一右移，其一故处。");
            // [creature]将目标劈成了两半！
            AddTranslation("[creature] cleaves it's target in half!", "[creature]劈其的为二！");
            // 海岸警卫
            AddTranslation("Coastguard", "海卫");
            // 在对手回合潜入水下。当对手造物被放置于空位对面时，[creature]会在潜水状态下移动至该空位。
            AddTranslation("Submerges during the opponent's turn. When an opposing creature is placed opposite to an empty space, [creature] will move to that empty space while submerged.", "敌合则潜。若敌物陈于空位之对，[creature]潜而移据其空位。");
            // 连带伤害
            AddTranslation("Collateral Damage", "旁伤");
            // 持牌人回合结束时，若[creature]在场，距离此卡最近的造物将受到10点伤害。
            AddTranslation("At the end of the owner's turn, if [creature] is on the board, the nearest creature to this card will be dealt ten damage.", "持牌者合终，若[creature]在场，则距此牌最近之物受10伤。");
            // 收藏家
            AddTranslation("Collector", "敛者");
            // 持牌人回合结束时，[creature]将向印记标注的方向移动。沿途的造物会被收回持牌人手中。
            AddTranslation("At the end of the owner's turn,[creature] will move in the direction inscribed on the sigil. Creatures in the way will be returned to the owner's hand.", "持牌者合终，[creature]循印所志而移。道中诸物，皆返其主持手。");
            // 指挥官
            AddTranslation("Commander", "将令");
            // 当[creature]被攻击时，其左右两侧的造物会反击攻击者。
            AddTranslation("When [creature] is struck, the creatures to it's left and right will attack the striker.", "[creature]受击，则其左右之物皆攻击者。");
            // 充能双击
            AddTranslation("Double Strike When Powered", "得能双击");
            // 如[creature]处在回路中，则会在攻击时额外攻击对面位置一次。
            AddTranslation("If [creature] is within a circuit, it will strike the opposing space an additional time when it attacks.", "若[creature]在回路中，则攻时加击其对位一次。");
            // 充能奖励
            AddTranslation("Gift When Powered", "得能赐");
            // 如[creature]阵亡时处在回路中，则会给你随机增加一张手牌。
            AddTranslation("If [creature] is within a circuit when it perishes, a random card is created in your hand.", "若[creature]死时在回路中，则于汝手生一随机牌。");
            // 充能一口之量
            AddTranslation("Morsel When Powered", "得能一脔");
            // 当[creature]在完整回路中被献祭时，其状态值会附加至献祭目标卡牌。
            AddTranslation("When[creature] is sacrificed while inside a completed circuit, ⁣it adds its stat values to the card it was sacrificed for.", "[creature]在成路中见祀，则以其威命附于所祀之牌。");
            // 充能全向打击
            AddTranslation("Omnipotent When Powered", "得能遍击");
            // 如[creature]处在回路中，攻击时将打击对面所有存在卡牌的空间。若没有造物阻挡或不在回路中，[creature]将直接攻击。
            AddTranslation("If [creature] is within a circuit, it will strike every opposing space containing a card when it attacks. [creature] will strike directly if no creatures oppose it, or if it is not in a circuit.", "若[creature]在回路中，则攻时遍击敌侧有牌之位。若前无物，或不在回路中，则直击。");
            // 充能双重刺甲
            AddTranslation("Powered Quills", "得能利棘");
            // 当[creature]处在完整回路中受到攻击时，攻击者会受到2点伤害。
            AddTranslation("When [creature] is struck while inside a completed circuit, the striker is dealt 2 damage.", "[creature]在成路中受击，则击者受2伤。");
            // 充能玛珂绘制
            AddTranslation("Print When Powered", "得能印玉");
            // 若[creature]处于完整回路中，持牌人回合开始时其手牌中将生成一颗玛珂宝石。
            AddTranslation("If [creature] is inside a completed circuit, a gem will be created in its owners hand at the start of their turn.", "若[creature]在成路中，持牌者合始，于其手生一玉。");
            // [creature]为持有者印出一颗玛珂宝石！
            AddTranslation("[creature] prints a mox gem for its owner!", "[creature]为其主印出一玉！");
            // 充能厌恶情绪
            AddTranslation("Repulsive When Powered", "得能可憎");
            // 当[creature]处于回路中时，其他造物将无法对其发起攻击。
            AddTranslation("While [creature] is within a conduit, if another creature would strike it, it does not.", "[creature]在回路中，则他物欲击之而不能。");
            // 充能拾荒
            AddTranslation("Scavenge When Powered", "得能拾荒");
            // 当[creature]处于完整回路中时，敌方造物死亡时也会提供骨头。
            AddTranslation("While [creature] is inside a completed circuit, opposing creatures also grant Bones upon death.", "[creature]在成路中，则敌物死亦授骨。");
            // 充能溅射
            AddTranslation("Splash Damage When Powered", "得能溅伤");
            // 当[creature]处在回路中攻击某个位置时，被攻击位置左右两侧的造物均会受到1点伤害。
            AddTranslation("While [creature] is within a conduit when it strikes a slot, creatures to the left and right of the struck slot will be dealt 1 damage.", "[creature]在回路中击一位时，其所击位左右诸物各受1伤。");
            // 充能刺激
            AddTranslation("Stimulate When Powered", "得能激哉");
            // 当[creature]处于完整回路中时，持牌人回合开始时其生命值增加2点。
            AddTranslation("While [creature] is inside a completed circuit, it gains 2 health at the start of its owners turn.", "[creature]在成路中，则持牌者合始，其命加2。");
            // [creature]强化了生命值！
            AddTranslation("[creature] stimulates its health!", "[creature]益其命矣！");
            // 空袭契约
            AddTranslation("Billowing Bond", "翔契");
            // 处在由[creature]构成的契约中的造物会在每回合开始时获得飞行能力。
            AddTranslation("Creatures within a bond completed by [creature] gain the power of flight at the start of each turn.", "[creature]所成契中之物，每合始皆得飞。");
            // 宝石骷髅管道
            AddTranslation("Elder Conduit", "玉骨渠");
            // 当处在由[creature]构成的回路中的造物阵亡时，会在其位置生成一个宝石骷髅。
            AddTranslation("When a creature within a circuit completed by [creature] perishes, a Gem Skeleton will be created in it's place.", "凡在[creature]所成回路中而死之物，其处生一玉骨。");
            // [creature]用古老魔法召唤出了宝石骷髅
            AddTranslation("[creature] calls forth a Gem Skeleton with the old magics!", "[creature]以古术召一玉骨！");
            // 绿宝石管道
            AddTranslation("Emerald Conduit", "绿玉渠");
            // 如果[creature]参与构成一条完整回路，其持牌人将额外控制一颗绿宝石。
            AddTranslation("If [creature] is part of a completed circuit, its owner gains a green gem.", "若[creature]与成路，其主持有一绿玉。");
            // [creature]构成完整回路，并为持牌人提供一颗绿宝石！
            AddTranslation("[creature] completes a circuit, and grants its owner a green gem!", "[creature]成一回路，而授其主一绿玉！");
            // [creature]不再构成回路，也不再提供绿宝石！
            AddTranslation("[creature] no longer completes a circuit, and no longer grants a green gem!", "[creature]不复成回路，亦不复授绿玉！");
            // 友谊契约
            AddTranslation("Friendship Bond", "友契");
            // 由[creature]构成的契约中的空位将在持牌人回合结束时生成松鼠。
            AddTranslation("Empty spaces within a bond completed by [creature] spawn Squirrels at the end of the owner's turn.", "[creature]所成契中之空位，持牌者合终皆生松鼠。");
            // 掘骨管道
            AddTranslation("Grave Conduit", "骨渠");
            // 构成回路。持牌人回合结束时，[creature]会为回路中的每个造物生成1根骨头。
            AddTranslation("Completes a circuit. At the end of the owner's turn, [creature] will generate one bone for each creature contained within the circuit it completes.", "成回路。持牌者合终，[creature]以其所成回路中每物各生一骨。");
            // [creature]会为回路中的每个造物提供1根骨头
            AddTranslation("[creature] grants a bone for every creature in it's circuit.", "[creature]为其回路中每物授一骨。");
            // 哨兵管道
            AddTranslation("Gun Conduit", "铳渠");
            // 当造物进入由[creature]构成的回路中卡牌对面的位置时，该造物会受到1点伤害。
            AddTranslation("When a creature moves into the slot opposing a card in a circuit completed by [creature], the moved creature is dealt 1 damage.", "凡物入于[creature]所成回路中牌之对位，则彼物受1伤。");
            // [creature]的枪先发制人
            AddTranslation("[creature] takes a free shot!", "[creature]得一先击！");
            // 灼热管道
            AddTranslation("Hot Conduit", "灼渠");
            // 当处在由[creature]构成的回路中的造物被攻击时，攻击者将获得燃烧印记。此外，该卡牌回路中的造物不会受到燃烧印记的伤害。
            AddTranslation("When a creature within a circuit completed by [creature] is struck, the striker gains the Burning Sigil. Also, creatures within this card's circuit do not take damage from the Burning sigil.", "在[creature]所成回路中之物受击，则击者得燃印；且此回路中诸物不受燃印之伤。");
            // 劫掠管道
            AddTranslation("Loot Conduit", "掠渠");
            // 构成回路。在持牌人回合开始时，[creature]会为回路中每个空位抽取1张牌加入持牌人手牌。
            AddTranslation("Completes a circuit. At the start of the owner's turn, [creature] will draw 1 card to the owners hand for every empty space in the circuit it completes.", "成回路。持牌者合始，[creature]以其所成回路中每空位各抽一牌入主手。");
            // [creature]为回路中每个空位抽取一张牌！
            AddTranslation("[creature] draws a card for every empty space in it's circuit!", "[creature]为其回路中每空位各引一牌！");
            // 故障管道
            AddTranslation("Malfunctioning Conduit", "故渠");
            // 构成回路。持牌人回合结束时，随机从手牌选取卡牌置入由[creature]构成的回路空位，并获得燃烧印记。
            AddTranslation("Completes a circuit. At the end of its owner's turn, random cards from its owners hand will be played in random spaces inside of the circuit completed by [creature]. Those cards gain the Burning Sigil.", "成回路。持牌者合终，自其手随机取牌，置于[creature]所成回路之空位；彼牌并得燃印。");
            // [creature]将卡牌吸入回路中！
            AddTranslation("[creature] draws cards into it's circuit!", "[creature]引牌入其回路！");
            // 空无契约
            AddTranslation("Meaningless Bond", "虚契");
            // [creature]可构成契约，但无任何额外效果。
            AddTranslation("[creature] may complete a bond, but provides no additional effect.", "[creature]可成契，而别无所效。");
            // 纳米管道
            AddTranslation("Nano Conduit", "甲渠");
            // 持牌人回合结束时，处在由[creature]构成的回路中的造物将获得纳米护盾印记。
            AddTranslation("At the end of its owners turn, creatures within a circuit completed by [creature] gain the Armored sigil.", "持牌者合终，凡在[creature]所成回路中之物皆得甲印。");
            // [creature]为回路中的所有造物提供护盾！
            AddTranslation("[creature] shields all creatures in its circuit!", "[creature]护其回路中诸物矣！");
            // 红宝石管道
            AddTranslation("Ruby Conduit", "红玉渠");
            // 如果[creature]参与构成一条完整回路，其持牌人将额外控制一颗橙宝石。
            AddTranslation("If [creature] is part of a completed circuit, its owner gains an orange gem.", "若[creature]与成路，其主持有一红玉。");
            // [creature]构成回路，并为持牌人提供一颗橙宝石！
            AddTranslation("[creature] completes a circuit, and grants its owner an orange gem!", "[creature]成一回路，而授其主一红玉！");
            // [creature]不再构成回路，且不再提供橙宝石！
            AddTranslation("[creature] no longer completes a circuit, and no longer grants an orange gem!", "[creature]不复成回路，亦不复授红玉！");
            // 蓝宝石管道
            AddTranslation("Sapphire Conduit", "蓝玉渠");
            // 如果[creature]参与构成一条完整回路，其持牌人将额外控制一颗蓝宝石。
            AddTranslation("If [creature] is part of a completed circuit, its owner gains a blue gem.", "若[creature]与成路，其主持有一蓝玉。");
            // [creature]构成回路，并为持牌人提供一颗蓝宝石！
            AddTranslation("[creature] completes a circuit, and grants its owner a blue gem!", "[creature]成一回路，而授其主一蓝玉！");
            // [creature]不再构成回路，也不再提供蓝宝石！
            AddTranslation("[creature] no longer completes a circuit, and no longer grants a blue gem!", "[creature]不复成回路，亦不复授蓝玉！");
            // 刺激管道
            AddTranslation("Stim Conduit", "激渠");
            // 持牌人回合结束时，处在由[creature]构成的回路中的造物增加1点生命值。
            AddTranslation("At the end of its owners turn, creatures within a circuit completed by [creature] gain 1 Health.", "持牌者合终，凡在[creature]所成回路中之物命加1。");
            // [creature]提升了回路中所有造物的生命值！
            AddTranslation("[creature] increases the health of every creature in it's circuit!", "[creature]益其回路中诸物之命矣！");
            // 温柔契约
            AddTranslation("Tender Bond", "柔契");
            // 由[creature]构成的契约中的造物会在持牌人回合开始时恢复全部生命值。
            AddTranslation("Creatures within a bond completed by [creature] heal to full health at the start of the owner's turn.", "[creature]所成契中之物，持牌者合始皆复其全命。");
            // 尖刺管道
            AddTranslation("Thorny Conduit", "棘渠");
            // 处在由[creature]构成的回路中的造物被攻击时，攻击者也会受到1点伤害
            AddTranslation("When a creature within a circuit completed by [creature] is struck, the striker is then dealt a single damage point.", "在[creature]所成回路中之物受击，则击者亦受1伤。");
            // 颠三倒四
            AddTranslation("Confusion", "乱");
            // 当[creature]被放置在对面的造物对面时，交换该造物的力量与生命。
            AddTranslation("When [creature] is played opposite an opponents creature, swap that creatures power and health.", "[creature]陈于敌物之对，则易彼物之威与命。");
            // [creature]对面的卡牌陷入混乱！
            AddTranslation("The card opposing [creature] is confused!", "[creature]对位之牌乱矣！");
            // 影印设备
            AddTranslation("Copier", "摹印");
            // [creature]阵亡时，你的手牌里会出现一张杀害它的造物的复制品。
            AddTranslation("When [creature] perishes, a copy of it's murderer is created in your hand.", "[creature]死，则于汝手生一杀之者之副本。");
            // 贪生怕死
            AddTranslation("Coward", "怯");
            // 当[creature]成为攻击目标时，它会跃开躲避。
            AddTranslation("When [creature] is targeted, it will leap out of the way.", "[creature]为攻击所指，则跃而避之。");
            // 偏左打击
            AddTranslation("Crooked Strike Left", "偏左击");
            // [creature]会攻击其预定目标左侧的位置。
            AddTranslation("[creature] will attack the space to the left of it's intended target.", "[creature]攻其所向之左位。");
            // 偏右打击
            AddTranslation("Crooked Strike Right", "偏右击");
            // [creature]会攻击其预定目标右侧的位置。
            AddTranslation("[creature] will attack the space to the right of it's intended target.", "[creature]攻其所向之右位。");
            // 十字骨
            AddTranslation("Crossbones", "十字骨");
            // 当使用[creature]时，能为持牌人提供2根骨头。
            AddTranslation("When [creature] is played, it grants 2 bones to it's owner.", "[creature]既陈，则授其主2骨。");
            // 酥脆
            AddTranslation("Crunchy", "脆");
            // 当[creature]被献祭时，将为持牌人产生1根骨头。
            AddTranslation("When [creature] is sacrificed, it generates one bone for its owner.", "[creature]见祀，则为其主生1骨。");
            // 可爱
            AddTranslation("Cute", "可人");
            // 攻击[creature]的造物会产生愧疚感，并跳过下一次攻击。
            AddTranslation("Creatures that strike [creature] feel guilty, and will skip their next strike.", "击[creature]之物怀愧，而后一击遂阙。");
            // 数据泄露
            AddTranslation("Data Breach", "泄机");
            // 当[creature]阵亡时，其持牌人必须从牌组抽一张牌并立即弃置。对手将受到等同于所抽卡牌攻击力的伤害
            AddTranslation("When [creature] perishes, its owner must draw a card from their deck and immediately discard it. The opponent is dealt damage equal to the drawn creatures attack power.", "[creature]死，则其主自牌列引一牌而立弃之。敌受其所引物威数之伤。");
            // 死铃使者
            AddTranslation("Deadringer", "死铃");
            // 当[creature]存活且在牌桌上时，若其力量低于5点，每次铃响可使其增加1点力量。
            AddTranslation("While [creature] is alive and on the board, it gains +1 power each time the bell is rung, if it has less than 5 power.", "[creature]存于场而威未满5，则每铃鸣加1威。");
            // [creature]的力量提升了
            AddTranslation("[creature] powers up!", "[creature]威益矣！");
            // 死亡掠夺
            AddTranslation("Death Snatch", "死掠");
            // [creature]阵亡时，从你的牌组中抽一张牌。
            AddTranslation("When [creature] perishes, draw a card from your deck.", "[creature]死，则自乃牌列引一牌。");
            // 全副武装
            AddTranslation("Decked Out", "具装");
            // [creature]受到攻击时，会从随机神殿的副牌组中抽取一张牌加入你的手牌。
            AddTranslation("When [creature] is struck, a card from a random temple's side deck is created in your hand.", "[creature]受击，则自随机神殿之副牌生一牌于汝手。");
            // 污染者
            AddTranslation("Defiler", "污者");
            // [creature]阵亡时，其持牌人必须从牌组抽一张牌并立即弃置。
            AddTranslation("When [creature] perishes, its owner must draw a card from their deck and immediately discard it.", "[creature]死，则其主自牌列引一牌而立弃之。");
            // 孤注一掷
            AddTranslation("Desperate", "穷搏");
            // [creature]阵亡时对对手造成1点伤害。
            AddTranslation("When [creature] perishes, it deals one point of damage to the opponent.", "[creature]死，则遗1伤于敌。");
            // [creature]在阵亡时造成了1点额外伤害。
            AddTranslation("[creature] deals a free point of damage as it perishes.", "[creature]死而遗1伤于敌。");
            // 鹿神敬拜
            AddTranslation("Deus Hoof", "鹿神");
            // 当[creature]在场时，所有友方有蹄类造物获得+1力量和生命。此外，所有有蹄类造物会攻击任何袭击[creature]的目标。
            AddTranslation("All friendly hooved creatures gain +1 Power and Health while [creature] is on the board. Also, all hooved creatures will attack anything that strikes [creature].", "[creature]在场，则诸有蹄之友物皆加1威1命。凡击[creature]者，亦为诸蹄物所攻。");
            // 右前打击
            AddTranslation("Dexter Strike", "右前击");
            // [creature]攻击时会同时攻击正对面位置右侧的格子。
            AddTranslation("[creature] will also strike the slot to the right of the opposing slot when it attacks.", "[creature]攻时，亦击对位之右格。");
            // 对角打击
            AddTranslation("Diagonal Strike", "斜击");
            // 当[creature]攻击时，会优先攻击原目标左侧或右侧存在造物的位置。若两侧均有或均无造物，则随机选择左侧或右侧攻击。
            AddTranslation("When [creature] attacks, it will strike either to the left or right of its original target, prioritising striking slots containing creatures. If both or neither slots adjacent to the target contain creatures, [creature] will attack to the left or right at random.", "[creature]攻时，或击其本的之左，或击其右，先择有物者。若两侧俱有，抑俱无，则左右随机。");
            // 开膛破肚
            AddTranslation("Disembowel", "剖腹");
            // 当[creature]被献祭时，其持牌者手牌中将生成等同于剩余生命值的内脏。
            AddTranslation("When [creature] is sacrificed, an amount of guts equal to its remaining health are created in its owners hand.", "[creature]见祀，则其主手中生脏，如其余命之数。");
            // [creature]的内脏爆裂到你手中。
            AddTranslation("[creature]s guts explode into your hands.", "[creature]之脏迸入汝手。");
            // 魂不守舍
            AddTranslation("Distraction", "诱替");
            // 当[creature]可能受到攻击时，会在原地留下分心物，[creature]自身则向右移动。
            AddTranslation("When [creature] would be struck, a distraction is left in its place and [creature] moves to the right.", "[creature]将受击，则留一诱物于故处，而自身右移。");
            // 潜行者
            AddTranslation("Diver", "潜者");
            // [creature]可以直接攻击对位处于潜水状态的卡牌。
            AddTranslation("[creature] can strike the opposing card even while it is submerged.", "[creature]虽对位潜伏，亦可击之。");
            // 当[creature]存活且在牌桌上时，下一张抽到的卡牌将被复制。
            AddTranslation("The next card drawn while [creature] is alive and on the board will be duplicated.", "[creature]存于场，则后所引之牌将见复制。");
            // 可除性打击
            AddTranslation("Divisibility Strike", "奇偶击");
            // 每回合结束时，[creature]会交替攻击所有奇数编号和偶数编号的对手位置。
            AddTranslation("At the end of each turn, [creature] will alternate between striking all odd indexed opponent slots, and all even indexed opponent slots.", "每合终，[creature]交替击敌侧诸奇列与诸偶列。");
            // 温顺
            AddTranslation("Docile", "驯");
            // [creature]需等待固定回合数才能再次攻击。
            AddTranslation("[creature] will wait a set number of turns in between being allowed to attack.", "[creature]每攻之间，须俟定数之合。");
            // 命定者
            AddTranslation("Doomed", "定死");
            // 回合结束时，[creature]会阵亡。
            AddTranslation("At the end of the turn, [creature] will perish.", "合终，[creature]死。");
            // 协同攻击
            AddTranslation("Double Tap", "并击");
            // 当友方造物攻击敌方造物时，[creature]也会对该敌方造物发起攻击。
            AddTranslation("When a friendly creature strikes an opponent creature, [creature] will also attack that opponent creature.", "友物攻敌物时，[creature]亦攻彼物。");
            // [creature]在战斗中支援它的战友！
            AddTranslation("[creature] aids its comrades in battle!", "[creature]助其同袍战矣！");
            // 下沉气流
            AddTranslation("Downdraft", "下风");
            // [creature]会赋予左右两侧造物飞行能力。
            AddTranslation("[creature] will grant the power of flight to creatures to it's left and right.", "[creature]授其左右之物以飞。");
            // 绘牌之手
            AddTranslation("Draw", "引");
            // 当使用[creature]时，其持有者将抽取等同于该印记所示数量的卡牌。
            AddTranslation("When [creature] is played, its owner draws cards equal to the number inscribed on this sigil.", "[creature]既陈，其主引牌，如印所书之数。");
            // 流连
            AddTranslation("Dripping", "滴行");
            // 持牌人回合结束时，[creature]将向印记标注的方向移动，并在移动轨迹上留下部分躯体。
            AddTranslation("At the end of the owner's turn, [creature] will move in the direction inscribed in the sigil and leave part of it's own body in it's wake.", "持牌者合终，[creature]循印所志而移，并遗其身之一分于行迹。");
            // 得手投弃
            AddTranslation("Drop", "引即陈");
            // 若[creature]作为初始手牌被抽到，将免费自动部署在随机空位。
            AddTranslation("If[creature] is drawn as part of your opening hand, it will be automatically played on a random board space for free.", "若[creature]为开局手牌所引，则免费自陈于随机空位。");
            // 使用[creature]时，你可在牌组中搜索任意卡牌并在手牌中生成其复制品。
            AddTranslation("When [creature] is played, you may search your deck for any card and create a duplicate of it in your hand.", "[creature]既陈，汝可于牌列索任一牌，并生其副本于手。");
            // 双重奏
            AddTranslation("Duppelgang", "双影");
            // 使用[creature]时，从牌组中抽取与其相邻卡牌的复制品加入手牌。
            AddTranslation("When [creature] is played, draw copies of cards adjacent to it from your deck to your hand.", "[creature]既陈，自牌列引其邻牌之副本入手。");
            // 渴望
            AddTranslation("Eager", "亟");
            // [creature]在牌桌上的首个回合内将获得+2力量。
            AddTranslation("[creature] will gain +2 power for the duration of it's first turn on the board.", "[creature]在场之初合，威加2。");
            // 轻而易举
            AddTranslation("Easy Pickings", "易取");
            // 当[creature]入场时，牌桌上所有生命值为1的造物将立即阵亡。
            AddTranslation("When [creature] is played, all other creatures on the board with 1 health will perish.", "[creature]既陈，场上一切命为1之物皆立死。");
            // 脱胎换骨
            AddTranslation("Emancipation", "脱化");
            // 使用[creature]时，持牌人拥有的所有瓶中卡牌会复制到其手牌中。
            AddTranslation("When [creature] is played, copies of any bottled cards the owner possesses are created in the owner's hand.", "[creature]既陈，则其主持有之诸瓶牌，皆生副本于手。");
            // 绿宝石核芯
            AddTranslation("Emerald Core", "绿玉核");
            // 当[creature]阵亡时，会在原地生成一个绿宝石容器。
            AddTranslation("When [creature] perishes, an Emerald Vessel is created in its place.", "[creature]死，则其处生一绿玉皿。");
            // 绿宝石之心
            AddTranslation("Emerald Heart", "绿玉心");
            // 当[creature]阵亡时，会在原地生成一张绿宝石玛珂。
            AddTranslation("When [creature] perishes, an Emerald Mox is created in its place.", "[creature]死，则其处生一绿玉玛珂。");
            // 附魔
            AddTranslation("Enchanting", "赋印");
            // 使用[creature]时，你打出的所有造物将随机获得它的一个其他印记。
            AddTranslation("When [creature] is played, all creatures you control gain one of its other sigils, at random.", "[creature]既陈，则汝所御诸物随机得其一他印。");
            // 濒危
            AddTranslation("Endangered", "垂危");
            // 回合结束时，[creature]有25%概率阵亡。
            AddTranslation("At the end of the turn, [creature] has a one in four chance to perish.", "合终，[creature]有四分之一之几而死。");
            // 敌军战线
            AddTranslation("Enemy Lines", "敌阵");
            // [creature]攻击时，会锁定所有非正对位置的敌方空位。
            AddTranslation("When [creature] attacks, it will target all opponent slots that it is NOT directly opposing.", "[creature]攻时，凡非其正对之敌位，皆为所向。");
            // 能量依赖
            AddTranslation("Energy Dependent", "恃能");
            // 若使用者能量为0，[creature]将阵亡。
            AddTranslation("If the user has 0 Energy, [creature] will perish.", "若其主之能为0，[creature]死。");
            // 愤怒
            AddTranslation("Enraged", "愤");
            // 当[creature]被攻击时，获得1点力量。
            AddTranslation("When [creature] is struck, it gains 1 attack power.", "[creature]受击，则威加1。");
            // 盘根错节
            AddTranslation("Entangle", "缠");
            // [creature]阵亡时，击杀者力量减半（向下取整）并持续一回合。
            AddTranslation("When [creature] perishes, its killer has their power reduced by half and rounded down for one turn.", "[creature]死，则杀之者威半减，取下而止于一合。");
            // 飘忽不定
            AddTranslation("Erratic", "无恒");
            // 持牌人回合结束时，[creature]将向印记标注的方向移动。若目标格位被阻挡则不会移动。每次移动后有50%概率改变方向。
            AddTranslation("At the end of the owner's turn, [creature] will move in the direction inscribed on the sigil. It will not move if the target slot is obstructed. Direction has a 50/50 chance to change after moving.", "持牌者合终，[creature]循印所志而移。若前格有阻，则不移；每移之后，有半几改其向。");
            // 团队精神
            AddTranslation("Esprit De Corps", "同心");
            // 当[creature]在牌桌上时，同侧最左与最右位置的造物增加1点力量。
            AddTranslation("While [creature] is on the board, creatures in the leftmost and rightmost slots on the same side of the board gain 1 power.", "[creature]在场，则同侧最左与最右之物威加1。");
            // 当[creature]存活于牌桌上时，其持牌人不会受到致命伤害。
            AddTranslation("While[creature] is alive and on the board, its owner may not take fatal damage.", "[creature]存于场，则其主不受致死之伤。");
            // 偶数打击
            AddTranslation("Even Strike", "偶列击");
            // [creature]攻击时会打击所有偶数索引列的对面位置。列索引从左至右计数，起始值为1。
            AddTranslation("[creature] will strike all opposing spaces in even indexed columns when it attacks. Column index is counted from the left, starting at 1.", "[creature]攻时，凡敌侧偶列之位皆击之。列数自左计，始于1。");
            // 传说祭品
            AddTranslation("Exceptional Sacrifice", "奇祭");
            // [creature]在献祭时可算作6点血量，而非1点。与生生不息印记相性不佳。
            AddTranslation("[creature] counts as 6 Blood rather than 1 Blood when sacrificed. Does not pair well with many lives.", "[creature]见祀时，算6血，非1血。与多命不甚相宜。");
            // 嗜血狂兽
            AddTranslation("Bloodstarved Beast", "嗜血兽");
            // 使用[creature]时，持牌人可从墓地中搜索一张卡牌并加入手牌。
            AddTranslation("When [creature] is played, it's owner may search their graveyard for a card, and add that card to their hand.", "[creature]既陈，其主可于墓地索一牌而纳之手。");
            // 尸爆
            AddTranslation("Exploding Corpse", "尸爆");
            // 当[creature]阵亡时，牌桌上的所有空位会自动出现内脏卡牌。
            AddTranslation("When [creature] perishes, all empty spaces on the board are filled with it's innards.", "[creature]死，则场上诸空位皆以其脏充之。");
            // 呕物驱逐
            AddTranslation("Expulsion", "吐逐");
            // 当[creature]受到伤害时，会将其内容物吐到右侧相邻位置。
            AddTranslation("When [creature] takes damage, it regurgitates it's contents into the adjacent space to the right.", "[creature]受伤，则吐其所吞于右邻之位。");
            // 放血
            AddTranslation("Exsanguination", "渫血");
            // 当[creature]在牌桌上时，友方造物的血量费用减少1点。
            AddTranslation("While [creature] is on the board, friendly creatures have their blood cost reduced by 1.", "[creature]在场，则友物之血费减1。");
            // 战斗之眼
            AddTranslation("Eye For Battle", "战目");
            // 若[creature]未正对敌方造物，将失去所有攻击力。
            AddTranslation("[creature] will lose all attack power if it is not directly opposing an opponent's creature.", "[creature]不正对敌物，则尽失其威。");
            // 面面相觑
            AddTranslation("Face To Face", "相对");
            // 当[creature]被抽到时，它会变形模仿当前对手。
            AddTranslation("When [creature] is drawn, it morphs to mimic the current opponent.", "[creature]既引，则化而效今敌。");
            // 妖扇之尾
            AddTranslation("Fan Tailed", "扇尾");
            // 当[creature]入场时，牌桌上所有友方造物获得飞行能力。
            AddTranslation("When [creature] is played, all friendly creatures on the board take flight.", "[creature]既陈，场上诸友物皆得飞。");
            // 致命侧翼
            AddTranslation("Fatal Flank", "致翼");
            // 当[creature]在战斗中阵亡时，会在所有相邻空位生成特定造物。
            AddTranslation("When [creature] perishes to combat, it creates a specific creature in all empty adjacent slots.", "[creature]战死，则诸相邻空位皆生一定之物。");
            // 凶神恶煞
            AddTranslation("Fearsome", "可畏");
            // 当[creature]试图进入已被其他造物占据的位置时，若存在可移动空间，该造物会为其让路。
            AddTranslation("When [creature] targets a slot occupied by another creature, that creature will move to make way for it if there is room to do so.", "[creature]所向之位若为他物所据，则其物有隙可徙，便徙以让。");
            // 文件管理
            AddTranslation("File Explorer", "探卷");
            // 当使用[creature]时，从牌组随机选择两只造物。这些造物将随机决定该卡牌的力量与生命值。若该卡牌阵亡，用于决定其属性的造物也会同时阵亡
            AddTranslation("When [creature] is played, choose two creatures from random selection of your deck. These creatures will define this cards power and health at random. If this card dies, the creatures used to define its stats perish as well.", "[creature]既陈，自牌列随机择二物。此二物将随机定此牌之威与命。若此牌死，则定其属性之物亦并死。");
            // 滤食之物
            AddTranslation("Filter Feeder", "滤食");
            // 当[creature]相邻的造物阵亡时，该卡牌将获得1点力量或1点生命。
            AddTranslation("When a creature perishes adjacent to [creature], the card will gain either 1 power or 1 health.", "邻[creature]之物死，则此牌或加1威，或加1命。");
            // 火焰引爆器
            AddTranslation("Firebomb", "火爆");
            // [creature]阵亡时，相邻及正对面的造物受到2点伤害并获得燃烧印记。
            AddTranslation("When [creature] perishes, creatures adjacent to it and opposing it take 2 damage and gain the Burning sigil.", "[creature]死，则邻之与正对之物受2伤，并得燃印。");
            // [creature]爆炸了，火焰四处飞溅！
            AddTranslation("[creature] explodes, spraying fire everywhere!", "[creature]爆矣，火四溅焉！");
            // 小心炮弹
            AddTranslation("Fire In The Hole", "穴中火");
            // [creature]阵亡时，其持牌人可选定对手的一个卡槽，该槽位造物将受到10点伤害。
            AddTranslation("When [creature] perishes, it's owner may choose an opponent slot. The creature in that slot will take ten damage.", "[creature]死，则其主可择敌之一位；其位之物受10伤。");
            // 防火
            AddTranslation("Fire Resistant", "耐火");
            // [creature]不会受到燃烧印记的伤害
            AddTranslation("[creature] will not take damage from the Burning sigil.", "[creature]不受燃印之伤。");
            // 侧牌引爆器
            AddTranslation("Flank Blast", "侧爆");
            // 当[creature]死亡时，相邻的友方造物会受到10点伤害。
            AddTranslation("When [creature] dies, adjacent friendly creatures are dealt 10 damage.", "[creature]死，则相邻友物受10伤。");
            // 跳蚤满身
            AddTranslation("Flea Ridden", "多蚤");
            // [creature]在战斗中阵亡时，会在所有相邻空位生成跳蚤。跳蚤具有：0点力量、1点生命，渴望，脆弱。
            AddTranslation("When [creature] perishes to combat, it creates a Flea in all empty adjacent slots. A Flea is defined as 0 Power, 1 Health, Eager, Frail", "[creature]战死，则诸相邻空位皆生跳蚤。跳蚤者：0威、1命，亟、脆。");
            // 轻浮
            AddTranslation("Flighty", "轻扬");
            // 回合结束时，[creature]会随机移动到一个可用位置。
            AddTranslation("At the end of the turn, [creature] will move to a random available space.", "合终，[creature]随机移于一可用之位。");
            // 化石记录
            AddTranslation("Fossil Record", "化石录");
            // 当[creature]在牌桌上时，地形卡被摧毁时将额外获得3根兽骨。
            AddTranslation("While [creature] is on the board, terrain cards will award 3 additional bones when destroyed.", "[creature]在场，则地形牌毁时，额外授3骨。");
            // 脆弱
            AddTranslation("Frail", "脆");
            // 当[creature]受到攻击时，它将立即阵亡。
            AddTranslation("When [creature] is struck, it will perish.", "[creature]受击，则立死。");
            // 脆弱献祭
            AddTranslation("Frail Sacrifice", "脆祀");
            // 当[creature]被献祭时，接受献祭的造物将获得脆弱印记。
            AddTranslation("When [creature] is sacrificed, the creature it was sacrificed for gains the Frail Sigil.", "[creature]见祀，则受其祀之物得脆印。");
            // 自由落体
            AddTranslation("Freefall", "坠");
            // 当[creature]在牌桌上时，所有具有空袭印记的召唤需求减少1点对应资源。
            AddTranslation("While [creature] is on the board, all airborne creatures require exactly 1 less of their respective cost to be played.", "[creature]在场，则诸飞物所需之费，各减1。");
            // 找呀找朋友
            AddTranslation("Friend Finder", "求友");
            // 使用[creature]时，其左右两侧空位将各生成一个随机Steam好友。
            AddTranslation("When [creature] is played, a random friend is created in the slots to it's left and right.", "[creature]既陈，其左右空位各生一随机之友。");
            // 边路打击
            AddTranslation("Fringe Strike", "边击");
            // [creature]会始终攻击最左和最右路线的敌方位置。
            AddTranslation("[creature] will always attack the leftmost and rightmost opponent lanes.", "[creature]恒击敌侧最左与最右之路。");
            // 众蛙之友
            AddTranslation("Frog Friend", "蛙友");
            // 持牌人回合结束时，[creature]将向印记标注的方向移动。你可以从牌组中搜寻任意“蛙”或“蟾蜍”造物，并将其放置在[creature]原先的位置上。
            AddTranslation("At the end of the owner's turn, [creature] will move in the direction inscrybed in the sigil. You may search your deck for any 'frog' or 'toad' creatures, and play them in [creature]'s old space.", "持牌者合终，[creature]循印所志而移。汝可于牌列索诸“蛙”或“蟾”之物，而陈之于[creature]故处。");
            // 绿宝石依赖
            AddTranslation("Emerald Dependant", "恃绿玉");
            // 如果[creature]的持牌人未打出绿色玛珂，则[creature]会阵亡
            AddTranslation("If [creature]'s owner controls no green mox gems, it will perish.", "若[creature]之主持无绿玉玛珂，则死。");
            // [creature]需要绿宝石玛珂才能存在，否则会阵亡
            AddTranslation("[creature] requires an emerald mox to exist and perishes.", "[creature]恃绿玉玛珂而存；无则死。");
            // 红宝石依赖
            AddTranslation("Ruby Dependant", "恃红玉");
            // 如果[creature]的持牌人未打出橙色玛珂，则[creature]会阵亡
            AddTranslation("If [creature]'s owner controls no orange mox gems, it will perish.", "若[creature]之主持无红玉玛珂，则死。");
            // [creature]需要红宝石玛珂才能存在，否则会阵亡
            AddTranslation("[creature] requires a ruby mox to exist and perishes.", "[creature]恃红玉玛珂而存；无则死。");
            // 蓝宝石依赖
            AddTranslation("Sapphire Dependant", "恃蓝玉");
            // 如果[creature]的持牌人未打出蓝宝石玛珂，则[creature]会阵亡
            AddTranslation("If [creature]'s owner controls no blue mox gems, it will perish.", "若[creature]之主持无蓝玉玛珂，则死。");
            // [creature]需要蓝宝石玛珂才能存在，否则会阵亡
            AddTranslation("[creature] requires a sapphire mox to exist and perishes.", "[creature]恃蓝玉玛珂而存；无则死。");
            // 玛珂掉落
            AddTranslation("Gem Shedder", "遗玉");
            // 持牌人回合结束时，[creature]将向印记标注的方向移动，并在原地随机留下一颗玛珂
            AddTranslation("At the end of the owner's turn, [creature] will move in the direction inscrybed in the sigil and drop a random Gem in its old place.", "持牌者合终，[creature]循印所志而移，并于故处随机遗一玉。");
            // 宝石质疑者
            AddTranslation("Gem Skeptic", "疑玉");
            // 当牌桌上有[creature]时，其持牌人无法使用任何玛珂宝石。
            AddTranslation("While [creature] is on the board, its owner may not play any mox gems.", "[creature]在场，则其主不得陈任何玛珂。");
            // 巨人
            AddTranslation("Giant", "巨");
            // 当[creature]在场时，所有对其持牌人的攻击将转而以它为攻击目标。
            AddTranslation("While [creature] is on the board, any strikes against its owner will target it instead.", "[creature]在场，则凡攻其主者，皆转而向之。");
            // 礼品商
            AddTranslation("Gift Bearer", "怀礼");
            // [creature]阵亡时，你的手牌中会随机生成一只造物。
            AddTranslation("When [creature] perishes, a random creature is created in your hand.", "[creature]死，则于汝手生一随机之物。");
            // 辉耀之心
            AddTranslation("Glitterheart", "辉心");
            // 当[creature]在场时，打出玛珂宝石可使其生命值+1。
            AddTranslation("While [creature] is on the board, playing a mox gem will increase its health by 1.", "[creature]在场，则陈玛珂可使其命加1。");
            // [creature]因打出宝石而获得强化。
            AddTranslation("[creature] is bolstered by the played gem.", "[creature]因所陈之玉而益。");
            // 四海为家
            AddTranslation("Globetrotter", "周行");
            // 持牌人回合结束时，[creature]将向印记标注的方向移动。若遇阻碍，则会绕至牌桌另一侧开始回旋移动。
            AddTranslation("At the end of the owner's turn,[creature] will move in the direction inscribed on the sigil. If obstructed, it will move to the other side of the board and begin to circle back.", "持牌者合终，[creature]循印所志而移。若有阻，则绕至牌局彼侧而旋返。");
            // 使用[creature]时，其持有者的手牌里会出现一张黑山羊牌。
            AddTranslation("When [creature] is played, a Black Goat is created in its owners hand.", "[creature]既陈，其主手中生一黑山羊。");
            // 掘金者
            AddTranslation("Gold Digger", "掘金");
            // 在持牌人回合结束时，[creature]将产生1枚金币，每场战斗最多触发五次。
            AddTranslation("At the end of the owner's turn, [creature] will generate 1 currency, up to five times per battle.", "持牌者合终，[creature]生1金，每战至多五次。");
            // 淘金热
            AddTranslation("Gold Rush", "金潮");
            // 当使用[creature]时，牌桌上所有敌方卡牌都会阵亡，并被金块取代。
            AddTranslation("When [creature] is played, all opponent cards on the board perish, and are replaced by Gold Nuggets.", "[creature]既陈，敌牌尽死，而皆为金块所代。");
            // 黏液
            AddTranslation("Gooey", "黏");
            // 当[creature]被攻击时，攻击者损失1点力量。
            AddTranslation("When [creature] is struck, the striker loses 1 power.", "[creature]受击，则击者失1威。");
            // 把船体上的黏液刮干净，伙计们！全速前进！
            AddTranslation("Scrape that gunk off the hull, lads! Full steam ahead!", "刮去船壳之黏胶，诸子！鼓汽疾进！");
            // 再多的黏液也无法减缓天体的运行轨迹……
            AddTranslation("No amount of ooze can slow the motion of a celestial body...", "黏胶虽多，不能缓天体之行……");
            // 墓地轮班
            AddTranslation("Graveyard Shift", "冢更");
            // [creature]在战斗中阵亡时，会在原位置留下其他造物。与冰封禁锢不同，新造物将保留原造物的印记与增益效果。
            AddTranslation("When [creature] perishes by combat, it leaves something else in it's old space. Unlike Frozen Away, this new creature will retain the sigils and buffs of the original.", "[creature]战死，则其故处留一他物。异于“冰封禁锢”，新物犹存故物之印与益。");
            // 万有引力
            AddTranslation("Gravity", "引");
            // 当使用[creature]时，其持牌人可选择任意敌方造物，并将其移至己方牌桌的任意空位。
            AddTranslation("When [creature] is played, it's owner may choose any opponent creature, and move it to any open space on their side of the board.", "[creature]既陈，其主可择任一敌物，移之于己侧任一空位。");
            // 绿色灵感
            AddTranslation("Green Inspiration", "绿感");
            // 当牌桌上有[creature]时，所有有以绿宝石为费用的友方造物获得+2生命。
            AddTranslation("While [creature] is on the board, all friendly creatures which cost a green gem gain +2 health.", "[creature]在场，则凡费绿玉之友物，命加2。");
            // 呕脏者
            AddTranslation("Gut Spewer", "吐脏者");
            // 使用[creature]时，你的手牌里会出现一张内脏卡牌。
            AddTranslation("When [creature] is played, its innards are created in your hand.", "[creature]既陈，则其脏生于汝手。");
            // 先驱者
            AddTranslation("Harbinger", "先驱");
            // 当友方造物阵亡时，[creature]会移动至该空位补位。
            AddTranslation("When a friendly creatures perishes, [creature] will move to fill it's empty space.", "友物死，则[creature]移而补其空位。");
            // 内心之鹿
            AddTranslation("Harts Within", "内鹿");
            // [creature]受到攻击时，你的手牌中将随机出现一张有蹄类族群的卡牌。
            AddTranslation("When [creature] is struck, a random creature from the hooved tribe is created in your hand.", "[creature]受击，则于汝手随机生一有蹄族之牌。");
            // 阴魂不散
            AddTranslation("Haunter", "留魂");
            // 当[creature]战死时，其亡魂会盘踞在原位。进入该位置的造物将吸收其原有印记。
            AddTranslation("When [creature] dies to combat, it haunts the space it died in. Creatures that enter this space absorb its old sigils.", "[creature]战死，则其魂留于故位。后入其位之物，将纳其旧印。");
            // [creature]将印记留在了灵界！
            AddTranslation("[creature] leaves its sigils behind in the ethereal plane!", "[creature]遗其印于灵界矣！");
            // 在持牌人回合结束时，[creature]的持有者可以选择一个己方造物。该造物恢复1点生命。
            AddTranslation("At the end of the owner's turn, [creature]s owner may choose a creature they control. That creature gains 1 health.", "持牌者合终，[creature]之主可择一己物；其物命加1。");
            // 治疗护盾
            AddTranslation("Healshield", "疗甲");
            // 若[creature]在一回合内未受伤害，持牌人下回合开始时它将获得护甲。
            AddTranslation("If [creature] does not take damage during a turn, it will gain Armor at the start of its owner's next turn.", "若[creature]一合之中未受伤，则其主持下一合始时，它得甲。");
            // 使节
            AddTranslation("Herald", "报者");
            // 当[creature]击杀对面造物时，该卡牌左右两侧的造物各获得1点力量。
            AddTranslation("When[creature] attacks an opposing creature and it perishes, creatures to the left and right of this card gain 1 power.", "[creature]攻敌物而杀之，则此牌左右之物各得1威。");
            // 高功率
            AddTranslation("High Powered", "高能");
            // 在持牌人回合开始时，[creature]将消耗1点能量。
            AddTranslation("At the start of its owners turn, [creature] will consume 1 energy.", "其主持合始时，[creature]耗1能。");
            // 全垒打
            AddTranslation("Home Run", "本垒击");
            // [creature]会记住被放置的路线，并始终攻击该路线。
            AddTranslation("[creature] will remember the lane in which it was played, and will always attack that lane.", "[creature]识其初陈之路，而恒攻其路。");
            // 全套诱饵
            AddTranslation("Hook Line And Sinker", "钩线饵全");
            // 当[creature]在战斗中阵亡时，对面的造物会被拉入其原先所在位置。
            AddTranslation("When [creature] perishes by combat, the opposing creature will be pulled into it's old space.", "[creature]战死，则对位之物为曳入其故处。");
            // 超形态
            AddTranslation("Hypermorphic", "超形");
            // 每回合结束时，[creature]会随机变形为同类型同品质的卡牌。
            AddTranslation("At the end of each turn, [creature] will transform into a random card of the same type and quality.", "每合终，[creature]随机化为同类同品之一牌。");
            // 点燃
            AddTranslation("Ignition", "燃");
            // 当[creature]攻击造物时，目标将获得燃烧印记。
            AddTranslation("When [creature] strikes a creature, that creature gains the Burning sigil.", "[creature]击物，则彼物得燃印。");
            // 无瑕形态
            AddTranslation("Immaculate Form", "无瑕形");
            // 当[creature]在场时，所有友方造物的宝石消耗减少2颗。
            AddTranslation("While [creature] is on the board, the gems cost of all friendly creatures is reduced by 2 gems.", "[creature]在场，则诸友物之玉费减2。");
            // 缥缈之物
            AddTranslation("Immaterial", "无质");
            // 对手回合中对[creature]发动的攻击将直接穿透，并击中其持牌人。
            AddTranslation("Any attacks made against [creature] during the opponents turn will pass straight through, and hit the creature's owner directly.", "敌合中凡攻[creature]者，皆直透而中其主。");
            // 不朽之环
            AddTranslation("Immortal Coil", "不死环");
            // 当[creature]存活于牌桌上时，任何在战斗中阵亡的友方造物都会以略微削弱的状态返回持牌人手牌。
            AddTranslation("While [creature] is alive on the board, any friendly creatures that die to combat will return to the owner's hand, though slightly weakened.", "[creature]存于场，则凡友物战死者，皆稍弱而返其主之手。");
            // 失禁
            AddTranslation("Incontinent", "遗泄");
            // 当[creature]即将受到攻击时，会在其位置生成一团污秽，同时[creature]会向右移动。
            AddTranslation("When [creature] would be struck, a mess is created in its place and a card bearing this sigil moves to the right.", "当[creature]将受击，则其位生秽，带此印之牌右移。");
            // 鼓舞之血
            AddTranslation("Inspiring Sacrifice", "励祀");
            // 当[creature]被献祭时，它的印记会转移给被献祭的造物。
            AddTranslation("When [creature] is sacrificed, it grants its sigils to the creature it was sacrificed for.", "当[creature]为祀，则以诸印授于所祀之物。");
            // 即时效果
            AddTranslation("Instant Effect", "立效");
            // [creature]在牌桌生效后会立即阵亡。
            AddTranslation("After resolving on the board, [creature] will immediately perish.", "在场结算毕，[creature]立亡。");
            // 杀戮玩笑
            AddTranslation("Killing Joke", "杀戏");
            // 当[creature]在场时，所有消耗橙宝石的友方造物登场时将随机获得+1或-1力量。
            AddTranslation("While [creature] is on the board, all friendly creatures which cost an orange gem will either gain +1 power or -1 power when played.", "当[creature]在场，凡费橙玛珂之友物，陈时或+1威，或-1威。");
            // [creature]会随机调整消耗橙宝石卡牌的力量！
            AddTranslation("[creature] randomly modifies the power of the Orange Gem cost card!", "[creature]随机改橙玛珂费牌之威！");
            // 亲族商
            AddTranslation("Kin Bearer", "同承");
            // 当[creature]阵亡时，你的手牌中会随机生成一张同族造物。
            AddTranslation("When [creature] perishes, a random creature of the same tribe is created in your hand.", "当[creature]亡，则同族随机一物生于汝手。");
            // 亲族之后
            AddTranslation("Kindred", "同族");
            // 当使用[creature]时，会免费在其左右两侧随机召唤同族普通造物。
            AddTranslation("When [creature] is played, random common creatures of the same tribe will be played for free to its left and right.", "当[creature]陈，则其左右随机免费陈同族常物。");
            // 跳跃机器人掉落器
            AddTranslation("L33p Leaver", "跃离");
            // 持牌人回合结束时，[creature]将向印记标注的方向移动，并在原地留下一台跳跃机器人。
            AddTranslation("At the end of the owner's turn,[creature] will move in the direction inscrybed in the sigil and drop a L33pB0t in its old place.", "于其主合末，[creature]依印所书之向而移，并于故位坠L33pB0t。");
            // 景观设计师
            AddTranslation("Landscaper", "平地");
            // 使用[creature]时，牌桌上所有地形卡牌将被移除并返回持牌人手牌。
            AddTranslation("When[creature] is played, any terrain cards on the board are removed and added to it's owner's hand.", "当[creature]陈，则场上诸地形牌尽除，归其主手。");
            // 狂乱攻击
            AddTranslation("Lash Out", "反击");
            // 持牌人回合结束时，[creature]会随机攻击一个对面位置。
            AddTranslation("At the end of the owner's turn,[creature] will attack a random opposing slot.", "于其主合末，[creature]随机击敌一位。");
            // 空袭传花
            AddTranslation("Airborne Latch", "翔袭遗契");
            // [creature]阵亡时，其持牌人需选定下一个继承空袭印记的造物。
            AddTranslation("When [creature] perishes, its owner chooses a creature to gain the airborne sigil.", "当[creature]亡，其主择一物，使得翔袭印。");
            // 恼人传花
            AddTranslation("Annoying Latch", "可厌遗契");
            // [creature]阵亡时，其持牌人需选定下一个继承惹人生厌印记的造物。
            AddTranslation("When [creature] perishes, its owner chooses a creature to gain the annoying sigil.", "当[creature]亡，其主择一物，使得烦印。");
            // 燃焰传花
            AddTranslation("Burning Latch", "燃缀");
            // [creature]阵亡时，其持牌人需选定下一个继承燃烧印记的造物。
            AddTranslation("When [creature] perishes, its owner chooses a creature to gain the burning sigil.", "当[creature]亡，其主择一物，使得燃印。");
            // 钻地龙传花
            AddTranslation("Burrower Latch", "穴缀");
            // [creature]阵亡时，其持牌人需选定下一个继承钻地龙印记的造物。
            AddTranslation("When [creature] perishes, its owner chooses a creature to gain the burrower sigil.", "当[creature]亡，其主择一物，使得穴印。");
            // 脆弱传花
            AddTranslation("Frail Latch", "脆缀");
            // [creature]阵亡时，其持牌人需选定下一个继承脆骨印记的造物。
            AddTranslation("When [creature] perishes, its owner chooses a creature to gain the frail sigil.", "当[creature]亡，其主择一物，使得脆印。");
            // 临时宝石化
            AddTranslation("Temporarily Gemified", "暂珂化");
            // [creature]被暂时宝石化，效果持续至对战结束。
            AddTranslation("[creature] has been temporarily gemified until the end of battle.", "[creature]暂珂化，至战终。");
            // 宝石传花
            AddTranslation("Gem Latch", "珂缀");
            // [creature]阵亡时，其持牌人需选定一个造物进行宝石化。
            AddTranslation("When[creature] perishes, its owner chooses a creature to become gemified.", "当[creature]亡，其主择一物，使之珂化。");
            // 阴魂传花
            AddTranslation("Haunter Latch", "鬼缀");
            // [creature]阵亡时，其持牌人需选定下一个继承阴魂不散印记的造物。
            AddTranslation("When [creature] perishes, its owner chooses a creature to gain the haunter sigil.", "当[creature]亡，其主择一物，使得鬼缠印。");
            // 空无传花
            AddTranslation("Null Latch", "虚缀");
            // [creature]阵亡时，其持牌人需选定下一个继承空无管道印记的造物。
            AddTranslation("When [creature] perishes, its owner chooses a creature to gain the null conduit sigil.", "当[creature]亡，其主择一物，使得虚渠印。");
            // 超频传花
            AddTranslation("Overclocked Latch", "超速缀");
            // [creature]阵亡时，其持牌人需选定下一个继承1点力量与超频运转印记的造物。
            AddTranslation("When [creature] perishes, its owner chooses a creature to gain 1 power, and the overclocked sigil.", "当[creature]亡，其主择一物，使之+1威，并得超速印。");
            // 狙击传花
            AddTranslation("Sniper Latch", "狙缀");
            // [creature]阵亡时，其持牌人需选定下一个继承狙击手印记的造物。
            AddTranslation("When [creature] perishes, its owner chooses a creature to gain the sniper sigil.", "当[creature]亡，其主择一物，使得狙印。");
            // 冲刺传花
            AddTranslation("Sprinter Latch", "疾缀");
            // [creature]阵亡时，其持牌人需选定下一个继承冲刺能手印记的造物。
            AddTranslation("When [creature] perishes, its owner chooses a creature to gain the sprinter sigil.", "当[creature]亡，其主择一物，使得疾驰印。");
            // 坚毅传花
            AddTranslation("Stalwart Latch", "坚缀");
            // [creature]阵亡时，其持牌人需选定下一个继承坚毅印记的造物。
            AddTranslation("When [creature] perishes, its owner chooses a creature to gain the stalwart sigil.", "当[creature]亡，其主择一物，使得坚毅印。");
            // 图腾传花
            AddTranslation("Totem Latch", "偶缀");
            // [creature]阵亡时，其持牌人需选定下一个继承当前图腾印记的造物。
            AddTranslation("When [creature] perishes, its owner chooses a creature to gain the sigil on their current totem.", "当[creature]亡，其主择一物，使得其今神偶之印。");
            // 水袭传花
            AddTranslation("Waterborne Latch", "潜缀");
            // [creature]阵亡时，其持牌人需选定下一个继承水袭印记的造物。
            AddTranslation("When [creature] perishes, its owner chooses a creature to gain the waterborne sigil.", "当[creature]亡，其主择一物，使得潜袭印。");
            // 跃行者
            AddTranslation("Leaper", "跃者");
            // 持牌人回合结束时，[creature]将向印记标注的方向移动，并能跃过单个卡牌障碍。
            AddTranslation("At the end of the owner's turn, [creature] will move in the direction inscribed in the sigil, leaping over single card obstructions.", "于其主合末，[creature]依印所书之向而移，越一牌之障。");
            // 当[creature]受到攻击时，会根据剩余生命值在持牌人手牌中生成等量卡牌，随后阵亡。
            AddTranslation("When [creature] is struck, it creates a number of cards in the owner's hand equal to it's remaining HP, then perishes.", "当[creature]受击，则以余命数，生等量牌于主手，而后亡。");
            // 锁关闭隘
            AddTranslation("Lockdown", "锁缚");
            // 当使用[creature]时，对面造物失去等同于该卡牌力量的攻击力，并获得坚毅印记。
            AddTranslation("When [creature] is played, the opposing creature loses attack power equal to the power of this card and gains the Stalwart sigil.", "当[creature]陈，则敌物失等同于此牌之威，并得坚毅印。");
            // [creature]将对面造物牢牢锁定在原位！
            AddTranslation("[creature] locks the opposing creature in place!", "[creature]锁敌物于位！");
            // 孤独
            AddTranslation("Lonesome", "孤");
            // [creature]每有一个相邻空位便增加1点力量。
            AddTranslation("[creature] gains +1 power for each adjacent empty space.", "[creature]每邻一空位，则威益一。");
            // 水袭哨兵
            AddTranslation("Lurk", "潜伏");
            // [creature]会在对手回合潜入水下。任何造物在进入[creature]对面的位置时，均会受到1点伤害。
            AddTranslation("Submerges during the opponent's turn. When a creature moves into the space opposing [creature], they are dealt 1 damage.", "敌合时潜没。若有物移入其对位，则受1伤。");
            // 魔法科技
            AddTranslation("Magitech", "魔工");
            // 当[creature]存活且在牌桌上时，打出玛珂宝石可为持牌人提供一个能量槽。
            AddTranslation("While [creature] is alive and on the board, playing a mox gem will provide it's owner with an energy cell.", "当[creature]在场而生，陈一玛珂，则其主得1能。");
            // [creature]通过你的宝石传导电能！
            AddTranslation("[creature] channels electrical power through your gems!", "[creature]以电通诸玛珂！");
            // 恶意软件
            AddTranslation("Malware", "恶码");
            // 除非你再受到3点或更少伤害即败北时，否则无法使用[creature]。
            AddTranslation("You may not play [creature] unless you are three or less damage away from losing the game.", "非距败三伤内，不得陈[creature]。");
            // 凋而不落
            AddTranslation("Marcescent", "枯荣");
            // 当[creature]击杀对面造物时，可获得该造物的攻击力。
            AddTranslation("When [creature] attacks an opposing creature and it perishes, this card gains it's attack power.", "当[creature]击敌物而令其亡，则此牌得其威。");
            // 石匠
            AddTranslation("Mason", "砌匠");
            // 使用[creature]时，你的手牌里会随机出现一座方尖碑。
            AddTranslation("When [creature] is played, a random obelisk is created in your hand.", "当[creature]陈，则随机一方碑生于汝手。");
            // 抨击者
            AddTranslation("Mauler", "猛击");
            // [creature]造成的过量伤害将直接作用于对手。
            AddTranslation("[creature] will deal overkill damage directly to the opponent.", "[creature]之溢伤直加于敌。");
            // 灵丹妙药
            AddTranslation("Medicinal", "愈疗");
            // 当[creature]入场时，治疗所有友方造物2点生命并移除其负面印记。
            AddTranslation("When [creature] is played, it heals all friendly creatures by 2 and removes all negative sigils from friendly creatures.", "当[creature]陈，则诸友物皆愈二命，并除其负印。");
            // 镜像传花
            AddTranslation("Mirrific", "镜化");
            // [creature]阵亡时，其持牌人需选定下一个继承镜子子镜能力的造物。
            AddTranslation("When [creature] perishes, it's owner chooses a creature to gain the Mirror rorriM ability.", "当[creature]亡，其主择一物，使得镜返能。");
            // 嘲弄
            AddTranslation("Mockery", "讥拟");
            // 若[creature]被放置在敌方造物对面，[creature]的力量与生命值将变为与该造物相同。
            AddTranslation("If [creature] is played opposite an opponent's creature, it's stats change to mimic that creature's stats.", "若[creature]陈于敌物对位，则其威命拟彼。");
            // 无形移态
            AddTranslation("Morph Mover", "变移");
            // 抽到[creature]时，此印记将被随机替换为移动类印记。
            AddTranslation("When [creature] is drawn, this sigil is replaced by a random movement related sigil.", "当[creature]被引，则此印换为随机移印。");
            // 斗志之源
            AddTranslation("Motivator", "励威");
            // 当[creature]攻击造物时，该造物获得1点力量。
            AddTranslation("When [creature] strikes a creature, that creature gains 1 power.", "当[creature]击物，则彼得+1威。");
            // 玛的世界
            AddTranslation("Moxcraft", "珂造");
            // [creature]受到攻击时，你的手牌中将随机出现一张玛珂牌。
            AddTranslation("When [creature] is struck, a random mox is created in your hand.", "当[creature]受击，则随机一玛珂生于汝手。");
            // 玛珂最大值
            AddTranslation("Mox Max", "珂极");
            // 若持牌人侧牌桌上未同时存在两张提供对应玛珂消耗颜色的卡牌，则无法使用[creature]。
            AddTranslation("[creature] cannot be played unless two cards which grant its respective mox cost colour are present on the owners side of the board.", "除非其主场侧有二牌供其费色，不得陈[creature]。");
            // 变形玛珂
            AddTranslation("Moxwarp", "珂跃");
            // 当[creature]存活于牌桌时，任何进入蓝宝石玛珂的敌方攻击都将从所有红宝石玛珂处反弹，反之亦然。
            AddTranslation("While [creature] is alive on the board, any enemy attack that enters a sapphire mox will be returned out of all ruby mox, and vice versa.", "当[creature]在场而生，凡敌击入蓝玛珂者，皆自诸赤玛珂返出；反之亦然。");
            // 神秘玛珂
            AddTranslation("Mystery Mox", "秘珂");
            // 抽到[creature]时，此印记将被随机替换为一种宝石供应印记。
            AddTranslation("When [creature] is drawn, this sigil is replaced by a random gem-granting sigil.", "当[creature]被引，则此印换为随机赐珂印。");
            // 野性呼唤
            AddTranslation("Nature Of The Beast", "兽性");
            // 当[creature]阵亡时，持牌人的手牌中会随机生成一只完全随机的造物。
            AddTranslation("When [creature] perishes, a completely random creature is created in the owner's hand.", "当[creature]亡，则完全随机一物生于主手。");
            // 悉听尊便
            AddTranslation("Obedient", "顺从");
            // 持牌人回合结束时，[creature]将移动到己方场上的一个空位，具体位置由持牌人选择。
            AddTranslation("At the end of the owner's turn, [creature] will move to an empty space on the same side of the board, chosen by it's owner.", "于持牌人合终，[creature]移至场同侧一空位，由其主择之。");
            // 奇数打击
            AddTranslation("Odd Strike", "奇列击");
            // [creature]攻击时会打击所有奇数索引列的对面位置。列索引从左至右计数，起始为1。
            AddTranslation("[creature] will strike all opposing spaces in odd indexed columns when it attacks. Column index is counted from the left, starting at 1.", "列序自左起，始于1；[creature]击时，凡奇数列敌位尽击。");
            // 全能守护者
            AddTranslation("Omni Guardian", "全卫");
            // 当[creature]入场时，牌桌上所有友方造物均获得护甲。
            AddTranslation("When [creature] is played, all friendly creatures on the board gain armour.", "[creature]陈时，场上友物尽得坚甲。");
            // [creature]为所有友方造物赋予了身披坚甲印记。
            AddTranslation("[creature] gives the Armored sigil to all friendly creatures.", "[creature]授友物以坚甲印。");
            // 碎石者
            AddTranslation("Crusher", "碎击");
            // [creature]与地形卡对阵时将获得2点力量。
            AddTranslation("[creature] will gain 2 power when opposed by a terrain card.", "[creature]为地形牌对位时，得2威。");
            // 屠鹿者
            AddTranslation("Deerly Departed", "鹿逝");
            // 当[creature]对面出现有蹄类族群的造物时，获得2点力量。
            AddTranslation("[creature] will gain 2 power when opposed by a creature of the Hooved tribe.", "[creature]为蹄族之物对位时，得2威。");
            // 猎犬者
            AddTranslation("Dog Gone", "犬克");
            // 当[creature]对阵犬类族群造物时，将获得2点力量。
            AddTranslation("[creature] will gain 2 power when opposed by a creature of the Canine tribe.", "[creature]对犬属之物，则威加2。");
            // 戏鸟者
            AddTranslation("Fowl Play", "鸟克");
            // 当[creature]对阵鸟类族群造物时，获得2点力量。
            AddTranslation("[creature] will gain 2 power when opposed by a creature of the Avian tribe.", "[creature]对羽属之物，则威加2。");
            // 食虫者
            AddTranslation("Insectivore", "食虫");
            // 当[creature]对面是昆虫类族群造物时，获得2点力量。
            AddTranslation("[creature] will gain 2 power when opposed by a creature of the Insect tribe.", "[creature]对虫属之物，则威加2。");
            // 捕蛇者
            AddTranslation("Snakebite", "噬蛇");
            // [creature]与爬行族造物对战时将获得2点力量。
            AddTranslation("[creature] will gain 2 power when opposed by a creature of the Reptile tribe.", "[creature]对鳞属之物，则威加2。");
            // 橙色灵感
            AddTranslation("Orange Inspiration", "红感");
            // 当牌桌上有[creature]时，所有有以橙宝石为费用的友方卡牌增加1点力量。
            AddTranslation("While[creature] is on the board, all friendly cards which cost an orange gem gain +1 power.", "[creature]在局，则凡费橙玉之友牌，威加1。");
            // 器官盗贼
            AddTranslation("Organ Thief", "盗脏");
            // 当[creature]击杀另一只造物时，该造物的残骸会出现在你的手牌中。
            AddTranslation("When [creature] kills another creature, it's remains are created in your hand.", "[creature]杀一物，则彼物之骸生于汝手。");
            // 窃骨术
            AddTranslation("Osteoklepty", "窃骨");
            // 当[creature]入场时，它会窃取对手所有的骨头归其持牌人所有。
            AddTranslation("When [creature] is played, it steals all of the opponents bones for it's owner.", "[creature]既陈，则窃敌一切骨而归其主。");
            // 彼岸
            AddTranslation("Other Side", "彼岸");
            // 当[creature]在场时，所有在战斗中阵亡的友方造物将以骷髅形态返回持牌人手牌。
            AddTranslation("While [creature] is on the board, any friendly creatures that die in combat will be returned to the owner's hand as skeletons.", "[creature]在局，则凡友物战死，皆以枯骨之形返其主手。");
            // 痛苦占场
            AddTranslation("Painful Presence", "苦临");
            // 在每个维持阶段，[creature]对面、相邻以及斜对角相邻的所有造物均受到1点伤害。
            AddTranslation("On upkeep, all creatures adjacent to [creature] vertically, horizontally, or diagonally take 1 damage.", "每合始，[creature]纵横斜邻之诸物皆受1伤。");
            // 麻痹
            AddTranslation("Paralytic", "痹");
            // 当[creature]攻击造物时，该造物损失1点力量。
            AddTranslation("When [creature] strikes a creature, that creature loses 1 power.", "[creature]击物，则彼物失1威。");
            // 单性生殖
            AddTranslation("Parthenogenesis", "单生");
            // [creature]在战斗中死亡时，会在原位置留下幼虫形态，1回合后将进化为完全相同的克隆体。
            AddTranslation("When [creature] dies to combat, a larval form is left in it's old space that evolves into an exact clone after 1 turn.", "[creature]战死，则其故处留一幼体；一合后化为与之无异之副。");
            // 完美形态
            AddTranslation("Perfect Form", "完形");
            // 当牌桌上有[creature]时，所有友方造物的宝石消耗减少1颗。
            AddTranslation("While [creature] is on the board, the gems cost of all friendly creatures is reduced by 1 gem.", "[creature]在局，则诸友物之玉费减1。");
            // 移形换影
            AddTranslation("Phantasmic", "幻行");
            // 回合结束时，[creature]将沿印记标注方向移动，可穿透障碍物；若无法移动则绕至牌桌另一侧。
            AddTranslation("At the end of the turn, [creature] will move in the direction inscribed in the sigil, phasing past obstacles and wrapping around to the other side of the board if movement is impossible.", "合终，[creature]循印所志而移，能过阻碍；若不可移，则绕至牌局彼侧。");
            // 穿刺
            AddTranslation("Piercing", "穿");
            // 当[creature]攻击一个已有造物在后方排队的槽位时，排队的造物将受到1点伤害。
            AddTranslation("When [creature] strikes a slot which has a creature queued behind it, the queued creature will take 1 damage.", "[creature]击一位而其后有候补之物，则其候补者受1伤。");
            // 巅峰打击
            AddTranslation("Pinnacle Strike", "极击");
            // [creature]会在攻击时打击所有敌方位置。
            AddTranslation("[creature] will strike all opponent spaces when it attacks.", "[creature]攻时，尽击敌侧诸位。");
            // 涨潮者
            AddTranslation("Point Nemo", "海极");
            // 使用[creature]时，牌桌上所有造物均获得水袭印记。
            AddTranslation("When [creature] is played, all creatures on the board gain the Waterborne sigil.", "[creature]既陈，场上诸物皆得潜袭印。");
            // 强力献祭
            AddTranslation("Potent", "强祀");
            // 当[creature]被献祭时，献祭获得的新卡将随机附加一个印记。
            AddTranslation("When [creature] is sacrificed, the creature it was sacrificed for gains a random sigil.", "[creature]见祀，则受其祀之物随机得一印。");
            // 预先攻击
            AddTranslation("Preemptive Strike", "先发");
            // [creature]首次打出时会立即攻击一次。
            AddTranslation("[creature] will attack once when first played.", "[creature]初陈即攻一次。");
            // [creature]发动了一次先制攻击。
            AddTranslation("[creature] makes a free attack!", "[creature]得一先攻！");
            // 传播者
            AddTranslation("Propagation", "孳");
            // 当[creature]击杀对面造物时，会在该卡牌左右两侧的牌桌位置生成一个造物。
            AddTranslation("When [creature] attacks an opposing creature and it perishes, a creature is created on the board to the left or right of this card.", "[creature]攻敌物而杀之，则此牌左右之一位生一物。");
            // 预言家
            AddTranslation("Prophecy", "预言");
            // 当使用[creature]时，你可以检视牌组中的三张卡牌并按顺序选择。接下来你抽的三张牌将是你所选择的牌，且顺序与你在此处选择的顺序一致。
            AddTranslation("When [creature] is played, you may look at three cards from your deck and choose them in order. The next three cards you draw will be the cards you were shown, in the order that you chose them.", "[creature]既陈，汝可阅牌列中三牌而次定之。后所引三牌，即此三牌，次如所定。");
            // 我将允许你从三张卡牌中选择。这三张牌将是你接下来从牌组中抽到的牌，顺序与你在此处选择的顺序一致。
            AddTranslation("I will allow you to choose from three cards. These three cards will be the next three cards you draw from your deck, in the order you choose them here.", "我许汝自三牌中择之。此三牌将为汝后所引之三牌，次如汝今所定。");
            // 选择三个造物，改变你接下来的抽牌。
            AddTranslation("Choose three creatures, and alter your next draws.", "择三物，而易后引。");
            // 你知道该怎么做的。
            AddTranslation("You know how this goes.", "汝知其法。");
            // 从三张卡牌中选择。这三张牌将是你接下来从牌组中抽到的牌，顺序与你在此处选择的顺序一致。
            AddTranslation("Choose from three cards. These three cards will be the next three cards you draw from your deck, in the order you chose them.", "自三牌中择之。此三牌将为汝后所引之三牌，次如所定。");
            // 选择你接下来要抽的三张牌。
            AddTranslation("Choose your next three draws.", "定汝后三引。");
            // 唔……看来你的新预言覆盖了旧的。
            AddTranslation("Hmmm... your new prophecy overwrites the old, it would seem.", "唔……新预言覆旧者矣。");
            // 你的新预言覆盖了旧的！
            AddTranslation("Your new prophecy overwrites the old!", "新预言覆旧矣！");
            // 唔……很好
            AddTranslation("Hmm... very well", "唔……可。");
            // 你剩余的卡牌不足以进行预言。
            AddTranslation("You do not have enough cards left for a prophecy.", "汝馀牌不足为预言。");
            // 你剩余的卡牌不足以进行新的预言！
            AddTranslation("You don't have enough cards left to make a new prophecy!", "汝馀牌不足为新预言！");
            // 纯净之心
            AddTranslation("Pure Heart", "纯心");
            // 当[creature]阵亡时，会在原地生成一张巅峰玛珂。
            AddTranslation("When [creature] perishes, a Pinnacle Mox is created in its place.", "[creature]死，则其处生一极玛珂。");
            // 软柿子
            AddTranslation("Pushover", "易殪");
            // 若[creature]对面存在敌方造物，该卡牌将直接阵亡。
            AddTranslation("If [creature] is opposed by an enemy creature, the card will perish.", "若[creature]对面有敌物，则此牌立死。");
            // 步哨工程师
            AddTranslation("Put Sentry Here", "置哨于此");
            // 使用[creature]时，会在其左右两侧各部署一台哨兵无人机。
            AddTranslation("When [creature] is played, a Sentry Drone is created to its left and right.", "[creature]既陈，其左右各生一戍飞械。");
            // 四重攻击
            AddTranslation("Quad Strike", "四击");
            // [creature]会攻击正对面的左右两侧位置各一次，并额外攻击正前方位置一次。
            AddTranslation("[creature] will strike each opposing space to the left and right of the spaces across from it as well as striking the space in front of it an additional time.", "[creature]攻时，并击正对左右二位，而正前更加一击。");
            // 快攻
            AddTranslation("Quickdraw", "速陈");
            // [creature]会在每场战斗开始时自动从牌组中打出至随机空位。
            AddTranslation("[creature] will automatically play itself from your deck onto a random space at the start of each battle.", "[creature]每战之始，自牌列陈于随机空位。");
            // 突击员
            AddTranslation("Ranger", "游击");
            // 当[creature]入场时，其持牌人可选择一名敌方造物，该造物将受到10点伤害。
            AddTranslation("When [creature] is played, it's owner may choose an opponent creature. That creature will take 10 damage.", "[creature]既陈，其主可择一敌物；彼物受10伤。");
            // 贪婪之噬
            AddTranslation("Ravenous", "饕");
            // 当[creature]击杀一只造物时，它将在本场战斗中额外攻击对面位置一次。
            AddTranslation("When [creature] kills a creature, it will gain an additional strike against the opposing space until the end of combat.", "[creature]杀一物，则至战终前，对位更增一击。");
            // 蓄势
            AddTranslation("Recharge", "复能");
            // 使用[creature]时，持牌人恢复1点能量。不影响当前能量上限。
            AddTranslation("When [creature] is played, it's owner regains 1 energy. Does not affect the current energy maximum.", "[creature]既陈，其主复1能；不益今能极。");
            // 回收利用
            AddTranslation("Recycle", "回用");
            // 当[creature]在场时，任何友方造物因战斗阵亡时，其持有者手牌中将生成一张特殊卡牌。生成的卡牌类型取决于阵亡友方卡牌所属的神殿。
            AddTranslation("While [creature] is on the board, when any friendly creature perishes by combat a special card will be created in the owners hand. The card created depends on the temple of the friendly card which perishesd.", "[creature]在局，则凡友物战死，其主手中生一殊牌。所生之牌，视战死牌所属神殿而定。");
            // 镜面反击
            AddTranslation("Reflective", "映威");
            // 当[creature]对阵造物时，其力量将提升至与对面造物相同。
            AddTranslation("When [creature] is opposed by a creature, it gains power equal to the opposing creatures power.", "[creature]对位有物，则其威增至与彼相同。");
            // 万象更新
            AddTranslation("Regenerator", "自新");
            // 在持牌人回合开始时，[creature]将恢复1点生命值。
            AddTranslation("At the start of the owners turn, [creature] will heal 1 health.", "持牌者合始，[creature]复1命。");
            // [creature]恢复了1点生命值！
            AddTranslation("[creature] regenerates one health!", "[creature]复1命矣！");
            // 纪念之花
            AddTranslation("Rememberance", "追念");
            // 当使用[creature]时，其持牌人可从墓地检索一张卡牌，此印记将被该卡牌的印记所取代。
            AddTranslation("When [creature] is played, it's owner may search their graveyard for a card. This sigil is replaced by that cards sigils.", "[creature]既陈，其主可于墓地索一牌；此印即为彼牌诸印所代。");
            // 遥控
            AddTranslation("Remote Controlled", "遥御");
            // 使用[creature]时，持牌人将获得一个遥控器。当遥控器受到攻击时，[creature]会反击攻击者。
            AddTranslation("When [creature] is played, a Remote Controller is created in the owner's hand. When the remote controller is struck, [creature] will attack the striker.", "[creature]既陈，其主手中生一遥御器。遥御器受击，则[creature]攻其击者。");
            // 重新定向
            AddTranslation("Reroute", "易路");
            // 回合结束时，[creature]将与同侧随机一名造物交换位置。
            AddTranslation("At the end of the turn, [creature] will swap places with a random creature on the same side of the board.", "合终，[creature]与同侧随机一物易位。");
            // 百折不挠
            AddTranslation("Resilient", "韧");
            // [creature]受到的所有伤害均降为1点。
            AddTranslation("All damage taken by [creature] is reduced to 1.", "[creature]凡所受伤，皆减为1。");
            // 退却
            AddTranslation("Retreat", "遁");
            // 当[creature]受到攻击时，会随机移动至牌桌同侧的空位。
            AddTranslation("When [creature] is struck, it will move to a random empty space on the same side of the board.", "[creature]受击，则随机移于同侧空位。");
            // 复仇攻击
            AddTranslation("Return Strike", "反击");
            // [creature]受到攻击时会进行反击。
            AddTranslation("When [creature] is struck, it attacks in retaliation.", "[creature]受击，则反击之。");
            // 时针顺之魂
            AddTranslation("Revolve", "周旋");
            // 使用[creature]时，牌桌上所有卡牌均会按顺时针方向移动一格。
            AddTranslation("When [creature] is played, all cards on the board are moved one space clockwise.", "[creature]既陈，局上诸牌皆顺时步一格。");
            // 开膛手
            AddTranslation("Ripper", "剖者");
            // [creature]会移动并消灭任何生命值为1的非地形造物，每消灭一个都会变得更强。
            AddTranslation("[creature] will move to and destroy any free, 1 health, non-terrain creatures played, and becomes stronger for each one consumed.", "凡所陈之无费、命1、非地形物，[creature]皆移而灭之；每食一，则益强。");
            // 磐石吞噬者
            AddTranslation("Rock Eater", "食磐");
            // 当[creature]同侧的牌桌出现地形卡时，该卡会被吞噬，其属性与印记将转移至这张地形卡。
            AddTranslation("When a Terrain card is played on the same side of the board as [creature], it will be consumed, granting it's stats and sigils to the card.", "若[creature]同侧有地形牌既陈，则为其所食，而其威命与印皆归[creature]。");
            // 红宝石核芯
            AddTranslation("Ruby Core", "红玉核");
            // 当[creature]阵亡时，会在原地生成一个红宝石容器。
            AddTranslation("When [creature] perishes, a Ruby Vessel is created in its place.", "[creature]死，则其处生一红玉皿。");
            // 奔袭打击
            AddTranslation("Running Strike", "奔击");
            // 攻击后，[creature]将沿印记标注方向移动，并在移动过程中攻击目标位置对面的空间。
            AddTranslation("After attacking, [creature] will move in the direction inscribed on the sigil, striking the space opposing it's destination as it does so.", "攻后，[creature]循印所志而移，移时击其所至之对位。");
            // 割裂之触
            AddTranslation("Rupture", "裂触");
            // 当[creature]对造物造成伤害时，该伤害值的一半（向下取整）将同时作用于该造物的持有者。
            AddTranslation("When [creature] deals damage to a creature, half of that damage, rounded down, is also dealt to that creature's owner.", "[creature]伤一物，则其伤之半，取下，亦及其主。");
            // 血祭力量
            AddTranslation("Sanguine", "血威");
            // 当有造物被献祭时，[creature]的力量会临时增加1点直至战斗结束。
            AddTranslation("When a creature is sacrificed, [creature] gains 1 power until the end of combat.", "有物见祀，则[creature]威加1，至战终。");
            // 蓝宝石核芯
            AddTranslation("Sapphire Core", "青核");
            // 当[creature]阵亡时，会在原地生成一个蓝宝石容器。
            AddTranslation("When [creature] perishes, a Sapphire Vessel is created in its place.", "[creature]亡时，其位生青皿。");
            // 蓝宝石之心
            AddTranslation("Sapphire Heart", "青心");
            // 当[creature]阵亡时，会在原地生成一张蓝宝石玛珂。
            AddTranslation("When [creature] perishes, a Sapphire Mox is created in its place.", "[creature]亡时，其位生青玛珂。");
            // 野蛮仪式
            AddTranslation("Savage Ritual", "野祀");
            // 当[creature]被献祭时，会在死亡前发动一次攻击。
            AddTranslation("When [creature] is sacrificed, it attacks once before dying.", "[creature]为祀时，先击一次而后死。");
            // 三重哨兵
            AddTranslation("Sentriple", "三哨");
            // 任何造物在进入[creature]对面的位置时，该造物及其左右相邻的造物均会受到1点伤害。
            AddTranslation("When a creature moves into the space opposing [creature], they, as well as any creatures to their left or right, are dealt 1 damage.", "有物移入[creature]对位时，彼及其左右诸物皆受1伤。");
            // 骨骼刺甲
            AddTranslation("Sharp Bones", "锐骨");
            // [creature]被攻击时，攻击者会受到等同于持牌人持有兽骨数量一半的伤害（向下取整）。
            AddTranslation("When [creature] is struck, the striker is dealt damage equal to half the number of bones its owner has, rounded down.", "[creature]受击时，其击者受伤，数等其主所持骨之半，取下整。");
            // 双重刺甲
            AddTranslation("Sharper Quills", "锐翎");
            // [creature]被攻击时，攻击者会受到2点伤害。
            AddTranslation("When [creature] is struck, the striker is dealt 2 damage.", "[creature]被击，则击者受二伤。");
            // 三重刺甲
            AddTranslation("Sharpest Quills", "绝锋翎");
            // [creature]被攻击时，攻击者会受到3点伤害。
            AddTranslation("When [creature] is struck, the striker is dealt 3 damage.", "[creature]被击，则击者受三伤。");
            // 致命触击
            AddTranslation("Sharp Shot", "绝击");
            // 当[creature]阵亡时，获得+2力量并在死亡前发动一次攻击。
            AddTranslation("When [creature] perishes, it gains +2 power and attacks once before dying.", "[creature]亡，则得+2威，先击一回而后亡。");
            // 印记模仿
            AddTranslation("Sigil Mimic", "印仿");
            // 若[creature]被放置在敌方造物对面，此印记将被替换为对方造物印记的复制。
            AddTranslation("If [creature] is played opposite an opponent's creature, this sigil is replaced by copies of that creatures sigils.", "[creature]若陈于敌物对位，则此印化为彼物诸印之副本。");
            // [creature]攻击时还会同时攻击对面位置左侧的槽位。
            AddTranslation("[creature] will also strike the slot to the left of the opposing slot when it attacks.", "[creature]击时，亦击敌位左侧之位。");
            // 虹吸
            AddTranslation("Siphon", "汲威");
            // [creature]左侧的造物失去全部攻击力，该攻击力会转移至本卡牌。
            AddTranslation("Creatures to the left of [creature] lose all attack power. That attack power is instead added to this card's power.", "[creature]左之诸物尽失威；其威转加于此牌。");
            // 毛皮操偶师
            AddTranslation("Skin Animator", "皮灵");
            // 当[creature]存活于牌桌时，所有兽皮卡牌将获得其攻击力。
            AddTranslation("While [creature] is alive on the board, all pelts gain it's attack power.", "[creature]生而在场，则诸革皆得其威。");
            // 骷髅双击
            AddTranslation("Skull Swarm", "骷潮");
            // 当[creature]存活于牌桌时，所有骷髅造物攻击时将进行两次打击。
            AddTranslation("While [creature] is alive and on the board, all Skeletons will strike twice when attacking.", "[creature]生而在场，则诸骷髅击时皆再击。");
            // 黏液球
            AddTranslation("Slimeball", "涎丸");
            // 当使用[creature]时，它会在对面的位置永久留下黏液痕迹。任何处于黏液位置且不具备磐石之身的造物都会损失1点力量。
            AddTranslation("When [creature] is played, it permanently stains the opposing slot with slime. Any creatures in a slimy slot without made of stone lose 1 power.", "[creature]陈时，永以黏污敌位。凡在黏位而非石躯之物，皆失1威。");
            // 快照
            AddTranslation("Snapshot", "瞬录");
            // [creature]阵亡时，整个牌桌将恢复至该造物登场时的状态。
            AddTranslation("When [creature] perishes, the entire board reverts to the state it was in when [creature] was placed.", "[creature]亡，则全场复归其陈时之状。");
            // 恶食陷阱
            AddTranslation("Snare", "陷缚");
            // 当[creature]被放置在对立位置时，该位置的造物会被捕获并储存在持有者体内，持有者阵亡时释放被捕获的造物。
            AddTranslation("When [creature] is played opposite a creature, that creature is ensnared and stored within the bearer, being released when the bearer perishes.", "[creature]若陈于物对位，则缚彼物于持者之内；持者亡而后释。");
            // 剪刀之魂
            AddTranslation("Snip", "裁断");
            // 当使用[creature]时，其正对面的造物会被移出牌桌且不会触发死亡效果。
            AddTranslation("When [creature] is played, the creature opposing it is removed from the board without triggering on-death effects.", "[creature]陈时，敌对之物去场，不发死效。");
            // [creature]将对手一分为二
            AddTranslation("[creature] cuts it's opponent in half.", "[creature]裂其敌为二。");
            // 浸微浸消
            AddTranslation("Soak", "浸");
            // [creature]受到的伤害减少1点。每次受伤会减少该印记显示的计时器数值。当计时器归零时，持有者将以等同于生命值的攻击力发动攻击，随后阵亡。
            AddTranslation("Any damage taken by [creature] is reduced by 1. Taking damage decrements the timer rendered on this sigil. When the timer rendered on this sigil reaches 0, the bearer will attack with power equal to it's health, then perish.", "[creature]所受之伤减1。受伤则减此印之计；计至0，持者将以等于其命之威击，继而亡。");
            // 蛛猎之网
            AddTranslation("Spiders Web", "蛛网");
            // 当任何敌方卡牌移动时（首次登场除外），[creature]会对其造成1点伤害。
            AddTranslation("When any opponent card moves, with the exception of entering the board for the first time,[creature] will strike them for one damage.", "凡敌牌移，初入场者除外，[creature]皆击之，伤1。");
            // 溅射伤害
            AddTranslation("Splash Damage", "溅伤");
            // 当[creature]攻击一个位置时，被攻击位置左右两侧的造物均会受到1点伤害。
            AddTranslation("When [creature] strikes a slot, creatures to the left and right of the struck slot will be dealt 1 damage.", "[creature]击一位，则其左右诸物各受1伤。");
            // 溅射领域
            AddTranslation("Splash Zone", "溅域");
            // 当[creature]被攻击时，其左右两侧的造物也会受到1点伤害。
            AddTranslation("When [creature] is struck, the creatures to it's left or right are also dealt 1 damage.", "[creature]被击，则左右诸物亦各受1伤。");
            // 对[creature]造成的伤害溅射到了其同伴身上。
            AddTranslation("The damage dealt to [creature] splashes out to its comrades.", "加诸[creature]之伤，亦溅其众。");
            // 对角引爆器
            AddTranslation("Split Detonation", "裂爆");
            // 当[creature]死亡时，对角相邻的敌方造物会受到10点伤害。
            AddTranslation("When [creature] dies, diagonally adjacent enemy creatures are dealt 10 damage.", "[creature]死，则对角邻敌物受10伤。");
            // 分裂哨兵
            AddTranslation("Split Sentry", "裂哨");
            // 当有造物进入[creature]对面的位置时，其左右两侧的造物均会受到1点伤害。
            AddTranslation("When a creature moves into the space opposing [creature], any creatures to their left or right are dealt 1 damage.", "有物入[creature]对位，则其左右诸物各受1伤。");
            // 驱使者
            AddTranslation("Spurred", "催势");
            // 当[creature]对面位置有造物时，增加1点力量。
            AddTranslation("[creature] gains 1 power while the slot opposing it is occupied.", "[creature]对位有物，则得+1威。");
            // 松鼠依赖
            AddTranslation("Squirrel Dependent", "倚鼠");
            // 若[creature]的持牌人打出的造物中没有松鼠，[creature]将阵亡。若该卡牌为松鼠，其不可自我维持。
            AddTranslation("If [creature]'s owner controls no Squirrels, [creature] will perish. If this card is a squirrel, it cannot support itself.", "若[creature]之主无松鼠，则[creature]亡。若此牌为松鼠，则不能自立。");
            // 松鼠王
            AddTranslation("Squirrel King", "鼠王");
            // 当[creature]攻击对面造物时，持牌人手牌中将出现一张松鼠牌。
            AddTranslation("When [creature] attacks an opposing creature, a squirrel is created in the owner's hand.", "[creature]击敌物，则于主手生一松鼠。");
            // 坚毅
            AddTranslation("Stalwart", "坚毅");
            // 若[creature]从其初始位置被移动，它会立即返回原位，并将期间占据该位置的卡牌强制移开。
            AddTranslation("If [creature] is moved from the space it was placed in, it will immediately move back, shunting any card which may have moved there in the meantime out of the way.", "若[creature]自其初位移，则立复其位；期间若有他牌入彼位，皆被挤开。");
            // 黏性痕迹
            AddTranslation("Sticky Trail", "黏迹");
            // 当[creature]进入牌桌某位置时，会永久用黏液标记该处。任何进入该位置且不具有磐石之身印记的造物将失去1点力量。
            AddTranslation("When [creature] enters a space on the board, it permantently marks that space with its slime. Any creatures that enter that space without the Made of Stone sigil lose 1 power.", "[creature]入场上一位，则永以黏污之。后入其位而无石躯印者，失1威。");
            // 坚不可摧
            AddTranslation("Sturdy", "坚躯");
            // [creature]受到的所有伤害均减少1点。
            AddTranslation("All damage taken by [creature] is reduced by 1.", "[creature]所受之伤减1。");
            // 水下刺
            AddTranslation("Subaquatic Spines", "潜刺");
            // [creature]会在对手回合潜入水下。潜水时，敌方造物将直接攻击其持有者，并在攻击后受到1点伤害。
            AddTranslation("[creature] will submerge during the opponent's turn. While submerged, opposing creatures attack it's owner directly, and will take 1 damage after attacking.", "[creature]于敌合潜。潜时，敌物直击其主，且击后受1伤。");
            // 召唤师
            AddTranslation("Summoner", "召者");
            // 使用[creature]时，持牌人可从随机卡牌中选择一张加入手牌。
            AddTranslation("When [creature] is played, it's owner may choose from a selection of random cards to add to their hand.", "[creature]陈时，其主可自随机牌中择一入手。");
            // 超载充能
            AddTranslation("Supercharge", "亢充");
            // 当使用[creature]时，会将持牌人的能量恢复至当前最大值。
            AddTranslation("When [creature] is played, it refreshes it's owner's energy to the current maximum.", "[creature]陈时，复其主之能至今上限。");
            // [creature]为持牌人恢复了能量
            AddTranslation("[creature] restores it's owner's energy.", "[creature]复其主之能。");
            // 激流刺甲
            AddTranslation("Surging Quills", "涌刺");
            // [creature]被攻击时，攻击者会受到等同于该[creature]被攻击次数的伤害。
            AddTranslation("When [creature] is struck, the striker is dealt damage equal to the amount of times this has been struck.", "[creature]被击，则击者受伤，等于其所受击数。");
            // 横扫左击
            AddTranslation("Sweeping Strike Left", "左横击");
            // [creature]总是攻击最左侧的敌方造物。过量伤害会向右传递而非作用于后排。
            AddTranslation("[creature] will always attack the leftmost opponent creature. Overkill damage travels to the right instead of to the backlane.", "[creature]恒击敌最左之物。溢伤不入后列，而右行。");
            // 横扫右击
            AddTranslation("Sweeping Strike Right", "右横击");
            // [creature]总会攻击最右侧的敌方造物。过量伤害会向左传递而非作用于后排。
            AddTranslation("[creature] will always attack the rightmost opponent creature. Overkill damage travels to the left instead of to the backlane.", "[creature]恒击敌最右之物。溢伤不入后列，而左行。");
            // 交替打击
            AddTranslation("Switch Strike", "转击");
            // 持牌人回合结束时，[creature]会在攻击对面位置的同时，交替攻击其左侧或右侧位置。
            AddTranslation("At the end of its owners turn [creature] will alternate between striking to the left or right of the opposing slot when it attacks, in addition to striking the opposing slot.", "至主合末，[creature]击时，除击对位外，兼交替击其左或右邻。");
            // 翻飞打击
            AddTranslation("Swooping Strike", "俯击");
            // [creature]会在攻击时对对面位置发动第二次打击。此外，[creature]每回合的首次攻击将越过敌方造物直接命中对手。
            AddTranslation("[creature] will strike the opposing space a second time when attacking. Also, [creature]'s first strike each turn will occur directly, over opponent creatures.", "[creature]击敌位时复击一次。且其每合首击，直越敌物而至。");
            // 心灵感应
            AddTranslation("Telepathic", "心通");
            // 当[creature]在场时，所有友方造物攻击时会优先攻击敌方最强卡牌。
            AddTranslation("While [creature] is on the board, all friendly creatures will stike the most powerful opponent card when they attack.", "[creature]在场，则友物击时皆取敌最强者。");
            // 诱人的目标
            AddTranslation("Tempting Target", "诱靶");
            // 若敌方造物试图攻击[creature]相邻位置，则改为攻击[creature]。
            AddTranslation("If an opponent creature would strike a space adjacent to [creature], it will instead strike [creature].", "若敌物欲击[creature]之邻位，则转击[creature]。");
            // 白蚁后
            AddTranslation("Termatriarch", "蚁后");
            // 当[creature]与另一张带有白蚁王印记的卡牌同时存活在场时，你的回合开始时手牌中将生成一张白蚁卡牌。
            AddTranslation("While [creature] and a different card bearing the Termite King sigil are alive and on the board, a termite will be created in your hand at the start of your turn.", "[creature]与他牌之蚁王印者同生在场，则汝合初生一白蚁于手。");
            // 白蚁王
            AddTranslation("Termite King", "蚁王");
            // 当[creature]与另一张带有白蚁后印记的卡牌存活于场上时，你的回合开始时将获得一张白蚁卡牌。
            AddTranslation("While [creature] and a different card bearing the Termatriarch sigil are alive and on the board, a termite will be created in your hand at the start of your turn.", "[creature]与他牌之蚁后印者同生在场，则汝合初生一白蚁于手。");
            // 测试印记
            AddTranslation("TestSigil", "试印");
            // [creature]多半会把事情搞砸。
            AddTranslation("[creature] will most likely fuck shit up.", "[creature]大抵将大乱其局。");
            // 盗贼
            AddTranslation("Thief", "盗");
            // [creature]击杀其他造物时将获得一定数量的货币。
            AddTranslation("[creature] will grant an amount of currency when it kills another creature.", "[creature]杀他物，则得若干币。");
            // 时间旅行
            AddTranslation("Time Travel", "时渡");
            // 当使用[creature]时，对手必须跳过其下一回合。
            AddTranslation("While [creature] is played, the opponent is obligated to skip their next turn.", "[creature]陈时，敌必失其下合。");
            // 我会跳过我的下一回合。
            AddTranslation("I'll pass my next turn.", "余下合不行。");
            // 你的对手必须跳过下一回合！
            AddTranslation("Your opponent must skip their next turn!", "汝敌下合必失！");
            // 呃。好吧。我跳过。
            AddTranslation("Ugh. Fine. I'll pass.", "唉。可，余下合不行。");
            // 很公平亲爱的，我选择跳过
            AddTranslation("Fair enough dear, I'll pass.", "然，亲者，余下合不行。");
            // 拔牙器
            AddTranslation("Tooth Puller", "拔齿");
            // 持牌人回合结束时，[creature]会无视其攻击力或阻挡状态，为天平增加1点对持牌人有利的伤害。
            AddTranslation("At the end of the owner's turn, [creature] will add one damage to the scales in the owner's favour, regardless of it's attack power or obstruction.", "至主合末，[creature]必为主之衡增1伤，不计其威与阻。");
            // 剧毒之物
            AddTranslation("Toxic", "剧毒");
            // 当[creature]受到攻击但未阵亡时，攻击者将立即阵亡。对磐石之身卡牌无效。
            AddTranslation("When [creature] is struck but does not perish, the striker perishes. Does not affect Made of Stone cards.", "[creature]被击而不亡，则击者亡。石躯牌不受其害。");
            // [creature]的剧毒一击必杀！
            AddTranslation("[creature]s toxicity kills instantly!", "[creature]之毒，触即亡！");
            // 叛徒
            AddTranslation("Traitor", "叛徒");
            // 当使用[creature]时，若路径未被阻挡，它将移动至对手侧牌桌。
            AddTranslation("When [creature] is played, it will move onto the opponent's side of the board if unobstructed.", "[creature]既陈，若路无阻，则移于敌侧。");
            // 狙击刺甲
            AddTranslation("Trajectile Quills", "射棘");
            // [creature]被攻击时，其持牌人可选定一个敌方造物造成1点伤害。
            AddTranslation("When [creature] is struck, an opponent creature of the owner's choosing is dealt 1 damage.", "[creature]受击，则其主可择一敌物，使之受1伤。");
            // 撼地者
            AddTranslation("Trampler", "蹂者");
            // 持牌人回合结束时，[creature]将向印记标注的方向移动。沿途的卡牌会被击杀，并使印记持有者获得+1攻击力。
            AddTranslation("At the end of the owner's turn, [creature] will move in the direction inscribed on the sigil. Cards in the way will be killed, and grant +1 attack power to the sigil bearer.", "持牌者合终，[creature]循印所志而移。道中诸牌皆死，而此印之主威加1。");
            // 易形者
            AddTranslation("Transformer", "易形者");
            // 回合结束时，[creature]会在当前形态与转化形态间切换一次。
            AddTranslation("At the end of the turn, [creature] will transform to or from it's alternate form.", "合终，[creature]往来于本形与异形之间。");
            // 变形术
            AddTranslation("Transmogrification", "化形术");
            // 当[creature]攻击造物时，该造物会转变为另一种形态。
            AddTranslation("When [creature] strikes a creature, that creature will be changed into another form.", "[creature]击物，则彼物化为异形。");
            // 陷阱颚
            AddTranslation("Trapjaw", "阱颌");
            // 若对面位置的左右两侧被阻挡，[creature]会攻击这些位置；若未被阻挡，则攻击会转移至正对面的位置。
            AddTranslation("[creature] will attack to the left and the right of the opposing space if those slots are obstructed. If those slots are not obstructed, the strikes will be transferred to the directly opposing space.", "若对位之左右两格有阻，[creature]则击其二位；若无阻，则二击皆归正对之位。");
            // 精良祭品
            AddTranslation("Trifling Sacrifice", "二血祭");
            // [creature]在献祭时可算作2点血量，而非1点。
            AddTranslation("[creature] counts as 2 Blood rather than 1 Blood when sacrificed.", "[creature]见祀时，算2血，非1血。");
            // 禁忌三重奏
            AddTranslation("Trio", "三身");
            // 当打出[creature]时，会在其左右两侧各生成一张相同的卡牌。
            AddTranslation("When [creature] is played, a copy of it is created to the left and right.", "[creature]既陈，则其左右各生一副本。");
            // 三重攻击
            AddTranslation("Triple Strike", "三击");
            // [creature]会在攻击时额外攻击对面位置两次。
            AddTranslation("[creature] will strike the opposing space two extra times when attacking.", "[creature]攻时，于对位更加二击。");
            // 战利品猎手
            AddTranslation("Trophy Hunter", "猎魁");
            // [creature]攻击时会锁定对面力量最强的卡牌。
            AddTranslation("[creature] will target the most powerful opposing card when it attacks.", "[creature]攻时，专取对面威最强之牌。");
            // 缩滚乐
            AddTranslation("Tuck And Roll", "伏滚");
            // 战斗结束时，[creature]会移动到受攻击力最小的空闲位置，计算时考虑后排待命造物、飞行与死神之触。
            AddTranslation("At the end of combat, [creature] will move to the free space opposed by the least amount of attack power, taking into account queued creatures, flight, and Touch of Death.", "战终，[creature]移于受敌威最少之空位；其算兼后候之物、飞行与死触。");
            // 生拉硬拽
            AddTranslation("Tug", "曳");
            // 当打出[creature]时，若条件允许，它会将排队中的对方造物拖拽至正对面的主位置。
            AddTranslation("When [creature] is played, it will draw the queued opposing creature into the main opposing space, if possible.", "[creature]既陈，若可，则曳敌之后候之物至正对之主位。");
            // 双生契约
            AddTranslation("Twin Bond", "双契");
            // 当使用[creature]时，会在相邻位置生成其复制体（若无空位则消灭其他造物腾出空间）。这两张卡牌共享生命值，其中任意一张死亡时，另一张也会随之死亡。
            AddTranslation("When [creature] is played, a copy of it is created adjacent, killing other creatures to make room if there is none. These cards share a health pool, and when either card dies, it's twin will die as well.", "[creature]既陈，则邻位生其副本；无空则杀他物以腾地。二牌共一命池，其一死，则其双亦死。");
            // 星轮变换
            AddTranslation("Twister", "旋变");
            // 当[creature]受到攻击时，会在当前形态与另一形态间转换。
            AddTranslation("When struck, [creature] will transform to or from it's alternate form.", "[creature]受击，则往来于本形与异形之间。");
            // 失衡领袖
            AddTranslation("Unbalanced Leadership", "偏帅");
            // [creature]左侧相邻的造物获得2点力量。
            AddTranslation("The creature directly to the left of [creature] gains 2 power.", "[creature]左邻之物威加2。");
            // 压力之下
            AddTranslation("Under Pressure", "压裂");
            // 当[creature]阵亡时，对正对面的造物造成2点伤害。此外，当[creature]阵亡时，所有相邻且带有该印记的造物均会受到10点伤害。
            AddTranslation("When [creature] perishes, 2 damage is dealt to the opponent creature. Also, when [creature] perishes, any adjacent creatures with this sigil also take ten damage.", "[creature]死，则对位之物受2伤。且凡相邻而负此印之物，亦受10伤。");
            // [creature]爆裂，对正对面的造物造成2点伤害！
            AddTranslation("[creature] pops, dealing 2 damage to the opposing creature!", "[creature]爆裂，而对位之物受2伤！");
            // 胡乱打击
            AddTranslation("Unfocused Strike", "妄击");
            // [creature]攻击时会随机选择一个目标位置。
            AddTranslation("[creature] will target a random space when it attacks.", "[creature]攻时随机取一位。");
            // 不可锤击
            AddTranslation("Unhammerable", "不可锤");
            // [creature]无法被锤子击杀
            AddTranslation("[creature] cannot be killed using the hammer.", "[creature]不可为锤所杀。");
            // 命途多舛
            AddTranslation("Unlucky", "薄命");
            // 当[creature]存活于牌桌时，对手打出的卡牌有几率被削弱状态值或随机失去一个印记。
            AddTranslation("While [creature] is alive on the board, cards played by the opponent have a chance to have debuffed stats, or lose a random sigil.", "[creature]存于场，则敌所陈之牌有几率削其威命，抑失一随机之印。");
            // 不可言喻
            AddTranslation("Unspeakable", "不可言");
            // 当你打出的卡牌未经手牌使用便结算至牌桌时，可选择从手牌或牌组中打出[creature]替代。
            AddTranslation("When a card you control resolves on the board without being played from your hand, you may choose to play [creature] from your hand or deck instead.", "凡汝所御之牌，未由手陈而见结于场时，可择自手抑自牌列改陈[creature]。");
            // 不稳定宝石
            AddTranslation("Unstable Gems", "危玉");
            // 当[creature]在场时，所有以玛珂宝石为费用的友方造物在打出时将获得脆骨印记。
            AddTranslation("While [creature] is on the board, all friendly creatures which cost a mox gem will gain the brittle sigil when played.", "[creature]在场，则凡费玛珂之友物，既陈时皆得脆骨印。");
            // [creature]使需要宝石的造物变得不稳定！
            AddTranslation("[creature] renders the gem cost creature unstable!", "[creature]使费玉之物危矣！");
            // 吉光片羽
            AddTranslation("Valuable", "值金");
            // [creature]阵亡时将给予一定数量的货币。
            AddTranslation("[creature] will grant an amount of currency when it perishes.", "[creature]死，则授若干之货。");
            // 吸血鬼
            AddTranslation("Vampiric", "饮血");
            // 当[creature]击杀对面造物时，可增加1点生命。
            AddTranslation("When [creature] attacks an opposing creature and it perishes, this card gains 1 health.", "[creature]攻敌物而杀之，则此牌命加1。");
            // 易形猎手
            AddTranslation("Venator", "猎变");
            // 当[creature]击杀另一只造物时，会在当前形态与第二形态间切换。
            AddTranslation("When [creature] kills another creature, it will transform to or from it's alternate form.", "[creature]杀一物，则往来于本形与异形之间。");
            // 容器掉落
            AddTranslation("Vessel Shedder", "遗皿");
            // 持牌人回合结束时，[creature]将向印记标注的方向移动，并在原地留下一个空容器。
            AddTranslation("At the end of the owner's turn, [creature] will move in the direction inscrybed in the sigil and drop an Empty Vessel in its old place.", "持牌者合终，[creature]循印所志而移，并于故处遗一空皿。");
            // 感官异能
            AddTranslation("Visceral", "余血化骨");
            // 当[creature]被献祭时，未被消耗的剩余血量将转化为骨头。
            AddTranslation("When [creature] is sacrificed, any leftover blood that is not used for the sacrifice will be converted into bones.", "[creature]见祀，则其未尽之余血化为骨。");
            // 革命万岁
            AddTranslation("Viva La Revolution", "变革万岁");
            // 在持牌人回合开始时，[creature]会使牌桌上所有造物顺时针旋转。此外，[creature]不会攻击其原主人。
            AddTranslation("At the start of its owners turn, [creature] will revolve all creatures on the board clockwise. Also, [creature] will not attack it's original owner.", "其主持合始，[creature]使场上诸物皆顺时而旋。且[creature]不攻其故主。");
            // 水鸟
            AddTranslation("Waterbird", "水禽");
            // 若[creature]攻击的位置有潜水的造物，该造物会浮出水面，[creature]将转而攻击它而非直接攻击。
            AddTranslation("If [creature] strikes a slot containing a submerged creature, that creature will re-emerge and [creature] will attack it instead of attacking directly.", "若[creature]所击之位有潜物，则彼物出水，[creature]转而击之，不复直攻。");
            // 摇摆打击
            AddTranslation("Wavering Strike", "摆击");
            // [creature]会在每回合结束时交替攻击原本攻击位置的左侧或右侧。
            AddTranslation("[creature] will alternate between striking to the left or right of where it would otherwise attack at the end of each turn.", "[creature]每合终交替而击其本所攻位之左，抑其右。");
            // 织网者
            AddTranslation("Weaver", "织者");
            // 持牌人回合结束时，[creature]将向印记标注的方向移动，并在原地留下一张蛛网。[creature]可以重新移动到自己放置的蛛网上。
            AddTranslation("At the end of the owner's turn, [creature] will move in the direction inscribed on the sigil and leave a Web in it's old space. [creature] can move back over webs it has placed.", "持牌者合终，[creature]循印所志而移，并于故处留一网。[creature]可复移于自所置之网。");
            // 昆虫类族群的造物不会攻击[creature]。
            AddTranslation("Creatures in the insect tribe will not attack [creature].", "虫族之物不攻[creature]。");
            // 无形传花
            AddTranslation("Weird Latch", "怪传花");
            // 抽到[creature]时，此印记将被随机替换为某个传花类印记。
            AddTranslation("When [creature] is drawn, this sigil is replaced by a random latch sigil.", "[creature]既引，则此印随机易为一传花印。");
            // 狂野易形
            AddTranslation("Wild Shape", "野形");
            // 当使用[creature]时，它会根据持牌人提供的宝石颜色进行变形。
            AddTranslation("When [creature] is played, it transforms based on what gem colours its owner controls.", "[creature]既陈，则因其主持有之宝石颜色而变形。");
            // [creature]会根据持牌人的宝石进行变形……
            AddTranslation("[creature] transforms based on its owner's gems...", "[creature]因其主之宝石而变形……");
            // 怯战
            AddTranslation("Wimpy", "怯弱");
            // [creature]对造物造成伤害时，实际伤害值总会比应有值少1点。
            AddTranslation("When [creature] deals damage to a creature, it will always deal 1 less damage than it should.", "[creature]伤物时，所成之伤恒少其应有者1。");
            // 碎翼者
            AddTranslation("Wing Clipper", "翦翼者");
            // 当[creature]入场时，所有带有空袭印记的敌方造物将失去该印记。
            AddTranslation("When [creature] is played, all opponent creatures with the Airborne sigil lose the Airborne sigil.", "[creature]既陈，凡敌物负空袭印者，皆失其印。");
            // [creature]让所有对手落地了！
            AddTranslation("[creature] grounds all its opponents!", "[creature]使群敌皆坠地矣！");
            // 骑翼者
            AddTranslation("Wingrider", "乘翼者");
            // 当持牌人使用任意友方飞行造物时，若[creature]位于手牌中，该卡牌会自动部署至其相邻位置。
            AddTranslation("If a friendly airborne creature is played while [creature] is in the owner's hand, this card will be played adjacent to it.", "若友方飞物既陈而[creature]在主手中，则此牌自陈于其邻位。");
            // 法树领主
            AddTranslation("Woodsie Lord", "术松主");
            // 使用[creature]时，所有空位将生成附魔松树。附魔松树具有：0点力量、3点生命。
            AddTranslation("When [creature] is played, Enchanted Pines are created on every empty space. An enchanted pine is defined as 0 power, 3 health.", "[creature]既陈，诸空位皆生附魔松。附魔松者：0威、3命。");
            // 蠕形螨动
            AddTranslation("Wriggle", "蠕动");
            // 当使用[creature]时，会对所有敌方造物造成1点伤害。
            AddTranslation("When [creature] is played it deals 1 damage to all opponent creatures.", "[creature]既陈，则敌方诸物皆受1伤。");
            // 垂死挣扎
            AddTranslation("Writhe", "挣命");
            // [creature]阵亡时，会对所有正对面的位置造成1点伤害。
            AddTranslation("When [creature] perishes, it will attack all opposing spaces for 1 damage.", "[creature]死，则击敌侧诸位，各一伤。");
            // 你这肮脏的野狗！现在得让我的水手去擦洗甲板了！
            AddTranslation("Ye filthy dog! Now one o' me maties needs to swab the poop deck!", "汝秽犬！今吾舟侣须涤艉楼甲板矣！");
            // 四面骰
            AddTranslation("1d4", "四面骰");
            // 该印记代表的数值初始为2，之后每回合开始时将随机变为1至4之间的数字。
            AddTranslation("The value represented with this sigil starts at 2, and will become a random number between 1 and 4 at the start of each subsequent turn.", "此印之数始二，其后每合始，偶为一至四。");
            // [creature]的力量初始为2，之后每回合开始时将随机变为1至4之间的数字。
            AddTranslation("[creature]s power starts at 2, and will become a random number between 1 and 4 at the start of each subsequent turn.", "[creature]之威始二，其后每合始，偶为一至四。");
            // 野心家
            AddTranslation("Ambitious", "雄心");
            // 该印记代表的数值始终等于场上最高力量值（无论敌我）。在玩家与对手回合开始时更新。
            AddTranslation("The value represented with this sigil will be equal to highest power number present on the board, regardless of whether the card bearing it is friend or foe. Updates at the start of both the player and opponent turn.", "此印之数，等于局上最高之威；负此牌者敌友无问。敌我合始皆更算。");
            // [creature]的力量等于场上攻击力最高的造物力量值。每回合重新计算。
            AddTranslation("[creature]s power is equal to the power of the creature with the highest attack power on the board. Recalculates each turn.", "[creature]之威，等于局上威最高之物之威；每合更算。");
            // #蚂蚁+2
            AddTranslation("Ant Plus Two", "蚁加二");
            // 该印记代表的数值等于牌桌上蚂蚁数量加二。
            AddTranslation("The value represented with this sigil is equal to the number of ants on the board, plus two.", "此印之数，等于局上蚁数益二。");
            // [creature]的力量等于牌桌上所有友方蚂蚁数量加二。
            AddTranslation("[creature]s power is equal to the number of friendly ants on the board, plus two.", "[creature]之威，等于局上己蚁之数益二。");
            // 鸟为媒
            AddTranslation("Birds of a Feather", "同羽");
            // 该印记代表的数值等于牌桌上所有鸟类族群造物的数量（包含对手的造物）。
            AddTranslation("The value represented with this sigil will be equal to the number of avian tribe creatures on the board, including opponent creatures.", "此印之数，等于局上羽属物之数，敌物亦计。");
            // [creature]的力量等于牌桌上所有鸟类族群造物的数量（包含对手的造物）。
            AddTranslation("[creature]s power is equal to the number of avian tribe creatures on the board, including opponent creatures.", "[creature]之威，等于局上羽属物之数，敌物亦计。");
            // 血与骨
            AddTranslation("Blood and Bone", "血骨");
            // 该印记代表的数值等于对面卡牌的骨头费用，或对面卡牌血量费用的两倍。
            AddTranslation("The value represented with this sigil will be equal to the bone cost of the opposing card, or double the blood cost of the opposing card.", "此印之数，等于所对之牌骨直，或其血直二倍。");
            // [creature]的力量等于对面造物的骨头的费用加上其血量费用的两倍
            AddTranslation("[creature]s power is equal to the bone cost of the opposing creature plus twice the blood cost of the opposing creature.", "[creature]之威，等于所对之物骨直，加其血直二倍。");
            // 不变之骨
            AddTranslation("Boned", "骨定");
            // 该印记代表的数值等于持牌人在放置该造物时持有的骨头数量。放置后骨头数量变化不会影响该数值。
            AddTranslation("The value represented with this sigil will be equal to the number of bones the owner possessed when the bearer was placed. Does not fluctuate with bone count changes post placement.", "此印之数，等于其主陈此物时所持骨数；陈后骨数虽易，此数不移。");
            // [creature]的生命值等于持牌人在放置该造物时持有的兽骨数量。放置后兽骨数量变化不会影响该数值。
            AddTranslation("[creature]s health is equal to the number of bones the owner possessed when it was placed. Does not fluctuate with bone count changes post placement.", "[creature]之命，等于其主陈之时所持骨数；陈后骨数虽易，此数不移。");
            // 螃蟹舞
            AddTranslation("Crab Dance", "蟹舞");
            // 该印记代表的数值等于牌桌上所有甲壳类族群造物的数量（包括对手的造物）。
            AddTranslation("The value represented with this sigil will be equal to the number of crustacean tribe creatures on the board, including opponent creatures.", "此印所表之数，如局上甲属诸物之数，敌物亦在焉。");
            // [creature]的力量等于牌桌上所有甲壳类族群造物的数量（包括对手的造物）。
            AddTranslation("[creature]s power is equal to the number of crustacean tribe creatures on the board, including opponent creatures.", "[creature]之威，如局上甲属诸物之数，敌物亦在焉。");
            // 伤害骰子
            AddTranslation("Damage Dice", "骰威");
            // 该印记初始数值为3，之后每回合开始时将随机变为1至6之间的数值。
            AddTranslation("The value represented with this sigil starts at 3, and will become a random number between 1 and 6 at the start of each subsequent turn.", "此印所表之数，始于三；后每合始，偶变为一至六。");
            // [creature]的攻击力初始为3，之后每回合开始时将随机变为1至6之间的数值。
            AddTranslation("[creature]s power starts at 3, and will become a random number between 1 and 6 at the start of each subsequent turn.", "[creature]之威始于三；后每合始，偶变为一至六。");
            // 伤害缩放
            AddTranslation("Damage Scaling", "败余");
            // 该印记代表的数值等于5减去你距离败北还需承受的伤害值。
            AddTranslation("The value represented with this sigil will be equal to five minus the amount of damage until you lose the game.", "此印所表之数，如五减汝至败所余受伤之数。");
            // [creature]的力量等于5减去你距离败北还需承受的伤害值。
            AddTranslation("[creature]s power is equal to five minus the amount of damage until you lose the game.", "[creature]之威，如五减汝至败所余受伤之数。");
            // 操盘手
            AddTranslation("Director Of The Board", "局督");
            // 该印记代表的数值等于牌桌上所有卡牌的数量，包括对手的卡牌。
            AddTranslation("The value represented with this sigil will be equal to the number of cards on the board, including opponent cards.", "此印所表之数，如局上诸牌之数，敌牌亦在焉。");
            // [creature]的力量等于牌桌上所有卡牌的总数，包括对手的造物。
            AddTranslation("[creature]s power is equal to the total number of cards on the board, including opponent creatures.", "[creature]之威，如局上诸牌之总数，敌物亦在焉。");
            // 抽离之力
            AddTranslation("Drawn Out", "引积");
            // 该印记代表的数值等于本回合内当持有者位于牌桌上时你抽牌的数量。
            AddTranslation("The value represented with this sigil will be equal to the number of cards you have drawn this turn while it's bearer is on the board.", "此印所表之数，如此合中其持者在局时汝所引之牌数。");
            // [creature]的力量等于本回合内当它位于牌桌上时你抽牌的数量。
            AddTranslation("[creature]s power is equal to the number of cards you have drawn this turn while it is on the board.", "[creature]之威，如此合中其在局时汝所引之牌数。");
            // 稀有传奇
            AddTranslation("Fabled", "罕传");
            // 该印记代表的数值等于牌桌上稀有造物数量的两倍。
            AddTranslation("The value represented with this sigil will be equal to twice the number of rare creatures on the board.", "此印所表之数，如局上罕有物数之再。");
            // [creature]的力量等于牌桌上稀有造物数量的两倍。
            AddTranslation("[creature]s power is equal to twice the number of rare creatures on the board.", "[creature]之威，如局上罕有物数之再。");
            // 火焰之力
            AddTranslation("Firepower", "火威");
            // 该印记代表的数值等于场上带有燃烧印记的造物数量。
            AddTranslation("The value represented with this sigil will be equal to the number of creatures on the board with the Burning sigil.", "此印所表之数，如局上有焚印之物数。");
            // [creature]的力量等于场上带有燃烧印记的造物数量。
            AddTranslation("[creature]s power is equal to the number of creatures on the board with the Burning sigil.", "[creature]之威，如局上有焚印之物数。");
            // 跟随领导
            AddTranslation("Follow The Leader", "随长");
            // 该印记代表的数值将等于你手牌中第一张卡牌的攻击力。
            AddTranslation("The value represented with this sigil will be equal to the attack power of the first card in your hand.", "此印所表之数，如汝手中首牌之威。");
            // [creature]的力量等于你手牌中第一张卡牌的攻击力
            AddTranslation("[creature]s power is equal to the attack power of the first card in your hand.", "[creature]之威，如汝手中首牌之威。");
            // 绿芽
            AddTranslation("Greenhorn", "绿角");
            // 该印记代表的数值等于卡牌打出时持牌人侧牌桌上绿宝石数量的两倍。
            AddTranslation("The value represented with this sigil will be equal to twice the number of Green gems on the owner's side of the board when the bearer was played.", "此印所表之数，如其既陈之时持牌者一侧局上绿玉数之再。");
            // [creature]的生命值等于其打出时持牌人侧牌桌上绿宝石数量的两倍。
            AddTranslation("[creature]s health is equal to twice the number of Green gems on it's owner's side of the board when it was played.", "[creature]之命，如其既陈之时持牌者一侧局上绿玉数之再。");
            // 半充能
            AddTranslation("Half Charged", "半充");
            // 该印记代表的数值等于玩家当前能量值的一半（向上取整）。
            AddTranslation("The value represented with this sigil will be equal to half the player's current energy, rounded up.", "此印所表之数，如玩家今能之半，分奇则进一。");
            // [creature]的力量等于你当前能量值的一半（向上取整）。
            AddTranslation("[creature]s power is equal to half your current energy, rounded up.", "[creature]之威，如汝今能之半，分奇则进一。");
            // 手按心
            AddTranslation("Hand On Heart", "按心");
            // 该印记代表的数值等于你手中的卡牌数。
            AddTranslation("The value represented with this sigil will be equal to the number of cards in your hand.", "此印所表之数，如汝手中牌数。");
            // [creature]的生命值等于你手中的卡牌数。
            AddTranslation("[creature]s health is equal to the number of cards in your hand.", "[creature]之命，如汝手中牌数。");
            // 生命伤害
            AddTranslation("Health Damage", "命威");
            // 该印记代表的数值等于携带者当前的生命值。
            AddTranslation("The value represented with this sigil will be equal to it's bearer's current health.", "此印所表之数，如其持者今命。");
            // [creature]的力量等于其生命值
            AddTranslation("[creature]s power is equal to its health.", "[creature]之威，如其命。");
            // 放牧兽
            AddTranslation("Herding Beast", "群蹄");
            // 该印记代表的数值等于牌桌上所有有蹄类族群造物的数量（包括对手的造物）。
            AddTranslation("The value represented with this sigil will be equal to the number of hooved tribe creatures on the board, including opponent creatures.", "此印所表之数，如局上蹄属诸物之数，敌物亦在焉。");
            // [creature]的力量等于牌桌上所有有蹄类族群造物的数量（包括对手的造物）。
            AddTranslation("[creature]s power is equal to the number of hooved tribe creatures on the board, including opponent creatures.", "[creature]之威，如局上蹄属诸物之数，敌物亦在焉。");
            // 亲石者
            AddTranslation("Lithophile", "亲石");
            // 该印记代表的数值等于牌桌上地形牌的数量。
            AddTranslation("The value represented with this sigil will be equal to the number of terrain cards on the board.", "此印所表之数，如局上地形牌数。");
            // [creature]的力量等于牌桌上地形牌的数量。
            AddTranslation("[creature]s power is equal to the number of terrain cards on the board.", "[creature]之威，如局上地形牌数。");
            // 魔法力量
            AddTranslation("Magicke Power", "术威");
            // 该印记代表的数值等于该卡牌通过漂白剂印记或艺术许可印记移除的印记数量。
            AddTranslation("The value represented with this sigil is equal to the number of sigils this card has removed with the Bleach Sigil or Artistic License Sigil.", "此印所表之数，如此牌以漂液印与艺纵印所去之印数。");
            // [creature]的力量等于其通过漂白剂印记或艺术许可印记移除的印记数量。
            AddTranslation("[creature]s power is equal to the number of sigils it has removed with the Bleach Sigil or Artistic License Sigil.", "[creature]之威，如其以漂液印与艺纵印所去之印数。");
            // 半只松鼠
            AddTranslation("One Half Squirrels", "半鼠");
            // 该印记代表的数值等于你方副牌组中剩余松鼠数量的一半。
            AddTranslation("The value represented with this sigil will be equal to half the number of Squirrels remaining in your side deck. ", "此印所表之数，如汝副牌中余松鼠数之半。");
            // [creature]的力量等于你方副牌组中剩余松鼠数量的一半。
            AddTranslation("[creature]s power is equal to half the number of Squirrels remaining in your side deck.", "[creature]之威，如汝副牌中余松鼠数之半。");
            // 犬之猎
            AddTranslation("Pack Hunter", "群犬");
            // 该印记代表的数值等于牌桌上犬类族群造物的总数，包括对手的造物。
            AddTranslation("The value represented with this sigil will be equal to the number of canine tribe creatures on the board, including opponent creatures.", "此印所表之数，如局上犬属诸物之数，敌物亦在焉。");
            // [creature]的力量等于牌桌上犬类族群造物的总数，包括对手的造物。
            AddTranslation("[creature]s power is equal to the number of canine tribe creatures on the board, including opponent creatures.", "[creature]之威，如局上犬属诸物之数，敌物亦在焉。");
            // 道具力量
            AddTranslation("Pack Power", "器威");
            // 该印记代表的数值等于持牌人持有的道具数量。
            AddTranslation("The value represented with this sigil will be equal to the number of items the owner holds.", "此印所表之数，如持牌者所执器数。");
            // [creature]的力量等于持牌人持有的道具数量。
            AddTranslation("[creature]s power is equal to the number of items it's owner holds.", "[creature]之威，如持牌者所执器数。");
            // 双重道具力量
            AddTranslation("Pack Power Plus", "重器威");
            // 该印记代表的数值等于持牌人持有道具数量的两倍。
            AddTranslation("The value represented with this sigil will be equal to twice the number of items the owner holds.", "此印所表之数，如持牌者所执器数之再。");
            // [creature]的力量等于持牌人持有道具数量的两倍。
            AddTranslation("[creature]s power is equal to twice the number of items it's owner holds.", "[creature]之威，如持牌者所执器数之再。");
            // 狂热血祭
            AddTranslation("Sanguine Bond", "血契");
            // 该印记代表的数值等于带有印记的造物被放置时该回合内做出的献祭次数。
            AddTranslation("The value represented with this sigil will be equal to the number of sacrifices made on the turn when the bearer was placed.", "此印所表之数，如其持者既陈之合中所祀之数。");
            // [creature]的力量等于其被放置时该回合内做出的献祭次数。
            AddTranslation("[creature]s power is equal to the number of sacrifices made on the turn when it was placed.", "[creature]之威，如其既陈之合中所祀之数。");
            // 罪食者
            AddTranslation("Sin Eater", "食罪");
            // 该印记代表的数值等于召唤该造物时被献祭造物携带的印记总数。
            AddTranslation("The value represented with this sigil will be equal to the amount of sigils present on the creatures that were sacrificed to play it's bearer.", "此印所表之数，如陈其持者时所祀诸物所带印之总数。");
            // [creature]的力量等于召唤该造物时被献祭造物携带的印记总数。
            AddTranslation("[creature]s power is equal to the amount of sigils present on the creatures that were sacrificed to play it.", "[creature]之威，如陈之时所祀诸物所带印之总数。");
            // 饥渴
            AddTranslation("Starved", "饥");
            // 该印记代表的数值等于7减去你牌组中剩余的卡牌数。
            AddTranslation("The value represented with this sigil will be equal to seven minus the number of cards left in your deck.", "此印所表之数，如七减汝牌列所余之牌数。");
            // [creature]的力量等于7减去你牌组中剩余的卡牌数
            AddTranslation("[creature]s power is equal to seven minus the number of cards left in your deck.", "[creature]之威，如七减汝牌列所余之牌数。");
            // 众志成城
            AddTranslation("Strength In Numbers", "众威");
            // 该印记代表的数值等于牌桌上所有带有相同印记的造物数量（包括对手造物）。
            AddTranslation("The value represented with this sigil will be equal to the number of creatures bearing this sigil on the board, including opponent creatures.", "此印所表之数，如局上有此同印之物数，敌物亦在焉。");
            // [creature]的力量等于牌桌上所有带有相同特殊伤害属性的造物数量（包括对手造物）。
            AddTranslation("[creature]s power is equal to the number of creatures bearing the same special damage stat on the board, including opponent creatures.", "[creature]之威，如局上有此同特伤数之物数，敌物亦在焉。");
            // 道具生命力
            AddTranslation("Trinket Vitality", "器命");
            // 该印记代表的数值等于持牌人持有道具数量的两倍。
            AddTranslation("The value represented with this sigil will be equal to double the number of items the owner holds.", "此印所表之数，如持牌者所执器数之再。");
            // [creature]的生命等于其持牌人持有道具数量的两倍。
            AddTranslation("[creature]s health is equal to twice the number of items it's owner holds.", "[creature]之命，如持牌者所执器数之再。");
            // 万维网
            AddTranslation("World Wide Web", "天网");
            // 该印记代表的数值等于牌桌上所有蛛形类族群造物的数量（包括对手的造物）。
            AddTranslation("The value represented with this sigil will be equal to the number of arachnid tribe creatures on the board, including opponent creatures.", "此印所表之数，如局上蛛属诸物之数，敌物亦在焉。");
            // [creature]的力量等于牌桌上所有蛛形类族群造物的数量（包括对手的造物）。
            AddTranslation("[creature]s power is equal to the number of arachnid tribe creatures on the board, including opponent creatures.", "[creature]之威，如局上蛛属诸物之数，敌物亦在焉。");
            // 忍住
            AddTranslation("Abstain", "止");
            // 丰产囤积狂
            AddTranslation("Dupeglitch", "孳囤");
            // 左前打击
            AddTranslation("Sinister Strike", "左斜击");
            // 横行霸道
            AddTranslation("Bully", "凌");
            // 集团
            AddTranslation("Legion", "军");
            // 血魔
            AddTranslation("Bloodborn", "血裔");
            // 占星师
            AddTranslation("Divination", "卜");
            // 寻墓者
            AddTranslation("Exhume", "发冢");
            // 天使坠落
            AddTranslation("Eternal", "恒");
            // 山羊召唤
            AddTranslation("Goated", "召羊");
            // 治疗师
            AddTranslation("Healer", "疗者");
        }

    }

    public class AllTheSigilsMod
    {
        public static void RegisterTranslations()
        {
            // Card
            // 酸液滩
            AddTranslation("Acid Puddle", "酸沼");
            // 一滩酸液，摸起来很危险。
            AddTranslation("A puddle of Acid, dangerous to the touch", "酸潴一滩，触之则危。");
            // 鹿角兔
            AddTranslation("Jackalope", "鹿角兔");
            // 杰卡
            AddTranslation("Jacka", "杰卡");

            // Ability
            // 五谷丰登
            AddTranslation("Abundance", "丰");
            // [creature]死亡时，每有一个五谷丰登的实例，就会获得一个货币。
            AddTranslation("[creature] will grant one tooth per instance of Abundance when killed.", "[creature]死时，每有一重丰，得一齿。");
            // 酸性痕迹
            AddTranslation("Acidic Trail", "酸迹");
            // 在持牌人回合结束时，[creature]将沿印记标注的方向移动，如果能够移动，则对其对位造物造成1点伤害。
            AddTranslation("At the end of the owner's turn, [creature] will move in the direction inscribed in the sigil, and deal 1 damage to the opposing creature if it is able to move.", "持牌者合终，[creature]循印所志之向而移；若能移，则伤其对物一。");
            // 脆骨激转
            AddTranslation("Activated Latch Brittle", "启脆");
            // 激活时消耗1点能量，将允许持牌人给予一个造物脆骨印记。
            AddTranslation("When activated for a cost of 1 energy will allow the owner to give a creature Brittle.", "启之而费一能，则持牌者可予一物以脆骨。");
            // 炸弹激转
            AddTranslation("Activated Latch Explode On Death", "启殉爆");
            // 激活时消耗1点能量，将允许持牌人给予一个造物引爆器印记。
            AddTranslation("When activated for a cost of 1 energy will allow the owner to give a creature Explode On Death.", "启之而费一能，则持牌者可予一物以死爆。");
            // 坚盾激转
            AddTranslation("Activated Latch Nano Shield", "启坚盾");
            // 激活时消耗1点能量/2根骨头，将允许持牌人给予一个造物纳米铠甲。
            AddTranslation("When activated for a cost of 1 energy / 2 bones will allow the owner to give a creature Nano Shield.", "启之而费一能或二骨，则持牌者可予一物以坚盾。");
            // 高跳激转
            AddTranslation("Activated Latch Reach", "启高跃");
            // 激活时消耗2点能量，将允许持牌人给予一个造物高跳印记。
            AddTranslation("When activated for a cost of 2 energy will allow the owner to give a creature Reach.", "启之而费二能，则持牌者可予一物以高跃。");
            // 敏捷
            AddTranslation("Agile", "捷");
            // 当[creature]将被击中时，它会跳开躲避。
            AddTranslation("When [creature] would be struck, it will move out of the way.", "[creature]将见击，则避而移。");
            // 这张牌为了保全自己而跳到一边……
            AddTranslation("The Card jumped out of the way to save itself...", "此牌跃而自全矣……");
            // 他们留下的痕迹让人生疼。
            AddTranslation("The trail they leave behind, hurts.", "其所遗之迹，伤人。");
            // 全知之眼
            AddTranslation("All seeing", "全见");
            // 当[creature]在场时，同侧场上的所有会说话的卡牌获得+2生命。
            AddTranslation("While [creature] is on the board, all talking cards on your side of the board get +2 health.", "凡[creature]在局，汝侧诸言牌命益二。");
            // 交替爪迹
            AddTranslation("Alternating Scratch", "交爪");
            // 当[creature]攻击时，它还会攻击对位相邻的空间，它将攻击的相邻位置将在每个对手回合结束时在左右之间切换。
            AddTranslation("When [creature] attacks it will also attack a space adjacent to the attacked slot, the adjacent slot that it will attack will change between left or right at the end of each opponent's turn.", "[creature]攻时，亦击所攻位旁一位；所击之旁位，每敌合终，左右迭易。");
            // 伏击
            AddTranslation("Ambush", "伏");
            // 当造物移动到与[creature]相对的空间时，它们会受到1点伤害。
            AddTranslation("When a creature moves into the space opposing [creature], they are dealt 1 damage.", "有物移入[creature]对位之处，则受一伤。");
            // 鹿角商
            AddTranslation("Antler Bearer", "荷角");
            // 当[creature]被消灭时，随机获得三张随机有蹄类族群卡牌。
            AddTranslation("When [creature] is killed, gain three random hooved tribe cards.", "[creature]死，则得蹄属之牌三，皆偶然。");
            // 牧群聚在一起。
            AddTranslation("The herd sticks together.", "群蹄相附。");
            // 屏蔽
            AddTranslation("Shielded", "蔽");
            // 当[creature]受到伤害时，造成的伤害减半，向下取整。
            AddTranslation("When [creature] is dealt damage, the damage dealt is halved, rounded down.", "[creature]受伤，其伤减半，分奇则舍。");
            // 休眠
            AddTranslation("Asleep", "寐");
            // [creature]只要拥有此印记，攻击力为0，玩家回合开始时，此印记将从[creature]上移除。
            AddTranslation("[creature] has 0 attack for as long as it has this sigil, at the start of the player's turn this sigil will be removed from [creature].", "[creature]有此印时，威为零；及玩家合始，此印自去。");
            // 钓饵
            AddTranslation("Bait", "饵");
            // 当对侧上场卡牌时，若没有与[creature]相对位的卡牌，该造物将移动到[creature]的对位。
            AddTranslation("When an opposing creature is played and there is no card opposite of [creature], the opposing creature will move to that spot.", "敌物既陈，而[creature]对位无牌，则彼移就其位。");
            // 卓越祭品
            AddTranslation("Noble Sacrifice", "贵祭");
            // [creature]在献祭时可算作2点血量，而非1点。
            AddTranslation("[creature] is counted as 2 blood rather than 1 blood when sacrificed.", "[creature]祀时计二血，不一。");
            // 枯萎之血
            AddTranslation("Blight", "凋血");
            // 当[creature]被献祭时，献祭其上场的卡牌减去其属性值。
            AddTranslation("When [creature] is sacrificed, it subtracts its stat values to the card it was sacrificed for.", "[creature]祀时，所为而陈之牌减其数。");
            // 随机打击
            AddTranslation("Random Strike", "漫击");
            // [creature]攻击时会随机打击对手槽位。
            AddTranslation("[creature] will strike at opponent slots randomly when it attacks.", "[creature]攻时，漫击敌位。");
            // 致盲打击
            AddTranslation("Blinding Strike", "盲击");
            // 当[creature]对另一造物造成伤害时，该造物获得随机打击印记。
            AddTranslation("When [creature] damages another creature, that creature gains the Random Strikes Sigil.", "[creature]伤他物，则彼得漫击印契。");
            // 它们的攻击如此..宽广……
            AddTranslation("They strike widly...", "其击乱矣……");
            // 血液生长
            AddTranslation("Blood Growth", "长血");
            // 当[creature]攻击时，其作为祭品时计算的血量将会增加。
            AddTranslation("When [creature] attacks, the amount of blood it is counted as when sacrificed will increase.", "[creature]攻，则祀时所计之血益。");
            // 血液中蕴含力量。
            AddTranslation("There is power in the blood.", "血中有威。");
            // 鲜血吞噬者
            AddTranslation("BloodGuzzler", "饮血者");
            // [creature]造成伤害时，每造成1点伤害便获得1点生命值。
            AddTranslation("[creature] deals damage, it gains 1 Health for each damage dealt.", "[creature]出伤，每伤一，命益一。");
            // 从血中获得生命。
            AddTranslation("Gain life from the blood.", "饮血而生。");
            // 嗜血易形
            AddTranslation("Blood shifter", "血移");
            // 当[creature]杀死另一张牌时，它将变成那张牌。
            AddTranslation("When [creature] kills another card, it will turn into that card.", "[creature]杀他牌，则化为彼牌。");
            // 保镖
            AddTranslation("Bodyguard", "卫");
            // 如果相邻的位置将受到攻击，攻击者会改为攻击[creature]。
            AddTranslation("[creature] will redirect the initial attack of a card to it, if the attack was targeting a card in an adjacent space.", "相邻之位将见攻，则其初击改归[creature]。");
            // 一位致死也要坚持守护的保镖。
            AddTranslation("A protector, till the very end.", "卫之至终。");
            // 投弹虫
            AddTranslation("Bombardier", "投弹虫");
            // [creature]将在每个持牌人的回合结束阶段对场上任何一个随机造物造成10点伤害。
            AddTranslation("[creature] will deal 10 damage to a random creature during the end phase of the owner's turn.", "持牌者合终，[creature]随机伤一物十。");
            // 情同手足
            AddTranslation("Bond", "契");
            // 当[creature]左侧有卡牌时，[creature]将增加1点力量；当[creature]右侧有卡牌时，[creature]将增加1点生命。
            AddTranslation("Any creatures adjacent to [creature] will gain either +1 attack or +1 health, depending on which stat it is closest to.", "[creature]旁诸物，或威益一，或命益一，视其所近之数而定。");
            // [creature]死亡时没有骨头，所有印记给予的额外骨头将不生效。
            AddTranslation("[creature] gives no bones! Any bones gained from sigils or death will be negated.", "[creature]不出骨！凡由印契或死所得之骨，皆不算。");
            // 这个造物没有骨头！
            AddTranslation("That creature has no bones!", "彼物无骨！");
            // 衔骨者
            AddTranslation("Bone Picker", "衔骨者");
            // [creature]每杀死一个造物，将生成1根骨头。
            AddTranslation("[creature] kills a creature, it will generate 1 Bone.", "[creature]杀一物，则生一骨。");
            // 骨头碎片
            AddTranslation("Bone Shard", "骨屑");
            // [creature]被击中时，如果存活下来，将给予持有者1根骨头。
            AddTranslation("[creature] will generate 1 bone when hit, if it lives through the attack.", "[creature]见击而不死，则生一骨。");
            // 一块骨头的碎片。
            AddTranslation("A splinter of bone.", "骨之一屑。");
            // 盒中之物
            AddTranslation("Box", "匣");
            // [creature]死亡时将从你的牌组中移除，并在你的卡组中添加一个包含其中的新造物。
            AddTranslation("[creature] will get removed from your deck on death, and a new creature contained within will be added to it.", "[creature]死，则自汝牌列去；匣中别物入焉。");
            // 破碎
            AddTranslation("Broken", "残");
            // [creature]死亡后将永久从你的牌组中移除。
            AddTranslation("[creature] is permanently removed from your deck if it dies.", "[creature]若死，永出汝牌列。");
            // [creature]在燃烧，并在每个回合结束时获得1点力量并失去1点生命值。可由防火免疫。
            AddTranslation("[creature] is on fire, and will gain 1 power and loose 1 health each upkeep. Blocked by Fire Resistance.", "[creature]在火中，每合始威益一而命损一；火拒可遏之。");
            // 它在燃烧时狂暴。
            AddTranslation("It rampages while on fire.", "火中而狂。");
            // 在其持有者的回合结束时，[creature]将朝着印记标注的方向移动，并在其原位置留下一个酸液滩。
            AddTranslation("At the end of the towner's turn, [creature] will move in the direction inscribed in the sigil, and drop an acid puddle in their old space.", "持牌者合终，[creature]循印所志之向而移，而遗一酸沼于故处。");
            // [creature]被计为一只鸡。
            AddTranslation("[creature] counts as a Chicken.", "[creature]计作一鸡。");
            // 舞蹈编排
            AddTranslation("Choreography", "舞度");
            // 激活后，[creature]将循环：不动、向左移动和向右移动。在持牌人回合结束时，[creature]将按照选择的方式移动。
            AddTranslation("On activation [creature] will cycle through: don't move, move left and move right. At the end of the owner's turn [creature] will move in the chosen way.", "启之，则于不动、左移、右移三者循环；持牌者合终，[creature]依所择而移。");
            // 硬币寻找者
            AddTranslation("Coin Finder", "索箔");
            // 在持牌人的回合结束时，[creature]将赋予其1枚硬币。
            AddTranslation("At the end of the owner's turn, [creature] will grant the owner 1 foil.", "持牌者合终，[creature]予其主一箔。");
            // 这颗牙齿是你的意愿吗？
            AddTranslation("A tooth for your thoughts?", "以一齿问汝心乎？");
            // 消费者
            AddTranslation("Consumer", "啖");
            // 当[creature]击杀其他造物时，它获得2点生命值。
            AddTranslation("When [creature] kills another creature, it gains 2 health.", "[creature]杀他物，则命益二。");
            // 懦夫
            AddTranslation("Cowardly", "怯");
            // [creature]不会攻击比自身攻击力高2的卡牌。
            AddTranslation("[creature] will not attack a card with a power 2 higher than its own.", "[creature]不攻威逾己二之牌。");
            // 死亡水域
            AddTranslation("Deadly Waters", "死水");
            // [creature]在它潜水时，会消灭攻击过它位置的卡牌。不影响拥有空袭和磐石之身的卡牌。
            AddTranslation("[creature] will kill cards that attacked over it while it was face-down. Does not affect cards that have Airborne or Made of Stone.", "[creature]翻伏时，凡越其位而攻者皆死；翔袭与石身者不与。");
            // 死亡爆发
            AddTranslation("Deathburst", "死爆");
            // [creature]在死亡时会对其左侧、右侧和自身的每个敌对空间造成1点伤害。
            AddTranslation("[creature] will deal 1 damage to each oppsing space to the left, right, and center of it.", "[creature]死，则伤其敌左、敌右与敌前各一。");
            // 在持牌人的回合开始时，[creature]将失去1点攻击力并获得1点生命值。
            AddTranslation("At the Start of its owner's turn [creature] will lose -1 attack and will gain +1 health.", "持牌者合始，[creature]威减一，而命益一。");
            // 绝望之力
            AddTranslation("Desperation", "穷急");
            // [creature]受伤至只有1点生命时，其获得3点力量。
            AddTranslation("[creature] is damaged to 1 health, it will gain 3 power.", "[creature]伤至惟一命，则威益三。");
            // 当离死亡如此之近的时候，它爆发了。
            AddTranslation("When so close to death, it strikes out.", "迫死则奋。");
            // 疫病汲取
            AddTranslation("Disease Absorbtion", "吸疠");
            // 当[creature]上场时，其会将场上所有负面印记转移到自身。
            AddTranslation("When played, [creature] will take all negative sigils onto itself.", "[creature]既陈，尽取诸负印于身。");
            // 多么高尚。
            AddTranslation("How Noble.", "高矣。");
            // 骨驱水袭
            AddTranslation("Dive (Bones)", "骨潜");
            // 消耗2根骨头，持牌人的回合结束时，[creature]将潜水一回合（重复点击没有效果，除非你想浪费骨头）。
            AddTranslation("Pay 2 bones to cause this card to flip face down at the end of the owner's turn.", "费二骨，则持牌者合终，此牌翻伏。");
            // 电驱水袭
            AddTranslation("Dive (Energy)", "能潜");
            // 消耗2点能量，持牌人的回合结束时，[creature]将潜水一回合（重复点击没有效果，除非你想浪费能量）。
            AddTranslation("Pay 2 energy to cause this card to flip face down at the end of the owner's turn.", "费二能，则持牌者合终，此牌翻伏。");
            // 多重打击
            AddTranslation("Multi-Strike", "连击");
            // 如果[creature]攻击的目标在其第一次攻击下存活，其将会多次打击该牌。不会触发额外打击的攻击或受伤的触发器效果。
            AddTranslation("[creature] will strike a card multiple times, if it lives through the first attack. Will not trigger -on attack- or -on damage- effects with the extra strikes.", "[creature]连击一牌；若彼不死于初击，则更击之。额外诸击，不触攻时、受伤时之效。");
            // 双重爪迹
            AddTranslation("Double scratch", "双爪");
            // 当[creature]攻击时，它会攻击两次，并攻击对位的左右两侧的空间。
            AddTranslation("When [creature] attacks it attacks twice and the space right and left of the attacked slot.", "[creature]攻时，再击一次，并及所攻位之左右。");
            // 血绘者
            AddTranslation("Draw Blood", "引血");
            // 当[creature]被召唤时，你的手牌中会随机创建一张消耗血液的卡牌。
            AddTranslation("When [creature] is played, a random card costing blood is created in your hand.", "[creature]既陈，汝手中生一血直之偶牌。");
            // 骨绘者
            AddTranslation("Draw Bone", "引骨");
            // 当[creature]被召唤时，你的手牌中会随机创建一张消耗骨头的卡牌。
            AddTranslation("When [creature] is played, a random card costing bone is created in your hand.", "[creature]既陈，汝手中生一骨直之偶牌。");
            // 冰绘者
            AddTranslation("Draw Card", "引化");
            // 当[creature]被召唤时，会根据其冰立方参数（默认为白鼬）在你的手中创建一张相关卡牌。
            AddTranslation("When [creature] is played, a card relating to it's ice cube parameter (default Stoat) is created in your hand.", "[creature]既陈，依其冰块之参（默认白鼬），汝手中生相关之一牌。");
            // 鹿角兔子洞
            AddTranslation("Draw Jackalope", "引鹿角兔");
            // 当[creature]被召唤时，你会获得一张鹿角兔卡牌，鹿角兔具有：2点力量，2点生命，冲刺能手，鹿角兔子洞。
            AddTranslation("When [creature] is played, a Jackalope is created in your hand.", "[creature]既陈，汝手中生一鹿角兔。");
            // 冲刺绘者
            AddTranslation("Draw Strafe", "引移");
            // 当[creature]移动时，会在你的手中随机创建一张带有移动印记的卡牌。
            AddTranslation("When [creature] moves, a random card with a movement sigil is created in your hand.", "凡[creature]移，则汝手中生一有移印之偶牌。");
            // 花费绘者
            AddTranslation("Draw Cost", "引同直");
            // 当[creature]被召唤时，你的手牌中将随机生成一张与[creature]相同费用类型的卡牌。
            AddTranslation("When [creature] is played, a random card that has the same cost type as [creature] is created in your hand.", "[creature]既陈，汝手中生一与[creature]同直类之偶牌。");
            // 能量绘者
            AddTranslation("Draw Energy", "引能");
            // 当[creature]被召唤时，会在你的手中随机创建一张消耗能量的卡牌。
            AddTranslation("When [creature] is played, a random card costing energy is created in your hand.", "[creature]既陈，汝手中生一能直之偶牌。");
            // 魔绘者
            AddTranslation("Draw Mox", "引玛珂");
            // 当[creature]被召唤时，会在你的手中随机创建一张需要玛珂的卡牌。
            AddTranslation("When [creature] is played, a random card costing mox is created in your hand.", "[creature]既陈，汝手中生一玛珂直之偶牌。");
            // 支援呼叫
            AddTranslation("Support call", "援呼");
            // 当[creature]被召唤时，你立即抽一张副牌堆的牌。
            AddTranslation("When [creature] is played, a card from your sidedeck is created in your hand.", "[creature]既陈，汝手中生一副牌之牌。");
            // 醉酒
            AddTranslation("Drunk", "醉");
            // [creature]将随机打击它对面左右两侧的任意一个敌方空间。
            AddTranslation("[creature] will strike a random one of the opposing spaces to the left and right of the space across from it.", "[creature]漫击其对位左右之一敌位。");
            // 矮人
            AddTranslation("Dwarf", "矮");
            // 当[creature]被抽到时，它将失去一个单位的花费，以及1点力量和2点生命（生命值不能低于1点）。一个单位被定义为：1点血量、3根骨头、3点能量或所有玛珂需求。
            AddTranslation("When [creature] is drawn, it will loose one unit of cost, as well as 1 power and 2 health (can't go below 1 health). A unit is defined as: 1 blood, 3 bones, 3 energy, or all mox.", "[creature]既引，则失一直，并威一命二（命不下于一）。一直者：一血、三骨、三能，或尽其玛珂。");
            // 奄奄一息
            AddTranslation("Dying", "将死");
            // [creature]将在X个回合后死亡。
            AddTranslation("[creature] will die after X number of turns.", "[creature]历X合而死。");
            // 前往屠杀
            AddTranslation("To The Slaughter", "赴屠");
            // 每回合结束时，[creature]将随机吃掉一只鸡，获得与被吃掉鸡的生命值相同的攻击力，并获得与被吃掉鸡的攻击力相同的生命值。
            AddTranslation("At the end of each turn [creature] will eat a random Chicken gaining the same amount of attack as the eaten chicken's health, and gaining the same amount of health as the eaten chicken's attack.", "每合终，[creature]食一偶鸡，得其所食之鸡命数为威，威数为命。");
            // 电力制导
            AddTranslation("Electric", "旁电");
            // 当[creature]发动攻击时，会对目标相邻的卡牌造成一半伤害。
            AddTranslation("When [creature] decalres an attack, they will deal half the damage to cards adjacent to the target.", "[creature]宣攻时，所中左右邻牌各受其半伤。");
            // 执法者
            AddTranslation("Enforcer", "纠");
            // 在持牌人的回合开始时，[creature]将使相邻的造物攻击。
            AddTranslation("At the start of the owner's turn, [creature] will cause adjacent creatures to attack.", "持牌者合始，[creature]使左右诸物出击。");
            // 超频领袖
            AddTranslation("Enrage", "怒充");
            // [creature]将增加相邻的卡牌2点力量。然而，如果它们在获得力量时阵亡，它们将永久地从你的牌组中被移除。
            AddTranslation("[creature] will empower adjacent allies, increasing their strenght by 2. However, if they perish while empowered, they are permamently removed from your deck.", "[creature]益其旁友牌之威二。然彼受益而死，则永出汝牌列。");
            // 噬虫菌体
            AddTranslation("Entomophage", "啖虫");
            // [creature]将对昆虫类族群的卡牌造成额外2点伤害。
            AddTranslation("[creature] will deal 2 additional damage to cards of the insect tribe.", "[creature]对虫属之牌加伤二。");
            // 我听说它们是蛋白质的好来源。
            AddTranslation("They are a good source of protine I hear.", "闻其颇足为膳。");
            // 当相邻的卡牌攻击一张牌时，[creature]将帮助其攻击。
            AddTranslation("A familiar will help with attacking when it's adjacent allies attack a card.", "相邻之友攻牌，则[creature]助之击。");
            // 胆战心惊
            AddTranslation("Fearful", "惧");
            // 当[creature]被攻击但没有死亡时，它将被送回持牌人手中。
            AddTranslation("When [creature] is struck without it resulting in death, it will be returned to its owner's hand.", "[creature]见击而不死，则反归其主之手。");
            // 充能感应
            AddTranslation("Charge", "骨冲");
            // 消耗3根骨头选择一个敌对卡牌，[creature]将攻击选择的卡牌。
            AddTranslation("Pay 3 bones to choose an enemy creature that [creature] will strike.", "费三骨，择一敌物，[creature]击之。");
            // 星火燎原
            AddTranslation("Firestarter", "发火者");
            // 当[creature]对另一造物造成伤害时，该造物将获得燃烧印记。燃烧印记被定义为：每个维持阶段，[creature]获得1点力量但失去1点生命。
            AddTranslation("When [creature] damages another creature, that creature will gain the Burning Sigil. The Burning Sigil is define as: Each upkeep, this creature gains 1 strength but looses 1 health.", "[creature]伤他物，则彼得焚印。焚印者：每合始，此物威益一而命损一。");
            // 即使战斗结束，也会留下致命的痕迹.
            AddTranslation("Even once combat is over, it leaves a deadly mark", "战罢犹遗死痕。");
            // 饵钓潜袭
            AddTranslation("Lure", "诱");
            // [creature]在攻击时会迫使盖住的卡牌翻面。
            AddTranslation("[creature] will cause facedown cards to become face up when attacking.", "[creature]攻时，使伏牌翻见。");
            // 潜水的造物浮出了水面。
            AddTranslation("The Submerge are brought back to the surface", "潜者复出于水上。");
            // 当放置[creature]时，持牌人可以选择一张敌方的卡牌钩其至自己的一侧。
            AddTranslation("When [creature], a targeted card is moved to the owner's side of the board.", "[creature]既陈，所择一牌移于其主一侧之局。");
            // 骨魔
            AddTranslation("Bone lord 5", "骨王五");
            // 当[creature]死亡时，奖励5根骨头，而不是1根。
            AddTranslation("When [creature] dies, 5 bones are rewarded instead of 1.", "[creature]死，则赏骨五，不一。");
            // 惊恐
            AddTranslation("Frightened", "惊");
            // 当有卡牌移动到与[creature]相对的空间时，[creature]将远离该卡牌移动到随机的相邻空位，优先选择没有任何对位卡牌的空位。
            AddTranslation("When a creature moves into the space opposing [creature], [creature] will move away from that card to a random free adjacent spot, while prioritizing slots without any opposing creatures.", "有物移至与[creature]相对之位，则[creature]避彼而移于一邻空位，先择无对物者。");
            // 令人生畏
            AddTranslation("Frightful", "骇");
            // [creature]攻击时将迫使敌方造物让开道路。
            AddTranslation("[creature] will cause opposing creatures to move out of the way when it attacks.", "[creature]攻时，迫敌物避路。");
            // 当[creature]被召唤时，它将增加1点血祭消耗，以及1点攻击力和2点生命值。
            AddTranslation("When [creature] is drawn, it will gain one unit blood of cost, as well as one attack and two health.", "[creature]既引，则直加一血，并威一命二。");
            // 你那儿的造物多大啊。
            AddTranslation("What a large creature you have there", "汝有大物哉。");
            // 放牧
            AddTranslation("Grazing", "啮草");
            // 在持牌人的回合结束时，如果没有敌方造物，[creature]将回复1点生命值。
            AddTranslation("At the end of the owner's turn, [creature] will regen 1 health if there is no opposing creature.", "持牌者合终，若无对物，[creature]复一命。");
            // 该造物将在其持牌人回合结束时恢复1点生命值。
            AddTranslation("This creature will heal 1 Health at the end of it's owner's turn.", "此物于其主合终复一命。");
            // 夹持器
            AddTranslation("Gripper", "攫");
            // 在持牌人的回合结束时，[creature]将朝着印记标注的方向移动，如果可能，将尝试带着对方造物一起移动。
            AddTranslation("At the end of the owner's turn, [creature] will move in the direction inscribed in the sigil, and try to move the opposing creature with it if it can.", "持牌者合终，[creature]循印所志之向而移；若能，则并引其对物俱移。");
            // 它们留下的痕迹让人生疼。
            AddTranslation("The trail they leave behind, hurts.", "其所遗之迹，伤人。");
            // 匆忙
            AddTranslation("Haste", "亟");
            // [creature]一旦被放置到场上便会立刻攻击一次。
            AddTranslation("[creature] will attack as soon as it gets played on the board if played not during combat.", "[creature]若于战外既陈，则即攻。");
            // 急于求成
            AddTranslation("Hasteful", "先击");
            // [creature]将在被放置到场地上后立即攻击。它不会在正常战斗中攻击，它将在持牌人的回合开始时攻击。
            AddTranslation("[creature] will attack as soon as it gets played on the board. It will not attack during normal combat. It will attack at the start of the owner's turn.", "[creature]既陈即攻。常战之时则不攻，而于持牌者合始攻。");
            // 芸芸众生
            AddTranslation("Herd", "滋群");
            // [creature]将在每个维持阶段在同侧的空位上召唤一个自己的复制体，最多三次。
            AddTranslation("[creature] will summon a copy of itself each upkeep, up to three times.", "[creature]每合始生一己身之副于同侧空位，至三而止。");
            // 隐士
            AddTranslation("Hermit", "隐");
            // [creature]可以放置在任何地形卡上。若如此做，它们的印记和属性将合并，并创建一个名称组合。
            AddTranslation("[creature] may be placed on any terrain card. If it is their sigils and stats will be combined, and a name combination will be created.", "[creature]可陈于诸地形牌上。若然，则并其印与数，而成一合名。");
            // 涨潮之时
            AddTranslation("High Tide", "潮涨");
            // 当[creature]在场时，它将为同一侧的场上造物赋予水袭印记。不影响具有空袭印记的卡牌。
            AddTranslation("While [creature] is on the board, it will grant the waterborne sigil of cards that are played after it on it's side of the board. Does not affect cards that are Airborne.", "凡[creature]在局，后陈于其侧之牌皆得潜袭印契。翔袭者不与。");
            // 潮水上涨了。
            AddTranslation("The waters rise.", "潮起矣。");
            // 宾至如归
            AddTranslation("Homing", "趋的");
            // 如果[creature]的对位为空，且其相邻的路线有其他卡牌，[creature]将攻击该牌而不是直接攻击。
            AddTranslation("If the opposing slot is empty, and there is a creature in a neighbouring lane, [creature] will attack that creature instead of attacking the opposing slot.", "其对位若空，而邻列有物，则[creature]击彼物，不直击敌主。");
            // 变幻莫测
            AddTranslation("Hoodini", "幻换");
            // 当带[creature]被召唤时，它将与对位造物交换位置。如果对位没有卡牌，它将跑到对面。
            AddTranslation("When [creature] is played, it will swap places with the opposing creature.", "[creature]既陈，则与其对物易位；若彼处无牌，则径赴敌侧。");
            // 巢穴
            AddTranslation("Host", "巢");
            // [creature]是其他造物的巢穴。当它被攻击时，会给你特定的造物。
            AddTranslation("[creature] is the host of other creatures. It will give you such creature when struck.", "[creature]为他物之巢。见击，则予汝其物。");
            // 当[creature]被使用时，将使对手跳过其下一回合。
            AddTranslation("[creature] will cause the opponant to skip their turn when played.", "[creature]既陈，使敌过其一合。");
            // 时光流逝。
            AddTranslation("The sands of time tic away", "时沙渐尽。");
            // 积劳成疾
            AddTranslation("Exhaustion", "惫");
            // [creature]的攻击伤害将减少与它失去的生命值相同的量。
            AddTranslation("The attack of [creature] will be decreased by the same amount as its lost health.", "[creature]之威，减如其所失之命。");
            // 激动
            AddTranslation("Hyped", "奋");
            // [creature]除了在正常战斗期间攻击之外，也会在持牌人的回合开始时攻击。
            AddTranslation("[creature] will attack at the start of the owner's turn in addition to during normal combat.", "[creature]除常战时攻外，亦于持牌者合始攻。");
            // 注灵
            AddTranslation("Imbuing", "赋灵");
            // [creature]将根据用于召唤它的献祭中哪个族群最为突出而获得特定的增益效果。
            AddTranslation("[creature] will get specific buffs depending on which tribe is most promenent in the sacrifices that were used to summon it.", "[creature]所受之益，视召之所用牺牲中何属最著而定。");
            // 未知之触
            AddTranslation("Inaccurate", "失准");
            // [creature]将对其对位以及对位左侧和右侧的一个随机位置进行攻击。
            AddTranslation("[creature] will strike a random one of the opposing spaces to the left and right of the spaces across from it as well as the space in front of it.", "[creature]漫击其对位及其左右之一处。");
            // 岁月年华
            AddTranslation("Old Timer", "老成");
            // 在持牌人的回合开始时，[creature]将获得1点攻击力并受到1点伤害。
            AddTranslation("At the Start of its owner's turn [creature] will gain +1 attack and will take 1 damage.", "持牌者合始，[creature]威益一，而受一伤。");
            // 受伤
            AddTranslation("Injured", "伤");
            // [creature]每次声明攻击时都会因伤势而损失1点生命值。
            AddTranslation("[creature] is hurt and will lose 1 health each time it declares an attack due to the strain of the injuries.", "[creature]每宣攻，皆以其伤势失一命。");
            // 转瞬即逝
            AddTranslation("Instant", "立尽");
            // [creature]在放置后立即消亡。
            AddTranslation("[creature] will perish immediately after its played.", "[creature]既陈即灭。");
            // 启示之作
            AddTranslation("Launcher", "发物");
            // 在持牌人回合结束时，[creature]将在场上同侧的随机空位上创造另一个造物。
            AddTranslation("At the end of its owner's turn, [creature] will create another creature on a random empty space on the owner's side of the table.", "持牌者合终，[creature]于其侧一偶空位生别物。");
            // 骨骼领导
            AddTranslation("Lead (Bones)", "骨导");
            // 消耗2根骨头，使[creature]向印记标注的方向移动一个槽位。
            AddTranslation("Pay 2 bones to move this card one slot in the direction inscribed on the sigil.", "费二骨，使此牌循印所志之向移一位。");
            // 人能把马牵到水边……
            AddTranslation("one can lead  a horse to water...", "人能引马临水……");
            // 能量领导
            AddTranslation("Lead (Energy)", "能导");
            // 消耗2点能量，使[creature]向印记标注的方向移动一个槽位。
            AddTranslation("Pay 2 energy to move this card one slot in the direction inscribed on the sigil.", "费二能，使此牌循印所志之向移一位。");
            // 嗜血之蛭
            AddTranslation("Leech", "蛭");
            // 当[creature]造成伤害时，每对卡牌造成1点伤害将恢复1点生命值。
            AddTranslation("When [creature] deals damage, it will heal 1 Health for each damage dealt to a card.", "[creature]出伤时，凡伤一牌一分，则复一命。");
            // 活力来自血液！
            AddTranslation("Vigor from blood!", "力生于血！");
            // 左侧爪迹
            AddTranslation("Left scratch", "左爪");
            // 当[creature]攻击时，它还会攻击其左侧的空间。
            AddTranslation("When [creature] attacks it will also attack the space on the left of the attacked slot.", "[creature]攻时，亦及左旁之位。");
            // 生命赌徒
            AddTranslation("Life Gambler", "赌命");
            // 在持牌人的回合结束时，[creature]将对持牌人造成2点伤害，以换取0到6点属性值的提升。承担不起此代价将导致死亡。
            AddTranslation("At the end of the owner's turn, [creature] will deal 2 damage to the owner in exchange for a 0 to 6 increase in stats. Failing to pay this cost will result in death.", "持牌者合终，[creature]伤其主二，以易数值益零至六；不能偿此，则死。");
            // 你的血液，它们的力量！
            AddTranslation("Your blood, their strength!", "汝血，彼威！");
            // 语言学家
            AddTranslation("Linguist", "舌师");
            // 当[creature]在场时，同侧场上的所有会说话的卡牌获得1攻击力。
            AddTranslation("While [creature] is on the board, all talking cards on your side of the board get +1 attack.", "凡[creature]在局，汝侧诸言牌威益一。");
            // 退潮之时
            AddTranslation("Low Tide", "潮退");
            // 当[creature]在场时，它将移除其同侧造物的水袭印记。
            AddTranslation("While [creature] is on the board, it will negate the waterborne sigil of cards that are played after it on it's side of the board.", "凡[creature]在局，后陈于其侧之牌，其潜袭印契皆废。");
            // 摇篮曲
            AddTranslation("Lullaby", "眠谣");
            // 当[creature]死亡时，所有对立造物获得休眠印记。
            AddTranslation("When [creature] dies, all opposing creatures gain the asleep sigil.", "[creature]死，则敌诸物皆得寐印。");
            // 调遣
            AddTranslation("Maneuver", "调行");
            // 在持牌人回合开始时，如果[creature]对面槽位有造物，则将向印记标注的方位移动。否则，将向印记标注的相反方向移动。
            AddTranslation("At the start of the owner's turn, [creature] will strafe in the direction inscribed on the sigil if there is a creature in the opposing slot from it. Else it will strafe in the opposite direction inscribed on the sigil.", "持牌者合始，若[creature]对位有物，则循印所志之向移；不然，则反向而移。");
            // 它跑了。
            AddTranslation("It runs", "奔矣。");
            // 医疗兵
            AddTranslation("Medic", "医");
            // 在持牌人回合开始时，[creature]将尝试为每张友方卡牌治疗1点生命，前提是存在可医疗单位。
            AddTranslation("At the start of the owner's turn, [creature] will try heal 1 damage to a friendly card for each instance of Medic.", "持牌者合始，[creature]每因一重医，尝疗一友牌之一伤。");
            // 不错的医疗。
            AddTranslation("A good patching", "其疗善矣。");
            // 医疗救助
            AddTranslation("Medical Aid", "救疗");
            // 对手回合结束时，持牌人选择一个受到伤害的己方造物，恢复1点生命值。
            AddTranslation("At the end of the opponent's turn, choose a hurt creature on the owner's side to heal for 1.", "敌合终，持牌者择一受伤之己物，疗之以一命。");
            // 点石成金
            AddTranslation("Midas", "点金");
            // [creature]杀死一个造物时，每有一个点石成金的卡牌实例，就会给予一个货币。
            AddTranslation("[creature] kills a creature, it will generate 1 Foil for each instance of Midas the card has.", "[creature]杀一物，则此牌每有一点金，生一箔。");
            // 全额支付的赏金。
            AddTranslation("A bounty, paid in full.", "赏已尽偿。");
            // 固定装置
            AddTranslation("Mount", "载");
            // 其他卡牌可以放置在[creature]上方。若如此做，将合并它们的属性和印记，并创建一个名称组合。
            AddTranslation("Cards may be played on top of [creature]. If they are their sigils and stats will be combined, and a name combination will be created.", "诸牌可陈于[creature]之上。若然，则并其印与数，而成一合名。");
            // 运动的力量
            AddTranslation("Power from Movement", "动益");
            // 在持牌人的回合开始时，如果[creature]在上一个回合移动过，它将获得1点力量和1点生命。
            AddTranslation("At the start of the owner's turn, [creature] will gain 1 power and 1 health if it moved last round.", "持牌者合始，若[creature]上合尝移，则威命各益一。");
            // 每次移动，它都会成长。
            AddTranslation("Each move, it grows", "每移而长。");
            // 护士
            AddTranslation("Nurse", "护医");
            // 在对手回合结束时，[creature]将治愈所有相邻的友方卡牌。
            AddTranslation("At the end of the opponent's turn, [creature] will heal any adjacent friendly cards.", "敌合终，[creature]疗其左右己牌。");
            // 营养丰富
            AddTranslation("Nutritious", "饶养");
            // 当[creature]被献祭时，它将为献祭其上场的卡牌增加1点力量和2点生命。
            AddTranslation("When [creature] is sacrificed, it adds 1 power and 2 health to the card it was sacrificed for.", "[creature]祀时，所为而陈之牌威益一，命益二。");
            // 那个造物是如此的营养丰富，你所放置的造物将变得更强！
            AddTranslation("That creature is so full of nutrients, the creature you play comes in stronger!", "彼物饶养，故汝所陈者益强！");
            // 骨礼
            AddTranslation("Bone hoarder 1", "藏骨一");
            // [creature]被放置时，给予持有者1块骨头。
            AddTranslation("When [creature] is played, 1 bone is rewarded.", "[creature]既陈，则其主持得一骨。");
            // 机会主义者
            AddTranslation("Opportunist", "乘隙");
            // 当对位为空时，[creature]将因每个拥有机会主义者印记的实例获得1点力量。
            AddTranslation("[creature] will gain 1 power for each instance of Opportunist, when the opposing slot is empty.", "其对位若空，[creature]每因一重乘隙而威益一。");
            // 它抓住机会，当它得到时。
            AddTranslation("It takes it's chance when it gets it.", "得隙则乘之。");
            // 瘫痪
            AddTranslation("Paralysis", "瘫");
            // [creature]将只在奇数回合攻击。一些印记的效果可能会绕过这一限制。
            AddTranslation("[creature] will only attack every other turn. Some effects from sigils may bypass this.", "[creature]隔合乃攻。诸印之效或能逾此。");
            // 令人震惊的事件。
            AddTranslation("A shocking event.", "骇矣。");
            // 寄生虫
            AddTranslation("Parasite", "寄虫");
            // [creature]可以放置在任何卡牌上方。若如此做，将合并它们的属性和印记，并创建一个名称组合。
            AddTranslation("[creature] may be placed on top of any card. If it is their sigils and stats will be combined, and a name combination will be created.", "[creature]可陈于诸牌之上。若然，则并其印与数，而成一合名。");
            // 可悲之血
            AddTranslation("Pathetic Sacrifice", "鄙祭");
            // [creature]无法被献祭，且无法被锤击。
            AddTranslation("[creature] is so pathetic, it is not a worthy or noble sacrifice. [creature] is meant to stay on the board, and thus can't be targeted by the hammer.", "[creature]甚鄙，不为堪祀，亦非贵祭。[creature]当留于局，故锤不得指之。");
            // 这不是一个卓越的，或值得的献祭。
            AddTranslation("That is not a noble, or worthy sacrifice", "此非贵祭，亦非堪祀。");
            // 挑肥拣瘦
            AddTranslation("Picky", "择");
            // [creature]不能通过任何免费卡牌作为祭品召唤。
            AddTranslation("[creature] cannnot be summoned by using any free cards as sacrifice.", "[creature]不得以无费牌为牲而召。");
            // 隔山打牛
            AddTranslation("Pierce", "贯");
            // [creature]在声明攻击时，首先攻击其初始目标后面的队列中的卡牌。
            AddTranslation("[creature] attacks the card in queue behind it's initial target first when declaring an attack.", "[creature]宣攻时，先贯其初所攻者之后列之牌。");
            // 我的造物！
            AddTranslation("My creatures!", "吾物！");
            // 剧毒腐蚀
            AddTranslation("Poisonous", "毒");
            // 当[creature]阵亡时，杀死它的卡牌也会阵亡。
            AddTranslation("When [creature] perishes, the creature that killed it perishes as well.", "[creature]死，则杀之者亦死。");
            // 攻击有毒之物，不是明智的选择。
            AddTranslation("Attacking something poisonous, isn't that smart.", "攻毒物，非智也。");
            // 灵魂附身
            AddTranslation("Possessor", "附");
            // 当[creature]阵亡时，它将赋予一个随机友方卡牌基于该卡牌的基础力量和生命的属性。
            AddTranslation("When [creature] perishes, it will grant a random friendly card that is on the board it's base power and health.", "[creature]死，则以其本威与本命授局上一偶友牌。");
            // 它把力量传给剩余的造物。
            AddTranslation("It passes it's strength onto those who remain", "其遗其力于存者。");
            // 强力附身
            AddTranslation("Powerful Possessor", "强附");
            // 当[creature]阵亡时，它将赋予一个随机友方卡牌基于该卡牌的当前力量和生命的属性。
            AddTranslation("When [creature] perishes, it will grant a random friendly card that is on the board it's base plus modified power and base plus modified health.", "[creature]死，则以其今威与今命授局上一偶友牌。");
            // 掠食者
            AddTranslation("Predator", "掠");
            // 当其对位有卡牌时，[creature]将为每个拥有掠食者印记的实例增加1点力量。
            AddTranslation("[creature] will gain 1 power for each instance of Predator, when the opposing slot has a card.", "其对位有牌，则[creature]每因一重掠而威益一。");
            // 骄傲
            AddTranslation("Prideful", "骄");
            // [creature]不会攻击比自己攻击力低2的卡牌。
            AddTranslation("[creature] will not attack a card with a power 2 lower than its own.", "[creature]不攻威下己二之牌。");
            // 一个造物的骄傲就是它的堕落。
            AddTranslation("A creature's pride will be it's downfall.", "物之骄，其败也。");
            // 保护者
            AddTranslation("Protector", "佑");
            // [creature]在场时，攻击相邻卡牌的伤害将改为直接攻击持有者。
            AddTranslation("[creature] will attacks on adjacent allies to hit directly.", "[creature]在局，则攻其邻友者，皆直中其主。");
            // 它们保护它们的盟友，但谁保护你呢？
            AddTranslation("They protect their allies, but who protects you?", "彼护其友，谁护汝？");
            // 木偶之礼
            AddTranslation("Puppets gift", "傀礼");
            // 只要[creature]在场上，任何拥有脆骨印记的卡牌不会因脆骨印记而死亡。
            AddTranslation("As long as [creature] is on the board any cards with brittle won't die because of brittle.", "凡[creature]在局，有脆骨之牌不以脆骨而死。");
            // 史诗祭品
            AddTranslation("Superior Sacrifice", "上祭");
            // [creature]被献祭时被计为4点血量而非1点（此印记对不可献祭的卡牌无效）。
            AddTranslation("[creature] is counted as 4 blood rather than 1 blood when sacrificed.", "[creature]祀时计四血，不一。");
            // 好战之羊
            AddTranslation("Ram", "触");
            // [creature]在放置时将尝试撞击其面前的卡牌，直至成功为止的每个维持阶段。如果此牌在我方，则将攻击的目标送回后方队列；如果在敌方，则会将攻击的目标送回手牌。战斗阶段无效。
            AddTranslation("[creature] will try to ram the card infront of it when played, or every upkeep till it succeeds once. It will send the rammed target to the queue if on my side, or back to the hand if on your side. Does not work during combat.", "[creature]既陈，则尝触其前之牌；不成则每合始复然，至一成而止。此牌若在我侧，则所触者却于后列；若在汝侧，则反之于手。战时无效。");
            // 移动造物？多么粗鲁！
            AddTranslation("Moving creatures around? How Rude!", "移物耶？无礼甚矣！");
            // 无形的移动
            AddTranslation("Random Strafe", "偶移");
            // 抽到[creature]，此印记将随机改为一个移动印记。
            AddTranslation("[creature] is drawn, it will gain a random strafe sigil.", "[creature]既引，则得一偶移印。");
            // 它将如何移动？
            AddTranslation("How will it move?", "其将安移？");
            // 后坐力
            AddTranslation("Recoil", "反震");
            // [creature]每次攻击都会受到1点伤害。
            AddTranslation("[creature] will take 1 damage each time they attack.", "[creature]每攻，受一伤。");
            // 力量使它痛苦。
            AddTranslation("The strength causes the creature pain.", "其威反伤其身。");
            // 再生
            AddTranslation("Regen 1", "复一");
            // 在持牌人回合结束时，[creature]将恢复1点生命值。
            AddTranslation("At the end of the owner's turn, [creature] will regen 1 health.", "持牌者合终，[creature]复一命。");
            // 这个造物将在持牌人回合结束时恢复1点生命值。
            AddTranslation("This creature will heal 1 Health at the end of it's owner's turn.", "此物于其主合终复一命。");
            // 双重再生
            AddTranslation("Regen 2", "复二");
            // 在持牌人回合结束时，[creature]将恢复2点生命值。
            AddTranslation("At the end of the owner's turn, [creature] will regen 2 health.", "持牌者合终，[creature]复二命。");
            // 这个造物将在持牌人回合结束时恢复2点生命值。
            AddTranslation("This creature will heal 2 Health at the end of it's owner's turn.", "此物于其主合终复二命。");
            // 三重再生
            AddTranslation("Regen 3", "复三");
            // 在持牌人回合结束时，[creature]将恢复3点生命值。
            AddTranslation("At the end of the owner's turn, [creature] will regen 3 health.", "持牌者合终，[creature]复三命。");
            // 这个造物将在持牌人回合结束时恢复3点生命值。
            AddTranslation("This creature will heal 3 Health at the end of it's owner's turn.", "此物于其主合终复三命。");
            // 神愈再生
            AddTranslation("Regen", "尽复");
            // 在持牌人回合结束时，[creature]将恢复至满血。
            AddTranslation("At the end of the owner's turn, [creature] will regen to full health.", "持牌者合终，[creature]命尽复。");
            // 这个造物将在持牌人回合结束时恢复全部生命值。
            AddTranslation("This creature will heal to full Health at the end of it's owner's turn.", "此物于其主合终命尽复。");
            // 拒人千里
            AddTranslation("Repellant", "斥");
            // 当[creature]阵亡时，杀死它的造物会被推到后排。
            AddTranslation("When [creature] perishes, the creature that killed it gets pushed into the back row.", "[creature]死，则杀之者却于后列。");
            // 抗性提升
            AddTranslation("Resistant", "耐");
            // [creature]通常只会受到大多数造物的1点伤害。有些效果可能会绕过这一点。
            AddTranslation("[creature] will only ever take 1 damage from most things. Some effects might bypass this.", "[creature]凡所受伤，多不过一；诸效或能逾此。");
            // 它是一个顽强的造物。
            AddTranslation("A hardy creature that one is.", "此物诚强。");
            // 资源丰富
            AddTranslation("Resourceful", "余用");
            // 当[creature]被献祭时，它不会死亡，而是失去自身已有的一个随机印记。资源丰富仅在卡牌上没有其他印记时才会移除自己。
            AddTranslation("When [creature] is sacrificed, instead of dying, it loses a random sigil. Resourceful will only remove itself when there are no other sigils on the card.", "[creature]见祀不死，惟失一偶印；诸印既尽，余用乃自去。");
            // 反戈一击
            AddTranslation("Retaliate", "报击");
            // [creature]将对攻击其相邻卡牌的敌人进行反击。
            AddTranslation("[creature] will strike those who strike their adjacent allies.", "[creature]击诸攻其邻友者。");
            // 右侧爪迹
            AddTranslation("Right scratch", "右爪");
            // 当[creature]攻击时，它还会攻击其右侧的空间。
            AddTranslation("When [creature] attacks it will also attack the space on the right of the attacked slot.", "[creature]攻时，亦及右旁之位。");
            // 急行军
            AddTranslation("Rushing march", "疾行");
            // 在持牌人的回合结束时，[creature]将按印记标注的方向移动，但如果在移动过程中遇到卡牌，[creature]将停止，并且被击中的卡牌将消亡。
            AddTranslation("At the end of its owner's turn, [creature] will move in the direction inscribed on the sigil, however if it hits a card whilst moving, [creature] will stop and the card it hit will perish.", "持牌者合终，[creature]循印所志之向而移；若移时触牌，则止，而所触者死。");
            // 水袭指导
            AddTranslation("Schooling", "同潜");
            // [creature]将赋予拥有水袭印记的造物1点力量。
            AddTranslation("[creature] will grant creatures with the waterborn 1 power.", "[creature]使有潜袭印之物威益一。");
            // 水袭造物团结一心。
            AddTranslation("The waterborn stick together.", "潜者相附。");
            // 当[creature]被召唤时，剪碎一张目标卡牌。
            AddTranslation("When [creature] is played, a targeted card cut in two.", "[creature]既陈，可剖所择一牌为二。");
            // 我的卡牌！
            AddTranslation("My card!", "吾牌！");
            // 损伤易形
            AddTranslation("Shapeshifter", "易形");
            // [creature]一直在变化。一旦被击中，它就会改变形态。
            AddTranslation("[creature] is ever changing. It will change its form once it's struck.", "[creature]常变。见击，则易其形。");
            // 短小精悍
            AddTranslation("Short", "短");
            // [creature]不会被带有空袭印记的造物阻挡。
            AddTranslation("[creature] will not be blocked by an opposing creature bearing the airborn sigil.", "[creature]不为有翔袭之敌物所阻。");
            // 疾病肆虐
            AddTranslation("Sickness", "疾");
            // [creature]每次声明攻击时都会失去1点攻击力。
            AddTranslation("[creature] will loose 1 attack each time it declares an attack.", "[creature]每宣攻，失一威。");
            // 造物的力量在攻击时流失。
            AddTranslation("The creature's strength leaves it as it strikes.", "其击也，威去之。");
            // 骨神
            AddTranslation("Bone lord 6", "骨王六");
            // 当[creature]死亡时，奖励6根骨头，而不是1根。
            AddTranslation("When [creature] dies, 6 bones are rewarded instead of 1.", "[creature]死，则赏骨六，不一。");
            // 缓慢
            AddTranslation("Sluggish", "缓");
            // [creature]在正常战斗中不会攻击。它将改为在对手的卡牌攻击后进行攻击。
            AddTranslation("[creature] will not attack during normal combat. It will instead attack after the Opponent's cards attack.", "[creature]常战不攻；俟敌牌既攻而后攻。");
            // 有点慢，嗯？
            AddTranslation("A bit slow there eh?", "少缓矣？");
            // 安眠曲
            AddTranslation("Song of sleep", "眠歌");
            // 如果一个造物移动到[creature]对面的空间，该造物将获得休眠印记。
            AddTranslation("If a creature moves into the space opposing [creature], that creature will obtain the asleep sigil.", "若有物移至[creature]对位，则彼得寐印。");
            // 创造性冲刺
            AddTranslation("Spawner", "生行");
            // 在持牌人的回合结束时，[creature]将按照印记标注的方向移动，并在其原来的位置创造另一个造物。
            AddTranslation("At the end of its owner's turn, [creature] will move in the direction inscribed on the sigil and will create another creature in its old space.", "持牌者合终，[creature]循印所志而移，而故处生别物。");
            // 席卷狂潮
            AddTranslation("Stampede", "驰攻");
            // [creature]如果在非战斗状态下在场地上放置，将导致相邻的造物攻击。
            AddTranslation("[creature] will cause adjacent creatures to attack when played on the board if played not during combat.", "[creature]若于战外既陈，则使其旁诸物出击。");
            // 人多力量大。
            AddTranslation("Power in Numbers", "众则有力。");
            // 如胶似漆
            AddTranslation("Sticky", "胶");
            // 如果[creature]对位的卡牌移动，[creature]将尝试与其一起移动.
            AddTranslation("If the card opposing [creature] moves, [creature] will try to move with it", "若[creature]对位之牌移，[creature]亦尝从之。");
            // 风驰电掣
            AddTranslation("Velocity", "迅");
            // 在持牌人的回合结束时，[creature]将向印记标注的方向移动。如果它能够移动，它将获得1点力量和1点生命。
            AddTranslation("At the end of the owner's turn, [creature] will move in the direction inscribed in the sigil. If it is able to move, it will gain 1 power and 1 health.", "持牌者合终，[creature]循印所志而移；若能移，则威命各益一。");
            // 强风吹拂
            AddTranslation("Strong Wind", "烈风");
            // 如果[creature]在场上，则取消其后出场的所有卡牌的空袭印记。
            AddTranslation("If [creature] is on the board, negate the airbone sigil of all cards that are played after it.", "凡[creature]在局，后陈之牌，其翔袭印皆废。");
            // 强风迫使着陆。
            AddTranslation("The Wind forces a landing.", "风迫其降。");
            // 水下伏击
            AddTranslation("Submerged Ambush", "潜伏");
            // [creature]在它潜水时，将对攻击过它位置的卡牌造成1点伤害。不影响带有空袭印记的卡牌。
            AddTranslation("[creature] will deal 1 damage to cards that attacked over it while it was face-down. Does not affect cards that are Airborne.", "[creature]翻伏时，凡越其位而攻者，受一伤；翔袭者不与。");
            // 它的攻击来着水下。
            AddTranslation("It strikes from the water.", "出击于水中。");
            // 吞噬者
            AddTranslation("Swallower", "吞");
            // 在[creature]攻击后，如果它的生命值低于它所攻击的卡牌，它将摧毁它所攻击的卡牌并恢复所有生命。
            AddTranslation("After [creature] attacks, it will destroy the card it attacks if it has less health than it and heal to full health.", "攻后，若所攻之牌命少于[creature]，则毁之，而[creature]命尽复。");
            // 一饮而尽。
            AddTranslation("Gone in one gulp.", "一啜而尽。");
            // 同情
            AddTranslation("Sympathetic", "恤");
            // [creature]只有当对位造物的生命值不小于它时，才会攻击。
            AddTranslation("[creature] will only attack if the opposing creature has more or equal health to it.", "[creature]惟对物之命不少于己，乃攻。");
            // 骨驱空袭
            AddTranslation("Take-Off (Bones)", "骨翔");
            // 消耗2根骨头，使这张卡牌直到持牌人下一个回合开始时获得空袭印记的效果。
            AddTranslation("Pay 2 bones to give this card Airborne till the start of owner's next turn.", "费二骨，使此牌至其主持次合始得翔袭。");
            // 展翅飞翔。
            AddTranslation("Spread your wings and fly.", "展翼而翔。");
            // 电驱空袭
            AddTranslation("Take-Off (Energy)", "能翔");
            // 消耗2点能量，使这张卡牌直到持牌人的下一个回合开始时获得空袭印记的效果。
            AddTranslation("Pay 2 energy to give this card Airborne till the start of the owner's next turn.", "费二能，使此牌至其主持次合始得翔袭。");
            // 惊慌失措
            AddTranslation("Terrified", "骇遁");
            // 当有卡牌移动到与[creature]相对的空间时，[creature]将远离该卡牌移动到随机相邻的空位，同时推开挡在其路上的任何造物，优先选择没有任何相对造物的槽位。
            AddTranslation("When a creature moves into the space opposing [creature], [creature] will move away from that card to a random free adjacent spot while pushing any creatures in it's way, while prioritizing slots without any opposing creatures.", "有物移至与[creature]相对之位，则[creature]避彼而移于一邻空位；道有诸物，则推之；先择无对物者。");
            // 厚重甲壳
            AddTranslation("Thick Shell", "厚甲");
            // 当[creature]被攻击时，少受1点伤害。
            AddTranslation("When attacked, [creature] takes 1 less damage.", "[creature]见攻，则所受伤少一。");
            // 那个造物身上的厚壳保护它少受1点伤害！
            AddTranslation("The thick shell on that creature protected it from one damage!", "其厚壳为之省一伤！");
            // [creature]在战斗时或在持牌人的回合开始时，将尝试从对位造物那里偷取一个随机的默认印记，直到成功为止。
            AddTranslation("[creature] will try to steal a random default sigil from a card in the opposing lane when played, or at the start of the owner's turn until it does.", "[creature]既陈，或持牌者合始，尝自其对列之一牌窃一偶常印，至得乃止。");
            // 要是能偷月亮就好了……
            AddTranslation("If only I could steal the moon...", "若得窃月则善矣……");
            // 骨后
            AddTranslation("Bone prince 3", "骨侯三");
            // 当[creature]死亡时，奖励3根骨头，而不是1根。
            AddTranslation("When [creature] dies, 3 bones are rewarded instead of 1.", "[creature]死，则赏骨三，不一。");
            // 三重骨礼
            AddTranslation("Bone hoarder 3", "藏骨三");
            // [creature]被放置时，给予持有者3块骨头。
            AddTranslation("When [creature] is played, 3 bones are rewarded.", "[creature]既陈，则其主持得三骨。");
            // 牙齿交易
            AddTranslation("Tooth Bargain", "齿约");
            // 当[creature]被召唤时，它将对对手的天平一侧造成1点伤害。当它阵亡时，它将对持牌人的天平一侧造成2点伤害。
            AddTranslation("When [creature] is played, it will put 1 point of damage of it's opponent's side of the scale. When it perishes, it will put 2 damage on the owner's side of the scale.", "[creature]既陈，则敌衡加一伤；其死，则其主衡加二伤。");
            // 我看到了和魔鬼的交易……
            AddTranslation("A deal with a devil I see...", "盖与鬼神为约也……");
            // 拔牙器
            AddTranslation("Toothpuller", "抽齿");
            // 在持牌人回合结束时，[creature]将对对手的天平造成一点伤害。
            AddTranslation("At the end of the owner's turn, [creature] will add one point of damage to the opponent's scale.", "持牌者合终，[creature]使敌衡加一伤。");
            // 那很疼。
            AddTranslation("That Hurts", "痛哉。");
            // 牙齿碎片
            AddTranslation("Tooth Shard", "齿屑");
            // [creature]被攻击时，如果它存活下来，将给予持有者一个货币。
            AddTranslation("[creature] will generate 1 foil when hit, if it lives through the attack.", "[creature]见击而不死，则生一箔。");
            // 一小块金子。
            AddTranslation("A splinter of gold.", "金之一屑。");
            // 混合毒素
            AddTranslation("Toxin", "毒");
            // 当[creature]对另一造物造成伤害时，该造物失去1点力量和1点生命。
            AddTranslation("When [creature] damages another creature, that creature looses 1 power and 1 health.", "[creature]伤他物，则彼失一威一命。");
            // 所有的东西都可以用不同的方式磨损。
            AddTranslation("All things can be worn down, and in different ways.", "物皆可磨，而其途不同。");
            // 致命毒素
            AddTranslation("Toxin (Deadly)", "死毒");
            // 当[creature]对另一造物造成伤害时，该造物获得奄奄一息印记。奄奄一息的定义是：带有此印记的卡牌将在2回合后死亡。
            AddTranslation("When [creature] damages another creature, that creature gains the Dying Sigil. The Dying Sigil is defined as: [creature] will die after 2 number of turns.", "[creature]伤他物，则彼得将死印。将死印者：历二合而死。");
            // 即使战斗结束，也会留下致命的痕迹.
            AddTranslation("Even once combat is over, it leaves a deadly mark", "战罢犹遗死痕。");
            // 残废毒素
            AddTranslation("Toxin (Sickening)", "疾毒");
            // 当[creature]伤害另一个造物时，该造物获得疾病肆虐印记。疾病肆虐被定义为：每当带有此印记的造物宣布攻击时，它们将失去一点力量。
            AddTranslation("When [creature] damages another creature, that creature gains the Sickness Sigil. The Sickness Sigil is defined as: When ever a creature bearing this sigil declares an attack, they will loose one attack.", "[creature]伤他物，则彼得疾病印。疾病印者：凡有此印之物，每宣攻失一威。");
            // 即使战斗结束，疾病也会在战斗中传播。
            AddTranslation("Even once combat is over, it leaves sickness spreads in what it fights.", "战罢犹遗其疾于所斗者。");
            // 力量毒素
            AddTranslation("Toxin (Strength)", "削威毒");
            // 当[creature]伤害另一个造物时，该造物失去1点力量。
            AddTranslation("When [creature] damages another creature, that creature looses 1 power.", "[creature]伤他物，则彼失一威。");
            // 即使战斗结束，力量也会离开它们。
            AddTranslation("Even once combat is over, strength leaves it's target", "战罢犹使其靶失威。");
            // 生命毒素
            AddTranslation("Toxin (Vigor)", "削命毒");
            // 当[creature]对另一造物造成伤害时，该造物失去1点生命值。
            AddTranslation("When [creature] damages another creature, that creature looses 1 health.", "[creature]伤他物，则彼失一命。");
            // 践踏
            AddTranslation("Trample", "蹂");
            // 当[creature]对另一卡牌造成超额伤害时，超额伤害将传给该牌的持牌人。
            AddTranslation("When [creature] deals overkill damage to a card, the overkill damage will be sent to the owner.", "[creature]溢伤及其主。");
            // 践踏永不停止。
            AddTranslation("A stampede can not be stopped.", "驰群不可止。");
            // 易形鸡（仅敌人）
            AddTranslation("Transform Chicken (Enemy Only)", "化鸡（敌惟）");
            // [creature]将在每个持牌人的回合开始时使对方场地上的一个随机造物变成鸡。鸡被定义为：1点力量，1点生命。
            AddTranslation("[creature] will transform a random creature on the board on the opponent's side into a Chicken. A Chicken is defined as 1 Attack, 1 Health.", "[creature]每持牌者合始，使敌侧一偶物化为鸡。鸡者：1威、1命。");
            // 易形鸡（全场）
            AddTranslation("Transform Chicken (Loose Cannon)", "化鸡（全场）");
            // [creature]将在每个持牌人的回合开始时使全场的一个随机造物变成鸡。鸡被定义为：1点力量，1点生命。
            AddTranslation("[creature] will transform a random creature on the board into a Chicken. A Chicken is defined as 1 Attack, 1 Health.", "[creature]每持牌者合始，使局上一偶物化为鸡。鸡者：1威、1命。");
            // 易形鸡（对位）
            AddTranslation("Transform Chicken (Opposing)", "化鸡（对位）");
            // 当一个造物与[creature]对位时，它会变成一只鸡。鸡被定义为：1点力量，1点生命。
            AddTranslation("When a creature is played opposing [creature] it will turn into a Chicken. A Chicken is defined as 1 Attack, 1 Health.", "有物陈于[creature]对位，则化为一鸡。鸡者：1威、1命。");
            // 昙花一现
            AddTranslation("Transient", "旋返");
            // 在持牌人回合结束时，[creature]将回到其手中。
            AddTranslation("At the end of the owner's turn, [creature] will return to your hand.", "持牌者合终，[creature]反归汝手。");
            // 该造物在回合结束时跑回持牌人手中。
            AddTranslation("The creature blinks back into the owner's hand at the end of their turn.", "此物合终倏返其主之手。");
            // 族群盟友
            AddTranslation("Tribal Ally", "同属友");
            // 当[creature]被召唤时，你手中将产生一张与之相同族群的卡牌。无族群的卡牌视为“无族群”族群。
            AddTranslation("When [creature] is played, A card of the same tribe is created in your hand. No tribe counts as a tribe of tribeless.", "[creature]既陈，汝手中生一与之同属之牌。无属者，以无属为属。");
            // 它需要它的亲属。
            AddTranslation("It calls for it's kin.", "呼其族矣。");
            // 族群囤积
            AddTranslation("Tribal Tutor", "同属引");
            // 当[creature]被召唤时，你可以从牌库中搜寻一张与之相同族群的卡牌并将其加入你的手牌。无族群的卡牌视为“无族群”族群。
            AddTranslation("When [creature] is played, you may search your deck for a card of the same tribe and take it into your hand. No tribe counts as a tribe of tribeless.", "[creature]既陈，汝可索牌列中与之同属之一牌，取入手。无属者，以无属为属。");
            // 族群攻击
            AddTranslation("Tribe Attack", "属攻");
            // 当[creature]在场上时，同一侧所有相同族群的卡牌攻击力+1。
            AddTranslation("While [creature] is on the board, all other cards on your side of the board of the same tribe will gain +1 attack.", "凡[creature]在局，汝侧余牌与之同属者，威皆益一。");
            // 族群生命
            AddTranslation("Tribe Health", "属命");
            // 当[creature]在场上时，同一侧所有相同族群的卡牌生命值+1。
            AddTranslation("While [creature] is on the board, all other cards on your side of the board of the same tribe will gain +1 health.", "凡[creature]在局，汝侧余牌与之同属者，命皆益一。");
            // 混沌水域
            AddTranslation("Turbulent Waters", "湍波");
            // [creature]将迫使其他拥有水袭印记的造物浮出水面，并在持牌人的回合开始时受到1点伤害。
            AddTranslation("[creature] will force other creatures with waterborne to resurface and take 1 damage at the start of the owner's turn.", "[creature]迫有潜袭印之余物出水；持牌者合始，彼皆受一伤。");
            // 水面波涛汹涌。
            AddTranslation("The waters be rough.", "波涛甚恶。");
            // 骨臣
            AddTranslation("Bone prince 2", "骨侯二");
            // 当[creature]死亡时，奖励2根骨头，而不是1根。
            AddTranslation("When [creature] dies, 2 bones are rewarded instead of 1.", "[creature]死，则赏骨二，不一。");
            // 双重骨礼
            AddTranslation("Bone hoarder 2", "藏骨二");
            // [creature]被放置时，给予持有者2块骨头。
            AddTranslation("When [creature] is played, 2 bones are rewarded.", "[creature]既陈，则其主持得二骨。");
            // 扶弱锄强
            AddTranslation("Underdog", "居下");
            // [creature]只能在您处于劣势时使用。
            AddTranslation("[creature] can only be played when you are losing.", "汝处下风，乃得陈[creature]。");
            // 凶相毕露
            AddTranslation("Vicious", "狠");
            // 当[creature]被攻击时，它获得1点力量。
            AddTranslation("When [creature] is attacked, it gains 1 power.", "[creature]见攻，则威益一。");
            // 一次攻击只会让它生气。
            AddTranslation("A hit just makes it angry.", "一击适足怒之。");
            // 穿场者
            AddTranslation("Warper", "越界");
            // 在其持牌人的回合结束时，[creature]将向右移动，穿过其路径上的任何造物，如果遇到场地边缘，它将回到最左侧。
            AddTranslation("At the end of its owner's turn, [creature] will move to the right, jumping over any creatures in its path, if it encounters the edge of the board, it will loop over to the other side.", "持牌者合终，[creature]右移，越其途诸物；遇局边，则环至彼端。");
            // 狂野饥饿
            AddTranslation("Wild hunger", "饕行");
            // 在持牌人的回合结束时，[creature]将按印记标注的方向移动，若在移动过程中遇到其他卡牌，[creature]将停止移动，被撞到的卡牌将消亡，并且[creature]将获得1点力量和1点生命。
            AddTranslation("At the end of its owner's turn, [creature] will move in the direction inscribed on the sigil, however if it hits a card whilst moving, [creature] will stop, the card it hit will perish and [creature] will gain 1+/1+.", "持牌者合终，[creature]循印所志而移；若移时触牌，则止，所触者死，而[creature]威命各益一。");
            // 凋零
            AddTranslation("Withering", "枯");
            // [creature]将在对手回合结束时消亡。
            AddTranslation("[creature] will perish at the end of the opponant's turn.", "[creature]于敌合终灭。");
            // 瘫痪之触
            AddTranslation("Zapper", "痹触");
            // 当[creature]对另一造物造成伤害时，该造物将获得瘫痪印记。瘫痪印记定义为：带有此印记的卡牌将每隔一回合攻击一次。
            AddTranslation("When [creature] damages another creature, that creature will gain the Paralysis Sigil. The Paralysis sigil is defined as: A card bearing this sigil will only attack every other turn.", "[creature]伤他物，则彼得瘫印。瘫印者：有此印之牌，隔合乃攻。");
        }

    }

    public class BittysSigilsMod
    {
        public static void RegisterTranslations()
        {
            // Ability
            // 两侧堵塞。没有蛋给你。
            AddTranslation("Blocked on both sides. No Eggs for you.", "两旁既塞，无卵与汝。");
            // 没有空位，无法给你大冷杉。
            AddTranslation("No empty spaces. No firs for you.", "无空位，无杉与汝。");
            // 松鼠泛滥
            AddTranslation("Explosive Squirrel Reproduction", "蕃鼠");
            // 当打出[creature]时，你的副牌组将被松鼠填满。
            AddTranslation("When [creature] is played, fill your side deck with squirrels.", "[creature]既陈，则以松鼠充汝副牌列。");
            // 运输者
            AddTranslation("Hauler", "牵");
            // 在持牌人的回合结束时，[creature]会向印记标注的方向移动。相邻的友方生物会被拉向同一方向。
            AddTranslation("At the end of the owner's turn, [creature] will move in the direction inscribed in the sigil. Adjacent friendly creatures will be pulled in the same direction.", "持牌者合终，[creature]循印所志而移；其旁友物，亦为之牵而同移。");
            // 心灵交换
            AddTranslation("Heart Swap", "易心");
            // 当打出[creature]时，场上所有卡牌将交换其力量和生命值。
            AddTranslation("When [creature] is played, all cards on the board swap their power and health.", "[creature]既陈，局上诸牌皆易其威命。");
            // 相互雇佣
            AddTranslation("Mutual Hire", "相雇");
            // 当打出[creature]时，会在对方区域创造一个它的副本。
            AddTranslation("When [creature] is played, a copy of it is created in the opposing space.", "[creature]既陈，则其对位生一副。");
            // 充能弹幕
            AddTranslation("Charged Barrage", "充霰");
            // 消耗4点生命值，增加同侧场上所有卡牌1点力量。
            AddTranslation("Pay 4 life to increase the power of all cards on your side of the board by 1.", "费四命，则汝侧诸牌威皆益一。");
            // 生命骰子
            AddTranslation("Health Roll", "命骰");
            // 消耗1点能量，将[creature]的生命值设置为1到6的随机数字。
            AddTranslation("Pay 1 Energy to set the health of [creature] randomly between 1 and 6.", "费一能，使[creature]之命偶定于一至六。");
            // 印记骰子
            AddTranslation("Sigil Roll", "印骰");
            // 消耗4点生命值，将一个随机印记添加到[creature]上。
            AddTranslation("Pay 4 Life to add a random sigil to [creature].", "费四命，加一偶印于[creature]。");
            // 野兽相机
            AddTranslation("Wildlife Camera", "野影器");
            // 当[creature]击杀另一张卡牌时，会在你的手中创造该被击杀卡牌的副本。
            AddTranslation("When [creature] kills another card, a copy of the killed card is created in your hand.", "[creature]杀他牌，则彼牌之副生于汝手。");
            // 尘埃羽毛笔
            AddTranslation("Dusty Quill", "尘笔");
            // 当[creature]在场上时，若其他造物死亡，会在其位置召唤一具尸体。尸体被定义为：0点力量，1点生命。
            AddTranslation("Whenever a creature dies while [creature] is on the board, a corpse is raised in it's place. Corpses are defined as: 0/1.", "凡[creature]在局，有物死，则其处起一尸。尸者：0威、1命。");
            // 漂白之笔
            AddTranslation("Bleached Brush", "素笔");
            // 当[creature]被打出时，对位的卡牌将失去所有印记。
            AddTranslation("When [creature] is played, the opposing card will lose all its sigils.", "[creature]既陈，其对牌尽失诸印。");
            // 剽悍之魂
            AddTranslation("Strong Soul", "强魂");
            // [creature]不能接受其他造物的印记转移。
            AddTranslation("[creature] may not recieve sigils from another card.", "[creature]不得受他牌之印。");
            // 孱弱之魂
            AddTranslation("Weak Soul", "弱魂");
            // [creature]不能转移自己的印记。
            AddTranslation("[creature] may not have its sigils transferred to another card.", "[creature]不得徙己印于他牌。");
            // 缥缈之魂
            AddTranslation("Nonexistent Soul", "无魂");
            // [creature]不能接受其他造物的印记转移和转移自己的印记。
            AddTranslation("[creature] may not have sigils transferred to, or from this card.", "[creature]不得受印，亦不得徙印。");
            // 恐火症
            AddTranslation("Pyrophobia", "惧火");
            // [creature]不能在篝火事件获得增益。
            AddTranslation("[creature] may not be buffed at campsites.", "[creature]不得于篝火处受益。");
            // 恐火症（力量）
            AddTranslation("Pyrophobia (Attack)", "惧火（威）");
            // [creature]不能从篝火事件获得力量增益。
            AddTranslation("[creature] may not recieve power buffs from campsites.", "[creature]不得于篝火处受威益。");
            // 恐火症（生命）
            AddTranslation("Pyrophobia (Health)", "惧火（命）");
            // [creature]不能从篝火事件获得生命增益。
            AddTranslation("[creature] may not recieve health buffs from campsites.", "[creature]不得于篝火处受命益。");
            // 排斥
            AddTranslation("Repulsion", "斥");
            // [creature]不能攻击。
            AddTranslation("[creature] may not attack.", "[creature]不得攻。");
            // 神秘蘑菇
            AddTranslation("Mysterious Mushrooms", "异蕈");
            // 回合结束时，如果[creature]的两侧有牌，它们会融合在一起。
            AddTranslation("At the end of the turn, if there is a card on either side of [creature], they are fused together.", "合终，若[creature]两旁有牌，则并而为一。");
            // 在持牌人的回合结束时，[creature]会带动对位卡牌和自身向印记标注的方向移动。
            AddTranslation("At the end of the owner's turn, [creature] will move the opposing card and itself in the direction inscribed in the sigil.", "持牌者合终，[creature]引其对牌与己，循印所志而移。");
            // 反伤刺甲
            AddTranslation("Counter Attack", "反刺");
            // 一旦[creature]被攻击，攻击者将受到等同于这张卡牌攻击力的伤害。
            AddTranslation("Once [creature] is struck, the striker is then dealt damage equal to this card's attack.", "[creature]见击，则击者受伤如是牌之威。");
            // 镜面刺甲
            AddTranslation("Mirror Counter", "镜刺");
            // 一旦[creature]被攻击，攻击者将受到等同于攻击者攻击力的伤害。
            AddTranslation("Once [creature] is struck, the striker is then dealt damage equal to the striker's attack.", "[creature]见击，则击者受伤如其自威。");
            // 全场移相
            AddTranslation("Board Shifter", "移局");
            // 在持牌人的回合结束时，[creature]将按照印记标注的方向移动。所有卡牌将朝同一方向移动，绕到场地的另一侧。
            AddTranslation("At the end of the owner's turn, [creature] will move in the direction inscribed in the sigil. All cards will shift in the same direction, looping to the other edge of the board.", "持牌者合终，[creature]循印所志而移。诸牌皆同向而移，环至彼边。");
            // 友军移相
            AddTranslation("Board Shifter (Owner)", "移友局");
            // 在持牌人的回合结束时，[creature]将按照印记标注的方向移动。友方卡牌将朝同一方向移动，绕到场地的另一侧。
            AddTranslation("At the end of the owner's turn, [creature] will move in the direction inscribed in the sigil. Friendly cards will shift in the same direction, looping to the other edge of the board.", "持牌者合终，[creature]循印所志而移。友牌皆同向而移，环至彼边。");
            // 敌军移相
            AddTranslation("Board Shifter (Opposing)", "移敌局");
            // 在持牌人的回合结束时，[creature]将按照印记标注的方向移动。对手的卡牌将朝同一方向移动，绕到场地的另一侧。
            AddTranslation("At the end of the owner's turn, [creature] will move in the direction inscribed in the sigil. The opposing cards will shift in the same direction, looping to the other edge of the board.", "持牌者合终，[creature]循印所志而移。敌牌皆同向而移，环至彼边。");
            // 丧钟
            AddTranslation("Deathbell", "丧钟");
            // 每个回合开始时，[creature]会消亡。
            AddTranslation("At the start of the battle phase, [creature] perishes.", "战阶始，[creature]即灭。");
            // 顺时针
            AddTranslation("Clockwise", "顺时");
            // 当一张[creature]被打出时，场上所有卡牌顺时针移动一格。
            AddTranslation("When [creature] is played, move all cards on the board clockwise.", "[creature]既陈，局上诸牌皆顺时移一格。");
            // 顽固不化
            AddTranslation("Stubborn", "固");
            // [creature]不能交换其属性。
            AddTranslation("[creature] may not have its stats swapped.", "[creature]不得易其数。");
            // 每回合结束时，若场上存在一张[creature]，则将场上的所有卡牌顺时针移动一格。
            AddTranslation("At the end of each turn [creature] is on the board, move all cards on the board clockwise.", "每合终，若[creature]在局，则局上诸牌皆顺时移一格。");
            // 稍纵即逝
            AddTranslation("Fleeting", "暂");
            // 一张[creature]将在回合结束时被弃置。
            AddTranslation("At the end of the turn [creature] will be discarded from your hand.", "合终，[creature]自汝手见弃。");
            // 灵魂链接
            AddTranslation("Soul Link", "同魂");
            // 当[creature]消亡时，所有其他带有此印记的友方卡牌也将随之消亡。
            AddTranslation("When [creature] perishes, all other allied cards bearing this sigil perish as well.", "[creature]灭，则余有此印之友牌皆灭。");
            // 空洞抽取
            AddTranslation("Hollow Draw", "虚引");
            // 当[creature]被打出时，弃掉你手中最早抽到的卡牌，重新抽一张牌。
            AddTranslation("When [creature] is played, discard the oldest card in your hand, draw a card.", "[creature]既陈，弃汝手中最先所引之牌，而更引一牌。");
            // 空洞弹幕
            AddTranslation("Hollow Barrage", "虚霰");
            // 当[creature]被打出时，场上所有卡牌受到1点伤害。
            AddTranslation("When [creature] is played, all cards take 1 damage.", "[creature]既陈，局上诸牌皆受一伤。");
            // 宝石恐惧
            AddTranslation("Gem Phobic", "惧玉");
            // 若[creature]的持有者场上拥有任何玛珂牌，[creature]将消亡。
            AddTranslation("If [creature]'s owner controls a Mox card, [creature] perishes.", "若[creature]之主持有玛珂牌，[creature]即灭。");
            // 鲁莽
            AddTranslation("Foolhardy", "妄");
            // [creature]不能从任何事件中获得修改。
            AddTranslation("[creature] may not recieve modifications from any source.", "[creature]不得受任何改益。");
            // 跳跃者
            AddTranslation("Jumper", "跃");
            // 在持牌人的回合结束时，[creature]会自行向印记标注的方向移动至第一个空位。
            AddTranslation("At the end of the owner's turn, [creature] will move itself to the first empty space in the direction inscribed in the sigil.", "持牌者合终，[creature]自循印所志之向移至其首空位。");
            // 冲刺狂人
            AddTranslation("Super Sprinter", "疾趋");
            // 在持牌人的回合结束时，[creature]会尽可能地向印记标注的方向移动。
            AddTranslation("At the end of the owner's turn, [creature] will move itself as far as possible in the direction inscribed in the sigil.", "持牌者合终，[creature]尽所能循印所志而移。");
            // 蛋之艺术
            AddTranslation("Eggist", "生卵");
            // 当打出[creature]时，在每个相邻的空位上各创建一个蛋。
            AddTranslation("When [creature] is played, an Egg is created on each empty adjacent space.", "[creature]既陈，其邻空位各生一卵。");
            // 唤林者
            AddTranslation("Fir Caller", "召杉");
            // 当[creature]被打出时，在持牌人的每个空位上创造一个大冷杉。
            AddTranslation("When [creature] is played, a Fir is created in each of the owner's spaces.", "[creature]既陈，持牌者诸空位各生一杉。");
            // 浮光掠影
            AddTranslation("Flipper", "易数");
            // 在持牌人回合结束时，[creature]会交换其属性。
            AddTranslation("At the end of the owner's turn, [creature] swaps its stats.", "持牌者合终，[creature]易其数。");
            // 消逝之手
            AddTranslation("Fleeting Draw", "暂引");
            // 当一张[creature]被打出时，获得一张带有稍纵即逝印记的牌。
            AddTranslation("When [creature] is played, draw 1 card with Fleeting.", "[creature]既陈，则引一有暂印之牌。");
            // 流浪者
            AddTranslation("Outcast", "还列");
            // 回合结束时，[creature]会被洗入你的牌组。
            AddTranslation("At the end of the turn, [creature] is shuffled into the deck.", "合终，[creature]还入汝牌列而乱之。");
            // 空洞中继
            AddTranslation("Hollow Repeater", "虚继");
            // 当[creature]消亡时，该卡牌上所有上场时触发的印记将被激活。
            AddTranslation("When [creature] perishes, all On Play sigils on that card are activated.", "[creature]灭，则此牌上凡陈时所发之印皆启。");
            // 买一送一
            AddTranslation("Replenish", "续引");
            // 当一张[creature]被抽到时，再抽一张牌。
            AddTranslation("When [creature] is drawn, draw a card.", "[creature]既引，更引一牌。");
            // 目标交换器
            AddTranslation("Target Swap", "易数指");
            // 放置[creature]时，持牌人选择一张牌：该牌的力量和生命数值将被交换。
            AddTranslation("When [creature] is played, Target a Card: the card's stats are swapped.", "[creature]既陈，择一牌而易其威命。");
            // 祭祀生长
            AddTranslation("Sacrificial Growth", "祀长");
            // 当[creature]被献祭时，它将成长为更强大的形态。
            AddTranslation("When [creature] is sacrificed, it will grow into a more powerful form.", "[creature]见祀，则长为益强之形。");
            // 红宝石易形
            AddTranslation("Ruby Transformer", "红玉化");
            // 若[creature]的持牌人场上拥有红宝石玛珂，[creature]将转变为另一种形态；否则[creature]将转变为其基础形态。
            AddTranslation("If [creature]'s owner controls a Ruby Mox, [creature] will be transformed; otherwise [creature] will transform into its base form.", "若[creature]之主持红玉玛珂，则[creature]化其异形；不然，则反其本形。");
            // 宝石增益
            AddTranslation("Gemify", "玉益");
            // [creature]根据进场时持牌人拥有宝石获得增益。橙色：增加1点力量；绿色：增加2点生命；蓝色：降低花费成本。
            AddTranslation("[creature] gains buffs based on moxes in play on the owner's side. Orange is 1 Power. Green is 2 Health. Blue is lower Cost.", "[creature]视其主持局中诸玛珂而受益：橙则威益一，绿则命益二，蓝则直降。");

            // Card
            // 尸体
            AddTranslation("Corpse", "尸");
            // 测试卡牌
            AddTranslation("TestCard", "试牌");
        }

    }

    public class BittysChallengesMod
    {
        public static void RegisterTranslations()
        {
            // DialogueEvent
            // 那是三叶草吗？
            AddTranslation("Is that a clover?", "彼三叶草乎？");
            // 原来如此。
            AddTranslation("I see.", "然。");
            // 哦？
            AddTranslation("Oh?", "噫？");
            // 你不喜欢被发牌针对吗？
            AddTranslation("Did you not like having a stacked deck?", "汝不喜牌列偏向乎？");
            // 我无所谓。
            AddTranslation("That's fine with me.", "于我可也。");
            // 反正这样更公平些。
            AddTranslation("It will be more fair this way anyways.", "如此差为平矣。");
            // 哦？
            AddTranslation("oh?", "噫？");
            // 我自己的衔尾蛇。
            AddTranslation("my very own ouroboros.", "我之衔尾蛇。");
            // 我一定会好好利用它的。
            AddTranslation("i will be sure to put it to good use.", "我必善用之。");
            // 衔尾蛇已追随你而来。
            AddTranslation("the ouroboros has followed you.", "衔尾蛇随汝来矣。");
            // 它已露出毒牙，准备再战一场。
            AddTranslation("it's fangs are beared, and it's ready for another fight.", "其牙已露，复可一战。");
            // 不屈不死的衔尾蛇已然归来，
            AddTranslation("the unyielding ouroboros has returned,", "不屈之衔尾蛇复来，");
            // 每次死亡都令其更加强大。
            AddTranslation("growing stronger every death.", "每死而益强。");
            // 如同死亡般不可避免，
            AddTranslation("as inevitable as death,", "如死之必至，");
            // 衔尾蛇已然归来。
            AddTranslation("the ouroboros has returned.", "衔尾蛇复来矣。");
            // 一条蛇从灌木丛中蜿蜒而出。
            AddTranslation("a serpent slithers out from the undergrowth.", "有蛇蜿蜒出于丛薄。");
            // 或许你曾见过它？
            AddTranslation("perhaps you have seen it before?", "汝或尝见之乎？");
            // 衔尾蛇死了。
            AddTranslation("the ouroboros has died.", "衔尾蛇死矣。");
            // 然而，它终将归来。
            AddTranslation("and yet, it will return.", "然终必复归。");
            // 蛇的怒火已被延缓。
            AddTranslation("the serpent's wrath has been delayed.", "蛇之怒姑缓。");
            // 暂且如此。
            AddTranslation("for now.", "姑尔。");
            // 衔尾蛇只会因死亡而愈发强大。
            AddTranslation("the ouroboros only grows stronger from death.", "衔尾蛇惟死而益强。");
            // 它终将归来。
            AddTranslation("it will be back.", "终当复来。");
            // 啊…啊，印记……
            AddTranslation("a-ah, the sigils...", "啊……其印……");
            // 哦…哦，这股力量……
            AddTranslation("o-oh, the power...", "哦……其威……");
            // 啊…啊，生命……
            AddTranslation("a-ah, the health...", "啊……其命……");
            // 啊……
            AddTranslation("ah...", "啊……");
            // 金羊克律索马罗斯。
            AddTranslation("Chrysomallos, the golden ram.", "克律索马罗斯，金羊也。");
            // 多么华美的毛皮啊……
            AddTranslation("what a glorious pelt....", "其革何华也……");
            // 金羊。
            AddTranslation("The golden ram.", "金羊。");
            // 趁它逃走前抓住它。
            AddTranslation("catch it before it escapes.", "其遁前执之。");
            // 难得一见
            AddTranslation("a rare sight", "罕见也。");
            // 它不会久留
            AddTranslation("it will not stay for long", "不久留也。");
            // 多么闪耀的羊毛啊，
            AddTranslation("what glittering wool,", "其毛灿然，");
            // 竟附着在如此稀有的生物身上。
            AddTranslation("attached to such a rare creature.", "乃著于此罕物。");
            // 哦？
            AddTranslation("oh?", "噫？");
