            // 最好别错过。
            AddTranslation("best make the most of it.", "宜尽其机。");
            // 你击杀了这只发光的生物，剥下了它的毛皮。
            AddTranslation("You slay the glimmering creature, stealing its pelt.", "汝杀其晶耀之物，而取其革。");
            // 如此辉煌的生灵就此陨落。
            AddTranslation("The end of such a glorious creature.", "若此华物，竟止于此。");
            // 而你获得了何等华美的皮毛。
            AddTranslation("And what a glorious pelt you have obtained.", "而汝所得之革，亦何华也。");
            // 克律索马罗斯……
            AddTranslation("Chrysomallos...", "克律索马罗斯……");
            // 你的故事何其悲惨……
            AddTranslation("How tragic your tale is...", "尔事何悲……");
            // 竟为皮毛而遭屠戮……
            AddTranslation("To be killed for your pelt...", "竟为其革而见杀……");
            // 金羊又活过了一天。
            AddTranslation("The Golden Ram lives another day.", "金羊又得一日之生。");
            // 时间到了。
            AddTranslation("Time's up.", "时至矣。");
            // 金羊已经找到了逃脱路线。
            AddTranslation("The Golden Ram has found an escape route.", "金羊已得遁路。");
            // 金羊皮毛的闪光晃花了你的眼，
            AddTranslation("The glimmer of the Golden Ram's fur blinds you,", "金羊之毛晶耀眩汝目，");
            // 让它得以趁机逃脱。
            AddTranslation("giving it the opportunity to escape.", "故得乘隙而遁。");
            // 啊……
            AddTranslation("Ah...", "啊……");
            // 你的[v:0]遭到了[v:1]的毁灭性打击。
            AddTranslation("Your [v:0] has taken a devastating blow from the [v:1].", "乃[v:0]为[v:1]所重创。");
            // 你将无法将其带进队伍。
            AddTranslation("You will not be able to take it with your caravan.", "汝不得携之偕行。");
            // 啊……
            AddTranslation("Ah...", "啊……");
            // 你再也见不到你的[v:0]了，
            AddTranslation("You won't be seeing your [v:0] again,", "汝不复见乃[v:0]矣，");
            // 它承受了太多伤害。
            AddTranslation("It has taken too much damage.", "其所受伤已甚。");
            // 啊……
            AddTranslation("Ah...", "啊……");
            // 你是故意永久牺牲[v:0]的吗？
            AddTranslation("Did you permanently kill your [v:0] on purpose?", "汝故永杀乃[v:0]乎？");
            // 真可惜……
            AddTranslation("A shame...", "惜哉……");
            // 哈！我的大副来了！
            AddTranslation("Ha! There be my first mate!", "哈！我大副来也！");
