            // 哈！它死了！
            AddTranslation("Ha! It's dead!", "哈！彼死矣！");
            // 什么？
            AddTranslation("what?", "何？");
            // 海盗？
            AddTranslation("Pirates?", "海上之盗？");
            // ……
            AddTranslation("...", "……");
            // 准了。
            AddTranslation("I'll allow it.", "吾许之。");
            // 什么？
            AddTranslation("what?", "何？");
            // 作弊？
            AddTranslation("cheating?", "诈乎？");
            // 真令人失望……
            AddTranslation("how dissapointing...", "可惋哉……");
            // ……
            AddTranslation("...", "……");
            // 这场游戏将因你卑劣的轻松取胜而索然无味。
            AddTranslation("the game will be soured from a pitifully easy ascent.", "此局将以卑易之胜而索然。");
            // 作弊者……
            AddTranslation("cheater...", "诈者……");
            // 你难道不知羞耻吗？
            AddTranslation("Have you no shame?", "汝无耻乎？");
            // 如此明目张胆地作弊……
            AddTranslation("To cheat so blatantly...", "乃敢显然为诈……");
            // 你本该命丧黄泉。
            AddTranslation("you should be dead.", "汝本当死。");
            // 然而……
            AddTranslation("and yet...", "然而……");
            // 真是令人失望……
            AddTranslation("how dissapointing...", "可惋哉……");
            // ……
            AddTranslation("...", "……");
            // 我不会再容忍太久了……
            AddTranslation("I won't tolerate this for much longer...", "我不复容此久矣……");
            // 适可而止吧。
            AddTranslation("Enough of this.", "止于此。");
            // 你没死？
            AddTranslation("Yer not dead?", "汝未死乎？");
            // 啊……
            AddTranslation("ah...", "啊……");
            // 那么……恢复正常了？
            AddTranslation("back to normal then?", "则复常乎？");
            // 我得承认，我已经习惯那些改动了……
            AddTranslation("I'll admit, I had gotten used to the changes...", "吾诚言之，我已习于其变矣……");
            // 虚弱卡牌？
            AddTranslation("Weak Cards?", "羸牌乎？");
            // 这很难解释……
            AddTranslation("This is hard to explain...", "此难言也……");
            // 也许他们生病了？没错。
            AddTranslation("Perhaps they are sick? Yes.", "殆疾乎？然。");
            // 一种致残疾病侵袭了你那可怜的造物们。
            AddTranslation("A crippling disease afflicted your meager troupe of creatures.", "沉疢加于汝微薄之物众。");
            // 水生卡牌？
            AddTranslation("Waterborne Cards?", "潜袭牌乎？");
            // 这很难解释……
            AddTranslation("This is hard to explain...", "此难言也……");
            // 或许是变异？没错。
            AddTranslation("Perhaps a mutation? Yes.", "殆其变乎？然。");
            // 你的造物队伍发生了惊人的变异，
            AddTranslation("Your caravan of creatures had a startling mutation,", "汝所偕行之物众，骤有异变，");
            // 它们只能在水域中存活。
            AddTranslation("They could only survive in the water.", "惟于水中乃能存。");
            // 麻痹卡牌？
            AddTranslation("Paralyzed Cards?", "瘫牌乎？");
            // 唔……
            AddTranslation("Hmm...", "唔……");
            // 你的造物们因长途跋涉而精疲力竭，
            AddTranslation("Your group of creatures were fatigued from the long journey,", "乃诸物以长途而疲，");
            // 但前路依然漫长。
            AddTranslation("but there would be a long way to go yet.", "而前路尚长。");
            // 魂弱之牌？
            AddTranslation("Weak Souled Cards?", "弱魂之牌乎？");
            // 唔……
            AddTranslation("Hmm...", "唔……");
            // 你无法将它们的灵魂萃取为新造物，
            AddTranslation("You will not be able to extract their souls into new creatures,", "汝不得抽其魂以入新物，");
            // 塞翁失马……
            AddTranslation("For better or worse...", "祸福难知……");
            // 过往挑战者的命数正压在你身上……
            AddTranslation("The lives of past challengers weighed down on you...", "往昔角者之命数，重压于汝……");
            // 嗯？
            AddTranslation("Hm?", "唔？");
            // 该怎么解释呢……
            AddTranslation("How to explain this...", "斯何以言……");
            // 那天你的补给所剩无几……
            AddTranslation("You were running low on supplies that day...", "其日汝资用将匮……");
            // 你能使用的[c:G][v:0][c:]会更少。
            AddTranslation("You'll have fewer [c:G][v:0]s[c:] to work with.", "汝所用之[c:G][v:0][c:]将寡。");
            // 嗯？
            AddTranslation("Hm?", "唔？");
            // [c:G][v:0][c:]的大爆发……
            AddTranslation("An abundance of [c:G][v:0]s[c:]...", "[c:G][v:0][c:]大蕃矣……");
            // 想必是交配季节到了……
            AddTranslation("Must be mating season...", "殆其交时乎……");
            // 嗯？
            AddTranslation("Hm?", "唔？");
            // 环境效果？
            AddTranslation("Environmental effects?", "环境之效乎？");
            // 真有意思……
            AddTranslation("how interesting...", "有趣哉……");
            // 若要前行，
            AddTranslation("In order to proceed,", "欲前行，");
            // 你不得不艰难跋涉穿过沼泽的湿泞区域。
            AddTranslation("you had to slog through the wetter parts of the swamp.", "汝不得不跋涉泽中最湿之处。");
            // 黏稠的[c:G]淤泥[c:]粘附靴底，拖缓了你的步伐……
            AddTranslation("The thick[c:G][c:G]mud[c:] stuck to your boots, and hindered your movements...", "稠[c:G]泥[c:]著于靴，而缓乃步……");
            // 刺骨的寒风并非你唯一的阻碍，
            AddTranslation("The frigid air was not the only obstacle in your way,", "砭骨之寒，非汝独一之阻也，");
            // 严酷的冰原与无情的积雪同样横亘于前。
            AddTranslation("the harsh ice and unforgiving snow also stood in your path.", "严冰与积雪亦并横于前。");
            // 很快你便置身于……
            AddTranslation("before long you found yourself in...", "未几，汝已置身于……");
            // [c:B]冰雹风暴[c:]之中。
            AddTranslation("a [c:B]hailstorm.[c:]", "一场[c:B]雹暴[c:]。");
            // 你发现自己被逼到了陡峭的石壁前，
            AddTranslation("You found yourself cornered against a sheer rock wall,", "汝迫于峭壁之前，");
            // 一面[c:G]悬崖边缘[c:]。
            AddTranslation("the [c:G]cliffside.[c:]", "一面[c:G]绝崖[c:]。");
            // 面对冰冷的岩石，战斗空间将变得更为狭小
            AddTranslation("Against the cold stone, there would be less space to fight.", "负冷石而战，其地益狭。");
            // 菌学家们留下了一项实验品，
            AddTranslation("The mycologists had left one of their experiments behind,", "蕈家遗其一试物，");
            // 他们未曾察觉，这实验品已开始溃烂滋长。
            AddTranslation("unbeknownst to them, it began to fester and grow.", "而彼不知其已溃而长。");
            // 即便是与你交战的生物也难逃[c:G]真菌团块[c:]的侵蚀。
            AddTranslation("even the creatures fighting you would not be safe from the [c:G]fungal mass.[c:]", "虽与汝战之物，亦难免于[c:G]蕈团[c:]之侵。");
            // 你无意中发现了一处矿工的营地。
            AddTranslation("You stumbled across one of the Prospector's Camps.", "汝偶至采夫一营。");
            // 营地里堆满了采矿工具。
            AddTranslation("The camp was filled with prospecting tools.", "营中充采具。");
            // 镐头、矿灯……
            AddTranslation("pickaxes, headlamps...", "镐、矿灯……");
            // 还有[c:bR]炸药[c:]。
            AddTranslation("and [c:bR]dynamite.[c:]", "与[c:bR]炸药[c:]。");
            // 你遇到了钓鱼人的一个池塘，
            AddTranslation("You came across one of the Angler's Ponds.", "汝过渔父之池一所，");
            // 空气中弥漫着腐鱼的恶臭
            AddTranslation("the area stank of rotting fish", "其地满腐鱼之恶臭");
            // 气味来自附近废弃的[c:dB]鱼饵[c:]桶。
            AddTranslation("emanating from the nearby abandoned buckets of [c:dB]bait.[c:]", "其气出于近侧弃置之[c:dB]饵[c:]桶。");
            // 你发现了一处猎人的狩猎场。
            AddTranslation("You came across one of the Trapper's Hunting Grounds.", "汝至猎夫之猎场一所。");
            // 空气中弥漫着血腥味……
            AddTranslation("the stench of blood hung in the air...", "血腥之气悬于空中……");
            // 你注意到地上潜伏着许多[c:G]陷阱[c:]。
            AddTranslation("you noticed the numerous [c:G]traps[c:] lying in wait.", "汝见地上多[c:G]阱[c:]伏焉。");
            // 你遇到一座奇怪的[c:bR]图腾[c:]。
            AddTranslation("You came upon a strange [c:bR]totem.[c:]", "汝遇一怪[c:bR]图腾[c:]。");
            // 神秘能量在其周围盘旋，
            AddTranslation("a mysterious energy swirled around it,", "神异之气旋于其旁，");
            // 附近的生物似乎比往常更具攻击性……
            AddTranslation("the creatures nearby seem more agressive than usual...", "近侧诸物似较常时益暴……");
            // 啊……
            AddTranslation("Ah...", "啊……");
            // 一轮[c:bR]血月[c:]。
            AddTranslation("a [c:bR]Blood Moon.[c:]", "一轮[c:bR]血月[c:]。");
            // 呃……
            AddTranslation("Er...", "呃……");
            // 你……
            AddTranslation("You...", "汝……");
            // ……
            AddTranslation("...", "……");
            // ……什么？
            AddTranslation("...What?", "……何？");
            // 我无言以对。
            AddTranslation("I am at a loss for words.", "我无以言。");
            // 狂风在你周围呼啸。
            AddTranslation("The wind was howling around you.", "狂风号于汝四周。");
            // 被困在暴风雪中央，
            AddTranslation("Stuck in the middle of a blizzard,", "困于暴雪之中，");
            // 你听见上方山脉传来隆隆巨响。
            AddTranslation("You heard rumbling from the mountains above.", "汝闻上方群山有殷殷之声。");
            // 它来了……
            AddTranslation("Here it comes...", "其来也……");
            // 一场[c:B]雪崩[c:]。
            AddTranslation("an [c:B]avalanche.[c:]", "一场[c:B]雪崩[c:]。");
            // 你偶然发现了一块诡异的黑色石碑。
            AddTranslation("You stumble across a strange black stone.", "汝偶见一怪黑石。");
            // 碑前摆放着用于献祭的石制祭坛。
            AddTranslation("A stone tablet sits in front of it, clearly made for sacrifices.", "其前有石坛，显为牲祀而设。");
            // 或许特定造物能引发异象？
            AddTranslation("Perhaps a certain creature may cause a reaction?", "或某物能致其应乎？");
            // 方尖碑因喜悦而震颤。
            AddTranslation("The obelisk trembles in delight.", "方尖碑喜而震。");
            // 山羊确实是上等祭品。
            AddTranslation("A goat is truly a worthy sacrifice.", "山羊诚堪祀也。");
            // 你再也见不到它了。
            AddTranslation("You won't be seeing it again.", "汝不复见之矣。");
            // 方尖碑因愤怒而震颤。
            AddTranslation("The obelisk rumbles with anger.", "方尖碑忿而震。");
            // 毛皮实在是可悲的祭品。
            AddTranslation("A pelt is a truly pitiful sacrifice.", "革诚鄙祭也。");
            // ……
            AddTranslation("...", "……");
            // ……这算不上真正的献祭。
            AddTranslation("...That is not a proper sacrifice.", "……此非正祭。");
            // 住手。
            AddTranslation("Stop this.", "止。");
            // 你……
            AddTranslation("You...", "汝……");
            // 这是无谓的杀戮。
            AddTranslation("This is bloodshed without meaning.", "此徒流血耳。");
            // [v:0]……
            AddTranslation("[v:0]...", "[v:0]……");
            // 嗯？
            AddTranslation("Hmm?", "唔？");
            // 这是何物？
            AddTranslation("What is this?", "此何物？");
            // 嘿嘿嘿……
            AddTranslation("Heh heh heh...", "呵呵呵……");
            // 你闯进海盗老窝了！
            AddTranslation("Ye walked into th' pirate's cove!", "汝误入海上之盗之巢矣！");
            // 老子的小弟们马上送你上路！
            AddTranslation("Me crew will get rid of ye quick!", "吾徒众须臾除汝！");
            // 你劈开茂密的灌木与枝叶。
            AddTranslation("You carve through the thick underbrush and foilage.", "汝披荆斩棘而行。");
            // 树冠遮蔽了阳光……
            AddTranslation("The trees blotting out the sun...", "木阴蔽日……");
            // 行进间，你听见周遭的树林开始发出吱呀声响。
            AddTranslation("As you travel, you hear the woods start to creak around you.", "行旅之间，汝闻林木四周始作格格之声。");
            // 你该明白不该在黑暗中穿行……
            AddTranslation("You should know better than to walk in the darkness...", "汝当知不宜行于冥暗……");
            // 当你的造物队伍行进时，你听到一阵湍急的声响。
            AddTranslation("As your caravan of creatures travels, you hear a rushing sound.", "汝所偕行之物众行时，闻有急流之声。");
            // 你攀至高处，四周水流奔涌。
            AddTranslation("You climb to a higher place as water flows around you.", "汝登高处，而水四面奔流。");
            // 你被困在[c:B]洪水[c:]之中。
            AddTranslation("You are caught in a [c:B]flood.[c:]", "汝困于[c:B]洪水[c:]。");
            // 只有地形卡与飞行造物能避开洪水侵袭。
            AddTranslation("Only the terrain and flying creatures will be able to avoid the waters.", "惟地形牌与翔物得免于水。");
            // 当你的造物队伍穿过一片空地时，风势渐强。
            AddTranslation("As your caravan of creatures moves across a clearing, the winds blow stronger.", "汝所偕行之物众过一旷地，而风益劲。");
            // 一阵强风迎面袭来，你为保命紧紧抓住周围物体。
            AddTranslation("A strong breeze greets your face, and you grasp onto the surroundings for dear life.", "劲风迎面而至，汝攀援四旁以自全。");
            // 你的造物们被吹得[c:G]腾空而起[c:]。
            AddTranslation("Your creatures are blown [c:G]airborne.[c:]", "乃诸物皆为风吹而[c:G]翔袭[c:]。");
            // 唯有入地或潜水的造物能避开这股狂风。
            AddTranslation("Only burrowing and submerged creatures will be able to avoid the gusts.", "惟潜地与潜水之物得避此风。");
            // 微风轻拂……
            AddTranslation("The Breeze blows...", "微风作矣……");
            // 你发现了一堆尸体。
            AddTranslation("You come across a pile of corpses.", "汝见积尸一堆。");
            // 当你靠近时，一股诡异的能量在尸体周围盘旋。
            AddTranslation("A strange energy swirls around them as you approach.", "汝既近，则怪气旋其旁。");
            // 随后……
            AddTranslation("Then...", "俄而……");
            // [c:R]亡者苏生[c:]。
            AddTranslation("[c:R]The dead walk.[c:]", "[c:R]亡者起行。[c:]");
            // [c:R]亡者苏生[c:]。
            AddTranslation("[c:R]The dead walk.[c:]", "[c:R]亡者起行。[c:]");
            // 你遇到一片葱郁的林间空地。
            AddTranslation("You came across an overgrown glade.", "汝过一蔓生之隙地。");
            // 树木似乎比往常更加高大茁壮。
            AddTranslation("The trees seemed taller, and stronger than usual.", "木似较常时益高且壮。");
            // 你的造物们也生长得更快了。
            AddTranslation("Your creatures grew faster as well.", "乃诸物亦长益速。");
            // <color=#25C102>急速生长</color>。
            AddTranslation("<color=#25C102>Flash Growth.</color>", "<color=#25C102>急长。</color>");
            // <color=#25C102>急速生长</color>。
            AddTranslation("<color=#25C102>Flash Growth.</color>", "<color=#25C102>急长。</color>");
            // 嗯？
            AddTranslation("Hm?", "唔？");
            // 你在减少容器数量？
            AddTranslation("You're decreasing the number of vessels you have?", "汝减所蓄之皿数乎？");
            // 像你这么菜的玩家不该多留些炮灰挡刀吗？
            AddTranslation("Surely a player as bad as you needs the extra chump blockers?", "如汝之拙者，岂不需此徒御者乎？");
            // 等着瞧吧
            AddTranslation("You'll see.", "后自知之。");
            // 嗯？
            AddTranslation("Hm?", "唔？");
            // 你要增加容器数量？
            AddTranslation("You're increasing the number of vessels you have?", "汝益所蓄之皿数乎？");
            // 合理。
            AddTranslation("Makes sense.", "然。");
            // 毕竟像你这么菜的玩家需要多点炮灰挡刀。
            AddTranslation("After all, a player as bad as you needs the extra chump blockers.", "毕竟如汝之拙者，需此徒御者。");
            // [v:0]个容器……
            AddTranslation("[v:0] vessels...", "[v:0]皿……");
            // 哦？
            AddTranslation("Oh?", "噫？");
            // 你连这点改动都坚持不了？
            AddTranslation("You couldn't even stick to the changes?", "汝连此变亦守不能乎？");
            // 可悲。
            AddTranslation("Pathetic.", "鄙矣。");
            // 哦？
            AddTranslation("Oh?", "噫？");
            // 我自己的机械衔尾蛇？
            AddTranslation("My own Ourobot?", "我之机衔尾蛇乎？");
            // 觉得这是个好主意，你肯定有受虐倾向。
            AddTranslation("You must be masochistic if you thought this was a good idea.", "汝以此为善谋，则殆好苦者也。");
            // 你自找的。
            AddTranslation("Your funeral.", "自取其殃。");
            // 它没了。
            AddTranslation("There it goes.", "彼去矣。");
            // 你只是让它变得更强了。
            AddTranslation("You just made it stronger.", "汝徒使之益强耳。");
            // 当然，你早就知道会这样。
            AddTranslation("Of course, you knew that already.", "当然，汝固已知之。");
            // 我可不担心。
            AddTranslation("I'm not worried.", "我不忧。");
            // 它迟早会回来碾碎你。
            AddTranslation("It'll come back to crush you later.", "后必复来而碎汝。");
            // 嗯？
            AddTranslation("Hm?", "唔？");
            // 初始卡牌削弱了？
            AddTranslation("Weaker starting cards?", "初牌益弱乎？");
            // 区区1点生命值能改变什么。
            AddTranslation("As if one health will make a difference.", "一命之差，何足道。");
            // 嗯？
            AddTranslation("Hm?", "唔？");
            // 莫非我的环境牌还入不了你的眼？
            AddTranslation("Were my environments not good enough for you?", "莫非我之环境不足入汝目乎？");
            // 行吧。
            AddTranslation("Fine.", "可。");
            // 嗯……
            AddTranslation("Hm...", "唔……");
            // 你发现了一处……
            AddTranslation("You have found a...", "汝得一……");
            // 机器人坟场。
            AddTranslation("Robot scrapyard.", "机冢。");
            // 到处都是报废的机器人。
            AddTranslation("There's broken down robots everywhere.", "四野皆弊机人。");
            // 这片区域的每个机器人都会死两次。
            AddTranslation("Every robot in this area dies twice.", "此地诸机人皆二死。");
            // 又是废料场。
            AddTranslation("It's the scrapyard again.", "又机冢矣。");
            // 规矩你都懂。
            AddTranslation("You know the drill.", "其故常汝已知之。");
            // 呃
            AddTranslation("Eugh", "啧。");
            // 这是[c:O]他[c:]的东西。
            AddTranslation("This is one of [c:O]HIS.[c:]", "此乃[c:O]彼[c:]之一也。");
            // 你的……易形者机器人在这里会更有效。
            AddTranslation("Your... transformer bots will be more effective here.", "乃易形机人于此益效。");
            // 打出时它们会变形。
            AddTranslation("They'll transform when played.", "既陈则化。");
            // 等着瞧吧。
            AddTranslation("You'll see.", "后自知之。");
            // 你的易形者机器人在这里会更有效。
            AddTranslation("Your transformer bots will be more effective here.", "乃易形机人于此益效。");
            // 打出时它们会变形。
            AddTranslation("They'll tranform when played.", "既陈则化。");
            // 啊……
