            // 这是我最中意的机制。
            AddTranslation("A favorite of mine.", "此我所好也。");
            // 在你的每个回合开始时，所有卡牌都会顺时针移动。
            AddTranslation("At the start of each of your turns all cards will be moved clockwise.", "汝每合始，诸牌皆顺时而移。");
            // 想必你早见识过了。
            AddTranslation("I'm sure you've seen it before.", "想汝已见之矣。");
            // 在你的每个回合开始时，所有卡牌都会顺时针移动。
            AddTranslation("At the start of each of your turns all cards will be moved clockwise.", "汝每合始，诸牌皆顺时而移。");
            // 你之前见过这个效果。
            AddTranslation("You've seen it before.", "汝尝见之矣。");
            // 啊……
            AddTranslation("Ah...", "啊……");
            // 你的<color=#25C102>宝</color>[c:O]石[c:][c:B]们[c:]会更有用。
            AddTranslation("Your <color=#25C102>G</color>[c:O]E[c:][c:B]M[c:]s will be more useful.", "乃<color=#25C102>玉</color>[c:O]石[c:][c:B]诸物[c:]将益有用。");
            // 比[c:R]他[c:]能创造的更有用……
            AddTranslation("More useful than [c:R]he[c:] ever was able to make them...", "益于[c:R]彼[c:]之所能为者……");
            // ……只要你让那东西活着。
            AddTranslation("...As long as you keep that one alive.", "……惟当使彼一物生。");
            // 你的<color=#25C102>宝</color>[c:O]石[c:][c:B]们[c:]会更有用。
            AddTranslation("Your <color=#25C102>G</color>[c:O]E[c:][c:B]M[c:]s will be more useful.", "乃<color=#25C102>玉</color>[c:O]石[c:][c:B]诸物[c:]将益有用。");
            // ……只要你让那东西活着。
            AddTranslation("...As long as you keep that one alive.", "……惟当使彼一物生。");
            // 呵
            AddTranslation("Heh", "呵。");
            // 这个会相当……
            AddTranslation("This one will be quite...", "此将颇……");
            // 电人。
            AddTranslation("Shocking.", "骇矣。");
            // 你发现自己身处雷暴之中。
            AddTranslation("You find yourself in an electrical storm.", "汝身处雷暴之中。");
            // 打出卡牌时会受到1点伤害。
            AddTranslation("When a card is played, it will take 1 damage.", "有牌既陈，则受一伤。");
            // 若能存活则会暂时变强。
            AddTranslation("If it survives, it'll be stronger for a bit.", "若不死，则暂益强。");
            // 你会发现这个相当……
            AddTranslation("I think you'll find this one quite...", "汝将见此颇……");
            // 电人。
            AddTranslation("Shocking.", "骇矣。");
            // 不死鹦鹉
            AddTranslation("Undead Parrot", "不死鹦鹉");

            // Challenge
            // 攀登者的祸根
            AddTranslation("Ascender's Bane", "陟者殃");
            // 你的初始牌组中多了一张无用的牌。
            AddTranslation("You start with a useless card in the deck.", "始牌列中增一无用之牌。");
            // 优胜冠军
            AddTranslation("Champions", "冠军");
            // 对手牌有概率获得各色冠军印记。
            AddTranslation("Opponent cards have a chance to become a champion.", "敌牌或得为冠军。");
            // 环境影响
            AddTranslation("Environmental Effects", "环境之效");
            // 在每次战斗开始时都可能会激活一个随机的环境效果。
            AddTranslation("At the start of each battle, a random environmental effect may activate.", "每战始，或发一偶环境之效。");
            // 饥荒
            AddTranslation("Famine", "饥");
            // 失控副牌
            AddTranslation("Runaway Side Deck", "奔副牌");
            // 你的副牌获得稍纵即逝印记。
            AddTranslation("Your Side Deck cards have the Fleeting sigil.", "汝副牌皆有暂印。");
            // 金色羊皮
            AddTranslation("The Golden Fleece", "金革");
            // 在整个游戏过程中随机出现一只金羊。
            AddTranslation("A Golden Ram appears randomly throughout the run.", "一金羊行于此局，时或见之。");
            // 更强的头目
            AddTranslation("Harder Bosses", "强魁");
            // 头目的主力牌更强大，头目更具攻击性。
            AddTranslation("Bosses' main cards are more powerful, and bosses are more agressive.", "诸魁主牌益强，而魁亦益暴。");
            // 真正的海盗
            AddTranslation("True Pirate", "真海盗");
            // 海盗入侵头目战。最终的头目挑战更难。
            AddTranslation("Pirates invade Bosses. The Final Boss Challenge is harder.", "海上之盗犯诸魁。终竟易魁之角，益难。");
            // 额外生命
            AddTranslation("Extra Lives", "余命");
            // 拙劣实验
            AddTranslation("Botched Experiments", "拙试");
            // 菌学家在融合卡牌时有可能出错。
            AddTranslation("The Mycologists have a chance to make mistakes while fusing cards.", "蕈家并牌，或致谬失。");
            // 无尽丰产
            AddTranslation("Old Fecundity", "旧蕃息");
            // 丰产之巢印记回归至与原版一致。
            AddTranslation("Reverts the Fecundity Nerf.", "使蕃息复其旧制。");
            // 重新尝试
            AddTranslation("Mulligan", "更引");
            // 你可以在每场战斗开始时重新抽取你的手牌。
            AddTranslation("You may redraw your hand at the start of each battle.", "每战始，汝可更引其手牌。");
            // 反向天平不平
            AddTranslation("Reverse Scales", "反倾衡");
            // 在天平的敌对一侧受到1点伤害的情况下开始所有战斗。
            AddTranslation("Start all battles with 1 damage on the opponent's side of the scale.", "诸战皆以敌衡先受一伤而始。");
            // 惊魂未定的开局
            AddTranslation("Shocked Starters", "初牌瘫");
            // 起始牌组中的牌每隔一回合才会攻击一次。
            AddTranslation("Cards in starting deck attack every other turn.", "初牌列中诸牌，隔合乃攻。");
            // 奔腾灾难
            AddTranslation("Sprintmaggedon", "疾行灾");
            // 所有卡牌在抽取时都会获得一个随机移动印记。
            AddTranslation("All cards get a random Sprinter sigil when drawn.", "诸牌既引，皆得一偶移印。");
            // 旅行衔尾蛇
            AddTranslation("Traveling Ouroboros", "行衔尾蛇");
            // 一只旅行的衔尾蛇出现在整个冒险过程中。
            AddTranslation("A traveling Ouroboros appears throughout the run.", "行衔尾蛇周见于此局。");
            // 不公之手
            AddTranslation("Unfair Hand", "偏手");
            // 你的起始手牌是完全随机抽取的。
            AddTranslation("Your starting hand is randomly drawn.", "汝初手皆偶引。");
            // 爆炸噪音
            AddTranslation("Explosive Noise", "爆响");
            // 当一张牌死了，就会响起一声巨响。所有卡牌在死亡时都会爆炸。
            AddTranslation("When a card dies, a loud boom will play. All cards explode on death.", "牌死则巨响发，诸牌死皆爆。");
            // 水袭的开局
            AddTranslation("Aquatic Starters", "初牌潜");
            // 起始牌组中的牌拥有水袭印记。
            AddTranslation("Cards in starting deck have the Waterborne sigil.", "初牌列中诸牌皆有潜袭印。");
            // 失魂的开局
            AddTranslation("Unspirited Starters", "初牌弱魂");
            // 起始牌组中的牌拥有孱弱之魂印记。
            AddTranslation("Cards in the starting deck may not have their sigils transferred.", "初牌列中诸牌皆有弱魂印。");
            // 虚弱的开局
            AddTranslation("Weak Starters", "初牌弱");
            // 起始牌组中的牌的生命值减少1。
            AddTranslation("Cards in the starting deck have 1 less health.", "初牌列中诸牌命减一。");

            // Ability
            // 蓝色冠军
            AddTranslation("Blue Champion", "蓝冠军");
            // 只要此冠军还存活在场，此冠军就会让同一侧的所有其他非地形卡获得空袭印记。
            AddTranslation("This champion will cause all other non-Terrain cards on the same side to gain flight, as long as the champion is alive.", "此冠军存，则同侧余非地形牌皆得翔袭。");
            // 鲜红冠军
            AddTranslation("Bright Red Champion", "绛冠军");
            // 在每个回合开始时，此冠军将治愈对手一侧的所有非地形生物1点生命。
            AddTranslation("At the start of each turn, this champion will heal all other non-terrain creatures on the opponent's side by 1.", "每合始，此冠军疗敌侧余非地形物一命。");
            // 青色冠军
            AddTranslation("Cyan Champion", "青冠军");
            // 当这位冠军阵亡时，它将对场上的其他造物造成1点伤害。
            AddTranslation("When this champion perishes, it will deal 1 damage to every other creature on the board.", "此冠军死，则伤局上余物各一。");
            // 爆炸性之物
            AddTranslation("Explosive", "爆");
            // 其他卡牌可以放在[creature]的上方；相邻卡牌和对位卡牌都将受到10点伤害。
            AddTranslation("Other cards may be placed on top of [creature]; the other card, adjacent cards, and opposing cards will all be dealt 10 damage.", "他牌可陈于[creature]之上；其牌、邻牌与对牌皆受十伤。");
            // 当[creature]阵亡时，它会回到你手中。
            AddTranslation("When [creature] perishes, a copy of it is created in the opponent's hand.", "[creature]死，则其副生于敌手。");
            // 虚弱
            AddTranslation("Fragile", "脆");
            // 如果带有该印记的卡牌阵亡，它将从你的牌组中永久移除。
            AddTranslation("If [creature] perishes, it is permanently removed from your deck.", "[creature]若死，永出汝牌列。");
            // 绿色冠军
            AddTranslation("Green Champion", "绿冠军");
            // 这位冠军在摧毁另一个造物后，将直接对其持有者造成1点伤害。
            AddTranslation("This champion will deal 1 damage directly to you, after it destroys another creature.", "此冠军杀他物后，直伤其主一。");
            // 淡蓝冠军
            AddTranslation("Light Blue Champion", "淡蓝冠军");
            // 当这位冠军阵亡时，它将对其左右两侧的造物以及对方造物造成3点伤害。
            AddTranslation("When this champion perishes, it will deal 3 damage to creatures to the left and right of it as well as the opposing creature.", "此冠军死，则其左右之物与其对物皆受三伤。");
            // 浅绿冠军
            AddTranslation("Light Green Champion", "浅绿冠军");
            // 这位冠军将阻止第一次攻击造成的所有伤害。印记等效果造成的伤害将无法阻止。
            AddTranslation("This champion will prevent all damage from the first strike dealt to it. Damage from effects like sigils will not be prevented.", "此冠军首见击，尽拒其伤；印等诸效之伤，则不能拒。");
            // 品红冠军
            AddTranslation("Magenta Champion", "品红冠军");
            // 在每个回合开始时，这位冠军将在你一侧的随机空间造成1点伤害。
            AddTranslation("At the start of each turn, this champion will attack for 1 damage in a random space on your side.", "每合始，此冠军于汝侧偶一位出一伤。");
            // 污泥浊浪
            AddTranslation("Muddy", "泥");
            // 其他牌可以放在带有该印记的卡牌的上方，但一回合内无法攻击，将获得污泥浊浪印记。如果带有该印记的卡牌被献祭，献祭其上场的生物第一回合无法攻击。
            AddTranslation("Other cards may be placed on top of [creature], but will be unable to attack for one turn and will gain Muddy. If [creature] is sacrificed, the sacrificing creature will be unable to attack for one turn.", "他牌可陈于[creature]之上，然一合不得攻，且得泥印；若[creature]见祀，则受其祀而陈者亦一合不得攻。");
            // 献祭石板
            AddTranslation("Sacrificial Slab", "祀石");
            // 其他卡牌可以放在带有该印记的卡牌的上方；另一张牌将会被杀死。
            AddTranslation("Other cards may be placed on top of [creature]; the other card will die.", "他牌可陈于[creature]之上；其牌即死。");
            // 橙色冠军
            AddTranslation("Orange Champion", "橙冠军");
            // 如果直接对你造成伤害，这位冠军会从你身上偷走2个货币金牙。
            AddTranslation("This champion will steal 2 golden teeth from you if it damages you directly.", "此冠军若直伤汝，则窃金齿二。");
            // 带有该印记的卡牌每隔一回合才会攻击一次。
            AddTranslation("[creature] may not attack every other turn.", "[creature]隔合一攻。");
            // 紫色冠军
            AddTranslation("Purple Champion", "紫冠军");
            // 每次你出牌时，如果这位冠军的对位是空的，该牌就会移动到那个空间。
            AddTranslation("Each time you play a card, if the space opposing this champion is empty, that card will move to that space.", "汝每陈牌，若此冠军对位为空，则彼牌移就其位。");
            // 适航状态
            AddTranslation("Seaworthy", "耐潜");
            // 其他卡牌可以放在带有该印记的卡牌的顶部，卡牌上的任何水袭印记都将失效。
            AddTranslation("Other cards may be placed on top of [creature], any Waterborne sigils on the card will be negated.", "他牌可陈于[creature]之上；其牌之潜袭印皆废。");
            // 红色冠军
            AddTranslation("Red Champion", "赤冠军");
            // 此冠军额外获得2点生命值。
            AddTranslation("This champion starts with 2 additional Health.", "此冠军始得命二。");
            // 避难所
            AddTranslation("Shelter", "庇");
            // 与带有该印记的卡牌相邻的卡牌不受环境影响。
            AddTranslation("Adjacent cards are sheltered from environmental effects.", "邻牌得庇于环境之效。");
            // 雪崩
            AddTranslation("Avalancher", "崩");
            // 在持牌人的回合结束时，带有该印记的卡牌将按印记标注方向移动。相撞的造物将被杀死。如果带有该印记的卡牌位于场地最右侧，它将死亡。
            AddTranslation("At the end of the owner's turn, [creature] will move in the direction inscribed in the sigil. Creatures in the way will be killed. If [creature] is at the right most side of the board, it dies.", "持牌者合终，[creature]循印所志而移；当途之物皆死。若[creature]已在最右，则自死。");
            // 在持牌人的回合结束时，带有该印记的卡牌将按印记标注方向移动。相撞的造物将被杀死。
            AddTranslation("At the end of the owner's turn, [creature] will move in the direction inscribed in the sigil. Creatures in the way will be killed.", "持牌者合终，[creature]循印所志而移；当途之物皆死。");
            // 持牌人的回合结束时，带有该印记的卡牌将向右移动，跳过其路径上的任何造物，如果遇到场地边缘，它将绕到另一边。
            AddTranslation("At the end of the owner's turn, [creature] will move to the right, jumping over any creatures in its path. If it encounters the edge of the board, it will loop over to the other side.", "持牌者合终，[creature]右移，越其途诸物；遇边，则绕于彼侧。");
            // 白色冠军
            AddTranslation("White Champion", "白冠军");
            // 当这个冠军阵亡时，它将在自己的空间里生成一个磐石。[define:Boulder]
            AddTranslation("When this champion perishes, it will create a Boulder in its space. [define:Boulder]", "此冠军死，则其处生一磐。[define:Boulder]");
            // 黄色冠军
            AddTranslation("Yellow Champion", "黄冠军");
            // 此冠军额外获得1点力量。
            AddTranslation("This champion starts with 1 additional Power.", "此冠军始得威一。");

            // Boon
            // 环境：钓鱼人的池塘
            AddTranslation("Environment: Angler's Pond", "环境：渔父之池");
            // 对手将以拥有鱼饵的方式展开战斗。
            AddTranslation("The opponent will start the battle with Bait Buckets.", "敌将以饵桶而战始。");
            // 环境：暴雪
            AddTranslation("Environment: Blizzard", "环境：暴雪");
            // 在每回合开始时，如果场上没有雪崩，则会在场上的最左侧生成一个雪崩。
            AddTranslation("At the start of each turn, if there is not an Avalanche present on the board, one will be created on the left-most side of the board.", "每合始，若局中无雪崩，则最左生一雪崩。");
            // 环境：血月
            AddTranslation("Environment: Blood Moon", "环境：血月");
            // 对手将以拥有冰原狼幼崽的情况下开始战斗。
            AddTranslation("The opponent will start the battle with Dire Wolf Pups.", "敌将以恐狼崽而战始。");
            // 环境：微风
            AddTranslation("Environment: Breeze", "环境：微风");
            // 在每个回合开始时，场上所有造物都会获得或失去空袭印记；此环境对地形和拥有水袭或钻地龙印记的造物无效。
            AddTranslation("At the start of every turn, all creatures gain or lose Airborne. Terrain, and creatures with Waterborne or Burrower are ignored.", "每合始，诸物或得或失翔袭；地形与有潜袭、潜龙者不与。");
            // 环境：萝卜地
            AddTranslation("Environment: Carrot Patch", "环境：萝圃");
            // 对手将以拥有兔子的情况下开始战斗。
            AddTranslation("The opponent will start the battle with Rabbits.", "敌将以兔而战始。");
            // 环境：陡崖
            AddTranslation("Environment: Cliffside", "环境：绝崖");
            // 在战斗开始时，最左侧的路线将被陡崖封锁。
            AddTranslation("At the start of the battle, the leftmost lane will be blocked with Cliffs.", "战始，最左之列为崖所塞。");
            // 环境：工厂
            AddTranslation("Environment: Factory", "环境：工肆");
            // 维持状态下，场上所有卡牌均顺时针旋转1格。
            AddTranslation("On Upkeep, all cards are rotated clockwise.", "每合始，诸牌皆顺时移一格。");
            // 环境：黑森林
            AddTranslation("Environment: Dark Forest", "环境：黑林");
            // 对手将在拥有森林的情况下展开战斗。对手的所有地形卡都+1力量。
            AddTranslation("The opponent will start the battle with Trees. All of the opponent's terrain have +1 power.", "敌将以树而战始；其诸地形牌威皆益一。");
            // 环境：矿工的营地
            AddTranslation("Environment: Prospector's Camp", "环境：采夫之营");
            // 您将在某些位置上与潜在的危险人物展开战斗。
            AddTranslation("You will start the battle with Dynamite on some of your spaces.", "汝战始时，其侧数位有炸药。");
            // 环境：雷暴
            AddTranslation("Environment: Electrical Storm", "环境：雷暴");
            // 放置一张牌时，它会受到1点伤害，并获得1点力量。
            AddTranslation("When a card is played, it takes 1 damage and gains 1 power.", "牌既陈，则受一伤而威益一。");
            // 环境：快速生长
            AddTranslation("Environment: Flash Growth", "环境：急长");
            // 当一张牌被放置时，任何在回合开始时激活的印记都被激活一次。
            AddTranslation("When a card is played, any sigils that activate at the start of the turn are activated.", "牌既陈，则凡合始而发之印皆启。");
            // 环境：洪水
            AddTranslation("Environment: Flood", "环境：洪水");
            // 每放置一张造物，其获得水袭印记；此环境对地形和具有空袭印记的造物无效。
            AddTranslation("Whenever a creature is played, it gains Waterborne. Terrain, and creatures with Airborne are ignored.", "物既陈，则得潜袭；地形与有翔袭者不与。");
            // 环境：宝石保护区
            AddTranslation("Environment: Gem Sanctuary", "环境：玉境");
            // 所有宝石都+1力量。
            AddTranslation("All gems have +1 power.", "诸玉威皆益一。");
            // 环境：墓地
            AddTranslation("Environment: Graveyard", "环境：墓");
            // 当一个造物死亡时，它会立即复活并再次死亡。
            AddTranslation("When a creature dies, it dies again.", "一物既死，则复死。");
            // 环境：冰雹
            AddTranslation("Environment: Hail Storm", "环境：雹暴");
            // 在每个回合开始时，回合所有者的所有非地形卡受到1点伤害。
            AddTranslation("At the start of each turn, all of the turn owner's non-terrain cards take 1 damage.", "每合始，合主诸非地形牌皆受一伤。");
            // 环境：海盗谷
            AddTranslation("Environment: Pirate's Hollow", "环境：盗谷");
            // 对手将用迷你柠檬琴开始战斗。
            AddTranslation("The opponent will start the battle with a Minicello.", "敌将以小琴舟而战始。");
            // 环境：泥沼
            AddTranslation("Environment: Mud Swamp", "环境：泥泽");
            // 你将在场上有泥沼的情况下开始战斗。
            AddTranslation("You will start the battle with Mud on some of your spaces.", "汝战始时，其侧数位有泥。");
            // 环境：真菌场
            AddTranslation("Environment: Fungal Field", "环境：蕈场");
            // 对手将使用蘑菇开始战斗。
            AddTranslation("The opponent will start the battle with Mushrooms.", "敌将以蕈而战始。");
            // 环境：方尖碑
            AddTranslation("Environment: Obelisk", "环境：方尖碑");
            // 对手将在拥有方尖碑的情况下开始战斗。
            AddTranslation("The opponent will start the battle with an Obelisk.", "敌将以方尖碑而战始。");
            // 环境：诅咒图腾
            AddTranslation("Environment: Cursed Totem", "环境：咒图腾");
            // 对手将使用诅咒图腾以开始战斗。
            AddTranslation("The opponent will start the battle with Cursed Totems.", "敌将以咒图腾而战始。");
            // 环境：猎人的狩猎场
            AddTranslation("Environment: Trapper's Hunting Grounds", "环境：猎夫之猎场");
            // 对手将使用钢制陷阱以开始战斗。
            AddTranslation("The opponent will start the battle with Steel Traps.", "敌将以铁阱而战始。");

            // Card
            // 攀登者的祸根
            AddTranslation("Ascender's Bane", "陟者殃");
            // 提醒过去的挑战者。
            AddTranslation("A reminder of past challengers.", "往昔角者之征也。");
            // 雪崩
            AddTranslation("Avalanche", "雪崩");
            // 巨大的雪堆。
            AddTranslation("A monsterous mound of snow.", "巨雪之堆也。");
            // 陡崖
            AddTranslation("Cliff", "绝崖");
            // 坚固的岩石墙。
            AddTranslation("A solid wall of rock.", "坚岩之壁也。");
            // 三叶草
            AddTranslation("Clover", "三叶草");
            // 罗亚尔船员中忠诚的成员。
            AddTranslation("A loyal member of Royal's crew.", "罗亚尔舟卒之忠者。");
            // 炸药
            AddTranslation("Dynamite", "炸药");
            // 一盒炸药。
            AddTranslation("A box of dynamite.", "炸药一匣。");
            // 金羊
            AddTranslation("Chrysomallos", "克律索马罗斯");
            // 神秘的、闪闪发光的生物。
            AddTranslation("A mystical, glittering being.", "神异而晶耀之物。");
            // 冰块
            AddTranslation("Ice Cube", "冰块");
            // 一块冰。
            AddTranslation("A block of ice.", "冰一块。");
            // 迷你柠檬琴号
            AddTranslation("Minicello", "小琴舟");
            // 一艘著名海盗船的微型版。
            AddTranslation("A miniture version of a famous pirate's ship.", "名海盗舟之小制也。");
            // 泥沼
            AddTranslation("Mud", "泥");
            // 蘑菇
            AddTranslation("Mushrooms", "蕈");
            // 一批奇怪的蘑菇。它们吸引附近的任何东西。
            AddTranslation("A collection of strange mushrooms. They attract anything nearby.", "异蕈丛也。其能招近侧诸物。");
            // 方尖碑
            AddTranslation("Obelisk", "方尖碑");
            // 一块高高的神秘石头。
            AddTranslation("A tall mysterious stone.", "高而神异之石也。");
            // 献祭祭坛
            AddTranslation("Sacrificial Altar", "祀坛");
            // 一块扁平的神秘石头。
            AddTranslation("A flat mysterious stone.", "平而神异之石也。");
            // 木筏
            AddTranslation("Raft", "筏");
            // 洪水中的一块干地。
            AddTranslation("A dry patch in the flood.", "洪中燥地也。");
            // 避难所
            AddTranslation("Shelter", "庇");
            // 躲避暴风雨的避难所。
            AddTranslation("Shelter from the storm.", "避暴雨之所也。");
            // 诅咒图腾
            AddTranslation("Cursed Totem", "咒图腾");
            // 被神秘能量包围的图腾。
            AddTranslation("A totem surrounded in mysterious energy.", "神异之气环之之图腾。");
            // 我自己的衔尾蛇。
            AddTranslation("My very own Ouroboros.", "我之衔尾蛇。");
            // 木板
            AddTranslation("Wooden Board", "木板");
            // 一块普通的木板。
            AddTranslation("A regular wooden board.", "凡木板也。");
            // 鼹鼠大副
            AddTranslation("Mole Firstmate", "鼹大副");
            // 机械衔尾蛇
            AddTranslation("Ourobot", "衔尾机");
            // 活了的{0}
            AddTranslation("Living {0}", "活{0}");
        }

    }

    public class NewSpellCardToolkitMod
    {
        public static void RegisterTranslations()
        {
            // Ability
            // 攻击强化
            AddTranslation("Attack Up", "益攻");
            // 在本场战斗中提升目标单位的攻击力。
            AddTranslation("Increases the target's attack for the rest of the battle.", "益所中者之威，至战终。");
            // 攻击削弱
            AddTranslation("Attack Down", "损攻");
            // 在本场战斗中降低目标单位的攻击力。
            AddTranslation("Decreases the target's attack for the rest of the battle.", "损所中者之威，至战终。");
            // 灭世灾变
            AddTranslation("Cataclysm", "大坏");
            // 当[creature]死亡时，牌桌上所有其他卡牌也将随之毁灭。
            AddTranslation("When [creature] dies, all other cards on the boards perish as well.", "[creature]死，则局上余牌皆灭。");
            // 直接伤害
            AddTranslation("Direct Damage", "直伤");
            // 对目标造成直接伤害。
            AddTranslation("Deals damage directly to a target.", "直伤所中。");
            // 直接治疗
            AddTranslation("Direct Heal", "直疗");
            // 治疗目标单位。该效果可使目标生命值超过其初始上限。
            AddTranslation("Heals the target. This can heal the target beyond its original max health.", "疗所中者，且得逾其本命之极。");
            // 双倍抽牌
            AddTranslation("Draw Twice", "再引");
            // 当[creature]死亡时，可额外抽取两张牌加入牌组。
            AddTranslation("When [creature] dies, draw two more cards and add them to your deck.", "[creature]死，则更引二牌，纳于牌列。");
            // 夺取控制
            AddTranslation("Gain Control", "夺御");
            // 夺取目标造物的控制权。
            AddTranslation("Takes control of the targeted creature.", "夺所中之物。");
            // 赋予印记
            AddTranslation("Give Sigils", "予印");
            // 将此卡的印记赋予目标卡牌。
            AddTranslation("Gives this card's sigils to the target.", "以此牌之印予所中者。");
            // 赋予属性
            AddTranslation("Give Stats", "予数");
            // 将此卡的属性赋予目标卡牌。
            AddTranslation("Gives this card's stats to the target.", "以此牌之数予所中者。");
            // 赋予属性与印记
            AddTranslation("Give Stats and Sigils", "予数与印");
            // 将此卡的属性与印记赋予目标卡牌。
            AddTranslation("Gives this card's stats and sigils to the target.", "以此牌之数与印予所中者。");
            // 法术（全局）
            AddTranslation("Spell (Global)", "术（周）");
            // 当这张卡牌在牌桌任意位置打出时，会立即产生效果并消失。
            AddTranslation("When this card is played anywhere on the board, it will cause an immediate effect and then disappear.", "此牌无论陈于局何处，皆即时生效而后灭。");
            // 全局法术。
            AddTranslation("GLOBAL SPELL.", "周术。");
            // 法术（全局，瞬发）
            AddTranslation("Spell (Global, Instant)", "术（周，立发）");
            // 当这张卡牌打出时，会立即产生效果并消失。
            AddTranslation("When this card is played, it will cause an immediate effect and then disappear.", "此牌既陈，即生其效而灭。");
            // 瞬发全局法术。
            AddTranslation("INSTA-GLOBAL SPELL.", "立发周术。");
            // 法术（定向）
            AddTranslation("Spell (Targeted)", "术（指）");
            // 当这张卡牌打出时，它会选定并影响牌桌上的一个位置，随后消失。
            AddTranslation("When this card is played, it will target and affect a chosen space on the board and then disappear.", "此牌既陈，则择局上一位而及之，旋即自灭。");
            // 定向法术。
            AddTranslation("TARGETED SPELL.", "指术。");
            // 命令（全局）
            AddTranslation("Command (Global)", "令（周）");
            // 当这张卡牌在牌桌任意位置打出时，会立即产生效果并消失。
            AddTranslation("When this card is played anywhere on the board, it will cause an immediate effect and then disappear.", "此牌无论陈于局何处，皆即时生效而后灭。");
            // 全局命令。
            AddTranslation("GLOBAL COMMAND.", "周令。");
            // 命令（全局，瞬发）
            AddTranslation("Command (Global, Instant)", "令（周，立发）");
            // 当这张卡牌打出时，会立即产生效果并消失。
            AddTranslation("When this card is played, it will cause an immediate effect and then disappear.", "此牌既陈，即生其效而灭。");
            // 瞬发全局命令。
            AddTranslation("INSTA-GLOBAL COMMAND.", "立发周令。");
            // 命令（定向）
            AddTranslation("Command (Targeted)", "令（指）");
            // 当这张卡牌打出时，它会选定并影响牌桌上的一个位置，随后消失。
            AddTranslation("When this card is played, it will target and affect a chosen space on the board and then disappear.", "此牌既陈，则择局上一位而及之，旋即自灭。");
            // 定向命令。
            AddTranslation("TARGETED COMMAND.", "指令。");
        }

    }


    public class P03SigilariumMod
    {
        public static void RegisterTranslations()
        {
            // Card
            // 机械海胆电池
            AddTranslation("Urch1n Cell", "机海胆匣");
            // 充能！
            AddTranslation("Charge!", "充能！");
            // 升级！
            AddTranslation("Upgrade!", "升级！");
            // 电击！
            AddTranslation("Zap!", "电击！");
            // 轰爆！
            AddTranslation("Blast!", "轰爆！");
            // 防御！
            AddTranslation("Defend!", "防御！");
            // 废料堆
            AddTranslation("Junk", "废堆");
            // 机械鲑鱼
            AddTranslation("S4LM0N", "机鲑");
            // 种子
            AddTranslation("Seed", "种");

            // Ability
            // 附录12，第一节 - 额外机制{0}
            AddTranslation("APPENDIX XII, SUBSECTION I - Additional Mechanics {0}", "附录十二·第一节——别机{0}");
            // 坚盾吸收
            AddTranslation("Shield Absorption", "吸盾");
            // 当[creature]被使用时，所有造物都会失去护盾。每失去一个护盾，该造物便增加1点攻击力。
            AddTranslation("When [creature] is played, all creatures lose their shields. This creature gains 1 attack for each shield lost this way.", "[creature]既陈，诸物失其盾；每由此失一盾，此物威益一。");
            // 极速回收
            AddTranslation("Rapid Recycle", "疾回用");
            // 消耗1点能量选择你控制的另一张卡牌死亡并立即重生。每回合只能激活此能力一次。
            AddTranslation("Pay 1 Energy to choose another card you control to die and immediately respawn. You may only activate this ability once per turn.", "费一能，使汝所御别一牌死而即复生。此技每合惟一启。");
            // 超载充能
            AddTranslation("Supercharge", "亢充");
            // 消耗1点燃料：友方卡牌获得1点力量，持续至回合结束。该能力每回合只能激活一次。
            AddTranslation("Spend one fuel: friendly cards gain 1 power until the end of the turn. This ability can only be activated once per turn.", "费一油：友牌皆威益一，至合终。此技每合惟一启。");
            // 复制粘贴
            AddTranslation("Copy and Paste", "摹移");
            // [creature]的持牌人需选择其控制的两张卡牌，将第二张卡的印记替换为第一张卡的印记。
            AddTranslation("The controller of [creature] chooses two cards they control. The second card's sigils are replaced with the sigils of the first.", "[creature]之主持择其所御二牌。以后者之印，易为前者之印。");
            // 选择要复制印记的卡牌
            AddTranslation("Choose a card to copy sigils from", "择一牌以摹其印");
            // 选择要粘贴印记的卡牌
            AddTranslation("Choose a card to paste sigils onto", "择一牌以受其印");
            // 炮火轰击
            AddTranslation("Cannon Fire", "炮击");
            // 消耗1点燃料：在手牌中生成一张“轰爆！”牌。“轰爆！”具有：2点能量，是可以使目标着火的法术牌。该能力每回合只能激活一次。
            AddTranslation("Spend one fuel: Create a Blast! card in hand. Blast! is defined as a spell that costs 2 energy and sets the target on fire. This ability can only be activated once per turn.", "费一油，于手生一“轰爆！”。“轰爆！”者，费二能之术也，能然所指。此技每合惟一启。");
            // 消耗1点燃料：在手牌中生成一张“轰爆！”牌。“轰爆！”具有：2点能量，是可以使目标着火的命令牌。该能力每回合只能激活一次。
            AddTranslation("Spend one fuel: Create a Blast! card in hand. Blast! is defined as a command that costs 2 energy and sets the target on fire. This ability can only be activated once per turn.", "费一油，于手生一“轰爆！”。“轰爆！”者，费二能之令也，能然所指。此技每合惟一启。");
            // 充能储备
            AddTranslation("Recharge Reserves", "储充");
            // 消耗2点能量在手牌中生成一张“充能！”牌。“充能！”是使用时可恢复1点能量的法术牌。
            AddTranslation("Pay 2 Energy to create a Charge in your hand. Charge is defined as a spell that refills 1 Energy when played.", "费二能，于手生一“充能！”。“充能！”者，陈之则复一能之术也。");
            // 消耗2点能量在手牌中生成一张“充能！”牌。“充能！”是使用时可恢复1点能量的命令牌。
            AddTranslation("Pay 2 Energy to create a Charge in your hand. Charge is defined as a command that refills 1 Energy when played.", "费二能，于手生一“充能！”。“充能！”者，陈之则复一能之令也。");
            // 全息编织者
            AddTranslation("Holo Weaver", "幻织");
            // 每回合可在手牌中生成一张“防御！”牌。“防御！”具有：2点能量，是能为目标提供护盾的法术牌。
            AddTranslation("Once per turn, create a Defend! card in hand. Defend! is defined as a spell that costs 2 energy and gives the target a shield.", "每合一度，于手生一“防御！”。“防御！”者，费二能之术也，予所指以微铠。");
            // 每回合可在手牌中生成一张“防御！”牌。“防御！”具有：2点能量，是能为目标提供护盾的命令牌。
            AddTranslation("Once per turn, create a Defend! card in hand. Defend! is defined as a command that costs 2 energy and gives the target a shield.", "每合一度，于手生一“防御！”。“防御！”者，费二能之令也，予所指以微铠。");
            // 未来视界
            AddTranslation("Future Sight", "先见");
            // 查看牌组顶端的卡牌。你可以直接使用它。
            AddTranslation("Look at the top card of your deck. You can play it.", "视牌列上牌。汝可即陈之。");
            // 化石燃料
            AddTranslation("Fossil Fuel", "石脂");
            // 可提供1点额外能量槽。
            AddTranslation("Provides an additional energy cell.", "益一能格。");
            // 售货机
            AddTranslation("Dispenser", "予器");
            // 获得一个随机道具。
            AddTranslation("Gain a random item.", "得一偶物。");
            // 电能过载
            AddTranslation("Overcharge", "过充");
            // 消耗4点能量使该卡牌的力量+1。
            AddTranslation("Pay 4 Energy to increase the Power of this card by 1.", "费四能，益此牌威一。");
            // 超频领袖
            AddTranslation("Enrage", "怒充");
            // 消耗等同于该卡牌力量值加2点的能量，使该卡牌的力量值增加1点。
            AddTranslation("Pay Energy equal to the Power of this card plus 2 to increase the Power of this card by 1.", "费能如是牌之威加二，以益其威一。");
            // 驱动
            AddTranslation("Drive", "驱");
            // 消耗1点燃料：向该印记标注的方向移动。该能力每回合只能发动一次。
            AddTranslation("Spend one fuel: move in the direction inscribed in this sigil. This ability can only be activated once per turn.", "费一油：循此印所志而移。此技每合惟一启。");
            // 十字键
            AddTranslation("D-Pad", "十键");
            // 移动至相邻的空位
            AddTranslation("Move to an adjacent empty lane.", "移于邻虚列。");
            // 十字键左进
            AddTranslation("D-Pad Left", "左键");
            // 若左侧路线为空，则移动至该位置。
            AddTranslation("Move to the lane to the left, if it is empty.", "左列若虚，则移于彼。");
            // 十字键右进
            AddTranslation("D-Pad Right", "右键");
            // 若右侧路线为空，则移动至该位置。
            AddTranslation("Move to the lane to the right, if it is empty.", "右列若虚，则移于彼。");
            // 下潜
            AddTranslation("Submerge", "潜");
            // 消耗1点燃料：在对手回合期间潜入水下。潜水时，敌方造物将直接攻击其持有者。
            AddTranslation("Spend one fuel: submerge during the opponent's turn. While submerged, opposing creatures attack its owner directly.", "费一油：敌合则潜。既潜，则敌物直攻其主。");
            // 拖拽钩
            AddTranslation("Tow Hook", "牵钩");
            // 消耗1点燃料：将对方一个造物拖曳至你这一侧牌桌，持续到回合结束。被拖曳的造物无法被锤击。该能力每回合只能激活一次。
            AddTranslation("Spend one fuel: tow an opposing creature to your side of the board until end of turn. Creatures being towed cannot be hammered. This ability can only be activated once per turn.", "费一油：牵一敌物至汝侧，至合终。见牵者不得受槌。此技每合惟一启。");
            // 按键狂魔
            AddTranslation("Button Pusher", "叩键者");
            // 当使用[creature]时，所有可激活印记以及登场或死亡时触发的印记都会立即激活。
            AddTranslation("When [creature] is played, all activated sigils and sigils that trigger on play or on death are activated.", "[creature]既陈，凡可启之印，与陈时、死时而发之印，皆启。");
            // 寄生控制
            AddTranslation("Parasitic Control", "寄御");
            // 当使用[creature]时，所有对手卡牌都将转移至你这一侧的牌桌。
            AddTranslation("When [creature] is played, all opposing cards are moved to your side of the board.", "[creature]既陈，敌方诸牌皆移于汝侧。");
            // 能量力量
            AddTranslation("Energy Power", "能威");
            // 该印记代表的数值等于玩家本回合消耗能量的次数。
            AddTranslation("The value represented with this sigil will be equal to the number of times the player has spent energy this turn.", "此印所表之数，与玩家此合费能之次数等。");
            // 全息陷阱
            AddTranslation("Holo Trap", "幻阱");
            // 带有该印记的卡牌阵亡时，它对面的造物也会同时阵亡。你的手牌中将出现一张容器卡牌。
            AddTranslation("When a card bearing this sigil perishes, the creature opposing it perishes as well. A Vessel is created in your hand.", "负此印者死，则其对物亦死。汝手生一皿。");
            // 脆骨王
            AddTranslation("Brittle Lord", "脆主");
            // 只要[creature]存活，带有脆骨印记的卡牌都将获得不死之虫。
            AddTranslation("As long as [creature] is alive, cards with Brittle have Unkillable.", "惟[creature]生，凡有脆骨者皆得不死。");
            // 狂野冲撞
            AddTranslation("Buck Wild", "狂突");
            // 受到伤害时，此卡牌会冲入对面空位，沿途消灭一切阻挡之物。
            AddTranslation("Upon taking damage, this card will charge into the opposing slot, killing anything in its way.", "受伤则此牌突入其对位，所当者皆死。");
            // 燃烧卡槽(1)
            AddTranslation("Burning Slot (1)", "燔位（一）");
            // 这个卡槽着火了！它会在回合结束时对其中卡牌造成1点伤害。该效果持续1回合。
            AddTranslation("This slot is on fire! It deals one damage to the card in it at the end of the turn. This effect lasts one turn.", "此位焚矣！合终，处其中者受一伤。此效一合而止。");
            // 燃烧卡槽(2)
            AddTranslation("Burning Slot (2)", "燔位（二）");
            // 这个卡槽着火了！它会在回合结束时对其中卡牌造成1点伤害。该效果持续2回合。
            AddTranslation("This slot is on fire! It deals one damage to the card in it at the end of the turn. This effect lasts two turns.", "此位焚矣！合终，处其中者受一伤。此效二合而止。");
            // 燃烧卡槽(3)
            AddTranslation("Burning Slot (3)", "燔位（三）");
            // 这个卡槽着火了！它会在回合结束时对其中卡牌造成1点伤害。该效果持续3回合。
            AddTranslation("This slot is on fire! It deals one damage to the card in it at the end of the turn. This effect lasts three turns.", "此位焚矣！合终，处其中者受一伤。此效三合而止。");
            // 燃烧卡槽(4)
            AddTranslation("Burning Slot (4)", "燔位（四）");
            // 这个卡槽着火了！它会在回合结束时对其中卡牌造成1点伤害。该效果持续4回合。
            AddTranslation("This slot is on fire! It deals one damage to the card in it at the end of the turn. This effect lasts four turns.", "此位焚矣！合终，处其中者受一伤。此效四合而止。");
            // 过燃
            AddTranslation("Burnt Out", "焚尽");
            // 当[creature]死亡时，其所在位置将燃烧3回合。
            AddTranslation("When [creature] dies, it sets the land on fire for three turns.", "[creature]死，则其地焚三合。");
            // 燃烧中
            AddTranslation("on fire", "方焚");
            // 引燃
            AddTranslation("Catch Fire", "然火");
            // 当[creature]选定一个位置时，该位置将被引燃。
            AddTranslation("When [creature] targets a slot, the target is set on fire.", "[creature]所指之位皆焚。");
            // 失能退化
            AddTranslation("Transforms When Unpowered", "失能易形");
            // 若回合开始时[creature]未处于回路中，则会退化回原始形态。
            AddTranslation("If [creature] is NOT within a circuit at the beginning of the turn, it will transform back into its original form.", "合始，若[creature]不在回路中，则反其故形。");
            // 失能水袭
            AddTranslation("Waterborne When Unpowered", "失能潜袭");
            // 若[creature]不在回路中，则会在对手回合潜入水下。潜水时，敌方造物将直接攻击其持牌人。
            AddTranslation("If [creature] is NOT within a circuit it submerges itself during its opponent's turn. While submerged, opposing creatures attack its owner directly.", "若[creature]不在回路中，则敌合自潜；既潜，则敌物直攻其主。");
            // 充能短路
            AddTranslation("Short Circuit", "短路");
            // 若[creature]在回合开始时处于回路中，则会在你的手牌中生成一张“电击！”牌。“电击！”具有：2点能量，是可对任意目标造成1点伤害的法术牌。
            AddTranslation("If [creature] is within a circuit at the beginning of the turn, create a Zap! in your hand. Zap! is defined as a spell that costs 2 energy and deals 1 damage to any target.", "合始，若[creature]在回路中，则于手生一“电击！”。“电击！”者，费二能之术也，能伤所指一。");
            // 若[creature]在回合开始时处于回路中，则会在你的手牌中生成一张“电击！”牌。“电击！”具有：2点能量，是可对任意目标造成1点伤害的命令牌。
            AddTranslation("If [creature] is within a circuit at the beginning of the turn, create a Zap! in your hand. Zap! is defined as a command that costs 2 energy and deals 1 damage to any target.", "合始，若[creature]在回路中，则于手生一“电击！”。“电击！”者，费二能之令也，能伤所指一。");
            // 充能进化
            AddTranslation("Transforms When Powered", "得能易形");
            // 如[creature]在回合开始时处于回路中，则会进化为更强形态。
            AddTranslation("If [creature] is within a circuit at the beginning of the turn, it will transform into a stronger form.", "合始，若[creature]在回路中，则易为益强之形。");
            // 充能樱桃炸
            AddTranslation("Explodonate When Powered", "得能殉爆");
            // 如[creature]处在回路中，则会引爆自身并对周围五个相邻位置各造成10点伤害。
            AddTranslation("If [creature] is within a circuit, it detonates itself and deals 10 damage to all five adjacent spaces.", "若[creature]在回路中，则自爆，周五邻位各受十伤。");
            // 充能金属风宝
            AddTranslation("Mental Gemnastics When Powered", "得能玉智");
            // 当使用[creature]时，若其处于回路中，持牌人可抽取等同于己方牌桌上玛珂牌数量的手牌。
            AddTranslation("When [creature] is played, if it is within a circuit, its owner draw cards equal to the number of Mox Cards on their side of the game board.", "[creature]既陈，若在回路中，则其主引牌，如其侧局上玛珂牌之数。");
            // 充能陷阱
            AddTranslation("Trap When Powered", "得能阱");
            // 如带有该印记的卡牌阵亡时处在回路中，它对面的造物也会同时阵亡。你的手牌中将出现一张容器卡牌。
            AddTranslation("When a card bearing this sigil perishes while in a circuit, the creature opposing it perishes as well. A Vessel is created in your hand.", "负此印者在回路中而死，则其对物亦死。汝手生一皿。");
            // 充能不死
            AddTranslation("Unkillable When Powered", "得能不死");
            // 如[creature]阵亡时处在回路中，则会在你的手牌中生成一张同样的牌。
            AddTranslation("If [creature] is within a circuit when it perishes, a copy of it is created in your hand.", "若[creature]死时在回路中，则汝手生其副。");
            // 接合管道
            AddTranslation("Splice Conduit", "接渠");
            // 如果[creature]构成完整回路，该回路中的所有卡牌都会向其靠拢，并在可能时与之接合。
            AddTranslation("If [creature] completes a circuit, all cards within that circuit are moved towards it, splicing with it if possible.", "若[creature]成一回路，则回路中诸牌皆向之移；可接则接。");
            // 臭臭管道
            AddTranslation("Stinky Conduit", "恶臭渠");
            // 处在由[creature]构成的回路中的卡牌将获得臭臭。
            AddTranslation("Cards within a circuit completed by [creature] have Stinky.", "在[creature]所成回路中之牌，皆得恶臭。");
            // 空袭管道
            AddTranslation("Airborne Conduit", "翔袭渠");
            // 处在由[creature]构成的回路中的卡牌获得空袭。
            AddTranslation("Cards within a circuit completed by [creature] have Airborne.", "在[creature]所成回路中之牌，皆得翔袭。");
            // 燃气管道
            AddTranslation("Gas Conduit", "燃渠");
            // 处在由[creature]构成的回路中的卡牌会获得火焰打击和过燃效果。
            AddTranslation("Cards within a circuit completed by [creature] have Fire Strike and Burnt Out.", "在[creature]所成回路中之牌，皆得火击与焚尽。");
            // 璀璨管道
            AddTranslation("Bedazzling Conduit", "炫渠");
            // 处在由[creature]构成的回路中的卡牌将被宝石化。
            AddTranslation("Cards within a circuit completed by [creature] are Gemified.", "在[creature]所成回路中之牌，皆玉化。");
            // 静电传导
            AddTranslation("Static Electricity", "静电");
            // [creature]会使所有友方卡牌表现得如同处于完整回路中。
            AddTranslation("[creature] will cause all friendly cards to behave as if they are part of a completed conduit.", "[creature]使我方诸牌皆若处于成回路中。");
            // 燃气发电机
            AddTranslation("Gas Generator", "燃气机");
            // 只要燃料充足，[creature]就能让所有友方卡牌表现得如同处于完整回路中。
            AddTranslation("As long as it has fuel, [creature] will cause all friendly cards to behave as if they are part of a completed conduit.", "惟其有油，[creature]使我方诸牌皆若处于成回路中。");
            // 管道守护者
            AddTranslation("Conduit Protector", "护渠者");
            // 当[creature]处于完整回路中时，原本会作用于管道的伤害将转由该造物承担。
            AddTranslation("When [creature] is within a completed circuit, damage that would be dealt to the conduits is dealt to this creature instead.", "若[creature]在成回路中，则本加诸渠之伤，皆转加于此物。");
            // 死亡字节
            AddTranslation("Dead Byte", "死节");
            // 带有该印记的卡牌阵亡时，你会受到1点伤害。
            AddTranslation("When a card bearing this sigil perishes, take 1 damage.", "负此印者死，则汝受一伤。");
            // 双重冲刺
            AddTranslation("Double Sprinter", "再驰");
            // 持牌人回合结束时，带有该印记的卡牌会按照印记标记的方向连续移动两次。
            AddTranslation("At the end of the owner's turn, a card bearing this sigil will move in the direction inscribed in the sigil twice.", "持牌者合终，负此印者循印所志而移二。");
            // 脆骨召唤师
            AddTranslation("Brittle Summoner", "召脆");
            // 使用[creature]时，你的手牌中会随机生成一张脆骨卡牌。
            AddTranslation("When [creature] is played, a random brittle card is created in your hand.", "[creature]既陈，汝手生一偶脆骨牌。");
            // 迭代
            AddTranslation("Iterate", "迭出");
            // 使用[creature]时，你的手牌中将出现一张费用不同的复制卡牌。
            AddTranslation("When [creature] is played, a copy of it with a different cost is created in your hand.", "[creature]既陈，汝手生其副一牌，惟其费异。");
            // 机械师
            AddTranslation("Tinkerer", "机工");
            // 当使用[creature]时，随机生成三张法术牌。
            AddTranslation("When [creature] is played, create three spell cards selected at random.", "[creature]既陈，偶生三术牌。");
            // 当使用[creature]时，随机生成三张命令牌。
            AddTranslation("When [creature] is played, create three command cards selected at random.", "[creature]既陈，偶生三令牌。");
            // 相位炮就绪
            AddTranslation("Phasers Ready", "相炮备");
            // 使用[creature]时，在手牌中生成两张“电击！”牌。“电击！”具有：2点能量，是对任意目标造成1点伤害的法术牌。
            AddTranslation("When [creature] is played, create two Zap! cards in hand. Zap! is defined as a spell that costs 2 energy and deals 1 damage to any target.", "[creature]既陈，于手生二“电击！”。“电击！”者，费二能之术也，能伤所指一。");
            // 使用[creature]时，在手牌中生成两张“电击！”牌。“电击！”具有：2点能量，是对任意目标造成1点伤害的命令牌。
            AddTranslation("When [creature] is played, create two Zap! cards in hand. Zap! is defined as a command that costs 2 energy and deals 1 damage to any target.", "[creature]既陈，于手生二“电击！”。“电击！”者，费二能之令也，能伤所指一。");
            // 作战研习
            AddTranslation("Combat Research", "战研");
            // 当[creature]造成伤害时，在手牌中生成一张强制升级牌。强制升级具有：2点能量，是可使任意目标升级为新版本的法术牌。
            AddTranslation("When [creature] deals damage, create a Forced Upgrade card in hand. Forced Upgrade is defined as a spell that costs 2 energy and caused any target to upgrade to a new version.", "[creature]致伤，则于手生一“强升”。“强升”者，费二能之术也，能使所指即升为新形。");
            // 当[creature]造成伤害时，在手牌中生成一张强制升级牌。强制升级具有：2点能量，是可使任意目标升级为新版本的命令牌。
            AddTranslation("When [creature] deals damage, create a Forced Upgrade card in hand. Forced Upgrade is defined as a command that costs 2 energy and caused any target to upgrade to a new version.", "[creature]致伤，则于手生一“强升”。“强升”者，费二能之令也，能使所指即升为新形。");
            // 电力制导
            AddTranslation("Electric", "旁电");
            // 当[creature]发动攻击时，会对目标相邻的卡牌造成一半伤害。
            AddTranslation("When [creature] declares an attack, it will deal half the damage to cards adjacent to the target.", "[creature]既宣攻，则并以半伤及其所指左右。");
            // 绿色玛珂增益
            AddTranslation("Green Mox Buff", "绿玛珂益");
            // 当使用[creature]时，每打出一张绿色玛珂，该造物便获得2点生命值。
            AddTranslation("When [creature] is played, it gains two health for each Green Mox its owner controls.", "[creature]既陈，其主持每御一绿玛珂，此物命益二。");
            // 绿宝石祝福
            AddTranslation("Emerald Blessing", "绿玉福");
            // [creature]为你打出的所有造物提供+2点生命值。
            AddTranslation("[creature] provides +2 Health to all creatures you control.", "[creature]使汝所御诸物皆命益二。");
            // 绿宝石碎片
            AddTranslation("Emerald Shard", "绿玉屑");
            // 当[creature]即将受到攻击时，会在其位置生成一颗绿宝石玛珂，同时带有该印记的卡牌会向右移动。
            AddTranslation("When [creature] would be struck, an Emerald Mox is created in its place and a card bearing this sigil moves to the right.", "[creature]将受击，则其处生一绿玉玛珂，而负此印之牌右移。");
            // 坚盾予者
            AddTranslation("Armor Giver", "予铠者");
            // 当[creature]入场时，所有敌方卡牌获得纳米铠甲。
            AddTranslation("When [creature] enters, all opposing cards gain Nano Armor.", "[creature]既入，敌方诸牌皆得微铠。");
            // 能量虹吸
            AddTranslation("Energy Siphon", "吸能");
            // 当你拥有的其他卡牌在战斗中死亡时，[creature]会在你的手牌中生成一张“充能！”牌。“充能！”是使用时可恢复1点能量的法术牌。
            AddTranslation("Whenever another card you own dies in combat, [creature] creates a Charge in your hand. Charge is a spell that refills 1 Energy when played.", "凡汝他牌战死，[creature]于汝手生一“充能！”。“充能！”者，陈之则复一能之术也。");
            // 当你拥有的其他卡牌在战斗中死亡时，[creature]会在你的手牌中生成一张“充能！”牌。“充能！”是使用时可恢复1点能量的命令牌。
            AddTranslation("Whenever another card you own dies in combat, [creature] creates a Charge in your hand. Charge is a command that refills 1 Energy when played.", "凡汝他牌战死，[creature]于汝手生一“充能！”。“充能！”者，陈之则复一能之令也。");
            // 樱桃炸
            AddTranslation("Explodonate", "殉爆");
            // 当[creature]死亡时，会爆炸并对周围五个相邻位置各造成10点伤害。
            AddTranslation("When [creature] dies, it explodes and deals 10 damage to all five adjacent slots.", "[creature]死，则爆，周五邻位各受十伤。");
            // 火焰打击
            AddTranslation("Fire Strike", "火击");
            // 当[creature]攻击时，会使目标位置燃烧3回合。
            AddTranslation("When [creature] attacks, it sets the target space on fire for three turns.", "[creature]攻，则所指之位焚三合。");
            // 燃料火击
            AddTranslation("Fire Strike When Fueled", "得油火击");
            // 当[creature]攻击时若处于填充燃料状态，将消耗1点燃料使目标区域燃烧3回合。
            AddTranslation("When [creature] attacks, if it is fueled, it consumes one fuel to set the target space on fire for three turns.", "[creature]攻，若有油，则耗一油，使所指之位焚三合。");
            // 煽风点火
            AddTranslation("Flame Stoker", "鼓焰");
            // 当[creature]在场时，由你点燃的所有火焰都会更加强力，持续时间延长一回合。
            AddTranslation("While [creature] is on board, all fires you start will be stronger, causing them to last one turn longer.", "[creature]在局，则凡汝所然之火皆益炽，多延一合。");
            // 抛掷
            AddTranslation("Fling", "掷");
            // 当[creature]被使用时，若曾献祭一张或多张卡牌来使用它，[creature]将对玩家选择的一张卡牌造成等同于所有被献祭卡牌攻击力总和的伤害。
            AddTranslation("When [creature] is played, if one or more cards was sacrificed to play it, [creature] deals damage to a card of the player's choice equal to the total attack value of all sacrificed cards.", "[creature]既陈，若尝以一牌以上祀之，则对玩家所择一牌，伤如所祀诸牌威之总。");
            // 强制升级
            AddTranslation("Upgrade", "强升");
            // 当[creature]选定一个位置时，该位置上的单位会立即升级为更强版本。
            AddTranslation("When [creature] targets a slot, the target is immediately upgraded to a stronger version of itself.", "[creature]所指之位，即升为益强之形。");
            // 献血装置
            AddTranslation("Blood Donation", "输血");
            // 只要[creature]存活，所有友方卡牌，就算它们通常不可被献祭，也均可用于支付血量费用。
            AddTranslation("As long as [creature] is alive, all friendly cards can be sacrificed to pay blood costs even if they normally could not.", "惟[creature]生，我方诸牌纵素不可祀，今亦可祀以当血价。");
            // 磐石之赠
            AddTranslation("Stone Giver", "予磐");
            // 只要[creature]存活，所有友方卡牌都将获得磐石之身。
            AddTranslation("As long as [creature] is alive, all friendly cards are Made of Stone", "惟[creature]生，我方诸牌皆为磐身。");
            // 风尘之赠
            AddTranslation("Dust Giver", "予尘");
            // 只要[creature]存活，所有友方卡牌都会获得魔法粉尘。
            AddTranslation("As long as [creature] is alive, all friendly cards have Magic Dust.", "惟[creature]生，我方诸牌皆得灵尘。");
            // 煤炭滚轮
            AddTranslation("Coal Roller", "煤轮");
            // 只要[creature]存活，所有拥有燃料的友方卡牌都会获得臭臭。
            AddTranslation("As long as [creature] is alive, all friendly cards which have fuel are Stinky.", "惟[creature]生，我方有油诸牌皆得恶臭。");
            // 宝石点火器
            AddTranslation("Gem Ignition", "玉燃");
            // 只要[creature]存活，所有友方宝石获得+1点力量、火焰打击、脆骨与过燃效果。
            AddTranslation("As long as [creature] is alive, all friendly gems have +1 Power, Flame Strike, Brittle, and Burnt Out.", "惟[creature]生，我方诸玉皆威益一，兼得火击、脆骨、焚尽。");
            // 燃料打击
            AddTranslation("Fuel Strike", "油击");
            // [creature]每次攻击需消耗1点燃料，且仅在有燃料时才能攻击。
            AddTranslation("[creature] consumes one fuel to attack and can only attack if it has fuel.", "[creature]攻则耗一油；无油则不能攻。");
            // 该卡牌带有外部燃料源，可为它的一个或多个印记提供能量。当燃料耗尽时，这些印记将停止运作。
            AddTranslation("This card carries an external fuel source which powers one or more of its sigils. When a card's fuel tank empties, those sigils cease to function.", "此牌负外油之源，以行一印或数印。油既竭，则诸印皆废。");
            // 燃料
            AddTranslation("Fuel", "油");
            // 燃料护盾
            AddTranslation("Fuel Shield", "油盾");
            // 只要[creature]还有燃料，受到伤害时会优先消耗燃料而非生命值。
            AddTranslation("As long as [creature] has fuel, it takes damage by losing fuel instead of health.", "惟[creature]有油，受伤则先耗其油，不损其命。");
            // 燃料虹吸
            AddTranslation("Fuel Siphon", "吸油");
            // 当[creature]直接对对手造成伤害时，获得等量燃料。
            AddTranslation("Whenever [creature] deals damage directly to the opponent, it gains that much fuel.", "[creature]直伤敌，则得油如其伤。");
            // 血液满溢
            AddTranslation("Full of Blood", "盈血");
            // [creature]可被献祭以支付血量费用。
            AddTranslation("[creature] can be sacrificed to pay blood costs.", "[creature]可见祀以当血价。");
            // 燃油满溢
            AddTranslation("Full of Oil", "盈油");
            // 当[creature]死亡时，会为它两侧及对面的每张卡牌增加3点生命值。
            AddTranslation("When [creature] dies, it adds 3 health to each card on either side and across from it.", "[creature]死，则其两旁与其对之诸牌各命益三。");
            // 满载
            AddTranslation("Fully Loaded", "满载");
            // [creature]死亡时，会在其所在列留下永久的+1攻击力加成。
            AddTranslation("When [creature] dies, it leaves a permanent +1 attack bonus in the lane it occupied.", "[creature]死，则其所居之列遗永久益威一之效。");
            // 该卡槽的卡牌将获得+1攻击力。
            AddTranslation("The card in this slot has its power increased by one.", "此位之牌，威益一。");
            // 防御
            AddTranslation("Defend", "御");
            // 当[creature]选定一个位置时，目标将获得纳米铠甲。
            AddTranslation("When [creature] targets a slot, the target gains Nano Armor.", "[creature]所指之位，受微铠。");
            // 蓝色玛珂之赠
            AddTranslation("Blue Mox Gift", "蓝玛珂之赠");
            // [creature]阵亡时，若你打出了蓝色玛珂，则获得一张随机卡牌。
            AddTranslation("When [creature] perishes, if you control an Blue Mox, gain a random card.", "[creature]死，若汝御蓝玛珂，则得一偶牌。");
            // 蓝色玛珂劫掠
            AddTranslation("Blue Mox Looter", "蓝玛珂掠");
            // 当[creature]直接造成伤害时，若你打出了蓝色玛珂，每造成1点伤害即可抽一张牌。
            AddTranslation("When [creature] deals damage directly, if you control a Blue Mox, draw a card for each damage dealt.", "[creature]直伤，若汝御蓝玛珂，则每伤一，引一牌。");
            // 纯蓝主义
            AddTranslation("Purist With Blue", "蓝纯");
            // 若[creature]的持牌人打出有一张蓝色玛珂牌，则与[creature]对战的卡牌将失去所有印记。
            AddTranslation("If the owner of [creature] controls a Blue Mox, cards opposing [creature] have their sigils removed.", "若[creature]之主持有蓝玛珂，则其对牌失诸印。");
            // 无绿生厌
            AddTranslation("Annoying Without Green", "无绿则可厌");
            // 若[creature]的持牌人未打出绿宝石，则与之对阵的造物获得1点力量。
            AddTranslation("The creature opposing [creature] gains 1 power unless the owner of [creature] also controls a Green Mox.", "若[creature]之主持无绿玛珂，则其对物威益一。");
            // 绿色玛珂之赠
            AddTranslation("Green Mox Gift", "绿玛珂之赠");
            // [creature]阵亡时，若你打出了绿色玛珂，则获得一张随机卡牌。
            AddTranslation("When [creature] perishes, if you control a Green Mox, gain a random card.", "[creature]死，若汝御绿玛珂，则得一偶牌。");
            // 无橙即碎
            AddTranslation("Brittle Without Orange", "无橙则脆");
            // 攻击之后，若持牌人未打出橙色玛珂，[creature]会自毁。
            AddTranslation("After attacking, [creature] will perish if its owner does not control an Orange Mox.", "攻后，若其主持无橙玛珂，则[creature]死。");
            // 橙色玛珂空袭
            AddTranslation("Orange Mox Airborne", "橙玛珂翔袭");
            // 若你打出了橙色玛珂，[creature]将无视对面卡牌直接攻击对手。
            AddTranslation("If you control an Orange Mox, [creature] will ignore opposing cards and strike an opponent directly.", "若汝御橙玛珂，则[creature]无视其对牌，直击其主。");
            // 橙色玛珂打印机
            AddTranslation("Orange Mox Printer", "橙玛珂印机");
            // 若你打出了橙色玛珂，[creature]将在每回合开始时从副牌组抽一张牌。
            AddTranslation("If you control an Orange Mox, [creature] will draw a card from your side deck at the start of every turn.", "若汝御橙玛珂，则[creature]每合始，自副牌列引一牌。");
            // 宝石打击
            AddTranslation("Gem Strike", "玉击");
            // [creature]会根据持牌人打出的宝石提供器数量进行多次攻击。
            AddTranslation("[creature] attacks once for each gem provider its owner controls.", "[creature]每其主持所御一供玉者，则攻一次。");
            // 绿宝石力量
            AddTranslation("Emerald Power", "绿玉威");
            // 该印记代表的数值等于持牌人控制的绿宝石数量。
            AddTranslation("The value represented with this sigil will be equal to the number of green gems its owner controls.", "此印所表之数，与其主持所御绿玉之数等。");
            // 跑赢
            AddTranslation("Hopper", "跃");
            // 每回合结束时，[creature]会移动到持牌人指定的空位。
            AddTranslation("At the end of each turn, [creature] moves to an empty space of its owner's choosing.", "每合终，[creature]移于其主持所择之虚位。");
            // 克拉肯易形
            AddTranslation("Kraken Transformer", "克拉肯易形");
            // 在你的回合开始时，[creature]会在当前状态和克拉肯状态间切换一次。
            AddTranslation("At the beginning of your turn, [creature] will transform to, or from, Kraken mode.", "汝合始，[creature]一变为克拉肯之形，或反之。");
            // 恼人传花
            AddTranslation("Annoying Latch", "可厌遗契");
            // [creature]阵亡时，其持牌人需选定下一个继承惹人生厌印记的造物。
            AddTranslation("When [creature] perishes, its owner chooses a creature to gain the Annoying sigil.", "[creature]死，则其主持择一物，受可厌印契。");
            // 死亡传花
            AddTranslation("Death Latch", "死遗契");
            // [creature]将在回合结束时死亡。当[creature]阵亡时，其持牌人需选定下一个继承该印记的造物。此过程将循环往复。
            AddTranslation("[creature] will die at the end of the turn. When [creature] perishes, its owner chooses a creature to gain this sigil. This will repeat.", "[creature]将于合终死。其死，则其主持择一物，受此印契；如是循环。");
            // 首印传花
            AddTranslation("First Latch", "首印遗契");
            // [creature]阵亡时，其持牌人需选定下一个继承该卡牌首个印记的造物。
            AddTranslation("When [creature] perishes, its owner chooses a creature to gain the first sigil this card has.", "[creature]死，则其主持择一物，受此牌之首印。");
            // 空袭传花
            AddTranslation("Airborne Latch", "翔袭遗契");
            // [creature]阵亡时，其持牌人需选定下一个继承空袭印记的造物。
            AddTranslation("When [creature] perishes, its owner chooses a creature to gain the Airborne sigil.", "[creature]死，则其主持择一物，受翔袭印契。");
            // 管道传花
            AddTranslation("Conduit Latch", "虚渠遗契");
            // [creature]阵亡时，其持牌人需选定下一个继承空无管道印记的造物。
            AddTranslation("When [creature] perishes, its owner chooses a creature to gain the Null Conduit sigil.", "[creature]死，则其主持择一物，受虚渠印契。");
            // 冲撞传花
            AddTranslation("Rampage Latch", "横冲遗契");
            // [creature]阵亡时，其持牌人需选定下一个继承横冲直撞印记的造物。目标获得印记时将立即发动一次冲撞攻击。
            AddTranslation("When [creature] perishes, its owner chooses a creature to gain the Rampager sigil. The target will immediately rampage once when the latch is applied.", "[creature]死，则其主持择一物，受横冲印契。受之时，即先横冲一度。");
            // 臭臭传花
            AddTranslation("Stinky Latch", "恶臭遗契");
            // [creature]阵亡时，其持牌人需选定下一个继承臭臭印记的造物。
            AddTranslation("When [creature] perishes, its owner chooses a creature to gain the Stinky sigil.", "[creature]死，则其主持择一物，受恶臭印契。");
            // 交换传花
            AddTranslation("Swapper Latch", "易数遗契");
            // [creature]阵亡时，其持牌人需选定下一个继承交换器印记的造物。目标获得印记时将立即触发一次属性交换。
            AddTranslation("When [creature] perishes, its owner chooses a creature to gain the Swapper sigil. The target will immediately swap stats once when the latch is applied.", "[creature]死，则其主持择一物，受易数印契。受之时，即一易其数。");
            // 战利品箱
            AddTranslation("Lootbox", "掠匣");
            // 当[creature]击杀一张卡牌时，你的手牌中会随机生成一张卡牌。
            AddTranslation("Whenever [creature] kills a card, a random card is created in your hand.", "凡[creature]杀一牌，汝手生一偶牌。");
            // 生死与共
            AddTranslation("Synchronized Fate", "同命");
            // 当[creature]死亡时，你将输掉游戏。
            AddTranslation("When [creature] dies, you lose the game.", "[creature]死，则汝败。");
            // 魔法粉尘
            AddTranslation("Magic Dust", "灵尘");
            // 当[creature]死亡时，会在牌桌上留下一颗宝石。之后放置在该位置的卡牌都会提供相同类型的宝石。
            AddTranslation("When [creature] dies, it leaves one of its gems behind on the board. Any future cards in that space will provide those gems.", "[creature]死，则遗其一玉于局上。后陈于其位者，皆供其同类之玉。");
            // 蓝色玛珂卡槽
            AddTranslation("Blue Mox Slot", "蓝玛珂位");
            // 放置在该卡槽的卡牌会提供蓝色玛珂。
            AddTranslation("The card in this slot will provide a Blue Mox.", "处此位之牌，供蓝玛珂。");
            // 橙色玛珂卡槽
            AddTranslation("Orange Mox Slot", "橙玛珂位");
            // 放置在该卡槽的卡牌会提供橙色玛珂。
            AddTranslation("The card in this slot will provide an Orange Mox.", "处此位之牌，供橙玛珂。");
            // 绿色玛珂卡槽
            AddTranslation("Green Mox Slot", "绿玛珂位");
            // 放置在该卡槽的卡牌会提供绿色玛珂。
            AddTranslation("The card in this slot will provide a Green Mox.", "处此位之牌，供绿玛珂。");
            // 至尊玛珂卡槽
            AddTranslation("Great Mox Slot", "至尊玛珂位");
            // 放置在该卡槽的卡牌会同时提供三种玛珂。
            AddTranslation("The card in this slot will provide all three moxen.", "处此位之牌，并供三玛珂。");
            // 探矿者
            AddTranslation("Miner", "矿夫");
            // [creature]会在对手回合时潜入地下。潜地期间，敌方造物将直接攻击其持牌人。当它重返地面时，会为持牌人创造一张新卡牌。
            AddTranslation("[creature] buries itself during its opponent's turn. While buried, opposing creatures attack its owner directly. When it comes back up, it creates a card in its owner's hand.", "[creature]敌合则潜地。既潜，则敌物直攻其主。及其复出，则为其主生一牌于手。");
            // 橡皮图章
            AddTranslation("Rubber Stamp", "印模");
            // 当你使用[creature]时，它会变成你选择的另一个造物的复制品。若该造物具有其他能力，这些能力也将被转移（最多4个）。
            AddTranslation("Whenever you play [creature], it becomes a copy of another creature of your choosing. If this creature has other abilities, those abilities will be transferred (up to the maximum of 4).", "汝每陈[creature]，则其化为汝所择他物之副。若彼物别有诸技，则其技亦从之（至多四）。");
            // 导弹发射器
            AddTranslation("Launch Missile", "发弹");
            // [creature]可跳过本回合攻击以发射导弹，导弹将在下回合落地并对相邻位置造成溅射伤害。弹药有限，请谨慎使用。
            AddTranslation("[creature] can skip its attack this turn to launch a missile that lands on the next turn, splashing damage to adjacent spaces. Use carefully - ammo is limited.", "[creature]此合可舍其攻，以发一弹；后合乃坠，并旁溅其伤。慎用之，弹有限。");
            // 自我发射器
            AddTranslation("Launch Self", "自发");
            // [creature]可牺牲自己发射一枚导弹，导弹将在下回合落地并对相邻位置造成溅射伤害。
            AddTranslation("[creature] can sacrifice itself to launch a missile that lands on the next turn, splashing damage to adjacent spaces.", "[creature]可自祀以发一弹；后合乃坠，并旁溅其伤。");
            // 易燃
            AddTranslation("Flammable", "易燔");
            // 当[creature]死亡时，它会爆炸并使相邻位置燃烧3回合。
            AddTranslation("When [creature] dies, it detonates and sets adjacent spaces on fire for three turns.", "[creature]死，则爆，且其邻位焚三合。");
            // 纵火狂
            AddTranslation("Arsonist", "纵火");
            // 当使用[creature]时，牌桌上所有位置将燃烧4个回合。
            AddTranslation("When [creature] is played, it sets all spaces on the board on fire for four turns.", "[creature]既陈，局上诸位皆焚四合。");
            // 加油站
            AddTranslation("Refueler", "补油者");
            // 只要燃料充足，[creature]会主动靠近你打出的其他需燃料造物。每回合为相邻造物补充燃料。
            AddTranslation("As long as it has fuel, [creature] will attempt to move beside any creatures you play that also use fuel. Each turn, [creature] will refuel adjacent creatures.", "惟其有油，[creature]将趋汝所陈他有油之物旁。每合为邻物补油。");
            // 死灰复燃
            AddTranslation("Second Chance", "再起");
            // 当友方非脆骨造物死亡时，若[creature]在战场上，将在其位置生成一个1/1的骷髅。
            AddTranslation("Whenever a friendly non-Brittle creature dies, if [creature] is on the battlefield, a 1/1 skeleton will be created in its place.", "凡我方非脆骨之物死，若[creature]在场，则其处生一一一枯骨。");
            // 额外能量管道
            AddTranslation("Bonus Energy Conduit", "余能渠");
            // 如果[creature]参与构成一条完整回路，那么它会提供一个等同于玩家当前最大能量值的能量储备。
            AddTranslation("If [creature] is part of a completed circuit, it provides a reserve of energy equal to the player's current maximum energy.", "若[creature]在成回路中，则所供之余能，如玩家今之能极。");
            // 外骨骼超频
            AddTranslation("Skeleclocked", "骨机化");
            // 当[creature]死亡时，它会永久变为具有相同能力的机械外骨骼。若[creature]带有不死之虫则不受影响。
            AddTranslation("When [creature] dies, it permanently becomes an Exeskeleton with the same abilities. If [creature] has Unkillable, it will be unaffected.", "[creature]死，则永久化为一外骨骼，而其诸技如故。若[creature]有不死，则不与。");
            // 过热
            AddTranslation("Overheat", "亢热");
            // 当战局对你有利时，[creature]损失1点力量。当战局不利时，[creature]获得1点力量。
            AddTranslation("When the scales are in your favor, [creature] loses 1 power. When the scales aren't in your favor, [creature] gains 1 power.", "衡若利汝，[creature]威损一；不利，则威益一。");
            // 能量流失
            AddTranslation("Power Drain", "耗能");
            // [creature]每回合会消耗其持牌人所有的可用能量。
            AddTranslation("[creature] consumes all of its owner's available energy each turn.", "[creature]每合尽耗其主持可用之能。");
            // 纯粹主义
            AddTranslation("Purist", "粹者");
            // 与[creature]对位的卡牌将失去所有印记。
            AddTranslation("Cards opposing [creature] have their sigils removed.", "与[creature]对之牌，失诸印。");
            // 该效果会实际移除能力。你本不该在卡牌上看到这个能力！！！
            AddTranslation("This handles actually removing abilities. You should never see this ability on a card!!!", "此者实用于去诸技。汝本不当于牌上见之！！！");
            // 赏金猎人
            AddTranslation("Bounty Hunter", "购捕者");
            // 当被抽到时，[creature]会随机变成一名赏金猎人。
            AddTranslation("When drawn, [creature] will turn into a random bounty hunter.", "既引，[creature]随机化为一购捕者。");
            // 来Nerf这招！
            AddTranslation("Nerf This!", "削此！");
            // 当[creature]被抽到时，会随机获得一个负面印记。
            AddTranslation("When [creature] is drawn, it gains a randomly selected negative ability.", "既引，[creature]得一偶负印。");
            // 无形神物
            AddTranslation("Apotheosis", "登神");
            // 当[creature]被抽到时，会随机获得一项稀有能力。
            AddTranslation("When [creature] is drawn, it gains a randomly selected rare ability.", "既引，[creature]得一偶稀技。");
            // 蓄势
            AddTranslation("Recharge", "复能");
            // 当使用[creature]时，将恢复1点能量（不超过玩家能量上限）。
            AddTranslation("When [creature] is played, one energy will be refilled (up to the player's maximum energy)", "[creature]既陈，复一能（至玩家之能极）。");
            // 闹钟机器人
            AddTranslation("Alarm Clock", "报时机");
            // 该印记当前指向的造物将获得+1点力量。闹钟会在玩家回合开始时旋转方向。
            AddTranslation("The creature that this sigil is pointing to will gain +1 attack. The clock will turn at the beginning of the player's turn.", "此印所指之物威益一。玩家合始，此钟自转。");
            // 红宝石祝福
            AddTranslation("Ruby Blessing", "红玉福");
            // [creature]为你打出的所有造物提供+1力量。
            AddTranslation("[creature] provides +1 Attack to all creatures you control.", "[creature]使汝所御诸物皆威益一。");
            // 橙色玛珂战士
            AddTranslation("Orange Mox Warrior", "橙玛珂武者");
            // 当使用[creature]时，它会攻击所有与持牌人打出的橙玛珂提供者相对的敌方卡牌。
            AddTranslation("When [creature] is played, it attacks all enemy cards opposite Orange Mox providers its owner controls.", "[creature]既陈，则攻诸与其主持所御橙玛珂供者相对之敌牌。");
            // 轰然炸裂
            AddTranslation("Burst", "爆");
            // 为召唤[creature]而献祭的卡牌会爆炸，对每张相邻卡牌造成10点伤害。
            AddTranslation("Cards sacrificed to pay for [creature] explode, dealing 10 damage to each adjacent card.", "为陈[creature]所祀之牌皆爆，各伤邻牌十。");
            // 宝石吞噬者
            AddTranslation("Gem Consumer", "噬玉者");
            // 使用[creature]时，持牌人侧牌桌上所有宝石容器均会被献祭。
            AddTranslation("When [creature] is played, all gem vessels on its owner's side of the board are sacrificed.", "[creature]既陈，其主持之侧局上诸玉皿皆见祀。");
            // 奔涌传花
            AddTranslation("Emergence Latch", "涌遗契");
            // 当为[creature]献祭的卡牌死亡时，其持牌人需选定一张卡牌继承它们的首个印记。
            AddTranslation("When cards sacrificed to pay for [creature] die, their owner chooses a card to gain their first sigil.", "为陈[creature]而祀之牌既死，则其主持择一牌，受其首印。");
            // 惊悚蜕变
            AddTranslation("Macabre Growth", "凶长");
            // [creature]将获得所有被献祭卡牌的攻击力和生命值。
            AddTranslation("[creature] gains the attack and health of all cards sacrificed to play it.", "[creature]得诸祀牌之威与命。");
            // 分崩离析
            AddTranslation("Shatter", "碎");
            // 为支付[creature]的费用而献祭的卡牌死亡时将掉落4根骨头而非1根。
            AddTranslation("Cards sacrificed to pay for [creature] drop 4 bones instead of 1 when they die.", "为陈[creature]所祀之牌死，则落骨四，不止一。");
            // 内脏祭品
            AddTranslation("Guts Sacrifice", "腑祀");
            // 为支付[creature]的费用而献祭的卡牌死亡时，会在对面位置留下黏液。位于黏液位置的卡牌减少1点力量。
            AddTranslation("Cards sacrificed to pay for [creature] slime the opposing slot when they die. Cards in slimed slots have one less power.", "为偿[creature]之费而祀之牌既死，则涂其对位以涎。处涎位者威减一。");
            // 蓝色玛珂充能器
            AddTranslation("Blue Mox Charger", "蓝玛珂充者");
            // 当使用[creature]时，持牌人每打出一张蓝宝石玛珂，就会在手牌中生成一张“充能！”牌。“充能！”是使用时可恢复1点能量的法术牌。
            AddTranslation("When [creature] is played, it creates a Charge in your hand for each Blue Mox its owner controls. Charge is a spell that refills 1 Energy when played.", "[creature]既陈，其主持每御一蓝玛珂，则于手生一“充能！”。“充能！”者，陈之则复一能之术也。");
            // 当使用[creature]时，持牌人每打出一张蓝宝石玛珂，就会在手牌中生成一张“充能！”牌。“充能！”是使用时可恢复1点能量的命令牌。
            AddTranslation("When [creature] is played, it creates a Charge in your hand for each Blue Mox its owner controls. Charge is a command that refills 1 Energy when played.", "[creature]既陈，其主持每御一蓝玛珂，则于手生一“充能！”。“充能！”者，陈之则复一能之令也。");
            // 蓝宝石祝福
            AddTranslation("Sapphire Blessing", "蓝玉福");
            // [creature]可使你手牌中所有卡牌的费用降低1点。
            AddTranslation("[creature] reduces the cost of all cards in your hand by 1.", "[creature]使汝手中诸牌之费皆减一。");
            // 废料倾卸机
            AddTranslation("Scrap Dumper", "倾废者");
            // 使用带有该印记的卡牌时，对面位置会出现一个损坏的机器人。
            AddTranslation("When a card bearing this sigil is played, a broken bot is played on the opposing space.", "负此印者既陈，则其对位生一坏机。");
            // 废物利用
            AddTranslation("Scrap Salvage", "废取");
            // 使用[creature]时，将献祭卡牌的总成本转化为资源：每点能量生成1张“充能！”卡牌，每颗宝石生成1张“电击！”卡牌，每点血量生成1张“升级！”卡牌，每根骨头生成1张“防御！”卡牌。
            AddTranslation("When [creature] is played, add the total cost of all cards sacrificed to play it, then create a Charge! for each energy, create a Zap! for each gem, create an Upgrade! for each blood, and create a Defend! for each bone.", "[creature]既陈，合所祀诸牌之总费：每一能，生一“充能！”；每一玉，生一“电击！”；每一血，生一“升级！”；每一骨，生一“防御！”。");
            // 推土机
            AddTranslation("Bulldoze", "推辟");
            // 消耗1点能量使该卡牌朝印记标注的方向移动。沿途的造物会被推向同一方向。
            AddTranslation("Pay 1 Energy to cause this card to move in the direction inscribed in the sigil. Creatures that are in the way will be pushed in the same direction.", "费一能，使此牌循印所志而移。当途之物皆同向见推。");
            // 零敲碎打
            AddTranslation("Shred", "裂牌");
            // 粉碎一张手牌以获得+1攻击力（持续至回合结束）。被粉碎的卡牌视同死亡。无法被消灭的卡牌和石制卡牌不可被粉碎。
            AddTranslation("Shred a card from your hand to get +1 Attack (until end of turn). The shredded card behaves as if it died. Unkillable cards and cards Made of Stone cannot be shredded.", "裂汝手中一牌，以得威益一，至合终。彼裂牌视若已死。不死牌与磐身牌，不可裂。");
            // 副牌组力量
            AddTranslation("Side Deck Power", "副列威");
            // 该印记代表的数值等于持牌人从副牌组中抽取的卡牌数量。
            AddTranslation("The value represented with this sigil will be equal to the number of cards its owner has drawn from the side deck.", "此印所表之数，与其主持自副牌列所引之牌数等。");
            // 黏液卡槽
            AddTranslation("Slimed Slot", "涎位");
            // 该卡槽中的卡牌攻击力将降低1点。
            AddTranslation("The card in this slot will have its attack reduced by one.", "处此位之牌，威减一。");
            // 相位穿梭
            AddTranslation("Phase Through", "穿相");
            // 持牌人回合结束时，[creature]将向指定方向移动一格，必要时可穿透其他卡牌直至找到空位。
            AddTranslation("At the end of its controller's turn, [creature] moves one space in the direction indicated, moving through other cards if necessary until it finds an empty space.", "持牌者合终，[creature]循所志而移一；必要则穿诸牌而过，至得虚位乃止。");
            // 太阳之心
            AddTranslation("Solar Heart", "日心");
            // 当[creature]死亡时，其心脏会留在原地并为该卡槽提供管道能量。
            AddTranslation("When [creature] dies, its heart stays behind and provides conduit power to the slot.", "[creature]死，则其心留于故处，而为其位输渠能。");
            // 太阳能供电
            AddTranslation("Solar Powered", "日能");
            // 该卡槽将始终保持充能状态，即使未处于完整回路中。
            AddTranslation("This card slot stays powered at all times, even if it is not in a completed circuit.", "此位常得能，纵不在成回路中亦然。");
            // 强势入场
            AddTranslation("Overwhelming Entrance", "压入");
            // 当[creature]被使用时，所有对位的造物都会被抛到新的位置。非管道地形不受影响。
            AddTranslation("When [creature] is played, all opposing creatures are tossed into new slots. Non-conduit terrain is not affected.", "[creature]既陈，诸对物皆掷于新位。非渠地形不与。");
            // 使魔召唤
            AddTranslation("Summon Familiar", "召使魔");
            // 当使用[creature]时，会在相邻空位放置一只机械兽。
            AddTranslation("When [creature] is played, it plays a techbeast in an empty adjacent slot.", "[creature]既陈，则于邻虚位陈一机兽。");
            // 死亡时速
            AddTranslation("Zip of Death", "疾毙");
            // 受到2点伤害
            AddTranslation("Take 2 damage.", "受二伤。");
            // 目标锁定
            AddTranslation("Target Required", "有敌乃击");
            // [creature]只能攻击有卡牌存在的路线。
            AddTranslation("[creature] can only attack lanes that have cards in them.", "[creature]惟可攻有牌之列。");
            // 操控
            AddTranslation("Controlled", "见御");
            // [creature]当前由对手操控。回合结束时将回归原主。被操控期间无法被锤击。
            AddTranslation("[creature] is under control of its opponent. At the end of the turn, it will return to its owner. While being controlled, it cannot be hammered.", "[creature]今为敌所御。合终则归故主。既见御，不得受槌。");
            // 火球术
            AddTranslation("Fireball", "火丸");
            // [creature]回合结束时，将选择一个卡槽点燃，持续三回合。
            AddTranslation("At the end of its turn, [creature] chooses a card slot to set on fire for three turns.", "其合终，[creature]择一位，使之焚三合。");
            // 黏液球
            AddTranslation("Slimeball", "涎丸");
            // [creature]会在其回合结束时选择一个卡槽进行黏液覆盖。处于黏液卡槽中的卡牌会减少1点力量。
            AddTranslation("At the end of its turn, [creature] will choose one slot to become slimed. Cards in a slimed slot lose one power.", "其合终，[creature]择一位，使为涎位。处涎位者威减一。");
            // 史莱姆破坏者
            AddTranslation("Slime Vandal", "涎贼");
            // 当使用[creature]时，它会污染牌桌上所有空位。被污染空位中的卡牌将损失1点力量。
            AddTranslation("When [creature] is played, it slimes all slots on the board. Cards in slimed slots lose one power.", "[creature]既陈，则局上诸位皆涎。处涎位者威减一。");
            // 内脏炸弹
            AddTranslation("Full of Guts", "满腑");
            // 当[creature]死亡时，会在对面位置留下一滩内脏黏液。
            AddTranslation("When [creature] dies, it slimes the opposing slot.", "[creature]死，则其对位涎。");
            // 种子掉落
            AddTranslation("Seed Sprinter", "遗种驰");
            // 在持牌人回合结束时，[creature]会向指定方向移动一格（若可行）并在原位置种下一颗种子。
            AddTranslation("At the end of its controller's turn, [creature] moves one space in the direction indicated (if it can) and plants a seed in its previous space.", "持牌者合终，[creature]循所志移一（若可），而其故处殖一种。");
            // 容器之心
            AddTranslation("Vessel Heart", "皿心");
            // 带有该印记的卡牌阵亡时，会在其位置生成一个容器。
            AddTranslation("When a card bearing this sigil perishes, a vessel is created in its place.", "负此印者死，则其处生一皿。");
            // 电击
            AddTranslation("Zap", "电击");
            // 对目标造成直接伤害。
            AddTranslation("Deals damage directly to the target.", "直伤所指。");
            // 海胆生成管道
            AddTranslation("Urchin Spawn Conduit", "海胆生渠");
            // 由[creature]构成的回路中的空位置可在持牌人回合结束时生成海胆电池。
            AddTranslation("Empty spaces within a circuit completed by [creature] spawn Urchin Cells at the end of the owner's turn.", "在[creature]所成回路中之虚位，持牌者合终皆生海胆匣。");
            // 消耗2点能量，使[creature]力量设为1至6之间的随机数值。
            AddTranslation("Pay 2 Energy to set the power of [creature] randomly between 1 and 6.", "费二能，使[creature]之威偶定于一至六。");
        }

    }

    public class P03InKayceesModMod
    {
        public static void RegisterTranslations()
        {
            // Ability: Base
            // 双重死亡
            AddTranslation("Double Death", "再死");
            // 爆头射击
            AddTranslation("Head Shot", "枭首");
            // [creature]可免疫死神之触、臭臭印记和火焰的效果。
            AddTranslation("[creature] is immune to the effects of Touch of Death, Stinky, and fire.", "[creature]不受死触、恶臭与火之效。");
            // 如果[creature]持牌人未打出玛珂容器，则[creature]会阵亡。
            AddTranslation("If [creature]'s owner controls no Gem Vessels, [creature] perishes.", "若[creature]之主持无玉皿，则[creature]死。");
            // 加密货币矿机
            AddTranslation("Mine Cryptocurrency", "采密币");
            // 当[creature]作为管道的一部分时，将会生成加密货币。
            AddTranslation("When part of a conduit, [creature] will generate cryptocurrency.", "当[creature]处渠中，则生密币。");
            // 盖章文件
            AddTranslation("Stamp Paperwork", "印牍");
            // 消耗1点能量为这份文件盖章，确认其已妥善归档并准备进入下一流程。
            AddTranslation("Pay 1 Energy to stamp this paperwork as properly filed and ready for further processing.", "费一能，以印此牍，使之既录，可更行其事。");
            // 强力打击
            AddTranslation("Big Strike", "并击");
            // [creature]会攻击对面所有路线上的卡牌，如果对面没有卡牌则会攻击正中间路线。
            AddTranslation("[creature] attacks all cards in all lanes opposing it, or attacks just the center opposing lane if there are no cards it can attack.", "[creature]攻其对之诸列诸牌；若无可攻者，则独攻中央对列。");
            // Ability: Multiverse
            // 多元宇宙炸弹传花
            AddTranslation("Multiverse Bomb Latch", "诸界爆弹遗契");
            // [creature]阵亡时，其持牌人需在任意宇宙中选定一个造物继承多元宇宙引爆器印记
            AddTranslation("When [creature] perishes, its owner chooses a creature in any universe to gain the Multiverse Detonator sigil.", "[creature]死，则其主持择诸界一物，受诸界引爆印契。");
            // 多元宇宙脆骨传花
            AddTranslation("Multiverse Brittle Latch", "诸界脆骨遗契");
            // [creature]阵亡时，其持牌人需在任意宇宙中选定一个造物继承脆骨印记。
            AddTranslation("When [creature] perishes, its owner chooses a creature in any universe to gain the Brittle sigil.", "[creature]死，则其主持择诸界一物，受脆骨印契。");
            // 多元宇宙引爆器
            AddTranslation("Multiverse Detonator", "诸界引爆");
            // 当[creature]死亡时，所有平行宇宙中相邻的卡牌都会受到10点伤害
            AddTranslation("When [creature] dies, all adjacent cards in all universes are dealt 10 damage", "[creature]死，则诸界邻牌皆受十伤。");
            // 多元宇宙燃油满溢
            AddTranslation("Multiverse Full of Oil", "诸界盈油");
            // 当[creature]死亡时，每个宇宙中其左右两侧及正对面的造物都会获得3点生命值。
            AddTranslation("When [creature] dies, it adds 3 health to the creature on either side and across from it in every universe.", "[creature]死，则诸界中其两旁与其对之物皆命益三。");
            // 多重宇宙满载
            AddTranslation("Multiverse Fully Loaded", "诸界满载");
            // [creature]死亡时，会在其所在平行宇宙的对应位置留下永久的+1攻击力加成。
            AddTranslation("When [creature] dies, it leaves a permanent +1 attack bonus in the lane it occupied in every universe.", "[creature]死，则诸界中其所居列皆遗永久益威一之效。");
            // 多元宇宙守护者
            AddTranslation("Multiverse Guardian", "诸界守者");
            // 当任意宇宙中的对手造物被放置在一个空位对面时，[creature]会移动至该空位。
            AddTranslation("When an opposing creature is placed opposite to an empty space in any universe, [creature] will move to that empty space.", "诸界中，敌物若陈于一空位之对，则[creature]移于彼空位。");
            // 多元宇宙钻地龙
            AddTranslation("Multiverse Burrower", "诸界潜龙");
            // 当一个空位可能受到攻击时，[creature]会穿越多元宇宙移动至该位置承受攻击。
            AddTranslation("When an empty space would be struck, [creature] will cross universes to move to that space to receive the strike instead.", "若诸界有空位将受击，则[creature]越界移于彼，代受其击。");
            // 多元宇宙空无管道
            AddTranslation("Multiverse Null Conduit", "诸界虚渠");
            // 由[creature]构成的回路将在所有宇宙中同时生效
            AddTranslation("Circuits completed by [creature] are completed in every universe.", "[creature]所成回路，诸界皆成。");
            // 多元宇宙高跳
            AddTranslation("Multiverse Mighty Leap", "诸界高跃");
            // [creature]会跨越多元宇宙拦截该路径上发生的所有攻击
            AddTranslation("[creature] will leap across universes to block attacks that occur in this lane in any universe.", "[creature]跃越诸界，以御诸界中此列所至之攻。");
            // 多元宇宙哨兵
            AddTranslation("Multiverse Sentry", "诸界哨兵");
            // 任何造物在任意宇宙中进入[creature]对面的位置时，均会受到1点伤害。
            AddTranslation("When a creature moves into the space opposing [creature] in any universe, they are dealt 1 damage.", "任一界有物入[creature]对位，则彼受一伤。");
            // 多元宇宙坚盾传花
            AddTranslation("Multiverse Shield Latch", "诸界微铠遗契");
            // [creature]阵亡时，其持牌人可选择任意宇宙中的造物继承纳米铠甲印记。
            AddTranslation("When [creature] perishes, its owner chooses a creature in any universe to gain the Nano Armor sigil.", "[creature]死，则其主持择诸界一物，受微铠印契。");
            // 多元宇宙冲刺能手
            AddTranslation("Multiverse Sprinter", "诸界驰者");
            // 持牌人回合结束时，[creature]将跃迁至下一个宇宙。
            AddTranslation("At the end of the owner's turn, [creature] will move to the next universe.", "持牌者合终，[creature]跃于次界。");
            // 多重宇宙打击
            AddTranslation("Multiverse Strike", "诸界击");
            // [creature]会攻击除自身所在宇宙外所有平行宇宙中的对应位置
            AddTranslation("[creature] will strike each opposing space in every universe other than its own.", "[creature]攻诸界中凡非其本界之对位。");
            // 多元宇宙至尊玛珂
            AddTranslation("Multiverse Great Mox", "诸界至尊玛珂");
            // 当打出[creature]时，所有平行宇宙中持牌人侧牌桌都将获得绿、橙、蓝宝石各一颗
            AddTranslation("When [creature] is played, a Green, Orange, and Blue Gem is provided to the owner's side in every universe.", "[creature]既陈，则诸界中其主持之侧，皆得绿、橙、蓝玉各一。");
            // 多元宇宙囤积狂
            AddTranslation("Multiverse Hoarder", "诸界藏者");
            // 使用[creature]时，你可以从多元宇宙中搜寻一张已消亡且能穿越多元宇宙的卡牌。
            AddTranslation("When [creature] is played, you may search the multiverse for a card that has perished that is capable of traversing the multiverse.", "[creature]既陈，汝可于诸界求一已死而能越界之牌。");


