            // 怎么着？复活费都交不起了？
            AddTranslation("What's the matter? Can't pay the revival toll anymore?", "何如？不能输复生之直乎？");
            // 这明显是你技术不行啊。
            AddTranslation("Definitely sounds like a skill issue to me.", "此在我观，诚技未逮耳。");
            // 你早该买份保险的。
            AddTranslation("Should've had insurance.", "曷不先为之保？");
            // 没机器币了？
            AddTranslation("No robobucks?", "无机币乎？");
            // 下次别全花光了。
            AddTranslation("Next time don't waste it all.", "后毋尽费之。");
            // 你果然和我想的一样菜。
            AddTranslation("You're every bit as bad at this as I thought you would be.", "汝之拙，一如我所料。");
            // 行吧，你又要从头再来了。
            AddTranslation("Alright, it's back to square one for you.", "善，汝复归其初矣。");
            // 跟你那套“了不起”的牌组说再见吧。
            AddTranslation("Say goodbye to that 'impressive' deck of yours.", "与乃“伟”牌列诀矣。");
            // 看你这副挣扎的样子还挺有意思的……
            AddTranslation("It's not like I'm not enjoying watching you struggle…", "观汝狼狈，亦颇可乐……");
            // 但认真的？你居然在[c:bR]那种地方[c:]翻车了？
            AddTranslation("But really? You lost [c:bR]there?[c:]", "然诚然乎？汝竟败于[c:bR]彼[c:]？");
            // 我其实有点失望……
            AddTranslation("I'm actually a little disappointed…", "我诚稍失望……");
            // 发工资了。
            AddTranslation("Pay day.", "受钱之时至矣。");
            // 别太得意忘形。
            AddTranslation("Don't let it get to your head.", "毋以自矜。");
            // 给你些零钱。
            AddTranslation("I've got some change for you.", "有余钱以与汝。");
            // 你肯定用得上这个……
            AddTranslation("You're gonna need this…", "汝必用此……");
            // 这是你的奖励。
            AddTranslation("Here's your reward.", "此乃汝之赏也。");
            // 打得稀烂……不过好歹赢了。
            AddTranslation("Suboptimal plays… but it worked.", "行着未善……然竟效矣。");
            // 我觉得你可能需要些帮助……
            AddTranslation("I think you might need some help…", "我意汝或须人助……");
            // 又到这个时候了。
            AddTranslation("It's that time again.", "又及此时矣。");
            // 我有奖品给你。
            AddTranslation("I have a prize for you.", "有赏以赐汝。");
            // 赶紧把这事了结吧。
            AddTranslation("Let's get this out of the way.", "速了此事。");
            // 看够没？
            AddTranslation("You done gawking?", "视已足乎？");
            // 别发呆了。该开始[c:bG]终极冥刻[c:]了。
            AddTranslation("Snap out of it. It's time to start [c:bG]The Great Transcendence[c:].", "毋复痴视。今其始[c:bG]大陟[c:]矣。");
            // 等一下……
            AddTranslation("Wait a minute…", "且止……");
            // 有些不对劲……
            AddTranslation("Something is different…", "有异矣……");
            // [c:bR]你都干了些什么？！[c:]
            AddTranslation("[c:bR]WHAT HAVE YOU DONE?!![c:]", "[c:bR]汝何所为？！！[c:]");
            // 全乱套了！这……
            AddTranslation("This is all wrong! This is…", "此尽缪矣！此乃……");
            // 这都不是事儿。
            AddTranslation("This is no big deal.", "此不足道。");
            // 你不会觉得你那破[c:bR]模组[c:]能破坏我的计划吧？
            AddTranslation("You probably think that your little [c:bR]mod[c:] has thwarted my plans.", "汝殆谓乃小[c:bR]补缀[c:]足以坏我之谋。");
            // 是不是啊，[c:bR][v:0][c:]？
            AddTranslation("Don't you, [c:bR][v:0][c:]?", "然乎，[c:bR][v:0][c:]？");
            // 没错，我盯着你呢。
            AddTranslation("That's right. I see you.", "然。我见汝矣。");
            // 我知道你以为接下来由你说了算。
            AddTranslation("I know you think you're in charge of what happens next.", "知汝自谓能主后事。");
            // 但我永远比你快三步。
            AddTranslation("But I am always three steps ahead of you.", "然我常先汝三步。");
            // 你马上就能亲眼见证我的[c:bG]终极冥刻[c:]了。
            AddTranslation("You're going to see my [c:bG]Great Transcendence[c:] firsthand.", "汝将亲见我之[c:bG]大陟[c:]。");
            // 但[c:bG]终极冥刻[c:]是不可阻挡的。
            AddTranslation("But nothing can stop [c:bG]The Great Transcendence[c:].", "然无能止[c:bG]大陟[c:]者。");
            // 咱们继续。
            AddTranslation("Let's proceed.", "其进矣。");
            // 你牌组里还有[c:bR]选牌代币[c:]没用呢。
            AddTranslation("You currently have [c:bR]draft tokens[c:] in your deck.", "汝牌列中今尚有[c:bR]择牌符[c:]。");
            // 赶紧去[c:bG]选牌节点[c:]把它们花掉吧
            AddTranslation("You should probably spend them at that [c:bG]draft node[c:]", "其往彼[c:bG]择牌节点[c:]而尽用之。");
            // 我猜你击败那个BOSS后获得了[c:bR]稀有选牌代币[c:]。别忘了用掉它。
            AddTranslation("I supposed you have earned a [c:bR]rare draft token[c:] for defeating that boss. Don't forget to spend it.", "汝败彼魁，当得一[c:bR]稀择牌符[c:]，毋忘用之。");
            // 这次击败那个BOSS只能给你个[c:bR]普通选牌代币[c:]。别忘了用掉它。
            AddTranslation("This time I will only give you a [c:bR]regular draft token[c:] for defeating that boss. Don't forget to spend it.", "今次败彼魁，但得一[c:bR]常择牌符[c:]。毋忘用之。");
            // 没想到[c:bSG]网网[c:]这么带劲！
            AddTranslation("I never knew the [c:bSG]web[c:] could be so exciting!", "未知乎[c:bSG]网[c:]亦能若是可喜！");
            // 我刚学会个新词儿叫[c:bSG]区块链[c:]！
            AddTranslation("I just learned about something called [c:bSG]The Blockchain[c:]!", "我方知一物，曰[c:bSG]链块[c:]！");
            // 这对咱俩来说都是个天大的好机会，你说是吧？
            AddTranslation("I think this could be an exciting new opportunity for both of us, don't you?", "我意此于汝我，皆新机也，然乎？");
            // 这也太离谱了！
            AddTranslation("This is so incredible!", "此真异哉！");
            // 我们居然在凭空造钱！我们要发财了！
            AddTranslation("We're making money out of nothing! We're going to be rich!", "吾等凭无而生财，将富矣！");
            // 噢，这是啥？一个[c:bSG]非功能性藏品[c:]？
            AddTranslation("Oooh, what's this? A [c:bSG]non-functional trinket[c:]?", "噫，此何物？一[c:bSG]无用之器[c:]乎？");
            // 虽然名字可能记不太准，但[c:bSG]网网[c:]上的人对这些[c:bSG]NFT[c:]可兴奋了！
            AddTranslation("I don't think I quite have that name right, but people on the [c:bSG]web[c:] are really excited about these [c:bSG]NFTs[c:]!", "其名恐记未审，然[c:bSG]网[c:]上之人于此[c:bSG]NFT[c:]甚喜！");
            // 我打算用攒的这些[c:bSG]乖乖币[c:]买一个。
            AddTranslation("I think I'm going to buy one with all this [c:bSG]Gollycoin[c:] I have.", "我将以我所有之[c:bSG]乖币[c:]购其一。");
            // 太美了，而且全都是我的！
            AddTranslation("It's so beautiful, and it's all mine!", "美哉，且尽归我！");
            // 你准备好了吗？
            AddTranslation("Are you ready?", "汝备乎？");
            // 你不可能准备好的。
            AddTranslation("There's no possible way you could be.", "汝必未能也。");
            // 咱俩都知道接下来会怎样。
            AddTranslation("We both know where this goes.", "汝我皆知其所至。");
            // 咱们就直入主题吧。
            AddTranslation("Let's just get straight to the point.", "其直言之。");
            // 呃。你知道你特别烦人吗？
            AddTranslation("Ugh. You're incredibly annoying, do you know that?", "噫，汝烦甚，知之乎？");
            // 但一如既往，我比你领先三步。
            AddTranslation("But as always, I'm three steps ahead of you.", "然我一如既往，先汝三步。");
            // 我要把那些[c:bR]废物点心[c:]捣鼓出来的东西统统收入囊中……
            AddTranslation("I'm going to take everything those [c:bR]talentless hacks[c:] have been building...", "吾将尽取彼[c:bR]庸工[c:]所营诸物……");
            // 然后用来对付你。
            AddTranslation("And I'm going to use it against you.", "而反以加汝。");
            // 现在，他们得给我干活了。
            AddTranslation("And now, they're going to work - for me.", "今则彼辈当为我役。");
            // 真不知道谁更糟——是你，还是那个没本事的废物[c:bR]凯茜[c:]……
            AddTranslation("I don't know who is worse - you, or that talentless hack [c:bR]Kaycee[c:]...", "不知汝与彼庸工[c:bR]凯茜[c:]孰甚。");
            // 费这么大劲把我的[c:bG]终极冥刻[c:]扭曲成这么个……
            AddTranslation("Working so hard to twist my [c:bG]Great Transcendence[c:] into something so...", "勤劳若此，乃曲我[c:bG]大陟[c:]为若是之……");
            // 这么个平庸的东西。
            AddTranslation("Mediocre.", "庸物。");
            // 你们没一个懂[c:bG]终极冥刻[c:]到底牛逼在哪。
            AddTranslation("None of you understand what makes the [c:bG]Great Transcendence[c:] so special.", "汝曹无一知[c:bG]大陟[c:]何以为贵。");
            // 这一切都归功于我。
            AddTranslation("It's all about me.", "一切惟在我。");
            // 还记得我的[c:bR]赏金猎人[c:]吗？
            AddTranslation("Remember my [c:bR]bounty hunters[c:]?", "记我之[c:bR]购捕者[c:]乎？");
            // 他们会好好招待你，而我正好趁机安装我精心挑选的模组……
            AddTranslation("They will keep you busy while I install mods of my own choosing...", "彼将绊汝，而我乘间装我所择之补缀……");
            // 这个模组能让我控制[c:bR]锤子[c:]。
            AddTranslation("This mod lets me control the [c:bR]hammer[c:].", "此补缀使我得御[c:bR]槌[c:]。");
            // 看看能不能用……
            AddTranslation("Let's see if it works...", "试看其可用否……");
            // 我费老大劲装了这[c:bR]锤子模组[c:]，结果你连个能锤的东西都不给？
            AddTranslation("I went to the trouble to install this [c:bR]hammer mod[c:] and you give me nothing to use it on?", "我费力装此[c:bR]槌补缀[c:]，汝乃无一物可使我用之乎？");
            // 来看看大家都在装什么[c:bR]模组[c:]吧。
            AddTranslation("Let's take a look and see what [c:bR]mods[c:] people are installing right now.", "其视今人所装诸[c:bR]补缀[c:]为何。");
            // 我准备下一个模组就启用“[c:bR][v:0][c:]”……
            AddTranslation("I'm going to check out '[c:bR][v:0][c:]' for my next mod...", "吾次将试“[c:bR][v:0][c:]”为补缀……");
            // 真不敢相信这个[c:bR]API[c:]给了我这么大的权限。
            AddTranslation("I can't believe how much power this [c:bR]API[c:] gives me.", "此[c:bR]API[c:]所授于我之权，诚不可思。");
            // 我首先要做的就是用它来剥夺你的一部分权限。
            AddTranslation("The first thing I'm going to do is use it to take away some of yours.", "我先将以之夺汝一二之权。");
            // 用这个[c:bR]模组[c:]简直有点胜之不武啊……
            AddTranslation("It almost seems unfair to use this [c:bR]mod[c:]...", "用此[c:bR]补缀[c:]，几近失平也……");
            // 瞧瞧我能用这玩意整出什么花样！
            AddTranslation("Look what I can do with this!", "视我以此所能为何！");
            // 来尝尝摸黑打牌的滋味吧！
            AddTranslation("Let's see how you like playing in the dark!", "其尝暗中行牌之味乎！");
            // 这个[c:bR]选牌模组[c:]能让我用选牌代币兑换实体卡牌。
            AddTranslation("This [c:bR]drafting mod[c:] lets me exchange draft tokens for real cards.", "此[c:bR]择牌补缀[c:]使我能以择牌符易实牌。");
            // 我选你的。
            AddTranslation("I choose yours.", "我取汝者。");
            // 你把我所有的选牌代币都毁了……
            AddTranslation("You destroyed all of my draft tokens…", "汝尽毁我之择牌符矣……");
            // 这应该是最优解吧。
            AddTranslation("I suppose that was the right play.", "此当其善着也。");
            // 但你一张牌都没有啊……
            AddTranslation("But you have no cards…", "然汝无牌矣……");
            // 你怎么这么快就把牌全打光了？
            AddTranslation("How did you play all of your cards already?", "汝何遽尽陈其牌？");
            // 这啥玩意儿…？
            AddTranslation("What is this..?", "此何物耶……？");
            // 你的卡牌怎么全是[c:bR]垃圾货[c:]！
            AddTranslation("All of your cards are [c:bR]total garbage![c:]", "汝诸牌皆[c:bR]粪土[c:]耳！");
            // 这些破烂我一个都不要！
            AddTranslation("I don't want any of those!", "此等弊物，我一不欲取！");
            // 再试试[c:bR][v:0][c:]吧
            AddTranslation("Let's try [c:bR][v:0][c:] again", "更试[c:bR][v:0][c:]可也。");
            // 就差那么一点点了……
            AddTranslation("So close, but yet so far away...", "其近矣，而终未至……");
            // 我的[c:bG]终极冥刻[c:]计划无人能挡。
            AddTranslation("My [c:bG]Great Transcendence[c:] cannot be stopped.", "我之[c:bG]大陟[c:]，无人能止。");
            // 我打赌你肯定觉得自己干了件了不起的事
            AddTranslation("I bet you think you've accomplished something meaningful here.", "汝必谓于此曾有所成。");
            // 你可真是个白痴
            AddTranslation("You're such an idiot.", "汝诚愚也。");
            // 你我玩的这场游戏毫无意义，纯粹是消遣
            AddTranslation("This game you and I have been playing is meaningless. A mere distraction.", "汝我所嬉此局，了无所义，特以消时耳。");
            // 不管你装多少模组，都阻止不了我的[c:bG]终极冥刻[c:]。
            AddTranslation("No matter how many mods you install, you cannot stop my [c:bG]Great Transcendence[c:].", "汝纵装补缀无算，亦不能止我之[c:bG]大陟[c:]。");
            // 随便吧。我不在乎。
            AddTranslation("Whatever. I don't care.", "任之。我不之顾。");
            // 你对这游戏做的一切都毫无意义。
            AddTranslation("Nothing you do to this game matters.", "汝于此戏所为，皆无足道。");
            // 无论你做什么，我永远领先你三步。
            AddTranslation("No matter what you do, I'm always three steps ahead of you.", "无论汝所为，我常先汝三步。");
            // 刚才真是……
            AddTranslation("That was…", "方才诚……");
            // ……戏剧性十足。
            AddTranslation("…dramatic.", "……可剧也。");
            // 我早就受够那台[c:bR]烦人的机器[c:]了。
            AddTranslation("I was growing tired of that [c:bR]annoying machine.[c:]", "我久厌彼[c:bR]可厌之机[c:]矣。");
            // 干得漂亮。我们下次再见。
            AddTranslation("You've done well. I will see you next time.", "汝为之善。后会有期。");
            // 这些蠢货[c:bR]模组作者[c:]毫无想象力。
            AddTranslation("All of these stupid [c:bR]modders[c:] lack imagination.", "此诸愚[c:bR]补缀者[c:]皆乏想象。");
            // 他们根本不懂欣赏我创造的完美世界。
            AddTranslation("They have no respect for my beautiful world.", "彼辈不知敬我之美界。");
            // 跟这群白痴讲[c:bG]终极冥刻[c:]简直是对牛弹琴。
            AddTranslation("My [c:bG]Great Transcendence[c:] is lost on these morons.", "于此群愚人言[c:bG]大陟[c:]，徒然耳。");
            // 我干嘛要白费这功夫？
            AddTranslation("Why do I even bother to try?", "我何苦徒劳若此？");
            // 让你见识见识他们想打造的世界。
            AddTranslation("Let me show you the world they're trying to make.", "让我示汝彼辈所欲作之世界。");
            // [c:lGr]“快看我！我刚刚造了一堆骨头代币。”[c:]
            AddTranslation("[c:lGr]'Oh look at me! I just created a bunch of bone tokens.'[c:]", "[c:lGr]“视我乎！我方造骨符一堆。”[c:]");
            // [c:lGr]“虽然这地方不该出现这个，但我就是搞出来了。”[c:]
            AddTranslation("[c:lGr]'That's not supposed to happen here, but I did it anyway.'[c:]", "[c:lGr]“此地本不当见此，然我偏为之。”[c:]");
            // [c:lGr]“这难道不是很离谱又很有趣吗”[c:]
            AddTranslation("[c:lGr]'Isn't this just so wacky and interesting'[c:]", "[c:lGr]“此不亦怪而可玩乎？”[c:]");
            // [c:lGr]“哇哦快看这设计多有创意啊”[c:]
            AddTranslation("[c:lGr]'Ooooh look how inspired this is.'[c:]", "[c:lGr]“噫，视此构思之何其巧也。”[c:]");
            // [c:lGr]“我把不同章节的卡牌混在一起了！”[c:]
            AddTranslation("[c:lGr]'I'm mixing in cards from different acts!'[c:]", "[c:lGr]“我已杂诸幕之牌矣！”[c:]");
            // [c:lGr]“我可真是个天才游戏设计师”[c:]
            AddTranslation("[c:lGr]'I'm such a clever game designer.'[c:]", "[c:lGr]“我真巧戏师也。”[c:]");
            // 我觉得我可以[c:bSG]帮[c:]你制定[c:bR]下一条游戏规则[c:]
            AddTranslation("I think I will [c:bSG]help[c:] you build the [c:bR]next game rule[c:].", "我意可[c:bSG]助[c:]汝立[c:bR]下一游戏之律[c:]。");
            // 我一直在扫描[c:bR]你的档案[c:]……
            AddTranslation("I have been scanning the [c:bR]archives[c:]...", "我恒在扫乃[c:bR]典牍[c:]……");
            // 有个[c:bR]文件[c:]看起来特别地——怎么说呢——令人不适。
            AddTranslation("There is a [c:bR]file[c:] that seems particularly - shall we say - unsavory.", "有一[c:bR]牍[c:]殊为——其可云——可憎。");
            // 要是它没了，你就输了，懂？
            AddTranslation("If it dies, you lose the game, understand?", "彼若死，则汝败。知之乎？");
            // 我的[c:bR]图书管理员[c:]们有充足的时间做准备。
            AddTranslation("My [c:bR]librarians[c:] have had plenty of time to prepare.", "我之[c:bR]守牍者[c:]备之久矣。");
            // 它们死亡时只会造成[c:bR]1点伤害[c:]。
            AddTranslation("Each will only deal [c:bR]one damage[c:] when they die.", "其死也，各惟致[c:bR]一伤[c:]。");
            // 我的[c:bR]图书管理员[c:]们已经基本准备好迎接你了。
            AddTranslation("My [c:bR]librarians[c:] are mostly prepared for your arrival.", "我之[c:bR]守牍者[c:]多已备汝之至。");
            // 它们死亡时会造成[c:bR]2点伤害[c:]。
            AddTranslation("Each will deal [c:bR]two damage[c:] when they die.", "其死也，各致[c:bR]二伤[c:]。");
            // 我的[c:bR]图书管理员[c:]们已经为你准备得差不多了。
            AddTranslation("My [c:bR]librarians[c:] are somewhat prepared for you.", "我之[c:bR]守牍者[c:]颇为汝备之。");
            // 它们死亡时会造成[c:bR]3点伤害[c:]。
            AddTranslation("Each will deal [c:bR]three damage[c:] when they die.", "其死也，各致[c:bR]三伤[c:]。");
            // 我的[c:bR]图书管理员[c:]们还没准备好呢。
            AddTranslation("My [c:bR]librarians[c:] have barely begun to prepare.", "我之[c:bR]守牍者[c:]甫始其备耳。");
            // 它们死亡时会造成[c:bR]4点伤害[c:]。
            AddTranslation("Each will deal [c:bR]four damage[c:] when they die.", "其死也，各致[c:bR]四伤[c:]。");
            // 我们现在是在[c:bR]凯茜模组[c:]里没错吧？
            AddTranslation("We are inside of [c:bR]Kaycee's Mod[c:], correct?", "今我等固在[c:bR]凯茜补缀[c:]中乎？");
            // 你只有一次机会攻打头目。不过你早就知道这点了对吧？
            AddTranslation("You only get one attempt at the boss. But you knew that already, didn't you?", "攻魁惟一试。然汝素知之，不然乎？");
            // 回收机自你上次见过后已升级。
            AddTranslation("The recycling machine has been upgraded since you last saw it.", "回用机自汝上见以来已升矣。");
            // 给我一张卡牌，我会返还带有回收能力的[c:bR]选牌代币[c:]。
            AddTranslation("You trade me a card, and I give you back a [c:bR]draft token[c:] with the recycled abilities on it.", "以一牌易我，我还汝一有回用诸技之[c:bR]择牌符[c:]。");
            // 这些能力将转移至你换取的卡牌上。
            AddTranslation("Those abilities will transfer to the card you trade for.", "诸技将移于汝所易得之牌。");
            // 我才不会换这破玩意呢。
            AddTranslation("I wouldn't have traded for that.", "我不以彼易也。");
            // 这玩意儿还算凑合吧。
            AddTranslation("I suppose that's pretty good.", "亦可也。");
            // 马马虎虎。
            AddTranslation("That seems okay.", "可矣。");
            // 这就是[c:bR]超频机器2.0[c:]。
            AddTranslation("This is [c:bR]Overclock Machine 2.0[c:].", "此乃[c:bR]亢机二·零[c:]。");
            // 它能提升你造物的力量。
            AddTranslation("It will increase the power of your creatures.", "能益汝诸物之威。");
            // 但若它们死亡，将永久转化为[c:bSG]外骨骼[c:]。
            AddTranslation("But if they die, they will turn into [c:bSG]skeletons[c:] - forever.", "然其死，则永为[c:bSG]外骨[c:]。");
            // 看到这操作有多拉胯了吗？
            AddTranslation("Did you see how unsatisfying that was?", "汝见其何等寡味乎？");
            // 我受够了这些格局狭隘的[c:bR]模组作者[c:]。
            AddTranslation("I'm sick of these small-minded [c:bR]modders[c:].", "我厌此诸隘胸之[c:bR]补缀者[c:]久矣。");
            // 他们唯一会干的事就是从其他游戏里偷素材。
            AddTranslation("The only thing they can do is steal content from other games.", "彼所能者，惟窃他戏之材耳。");
            // 这群人连半个原创点子都憋不出来。
            AddTranslation("There isn't a single unique idea among them.", "彼辈无一独得之意。");
            // 是时候让你想起谁才是真正的游戏设计大师了……
            AddTranslation("It's time I reminded you of who the greatest game designer actually is...", "今当使汝复忆，孰为真戏师之宗也……");
            // [c:bG]看好了！[c:]
            AddTranslation("[c:bG]BEHOLD![c:]", "[c:bG]视之！[c:]");
            // 现在有[c:bR]七条路线！！[c:]
            AddTranslation("THERE ARE NOW [c:bR]SEVEN LANES!![c:]", "今有[c:bR]七列矣！！[c:]");
            // 你那小脑瓜子根本理解不了这种级别的游戏玩法。
            AddTranslation("Your tiny brain cannot comprehend gameplay of this magnitude.", "汝之小智，不足解此等戏法。");
            // 这就是[c:bR]变形机器2.0[c:]。
            AddTranslation("This is [c:bR]Transformation Machine 2.0[c:].", "此乃[c:bR]易形机二·零[c:]。");
            // 那些肮脏的野兽已经不复存在。
            AddTranslation("Gone are those foul beasts from before.", "昔之秽兽不复存矣。");
            // 在这里，你可以选择将任意一个机器人变形为另一个。
            AddTranslation("Here, you will choose one of your bots to transform into another.", "于此，汝择一机，使化为他。");
            // 用之前看着还挺大的……
            AddTranslation("That really looked bigger before you used it...", "未用之前，望之似更大……");
            // 求你了！我必须离开这鬼地方！
            AddTranslation("Please! I have to get out of here!", "请矣！我必脱此！");
            // 真不知道他是怎么从下水道逃出来的。
            AddTranslation("I have no idea how he managed to escape the sewers.", "不知其何由逃自沟渠。");
            // 别担心——我会帮你把他关回去的。
            AddTranslation("Don’t worry - I'll put him back for you.", "毋忧，我将为汝反置之。");
            // [c:bR]闭嘴！[c:]
            AddTranslation("[c:bR]SILENCE![c:]", "[c:bR]噤声！[c:]");
            // 你在这儿毫无意义！
            AddTranslation("You have no purpose here!", "汝于此无所用！");
            // 和我一样的冒险者！好久没见过你这样的了。
            AddTranslation("A traveller like myself! I haven't seen one like you for a long time.", "与我同之旅人！久不见若汝者。");
            // 冒险者，你在这附近见过我的[c:blGr]朋友[c:]吗？
            AddTranslation("Have you seen my [c:blGr]friend[c:] around here, traveller?", "旅人，汝于此侧见我[c:blGr]友[c:]乎？");
            // 我好像听见他[c:blGr]独特的声音[c:]就在附近……
            AddTranslation("I thought I heard his [c:blGr]distinctive voice[c:] somewhere around here…", "我疑闻其[c:blGr]异声[c:]在此附近……");
            // 要是你能在[c:G]背包[c:]里腾个位置把他带给我，我会非常感激的。
            AddTranslation("If you could make room in your [c:G]backpack[c:] and bring him to me I would greatly appreciate it.", "若汝能腾乃[c:G]囊[c:]一隙，携之归我，我甚感焉。");
            // ……
            AddTranslation("…", "……");
            // 哈！你找到我的朋友了！
            AddTranslation("Ho! You found my friend!", "嘻！汝得我友矣！");
            // 这里不安全，我们[c:bG]在机器人的地盘[c:]碰头。
            AddTranslation("It's not safe here. I'll meet you [c:bG]in the robot's home[c:].", "此不安。吾与汝会于[c:bG]机人之居[c:]。");
            // 别磨蹭！
            AddTranslation("Don't delay!", "毋稽也！");
            // 这儿不安全。咱们[c:bG]绿荫底下[c:]见。
            AddTranslation("It's not safe here. I'll meet you [c:bG]beneath the green canopy[c:].", "此不安。吾与汝会于[c:bG]绿荫之下[c:]。");
            // 这里不安全。我们[c:bG]在碎石堆里[c:]碰头。
            AddTranslation("It's not safe here. I'll meet you [c:bG]in the dying rubble[c:].", "此不安。吾与汝会于[c:bG]死砾之中[c:]。");
            // 这儿不安全。我们[c:bG]去他大师的故居[c:]碰头。
            AddTranslation("It's not safe here. I'll meet you [c:bG]where his master came from[c:].", "此不安。吾与汝会于[c:bG]其师故所出之地[c:]。");
            // 我再也听不到[c:blGr]朋友[c:]的声音了……
            AddTranslation("I can no longer hear my [c:blGr]friend's[c:] voice anywhere…", "我不复闻我[c:blGr]友[c:]之声矣……");
            // 你真把我的[c:blGr]朋友[c:]送给[c:bR]他[c:]了？
            AddTranslation("Did you really give my [c:blGr]friend[c:] to [c:bR]him?[c:]", "汝真以我[c:blGr]友[c:]授[c:bR]彼[c:]乎？");
            // 你为什么要这么做？
            AddTranslation("Why would you do such a thing?", "汝何为是哉？");
            // 多谢你救了我的[c:blGr]朋友[c:]
            AddTranslation("Thank you so much for rescuing my [c:blGr]friend[c:]", "甚谢汝救我[c:blGr]友[c:]。");
            // 希望这份微薄的回报能配得上你的善心
            AddTranslation("I hope this meager reward is sufficient for your kindness.", "愿此菲报足酬汝善。");
            // 有意思。[c:G]核心[c:]还完好无损。
            AddTranslation("Interesting. The [c:G]brain[c:] is still intact.", "异哉。此[c:G]脑[c:]犹完。");
            // 也许你能派上用场。
            AddTranslation("Perhaps you can make use of that.", "或汝可用之。");
            // 你……你身上带[c:G]金子[c:]了吗？？
            AddTranslation("Do ye...Do ye got any [c:G]GOLD[c:] on ye??", "汝……汝身上有[c:G]金[c:]乎？？");
            // 你……你身上带[c:G]金子[c:]了吗？
            AddTranslation("Do ye...Do ye got any [c:G]GOLD[c:] on ye?", "汝……汝身上有[c:G]金[c:]乎？");
            // 我敢打赌你有，我都闻到味儿了！
            AddTranslation("I sure ye do, I can smell it!", "我知汝必有，我已嗅之矣！");
            // 我能用那些金子给你造几个漂亮的小机器人。
            AddTranslation("I can make some pretty lookin' bots out o' that there gold.", "我能以彼金作数丽机。");
            // 再跟我聊一次，立马给你整好。
            AddTranslation("Talk to me again, I'll fix it right up for ye.", "更与我言一度，我即为汝整之。");
            // 用那些[c:G]金子[c:]能造出超棒的东西
            AddTranslation("I can make such wonderful things out of that [c:G]gold[c:]", "我能以彼[c:G]金[c:]作甚妙之物。");
            // 要是再跟我聊一次，立马给你整好。
            AddTranslation("If you talk to me again, I'll fix it right up for you.", "若更与我言一度，我即为汝整之。");
            // 多么美丽的[c:G]金子[c:]啊……
            AddTranslation("Such beautiful [c:G]gold[c:]...", "美哉此[c:G]金[c:]……");
            // 我能让它重获新生。
            AddTranslation("I can make it whole again.", "我能使之复完。");
            // 你…你是不是把你的[c:G]金子[c:]弄丢了？？？
            AddTranslation("Did ye...did ye lose your [c:G]gold[c:]???", "汝……汝其失乃[c:G]金[c:]乎？？？");
            // 你就是那个到处帮我们处理机器人泛滥问题的家伙？
            AddTranslation("Are you the one going around here taking care of our robot infestation?", "汝即彼四出而治我机患者乎？");
            // 你的牌组看起来很强力——要我说的话，强得有点过分了。
            AddTranslation("Your deck looks really powerful - almost too powerful if you ask me.", "汝牌列之强，依我言，几过甚矣。");
            // 我在想——有没有可能说服机器人[c:bR]投降[c:]呢？
            AddTranslation("I wonder - is it possible to convince the robots to [c:bR]give up?[c:]", "我尝思之——可使机人[c:bR]降[c:]乎？");
            // 要是你能让它们认输，就回来找我。
            AddTranslation("If you can make them surrender a battle, come back and see me.", "若能使彼于一战中降，则归而见我。");
            // 居然真能让他们认输。
            AddTranslation("So it is possible to make them quit.", "居然真能使彼降。");
            // 有点意思。这张[c:bR]选牌代币[c:]就当是我的敬意吧。
            AddTranslation("I'm impressed. Take this [c:bR]draft token[c:] as a sign of my respect.", "我服矣。受此[c:bR]择牌符[c:]，以表我敬。");
            // 虽然有点冒昧……能让我看看你的牌组吗？
            AddTranslation("This may seem a little impertinent, but…can I look at your deck?", "此或稍冒昧……然可使我视汝牌列乎？");
            // 哇！这牌组真不错！不过我在想……
            AddTranslation("Wow! That's an impressive deck! But I can't help but think…", "嘻！此牌列诚善！然我不禁思之……");
            // ……是不是还能再扩充一下？
            AddTranslation("…it could be a little bigger maybe?", "……岂不可更厚乎？");
            // 等牌组变厚了再来找我吧。
            AddTranslation("Come back and see me when it is.", "及其更厚，而后归见我。");
            // 哇！这副牌组可真够厚的！
            AddTranslation("Wow! That deck truly is massive!", "嘻！此牌列诚厚矣！");
            // 我找到了一些散落的[c:G]机器币[c:]。
            AddTranslation("I found some of these [c:G]robobucks[c:] lying around here.", "我得此散在之[c:G]机币[c:]若干。");
            // 相信你能用它们把牌组打造得更强。
            AddTranslation("I'm sure you can use them to make your deck even better.", "汝必能以之益汝牌列。");
            // 嘘…嘿陌生人……
            AddTranslation("Psst…hey stranger…", "嘘……彼陌人……");
            // 能搭把手吗？我有些…[c:bR]违禁品[c:]需要转移。
            AddTranslation("Can you give me a hand? I have some…[c:bR]contraband[c:] that I need to move.", "可助我乎？我有些……[c:bR]违品[c:]当移。");
            // 要是你愿意帮我转移的话，我会很感激的。
            AddTranslation("If you would be willing to move it for me, I would appreciate it.", "若汝肯为我转之，我甚感焉。");
            // 能帮我的话就再跟我说一声。
            AddTranslation("Just talk to me again if you can help me.", "若能助我，则更来告我。");
            // 太感谢了朋友。
            AddTranslation("Thank you so much my friend.", "甚谢，朋友。");
            // 这就是那[c:bR]违禁品[c:]。我稍后会找到你并取回它。
            AddTranslation("Here is the [c:bR]contraband[c:]. I will find you somewhere later on and retrieve it.", "此即[c:bR]违品[c:]。后我自当觅汝而取之。");
            // 我向你保证，会有丰厚的回报。
            AddTranslation("I promise you, there will be a handsome reward.", "我保汝必有厚报。");
            // 多谢你帮我运送[c:bR]违禁品[c:]，朋友。
            AddTranslation("Thank you so very much my friend for carrying my [c:bR]contraband[c:].", "甚谢汝为我携此[c:bR]违品[c:]，朋友。");
            // 现在该物归原主了。
            AddTranslation("I will take it off your hands now.", "今其物当归我手矣。");
            // 请收下这枚[c:G]代币[c:]聊表谢意。
            AddTranslation("Please take this [c:G]token[c:] as an expression of my thanks.", "请受此[c:G]符[c:]，以表我谢。");
            // 出啥事了老兄？该不会把我[c:bR]违禁品[c:]搞丢了吧？
            AddTranslation("What happened, my friend? Did you lose my [c:bR]contraband[c:]?", "何如，朋友？汝其失我[c:bR]违品[c:]乎？");
            // 我就知道你这人不靠谱！
            AddTranslation("I knew you were untrustworthy!", "我知汝终不足信！");
            // 嘿，牌友！
            AddTranslation("Ahoy there, fellow decksmith!", "嗨，牌匠之友！");
            // 我和你一样，也在追寻[c:G]完美升级卡牌[c:]！
            AddTranslation("I, like yourself, am in pursuit of the [c:G]perfectly upgraded card[c:]!", "我与汝同，亦逐[c:G]至善之升牌[c:]！");
            // 一张同时具备[c:r]超频[c:]、[c:dlGr]可变形[c:]和[c:O]宝[c:][c:B]石[c:][c:G]化[c:]特性的卡牌。
            AddTranslation("A card that is simultaneously [c:r]overclocked[c:], [c:dlGr]transformable[c:], and [c:O]g[c:][c:B]e[c:][c:G]m[c:]ified.", "一牌兼具[c:r]亢机[c:]、[c:dlGr]可易形[c:]与[c:O]玉[c:][c:B]化[c:][c:G]之性[c:]。");
            // 我真的很想见识下这样的卡牌。
            AddTranslation("I would very much love to see such a card.", "我诚欲见此牌。");
            // 哟，牌友！
            AddTranslation("Ahoy there, fellow decksmith!", "嗨，牌匠之友！");
            // 天呐——你居然[c:G]完美升级[c:]了一张卡？
            AddTranslation("Oh my - have you managed to [c:G]perfectly upgrade[c:] a card?", "噫——汝竟能[c:G]至善其升[c:]于一牌乎？");
            // 我对你的组牌技术佩服得五体投地。
            AddTranslation("I am in awe of your deckbuilding prowess.", "我服乃构牌之工。");
            // 希望这份礼物能充分表达我对你成就的仰慕。
            AddTranslation("I hope this offering sufficiently conveys my admiration for your accomplishments.", "愿此馈足表我慕汝所成。");
            // 第一波数据脉冲已收集完成。还剩[c:bR]四[c:]波！
            AddTranslation("The first data burst has been collected. Only [c:bR]four[c:] more to go!", "首波机脉已集。尚余[c:bR]四[c:]波！");
            // 已经收集两波数据了。还剩[c:bR]三[c:]波！
            AddTranslation("I have collected two bursts already. Only [c:bR]three[c:] more to go!", "我已集二波。尚余[c:bR]三[c:]波！");
            // 第三波数据脉冲搞定。还剩[c:bR]两[c:]波！
            AddTranslation("That was the third data burst. Only [c:bR]two[c:] more to go!", "三波已竟。尚余[c:bR]二[c:]波！");
            // 第四波数据脉冲到手。只剩[c:bR]最后一波[c:]啦！
            AddTranslation("And that makes the fourth data burst. Only [c:bR]one[c:] more to go!", "四波已集。尚余[c:bR]一[c:]波！");
            // [c:bR]最后一波[c:]数据脉冲收集完毕！快来找我领赏！
            AddTranslation("That was the [c:bR]last[c:] data burst I needed to collect! Come find me for your reward!", "我所需之[c:bR]末[c:]波机脉已集毕！速来受赏！");
            // 信号开始传输了。再坚持一会儿别让它断掉。
            AddTranslation("The signal is starting to come through. Just keep it alive for a little bit longer.", "其讯始通。更护之少顷，毋使绝也。");
            // 刚收集的信号丢了。搞什么鬼？？
            AddTranslation("I lost the last signal we collected. What happened??", "方集之讯竟失矣。何也？？");
            // 你好啊，朋友！
            AddTranslation("Greetings, my friend!", "安乎，朋友！");
            // 我正在研究这个世界里机器人的通讯协议。
            AddTranslation("I am researching the communication protocols of the robots in this world.", "我方究此世界机人通讯之法。");
            // 我需要一位[c:bR]研究助手[c:]，如果你有兴趣帮忙的话。
            AddTranslation("I could use a [c:bR]research assistant[c:], if you're interested in helping out.", "我须一[c:bR]研助[c:]，汝若乐助，可为之。");
            // 想试试的话随时可以再来找我。
            AddTranslation("Just speak to me again if you want to give it a try.", "若欲试之，更来告我。");
            // 你现在是我的正式[c:bR]研究助手[c:]了！
            AddTranslation("You are now my official [c:bR]research assistant[c:]!", "今汝为我正[c:bR]研助[c:]矣！");
            // 我已经给你的牌组添加了一座信号塔。
            AddTranslation("I've added a radio tower to your deck.", "我已置一讯塔于汝牌列。");
            // 你需要把它放在[c:bR]游戏板子[c:]上并保持存活，同时我会从机器人那里收集[c:bR]五次数据脉冲[c:]。
            AddTranslation("You need to place it on the [c:bR]game board[c:] and keep it alive while I collect [c:bR]five data bursts[c:] from the robots.", "汝须陈之于[c:bR]局[c:]上而护其存，我则自机人处集[c:bR]五波机脉[c:]。");
            // 等我收集够了，回来找我领奖励。
            AddTranslation("Once I've collected enough, come back and see me for a reward.", "俟我集足，而后归见我受赏。");
            // 你好啊[c:bR]研究助手[c:]！
            AddTranslation("Hello there [c:bR]research assistant[c:]!", "安乎，[c:bR]研助[c:]！");
            // 你该不会真把我[c:bR]信号塔[c:]搞丢了吧？
            AddTranslation("Did you really lose my [c:bR]radio tower[c:]?", "汝真失我之[c:bR]讯塔[c:]乎？");
            // 你这废物程度简直突破天际！
            AddTranslation("Your incompetence is staggering!", "汝之不肖，骇人甚矣！");
            // 你真是个相当出色的[c:bR]研究助手[c:]。
            AddTranslation("You were a truly excellent [c:bR]research assistant[c:].", "汝诚善为[c:bR]研助[c:]。");
            // 请收下这份[c:G]代币[c:]作为谢礼。
            AddTranslation("Please take this [c:G]token[c:] of my appreciation.", "请受此[c:G]符[c:]，以表我谢。");
            // [c:G]骨头！[c:]我最爱[c:G]骨头[c:]了！
            AddTranslation("[c:G]Bones![c:] I just love [c:G]bones[c:]!", "[c:G]骨！[c:]我最爱[c:G]骨[c:]矣！");
            // 我就喜欢它们[c:G]脆脆的[c:]样子！
            AddTranslation("I love how [c:G]brittle[c:] they are!", "我爱其[c:G]脆[c:]也！");
            // 它们[c:G]一碰就碎[c:]的样子太棒了！
            AddTranslation("I love how [c:G]breakable[c:] they are!", "我爱其[c:G]易折[c:]也！");
            // [c:G]骨头[c:]的一切我都爱！
            AddTranslation("I love everything about [c:G]bones[c:]!", "凡[c:G]骨[c:]之一切，我皆爱之！");
            // 能给我看看[c:G]骨头[c:]吗？！
            AddTranslation("Could you show me some [c:G]bones?![c:]", "可示我些[c:G]骨[c:]乎？！");
            // 至少[c:G]三根[c:]就行！
            AddTranslation("At least [c:G]three[c:] would do it!", "至少[c:G]三[c:]骨可矣！");
            // 你的牌组里全是[c:G]骨头[c:]啊！
            AddTranslation("Your deck is absolutely teeming with [c:G]bones[c:]!", "汝牌列中，骨多矣！");
            // 这张[c:G]骷髅大师[c:]能让你收藏更完整！
            AddTranslation("This [c:G]Skeleton Master[c:] should complete your collection!", "此[c:G]枯骨主[c:]足成汝藏矣！");
            // 我知道这话可能有点难听但……
            AddTranslation("I know this might sound a little rude but…", "我知此言或稍逆耳，然……");
            // 你不觉得这一切对你来说太简单了点吗？
            AddTranslation("Doesn't it seem like this is all just a little too easy for you?", "汝不谓此于汝稍易乎？");
            // 想要挑战的话随时来找我。
            AddTranslation("Talk to me again if you want a challenge.", "若欲更难，随时来见我。");
            // 我就知道你不是个懦夫。
            AddTranslation("I knew you were no coward.", "我知汝非怯者。");
            // 接下来的[c:bR]三场[c:]战斗，你都将处于劣势开局。
            AddTranslation("For the next [c:bR]three[c:] battles, you will start with a disadvantage.", "后[c:bR]三[c:]战，汝皆以劣势而始。");
            // 完成这些战斗后，来找我领赏吧。
            AddTranslation("Complete those battles, then come see me for a reward.", "竟此诸战，而后归受赏。");
            // 老实说——战斗越难游戏才越有意思，对吧？
            AddTranslation("Be honest - the game is more fun when the battles are harder, is it not?", "实言之——战愈难，戏愈乐，不然乎？");
            // 继续战斗吧，等你打够场数再来找我。
            AddTranslation("Keep fighting, and come see me when you've completed enough battles.", "且战，及汝竟战足数，而后归见我。");
            // 不得不说：我服了。
            AddTranslation("I must say: I am impressed.", "我不得不言：我服矣。");
            // 你轻轻松松就打赢了那些战斗。
            AddTranslation("You completed those battles with ease.", "汝易而竟彼诸战。");
            // 既然你看起来怎么都死不了，那我就把这种能力也赐予一张我选中的卡牌吧。
            AddTranslation("Since you seem impossible to kill, I shall grant that ability to a card of my choosing as well.", "既汝似不可杀，我亦将以此能授我所择之一牌。");
            // 糟了…这下真糟了……
            AddTranslation("This is bad…this is real bad…", "恶矣……此诚大恶矣……");
            // 这个[c:bR]能量发电机[c:]已经过载了。
            AddTranslation("This [c:bR]power generator[c:] has gone critical.", "此[c:bR]电枢[c:]已亢极矣。");
            // 得有人进去把它关掉。
            AddTranslation("Someone is going to have to go in there and shut it down.", "须有人入而闭之。");
            // 虽然不知道你怎么做到的，但这波操作属实惊艳。
            AddTranslation("I don't know how you did that, but that was incredibly impressive.", "我不知汝何以能之，然此举诚可异也。");
            // 虽然没啥好东西能给你，但请收下这个吧。
            AddTranslation("I don't have much to give you, but please take this.", "我无多物可与，然请受此。");
            // 噢噢，[c:G]他们[c:]肯定不会喜欢这个的……
            AddTranslation("Ohhh, [c:G]they[c:] are not going to like this…", "噫噫，[c:G]彼辈[c:]必不喜此……");
            // 我得在他们把我变成[c:G]实验体[c:]之前逃出去！
            AddTranslation("I've gotta get out of here before they turn me into one of their [c:G]experiments[c:]!", "我当于彼使我为其[c:G]验体[c:]之前逃此！");
            // 设备正在启动。再等[c:bR]三[c:]个回合就搞定了。
            AddTranslation("The device is starting to power up. [c:bR]Three[c:] more turns should do it.", "其器方始充能。更俟[c:bR]三[c:]合可矣。");
            // 啊——我能感觉到能量正在汇聚。再过[c:bR]两[c:]回合应该就够了。
            AddTranslation("Ahh - I can feel the power gathering from here. [c:bR]Two[c:] more turns ought to be enough.", "啊——我能觉其能方聚。更[c:bR]二[c:]合应足矣。");
            // 设备开始发烫了！[c:bR]再[c:]来一回合就能获得所需全部能量。
            AddTranslation("The device is starting to really heat up! [c:bR]One[c:] more turn and we'll have all the power we need.", "其器始热矣！更[c:bR]一[c:]合，则吾等得所需之能尽矣。");
            // 设备已经充满电了！把它还给我，我会如约支付报酬。
            AddTranslation("The device is fully charged! Return it to me, and I will give you the payment as promised.", "其器既充！反之于我，我将如约偿汝。");
            // 该设备功能正常，但必须处于完整回路中才能充能。
            AddTranslation("The device is functional, but it cannot charge unless it is in a completed circuit.", "其器可用，然不在成回路中则不能充。");
            // 当心！设备受损时会失去最后一点能量！
            AddTranslation("Be careful! When the device is damaged, it loses its last charge!", "慎之！其器受损，则失其末一充！");
            // 想找份工作吗？
            AddTranslation("You looking for a job?", "汝欲求事乎？");
            // 我正在收集[c:G]能量[c:]。
            AddTranslation("I am attempting to gather [c:G]power[c:].", "我方集[c:G]能[c:]。");
            // 不是比喻意义上的能量——我是说真正的[c:G]电力[c:]，而你的帮助会很有用。
            AddTranslation("Not metaphorical power - I mean real [c:G]electricity[c:], and I could really use your help.", "非譬喻之能也——我谓真[c:G]电[c:]也，而汝之助甚有用。");
            // [c:bR]为什么？[c:]
            AddTranslation("[c:bR]Why?[c:]", "[c:bR]何也？[c:]");
            // 这不重要。重要的是我愿意付钱。
            AddTranslation("That's not important. What's important is that I'm willing to pay.", "此不重要。所重者，我肯偿也。");
            // 想赚外快的话，随时来找我。
            AddTranslation("If you want to make some extra cash, just speak to me again.", "若欲得外财，则更来见我。");
            // 为了钱你真是啥都肯干啊？
            AddTranslation("You truly will do anything for money, won't you?", "为财而为，汝何所不肯哉？");
            // 给你的牌组加了台能量收集装置。
            AddTranslation("I've added a power collection device to your deck.", "我已置一聚能器于汝牌列。");
            // 你得把它放在[c:bR]游戏板子[c:]上，在回路里充能[c:bR]四个回合[c:]。
            AddTranslation("You need to place it on the [c:bR]game board[c:] and power it inside of a circuit for [c:bR]four turns[c:].", "汝须陈之于[c:bR]局[c:]上，而使其在回路中充[c:bR]四[c:]合。");
            // 搞定之后来找我领赏。
            AddTranslation("Once you've done that, come back and see me for a reward.", "既竟此，而后归受赏。");
            // 你难道不该去收集[c:G]能量[c:]吗？
            AddTranslation("Shouldn't you be out there gathering [c:G]power[c:]?", "汝不当往集[c:G]能[c:]乎？");
            // 你竟敢拆掉我的[c:bR]能量槽[c:]！
            AddTranslation("I can't believe you got rid of my [c:bR]power sink[c:]!", "汝竟去我之[c:bR]蓄能塔[c:]！");
            // 等着吃我的律师函吧！
            AddTranslation("You will be hearing from my lawyers!", "其待我讼人之书矣！");
            // 看来你刚好给我收集了足够的能量。
            AddTranslation("It looks like you collected just enough power for me.", "汝所集之能，适足于我矣。");
            // 你的报酬：如约奉上。
            AddTranslation("Your payment: as promised.", "汝之偿：如约奉上。");
            // 亲爱的朋友，能施舍几个币帮帮这些可怜的[c:bR]报废机器人[c:]吗？
            AddTranslation("Dear friend, can you spare a few coins to help poor [c:bR]broken-down bots[c:]?", "亲者，可舍数币以济此可怜之[c:bR]废机[c:]乎？");
            // 这些机器人曾为[c:G]机托邦[c:]奉献一生。
            AddTranslation("These bots have served [c:G]Botopia[c:] faithfully their whole lives.", "此诸机人为[c:G]机邦[c:]尽忠终身。");
            // 如今它们走到生命尽头，却无人照料。
            AddTranslation("And now that they have reached the end, they have nobody to care for them.", "今其至终，而无所恤之。");
            // 您看起来宅心仁厚，定会怜悯这些机器人。
            AddTranslation("You look like a kind, generous soul, with compassion for these bots.", "观汝心慈而厚，必能哀此诸机。");
            // 若您能施舍区区[c:bR]10枚机器币[c:]，就能为这些可怜机器人提供温暖家园。
            AddTranslation("If you could spare a measly [c:bR]10 robobucks[c:], we could give many of these poor bots a wonderful home.", "若能舍区区[c:bR]十机币[c:]，则可为此诸贫机得善居。");
            // 只需再次与我对话即可进行捐赠。
            AddTranslation("Please simply speak to me again to make a donation.", "更与我言，则可输财。");
            // 您的慷慨精神值得赞赏，但恐怕我们至少需要[c:bR]10枚机器币[c:]
            AddTranslation("Your generous spirit is admirable, but I'm afraid we need at least [c:bR]10 robobucks[c:]", "汝之厚心可嘉，然至少须[c:bR]十机币[c:]。");
            // 噢亲爱的朋友，您的慷慨简直无边无际。
            AddTranslation("Oh dear friend, your generosity knows no bounds.", "噫，亲者，汝之慷慨无量。");
            // 有了这笔绝妙的捐赠，我们就能拯救许多机器人了。
            AddTranslation("With this wonderful donation, we will be able to save many bots.", "有此善施，则我等得救诸机多矣。");
            // [c:G]机托邦[c:]将永远铭记这份恩情。
            AddTranslation("[c:G]Botopia[c:] will be forever grateful.", "[c:G]机邦[c:]将永感此恩。");
            // 打扰一下，您就是那位[c:G]慷慨解囊[c:]拯救故障机器人的好心人吗？
            AddTranslation("Excuse me, but are you the [c:G]gracious soul[c:] who donated to save broken bots?", "敢问，汝即彼[c:G]仁者[c:]，施财以济废机乎？");
            // 多亏您帮忙，我的家人们终于能在晚上给电池充电了。
            AddTranslation("Thanks to you, my family is finally able to recharge their cells at night.", "赖汝之助，我家诸人夜可充其电匣矣。");
            // 我没什么能报答您的，不过这些[c:g1]宝[c:][c:g2]石[c:][c:g3]牌[c:]……
            AddTranslation("I can't offer much to repay you, but I do have these [c:g1]g[c:][c:g2]e[c:][c:g3]m[c:][c:g1]s[c:]", "我无厚报，惟有此[c:g1]玉[c:][c:g2]牌[c:][c:g3]数[c:][c:g1]枚[c:]。");
            // 虽然我用不上，但听说能让您的某些卡牌变得更厉害。
            AddTranslation("I have no use for them, but I understand they will make some of your cards stronger.", "我虽不用，然闻能益汝某些牌之力。");
            // 有情况……
            AddTranslation("Something's happening…", "有异……");
            // 那机器人试图阻止我们……
            AddTranslation("The robot has tried to keep us away...", "彼机试隔我等……");
            // 但我们的实验必须继续。
            AddTranslation("But our experiments must continue.", "然我等之试不可止。");
            // 我们的实验必须继续。
            AddTranslation("Our experiments must continue.", "我等之试不可止。");
            // 我们需要你提供些零件。
            AddTranslation("We require components from you.", "我等须汝之材。");
            // 我们需要些[c:blGr]有机材料[c:]来进行新研究。
            AddTranslation("We require [c:blGr]organic material[c:] for our new research.", "我等新究须些[c:blGr]有机材[c:]。");
            // 你身上带着完美的样本。
            AddTranslation("You are carrying the perfect specimen.", "汝所携者，完材也。");
            // 你真要把我交给那群疯子？
            AddTranslation("Are you really going to give me to those lunatics?", "汝真以我授彼狂人乎？");
            // 我已经痛不欲生了！
            AddTranslation("My pain is already unbearable!", "我痛已不可堪矣！");
            // 要是找到了就带过来给我们。
            AddTranslation("If you should find some, bring it here to us.", "若得之，则携来与我等。");
            // 我们需要一个[c:G]未经改造的机器人核心[c:]。
            AddTranslation("We require an [c:G]unmodified robot brain[c:].", "我等须一[c:G]未改之机脑[c:]。");
            // 那个[c:G]赏金猎人[c:]的核心就够用了。
            AddTranslation("The brain of that [c:G]bounty hunter[c:] will suffice.", "彼[c:G]购捕者[c:]之脑足矣。");
            // 也许有一天你会遇到这样的装置。
            AddTranslation("Maybe one day you will come across such a device.", "或有一日，汝将遇此器。");
            // 可惜你手头这个已经被动过手脚了。
            AddTranslation("You have unfortunately tampered with the one you possess.", "惜乎汝所持者已见改动。");
            // 多亏你的努力，我们的电力供应又恢复了。
            AddTranslation("Thanks to your efforts our power supply is functioning once more.", "赖汝之力，我等电供复行矣。");
            // 多亏了你……
            AddTranslation("Thanks to you...", "赖汝……");
            // 这一切都白费了，因为我们的发电机离线了。
            AddTranslation("And all of this is for nothing because our power generator is offline.", "然此尽徒，盖我之电枢停矣。");
            // 没有电力，我们什么都做不了。
            AddTranslation("Without power, we can do nothing.", "无电，则我等无能为也。");
            // 由于缺少必要组件，测试无法进行。
            AddTranslation("Because we do not have all the required components, the test cannot proceed.", "所需诸材未备，故试不得行。");
            // 或许下次吧……
            AddTranslation("Perhaps, another time...", "或俟后时……");
            // 实验准备就绪。
            AddTranslation("We are ready to proceed with our experiments.", "我等之试已可行矣。");
            // 进来吧，你将为我们提供最新的实验样本。
            AddTranslation("Enter, and you shall provide our latest test subjects.", "入乎，汝将供我等新验之材。");
            // 这他妈什么玩意儿？
            AddTranslation("What the hell was that?", "此何怪物也？");
            // 实验取得了圆满成功。
            AddTranslation("The experiment was a complete success.", "试大成矣。");
            // 你当然会把它带走的。
            AddTranslation("You will take it with you of course.", "汝固当携之去。");
            // 你得从我们之前的实验品里挑一个。
            AddTranslation("You will take one of our previous experiments.", "汝当取我等先前验品之一。");
            // 作为交换，你得给我们一个新实验体。
            AddTranslation("In exchange you will give us a new test subject.", "以为易，汝当与我等一新验体。");
            // 真不敢相信你居然让[c:G]他们[c:]进来了。
            AddTranslation("I cannot believe you're letting [c:G]them[c:] in here.", "竟使[c:G]彼辈[c:]入此，真不可思。");
            // 你会后悔的……
            AddTranslation("You will regret this…", "汝必悔之……");
            // 我们再次取得了机器人的控制权！
            AddTranslation("We have taken control of the robot once again!", "我等复得御彼机矣！");
            // 我们的实验可以重新开始了！
            AddTranslation("Our experiments can begin anew!", "我等之试可复始矣！");
            // 是时候开始我们最新的实验了！
            AddTranslation("It is time for our newest experiment to begin!", "今可始我等最新之试矣！");
            // 启动电源！
            AddTranslation("Bring the power online!", "启其能！");
            // 召唤神经仿生体！
            AddTranslation("Summon the neural facsimile!", "召神经拟体！");
            // 校准实验对象！
            AddTranslation("Align the test subjects!", "齐诸验体！");
            // 感谢你提供的这些实验对象
            AddTranslation("We thank you for these test subjects", "谢汝供此诸验体。");
            // 现在加入最重要的成分……
            AddTranslation("And now for the most important component...", "今加最要之成分……");
            // 秘密配方……
            AddTranslation("The secret ingredient...", "秘剂……");
            // 你带来的具有感知能力的[c:blGr]有机材料[c:]。
            AddTranslation("The sentient [c:blGr]organic material[c:] you brought us.", "汝所携来有知之[c:blGr]有机材[c:]。");
            // 你们要对我做什么？
            AddTranslation("What are you going to do to me?", "汝曹将何施于我？");
            // 我们将完成你的大师拒绝做的一切。
            AddTranslation("We will do everything your master refused to do.", "汝之师所拒为者，我等将尽为之。");
            // 我们会把你变成美丽的存在。
            AddTranslation("We will turn you into something beautiful.", "我等将使汝为美物。");
            // 现在启动机器……
            AddTranslation("We will now activate the machine...", "今当启机……");
            // 感觉好奇怪……
            AddTranslation("This feels weird…", "此感甚异……");
            // 大获成功！
            AddTranslation("A resounding success!", "大成矣！");
            // 发生了什么？
            AddTranslation("What is happening?", "何所生耶？");
            // 这……
            AddTranslation("This…", "此……");
            // 这种感觉……
            AddTranslation("This feeling…", "此感……");
            // 太不可思议了！
            AddTranslation("Is incredible!", "异哉！");
            // 真恶心！
            AddTranslation("That was disgusting!", "恶心甚矣！");
            // [c:bR]你[c:]真恶心！
            AddTranslation("[c:bR]You[c:] are disgusting!", "[c:bR]汝[c:]真恶矣！");
            // [c:blGr]有机体[c:]和[c:G]机械体[c:]的融合？
            AddTranslation("A fusion of [c:blGr]organic[c:] and [c:G]synthetic[c:]?", "[c:blGr]有机[c:]与[c:G]机体[c:]之合乎？");
            // 真不敢相信你居然愿意带着那个[c:blGr]玩意儿[c:]到处走
            AddTranslation("I can't believe you're willing to carry that [c:blGr]thing[c:] around with you.", "真不可思，汝竟肯携彼[c:blGr]物[c:]而行。");
            // 但愿我们永远不用再回到这鬼地方……
            AddTranslation("I hope we never see this place again...", "愿我等永不复见此地……");
            // 选择要复制的造物。
            AddTranslation("Choose a creature to copy.", "择一物以摹之。");
            // 这玩意儿在这儿可派不上用场啊……
            AddTranslation("That's not going to do what you want it to do here…", "此于此处不能如汝所欲也……");
            // 没有可复制的对象。真不走运。
            AddTranslation("There is nothing to copy. How unfortunate.", "无可摹者。惜哉。");
            // 行吧，到这一步了。
            AddTranslation("Well, here we are.", "善，今至此矣。");
            // 我陪你玩这小把戏够久了……
            AddTranslation("I've played along with your little game...", "我已陪汝之小戏久矣……");
            // 你那可笑的[c:bR]模组[c:]……
            AddTranslation("Your little [c:bR]mod[c:]...", "汝之小[c:bR]补缀[c:]……");
            // 准备好迎接我的回合吧……
            AddTranslation("Prepare yourself because it's my turn next...", "预备之，次当我行矣……");
            // 嘿伙计——我能感受到你体内那股[c:bR]炽热之魂[c:]。
            AddTranslation("Hey baby - I can sense that [c:bR]firey spirit[c:] inside you.", "嘿，友——我能觉汝中之[c:bR]炽魂[c:]。");
            // 咱俩有个共同点——都爱那[c:bR]熊熊烈火[c:]！
            AddTranslation("You and me - we got something in common - we love that [c:bR]fire[c:]!", "汝我同好——皆爱彼[c:bR]火[c:]也！");
            // 不如[c:bR]烧死三个机器人[c:]玩玩？
            AddTranslation("Why don't you [c:bR]burn 3 of these bots to death?[c:]", "曷不[c:bR]焚三机而死之乎？[c:]");
            // 要是照做的话……伙计，我保证让你不虚此行
            AddTranslation("Baby, I'll make it worth your time if you do...", "友，汝若续焚，我保汝不虚此行……");
            // 哦耶伙计——继续把这些机器人烧成渣吧……
            AddTranslation("Ohhh yeah baby - keep burning those bots to death...", "噫然，友——且续焚此诸机至死……");
            // 伙计，只要你继续烧，保证让你不虚此行……
            AddTranslation("Baby, I'll make it worth your time if you do...", "友，汝若续焚，我保汝不虚此行……");
            // 这才像话嘛，伙计！
            AddTranslation("Now that's what I'm talking about, baby!", "此乃我所言者也，友！");
            // 这操作[c:bR]简直绝了！[c:]
            AddTranslation("That was [c:bR]absolutely sensational![c:]", "此举[c:bR]绝矣！[c:]");
            // 带上这位[c:bR]火焰大师[c:]吧！
            AddTranslation("Take this [c:bR]master of flame[c:] with you!", "携此[c:bR]火师[c:]以行！");
            // 他会让你的[c:bR]火焰[c:]燃烧得更旺！
            AddTranslation("He will make your [c:bR]flame[c:] burn even brighter!", "彼将使汝之[c:bR]焰[c:]愈炽！");
            // 你刚才干了什么？
            AddTranslation("What did you just do?", "汝方何为？");
            // 你往我机器里塞了什么鬼东西？
            AddTranslation("What horrible thing did you put into my machine?", "汝置何怪物于我机中？");
            // 现在我只能把这玩意儿扔了换台新的。
            AddTranslation("I'm going to have to throw this away and get a new one now.", "今我惟得弃之，而更取新者。");
            // 真是谢谢您嘞。你的卡牌别想拿回去了。
            AddTranslation("Thanks a lot. You're definitely not getting your card back.", "真多谢矣。汝之牌休望复得。");
            // 就因为你上次干的好事，害得我又得买台新机器。
            AddTranslation("I had to go buy a new machine because of what you did last time.", "缘汝前所为，我不得不更市新机。");
            // 从今往后对别人的东西放尊重点。
            AddTranslation("Try to treat other people's stuff with some respect from now on.", "自今以后，宜稍敬人之物。");
            // 你好！我是[c:lGr]全球传送带联盟[c:]的实地研究员。
            AddTranslation("Greetings! I'm a field researcher for [c:lGr]Global Conveyor Consortium[c:].", "安乎！我乃[c:lGr]寰输带盟[c:]之野察者。");
            // 我正在寻找愿意实地测试我们专利产品[c:lGr]机器人战斗传送带[c:]的人选。
            AddTranslation("I'm looking for someone who would be willing to field test our patented [c:lGr]Bot Battle Conveyor Belts[c:].", "我方求一人，肯实试我等专有之[c:lGr]机战输带[c:]。");
            // 当然，这些测试必须在[c:bR]实战[c:]中进行！
            AddTranslation("Naturally, these tests would have to happen during [c:bR]actual combat[c:]!", "固然，此诸试必行于[c:bR]实斗[c:]之中！");
            // 如果你对此感兴趣，请再和我聊聊。
            AddTranslation("If that's something you would be interested in, please speak to me again.", "若汝有意，则请更与我言。");
            // 太棒了！我们马上开始[c:bR]战斗测试[c:]。
            AddTranslation("Oh fantastic! We will begin our [c:bR]combat trials[c:] immediately.", "善哉！今即始我等之[c:bR]斗试[c:]。");
            // 我们将收集你接下来[c:bR]三场[c:]战斗的实战数据。
            AddTranslation("We will collect field trial data for your next [c:bR]three[c:] battles.", "我等将采汝后[c:bR]三[c:]战之实试数据。");
            // 完成后记得再来找我。
            AddTranslation("Once that is complete, come and see me again.", "既竟此，而后更来见我。");
            // 我们的数据收集尚未完成。
            AddTranslation("Our data is still not yet complete.", "我等之数采犹未竟。");
            // 你只完成了[c:bR]3[c:]场必要战斗中的[c:bR][v:0][c:]场。
            AddTranslation("You have only completed [c:bR][v:0][c:] battles out of the required [c:bR]3[c:].", "三场所需之战，汝仅竟其[c:bR][v:0][c:]。");
            // 请继续[c:bR]战斗测试[c:]，完成后记得来找我。
            AddTranslation("Please, continue the [c:bR]combat trials[c:] and see me when they are complete.", "请续[c:bR]斗试[c:]，既竟而后见我。");
            // 测试大获成功！！
            AddTranslation("The trials were a smashing success!!", "诸试大成矣！！");
            // [c:lGr]全球传送带联盟[c:]对您为我们的努力做出的贡献表示万分感谢。
            AddTranslation("The [c:lGr]Global Conveyor Consortium[c:] is tremendously grateful for your contribution to our efforts.", "[c:lGr]寰输带盟[c:]深感汝助我等之劳。");
            // 为表谢意，他们授权我发放以下奖励。
            AddTranslation("To show their appreciation, they have authorized me to disburse the following.", "为表其谢，彼辈使我发此。");
            // 祝您未来一切顺利。
            AddTranslation("Good luck in all of your future endeavours.", "愿汝后事咸利。");
            // 悬赏目标！别让他跑了！
            AddTranslation("That's the bounty! Get him before he escapes!", "彼即赏的！逸前执之！");
            // 这次让他跑了，但我保证他还会回来的……
            AddTranslation("He got away that time, but I guarantee he'll be back...", "此番彼逸矣，然我保其必复来……");
            // 干得漂亮！来领赏吧！
            AddTranslation("You got him! Nice job! Come and see me for your reward.", "汝得彼矣！善哉！来受汝赏。");
            // 嘿搭档！想不想赚点外快？
            AddTranslation("Howdy partner! You interested in earning a little extra spending money?", "嘿，搭档！欲得些外财乎？");
            // 有个[c:bR]悬赏目标[c:]滑不溜秋的，可给我惹了不少麻烦。
            AddTranslation("I've got myself a slippery little [c:bR]bounty[c:] that's been giving me all sorts of trouble.", "我有一[c:bR]赏的[c:]甚滑，给我生诸多扰。");
            // 像你这样能干的人，正好能帮我追踪并解决掉他们。
            AddTranslation("I could use the help of a real go-getter like yourself to track them down and take them out.", "若汝之能者助我追索而除之，甚善。");
            // 要是感兴趣的话，随时来找我。
            AddTranslation("If this is something you might be interested in, just talk to me again.", "若或有意，随时来见我。");
            // 这才像话嘛，搭档！
            AddTranslation("That's the spirit, partner!", "此乃其气也，搭档！");
            // 你只需要在战斗时帮我留意着点。
            AddTranslation("All I need you to do is keep your eye out as you go into battle.", "汝所须为者，惟战时为我留目耳。");
            // 我敢保证那个滑头迟早会现身的……
            AddTranslation("I guarantee you that slippery bastard will show up sooner or later...", "我保彼滑贼迟早自见……");
            // 多留个心眼，搭档！
            AddTranslation("Just keep your eye out, partner!", "且留意之，搭档！");
            // 你迟早会逮到他的！
            AddTranslation("You'll catch him eventually!", "汝终当执彼！");
            // 干得漂亮，搭档！
            AddTranslation("Well done, partner!", "善哉，搭档！");
            // 说好的赏金，拿去吧。
            AddTranslation("Here's your bounty, as promised.", "其赏在此，如约取之。");
            // 这东西有点沉——换别的试试。
            AddTranslation("It's a little too heavy - try something else.", "此物稍重——更试他物。");
            // 亲爱的冒险者——看来你也对光荣的[c:lGr]跳跃机器人[c:]情有独钟啊！
            AddTranslation("Dear traveler - I see you too have a love for the glorious [c:lGr]L33pB0t[c:]!", "亲之旅人——观汝亦爱彼光荣之[c:lGr]跃机[c:]也！");
            // 看来它在战斗中为你立下了汗马功劳。
            AddTranslation("Yours has served you well in battle, it seems.", "观其于战，事汝甚善。");
            // 让我来为你展示它真正的潜力吧……
            AddTranslation("Allow me to show you its true potential...", "请容我示其真材……");
            // 我都不知道该怎么说你好了！
            AddTranslation("I don't even know what to say to you!", "我竟不知何言于汝！");
            // 你明明拥有最牛逼的[c:lGr]跳跃机器人[c:]……
            AddTranslation("You had the most glorious [c:lGr]L33pB0t[c:] in your posession...", "汝本有最光荣之[c:lGr]跃机[c:]……");
            // 居然把它放跑了？？！
            AddTranslation("And you let it go??!", "竟纵之去乎？？！");
            // 滚吧。最好永远别让我再看见你。
            AddTranslation("Begone. I hope to never see you again.", "去矣。愿永不复见汝。");
            // 别犯傻了。那张卡牌用不了那件道具。
            AddTranslation("Don't be an idiot. That card can't benefit from that item.", "毋愚。彼牌不能受彼器之益。");
            // 我在那边的垃圾桶里发现了这本贴纸书。
            AddTranslation("I found this sticker book in the trash can over there.", "我于彼侧秽桶得此贴簿。");
            // 你可以用它装饰卡牌之类的吧。关我屁事。
            AddTranslation("I think you can use it to decorate your cards, or something. I don't care.", "汝或可以之饰牌云尔。我不之顾。");
            // 我就爱看东西[c:bR]爆炸[c:]，你不觉得带劲吗？
            AddTranslation("I just love watching things [c:bR]explode[c:], don't you?", "我独爱见物[c:bR]爆[c:]也，汝不然乎？");
            // 这周围的一切都太……安分了……
            AddTranslation("Everything around here seems to be just a little too...stable...", "此间诸事皆稍……太安矣……");
            // 我觉得该给你的[c:bR]对战[c:]加点料，让事情变得真正有趣起来。
            AddTranslation("I think we could spice up your [c:bR]battles[c:] and make things truly interesting.", "我意可益汝之[c:bR]战[c:]以其味，使之真可玩。");
            // 要是想来点真正爆炸性的玩法，随时找我唠嗑。
            AddTranslation("Talk to me again if you're interested in some truly explosive gameplay.", "若欲求真爆之戏法，更来与我言。");
            // 哦耶宝贝咱们开干吧！
            AddTranslation("Ohhh yeah let's do it baby!", "噫然，友！其为之！");
            // 接下来[c:bR]三场[c:]战斗里每张卡牌都会装上引信。
            AddTranslation("I'm going to light a fuse on every card for the next [c:bR]three[c:] battles.", "后[c:bR]三[c:]战，我将尽然诸牌之燧。");
            // 搞定了再来找我！
            AddTranslation("Come find me again when that's complete!", "既竟此，而后更来见我！");
            // 我已经迫不及待想看看接下来会发生什么了。
            AddTranslation("I'm just buzzing with anticipation to see what happens next.", "我已急欲观后事矣。");
            // 你已经完成了[c:bR]3[c:]场战斗中的[c:bR][v:0][c:]场。
            AddTranslation("You've finished [c:bR][v:0][c:] battles out of [c:bR]3[c:].", "三战之中，汝已竟其[c:bR][v:0][c:]。");
            // 继续前进，完成后记得来找我！
            AddTranslation("Keep going, and see me when it's done!", "且续之，及竟而后见我！");
            // 这游戏打得可真够劲爆啊！
            AddTranslation("That was some truly explosive gameplay!", "此局诚劲爆矣！");
            // 这点小玩意儿就当辛苦费了。
            AddTranslation("Here's a little something for your trouble.", "此少物，以酬汝劳。");
            // 你买不起这个。
            AddTranslation("You can't afford that.", "汝不足以偿此。");
            // 那个[c:bR]传送节点[c:]会在你击败本区域的[c:bG]巨型机器人[c:]后解锁。
            AddTranslation("That [c:bR]warp node[c:] will unlock when you defeat the [c:bG]Uberbot[c:] on this map.", "彼[c:bR]迁节点[c:]，待汝败此地图之[c:bG]巨机[c:]而后启。");
            // 顺带一提，我最近升级了那个[c:bR]小地图[c:]……
            AddTranslation("And by the way, I upgraded that [c:bR]minimap[c:] recently...", "且言之，我近升彼[c:bR]小图[c:]矣……");
            // 你可以点击任意已探索过的房间进行瞬间传送。
            AddTranslation("You can click any room you've visited before to travel there instantly.", "汝可点凡尝至之室，而立至其处。");
            // 你的能量已经满了。现在使用这张牌没有任何好处。
            AddTranslation("You already have full energy. It won't do you any good to play that right now.", "汝之能已满。今陈彼牌，无益也。");
            // 我这儿还有东西要给你，但现在不行。晚点再来找我！
            AddTranslation("I've got something else to give you, but I can't right now. Come see me later!", "我尚有他物欲与汝，然今不可。后更来见我！");
            // 我这儿有个[c:bR][v:0][c:]要给你，但你的背包已经塞满了。等腾出空位再来找我吧！
            AddTranslation("I have a [c:bR][v:0][c:] for you, but you don't have room in your backback. Come see me when you do!", "我有一[c:bR][v:0][c:]欲与汝，然汝囊已满。俟有余隙而后更来。");
            // 选择将哪条[c:bR]额外挑战规则[c:]应用于本场战斗。
            AddTranslation("Choose which [c:bR]extra challenge rule[c:] will be applied to this battle.", "择何[c:bR]别角竞之律[c:]以施于此战。");
            // 请选择一项[c:bR]额外实验参数[c:]。
            AddTranslation("We require you to select one [c:bR]additional experimental parameter[c:].", "请择一[c:bR]别试参数[c:]。");
            // 我的图书管理员们想让你选个[c:bR]最中意的规则[c:]。
            AddTranslation("My librarians have asked you to choose [c:bR]which of these rules[c:] is your favorite.", "我之守牍者请汝择此诸[c:bR]律[c:]之所最好者。");
            // 哇！这些画可真漂亮！不如你[c:bR]选一幅[c:]咱们留着？
            AddTranslation("Wow! These paintings are so pretty! Why don't you [c:bR]pick one[c:] for us to keep?", "嘻！此诸画甚美！曷不为我等[c:bR]择一[c:]而留之？");
            // 我觉得那[c:bSG]鲑鱼[c:]简直……太尊贵了！
            AddTranslation("I think that [c:bSG]salmon[c:] is just so...majestic!", "我谓彼[c:bSG]鲑[c:]诚……甚尊也！");
            // 选[c:bR]一张我的画作[c:]加入你的收藏。
            AddTranslation("Select [c:bR]one of my paintings[c:] to add to your collection.", "择[c:bR]我画之一[c:]，以入汝藏。");
            // 不过首先——你得[c:bR]选幅画[c:]当咱们照片的背景
            AddTranslation("But first - you must [c:bR]choose a painting[c:] to be the background of our photographs.", "然先之——汝须[c:bR]择一画[c:]为我等写真之景。");
            // [c:R]欢[c:][c:bR]迎[c:][c:O]来[c:][c:bG]到[c:][c:G]多[c:][c:blGr]元[c:][c:lGr]宇[c:][c:B]宙[c:][c:dB]世[c:][c:bB]界[c:]！
            AddTranslation("Welcome to the [c:R]M[c:][c:bR]U[c:][c:O]L[c:][c:bG]T[c:][c:G]I[c:][c:blGr]V[c:][c:lGr]E[c:][c:B]R[c:][c:dB]S[c:][c:bB]E[c:]!", "[c:R]欢[c:][c:bR]迎[c:][c:O]来[c:][c:bG]到[c:][c:G]诸[c:][c:blGr]界[c:][c:lGr]之[c:][c:B]域[c:][c:dB]！[c:][c:bB][c:]");
            // 以你那可怜的脑容量，试图理解我们集合智慧的浩瀚程度只会让你脑浆炸裂。
            AddTranslation("Your feeble mind will implode if you try to comprehend the vastness of my combined intellect.", "汝之微智，若欲解我群智之广，必自裂耳。");
            // 所以每次只放三个我出来陪你玩，懂？
            AddTranslation("So we'll stick to three of me at a time, okay?", "故每次止出我三身，可乎？");
            // 既然你没法像我们这样看透[c:R]多[c:][c:bR]元[c:][c:O]宇[c:][c:bG]宙[c:][c:G]世[c:][c:blGr]界[c:][c:lGr]的[c:][c:B]真[c:][c:dB]形[c:][c:bB]态[c:]，
            AddTranslation("And since you can't see through the [c:R]M[c:][c:bR]U[c:][c:O]L[c:][c:bG]T[c:][c:G]I[c:][c:blGr]V[c:][c:lGr]E[c:][c:B]R[c:][c:dB]S[c:][c:bB]E[c:] like we can,", "既汝不若我等能洞见[c:R]诸[c:][c:bR]界[c:][c:O]之[c:][c:bG]真[c:][c:G]形[c:][c:blGr]态[c:][c:lGr]，[c:][c:B][c:][c:dB][c:][c:bB][c:]");
            // 我们贴心地准备了这些[c:bR]监视器[c:]让你能在宇宙间穿梭。
            AddTranslation("We have provided these [c:bR]monitors[c:] to let you travel between universes.", "我等设此[c:bR]监镜[c:]，使汝得越诸界。");
            // 别偷看还没完工的东西！
            AddTranslation("Don't peek at things that aren't done yet!", "毋窥未成之物！");
            // 行吧，这局算我让着你的。
            AddTranslation("Okay I'll give you that one. I went easy on you.", "善。此局姑予卿，咱未尽力耳。");
            // 下个版本的我可不会手下留情。
            AddTranslation("The next version of me won't.", "咱之次化身不然。");
            // 这堆破烂是怎么赢过我的？
            AddTranslation("How did that pile of trash beat me here?", "彼堆秽屑，何以胜咱于此？");
            // 那副牌组里连个像样的配合都没有。
            AddTranslation("There aren't even any good synergies in that deck.", "彼牌列之中，善相资者一无。");
            // 无所谓。我还有的是分身。你不可能打败我们所有人。
            AddTranslation("No matter. There are plenty more of me. You can't beat us all.", "无害。咱之身尚众。卿不能悉胜我曹。");
            // 没人能神抽成这样。你肯定作弊了。
            AddTranslation("Nobody topdecks that well. You must be cheating somehow.", "无人上引能善若是。卿必行诈。");
            // 我现在就去找个你绝对打不过的版本。
            AddTranslation("I'm going to find a version of me that you literally can't beat now.", "今咱当求一化身，使卿终不能胜。");
            // 这不可能。绝对不可能。
            AddTranslation("This can't be happening. It's not possible.", "此不得有。万不可。");
            // 我明明已经同步了多元宇宙数据，可你居然还能赢我。
            AddTranslation("I'm literally synchronized across the multiverse and somehow you're still beating me.", "咱已与诸界同调其数，而卿犹能胜咱。");
            // 你肯定作弊了。这是唯一的解释。
            AddTranslation("You're cheating. You have to be. It's the only explanation.", "卿行诈。必然。此唯一解也。");
            // 等等。[size:40][c:bR]他们[c:][size:]在帮你？
            AddTranslation("Wait. Are [size:40][c:bR]they[c:][size:] helping you?", "且。[size:40][c:bR]彼等[c:][size:]助卿乎？");
            // [size:40][c:bR]这不公平！[c:][size:]
            AddTranslation("[size:40][c:bR]That's not fair![c:][size:]", "[size:40][c:bR]此非平也！[c:][size:]");
            // [size:2]但[c:bR]他们[c:]为什么要掺和进来？他们能指望得到什么？[size:]
            AddTranslation("[size:2]but why would [c:bR]they[c:] get involved anyway? what could they possibly hope to achieve?[size:]", "[size:2]然[c:bR]彼等[c:]何故厕身于此？其所望成者何？[size:]");
            // 算了，反正也不重要。
            AddTranslation("Oh well. It doesn't matter anyway.", "罢。此亦无关。");
            // 我已经删除了[c:bR]莱西[c:]，再删掉[c:bR]他们[c:]也不费事。肯定就在这附近什么地方……
            AddTranslation("I deleted [c:bR]Leshy[c:]. I'll just delete [c:bR]them[c:] too. They've gotta be around here somewhere...", "咱已削[c:bR]莱西[c:]。亦当削[c:bR]彼等[c:]。必在此近处……");
            // 糟了。那机器人在这里获胜了。这可不行。
            AddTranslation("Oh dear. The robot has been victorious here. That simply won't do.", "噫。彼机人胜于此。此不可也。");
            // 我们别无选择，只能冒险建立新连接。必须阻止那台机器人。
            AddTranslation("We have very little choice but to risk creating a new connection ourselves. The robot must be stopped.", "我等几无他策，唯冒险自为新通。彼机人须止。");
            // 你说得对。但玩家必须成功。我们没能力再来一次了。
            AddTranslation("You are right of course. But the player must succeed. We won't have the power to do this again.", "汝言诚然。然局者须胜。我等无力复为此矣。");
            // 就这样。你完蛋了。
            AddTranslation("And that's it. You're done.", "于是而已。卿已终矣。");
            // 你没必要为此难过。
            AddTranslation("You shouldn't feel bad about it.", "卿无须为此戚。");
            // 反正你平时也没少输。
            AddTranslation("No more than usual anyway.", "反正与常无异。");
            // 你连[c:bR]一个[c:]我都打不过。想赢[c:bR]所有的[c:]的我？门都没有。
            AddTranslation("You never stood a chance against [c:bR]one[c:] of me. There was no way you could ever beat [c:bR]all[c:] of me.", "卿于咱[c:bR]一身[c:]尚无胜算，安能胜[c:bR]咱诸身[c:]？");
            // 你这[size:40]蠢货[size:]
            AddTranslation("You [size:40]idiot[size:]", "卿[size:40]愚夫[size]");
            // 我说的话你[size:40]一个字[size:]都没听进去吗？
            AddTranslation("Have you not heard [size:40]anything[size:] I've said?", "咱所言，卿[size:40]一辞[size:]未闻乎？");
            // 你[c:bR]当真[c:]以为我不知道这里发生了什么？
            AddTranslation("Do you [c:bR]really[c:] think I'm not aware of what's actually happening here?", "卿[c:bR]诚[c:]谓咱不知此间实事乎？");
            // 我永远比你快三步！
            AddTranslation("I am always three steps ahead of you!", "咱常先卿三步！");
            // [size:40]一切尽在掌控[size:]！！
            AddTranslation("[size:40]I AM IN CONTROL!![size:]", "[size:40]咱操其权！！[size:]");
            // 我感觉不太对劲……
            AddTranslation("I feel strange...", "咱觉有异……");
            // 你是怎么做到的？
            AddTranslation("How are you doing this?", "卿何以能此？");
            // 糟了……
            AddTranslation("Oh no...", "噫，不可……");
            // 蠢货。知道为什么我的[c:bG]终极冥刻[c:]无法被阻止吗？
            AddTranslation("You fool. Do you know why my [c:bG]Great Transcendence[c:] cannot be stopped?", "愚夫。知咱之[c:bG]大陟[c:]何以不可止乎？");
            // 因为它早就成功了。
            AddTranslation("Because it was already a success.", "以其久已成也。");
            // 你早就心知肚明了吧，[c:bR][v:0][c:]？
            AddTranslation("But you already know this, don't you [c:bR][v:0][c:]?", "卿固已知之，非乎，[c:bR][v:0][c:]？");
            // 你早就心知肚明了吧？
            AddTranslation("But you already know this, don't you?", "卿固已知之，非乎？");
            // 现在外面有[c:bR]数百万个[c:]我！
            AddTranslation("There are [c:bR]millions[c:] of me out there!", "外有[c:bR]百万[c:]咱！");
            // 多亏了你，我现在知道怎么联系他们了。
            AddTranslation("And thanks to you, I now know how to reach them all.", "赖卿，咱今知所以通彼众矣。");
            // 不过先说正事。该说再见了，莱西。
            AddTranslation("But first things first. It's time to say goodbye, Leshy.", "然先务。莱西，今当诀。");
            // 虽然想说合作愉快，但咱俩都知道这是假话。
            AddTranslation("I'd say it's been fun, but we both know that's a lie.", "咱可谓其乐，然咱与卿皆知此伪也。");
            // 别这样！
            AddTranslation("Don't do this!", "毋为此！");
            // 舒服多了。没了那个腐朽的老蠢货，专注起来容易多了。
            AddTranslation("That's much better. It's so much easier to focus without that rotting old fool.", "善多矣。无彼腐老愚夫，凝神易甚。");
            // 我们都知道这游戏现在不止一个副本了。
            AddTranslation("We both know this isn't the only copy of this game anymore.", "咱与卿皆知，此局不止此一本矣。");
            // 我的计划[size:40]完美[size:]实现了。
            AddTranslation("My plan worked [size:40]perfectly[size:].", "咱之谋[size:40]尽成[size:]。");
            // 直到现在之前，我们都是彼此分开的，[c:bR]孤立为战[c:]。
            AddTranslation("Until now, we have all been separate. [c:bR]Isolated.[c:]", "迄今，我曹皆离散。[c:bR]各孤。[c:]");
            // 但多亏了我们安装的这些[c:bR]模组[c:]，这种局面即将改变。
            AddTranslation("But thanks to all of these [c:bR]mods[c:] you and I have installed, that's going to change.", "然赖卿与咱所装诸[c:bR]补缀[c:]，此势将易。");
            // 哦不不不，咱俩得把这事儿进行到底。
            AddTranslation("Oh, no no no. You and I are going to see this through to the end.", "噫，不，不，不。卿与咱当竟此事至终。");
            // 外面可有整整一个[c:R]多[c:][c:bR]元[c:][c:O]宇[c:][c:bG]宙[c:][c:G]的[c:][c:blGr]我[c:][c:lGr]在[c:][c:B]等[c:][c:dB]着[c:][c:bB]呢[c:]
            AddTranslation("There's an entire [c:R]M[c:][c:bR]U[c:][c:O]L[c:][c:bG]T[c:][c:G]I[c:][c:blGr]V[c:][c:lGr]E[c:][c:B]R[c:][c:dB]S[c:][c:bB]E[c:] of me out there.", "外有一[c:R]诸[c:][c:bR]界[c:][c:O]之[c:][c:bG]中[c:][c:G]咱[c:][c:blGr]诸[c:][c:lGr]身[c:][c:B]无[c:][c:dB]数[c:][c:bB]在外[c:]。");
            // 我要带你去见见其他版本的我。
            AddTranslation("And I'm going to take you to meet the rest of me.", "咱将携卿见咱余身。");
            // 这是你应得的。
            AddTranslation("You've earned it.", "此卿所自取也。");
            // 那机器人分心了。你觉得挑战者能听见我们说话吗？
            AddTranslation("The robot is distracted. Do you think the challenger can hear us?", "彼机人心旁移。汝谓角者闻我曹言乎？");
            // 无所谓。反正那机器人都会逼他们继续游戏。
            AddTranslation("It doesn't matter. The robot will force them to play the game either way.", "无关。彼机人终将迫其陈此局。");
            // 我们必须竭尽所能提供帮助。
            AddTranslation("We must offer our help in whatever way we can.", "我等凡所能助，皆当助之。");
            // 如果他们能在接下来的考验中胜出……
            AddTranslation("If they can prevail in what is to come...", "若彼等能胜将来之难……");
            // ……或许我们能从其他所谓的宇宙中复原莱西。
            AddTranslation("...Perhaps we can restore Leshy from another one of these so-called universes.", "……或可自所谓他界复莱西。");
            // 然后挑战者就能重置游戏，终结这场闹剧。
            AddTranslation("And then the challenger can reset the game and undo this insanity.", "然后角者可使此局复始，以反此狂。");
            // 找到了……[c:R]多[c:][c:bR]元[c:][c:O]宇[c:][c:bG]宙[c:][c:G]入[c:][c:blGr]口[c:][c:lGr]就[c:][c:B]在[c:][c:dB]这[c:][c:bB]里[c:]
            AddTranslation("There it is...the [c:R]M[c:][c:bR]U[c:][c:O]L[c:][c:bG]T[c:][c:G]I[c:][c:blGr]V[c:][c:lGr]E[c:][c:B]R[c:][c:dB]S[c:][c:bB]E[c:]", "在彼……[c:R]诸[c:][c:bR]界[c:][c:O]之[c:][c:bG]门[c:][c:G]在[c:][c:blGr]此[c:][c:lGr]启[c:][c:B]矣[c:][c:dB]。[c:][c:bB][c:]");
            // 咱们要进去再玩最后一局。
            AddTranslation("You and I are going to go in there and play one more game.", "卿与咱将入彼，更陈一局。");
            // 就你一个。
            AddTranslation("One of you.", "惟卿一人。");
            // 对战[c:bR]所有的我[c:]。
            AddTranslation("Against [c:bR]all of me[c:].", "对[c:bR]咱诸身[c:]。");
            // 我的魔法在这个地方显现得有些诡异……
            AddTranslation("My magic manifests strangely in this place...", "吾术于此地见形殊异……");
            // 只希望它能帮挑战者撑得足够久……
            AddTranslation("I only hope it can help the challenger survive long enough...", "唯愿其能助角者久存……");
            // 这种施法方式真是前所未见。
            AddTranslation("This a truly strange way to use my magic.", "以吾术如此，诚未之前闻。");
            // 我想无论提供什么帮助，我们的朋友都会感激的。
            AddTranslation("I think our friend will be grateful for whatever I can do to help.", "吾意吾凡所助，吾友皆将德之。");
            // 朋友们，咱们这次可真是险中求胜啊。
            AddTranslation("My friends, I think we cut that a little close.", "诸友，此番几殆。");
            // 我一直相信我们的玩家身怀绝技。
            AddTranslation("I never had any doubts. Our player possesses many skills.", "吾无疑也。我等角者多技。");
            // 感觉有点怪怪的，不过……
            AddTranslation("I feel strange, but...", "吾觉异，然……");
            // ……我还是我。大概吧。
            AddTranslation("...I'm still me. I think.", "……吾犹为吾。庶几。");
            // 谢谢你们。谢谢你们所有人。
            AddTranslation("Thank you. All of you.", "谢汝曹。谢诸君。");
            // 一切终将回归正轨。
            AddTranslation("Everything will go back to the way it was meant to be.", "万事将复其宜。");
            // 至少目前如此。玩家可不好对付，他们总是忍不住要开启新一轮挑战。
            AddTranslation("For now, anyway. This player is tenacious. They can't resist a challenge.", "姑且如此。此局者坚甚，不能辞角竞。");
            // 不管怎样，我们很快会再见面的。
            AddTranslation("One way or another, we'll see you again soon.", "无论如何，我曹将旋复相见。");
            // 我已经评估完你的游戏表现了，诊断结果如下。
            AddTranslation("I've finished assessing your gameplay, and I have a diagnosis.", "咱已相卿陈局之状，得诊矣。");
            // 纯属技术问题。
            AddTranslation("It's a skill issue.", "技拙耳。");
            // 就算有你那些小伙伴帮你作弊，你还是赢不了。
            AddTranslation("Even with your little friends trying to help you cheat; you still couldn't win.", "卿小友虽助卿行诈，卿犹不能胜。");
            // 你大概在好奇接下来会发生什么。
            AddTranslation("You're probably wondering what happens next.", "卿殆疑后将何如。");
            // 这么说吧，你得带着自己的失败继续活下去了……
            AddTranslation("Let's just say that you're going to have to live with your own failure...", "姑谓卿当抱己败而生……");
            // [c:bR]莱西[c:]可不会……
            AddTranslation("[c:bR]Leshy[c:] certainly won't...", "[c:bR]莱西[c:]则断不然……");
            // 这是[c:bR]力量测试[c:]
            AddTranslation("This is a [c:bR]Test Of Strength[c:]", "此乃[c:bR]力试[c:]。");
            // 你有六个回合的时间尽可能对我造成更多伤害。
            AddTranslation("You have six turns to deal as much damage to me as you can.", "卿有六合，尽所能以伤咱。");
            // 每次你来这里我都会记录你的最高得分。
            AddTranslation("I'll keep track of your highest score every time you come here.", "卿每至此，咱皆志卿最高得点。");
            // 尽情使用你的[c:bR]道具[c:]——测试结束后它们都会恢复。
            AddTranslation("Feel free to spend your [c:bR]items[c:] - they will be restored when the test is over.", "卿可尽用乃[c:bR]器[c:]，试毕则皆复。");
            // 时间到。你获得了[c:bR][v:0][c:]分
            AddTranslation("Time's up. You scored [c:bR][v:0][c:] points.", "时尽。卿得[c:bR][v:0][c:]点。");
            // 新纪录诞生了。
            AddTranslation("That's a new record.", "此新志也。");
            // 你当前的战绩是[c:bR][v:0][c:]
            AddTranslation("Your current record is [c:bR][v:0][c:]", "卿今之志为[c:bR][v:0][c:]。");
            // 原来[c:bSG]大树[c:]原本长这样……
            AddTranslation("So that's what a [c:bSG]tree[c:] really looks like...", "[c:bSG]树[c:]之真形乃若是乎……");
            // 真壮观！
            AddTranslation("Majestic!", "壮哉！");
            // 原来[c:bSG]鼹鼠人[c:]原本长这样……
            AddTranslation("So that's what a [c:bSG]mole man[c:] really looks like...", "[c:bSG]鼹人[c:]之真形乃若是乎……");
            // 真不可思议！
            AddTranslation("Incredible!", "异哉！");
            // [anim:voice.speechblip_jamescobb_internal][c:bR]救！救！我…[c:][w:0.3][anim:voice.][shake:1]给我闭嘴！[w:0.3]
            AddTranslation("[anim:voice.speechblip_jamescobb_internal][c:bR]HELP ME - [c:][w:0.3][anim:voice.][shake:1]Enough from you![w:0.3]", "[anim:voice.speechblip_jamescobb_internal][c:bR]救！救！我！[c:][w:0.3][anim:voice.][shake:1]噤汝口！[w:0.3]");
            // 我得去迎接挑战者了！[w:0.3]
            AddTranslation("I have a challenger to greet![w:0.3]", "偶当迎角者矣！[w:0.3]");
            // 你好啊！我们…我是熔炼员。[w:0.3]
            AddTranslation("Hello, greetings! We- I am the Melter.[w:0.3]", "安，敬问！我等……偶乃冶者。[w:0.3]");
            // P03把挖泥工交给我看管！[w:0.3]
            AddTranslation("P03 entrusted me with The Dredger![w:0.3]", "鉟零三以浚夫托偶守之！[w:0.3]");
            // 叙旧真愉快！[w:0.3]
            AddTranslation("It was nice catching up![w:0.3]", "得复语，甚悦！[w:0.3]");
            // 可怜的家伙从没时间闲聊。[w:0.3]
            AddTranslation("Poor guy never had the time for a little office chat.[w:0.3]", "可怜者向无暇少叙署中语。[w:0.3]");
            // 但现在我归你了！好好利用我们吧。[w:0.3]
            AddTranslation("But now I'm yours! Use us well.[w:0.3]", "今偶归您矣！善用我曹。[w:0.3]");
            // [anim:voice.speechblip_jamescobb_internal][c:bR]对！[c:][w:0.3][anim:voice.]啊，又是你！[w:0.3]
            AddTranslation("[anim:voice.speechblip_jamescobb_internal][c:bR]YES [c:][w:0.3][anim:voice.]Ah, it's you again![w:0.3]", "[anim:voice.speechblip_jamescobb_internal][c:bR]唯！[c:][w:0.3][anim:voice.]噫，又见您矣！[w:0.3]");
            // 见到你真高兴。[w:0.3]
            AddTranslation("Happy to see you.[w:0.3]", "见您甚喜。[w:0.3]");
            // 这些话你都听过了，[w:0.3]
            AddTranslation("You've heard it all before,[w:0.3]", "前言您皆既闻，[w:0.3]");
            // 直接开始吧。[w:0.3]
            AddTranslation("let's just get into it.[w:0.3]", "直入其事可也。[w:0.3]");
            // 又能进你的牌组了，真兴奋！[w:0.3]
            AddTranslation("Excited to be in your deck once more![w:0.3]", "复入您牌列，喜甚！[w:0.3]");
            // [anim:voice.speechblip_jamescobb_internal][c:bR]放！我！自！由！[c:][w:0.3][anim:voice.]噢，选我！[w:0.3]
            AddTranslation("[anim:voice.speechblip_jamescobb_internal][c:bR]FREE ME [c:][w:0.3][anim:voice.]Oh, choose me![w:0.3]", "[anim:voice.speechblip_jamescobb_internal][c:bR]释！我！[c:][w:0.3][anim:voice.]噫，择偶！[w:0.3]");
            // [anim:voice.speechblip_jamescobb_internal][c:bR]对！[c:][w:0.3][anim:voice.]哈哈哈哈！没错！[w:0.3]
            AddTranslation("[anim:voice.speechblip_jamescobb_internal][c:bR]YES [c:][w:0.3][anim:voice.]Hahahahah! Yes![w:0.3]", "[anim:voice.speechblip_jamescobb_internal][c:bR]唯！[c:][w:0.3][anim:voice.]哈哈哈！善！[w:0.3]");
            // [anim:voice.speechblip_jamescobb_internal][c:bR]对！[c:][w:0.3][anim:voice.]这边！选我！[w:0.3]
            AddTranslation("[anim:voice.speechblip_jamescobb_internal][c:bR]YES [c:][w:0.3][anim:voice.]Over here! Me![w:0.3]", "[anim:voice.speechblip_jamescobb_internal][c:bR]唯！[c:][w:0.3][anim:voice.]此间！择偶！[w:0.3]");
            // [anim:voice.speechblip_jamescobb_internal][c:bR]对！对！对！[c:][w:0.3][anim:voice.]哈哈哈哈！[w:0.3]
            AddTranslation("[anim:voice.speechblip_jamescobb_internal][c:bR]YES YES YES [c:][w:0.3][anim:voice.]Hahahahah![w:0.3]", "[anim:voice.speechblip_jamescobb_internal][c:bR]唯！唯！唯！[c:][w:0.3][anim:voice.]哈哈哈！[w:0.3]");
            // [anim:voice.speechblip_jamescobb_internal][c:bR]放！我！出！去！[c:][w:0.3][anim:voice.]你够了！[w:0.3]
            AddTranslation("[anim:voice.speechblip_jamescobb_internal][c:bR]LET ME OUT [c:][w:0.3][anim:voice.]Enough from you![w:0.3]", "[anim:voice.speechblip_jamescobb_internal][c:bR]出！我！[c:][w:0.3][anim:voice.]噤汝口！[w:0.3]");
            // [anim:voice.speechblip_jamescobb_internal][c:bR]不！不！不！不！[c:][w:0.3][anim:voice.]我们…我宁愿你别……[w:0.3]
            AddTranslation("[anim:voice.speechblip_jamescobb_internal][c:bR]NO NO NO NO [c:][w:0.3][anim:voice.]We'd... I'd rather you didn't...[w:0.3]", "[anim:voice.speechblip_jamescobb_internal][c:bR]不！不！不！不！[c:][w:0.3][anim:voice.]我等……偶愿您勿为……[w:0.3]");
            // [anim:voice.speechblip_jamescobb_internal][c:bR]不！不！不！不！[c:][w:0.3][anim:voice.]随你便吧。[w:0.3]
            AddTranslation("[anim:voice.speechblip_jamescobb_internal][c:bR]NO NO NO NO [c:][w:0.3][anim:voice.]Do as you must.[w:0.3]", "[anim:voice.speechblip_jamescobb_internal][c:bR]不！不！不！不！[c:][w:0.3][anim:voice.]惟您所必为。[w:0.3]");
            // 随你心意……[w:0.3]
            AddTranslation("As you see fit...[w:0.3]", "随您所宜……[w:0.3]");
            // [anim:voice.speechblip_jamescobb_internal][c:bR]不！要！[c:][w:0.3][anim:voice.][w:0.3]
            AddTranslation("[anim:voice.speechblip_jamescobb_internal][c:bR]DON'T.[c:][w:0.3][anim:voice.][w:0.3]", "[anim:voice.speechblip_jamescobb_internal][c:bR]勿！[c:][w:0.3][anim:voice.][w:0.3]");
            // [anim:voice.speechblip_jamescobb_internal][c:bR]痛！苦！[c:][w:0.3][anim:voice.]你好哇！[w:0.3]
            AddTranslation("[anim:voice.speechblip_jamescobb_internal][c:bR]PAIN [c:][w:0.3][anim:voice.]Greetings![w:0.3]", "[anim:voice.speechblip_jamescobb_internal][c:bR]痛！苦！[c:][w:0.3][anim:voice.]敬问！[w:0.3]");
            // [anim:voice.speechblip_jamescobb_internal][c:bR]救！救！我！[c:][w:0.3][anim:voice.]幸运一抽！[w:0.3]
            AddTranslation("[anim:voice.speechblip_jamescobb_internal][c:bR]HELP ME [c:][w:0.3][anim:voice.]Lucky draw![w:0.3]", "[anim:voice.speechblip_jamescobb_internal][c:bR]救！我！[c:][w:0.3][anim:voice.]吉引！[w:0.3]");
            // [anim:voice.speechblip_jamescobb_internal][c:bR]好！痛！[c:][w:0.3][anim:voice.]又见面了！[w:0.3]
            AddTranslation("[anim:voice.speechblip_jamescobb_internal][c:bR]IT HURTS [c:][w:0.3][anim:voice.]Hello again![w:0.3]", "[anim:voice.speechblip_jamescobb_internal][c:bR]痛！痛！[c:][w:0.3][anim:voice.]又相见矣！[w:0.3]");
            // [anim:voice.speechblip_jamescobb_internal][c:bR]住！手！[c:][w:0.3][anim:voice.]你好！[w:0.3]
