            AddTranslation("[anim:voice.speechblip_jamescobb_internal][c:bR]HAHAHAHAH [c:][w:0.3][anim:voice.]Things are heating up![w:0.3]", "[anim:voice.speechblip_jamescobb_internal][c:bR]哈！哈！哈！哈！哈！[c:][w:0.3][anim:voice.]事势渐燠矣！[w:0.3]");
