            AddTranslation("[anim:voice.speechblip_jamescobb_internal][c:bR]IT IS TIME! [c:][w:0.3][anim:voice.]Oh this is fun![w:0.3]", "[anim:voice.speechblip_jamescobb_internal][c:bR]时！至！矣！[c:][w:0.3][anim:voice.]噫，此甚乐！[w:0.3]");
