            AddTranslation("When you sacrifice a beast card, you increase your max energy and gain an energy cell.", "汝祀一兽牌，则能极益，而得一能格。");
            // 当装备该奖励时，当你献祭一张野兽卡牌时，你将增加你的最大能量并获得一个能量槽。
            AddTranslation("With this boon equipped, When you sacrifice a beast card, you increase your max energy and gain an energy cell.", "有此惠，则汝祀一兽牌，能极益，而得一能格。");
            // 轮回之奖
            AddTranslation("Boon of Reincarnation", "轮回之惠");
            // 你献祭骷髅卡牌时，获得一张松鼠牌。
            AddTranslation("When a Skeleton is sacrificed, draw a squirrel.", "祀一枯骨，则引一松鼠。");
            // 当装备该奖励时，你献祭骷髅卡牌时，获得一张松鼠牌。
            AddTranslation("With this boon equipped, When a Skeleton is sacrificed, draw a squirrel.", "有此惠，则祀一枯骨，引一松鼠。");
            // 死灵之奖
            AddTranslation("Boon of Necromancy", "死灵之惠");
            // 当一张骷髅死亡时，将在其位置生成一张随机玛珂牌。
            AddTranslation("When a Skeleton dies, a random mox is placed in it's place.", "一枯骨死，则其位生一偶玛珂。");
            // 当装备该奖励时，当一张骷髅死亡时，将在其位置生成一张随机玛珂牌。
            AddTranslation("With this boon equipped, When a Skeleton dies, a random mox is placed in it's place.", "有此惠，则一枯骨死，其位生一偶玛珂。");
            // 碎屑之奖
            AddTranslation("Boon of Scrap", "废屑之惠");
            // 每当你达到满能量时，你就会获得一块骨头。
            AddTranslation("Whenever you reach full energy, you gain a bone.", "汝能既满，则得一骨。");
            // 当装备该奖励时，每当你达到满能量时，你就会获得一块骨头。
            AddTranslation("With this boon equipped, Whenever you reach full energy, you gain a bone.", "有此惠，则汝能既满，得一骨。");
            // 构筑之奖
            AddTranslation("Boon of Construct", "构成之惠");
            // 任何成本超过2能量的科技卡牌都会在死亡时掉落一张随机玛珂牌。
            AddTranslation("Any tech card that costs more than 2 energy will drop a random mox on death.", "凡费能逾二之机牌，死则坠一偶玛珂。");
            // 当装备该奖励时，任何成本超过2能量的科技卡牌都会在死亡时掉落一张随机玛珂牌。
            AddTranslation("With this boon equipped, Any tech card that costs more than 2 energy will drop a random mox on death.", "有此惠，则凡费能逾二之机牌，死则坠一偶玛珂。");
            // 救赎恩典
            AddTranslation("Boon of The Saving Grace", "全生之惠");
            // 每当你受到致命伤害时，会给你保留1点生命。（每场战斗限触发一次）
            AddTranslation("Whenever you would recieve fatal damage, the scales are only tipped down to 4.\nONCE PER BATTLE", "汝将受致命伤时，衡止倾至四。\n每战一发而已");
            // 当装备该奖励时，每当你受到致命伤害时，会给你保留1点生命。（每场战斗限触发一次）
            AddTranslation("With this boon equipped, Whenever you would recieve fatal damage, the scales are only tipped down to 4.\nONCE PER BATTLE", "有此惠，则汝将受致命伤时，衡止倾至四。\n每战一发而已");
            // 每场战斗开始时，在你一侧的场上放一只黑山羊。
            AddTranslation("Start each battle with a black goat on the board.", "每战始，于汝侧局上置一黑羊。");
            // 当装备该奖励时，每场战斗开始时，在你一侧的场上放一只黑山羊。
            AddTranslation("With this boon equipped, Start each battle with a black goat on the board.", "有此惠，则每战始，于汝侧局上置一黑羊。");
            // 每一场战斗开始时就有3块骨头。
            AddTranslation("Start each battle with +3 bones.", "每战始得骨三。");
            // 当装备该奖励时，每一场战斗开始时就有3块骨头。
            AddTranslation("With this boon equipped, Start each battle with +3 bones.", "有此惠，则每战始得骨三。");
            // 每回合抽2张牌，而不是1张，但只有当你战斗时牌组中的牌少于20张时，它才会起作用。
            AddTranslation("Draw 2 cards each turn instead of 1, but it will only function if you have less than 20 cards in your deck while battling.", "每合引二牌，不一。然惟战时牌列少于二十，乃行。");
            // 当装备该奖励时，每回合抽2张牌，而不是1张，但只有当你战斗时牌组中的牌少于20张时，它才会起作用。
            AddTranslation("With this boon equipped, Draw 2 cards each turn instead of 1, but it will only function if you have less than 20 cards in your deck while battling.", "有此惠，则每合引二牌，不一。然惟战时牌列少于二十，乃行。");
            // 每一场战斗开始时，你手中获得两张大冷杉。
            AddTranslation("Start each battle with 2 firs in your hand.", "每战始，汝手得二杉。");
            // 当装备该奖励时，每一场战斗开始时，你手中获得两张大冷杉。
            AddTranslation("With this boon equipped, Start each battle with 2 firs in your hand.", "有此惠，则每战始，汝手得二杉。");
            // 化石之奖
            AddTranslation("Boon of Fossils", "化石之惠");
            // 地形卡在死亡时产生3根骨头，而不是1根。
            AddTranslation("Terrain cards yield 3 bones on death instead of 1.", "地形牌死则出骨三，不一。");
            // 当装备该奖励时，地形卡在死亡时产生3根骨头，而不是1根。
            AddTranslation("With this boon equipped, Terrain cards yield 3 bones on death instead of 1.", "有此惠，则地形牌死则出骨三，不一。");
            // 骨髓之奖
            AddTranslation("Boon of Marrow", "骨髓之惠");
            // 献祭亡灵卡牌会产生2根骨头而不是1根。
            AddTranslation("Sacrificing undead cards yields 2 bones instead of 1.", "祀亡牌则得骨二，不一。");
            // 当装备该奖励时，献祭亡灵卡牌会产生2根骨头而不是1根。
            AddTranslation("With this boon equipped, Sacrificing undead cards yields 2 bones instead of 1.", "有此惠，则祀亡牌得骨二，不一。");
            // 石中取血之奖
            AddTranslation("Boon of Bloodstone", "血石之惠");
            // 你可以献祭地形卡。
            AddTranslation("You may sacrifice terrain cards.", "地形牌可见祀。");
            // 当装备该奖励时，你可以献祭地形卡。
            AddTranslation("With this boon equipped, You may sacrifice terrain cards.", "有此惠，则地形牌可见祀。");
            // 衔尾蛇之奖
            AddTranslation("Boon of Ouroboros", "衔尾蛇之惠");
            // 根据区域不同，您会获得不同的效果： / 野兽地牢：每场战斗开始时+2根起始骨头。 / 死亡地牢：每场战斗开始时+1个起始能量。 / 科技地牢：每场战斗开始时获得额外两张随机玛珂牌。 / 魔法地牢：每场战斗开始时获得两张额外松鼠。
            AddTranslation("You get a different effect depending on the region:\nBeast Dungeon:+2 Starting bones each battle.\nDeath Dungeon:+1 Starting Energy each battle\nTech Dungeon:Start the game with two random mox in your hand.\nMagick Dungeon:Start the game with 2 Squirrels in your hand.", "随所处之域而异其效：\n兽窟：每战始骨加二。\n死窟：每战始能加一。\n机窟：局始手得二偶玛珂。\n术窟：局始手得二松鼠。");
            // 当装备该奖励时，根据区域不同，您会获得不同的效果： / 野兽地牢：每场战斗开始时+2根起始骨头。 / 死亡地牢：每场战斗开始时+1个起始能量。 / 科技地牢：每场战斗开始时获得额外两张随机玛珂牌。 / 魔法地牢：每场战斗开始时获得两张额外松鼠。
            AddTranslation("With this boon equipped, You get a different effect depending on the region:\nBeast Dungeon:+2 Starting bones each battle.\nDeath Dungeon:+1 Starting Energy each battle\nTech Dungeon:Start the game with two random mox in your hand.\nMagick Dungeon:Start the game with 2 Squirrels in your hand.", "有此惠，则随所处之域而异其效：\n兽窟：每战始骨加二。\n死窟：每战始能加一。\n机窟：局始手得二偶玛珂。\n术窟：局始手得二松鼠。");
            // 哎呀，你不能站在这儿。
            AddTranslation("Ay yo yaw cant stand right here", "汝不得立此。");
            // 大冷杉
            AddTranslation("Fir", "杉");
            // 墓石
            AddTranslation("Tombstone", "墓石");
            // 管道塔
            AddTranslation("Conduit Tower", "渠塔");
            // 损坏的机器人
            AddTranslation("Broken Bot", "废机");
            // 桥梁栏杆
            AddTranslation("Bridge Railing", "桥栏");
            // 绿宝磐石
            AddTranslation("Emerald Boulder", "绿玉磐");
            // 红宝磐石
            AddTranslation("Ruby Boulder", "红玉磐");
            // 蓝宝磐石
            AddTranslation("Sapphire Boulder", "蓝玉磐");
            // 赏金猎人
            AddTranslation("Bounty Hunter", "购捕者");
            // 哇哦，让所有的说唱歌手闭嘴。
            AddTranslation("Waddup, to all rappers shut up with your shutting up.", "诸饶舌者，其尽缄口。");
            // 我的伤……它们很严重。
            AddTranslation("My injuries.. They are severe.", "我之伤……甚矣。");
            // 看来我要在这里……提前退休了。
            AddTranslation("I am forced to retire.. for now.", "我今不得不退矣……姑尔。");
            // 啊！！你对我做了什么？
            AddTranslation("Argh!! What have you done to me?", "呀！！汝何施于我？");
            // 一切都让我感到痛苦……但……我会回来的……
            AddTranslation("Everything hurts... But.. I'll be back..", "无不痛也……然……我必复来……");
            // 嗯……你阻止了我……
            AddTranslation("Well.. you stopped me..", "然……汝止我矣……");
            // 我会抓住你……挑战者……
            AddTranslation("I WILL get you.. challenger..", "我必执汝……角者……");
            // 我被杀了！
            AddTranslation("I've been scrapped!", "我败矣！");
            // 你完全击败了我……
            AddTranslation("You beat me fair and square...", "汝正正而胜我矣……");
            // 所以我要先撤退了……打得不错……期待不久之后的再战。
            AddTranslation("So I will retreat.. well played.. Expect a rematch soon though..", "故我且退……汝战善矣……然后会不久复战。");
            // 所以，我们又见面了……
            AddTranslation("So, we meet again..", "然则，我等复见矣……");
            // 哦，是你。
            AddTranslation("Oh.. Its You..", "噫……乃汝也……");
            // 啊哈，找到你了！
            AddTranslation("Aha! Found you!", "啊哈！得汝矣！");
            // 我是来报仇的！
            AddTranslation("I've come to get my revenge!", "我来雪仇也！");
            // 惊喜吧！
            AddTranslation("Surprise!", "惊乎！");
            // 喂。
            AddTranslation("Hey.", "喂。");
            // 好的，欢迎来到这里。
            AddTranslation("Well, Hello there.", "善，汝来矣。");
            // 向你问候！
            AddTranslation("Greeetings!", "问汝安！");
            // 你以为你在干什么？四处游荡，摧毁我们的地牢。
            AddTranslation("Just what do YOU think you're doing? Wandering around and destroying our dungeons.", "汝意己何为？周行四方，而坏我等之窟。");
            // 一只小老鼠闯入我的视线……
            AddTranslation("A little mouse wanders into my sight..", "有小鼠入我目矣……");
            // 我终于找到你了……
            AddTranslation("At last, I have found you..", "终得汝矣……");
            // 野兽
            AddTranslation("Beasts", "兽");
            // 科技
            AddTranslation("Technology", "机");
            // 魔法
            AddTranslation("Magick", "术");
            // 死亡
            AddTranslation("Dead", "死");
        }

    }


    public class WhistleWindAbnormalSigilsMod
    {
        public static void RegisterTranslations()
        {
            // Ability
            // 得寸进尺
            AddTranslation("Aggravating", "激众");
            // 当[creature]在场上时，所有敌对造物获得1点力量。
            AddTranslation("While this card is on the board, all opposing creatures gain 1 Power.", "[creature]在局，则敌诸物威益一。");
            // 我的野兽被你造物的存在激怒了。
            AddTranslation("My beasts are incensed by your creature's presence.", "我之兽因汝物在而怒。");
            // 炼金术士
            AddTranslation("Alchemist", "炼者");
            // 消耗2点能量以弃掉当前手牌，并抽取等同于弃牌数量的牌。
            AddTranslation("Pay 2 Energy to discard your current hand and draw cards equal to the amount you discarded.", "费能二，以弃今手，而引等数之牌。");
            // 无数承诺的永恒信念。
            AddTranslation("The unending faith of countless promises.", "众诺不穷之信也。");
            // [creature]洗掉了你的手牌替换为新牌！
            AddTranslation("[creature] replaces your hand with a new one!", "[creature]易汝手以新手！");
            // 吸纳者
            AddTranslation("Assimilator", "并纳者");
            // 当[creature]杀死其他卡牌时，它将获得1点力量和1点生命。
            AddTranslation("When this card kills an opposing card, it gains 1 Power and 1 Health.", "[creature]杀敌牌，则威命各益一。");
            // 从万物汲取。
            AddTranslation("From the many, one.", "众归于一。");
            // [creature]使受害者成为自己的一部分。
            AddTranslation("[creature] makes its victim a part of itself.", "[creature]并所害者于己。");
            // 匠心独运
            AddTranslation("Barreler", "辟道");
            // 在持牌人的回合结束时，[creature]将按印记标注的方向移动到场地末端，同时移动途中遇到的任何卡牌。
            AddTranslation("At the end of the owner's turn, this card moves in the sigil's direction to the end of the board, moving any cards in the way.", "持牌者合终，[creature]循印所志而移至局尽，途有诸牌皆徙之。");
            // 创造房间。
            AddTranslation("Make room.", "辟处。");
            // [creature]移动到场地末端，同时抛掷任何挡道的造物。
            AddTranslation("[creature] moves to the end of the board, tossing anything in its way.", "[creature]移至局尽，而掷诸挡道者。");
            // 捆绑打击
            AddTranslation("Binding Strike", "缚击");
            // 当[creature]攻击造物时，施加等同于该卡牌两倍力量的束缚。
            AddTranslation("When [creature] strikes an opposing creature, inflict Bind equal to twice this card's Power.", "[creature]击敌物，则加缚，其数倍此牌之威而二。");
            // 你的野兽落在狼群后面。
            AddTranslation("Your beast falls behind the pack.", "汝兽落群后矣。");
            // 死敌
            AddTranslation("Bitter Enemies", "深仇");
            // 场上每有一张带有此印记的卡牌，[creature]获得1点力量。
            AddTranslation("This card gains 1 Power for each other card on the board that also bears this sigil.", "局中每别有一牌亦负此印，[creature]威益一。");
            // 怨恨显露出来。
            AddTranslation("A bitter grudge laid bare.", "深憾既著。");
            // 血魔
            AddTranslation("Bloodfiend", "血魅");
            // 当[creature]造成伤害时，其获得1点生命值。
            AddTranslation("When this card deals damage, it gains 1 Health.", "[creature]出伤，则命益一。");
            // 被诅咒的恶魔。
            AddTranslation("Accursed fiend.", "被诅之魅。");
            // [creature]吸取新鲜的生命！
            AddTranslation("[creature] sucks out fresh life!", "[creature]啜新生矣！");
            // 血之函
            AddTranslation("Bloodletter", "血引");
            // 当[creature]受到非致命攻击时，从攻击者身上吸取1点生命值。
            AddTranslation("When a [creature] is struck with a nonfatal attack, absorb 1 Health from the striker.", "[creature]见非致命之击，则吸击者一命。");
            // 血液流动温暖，充满甘甜活力。
            AddTranslation("The blood runs warm with sweet vitality.", "血行而温，甘其生也。");
            // [creature]吸收养分！
            AddTranslation("[creature] absorbs nutrients!", "[creature]吸其养矣！");
            // 母巢
            AddTranslation("Broodmother", "孳母");
            // 当[creature]受到攻击时，在你的手上创造一只幼蛛。[define:wstl_spiderling]
            AddTranslation("When [creature] is struck, create a Spiderling in your hand. [define:wstl_spiderling]", "[creature]见击，则汝手中生一幼蛛。[define:wstl_spiderling]");
            // 一只小蜘蛛躲在你手里。
            AddTranslation("A small spider takes refuge in your hand.", "有小蛛避于汝手。");
            // [creature]掉落了一只小蜘蛛！
            AddTranslation("[creature] drops a spiderling!", "[creature]落一幼蛛！");
            // 交响乐指挥
            AddTranslation("Conductor", "指乐者");
            // 当[creature]在场上时，此印记的效果会在接下来的3个回合中不断改变。
            AddTranslation("The effect of this sigil will change over the next 3 turns while this card is on the board.", "[creature]在局，则此印之效于后三区回合更易。");
            // 从破碎和毁灭中，最美的演出起始。
            AddTranslation("From break and ruin, the most beautiful performance begins.", "破败之中，美奏始焉。");
            // [creature]演奏寂静的交响乐。
            AddTranslation("[creature] plays a quiet symphony.", "[creature]奏其静乐。");
            // 模仿者
            AddTranslation("Copycat", "拟者");
            // [creature]将转变为第一个对位它的造物的副本。
            AddTranslation("[creature] will transform into a copy of the first creature that opposes it.", "[creature]将化为初与之对位者之副。");
            // 近乎完美的模仿。
            AddTranslation("A near perfect impersonation.", "几全之拟也。");
            // [creature]试图模仿对位的造物。
            AddTranslation("[creature] tries to mimick the opposing creature.", "[creature]尝拟其对物。");
            // 校正者
            AddTranslation("Corrector", "校者");
            // 当[creature]被抽取时，根据其花费成本随机更改其属性值。
            AddTranslation("When [creature] is drawn, randomly change its stats according to its total play cost.", "[creature]既引，则随其总直而偶易其数。");
            // 如何平衡。
            AddTranslation("How balanced.", "均矣。");
            // [creature]属性被强制“修正”。
            AddTranslation("[creature] stats are forcefully 'corrected'.", "[creature]之数见强校矣。");
            // 无所畏惧
            AddTranslation("Courageous", "勇");
            // 与[creature]相邻的造物会损失至多2点生命值。每损失1点生命值，受影响的造物就会获得1点力量。此效果不会消灭卡牌。
            AddTranslation("Creatures adjacent to this card lose up to 2 Health. For each point of Heath lost, the affected creature gains 1 Power. This effect cannot kill cards.", "与[creature]相邻之物，命至多损二；每损一命，则威益一。此效不至杀牌。");
            // 生命只属于那些不惧怕死亡的人。
            AddTranslation("Life is only given to those who don't fear death.", "命惟授不惧死者。");
            // 诅咒
            AddTranslation("Cursed", "诅");
            // 当[creature]死亡时，杀死此牌的牌会变成这张卡牌的副本。
            AddTranslation("When [creature] dies, the killer transforms into a copy of this card.", "[creature]死，则杀之者化为此牌之副。");
            // 诅咒有增无减。
            AddTranslation("The curse continues unabated.", "诅延而不息。");
            // [creature]将会继续诅咒。
            AddTranslation("[creature] passes the curse on.", "[creature]传其诅矣。");
            // 循环器
            AddTranslation("Cycler", "环行者");
            // 在持牌人的回合结束时，[creature]会向印记标注的方向移动，在场上持牌人一侧循环。
            AddTranslation("At the end of the owner's turn, this card moves in the sigil's direction, looping around the owner's side of the board.", "持牌者合终，[creature]循印所志而移，环行于其主场侧。");
            // 一个永无止境的循环。
            AddTranslation("A never-ending cycle.", "无竟之环。");
            // [creature]移动到一个新的空间，绕过场地的边缘。
            AddTranslation("[creature] moves to a new space, going around its side of the board.", "[creature]移于新位，而循其侧而转。");
            // 虚伪王座
            AddTranslation("False Throne", "假座");
            // 每回合限一次，消耗1点生命值然后选定一个造物，然后在你手中创建一个免费的、未更改的副本。
            AddTranslation("Once per turn, pay 1 Health to give Neutered to a chosen creature, then create a free, unaltered copy of it in your hand.", "每合一次，费一命，使所择一物得绝育印，而后于汝手中生其无费未改之副。");
            // 一个简单的小魔术。
            AddTranslation("A simple little magic trick.", "小术耳。");
            // [creature]给被选中的造物一份仿制品。
            AddTranslation("[creature] gives a false present to the chosen creature.", "[creature]以伪赠授所择者。");
            // 旗手力量
            AddTranslation("Flag Bearer", "旗手");
            // 当[creature]在场上时，相邻的造物获得2点生命值。
            AddTranslation("While this card is on the board, adjacent creatures gain 2 Health.", "[creature]在局，则邻物命益二。");
            // 士气高涨。
            AddTranslation("Morale runs high.", "气正盛也。");
            // 冰霜统领
            AddTranslation("Ruler of Frost", "霜主");
            // 每回合限一次，消耗2根骨头选择一个场上位置。如果位置为空，则创建一块冰块。否则，如果这张牌可以杀死占位牌，将其变成一颗冰封之心。冰封之心具有：0点力量，2点生命，高跳。
            AddTranslation("Once per turn, pay 2 Bones to choose a space on the board. If the space is empty, create a Block of Ice. Otherwise, if this card can kill the occupying card, transform it into a Frozen Heart.", "每合一次，费二骨择局上一位。其位若空，则生冰块；不然，若此牌能杀所居者，则化之为冰心。");
            // 冰雪女王挥了挥手，挡住了去路。
            AddTranslation("With a wave of her hand, the Snow Queen blocked the path.", "雪后挥手，而塞其途。");
            // [creature]冻结了路径。
            AddTranslation("[creature] freezes the path.", "[creature]冰其途矣。");
            // 冰封之心
            AddTranslation("Frozen Heart", "冰心");
            // 杀死[creature]的牌获得2点生命值。
            AddTranslation("When [creature] dies, the killer gains 2 Health.", "[creature]死，则杀之者命益二。");
            // 春天来了，玫瑰花开了。
            AddTranslation("Spring arrives with blossoming roses.", "春至而玫开。");
            // [creature]释放温暖的生命。
            AddTranslation("[creature] releases warm life.", "[creature]释其温生。");
            // 园丁
            AddTranslation("Gardener", "圃者");
            // 当一张同盟卡牌被杀死时，在其位置创建一颗树苗。[define:wstl_parasiteTreeSapling]
            AddTranslation("When an allied card is killed, create a Sapling in their place. [define:wstl_parasiteTreeSapling]", "一盟牌死，则其位生一树苗。[define:wstl_parasiteTreeSapling]");
            // 它们增殖并变得完整。你能感觉到吗？
            AddTranslation("They proliferate and become whole. Can you feel it?", "其滋殖而成全，汝能觉乎？");
            // 一棵小树从死亡的卡牌尸体上长了出来。
            AddTranslation("A sapling grows out of the dead card's corpse.", "有树苗出于死牌之尸。");
            // 赠礼者
            AddTranslation("Gift Giver", "与礼者");
            // 放置[creature]时，你获得一张随机的牌。
            AddTranslation("When [creature] is played, create a random card in your hand.", "[creature]既陈，则汝手中生一偶牌。");
            // 一个给你的礼物。
            AddTranslation("A gift for you.", "以礼与汝。");
            // [creature]有一个礼物要给你！
            AddTranslation("[creature] has a gift for you!", "[creature]有礼与汝！");
            // 贪婪之愈
            AddTranslation("Greedy Healing", "贪愈");
            // 在持有者的回合结束时，[creature]获得2点生命值。如果两回合内[creature]没有受到攻击，它将死亡。
            AddTranslation("At the end of its owner's turn, this card gains 2 Health. If 2 turns pass without this card taking damage, it will die.", "其主合终，[creature]命益二；二合不见伤，则死。");
            // 你的野兽有过量生命。
            AddTranslation("Your beast has Health in excess.", "汝兽命过盈矣。");
            // [creature]给予自己更多生命！
            AddTranslation("[creature] gives itself more Health!", "[creature]自益其命！");
            // 粉碎机
            AddTranslation("Grinder", "磨者");
            // [creature]将获得为放置它而献祭的造物属性。
            AddTranslation("This card gains the stats of the creatures sacrificed to play it.", "[creature]得其所由祀而陈之物之数。");
            // 现在一切都会好起来的。
            AddTranslation("Now everything will be just fine.", "今万事将善矣。");
            // 团队治疗师
            AddTranslation("Group Healer", "群疗者");
            // 在持牌人的回合开始时，[creature]将治愈所有受伤盟友1点生命。
            AddTranslation("At the start of its owner's turn, this card will heal all allies that have taken damage by 1 Health.", "持牌者合始，[creature]疗诸伤友各一命。");
            // 你只会拖延不可避免的事情。
            AddTranslation("You only delay the inevitable.", "汝徒缓其必至耳。");
            // [creature]能治愈所有的盟友。
            AddTranslation("[creature] heals all its friends.", "[creature]疗其诸友。");
            // 治疗师
            AddTranslation("Healer", "疗者");
            // 在持牌人回合结束时，其可以选择一张其他卡牌，恢复该牌2点生命。
            AddTranslation("At the end of your turn, you may choose one of your other cards to heal by 2 Health.", "持牌者合终，可择他牌之一，疗之二命。");
            // 永远不要低估治疗师的重要性。
            AddTranslation("Never underestimate the importance of a healer.", "毋轻疗者之重。");
            // [creature]治愈被选中的造物！
            AddTranslation("[creature] heals the chosen creature!", "[creature]疗所择之物！");
            // 高度紧张
            AddTranslation("High-Strung", "劲张");
            // 在当前回合结束时，[creature]将获得的匆忙值等于对位卡牌力量的两倍。
            AddTranslation("At the end of the current turn, this card gains Haste equal to twice the opposing card's Power.", "今合终，[creature]得疾，其数倍对牌之威而二。");
            // 偶像
            AddTranslation("Idol", "偶");
            // 当[creature]在场上时，所有敌对造物都会失去1点力量。
            AddTranslation("While this card is on the board, all opposing creatures lose 1 Power.", "[creature]在局，则敌诸物威减一。");
            // 我的野兽听命于你。
            AddTranslation("My beasts defer to you.", "我之兽皆从汝。");
            // 偏左打击
            AddTranslation("Left-Veering Strike", "左偏击");
            // [creature]的攻击将始终在正常位置左侧一格。
            AddTranslation("[creature] will strike the opposing space to the left of the space across from it.", "[creature]常击其正对之左位。");
            // 偏右打击
            AddTranslation("Right-Veering Strike", "右偏击");
            // [creature]的攻击将始终在正常位置右侧一格。
            AddTranslation("[creature] will strike the opposing space to the right of the space across from it.", "[creature]常击其正对之右位。");
            // 孤独
            AddTranslation("Lonely", "孤");
            // 除非已经存在一张带有卵石的牌，否则选择在场一张牌以获得1个卵石，然后[creature]将回到你手中。如果带有卵石的卡牌死亡，所有友方卡牌将受到1点额外伤害，直到选择新牌为止。
            AddTranslation("Choose a card on the board to gain 1 Pebble unless a card with Pebble already exists, then return this card to your hand. If a card with Pebble dies, all ally cards receive 1 additional damage until a new card is chosen.", "若局中未有卵石印，则择一牌使得卵石，而后[creature]归汝手。若负卵石之牌死，则诸友牌皆多受一伤，至更择新牌。");
            // 留下来一位朋友。
            AddTranslation("A friend to stay.", "留一友焉。");
            // 烈士
            AddTranslation("Martyr", "死义");
            // 当[creature]死亡时，所有友方造物获得2点生命并失去所有负面状态效果。
            AddTranslation("When [creature] dies, all allied creatures gain 2 Health and lose any negative status effects.", "[creature]死，则诸友物命益二，并去其诸负效。");
            // 无私的死亡，净化你造物的邪恶。
            AddTranslation("A selfless death to cleanse your beasts of evil.", "无私之死，以涤汝诸物之秽。");
            // [creature]的死亡会净化你的其他造物！
            AddTranslation("[creature]'s death cleanses your other creatures!", "[creature]之死净汝他物矣！");
            // 荨麻衣
            AddTranslation("Nettle Clothes", "荨衣");
            // 当放置[creature]时，用随机的兄弟卡牌填补场上持牌人一侧的所有空位。[creature]获得每个友方兄弟卡牌的首个印记。
            AddTranslation("When this card is played, fill all empty spaces on the owner's side of the board with random Brothers. This card gains the first sigil of each allied Brother.", "[creature]既陈，则其主场侧诸空位尽满以偶兄弟；[creature]并得诸友兄弟之首印。");
            // 这些衣服一定会让我们恢复快乐的时光。
            AddTranslation("These clothes will surely restore our happy days.", "此衣必使我等乐时复还。");
            // [creature]带出了它的家人！
            AddTranslation("[creature] brings out its family!", "[creature]引其家人矣！");
            // 绝育
            AddTranslation("Neutered", "绝育");
            // [creature]的力量降低至0。在持牌人的回合开始时，此印记将被删除。
            AddTranslation("[creature] has its Power reduced to 0. At the start of the owner's turn, remove this sigil.", "[creature]之威降为零；其主合始，此印乃去。");
            // 绝育激转
            AddTranslation("Neutered Latch", "绝育遗契");
            // 每回合限一次，消耗[sigilcost:2根骨头]选择一个造物来获得绝育印记，然后将此印记的激活成本增加1根骨头。
            AddTranslation("Once per turn, pay [sigilcost:2 Bones] to choose a creature to gain the Neutered sigil, then increase this sigil's activation cost by 1 Bone.", "每合一次，费[sigilcost:2 Bones]择一物使得绝育印，而后此印启直益骨一。");
            // 每回合限一次，消耗1根骨头，然后将此印记的激活成本增加1根骨头。
            AddTranslation("Once per turn, pay 1 bone to choose a creature to gain the Neutered sigil, then increase this sigil's activation cost by 1 Bone.", "每合一次，费骨一，择一物使得绝育印，而后此印启直益骨一。");
            // 战斗的意志已经丧失。
            AddTranslation("The will to fight has been lost.", "战志已丧。");
            // [creature]阻止被选中的造物攻击。
            AddTranslation("[creature] prevents the chosen creature from attacking.", "[creature]遏所择之物使不得攻。");
            // 灵巧之足
            AddTranslation("Nimble-Footed", "捷足");
            // 在持牌人的回合开始时，[creature]获得2点匆忙值。
            AddTranslation("At the start of the owner's turn, this card gains 2 Haste.", "持牌者合始，[creature]得疾二。");
            // 机会主义
            AddTranslation("Opportunistic", "乘机");
            // [creature]对在自己回合中无法攻击此牌的对手卡牌造成1点额外伤害。
            AddTranslation("[creature] deals 1 additional damage to opposing cards that cannot attack this card during their own turn.", "[creature]于彼回合中不能攻此牌之敌牌，多受其一伤。");
            // 一次廉价的攻击。
            AddTranslation("A cheap hit.", "乘隙之一击。");
            // 迫害者
            AddTranslation("Persecutor", "迫者");
            // 当放置[creature]时，若相邻的左侧和右侧位置均为空，则分别在左侧和右侧空位上创建一个钉子和一把锤子。
            AddTranslation("When a card bearing this sigil is played, create a Nail in the adjacent left space and a Hammer in the adjacent right space if they are empty.", "负此印之牌既陈，若左右邻位空，则左生钉，右生槌。");
            // 你是否为自己封闭的心感到内疚？
            AddTranslation("Are you guilty of having a closed heart?", "汝于闭心有愧乎？");
            // [creature]露出了它隐藏的工具！
            AddTranslation("[creature] reveals its hidden tools!", "[creature]发其藏器矣！");
            // 坚持不懈
            AddTranslation("Persistent", "穷追");
            // 类似断尾求生和水袭这样的印记无法避免或转移[creature]的攻击。
            AddTranslation("Attacks by this card cannot be avoided or redirected by sigils like Loose Tail or Waterborne.", "[creature]之攻，不可为断尾、潜袭诸印所避易。");
            // 猎物可没那么容易藏匿自己。
            AddTranslation("Prey cannot hide so easily.", "猎不得易匿。");
            // [creature]追捕猎物。
            AddTranslation("[creature] chases its prey down.", "[creature]穷逐其猎。");
            // [creature]造成的伤害无法被身披坚甲或茂密皮毛等防御印记所抵消或减少。
            AddTranslation("Damage dealt by this card cannot be negated or reduced by sigils such as Armoured or Thick Skin.", "[creature]所出之伤，不可为坚甲、厚皮诸印所消减。");
            // 你的野兽把我撕碎了。
            AddTranslation("Your beast runs mine through.", "汝兽洞贯我矣。");
            // 与[creature]相邻的造物在被攻击时受到的伤害减少1点。
            AddTranslation("Creatures adjacent to this card take 1 less damage when struck.", "邻于[creature]之物见击，则其伤少一。");
            // 你的野兽为友方抵挡攻击。
            AddTranslation("Your beast shields its ally against the blow.", "汝兽蔽其友以当击。");
            // [生物]为它的友方提供保护！
            AddTranslation("[creature] shields its friend!", "[creature]蔽其友矣！");
            // 惩罚者
            AddTranslation("Punisher", "罚者");
            // 当[creature]被击中时，攻击者会被杀死。
            AddTranslation("When [creature] is struck, the striker is killed.", "[creature]见击，则击者死。");
            // 报复行动迅速且残忍。
            AddTranslation("Retaliation is switft and brutal.", "报速而酷。");
            // [creature]迅速反击！
            AddTranslation("[creature] swiftly retaliates!", "[creature]速报之！");
            // 蜂后
            AddTranslation("Queen Nest", "蜂后");
            // [creature]在场时，每当有其他卡牌被消灭时，在你的手牌中生成一只工蜂。[define:wstl_queenBeeWorker]
            AddTranslation("Whenever another card is killed, create a Worker Bee in your hand. [define:wstl_queenBeeWorker]", "他牌死时，汝手中生一工蜂。[define:wstl_queenBeeWorker]");
            // 为了蜂巢。
            AddTranslation("For the hive.", "为其巢也。");
            // 另一工人天生就是为了服务[creature]而存在的。
            AddTranslation("Another worker is born to serve [creature].", "又一工蜂生以事 [creature]。");
            // 反射者
            AddTranslation("Reflector", "返者");
            // 当[creature]被击中时，攻击者会受到与其力量值相等的伤害。
            AddTranslation("When this card is struck, the striker is dealt damage equal to the striker's Power.", "[creature]见击，则击者受其威等数之伤。");
            // 一报还一报。
            AddTranslation("What goes around comes around.", "反报其身。");
            // [creature]返还了伤害。
            AddTranslation("[creature] returns the damage.", "[creature]返其伤矣。");
            // 牌组重塑
            AddTranslation("Refresh Decks", "更牌列");
            // 将主牌堆和副牌堆的牌组重塑。
            AddTranslation("Refreshes and reshuffles both draw piles.", "更而复乱主副二牌堆。");
            // 在持牌人的回合开始时，[creature]会治愈相邻卡牌1点生命。
            AddTranslation("At the start of its owner's turn, this card heals adjacent cards by 1 Health.", "持牌者合始，[creature]疗邻牌一命。");
            // 伤口会愈合，但疤痕依然存在。
            AddTranslation("Wounds heal, but the scars remain.", "疮可愈，而痕犹存。");
            // [creature]治愈邻近的造物。
            AddTranslation("[creature] heals adjacent creatures.", "[creature]疗邻物。");
            // 回归手牌
            AddTranslation("Return Card to Hand", "归手");
            // 将所选卡牌归还回至你手中，并保留所有更改和属性。根据最近放置的卡牌时间，将所选卡牌的成本更改为0-2块骨头。
            AddTranslation("Returns the selected card to your hand with all changes and statuses retained. Change the selected card's cost to 0-2 Bones based on how recently it was played.", "使所择之牌归汝手，而诸改与诸状皆存。其直随其新旧，改为零至二骨。");
            // 回归虚无
            AddTranslation("Return to Nihil", "归虚");
            // 在持牌人的回合结束时，[creature]将对场上的所有其他卡牌造成与此牌力量值相等的伤害。
            AddTranslation("At the end of the owner's turn, deal damage equal to this card's Power to all other cards on the board.", "持牌者合终，[creature]伤局上他牌皆如其威。");
            // 离遗忘又近了一步。
            AddTranslation("One step closer to oblivion.", "去忘又近一步。");
            // 虚空召唤。
            AddTranslation("The void calls.", "虚召矣。");
            // 法定继承者
            AddTranslation("Rightful Heir", "正嗣");
            // 每回合一次，消耗[sigilcost:1根骨头]将选定的造物变成南瓜，然后将此印记的激活成本增加1。[define:wstl_ozmaPumpkin]
            AddTranslation("Once per turn, pay [sigilcost:1 Bone] to transform a chosen creature into a Pumpkin, then increase this sigil's activation cost by 1. [define:wstl_ozmaPumpkin]", "每合一次，费[sigilcost:1 Bone]使所择之物化为南瓜，而后此印启直益一。[define:wstl_ozmaPumpkin]");
            // 每回合一次，消耗1根骨头将选定的造物变成南瓜，然后将此印记的激活成本增加1。[define:wstl_ozmaPumpkin]
            AddTranslation("Once per turn, pay 1 bone to transform a chosen creature into a Pumpkin, then increase this sigil's activation cost by 1. [define:wstl_ozmaPumpkin]", "每合一次，费骨一使所择之物化为南瓜，而后此印启直益一。[define:wstl_ozmaPumpkin]");
            // 她现在只剩下孩子了。
            AddTranslation("All she has left now are her children.", "今其所余，惟子耳。");
            // [creature]把造物变成南瓜。
            AddTranslation("[creature] turns the creature into a pumpkin.", "[creature]化其物为南瓜。");
            // 缠根
            AddTranslation("Roots", "根缠");
            // 放置[creature]时，在相邻的空位生成刺藤。[define:wstl_snowWhitesVine]
            AddTranslation("When this card is played, create Thorny Vines on adjacent empty spaces. [define:wstl_snowWhitesVine]", "[creature]既陈，则邻空位生棘藤。[define:wstl_snowWhitesVine]");
            // 怨恨像野草一样爆发。
            AddTranslation("Resentment bursts forth like a weed.", "怨如莠而暴发。");
            // 尖锐的刺在[creature]周围射出！
            AddTranslation("Sharp thorns shoot out around [creature]!", "利棘四发于[creature]旁！");
            // 烈炎
            AddTranslation("Scorching", "灼");
            // 与[creature]对位的造物在回合结束时受到1点伤害。
            AddTranslation("The creature opposing this card takes 1 damage at the end of its owner's turn.", "[creature]对位之物，于其主合终受一伤。");
            // 缓慢而痛苦的死亡。
            AddTranslation("A slow and painful death.", "徐而痛之死也。");
            // 对抗[creature]的造物被烧毁了！
            AddTranslation("The creature opposing [creature] is burned!", "与[creature]对之者灼矣！");
            // 扰频器
            AddTranslation("Scrambler", "乱数者");
            // 当[creature]被献祭时，将其属性提供给献祭其上场的牌，然后将最终属性随机化。
            AddTranslation("When [creature] is sacrificed, give its stats to the sacrificing card then randomise the resulting stats.", "[creature]见祀，则以其数授受祀之牌，而后乱其成数。");
            // 当[creature]被献祭时，自身属性提供给献祭它上场的牌，然后将最终属性随机化。适用于法术。
            AddTranslation("When [creature] is sacrificed, give its stats to the sacrificing card then randomise the resulting stats. Works for Spells.", "[creature]见祀，则以其数授受祀之牌，而后乱其成数。术亦然。");
            // 你爱你的城市吗？
            AddTranslation("Do you love your city?", "汝爱汝城乎？");
            // 裸巢
            AddTranslation("Serpent's Nest", "蛇巢");
            // 当[creature]被攻击时，攻击者获得一点裸虫值。
            AddTranslation("When [creature] is struck, the striker gains 1 Worms.", "[creature]见击，则击者得裸虫一。");
            // 它可以通过任何孔进入你的身体。
            AddTranslation("It can enter your body through any aperture.", "彼可由汝诸孔而入。");
            // 史莱姆之身
            AddTranslation("Made of Slime", "胶躯");
            // 在持牌人的回合结束时，[creature]将给予相邻的卡牌此印记，如果这张牌不是史莱姆，则对其造成1点伤害。此牌在死亡时会变成史莱姆。
            AddTranslation("At the end of the owner's turn, give adjacent cards this sigil, and deal 1 damage to this card if it is not a Slime. This card transforms into a Slime on death.", "持牌者合终，[creature]以此印授邻牌；若其非胶，则自受一伤。此牌死则化为胶。");
            // 它的军队每天都在壮大。
            AddTranslation("Its army grows everyday.", "其众日长。");
            // [生物]融化成史莱姆！
            AddTranslation("[creature] melts into slime!", "[creature]融为胶矣！");
            // 孢子囊
            AddTranslation("Sporogenic", "散孢");
            // 与[creature]相邻的造物在其持牌人的回合结束时获得1个孢子。此印记将在其他印记之前生效。
            AddTranslation("Creatures adjacent to this card gain 1 Spores at the end of its owner's turn. This sigil activates before other sigils.", "邻于[creature]之物，于其主合终得孢一。此印先于他印而发。");
            // 它们会像爱祝福一样爱这个诅咒。
            AddTranslation("They will love this curse like a blessing.", "彼将爱此诅如祝。");
            // [creature]在相邻的卡牌上散布孢子！
            AddTranslation("[creature] scatters spores on the adjacent cards!", "[creature]散孢于邻牌矣！");
            // 团队领袖
            AddTranslation("Team Leader", "领队");
            // 当[creature]在场上时，所有友方造物都会获得1点力量。
            AddTranslation("While this card is on the board, all allied creatures gain 1 Power.", "[creature]在局，则友诸物威益一。");
            // 你的野兽让它的盟友更加大胆。
            AddTranslation("Your beast emboldens its allies.", "汝兽壮其友志。");
            // 列车
            AddTranslation("The Train", "列车");
            // 放置[creature]时，杀死场上的所有造物。以这种方式杀死的造物不会掉骨头。
            AddTranslation("When [creature] is played, kill all creatures on the board. Creatures killed this way do not drop bones.", "[creature]既陈，则局上诸物尽死。由此死者不出骨。");
            // 列车会消灭那些没有离开轨道的造物。
            AddTranslation("The train boards those that don't step away from the tracks.", "列车碾不避轨者。");
            // 列车鸣响警笛。
            AddTranslation("The train blows its mighty horn.", "列车鸣其巨角。");
            // 茂密皮毛
            AddTranslation("Thick Skin", "厚皮");
            // 每当[creature]受到伤害时，该伤害-1。
            AddTranslation("Whenever [creature] takes damage, reduce that damage by 1.", "[creature]凡受伤，则其伤减一。");
            // 你的造物的皮毛吸收了打击。
            AddTranslation("Your creature's hide absorbs the blow.", "汝物之皮受其击矣。");
            // [creature]吸收了这一击。
            AddTranslation("[creature] absorbs the blow.", "[creature]受其击矣。");
            // 易爆
            AddTranslation("Volatile", "躁爆");
            // 当[creature]死亡时，相邻和对位的卡牌将受到10点伤害。
            AddTranslation("When this card dies, adjacent and opposing cards are dealt 10 damage.", "[creature]死，则邻牌与对牌受伤十。");
            // 爆炸性的完成。
            AddTranslation("An explosive finish.", "爆而终焉。");
            // [creature]爆炸了！邻近的造物在爆炸中被杀死。
            AddTranslation("[creature] detonates! Adjacent creatures are killed in the blast.", "[creature]爆矣！邻物皆死于其炎。");
            // 目击者
            AddTranslation("Witness", "见者");
            // 消耗2根骨头，使所选造物的生命值增加2，受到的伤害增加1。此效果可叠加3次。
            AddTranslation("Pay 2 Bones to increase the selected creature's Health by 2 and their taken damage by 1. This effect stacks up to 3 times.", "费骨二，使所择之物命益二，而所受伤益一。此效至三重。");
            // 真相会让你获得自由。
            AddTranslation("The truth will set you free.", "真将释汝。");
            // 被选中的造物看到[creature]并获得新生。
            AddTranslation("The chosen beholds [creature] and is reborn.", "所择者见 [creature] 而更生。");
            // 樵夫
            AddTranslation("Woodcutter", "樵者");
            // 当其他造物移动到[creature]对面的空间时，它们受到等于[creature]力量值的伤害。
            AddTranslation("When a creature moves into the space opposite this card, they take damage equal to this card's Power.", "有物移至[creature]对位，则受其威等数之伤。");
            // 无论有多少棵树倒下，森林仍然茂密。
            AddTranslation("No matter how many trees fall, the forest remains dense.", "木虽多仆，林犹密也。");
            // [creature]自由摆动。
            AddTranslation("[creature] takes a free swing.", "[creature]乘势一挥。");
            // 在持牌人的回合结束时，[creature]会按印记标注的方向移动，在持牌人的场地上循环。友方造物会尽可能朝着这张牌运动的方向前进。
            AddTranslation("At the end of its owner's turn, this card moves in the sigil's direction, looping around the owner's side of the board. Allied creatures towards this card in the sigil's direction as far as possible.", "持牌者合终，[creature]循印所志而移，环行于其主场侧；友方诸物亦尽所能随其向而进。");
            // 我们一起走吧。
            AddTranslation("Let's go, together.", "其偕行矣。");
            // [creature]带领你的造物前进。
            AddTranslation("[creature] leads your creatures forward.", "[creature]导汝诸物而进。");
            // [creature]不受死神之触、臭臭、惩罚者、诅咒和偶像印记的影响。
            AddTranslation("A card bearing this sigil is immune to the effects of Touch of Death, Stinky, Punisher, Cursed, and Idol.", "负此印之牌，不受死触、恶臭、罚者、诅与偶之效。");
            // 相邻造物获得的力量等于带有该印记的卡牌的基础力量的一半，四舍五入。下一回合，此印记效果会发生变化。
            AddTranslation("Adjacent creatures gain Power equal to half this card's base Power, rounded down. This effect changes next turn.", "邻物得威等于此牌本威之半，余者舍。此效次合更易。");
            // 场上的友方造物获得的力量等于带有该印记的卡牌基础力量的一半，四舍五入。下一回合，此印记效果会发生变化。
            AddTranslation("Allied creatures on the board gain Power equal to half this card's base Power, rounded down. This effect changes next turn.", "局上友物得威等于此牌本威之半，余者舍。此效次合更易。");
            // 场上的所有其他造物获得与带有该印记的卡牌的力量值相等的力量。
            AddTranslation("All other creatures on the board gain Power equal to this card's Power.", "局上诸他物得威等于此牌之威。");
            // 没有你可以选择的卡牌。
            AddTranslation("There are no cards you can choose.", "无可择之牌。");
            // 你不能瞄准空气。
            AddTranslation("You can't target the air.", "不得指虚空。");
            // 你必须从其他卡牌中选择一张。
            AddTranslation("You must choose one of your other cards.", "汝须择他牌之一。");
            // 它已经锁上了……
            AddTranslation("It's already latched...", "其已见契矣……");
            // 你必须从其他卡牌中选择一张。
            AddTranslation("You must choose one of your other cards.", "汝须择他牌之一。");
            // 这个世界上有些东西太独特了，无法复制。
            AddTranslation("Some things in this world are too unique to replicate.", "世有物太独，不可摹也。");
            // 谎言破灭了，暴露了你可怜的真实自我。
            AddTranslation("The lie falls apart, revealing your pitiful true self.", "其伪既解，乃露汝可哀之真形。");
            // 你的造物构造太弱了。
            AddTranslation("Your creature's consitution is too weak.", "汝物之质太弱矣。");
            // 懦夫得不到勇者的恩惠。
            AddTranslation("Cowards don't get the boon of the brave.", "怯者不得勇者之惠。");
            // 爱惜自己。
            AddTranslation("Love yourself.", "自爱。");
            // 你的野兽的勇气枯萎了。
            AddTranslation("Your beast's moxie withers away.", "汝兽之锐气萎矣。");
            // 诅咒减弱了。
            AddTranslation("The curse abates.", "其诅衰矣。");
            // 因一个吻，冰雪女王冻结了它们的心。
            AddTranslation("With a single kiss, the Snow Queen froze their hearts.", "一吻而雪后冰其心。");
            // 雪融化了。也许春天来了。
            AddTranslation("The snow melts away. Perhaps spring is coming.", "雪解矣，其春将至乎。");
            // 为什么他们总是离开？
            AddTranslation("Why do they always leave?", "彼何恒去乎？");
            // 她看见她亲爱的兄弟们在远处。
            AddTranslation("She saw her dear brothers in the distance.", "其见所爱诸兄在远。");
            // 她的家人需要荨麻衣才能摆脱诅咒。
            AddTranslation("Her family that needed the nettle clothing to be free of the curse.", "其家人须荨衣，而后免诅。");
            // 她倒在地上，呕吐得像城市里的其他人一样。
            AddTranslation("She fell to the ground, vomiting ooze like the rest of [c:bR]the City[c:].", "其仆于地，呕秽如[c:bR]城[c:]中余众。");
            // 湖面轻轻泛起涟漪。仿佛许多天鹅刚刚飞走。
            AddTranslation("The lake ripples gently. As if a number of swans just took flight.", "湖面微波，若群鹄方逝。");
            // 贪婪的惩罚就是得到你想要的一切。
            AddTranslation("The punishment for greed is getting everything you wanted.", "贪之罚，得其所欲尽耳。");
            // 一个新的巢穴诞生了。
            AddTranslation("A new nest is born.", "新巢生矣。");
            // 状态溢出
            AddTranslation("Status Effect Overflow", "状溢");
            // 如果一张卡有5个以上的状态效果，将由此印记显示溢出。
            AddTranslation("If a card has more than 5 status effects, display the overflow here.", "一牌若有五以上之状，则其溢见于此。");
            // 无人可以治愈。
            AddTranslation("No one to heal.", "无人可疗。");
            // 无人能受此祝福。[c:bR]敌人[c:]亦足以代替之。
            AddTranslation("No allies to receive a blessing. [c:bR]An enemy[c:] will suffice instead.", "无友可受此祝。[c:bR]敌[c:]亦可代之。");
            // 连敌人也没有，看来这回合谁也别想得到祝福了。
            AddTranslation("No enemies either. It seems no blessings will be given this turn.", "敌亦无之，则此合无所施祝矣。");
            // 该敌人对寒冷效果免疫。
            AddTranslation("The enemy is immune to the cold.", "其敌不受寒。");
            // 其内心过于强大，无法被束缚。
            AddTranslation("Its heart is too strong to ensare.", "其心太强，不可羁也。");
            // 该造物燃烧者炽热的战意，对寒冷效果免疫。
            AddTranslation("This creature burns with passion. It cannot freeze.", "此物志炽，不可冰也。");
            // 寒气无法突破该目标，请另选目标。
            AddTranslation("Frost cannot penetrate this one. Choose another.", "寒不得入此物，宜更择之。");
            // 樵夫将熔化之心嵌入自己的胸腔。
            AddTranslation("The Woodcutter stuffs the melted heart into his chest.", "樵者纳熔心于其胸。");
            // 此类工具当前仍处于隐匿状态。
            AddTranslation("These tools remain hidden for now.", "此器今犹匿。");
            // 空间不足，藤蔓无法生长。
            AddTranslation("Not enough space for the vines to grow.", "地不足，藤不得长。");
            // 没有人听到你的消息。
            AddTranslation("There's no one to hear your message.", "无人闻汝言。");
            // 你必须选择另一张己方卡牌执行传教。
            AddTranslation("You must choose one of your other cards to proselytise.", "汝须择他友牌之一以传教。");

            // Card
            // 配置中禁用了异常印记。这可能会打破现状。
            AddTranslation("Abnormal Sigils is disabled in the configuration. This will likely break things.", "配置中已禁用异常印。此举恐有所破。");
            // 异常印记已加载！
            AddTranslation("Abnormal Sigils loaded!", "异常印已载！");
            // 蕾蒂希娅的小伙伴
            AddTranslation("Little Witch's Friend", "小巫之友");
            // 蕾蒂希娅的大伙伴
            AddTranslation("Little Witch's Big Friend", "小巫之巨友");
            // 史莱姆
            AddTranslation("Slime", "胶");
            // 钉子
            AddTranslation("Nail", "钉");
            // 杰克
            AddTranslation("Jack", "杰克");
            // 南瓜头
            AddTranslation("Pumpkin", "南瓜");
            // 树苗
            AddTranslation("Sapling", "苗木");
            // 工蜂
            AddTranslation("Worker Bee", "工蜂");
            // 冰块
            AddTranslation("Block of Ice", "冰块");
            // 冰封之心
            AddTranslation("Frozen Heart", "冰心");
            // 刺藤
            AddTranslation("Thorny Vines", "棘藤");
            // 蜘蛛巢
            AddTranslation("Spider Brood", "蛛巢");
            // 幼蛛
            AddTranslation("Spiderling", "幼蛛");
            // 大哥
            AddTranslation("First Brother", "长兄");
            // 二哥
            AddTranslation("Second Brother", "仲兄");
            // 三哥
            AddTranslation("Third Brother", "三兄");
            // 四哥
            AddTranslation("Fourth Brother", "四兄");
            // 五哥
            AddTranslation("Fifth Brother", "五兄");
            // 六哥
            AddTranslation("Sixth Brother", "六兄");
            // 孢子衍生物
            AddTranslation("Spore Mold Creature", "孢生物");
            // 虚无
            AddTranslation("Nihil", "虚无");
            // 此印记表示的值等于全场的空位数量。
            AddTranslation("The value represented by this sigil will be equal to the number of empty spaces on the board.", "此印所表之值，等于全局空位之数。");
            // 印记力量
            AddTranslation("Sigil Power", "印威");
            // 此印记表示的值将等于带有此印记的卡牌拥有的最强印记的力量等级。
            AddTranslation("The value represented with this sigil will be equal to the power level of this card's strongest sigil.", "此印所表之值，等于此牌最强之印威等。");
            // 史莱姆之爱
            AddTranslation("Loving Slimes", "爱胶");
            // 此印记表示的值将等于持牌人一侧的史莱姆数量。
            AddTranslation("The value represented by this sigil will be equal to the number of Slimes that the owner has on their side of the table.", "此印所表之值，等于其主一侧之胶数。");
            // 流逝的时间
            AddTranslation("Passing Time", "逝时");
            // 此印记表示的值将等于自带有此印记的牌上场后经过的回合数。
            AddTranslation("The value represented with this sigil will be equal to the number of turns that have passed since this card was placed on the board.", "此印所表之值，等于此牌既陈之后所历之合数。");
            // 绑定
            AddTranslation("Bind", "缚");
            // [creature]在绑定值较低的友方卡牌之后进行攻击。当绑定值为4时，也会在对位卡牌攻击之后进行攻击。此卡牌在攻击时或下一回合开始时，会移除所有绑定值。
            AddTranslation("This card attacks after ally cards with less Bind. At 4 Bind, attack after opposing cards as well. Remove all Bind from this card when it attacks or on next upkeep.", "此牌后于缚值较小之友牌而攻。缚至四，则亦后于敌牌而攻。及其攻时，若次合始，则其缚尽去。");
            // [creature]在攻击匆忙值较低的友方卡牌之前先行攻击。当其匆忙值为4时，也会优先于敌方卡牌进行攻击。此卡牌在攻击时或下一回合开始时，其匆忙值将被移除。
            AddTranslation("This card attacks before ally cards with less Haste. At 4 Haste, attack before opposing cards as well. Remove all Haste from this card when it attacks or on next upkeep.", "此牌先于疾值较小之友牌而攻。疾至四，则亦先于敌牌而攻。及其攻时，若次合始，则其疾尽去。");
            // 卵石
            AddTranslation("Pebble", "卵石");
            // [creature]在持牌人的回合结束时恢复1点生命值。当此牌被攻击时，将受到的伤害减少1。
            AddTranslation("This card regains 1 Health at the end of the owner's turn. When this card is struck, reduce the received damage by 1.", "持牌者合终，此牌命复一。见击，则所受之伤减一。");
            // 鞭笞
            AddTranslation("Flagellated", "鞭创");
            // [creature]被攻击时，受到的伤害与此印记值相等。
            AddTranslation("When this card is struck, take damage equal to this status effect.", "[creature]见击，则受伤等于此状之值。");
            // 孢子
            AddTranslation("Spores", "孢");
            // 在持牌人的回合开始时，[creature]受到的伤害等于它孢子值。死亡后，创建一个属性等于其孢子值的孢子衍生物。
            AddTranslation("At the start of its owner's turn, this card takes damage equal to its Spores. Upon dying, create a Spore Mold Creature with stats equal to its Spores.", "其主合始，此牌受伤等于其孢值。既死，则生一孢生物，其数等其孢。");
            // 裸虫
            AddTranslation("Worms", "裸虫");
            // 在持牌人的回合开始时，[creature]将获得1裸虫值。在裸虫值大于5时，改为攻击友方造物，有概率给被击中的卡牌1点裸虫值。
            AddTranslation("At the start of the owner's turn, this card gains 1 Worms. At 5+ Worms, attack allied creatures instead with a chance to give 1 Worms to struck cards.", "持牌者合始，[creature]得裸虫一。裸虫五以上，则反攻友物，且或以裸虫一授所击之牌。");
        }

    }

    public class WhistleWindLobotomyMod
    {
        public static void RegisterTranslations()
        {

            // other
            // 附录12，第二节 - 状态效果{0}
            AddTranslation("APPENDIX XII, SUBSECTION II - STATUS EFFECTS {0}", "附编十二，第二节——诸状{0}");
            // 你没有卡牌可以选择。
            AddTranslation("There are no cards you can choose.", "无可择之牌。");
            // 你不能瞄准空气。
            AddTranslation("You can't target the air.", "不得指虚空。");
            // 你必须从其他卡牌中选择一张。
            AddTranslation("You must choose one of your other cards.", "汝须择他牌之一。");
            // 它已经锁上了...
            AddTranslation("It's already latched...", "其已见契矣……");
            // 传花母本
            AddTranslation("LatchParent", "遗契母本");
            // 井中爬出的异物归入了你的旅队。你对身后井口的阵阵哀嚎置若罔闻，只管催着队伍加速赶路。
            AddTranslation("The creature rises from the well and joins your caravan. Ignoring the cries from the well, you hastily continue on.", "井中有物出，而入汝旅队。汝弗顾井中之号，亟驱众而前。");
            // 你可选择[c:bR]1[c:]张加入己方队伍，其余个体将永沉于渊，被彻底遗忘。
            AddTranslation("You may choose [c:bR]1[c:] to join you. The others will remain submerged and forgotten.", "汝可择[c:bR]1[c:]以从己。其余则永沈于渊，而为人忘。");
            // 虔敬
            AddTranslation("Adoration", "钦慕");
            // 持牌人回合开始时，若“溶解之爱”生命值为1，则吸收相邻史莱姆卡牌的生命值，直至“溶解之爱”恢复至最大生命值。
            AddTranslation("At the start of the owner's turn, if Melting Love is at 1 Health, absorb the Health of adjacent Slime cards until Melting Love is at max Health.", "其主合始，若“溶爱”惟一命，则吸邻胶牌之命，至“溶爱”复其极。");
            // 下
            AddTranslation("Down", "下");
            // [c:bR]蒙受恩泽之人啊，当称颂欢歌。因我与你们同在。[c:]
            AddTranslation("[c:bR]Ye who are full of blessings, rejoice. For I am with ye.[c:]", "[c:bR]尔既蒙祐，可乐也。盖我与尔偕。[c:]");
            // [c:bR]无人能挡我登神之路。[c:]
            AddTranslation("[c:bR]Thou cannot stop my ascension.[c:]", "[c:bR]汝不能遏我之升。[c:]");
            // [c:bR]宿命之刻已至，我将为你指明道路。[c:]
            AddTranslation("[c:bR]The time has come again. I will be thy guide.[c:]", "[c:bR]时复至矣，我将为汝导。[c:]");
            // [c:bR]起来吧，我的仆从，欢唱着迎接我的到来。[c:]
            AddTranslation("[c:bR]Rise, my servants. Rise and serve me.[c:]", "[c:bR]起，我仆也。起而事我。[c:]");
            // [c:bR]除我之外，你不得信奉任何神明。[c:]
            AddTranslation("[c:bR]Thou shalt have no other gods before me.[c:]", "[c:bR]汝于我前，毋有他神。[c:]");
            // 时钟之轮，正缓缓驶向救赎彼岸。
            AddTranslation("The hands of the Clock move towards salvation.", "钟针徐趋于救。");
            // [c:bR]待到那一日降临，来找到我。[c:]
            AddTranslation("[c:bR]When the day comes, find me.[c:]", "[c:bR]其日既至，来求我。[c:]");
            // [c:bR]渡你脱出毁灭，于终末将你重塑。[c:]
            AddTranslation("[c:bR]I will save your life from destruction and raise you from the end of the world.[c:]", "[c:bR]我将拯汝于毁，而举汝自终末。[c:]");
            // 赐福
            AddTranslation("Bless", "祐");
            // 每当疫医通过治愈印记成功治疗其他卡牌时，其自身形态将会发生改变。
            AddTranslation("Whenever Plague Doctor successfully heals another card using the Healer sigil, it changes its appearance.", "疫医凡以医印疗他牌而成，则变其形。");
            // 盲怒
            AddTranslation("Blind Rage", "瞽怒");
            // 愤怒侍从在攻击时将瞄准场上的随机位置，优先考虑已有卡牌的空间。
            AddTranslation("Servant of Wrath will target a random space on the board when attacking, prioritising occupied spaces.", "忿之侍攻时，偶指局中一位，先取有牌者。");
            // [数据删除]
            AddTranslation("CENSORED", "[削档]");
            // 每当[数据删除]击杀敌方卡牌时，将一张携带有该被击杀卡牌的攻击力、族群及印记的[数据删除]置入你的手牌。
            AddTranslation("Whenver CENSORED kills a card, create a CENSORED in your hand with the killed card's Power, tribes, and sigils.", "凡[削档]杀一牌，则汝手中生一[削档]，具彼牌之威、属与印。");
            // 和谐
            AddTranslation("Concord", "和");
            // 当阳卡牌与阴卡牌相邻时，激活特殊能力。
            AddTranslation("When Yang is adjacent to Yin, activate a special sequence.", "阳牌邻阴牌，则发异序。");
            // 懦夫
            AddTranslation("Cowardly", "怯");
            // 若场上存在非地形友方卡牌，胆小的猫咪将变形为更强形态；反之，则变形为弱化形态。
            AddTranslation("If there is an non-Structure ally card on the board, Scaredy Cat transforms into a stronger forme. Otherwise transform into a weaker forme.", "局中若有非地形之友牌，则怯猫化为强形；不然，则化为弱形。");
            // 绛红血痕
            AddTranslation("Crimson Scar", "绛痕");
            // 当又大又可能很坏的狼与小红帽雇佣兵中任意一方登场时，另一方将获得 1 点攻击力；且二者同时在场期间，彼此会将对方列为唯一攻击目标。
            AddTranslation("Big and Will Be Bad Wolf and Red Hooded Mercenary will gain 1 Power when their counterpart is played on the board. While they're on the board, target them exclusively.", "“大而将恶之狼”与“红兜佣者”，其对者既陈，则威益一；二者并在局，则各专指其对。");


            // ability
            // 黑森林的怪物
            AddTranslation("Monster in the Black Forest", "黑林之怪");
            // “从前，有三只鸟儿栖息在苍翠密林，日子过得安宁祥和……”
            AddTranslation("'Once upon a time, three birds lived happily in the lush forest...'", "“昔有三鸟，安居茂林……”");
            // 三鸟合一，化作一体，却仍徒劳地在林间徘徊，寻觅着那所谓的怪物。
            AddTranslation("The three birds, now one, wandered vainly looking for the monster.", "三鸟今合为一，而犹徒行于林，求彼所谓怪者。");
            // 使徒
            AddTranslation("Apostle", "使徒");
            // “汝将舍弃肉身，重获新生。”
            AddTranslation("'Thou wilt abandon flesh and be born again.'", "“汝将舍肌，而复生。”");
            // 巨眼
            AddTranslation("Big Eyes", "巨目");
            // 此卡牌在场期间，场上所有单位均不受力量变动效果影响。
            AddTranslation("While this card is on the board, all creatures on the board are unaffected by Power-changing effects.", "此牌在局，则局上诸物皆不受易威之效。");
            // 此卡牌在场期间，场上所有单位均不受力量变动效果影响。当生命值达到80/60/40时，永久禁用此效果，然后切换阶段。
            AddTranslation("While this card is on the board, all creatures on the board are unaffected by Power-changing effects. Upon reaching 80/60/40 Health, permanently disable this effect then switch phase.", "此牌在局，则局上诸物皆不受易威之效。命至80/60/40，则永废此效，而易其阶段。");
            // 忏悔与救赎
            AddTranslation("Confession and Pentinence", "忏与赎");
            // 怀坚定之心，持不渝之信。
            AddTranslation("Keep faith with unwavering resolve.", "执志不挠，而守其信。");
            // [c:bG]怀坚定之心，持不渝之信。[c:]
            AddTranslation("[c:bG]Keep faith with unwavering resolve.[c:]", "[c:bG]执志不挠，而守其信。[c:]");
            // 光耀
            AddTranslation("Dazzling", "耀");
            // 此卡牌打出的下一回合，可为场上至多3张其他卡牌施加附魔状态。
            AddTranslation("The turn after this card is played, inflict up to 3 other cards on the board with Enchanted.", "此牌既陈之一合后，可使局上他牌至三受附魔。");
            // 如飞蛾扑火，趋之若鹜。
            AddTranslation("Like moths to a flame.", "如蛾赴火。");
            // 长臂
            AddTranslation("Long Arms", "长臂");
            // 此卡牌免疫所有状态异常。
            AddTranslation("This card is immune to status ailments.", "此牌不受诸异状。");
            // 此卡牌免疫所有状态异常。当生命值达到80/60/40时，永久禁用此效果，然后切换阶段。
            AddTranslation("This card is immune to status ailments. Upon reaching 80/60/40 Health, permanently disable this effect then switch phase.", "此牌不受诸异状。命至80/60/40，则永废此效，而易其阶段。");
            // 灭罪
            AddTranslation("Misdeeds Not Allowed", "禁恶");
            // 此卡牌每次受到伤害，在持牌人回合结束前获得1点攻击力。
            AddTranslation("Whenever this card takes damage, gain 1 Power until the end of the owner's turn.", "此牌凡受伤，则威益一，至其主合终。");
            // 小喙
            AddTranslation("Small Beak", "小喙");
            // 回合开始时，随机选定场上一条战线。下一回合开始时，消灭该战线内所有卡牌，此牌除外。
            AddTranslation("At the start of the turn, target a random lane on the board.  At the start of the next turn, kill all cards in the targeted lane, excluding this card.", "合始，偶指局中一列。次合始，尽杀其列诸牌，此牌除外。");
            // 回合开始时，随机选定场上一条战线。下一回合开始时，消灭该战线内所有卡牌，此牌除外。当生命值达到80/60/40时，永久禁用此效果，然后切换阶段。
            AddTranslation("At the start of the turn, target a random lane on the board.  At the start of the next turn, kill all cards in the targeted lane, excluding this card. Upon reaching 80/60/40 Health, permanently disable this effect then switch phase.", "合始，偶指局中一列。次合始，尽杀其列诸牌，此牌除外。命至80/60/40，则永废此效，而易其阶段。");
            // 时间机器
            AddTranslation("Time Machine", "时机");
            // 结束当前战斗或阶段，随后将此牌移出玩家牌库。玩家必须从3张按战力筛选的卡牌中，额外选择1张移出牌库。
            AddTranslation("End the current battle or phase then remove this card from the player's deck. The player must choose an additional card from a selection of 3 to remove from their deck. Selection is based on card power.", "终今战若今阶段，而后去此牌于戏徒牌列。戏徒更须于按牌威所选之三牌中，择一并去之。");

            // BackwardClock
            // 闭上你的双眼，数到十吧。
            AddTranslation("Close your eyes and count to ten.", "阖汝目而数至十。");
            // 终焉救世主
            AddTranslation("True Saviour", "真救主");
            // “吾之过往，无处安放，无人知晓。”
            AddTranslation("'My story is nowhere, unknown to all.'", "“吾之往事，无所寄，亦无人知。”");
            // [c:bR]吾即是死亡，亦是生机；既是深渊，亦是曙光。[c:]
            AddTranslation("[c:bR]I am death and life. Darkness and light.[c:]", "[c:bR]我即死与生、幽与明也。[c:]");
            // 谬判天平
            AddTranslation("Unjust Scale", "枉衡");
            // 持牌人回合结束时，此牌将对其余所有卡牌施加1层罪孽；持牌人回合开始时，此牌将消灭所有叠加3层及以上罪孽的其他卡牌。
            AddTranslation("At the end of the owner's turn, inflict 1 Sin on all other cards. At the start of owner's turn, kill all other cards with 3+ Sin.", "其主合终，此牌加罪一于他诸牌；其主合始，此牌杀凡有罪三以上之他牌。");
            // 快攻
            AddTranslation("Quick Draw", "先发");
            // 早起的鸟儿有虫吃。
            AddTranslation("The early bird gets the worm.", "先飞之鸟得虫。");
            // 带有此印记的卡牌上场1回合后，将转变为另一种形态。
            AddTranslation("A card bearing this sigil will transform into an alternate forme after 1 turn on the board.", "负此印之牌在局一合，则化为异形。");
            // 精准裁决
            AddTranslation("Marksman", "中的");
            // 你的野兽将精准地发起攻击。
            AddTranslation("Your beast strikes with precision.", "汝兽发击甚精。");
            // 为特殊能力增加规则书条目。
            AddTranslation("Adding rulebook entries for special abilities.", "为异技增律书条。");
            // 所有模组卡牌已禁用，添加标准教学兔兔作为备用方案，以防止出现异常。
            AddTranslation("All mod cards are disabled, adding Standard Training-Dummy Rabbit as a fallback to prevent issues.", "诸补缀牌皆禁，乃加“标准习击兔”为后备，以防有失。");


            // cards
            // 米拉贝尔
            AddTranslation("Mirabelle", "米拉贝尔");
            // 普西
            AddTranslation("Poussey", "普西");
            // 干细胞-642
            AddTranslation("Stemcell-642", "干细胞-642");
            // 诺亚
            AddTranslation("Noah", "诺亚");
            // 和弓
            AddTranslation("Yumi", "优米");
            // 夏天
            AddTranslation("Summer", "夏");
            // 卡林斯
            AddTranslation("Currince", "卡林斯");
            // 伊戈里
            AddTranslation("Igoree", "伊戈里");
            // 灯神
            AddTranslation("Genie", "灯神");
            // 茂
            AddTranslation("Mao", "茂");
            // 伊万杰琳
            AddTranslation("Evangeline", "伊万杰琳");
            // 钨西尔
            AddTranslation("Ttungsil", "钨西尔");
            // 玛贝尔
            AddTranslation("Mabel", "玛贝尔");
            // 说谎的大人
            AddTranslation("The Adult Who Tells Lies", "言诳之长者");
            // 小帮手
            AddTranslation("All-Around Helper", "周助");
            // 嗜杀的清洁机器人。可比另一个家伙友善多了……罢了，不提也罢。
            AddTranslation("A murderous cleaning machine. Far nicer than a certain other...well, nevermind.", "嗜杀之洒扫机，然较彼一物，犹为善矣……已矣，勿言。");
            // 爱娜温
            AddTranslation("Alriune", "爱娜温");
            // 一心渴望化作人类的玩偶，一心渴望变为玩偶的人类。
            AddTranslation("A doll yearning to be a human. A human yearning to be a doll.", "欲为人之偶，与欲为偶之人。");
            // 安吉拉
            AddTranslation("Angela", "安吉拉");
            // 一台值得信赖的人工智能助手。你愿将性命托付于她。
            AddTranslation("A trustworthy AI assistant. You will trust her with your life.", "可信之智机佐也。汝将以性命托之。");
            // 大鸟之相
            AddTranslation("Aspect of Big Bird", "大鸟之相");
            // 小鸟之相
            AddTranslation("Aspect of Small Bird", "小鸟之相");
            // 长鸟之相
            AddTranslation("Aspect of Long Bird", "长鸟之相");
            // 瞳羽幼雏
            AddTranslation("Eyeball Chick", "瞳雏");
            // 黯林守役
            AddTranslation("Keeper of the Black Forest", "黑林守者");
            // 逃逸之鸟
            AddTranslation("Runaway Bird", "逸鸟");
            // 终末鸟
            AddTranslation("Apocalypse Bird", "终鸟");
            // 守护使徒
            AddTranslation("Guardian Apostle", "守使徒");
            // 异教徒
            AddTranslation("Heretic", "异教徒");
            // 鼹鼠使徒
            AddTranslation("Moleman Apostle", "鼹人使徒");
            // 镰刀使徒
            AddTranslation("Scythe Apostle", "镰使徒");
            // 长枪使徒
            AddTranslation("Spear Apostle", "矛使徒");
            // 魔杖使徒
            AddTranslation("Staff Apostle", "杖使徒");
            // 深黯“军团”
            AddTranslation("Army in Black", "玄军");
            // 深黯“军团”
            AddTranslation("Army in Pink", "绯军");
            // 一名友善的粉色奇兵。无论你去往何处，它都会护你周全。
            AddTranslation("A friendly pink soldier. It will protect you wherever you go.", "绯卒之善者也。汝所往之处，彼皆护汝。");
            // 回溯之钟
            AddTranslation("Backward Clock", "反时钟");
            // 一枚能倒转你虚度光阴的时钟。你，愿支付相应的代价吗？
            AddTranslation("A clock to rewind your wasted time. Will you pay the toll?", "能反汝虚度之时者，钟也。汝其偿其直乎？");
            // 美女和野兽
            AddTranslation("Beauty and the Beast", "丽人与兽");
            // 一只可悲的生灵。死亡于它而言，已是一种仁慈。
            AddTranslation("A pitiable creature. Death would be a mercy for it.", "可哀之物也。死于之，乃恕也。");
            // 行为矫正仪
            AddTranslation("Behaviour Adjustment", "正行器");
            // 一台用于 “修正” 迷途凶兽的装置。只是，它所定义的 “修正”，未必与你同源。
            AddTranslation("A device made to 'fix' errant beasts. Its idea of 'fixing' might not be yours, however.", "所以“正”迷兽之器也。然其所谓“正”，未必同于汝。");
            // 大鸟
            AddTranslation("Big Bird", "大鸟");
            // 它的双眼如星辰般点亮了黑暗。
            AddTranslation("Its eyes light up the darkness like stars.", "其目烛幽，若星然。");
            // 比娜
            AddTranslation("Binah", "比娜");
            // 她的力量虽不及往日，但依旧能成为你坚实的助力。
            AddTranslation("Though not as powerful as she once was, she will still make a great ally.", "其威虽不逮昔，而犹足为善助。");
            // 血浴缸
            AddTranslation("Bloodbath", "血浴");
            // 满满一盆血水。里头竟泡着那些你曾经爱过的人的手。
            AddTranslation("A tub of blood. The hands of people you once loved wait inside.", "盛血之一浴也。汝昔所爱者之手，浸其中焉。");
            // 碧蓝新星
            AddTranslation("Blue Star", "青星");
            // 当一切尘埃落定，我们便化作明星再会吧。
            AddTranslation("When this is over, let's meet again as stars.", "事毕之后，愿我曹复会于星。");
            // 穿刺乐园
            AddTranslation("The Burrowing Heaven", "贯天");
            // 不要看别处，一直盯着他，让它待在你的视线之内
            AddTranslation("Don't look away. Contain it in your sight.", "毋他顾，常系之于视。");
            // 皱巴巴的汽水罐头
            AddTranslation("Crumpled Can of WellCheers", "皱罐");
            // 生锈的汽水罐头
            AddTranslation("Rusted Can of WellCheers", "锈罐");
            // 骷髅虾
            AddTranslation("Skeleton Shrimp", "枯骨虾");
            // 韦尔奇乐牌汽水
            AddTranslation("Opened Can of WellCheers", "既启之汽罐");
            // 一台贩售海洋汽水的自动售货机。
            AddTranslation("A vending machine dispensing ocean soda.", "鬻海汽饮之机也。");
            // [数据删除]
            AddTranslation("CENSORED", "[削档]");
            // 最好永远别去知晓它的真面目。
            AddTranslation("It's best you never learn what it looks like.", "终毋知其真形为上。");
            // 海赛德
            AddTranslation("Chesed", "海赛德");
            // 没有什么比一杯香醇的咖啡，更适合开启新的一天了。
            AddTranslation("Nothing like a fresh cup of coffee to start your day.", "启新日者，莫若一杯新啡。");
            // 银河之子
            AddTranslation("Child of the Galaxy", "银河之子");
            // 一个渴求永恒挚友的孩童。你愿成为他的归宿吗？
            AddTranslation("A small child longing for an eternal friend. Will you be his?", "求永友之童也。汝愿为其友乎？");
            // 破裂盔甲
            AddTranslation("Crumbling Armour", "圮铠");
            // 一身褒奖勇者、惩戒懦夫的铠甲。
            AddTranslation("A suit of armour that rewards the brave and punishes the cowardly.", "赏勇而罚怯之铠也。");
            // 月光女神
            AddTranslation("Il Pianto della Luna", "月泣");
            // 事实却是，人类正对着月亮深陷绝望。
            AddTranslation("In reality, man despairs at [c:bR]the moon[c:].", "然人实向[c:bR]月[c:]而绝望。");
            // 魔弹射手
            AddTranslation("Der Freischütz", "魔弹者");
            // 于某些人而言，他是友善的猎手；于另一些人而言，却是冷酷的枪手。他的子弹，从未有过落空之时。
            AddTranslation("A friendly hunter to some, a cruel gunsman to others. His bullets always hit their mark.", "于或人为善猎者，于或人为酷铳手。其弹未尝失的。");
            // 别碰我
            AddTranslation("Don't Touch Me", "毋触我");
            // 别碰它。
            AddTranslation("Don't touch it.", "毋触之。");
            // 次元衍射变体
            AddTranslation("Dimensional Refraction Variant", "次元折变体");
            // 四维衍射变体
            AddTranslation("4th Dimensional Refraction Variant", "四维折变体");
            // 一种诡异的现象。或者更准确地说，这一生物本身，就是现象的具象化。
            AddTranslation("A strange phenomenon. Or rather, the creature is the phenomena in and of itself.", "怪象也。毋宁曰：此物即其象也。");
            // 梦中的洋流
            AddTranslation("The Dreaming Current", "梦流");
            // 一个病弱的孩童。每日，它都会被投喂那种能让它窥见海洋的糖果。
            AddTranslation("A sickly child. Everyday it was fed candy that let it see the ocean.", "病羸之童也。日饲以糖，使得见海。");
            // 现世的洋流
            AddTranslation("The Elder Dreaming Current", "老梦流");
            // 黑天鹅之梦
            AddTranslation("Dream of a Black Swan", "玄鹄之梦");
            // 她是六个兄弟的姐姐，曾不眠不休地守护着他们，可一切努力，终究是徒劳无功。
            AddTranslation("Sister of six brothers. Tirelessly she worked to protect them, all for naught.", "六兄之姊也。勤而无倦，以护诸兄，终徒劳耳。");
            // 黄泉列车
            AddTranslation("Express Train to Hell", "黄泉列车");
            // 当宿命降临之时，列车将鸣响其撼天动地的汽笛。
            AddTranslation("When the time comes, the train will sound its mighty horn.", "其时既至，列车将鸣其巨角。");
            // 精灵盛宴
            AddTranslation("Fairy Festival", "精怪之会");
            // 只要有了小精灵们的祝福，一切争端都会平息下来的。
            AddTranslation("Everything will be peaceful while you're under the fairies' care.", "汝在群精之护，则万争皆息。");
            // 血肉偶像
            AddTranslation("Flesh Idol", "肉偶");
            // 任何祈祷，最终都逃不过以信徒的彻底绝望收场。
            AddTranslation("Prayer inevitably ends with the worshipper's despair.", "祷之终，未有不归信者之绝望者也。");
            // 被遗弃的杀人魔
            AddTranslation("Forsaken Murderer", "弃杀者");
            // 惨遭实验，而后被彻底遗忘。曾经的满腔怒火，已然化为刻骨的憎恶。
            AddTranslation("Experimented on then forgotten. What was anger has become abhorrence.", "尝见试而后见遗。其忿已化为深憎。");
            // 宇宙碎片
            AddTranslation("Fragment of the Universe", "宇宙片");
            // 耳边响起的悦耳的歌声，它正慢慢朝你靠近...每一秒都在变得愈发绚烂斑斓。
            AddTranslation("You see a song in front of you. It's approaching, becoming more colourful by the second.", "汝见歌在前，徐徐而近，须臾益灿。");
            // 亡蝶葬仪
            AddTranslation("Funeral of the Dead Butterflies", "亡蝶葬");
            // 这具棺椁，是献给逝者的礼赞，亦是祭奠那些魂断他乡之人的碑铭。
            AddTranslation("The coffin is a tribute to the fallen. A memorial to those who can't return home.", "此棺者，所以礼死者，亦所以志不得归者。");
            // 盖布拉
            AddTranslation("Gebura", "盖布拉");
            // 惩戒部部长。一位勇猛善战的战士，亦是值得信赖的盟友。
            AddTranslation("Head of the Disciplinary Team. A fierce warrior and ally.", "惩戒部之长。猛士，亦可恃之友。");
            // 巨树汁液
            AddTranslation("Giant Tree Sap", "巨树液");
            // 末世之树所产的树液。此物乃是一剂强效的疗伤圣品。
            AddTranslation("Sap from a tree at the end of the world. It is a potent healing agent.", "终末之树所出之液，良疗也。");
            // 亡蝶葬仪二世
            AddTranslation("2nd Funeral of the Dead Butterflies", "再亡蝶葬");
            // 樱下墓
            AddTranslation("Grave of Cherry Blossoms", "樱冢");
            // 一株盛放的樱花树。尸骨逐渐堆积，樱海愈加美丽。
            AddTranslation("A blooming cherry tree. The more blood it has, the more beautiful it becomes.", "樱华方盛。其血愈多，其美愈甚。");
            // 快乐泰迪
            AddTranslation("Happy Teddy Bear", "乐熊");
            // 一只遭人遗弃的毛绒熊，它的记忆始于一个温暖的怀抱。
            AddTranslation("A discarded stuffed bear. Its memories began with a warm hug.", "弃置之绣熊，其忆始于温抱。");
            // 渴望之心
            AddTranslation("The Heart of Aspiration", "志心");
            // 一颗无人认领的心脏。它能为周遭之人赋予无畏的勇气。
            AddTranslation("A heart without an owner. It emboldens those nearby.", "无主之心，能壮近者。");
            // 霍德
            AddTranslation("Hod", "霍德");
            // 死亡虽无可避免，但做好万全准备，总归不是坏事，不是吗？
            AddTranslation("Though death is guaranteed, it never hurts to be prepared, right?", "死虽必至，然预备无伤，不然乎？");
            // 霍克玛
            AddTranslation("Hokma", "霍克玛");
            // 万事皆会应时发生，心怀信念就好。
            AddTranslation("All things will happen in time. Just have faith.", "万事皆各有时，惟持信耳。");
            // 风云法师
            AddTranslation("Honoured Monk", "荣僧");
            // 一位欲以善举求得觉悟的僧人。可通往涅槃之境，定然有更为捷径的法门……
            AddTranslation("A monk seeking enlightenment through good deeds. But surely there's a quicker way to nirvana...", "求悟于善行之僧。然涅槃岂无捷径……");
            // 一罪与百善
            AddTranslation("One Sin and Hundreds of Good Deeds", "一罪百善");
            // 虚无弄臣
            AddTranslation("The Jester of Nihil", "虚弄臣");
            // 审判鸟
            AddTranslation("Judgement Bird", "谳鸟");
            // 一头身形颀长的神鸟，以雷厉风行之姿审判罪愆。它的天平能够绝对公正地衡量任何罪恶。
            AddTranslation("A long bird that judges sinners with swift efficiency. It alone is above consequences.", "长鸟也，迅而谳罪。惟彼独不受其报。");
            // 蕾蒂希娅
            AddTranslation("Laetitia", "蕾蒂希娅");
            // 一位怀揣心形赠礼的小女巫。
            AddTranslation("A little witch carrying a heart-shaped gift.", "一小女巫，怀携心形之赠礼。");
            // 荧光手镯
            AddTranslation("Luminous Bracelet", "荧镯");
            // 这个手镯绝不会饶恕那些贪婪的鼠辈，所以只给那些有需要的人佩戴，可庇佑持有者痊愈。
            AddTranslation("A bracelet that will heal its bearer. It does not forgive the greedy.", "疗持者之镯也，不赦贪者。");
            // 愤怒侍从
            AddTranslation("The Servant of Wrath", "忿侍");
            // 一位来自异界的盲人守护者。
            AddTranslation("Blind protector of another world.", "异界之瞽护者。");
            // 贪婪女王
            AddTranslation("The King of Greed", "贪王");
            // 一位被凝固琥珀封存的少女。幸福，就此被贪婪牢牢禁锢。
            AddTranslation("A girl encased in hardened amber. Happiness trapped by greed.", "琥珀所锢之女也。乐为贪所执。");
            // 憎恶女王
            AddTranslation("The Queen of Hatred", "憎王");
            // 魔法少女
            AddTranslation("Magical Girl", "术少女");
            // 一位秉持爱与正义的英雄。她将在你的征途上施以援手。
            AddTranslation("A hero of love and justice. She will aid you on your journey.", "爱与义之雄也。彼将助汝于途。");
            // 绝望骑士
            AddTranslation("The Knight of Despair", "绝望骑者");
            // 那名骑士心怀赤诚忠勇，誓要为守护身边之人，奋战至终。
            AddTranslation("A loyal knight fighting to protect those close to her.", "忠骑也，为护所亲而战。");
            // 玛尔库特
            AddTranslation("Malkuth", "玛尔库特");
            // 控制部部长，她将愿以所能为你提供全方位协助。
            AddTranslation("The head of the Control Team, here to assist you any way she can.", "御队之长，将尽所能以佐汝。");
            // 陆生鮟鱇
            AddTranslation("Meat Lantern", "肉灯");
            // 一朵绽放在神秘生物身上的绮丽之花。
            AddTranslation("A beautiful flower attached to a mysterious creature.", "附于异物之丽花也。");
            // 溶解之爱
            AddTranslation("Melting Love", "溶爱");
            // 别让你们负责的那些异想体靠得太近。
            AddTranslation("Don't let your beasts get too close now.", "毋令汝兽近之太甚。");
            // 1.76兆赫
            AddTranslation("1.76 MHz", "1.76兆赫");
            // 这是我们绝对不能忘记的“那一天”的记录。
            AddTranslation("This is a record, a record of a day we must never forget.", "此记录也，记吾曹永不可忘之一日。");
            // 转性魔镜
            AddTranslation("The Mirror of Adjustment", "易性镜");
            // 一面镜面毫无映照的魔镜，唯有诡异螺旋在黑暗中隐现。
            AddTranslation("A mirror that reflects nothing on its surface.", "不照物之镜也。");
            // 微笑的尸山
            AddTranslation("The Mountain of Smiling Bodies", "笑尸山");
            // 一片尸骸堆积之地，经消融凝聚化作一头永不知足的饿兽。
            AddTranslation("A mass grave, melted and congealed into one eternally hungry beast.", "积尸之冢，融而凝为一永饥之兽。");
            // 无名怪婴
            AddTranslation("Nameless Fetus", "无名胎");
            // 一处取之不竭的血源。切记，万勿将其唤醒。
            AddTranslation("A neverending supply of blood. Just don't wake it up.", "血源无竭，第毋觉之。");
            // 内策赫
            AddTranslation("Netzach", "内策赫");
            // 他虽向来缺乏干劲，却仍会为了达成目标拼尽全力。
            AddTranslation("Despite his lack of motivation, he'll do his best to succeed.", "虽乏志，犹将尽力以济事。");
            // 诺斯费拉图
            AddTranslation("Nosferatu", "诺斯费拉图");
            // 暗夜之兽，自带华贵王者风范。你肯出手为它平息那无尽渴求吗？
            AddTranslation("A creature of the night, noble and regal. Will you help sate its thirst?", "夜之物也，贵而有仪。汝将助其解渴乎？");
            // 癫狂研究员的笔记本
            AddTranslation("Notes from a Crazed Researcher", "狂研者札");
            // 癫狂的忏悔与无意义的呓语交织，声声都浸透着洗不清的罪孽。
            AddTranslation("An insane garble of guilty confessions and incoherent gibberish.", "罪悔与呓言之乱编也。");
            // 一无所有
            AddTranslation("Nothing There", "无有");
            // 一只蛋
            AddTranslation("An Egg", "一卵");
            // 优米
            AddTranslation("Yumi", "优米");
            // 我不记得这个挑战者...
            AddTranslation("I don't remember this challenger...", "我不识此角者……");
            // 古老的信念与承诺
            AddTranslation("Old Faith and Promise", "旧信与诺");
            // 一颗神秘的大理石珠。摒弃欲望与期待去使用它，或许便能获得馈赠。
            AddTranslation("A mysterious marble. Use it without desire or expectation and you may be rewarded.", "神珠也。无欲无冀而用之，或见报焉。");
            // 老妇人
            AddTranslation("Old Lady", "老妪");
            // 一位年迈的说书人。她能为你讲述各式各样的故事，哪怕是那些本就不可能存在的传说。
            AddTranslation("An aged storyteller. She can tell you any tale, even those that can't exist.", "老说者也。虽不可有之事，亦能为汝言之。");
            // 一颗悬浮的骷髅头。它那空洞的眼窝，能将你的一切都看得通透。
            AddTranslation("A floating skull. Its hollow sockets see through you.", "浮髑髅也。其空眶洞见汝身。");
            // 奥兹玛
            AddTranslation("Ozma", "奥兹玛");
            // 曾是遥远国度的统治者，如今却沦落至此。
            AddTranslation("The former ruler of a far away land, now reduced to this.", "远邦故主，今乃沦于此。");
            // 寄生树
            AddTranslation("Parasite Tree", "寄树");
            // 一棵绮丽的巨树。它看似只想为你与设施内的异想体提供助益。
            AddTranslation("A beautiful tree. It wants only to help you and your beasts.", "丽树也。惟欲助汝与汝兽耳。");
            // 匹诺曹
            AddTranslation("Pinocchio", "匹诺曹");
            // 一尊木质玩偶，会模仿途中遇到的各类异想体野兽。你能否看穿它这层伪装的假象？
            AddTranslation("A wooden doll that mimics the beasts it encounters. Can you see through its lie?", "木偶也，遇兽则摹之。汝能识其伪乎？");
            // 疫医
            AddTranslation("Plague Doctor", "疫医");
            // 一位执掌奇迹的存在，谦逊地请求加入你的麾下。
            AddTranslation("A worker of miracles. He humbly requests to join you.", "司奇迹者也，谦请从汝。");
            // 棘刺公交
            AddTranslation("Porccubus", "棘魅");
            // 被它的一根绒刺扎到，便会产生足以致命的极致快感。
            AddTranslation("A prick from one of its quills creates a deadly euphoria.", "一刺所中，足生致命之极欢。");
            // 波迪
            AddTranslation("Ppodae", "波迪");
            // 不过是一只纯真无害的小狗罢了。
            AddTranslation("An innocent little puppy.", "纯然无害之小犬耳。");
            // 沉默的代价
            AddTranslation("Price of Silence", "默之值");
            // 时间那柄坚定不移的利刃，终将平等地斩落人类与野兽。
            AddTranslation("The unflinching hand of time cuts down man and beast alike.", "时之手不摇，均斩人与兽。");
            // 惩戒鸟
            AddTranslation("Punishing Bird", "罚鸟");
            // 一只身负惩戒恶人之命的小鸟。
            AddTranslation("A small bird on a mission to punish evildoers.", "小鸟也，奉命以惩恶。");
            // 蜂后
            AddTranslation("Queen Bee", "蜂后");
            // 一具由蜂巢与蜜蜂融合而成的畸变魔物。
            AddTranslation("A monstrous amalgam of a hive and a bee.", "蜂与房合为一之怪也。");
            // 小红帽雇佣兵
            AddTranslation("Little Red Riding Hooded Mercenary", "红兜佣者");
            // 一名技艺精湛的佣兵，身负血海深仇。或许，你能助她了结这份执念。
            AddTranslation("A skilled mercenary with a bloody vendetta. Perhaps you can help her sate it.", "善战之佣也，抱血仇焉。或汝能助其平之。");
            // 红舞鞋
            AddTranslation("Red Shoes", "红履");
            // 真漂亮啊，说不定还挺合身的呢。
            AddTranslation("How pretty. Maybe they'll fit.", "丽哉。或可适足。");
            // 雪橇鲁道夫
            AddTranslation("Rudolta of the Sleigh", "橇鲁道塔");
            // 一尊形态怪诞的驯鹿雕像。它怀抱着无尽的恨意，将 “馈赠” 赐予你。
            AddTranslation("A grotesque effigy of a reindeer. With its infinite hate, it bequeaths gifts onto you.", "怪鹿之偶也。怀无穷之恨，而以“赠”遗汝。");
            // 胆小的猫咪
            AddTranslation("Scaredy Cat", "怯猫");
            // 幸灾乐祸
            AddTranslation("Schadenfreude", "乐祸");
            // 一台构造奇特的机械装置。在机器的锁眼之中，你能感受到一只令人不安的眼睛正凝视着你。
            AddTranslation("A strange machine. You can feel someone's persistent gaze through the keyhole.", "怪机也。自钥孔间，可觉人之凝视不去。");
            // 焦化少女
            AddTranslation("Scorched Girl", "焦女");
            // 纵然已无任何可焚之物，这团火焰依旧燃之不尽。
            AddTranslation("Though there's nothing left to burn, the fire won't go out.", "虽无可焚者，火犹不灭。");
            // 3月27日的避难所
            AddTranslation("Shelter From the 27th of March", "三月二十七之庇");
            // 它通过篡改周遭现实，将自身化为世上最安全的地方。
            AddTranslation("It makes itself the safest place in the world by altering the reality around it.", "其变四周之实，而自为天下最安之所。");
            // 噤默处子
            AddTranslation("Silent Girl", "默女");
            // 一名将锤子与铁钉藏于身后的少女。
            AddTranslation("A girl hiding a hammer and nail behind her back.", "藏槌与钉于背后之女也。");
            // 椅子们
            AddTranslation("Chairs", "众椅");
            // 沉默乐团
            AddTranslation("The Silent Orchestra", "寂乐团");
            // 很快，那首无人能耳闻、却能被众生所聆听的歌谣，即将奏响。
            AddTranslation("Soon, the song none can hear but all can listen to will begin.", "顷之，无人能闻而众生皆可听之歌，将作矣。");
            // 歌唱机
            AddTranslation("Singing Machine", "歌机");
            // 一台上弦八音盒。它奏响的旋律，足以令人为之殒命。
            AddTranslation("A wind-up music machine. The song it plays is to die for.", "上弦之乐机也。其歌足以致死。");
            // 人皮启示录
            AddTranslation("Skin Prophecy", "皮书启示");
            // 一本圣典。其信徒为保全它的神圣性，竟以人皮将其包裹。
            AddTranslation("A holy book. Its believers wrapped it in skin to preserve its sanctity.", "圣书也。信者裹之以皮，以存其圣。");
            // 冰雪女皇
            AddTranslation("The Snow Queen", "雪后");
            // 一位来自遥远之地的女王。凡踏入她宫殿者，无一生还。
            AddTranslation("A queen from far away. Those who enter her palace never leave.", "远国之后也。入其宫者，无复出。");
            // 白雪公主的苹果
            AddTranslation("Snow White's Apple", "白雪之果");
            // 一枚化为人形的毒苹果。它执着追寻着属于自己的幸福结局，终究只是徒劳一场。
            AddTranslation("A poisoned apple brought to life, on a fruitless search for its own happily ever after.", "毒果成人者也。徒求其自家之终善。");
            // 白雪公主的腐烂苹果
            AddTranslation("Snow White's Rotted Apple", "白雪之腐果");
            // 蛛巢
            AddTranslation("Spider Bud", "蛛胎");
            // 一尊形态怪诞的蜘蛛之母。其幼崽虽身形渺小，生长速度却极为迅猛。
            AddTranslation("A grotesque mother of spiders. Its children are small but grow quickly.", "怪蜘蛛之母也。其子虽小，而长甚速。");
            // 炎雀
            AddTranslation("The Firebird", "火鸟");
            // 这只飞鸟，竟将被追捕猎杀的战栗，视作毕生追逐的极乐。
            AddTranslation("A bird that longs for the thrill of being hunted.", "此鸟好为人猎之战栗。");
            // 小王子
            AddTranslation("The Little Prince", "小王子");
            // 一块巨型菌核。其周身萦绕着一层孢子薄雾。
            AddTranslation("A giant mushroom chunk. A mist of spores surrounds it.", "巨蕈之块也。孢雾环其身。");
            // 裸巢
            AddTranslation("The Naked Nest", "裸巢");
            // 它们能钻进你身上的任何一处孔洞。
            AddTranslation("They can enter your body through any aperture.", "彼可由汝诸孔而入。");
            // 裸虫
            AddTranslation("Naked Worm", "裸虫");
            // 它能钻进你身上的任何一处孔洞。
            AddTranslation("It can enter your body through any aperture.", "彼可由汝诸孔而入。");
            // 特蕾西娅
            AddTranslation("Theresia", "特蕾西娅");
            // 一台老旧的八音盒。它奏响的旋律，令人倍感熟悉。
            AddTranslation("An old music box. It plays a familiar melody.", "故八音匣也。其曲甚熟。");
            // 归家的路途
            AddTranslation("The Road Home", "归途");
            // 一名与伙伴结伴、踏上归乡之旅的少女。
            AddTranslation("A young girl on a quest to return home with her friends.", "与友偕行而求归之少女。");
            // 蒂珀蕾斯
            AddTranslation("Tiphereth", "蒂珀蕾斯");
            // 双生子中的一人。切勿小觑她的能力。
            AddTranslation("One of a pair of twins. Don't underestimate her capabilities.", "双生之一也。毋轻其能。");
            // 今天也很害羞
            AddTranslation("Today's Shy Look", "今羞");
            // 一只优柔寡断的造物。每逢对其进行画像记录，它的神情皆会呈现出不同模样。
            AddTranslation("An indecisive creature. Her expression is different whenever you draw her.", "优柔之物也。汝每引之，其容辄异。");
            // 明天也很害羞
            AddTranslation("Tomorrow's Shy Look", "明羞");
            // 今天也很高兴
            AddTranslation("Today's Happy Look", "今喜");
            // 明天也很高兴
            AddTranslation("Tomorrow's Happy Look", "明喜");
            // 明天也很生气
            AddTranslation("Tomorrow's Angry Look", "明怒");
            // 今天也很生气
            AddTranslation("Today's Angry Look", "今怒");
            // 教学兔兔[Dummy]
            AddTranslation("Standard Training-Dummy Rabbit", "常式习击兔");
            // 一头形似训练假人的异兽。它是这类异常存在中最为安全的一个。
            AddTranslation("A beast in the shape of a training dummy. The safest of these abnormal creatures.", "类习偶之兽也。此等异物中最安者也。");
            // 单次召回
            AddTranslation("Single Recall", "单召");
            // 全部召回
            AddTranslation("Total Recall", "皆召");
            // 牌组重塑
            AddTranslation("Reshuffle Decks", "复乱牌列");
            // 空虚之梦
            AddTranslation("Void Dream", "虚梦");
            // 一头沉眠的山羊。又或者，那其实是绵羊？
            AddTranslation("A sleeping goat. Or is it a sheep?", "眠羊也。抑亦山羊乎？");
            // 面壁女
            AddTranslation("The Lady Facing the Wall", "向壁女");
            // 一段凝结为执念的深沉悲恸。或许，最好任由她独自静处。
            AddTranslation("A deep sorrow, grown to obsession. Perhaps it's best to leave her be.", "深哀结为执。殆任其自处为善。");
            // 面壁神女
            AddTranslation("The Elder Lady Facing the Wall", "老向壁女");
            // 热心的樵夫
            AddTranslation("Warm-Hearted Woodsman", "热肠樵者");
            // 一名追寻心脏的铁皮樵夫。或许，你可以将自己的心脏赠予他。
            AddTranslation("A tin woodsman on the search for a heart. Perhaps you can give him yours.", "锡樵求心者也。或汝可予之以心。");
            // 我们可以改变一切
            AddTranslation("We Can Change Anything", "万物可易");
            // 无论你对何物心存不满，这台机器皆能为你修正。你只需踏入其中即可。
            AddTranslation("Whatever you're dissatisfied with, this machine will fix it. You just have to step inside.", "凡汝不惬者，此机皆能正之。惟入其中耳。");
            // 白夜
            AddTranslation("WhiteNight", "白夜");
            // 时机已到。
            AddTranslation("The time has come.", "时至矣。");
            // 又大又可能很坏的狼
            AddTranslation("Big and Will Be Bad Wolf", "大而将恶之狼");
            // 生而为狼，便注定要成为童话里的恶人。
            AddTranslation("It's the fate of all wolves to be the villains of fairy tales.", "生而为狼，命为童话之恶者。");
            // 索求智慧的稻草人
            AddTranslation("Scarecrow Searching for Wisdom", "求智稻人");
            // 一具头颅空洞的稻草人。其稻草编织的四肢，早已被鲜血浸透。
            AddTranslation("A hollow-headed scarecrow. Blood soaks its straw limbs.", "首空之稻人也。其稻肢浸于血。");
            // 异世的肖像
            AddTranslation("Portrait of Another World", "异世肖像");
            // 我们必将失去什么？这幅肖像牢牢抓住了那一瞬间的精髓。
            AddTranslation("This portrait captures a moment, one we're destined to lose.", "此像取一瞬，而此瞬我曹终将失之。");
            // 阳
            AddTranslation("Yang", "阳");
            // 一枚能治愈周遭之人的白色吊坠。
            AddTranslation("A white pendant that heals those nearby.", "疗近者之白佩也。");
            // 耶索德
            AddTranslation("Yesod", "耶索德");
            // 情报部负责人。工作无能者，其部门绝不接纳。
            AddTranslation("The head of the Information Department. Incompetence will not be tolerated.", "讯部之长。无能者不见容。");
            // 阴
            AddTranslation("Yin", "阴");
            // 一枚追寻着失落另一半的黑色吊坠。
            AddTranslation("A black pendant in search of its missing half.", "索其失半之黑佩也。");
            // 你必须要幸福
            AddTranslation("You Must Be Happy", "汝须乐");
            // 接受该程序者，皆会重获安宁与健康。
            AddTranslation("Those that undergo the procedure find themselves rested and healthy again.", "受此术者，复得安与康。");
            // 你是个秃子...
            AddTranslation("You're Bald...", "汝秃矣……");
            // 我时常会想，成为光头会是怎样一番滋味。
            AddTranslation("I've always wondered what it's like to be bald.", "我恒念秃者何如。");


            // talkingcards
            // 人心本为漆黑，必当予以净化。
            AddTranslation("The human heart is black, and must be cleaned.", "人心玄黑，必涤之。");
            // 一只手从猩红的血池中缓缓升起。
            AddTranslation("A hand rises from the scarlet pool.", "一手出于丹池。");
            // 又一只苍白的手浮出水面。
            AddTranslation("Another pale hand emerges.", "又一苍手出焉。");
            // 第三只手伸出，仿佛在寻求援助。
            AddTranslation("A third hand reaches out, as if asking for help.", "三手复伸，若有所求。");
            // 你对我的野兽做了什么？
            AddTranslation("What have you done to my beast?", "汝于我兽为何？");
            // 历经漫长岁月，她终于寻到了他。
            AddTranslation("At long last, she has found him.", "久而后，其乃得之。");
            // 那块熟悉的红布……
            AddTranslation("That familiar red cloth...", "彼熟红布……");
            // 执念未了，锦鲤仍向伊甸跋涉。
            AddTranslation("Desire unfulfilled, the koi continues for Eden.", "志未遂，鲤犹趋伊甸。");
            // 守护再次落空，骑士重坠绝望深渊。
            AddTranslation("Having failed to protect again, the knight fell once more to despair.", "护又不成，骑者重坠于绝望。");
            // 平衡必须维系。没有恶，善就不能存在。
            AddTranslation("The balance must be maintained. Good cannot exist without evil.", "衡不可失。无恶则善不立。");
            // 它们甘愿满怀爱意地奉献自身。
            AddTranslation("They give themselves lovingly.", "彼甘以爱自献。");
            // 每吞噬一具尸体，它的贪欲便会愈发膨胀。
            AddTranslation("With each body added, its appetite grows.", "每益一尸，其欲愈长。");
            // 不必担忧，尸体的供应向来充足。
            AddTranslation("Don't worry, bodies are in no short supply.", "毋忧，尸未尝乏。");
            // 你的利刃切入异兽血肉的刹那，它会发出一声凄厉的尖啸。
            AddTranslation("As you cut into the beast's flesh, it lets out a piercing cry.", "汝刃入兽肌，其乃发刺耳之号。");
            // 那是什么？
            AddTranslation("What is that thing?", "彼为何物？");
            // 它似乎正试图模仿你。“试图” 二字，便是关键。
            AddTranslation("It seems to be trying to mimic you. 'Trying' is the key word.", "似欲效汝。其“欲”字最要。");
            // 它在做什么？
            AddTranslation("What is it doing?", "彼何为也？");
            // 时钟之轮，正缓缓驶向救赎彼岸。
            AddTranslation("The hands of the Clock move towards salvation.", "钟针徐趋于救。");
            // 这真是一记强劲的攻击，可惜这让她疲惫不堪，无力再自保。
            AddTranslation("A formidable attack. Shame it has left her too tired to defend herself.", "攻甚猛。惜其疲甚，不足自守。");
            // 这头怪物已恢复全盛状态。
            AddTranslation("The monster returns to full strength.", "此怪复其全盛。");
            // 被弃之不顾，又遭背叛，她因自己的无能陷入狂怒。
            AddTranslation("Abandoned and betrayed, she rages against her own failure.", "见弃见负，乃怒其自败。");
            // 不是每一天，都有心情展露笑容。
            AddTranslation("Some days you don't feel like smiling.", "有日不欲笑。");
            // 在这座都市，没人能皱着眉头活下去。
            AddTranslation("There was no place for frowns in the City.", "城中无容颦者之地。");
            // 不知该换上怎样的表情，她再度陷入羞怯。
            AddTranslation("Unable to decide what face to wear, she became shy again.", "不知当作何容，乃复羞。");
            // 如今你化为苍穹，我便成了大地。
            AddTranslation("Now you become the sky, and I the land.", "今汝为天，我为地。");

            // Angela_talk
            // 一位年迈的老人。
            AddTranslation("A decrepit old man.", "一老翁也。");
            // 我相信那头役畜
            AddTranslation("I believe that pack animal", "吾谓彼驮畜");
            // 它的消亡，定能助我们一臂之力。
            AddTranslation("will aid us with its death.", "其死足以助我曹。");
            // 你会不会好奇，他到底洗不洗澡？
            AddTranslation("Do you wonder if he ever bathes?", "汝曾疑彼是否沐乎？");
            // 事到如今，你该知道怎么做了。
            AddTranslation("You should know what to do by now.", "事至于今，汝宜知所为。");
            // 此人似乎头脑简单。
            AddTranslation("He appears to have a simple mind.", "其人似寡识。");
            // 我们能轻易操控他。
            AddTranslation("We can easily manipulate him.", "我曹易使之。");
            // 鱼这东西，跟人还挺像的，不是吗？
            AddTranslation("Fish are a lot like people, aren't they?", "鱼与人颇相似，不然乎？");
            // 我建议你屏住呼吸。
            AddTranslation("I recommend holding your breath.", "吾劝汝屏息。");
            // 每个人都有不为人知的一面。
            AddTranslation("Everyone has a different side to them.", "人皆有其异面。");
            // 你不这么觉得吗，主管？
            AddTranslation("Don't you think, manager?", "汝不以为然乎，主事？");
            // 活下去，主管。
            AddTranslation("Don't die manager.", "毋死，主事。");
            // 小心陷阱。
            AddTranslation("Watch out for traps.", "慎阱。");
            // 寒意会让你不适吗？
            AddTranslation("Does the cold bother you?", "寒汝乎？");
            // 看来，我们已经走到尽头了。
            AddTranslation("We appear to have reached the end.", "似已至其尽矣。");
            // 我期待你攻克这道难关
            AddTranslation("I expect you to conquer this challenge", "吾望汝破此难");
            // 轻松拿下就好，主管。
            AddTranslation("quite easily, manager.", "易耳，主事。");
            // 这是为你准备的最终试炼，主管。
            AddTranslation("A final trial for you, manager.", "此汝之终试也，主事。");
            // 这段旅途，也算波澜起伏了，不是吗？
            AddTranslation("It has been quite the journey, yes?", "此行亦多波折矣，不然乎？");
            // ...别指望我会发表任何看法。
            AddTranslation("...do not expect a comment from me.", "……毋望我有辞。");
            // 切勿被表象迷惑。
            AddTranslation("Do not be deceived.", "毋为其表所惑。");
            // 他并非异类。
            AddTranslation("He is not an abnormality.", "彼非异物。");
            // 一群不忠的部下……
            AddTranslation("An unloyal crew...", "不忠之众……");
            // 他身上有你的影子
            AddTranslation("He reminds me of you", "彼有汝之影");
            // 从某方面来说。
            AddTranslation("in a way.", "于某一端。");
            // 此番凶险，你怕是无力应对。
            AddTranslation("This threat may be beyond you.", "此患殆非汝所能胜。");
            // 这便是我们将他们
            AddTranslation("We kept them separated for", "我曹故使彼等");
            // 拆散的缘由，主管。
            AddTranslation("this reason, manager.", "相离者，以此也，主事。");
            // 你好，主管
            AddTranslation("Hello manager.", "主事，安。");
            // 那么，我们该动身了？
            AddTranslation("Shall we get going?", "其可行乎？");
            // 我在此为你提供协助。
            AddTranslation("I am here to assist you.", "我在此以佐汝。");
            // 惹上麻烦了？
            AddTranslation("Gotten yourself in trouble?", "自取其困乎？");
            // 我值得你托付。
            AddTranslation("You can rely on me.", "汝可恃我。");
            // 谢谢你。
            AddTranslation("Thank you.", "谢汝。");
            // 小心行事，别弄砸了。
            AddTranslation("Try not to make a mess.", "慎毋使乱。");
            // 速战速决，如何？
            AddTranslation("Let's hurry this up, yes?", "速毕之，可乎？");
            // 没有我克服不了的事。
            AddTranslation("Nothing I can't overcome.", "无我所不能胜者。");
            // 原来如此。
            AddTranslation("I see.", "然。");
            // 莫名忆起了当年的那个研究所。
            AddTranslation("Reminds me of the facility.", "使我忆及其所。");
            // 踌躇不前毫无意义。
            AddTranslation("No point in hesitating.", "迟疑无益。");
            // 总得有人做出牺牲。
            AddTranslation("Sacrifices must be made.", "汝必须行牺牲。");
            // 你完全不必为此感到不安。
            AddTranslation("Nothing you should be uncomfortable with.", "汝不必为此不安。");
            // 千载难逢的机会。
            AddTranslation("A golden opportunity.", "千载一会。");
            // 我期待你能做出最明智的抉择。
            AddTranslation("I expect you to know the best choice.", "吾望汝知何为善择。");
            // 我全权听凭你的决断。
            AddTranslation("I leave it to your discretion.", "惟汝所断。");
            // 生命之中，我们皆需跨越重重试炼。
            AddTranslation("We must all overcome ordeals in life.", "生而为人，皆当历难。");
            // 是你，让我明白了这一点。
            AddTranslation("You taught me that.", "此汝教我者。");
            // 你不会就这么轻易认输的，对吧？
            AddTranslation("You wouldn't fail so easily, right?", "汝不至尔易败，对乎？");
            // 事到如今，再犹豫也没用了。
            AddTranslation("No point in dilly-dallying now.", "今复迟回无益。");
            // 我前行的路上，又多了一重阻碍……
            AddTranslation("Yet another obstacle in my way...", "吾途又益一碍……");

            // ApocalypseBird_talk
            // 让我给你讲个故事吧，一个关于[c:bR]黑森林[c:]的故事。
            AddTranslation("Let me tell you a story. The story of the [c:bR]Black Forest[c:].", "姑为汝言一事，其[c:bR]黑林[c:]之事也。");
            // 三只鸟儿，[c:bR]如今仅剩一只[c:]，它四处打量，寻找[c:bR]那只猛兽[c:]。可眼前，一片虚无。
            AddTranslation("The three birds, [c:bR]now one[c:] looked around for [c:bR]the Beast[c:]. But there was nothing.", "三鸟，[c:bR]今合为一[c:]，四顾以求[c:bR]彼兽[c:]，而无所得。");
            // 没有活物，没有猛兽，连日月星辰都消失无踪。偌大的森林里，只剩那只鸟形单影只。
            AddTranslation("No creatures. No beast. No sun or moon or stars. Only a single bird, alone in an empty forest.", "无物，无兽，无日月星。惟一鸟，独在空林。");
            // 曾几何时，[c:bR]三只飞鸟[c:]与林中百兽相伴，悠游于这片蓊郁繁茂的森林里。
            AddTranslation("Once upon a time, [c:bR]three birds[c:] lived happily in the lush Forest with their fellow animals.", "昔者，[c:bR]三鸟[c:]与林中群兽，乐居于茂林。");
            // 直到某天，一位不速之客闯入了这片森林。他声称，这片林地很快便会被一场残酷的纷争所吞噬。
            AddTranslation("One day a stranger arrived at the Forest. He proclaimed that the Forest would soon be ensared in a bitter conflict.", "一日，有异客至林，言林将陷于苦争。");
            // 一场唯有待万物皆被[c:bR]可怖凶兽[c:]吞噬殆尽，方会终结的纷争。
            AddTranslation("One that would only end when everything was devoured by a [c:bR]terrible Beast[c:].", "且唯待万物尽为[c:bR]巨兽[c:]所食，而后息。");
            // 听闻这末日预言，三只飞鸟心生惶恐，决意要阻止这场纷争破土而出。
            AddTranslation("The birds, frightened by this doomsay, sought to prevent conflict from ever breaking out.", "鸟闻末言而惧，欲使争未作。");
            // 不管飞鸟们如何竭力挽回，争斗还是无可避免地发生。越来越多的生物，都离开了这片曾经祥和的林地。
            AddTranslation("Fights began to break out. More and more creatures left the Forest, no matter how hard the birds worked.", "斗终作矣。鸟虽尽力，离林者愈众。");
            // 走投无路之下，三只鸟决定将各自的力量融为一体，唯有如此，方能更有力地捍卫自己的故土。
            AddTranslation("They decided to combine their powers. This way, they could better protect their home.", "乃决并其力。如此，可以更善护其家。");
            // 唯有如此，方能更好地唤回往昔的安宁。
            AddTranslation("This way they could better return the peace.", "如此，乃庶几复其安。");
            // 夜幕骤然笼罩了整片森林。混乱肆虐横行，林中生灵望着那尊巨鸟的身影，发出惊恐的尖叫。
            AddTranslation("Darkness fell upon the forest. Mayhem ran amok as creatures screamed in terror at the towering bird.", "幽冥覆林。群物望巨鸟而号，乱作其中。");
            // 不知是谁嘶吼出声：[c:bB]“那就是凶兽啊！黑森林里盘踞着一头巨大又可怖的怪物！”[c:]
            AddTranslation("Someone yelled out [c:bB]'It's the Beast! A big, scary monster lives in the Black Forest!'[c:]", "[c:bB]或有呼曰：“是兽也！黑林有一巨且可畏之怪！”[c:]");
            // 长着万千眼目的[c:bG]大鸟[c:]，始终如一地守望着这片林地的所有角落。
            AddTranslation("[c:bG]Big Bird[c:] with his many eyes kept constant watch over the entire Forest.", "[c:bG]大鸟[c:]多目，常视全林。");
            // 那只[c:bG]长鸟[c:]，以其背负的天平衡量着林中众生的每一桩罪孽。
            AddTranslation("[c:bSG]Long Bird[c:] weighed the sins of all creatures in the forest with his scales.", "[c:bSG]长鸟[c:]以衡量林中诸物之罪。");
            // 那只[c:bG]小鸟[c:]，则用它尖利的喙，惩治着林中所有作奸犯科之徒。
            AddTranslation("[c:bR]Small Bird[c:] punished wrongdoers with his beak.", "[c:bR]小鸟[c:]以喙罚不义者。");
            // 你迈步走入一片开阔空地，黑黢黢的林木在四周森然围拢。
            AddTranslation("You walk down into a large clearing, the black trees crowding around you.", "汝步入一大空地，黑木四合。");
            // 一道异界的咆哮骤然入耳，你瞬间绷紧神经；脚下的土地都在恐惧中震颤，有什么东西正朝你步步逼近。
            AddTranslation("An otherworldly roar brings you to attention. The very earth quails in fear as something approaches you.", "异吼振耳，地亦战栗，有物逼汝。");
            // 那身影蹒跚笨重，却以违背常理的速度扑来，你回过神时，已然和它咫尺相对……
            AddTranslation("Lumbering yet impossibly fast, you find yourself face-to-face with...", "其行虽重而疾甚，须臾与汝相对者……");
            // 一声异界嘶吼直撼肺腑，林间地面震颤不已，某个存在正朝你步步逼近。
            AddTranslation("An otherworldly roar shakes you to your core. The forest floor quakes as something approaches you.", "异吼撼汝心骨，林地震动，有物逼汝。");
            // [c:bR]那头凶兽[c:]。
            AddTranslation("[c:bR]The Beast[c:].", "[c:bR]彼兽[c:]。");
            // 那双能洞穿万里的眼眸，已然被彻底蒙蔽。
            AddTranslation("The far-sighted eyes have been blinded.", "远瞩之目既蔽。");
            // 那颗曾仰望寰宇的头颅，如今已然低垂。
            AddTranslation("The head that looked to the cosmos has been lowered.", "望寰宇之首既垂。");
            // 那张吞噬万物的血口，已然阖然紧闭。
            AddTranslation("The mouth that devours everything has been shut.", "噬万物之口既阖。");
            // [c:bR]这头怪物[c:]，可没那么容易被降服。
            AddTranslation("[c:bR]The monster[c:] is not so easily tamed.", "[c:bR]此怪[c:]未易驯也。");
            // 你的一切努力，终究是徒劳一场。
            AddTranslation("Your efforts prove futile.", "汝劳徒耳。");
            // 那头凶兽，[c:bR]对普通的伤害全然免疫[c:]。
            AddTranslation("The Beast is [c:bR]immune to mortal damage[c:].", "彼兽[c:bR]不受凡伤[c:]。");
            // 可即便是它，也并非毫无破绽。
            AddTranslation("Yet even it has its weaknesses.", "然虽彼，亦有其弱。");
            // 鼓起你的勇气，继续向前迈进吧。
            AddTranslation("Gather your courage, and march onward.", "鼓汝之勇，进而前。");
            // [c:bSG]投身于这片苍茫的暮色之下。[c:]
            AddTranslation("[c:bSG]Into the twilight.[c:]", "[c:bSG]入于薄暮。[c:]");
            // 那张吞噬万物的巨口，豁然洞开。
            AddTranslation("The mouth that devours everything opens.", "噬万物之口启矣。");
            // 那只小鸟的喙中，传出绵绵不绝的低语。
            AddTranslation("The Small Bird's beak whispered endlessly.", "小鸟之喙低语不绝。");
            // 凶兽的血盆大口猛地咬合，却只咬中一片虚空。
            AddTranslation("The beast's maw snaps shut on empty air.", "兽吻暴合，而所得者空。");
            // 大鸟的眼眸，将光芒囚于其中……
            AddTranslation("The Big Bird's eyes imprisoned light...", "大鸟之目囚光……");
            // 随即，它们如繁星般炽烈灼燃……
            AddTranslation("...and they burned like stars.", "……而灼若群星。");
            // ……然而天地间，却寻不到一丝值得驻足凝望的痕迹。
            AddTranslation("...but there was nothing to behold.", "……然无所可观。");
            // 长鸟的翼臂之下，悄然藏匿了时光……
            AddTranslation("The Long Bird's arms concealed time...", "长鸟之臂匿时……");
            // 可那些罪孽，依旧日复一日地滋生蔓延……
            AddTranslation("...yet sins continued day after day.", "……而罪犹日滋。");
            // 凶兽嗅到了你的饥饿，行事愈发肆无忌惮。
            AddTranslation("The Beast senses your hunger, and grows more daring.", "彼兽察汝之饥，而益肆。");
            // 凶兽显露出穷途末路的狼狈。
            AddTranslation("The Beast begins to grow desperate.", "彼兽始困。");
            // 你所展露的力量，让凶兽怒火中烧。
            AddTranslation("Your power angers the Beast.", "汝威激怒彼兽。");
            // 凶兽的攻势，变得愈发凶狠凌厉。
            AddTranslation("The Beast grows more aggressive.", "彼兽益暴。");
            // 凶兽的力量，竟膨胀到了超乎想象的境地……
            AddTranslation("The Beast's strength grows beyond imagination...", "彼兽之威长至不可思……");
            // 你的那些造物的爪击，反倒让凶兽的外皮变得坚不可摧。
            AddTranslation("The Beast's hide hardens under your creatures' claws.", "汝诸物之爪，反坚其皮。");
            // 凶兽及其爪牙动作迅疾、出没频繁，趁此间隙调度你的造物，变换阵形。
            AddTranslation("The Beast and its ilk move quickly and frequently. Use these to reposition your creatures.", "彼兽及其属动数而疾。可乘此易汝诸物之位。");
            // 复生的造物，其召唤成本将依据你上一次召唤它们的时间远近发生变动。
            AddTranslation("Returned creatures will have their cost changed based on how recently you played them.", "所返之物，其直随汝前陈之久近而变。");
            // 新登场的造物，再度唤出时将收取[c:bR]2枚骨币[c:]作为代价。
            AddTranslation("Newly played creatures will cost [c:bR]2 Bones[c:] to play again.", "新陈之物，再陈之直为[c:bR]二骨[c:]。");
            // 我会逐步降低它们的召回成本，直至其可以[c:bR]免费[c:]再次召唤。
            AddTranslation("I will reduce their recall cost over time, until they become [c:bR]free[c:] to replay.", "我将徐损其召直，至[c:bR]无费[c:]可复陈。");
            // 以一定代价为交换，便可调动你的造物重新部署。
            AddTranslation("Use these to reposition your creatures, for a cost.", "可费少许，以更置汝诸物。");
            // 我们为什么不再多玩一会呢？
            AddTranslation("Why don't we continue a little longer?", "何不更嬉少时乎？");
            // 那头凶兽，对普通的伤害全然免疫。
            AddTranslation("The beast is immune to mortal damage.", "彼兽不受凡伤。");
            // 超出的伤害，反而能为你带来最多[c:bR]2枚[c:]骨币。
            AddTranslation("Excess injury will instead yield you up to [c:bR]2[c:] bones.", "溢伤反可予汝至多[c:bR]二[c:]骨。");
            // 无需忧虑补给耗尽，你所踏足之处，尽是取之不竭的骸骨。
            AddTranslation("Don't worry about running dry, the ground you walk on is full of them.", "毋忧骨尽，汝所履之地，骨满其中。");
            // 场地上到处都是骨头。
            AddTranslation("The ground is full of bones.", "地尽是骨。");
            // 穷途末路的凶兽，爆发出孤注一掷的凶戾之力。
            AddTranslation("Backed into a corner, the Beast releases one final burst of strength.", "穷兽出其末力。");
            // [c:bR]红色标记[c:]的区域一旦被凶兽击中，它将释放双倍常规威力的攻击。
            AddTranslation("When the Beast attacks a space marked in [c:bR]red[c:], it will deal twice the normal damage.", "彼兽若击[c:bR]朱记[c:]之位，则伤倍常。");
            // [c:bR]白色标记[c:]的区域遭凶兽攻击时，它的伤害会折半，且能借此恢复自身生命值。
            AddTranslation("When the Beast attacks a space marked in [c:bSG]white[c:], it will deal half the normal damage, but regain vitality.", "彼兽若击[c:bSG]白记[c:]之位，则伤半常，而复其命。");
            // 闭上你的双眼，数到十吧。
            AddTranslation("Close your eyes and count to ten.", "阖汝目而数至十。");
            // 当你将其开启，便会立于你心之所向的那个瞬间。
            AddTranslation("When you open them, you will be standing at the exact moment you wish to be in.", "既启目，则身立于汝所欲之时。");
            // 总得有[c:bR]一个你的造物[c:]留下来，为[c:bR]运转时钟[c:]献出自己。
            AddTranslation("[c:bR]One of your creatures[c:] must stay behind to operate [c:bR]the Clock[c:].", "[c:bR]汝一物[c:]须留而运[c:bR]此钟[c:]。");

            // Binah_talk
            // 尽快解决掉这些野兽。
            AddTranslation("Deal with those beasts quickly.", "疾治此诸兽。");
            // 不值一提的小阻碍。
            AddTranslation("A small obstacle.", "细碍耳。");
            // 让我们开始吧。
            AddTranslation("Let us begin.", "其始矣。");
            // 别在这时候没了干劲。
            AddTranslation("Don't lose your appetite now.", "毋于此时失志。");
            // 吃鱼，我都吃厌了。
            AddTranslation("I grow tired of fish.", "鱼，我已餍矣。");
            // 看来你很是享受这股恶臭。
            AddTranslation("You must enjoy the stench.", "汝似乐此恶臭。");
            // 又是一个口蜜腹剑的伪君子。
            AddTranslation("Another two-faced deceiver.", "又一两端之诈者。");
            // 世上从无不求回报的援手。
            AddTranslation("No one helps you without a price.", "世无无直之助。");
            // 落脚之处，务必当心。
            AddTranslation("Be wary of where your foot falls.", "落足宜慎。");
            // 看样子，一切都该尘埃落定了。
            AddTranslation("It seems we have reached the conclusion.", "视之，事殆当竟。");
            // 难道我们又要重蹈覆辙？
            AddTranslation("Are we doing this again?", "我曹复为此乎？");
            // 比这更强的对手，我也照样打过。
            AddTranslation("I have fought stronger foes.", "强于此者，我亦战之。");
            // 这是何物？
            AddTranslation("What is this?", "此何物？");
            // 一艘沉船的船长。
            AddTranslation("A captain of a sunken vessel.", "沉舟之长也。");
