            AddTranslation("He is no exception.", "彼亦不免。");
            // 只要我们凝心聚力，胜利便唾手可得。
            AddTranslation("If we focus, victory is assured.", "苟专志，则胜可必。");
            // 一切自有其定数。
            AddTranslation("Everything will happen as it should.", "万事皆当如其所宜。");
            // ……我承认，这局面确实令我措手不及。
            AddTranslation("...I admit I am caught off-guard.", "……我诚为此所愕。");
            // 到头来，这不过是一场徒劳无功的奔波。
            AddTranslation("In the end, this is all a pointless errand.", "终则皆徒劳之役。");
            // 这些炮台太慢了。
            AddTranslation("The cannons are slow.", "彼炮甚缓。");
            // 我们想避开它们，易如反掌。
            AddTranslation("We can easily avoid them.", "我曹易避之。");
            // 再强大的巨人，亦有其克星。
            AddTranslation("Every Goliath has its David.", "巨人皆有其敌。");
            // 相信你自己，亦要相信我们。
            AddTranslation("Have faith in yourself, and in us.", "信汝，亦信我曹。");
            // 向您致意，主管。
            AddTranslation("Greetings manager.", "主事，安。");
            // 尚有要务待理。
            AddTranslation("There is work to be done.", "尚有事当为。");
            // 比力量更重要的……
            AddTranslation("What matters more than strength...", "重于力者……");
            // 是对胜利的信念。
            AddTranslation("is faith in our victory.", "乃信我曹之胜。");
            // 坚守你的信念。
            AddTranslation("Stay true to your belief.", "守汝所信。");
            // 你我皆已行至
            AddTranslation("You have come to the point", "汝我皆至");
            // 决绝之境。
            AddTranslation("of no return.", "不返之地。");
            // 一切，将再度开启。
            AddTranslation("It begins once more.", "其始复作。");
            // 这定能帮上大忙。
            AddTranslation("This will help greatly.", "此助甚大。");
            // 让我们迎来新的一日。
            AddTranslation("Let us begin the day.", "其迎此日。");
            // 自负是最大的敌人。
            AddTranslation("Overconfidence is the greatest enemy.", "矜恃为大敌。");
            // 赶紧把活干完。
            AddTranslation("Let's hurry to finish this work.", "速毕此役。");
            // 白费功夫。
            AddTranslation("A pointless errand.", "徒劳之役。");
            // 机会来了。
            AddTranslation("An opportunity presents itself.", "机自来矣。");
            // 此事需谨慎。
            AddTranslation("Be prudent about this.", "此宜慎之。");
            // 我对你的决定有信心。
            AddTranslation("I have faith in your decision.", "我信汝断。");
            // 无边的傲慢与野心
            AddTranslation("Boundless pride and ambition", "无厓之矜与欲");
            // 终将招致惨痛的结局……
            AddTranslation("will bring about a bitter end...", "终致苦终……");
            // 切勿急躁。
            AddTranslation("Do not be hasty.", "毋遽。");
            // 事已至此，无可挽回。
            AddTranslation("There is no halting now.", "今无可止。");
            // 永无止境的试炼之路。
            AddTranslation("An endless series of trials.", "无穷之试。");

            // JesterOfNihil
            // 盯紧它们。
            AddTranslation("Watch them carefully.", "审视之。");
            // 它们在呐喊——不对，是在祷祝某物的降临。
            AddTranslation("They're calling - no, praying for something.", "彼在呼——不，是祷某物之至。");
            // 无从知晓，它们集结于此，是否为了化身为[c:gray]那位弄臣[c:]，
            AddTranslation("There was no way to know if they had gathered to become [c:gray]the Jester[c:],", "无由知其聚于此，欲化为[c:gray]弄臣[c:]，");
            // 亦或是[c:gray]弄臣[c:]早已变得与他们别无二致。
            AddTranslation("or if [c:gray]the Jester[c:] had come to resemble them.", "抑[c:gray]弄臣[c:]已似彼辈。");
            // 那[c:gray]弄臣[c:]，正循着所有人终将踏上的轨迹前行。
            AddTranslation("[c:gray]The Jester[c:] retraced the steps of a path everyone would've taken.", "那[c:gray]弄臣[c:]循众人所共行之路而返。");
            // 不管它如何挣扎，弄臣到头来都只会站在归途的终点。
            AddTranslation("No matter what it did, the Jester always found itself at the end of that road.", "无论如何，弄臣终立于彼途尽处。");

            // LyingAdult
            // 许久以前，曾有一座耀世的翡翠之城。
            AddTranslation("Long ago, there was a city made of shining emerald.", "昔有翡翠之城，烂然有光。");
            // 城主乃公主[c:bR]奥兹玛[c:]，城中藏有诸多异界奇景。
            AddTranslation("Ruled by the princess [c:bR]Ozma[c:], it was home to many otherworldly splendors.", "公主[c:bR]奥兹玛[c:]主之，城中多异界奇观。");
            // 某日，一位名为[c:g1]奥兹[c:]的成年人来到了翡翠城。
            AddTranslation("One day, an adult named [c:g1]Oz[c:] arrived to the Emerald City.", "一日，有一长者名[c:g1]奥兹[c:]者，至翡翠城。");
            // 望着这座流光溢彩的城池，她心中生出一条绝妙之计。
            AddTranslation("Looking upon the brilliant city, she came up with a brilliant plan.", "顾其华城，乃生一奇计。");
            // 不久之后，[c:g1]奥兹[c:]便被众人尊称为巫师。
            AddTranslation("Soon, [c:g1]Oz[c:] came to be known as a wizard by the people.", "未几，[c:g1]奥兹[c:]为众称巫。");
            // 没有什么比看似显而易见的真相更具欺骗性。
            AddTranslation("Nothing is as deceptive as evident truth.", "莫有欺于显真者甚焉。");
            // 归乡之路永被断绝，他们就此踏上了无尽的旅途。
            AddTranslation("Unable to ever go back home, they began an endless journey.", "既不得归，遂历无穷之途。");
            // [c:g1]我会实现你的愿望。你想要些什么？[c:]
            AddTranslation("[c:g1]I’ll make your wishes come true. What do you wish for?[c:]", "[c:g1]我将遂汝愿。汝欲何求？[c:]");
            // 可怜的[c:bR]奥兹玛[c:]公主，怎会知晓说谎的大人从不会无故接近他人。
            AddTranslation("Poor [c:bR]Ozma[c:] didn’t know that lying adults don’t approach others without reason.", "哀哉[c:bR]奥兹玛[c:]，不知言诳之长者未尝无故近人。");
            // [c:g1]最后，是那位归家的路途。我会送你回家。[c:]
            AddTranslation("[c:g1]Last of all, road that is lost. I will send you home.[c:]", "[c:g1]最后，是迷途之路，我将遣汝归家。[c:]");
            // [c:g1]你早已无家可归，又何苦这般拼死相争？[c:]
            AddTranslation("[c:g1]What are you fighting for so fiercely when you have nowhere to go back to?[c:]", "[c:g1]既无所归，何为奋争若是？[c:]");
            // [c:g1]可怜的稻草人，我会赐予你参透万物的智慧。[c:]
            AddTranslation("[c:g1]Poor stuffing of straw. I'll give you the wisdom to ponder over anything.[c:]", "[c:g1]哀哉稻腹者，我将予汝以思万物之智。[c:]");
            // [c:g1]难不成在你眼里，靠这张巧嘴胡言乱语，就什么都够了？[c:]
            AddTranslation("[c:g1]Do you think jabbering away with your oh-so smart mouth is all that matters?[c:]", "[c:g1]汝谓徒恃巧舌而饶辩，便足乎？[c:]");
            // [c:g1]胆小的猫咪，我会赐你直面万事万物的勇气。[c:]
            AddTranslation("[c:g1]Cowardly kitten, I'll give you the courage to stand up to anything and everything.[c:]", "[c:g1]怯猫，我将予汝以直面万物之勇。[c:]");
            // [c:g1]连直面一切的勇气都没有，你又能做成什么事？[c:]
            AddTranslation("[c:g1]What are you even going to do when you lack the bravery to face anything head-on?[c:]", "[c:g1]既无迎万事之勇，汝又何能为？[c:]");
            // [c:g1]冰冷的铁皮樵夫，我会赐你一颗能宽恕众生、怜爱世人的心。[c:]
            AddTranslation("[c:g1]Tin-cold woodsman. I'll give you the heart to forgive and love anyone.[c:]", "[c:g1]寒若锡之樵者，我将予汝以恕人爱人之心。[c:]");
            // [c:g1]凭你这颗铁石般的心肠，又能指望谁来懂你？[c:]
            AddTranslation("[c:g1]Who do you possibly expect to understand with that ice-cold heart of yours?[c:]", "[c:g1]怀此冰心，汝复望谁解汝乎？[c:]");

            // Malkuth_talk
            // 当心啊，主管！
            AddTranslation("Heads up manager!", "慎哉，主事！");
            // 交给我们没问题！
            AddTranslation("We've got this!", "有我曹在！");
            // 都打起精神来！
            AddTranslation("Let's stay sharp, now!", "皆振作！");
            // 这股死亡的味道，再熟悉不过了。
            AddTranslation("The familiar smell of death.", "死气之熟者。");
            // 胜利不过是时间问题！
            AddTranslation("Winning's just a matter of time!", "胜只在旦夕！");
            // 留神那些饵桶！
            AddTranslation("Watch out for those bait buckets!", "慎彼饵桶！");
            // 保持警戒！
            AddTranslation("Be on the look-out!", "常警之。");
            // 小心陷阱！
            AddTranslation("Watch out for traps!", "慎阱！");
            // 这事儿得动动脑筋。
            AddTranslation("We need to be smart about this.", "此事须智取。");
            // 这角色看着就棘手。
            AddTranslation("This guy looks tough.", "此人似难当。");
            // 深吸一口气，集中精神。
            AddTranslation("Take a deep breath, and focus.", "深息而专之。");
            // 我们都坚持到这一步了。
            AddTranslation("We've made this far.", "我曹已至于此。");
            // 现在绝不能输！
            AddTranslation("We can't lose now!", "今不可败！");
            // 那些是大炮吗？
            AddTranslation("Are those cannons?", "彼为炮乎？");
            // 更棘手的局面我们都挺过来了。
            AddTranslation("We've dealt with worse.", "更甚者我曹亦尝当之。");
            // 不必过分担忧！
            AddTranslation("No need to worry too much!", "毋过忧！");
            // 就当是又一个异想体
            AddTranslation("Treat it as another abnormality", "姑以为又一异想体");
            // 按规程应对即可！
            AddTranslation("and act accordingly!", "而如常应之！");
            // 这玩意儿也太大了……
            AddTranslation("This thing is huge...", "此物太巨……");
            // 呃，别担心！
            AddTranslation("Uh, don't worry!", "呃，毋忧！");
            // 我们能行！
            AddTranslation("We can do it!", "我曹能之！");
            // 我们只需坚持到它力竭……
            AddTranslation("We just need to outlast it...", "但须持之，待其力尽……");
            // 务必精打细算，合理调配资源！
            AddTranslation("Manage your resources carefully!", "汝之资用，当慎节之！");
            // 见到您很高兴，主管！
            AddTranslation("Nice to meet you, manager!", "幸会，主事！");
            // 又见面了！
            AddTranslation("Hello again!", "又会矣！");
            // 我已准备就绪，随时待命！
            AddTranslation("I'm prepared to help!", "我已备，可助也！");
            // 我保证，定能功成！
            AddTranslation("I promise to succeed!", "我必功成！");
            // 主管安好！
            AddTranslation("Greetings Manager!", "主事安好！");
            // 相信我，随我冲锋！
            AddTranslation("Trust me and follow my lead!", "信我，随我！");
            // 动手吧！
            AddTranslation("Let's do this!", "其始矣！");
            // 我已做好万全准备！
            AddTranslation("I'm fully prepared now!", "我今已具备！");
            // 胜利不过是时间问题！
            AddTranslation("Winning is just a matter of time!", "胜只在旦夕！");
            // 我必竭尽所能！
            AddTranslation("I'll do my best within my ability!", "我必尽我所能！");
            // 谢谢主管！
            AddTranslation("Thank you manager!", "谢主事！");
            // 切勿慌乱。
            AddTranslation("Don't panic.", "毋慌。");
            // 保持冷静。
            AddTranslation("Stay calm.", "安之。");
            // 我会再加把劲，不必担心！
            AddTranslation("I'll fight harder, don't worry!", "我将更奋，毋忧！");
            // 我感觉这场战斗一定能赢！
            AddTranslation("I've got a good feeling about this!", "我觉此战必胜！");
            // 都打起精神来，好吗？
            AddTranslation("Let's stay sharp, shall we?", "皆振作，可乎？");
            // 当心前方！
            AddTranslation("Focus on the path forward!", "专志于前路！");
            // 不该是这样的……
            AddTranslation("Not like this...", "不当如是……");
            // ……别放弃。
            AddTranslation("...Don't give up.", "……毋弃。");
            // 夸下海口，还是输了。
            AddTranslation("I talked big and failed, again.", "大言而复败矣。");
            // 诸位，保持镇定。
            AddTranslation("Stay calm, everyone.", "诸君，且镇。");
            // 我坚信你的决断。
            AddTranslation("I have faith in your decision.", "我信汝断。");
            // 不如，我们先深呼吸，如何？
            AddTranslation("Why don't we take a deep breath?", "何不先深息乎？");
            // 一切进展顺利！
            AddTranslation("Things are going smoothly!", "事皆顺也！");
            // 好好利用这机会！
            AddTranslation("Let's make the most of this!", "善乘此机！");
            // 我对你的判断深信不疑！
            AddTranslation("I trust your judgement!", "我深信汝断！");
            // 还请对我抱有信心！
            AddTranslation("Have faith in me!", "愿汝信我！");
            // 主管，您定能做到！
            AddTranslation("You've got this manager!", "主事，汝必能之！");
            // 没有什么是我们不曾解决的！
            AddTranslation("Nothing we haven't solved before!", "无一事非我曹昔所决者！");

            // MapNodes
            // 你步入一片空地，四周尽是扭曲的枯黑林木。
            AddTranslation("You enter a clearing surrounded by dark, twisting trees.", "汝入一空地，四周皆玄木盘曲。");
            // 你朝空地中央的那口井走去，林中枝干如利爪般抓挠着高悬的残月。
            AddTranslation("Their branches claw at the leering moon as you approach the well at the clearing's centre.", "汝趋空地中央之井，诸枝爪向残月。");
            // 非人的嘶吼自井口墨色深渊中翻涌而出，或哀求，或尖啸，或执念疯长，或欲念横生。
            AddTranslation("Unearthly voices arise from the its inky depths, pleading, screaming, wishing and wanting.", "非人之声起于其玄渊，或求、或号、或欲。");
            // 井中藏着某物，正静待被人汲出——那是股强大而诡秘的存在，
            AddTranslation("There are things in the well, waiting to be drawn up. Powerful, mysterious,", "井中有物，待汲而上。强而秘者，");
            // [c:bR]异想体[c:]。
            AddTranslation("[c:bR]abnormal[c:].", "[c:bR]异想体[c:]。");
            // 你穿行于荒寂旷野，偶遇一小队旅人。
            AddTranslation("As you journey through the wilderness, you come across a small group of humans.", "汝行旷野，遇一小众人。");
            // 他们的衣着与这片土地的气候格格不入，更令人心惊的是——[c:bR]他们竟认得你[c:]。
            AddTranslation("They're dressed oddly for this climate, and even odder, [c:bR]they seem to recognise you[c:].", "其服与此地不类，更异者，[c:bR]彼似识汝[c:]。");
            // 他们似是在进行一场远征，目标是搜寻[c:bR]怪异[c:]的野兽。
            AddTranslation("They are on an expedition of some kind, in search of [c:bR]strange[c:] beasts.", "彼似为远征，索[c:bR]怪[c:]兽。");
            // 这群人看起来颇有学识，或许你能说服他们，助你走完这段前路。
            AddTranslation("Their appear quite knowledgeable. Perhaps you can convince them to aid you on your journey.", "观其颇多闻，或可劝之助汝。");

            // Netzach_talk
            // 这砰砰的声响，真是烦死人了……
            AddTranslation("That banging's annoying...", "此击打声烦甚……");
            // 又来？
            AddTranslation("Again?", "又来乎？");
            // 那把镐子，我实在不喜欢。
            AddTranslation("Not a fan of that pickaxe.", "彼镐非我所好。");
            // 竟有这么多桶鱼……
            AddTranslation("So many buckets of fish...", "鱼桶何多……");
            // 这气味实在令人作呕。
            AddTranslation("The smell's making me sick.", "此气令人欲呕。");
            // 就不能绕点远路走吗？
            AddTranslation("Can't we take the long way around?", "岂不可迂道而行？");
            // 这儿的人全疯了……
            AddTranslation("Everyone here's crazy...", "此间之人皆狂……");
            // 还好，那些陷阱一眼就能看穿。
            AddTranslation("At least those traps are obvious.", "幸彼阱犹易见。");
            // 只想倒在雪地里
            AddTranslation("Just want to lie down in the snow", "但欲仆于雪中");
            // 再也不醒过来。
            AddTranslation("and go to sleep.", "长眠不起。");
            // 这就是最终头目？
            AddTranslation("This is the final boss?", "此即终魁乎？");
            // 既然都到这儿了，那就没什么好退缩的了。
            AddTranslation("Since we've come this far, may as well.", "既来至此，不如竟之。");
            // 让我们了结它。
            AddTranslation("Let's finish this.", "其了之。");
            // ……是我的错觉吗？
            AddTranslation("...am I hallucinating?", "……我见幻乎？");
            // 说起来，我见过的怪事比这离谱多了。
            AddTranslation("I guess I've seen weirder things.", "我所见怪事，尚有甚于此者。");
            // 这几门炮够慢的，对吧？
            AddTranslation("Those cannons are pretty slow, huh?", "彼炮甚缓，不然乎？");
            // 那是什么？
            AddTranslation("What is that thing?", "彼为何物？");
            // 我可经不起这种折腾了……
            AddTranslation("I don't need this stress...", "我不能堪此扰……");
            // 我们为什么回来了？
            AddTranslation("Why are we back here?", "我曹何为复至此？");
            // 换个人选不行吗？
            AddTranslation("Pick someone else?", "易他人为之，不可乎？");
            // 知道我现在最想要什么吗？撤退，然后睡一觉。
            AddTranslation("Know what I need most? Retreat and sleep.", "知我今最欲何乎？却退而寝。");
            // 唉…
            AddTranslation("Sigh...", "唉……");
            // 我实在没力气折腾了。
            AddTranslation("I'm too tired for this.", "我实无力为此。");
            // 这战场的氛围……
            AddTranslation("This battlefield atmosphere...", "此战地之气……");
            // 我可一点都不喜欢。
            AddTranslation("Not a fan of it.", "我殊不乐。");
            // 这样应该就够了吧？
            AddTranslation("That should be enough, right?", "如此可足乎？");
            // 白费功夫。
            AddTranslation("Waste of effort.", "徒劳。");
            // 我会尽力不让人失望。
            AddTranslation("I'll try not to disappoint.", "我将勉勿负人。");
            // 谢了，大概吧。
            AddTranslation("Thanks, I guess.", "谢矣，殆然。");
            // 我只想在后面打个盹……
            AddTranslation("I just wanna nap in the back...", "我但欲卧后而小寐……");
            // 我怎么会落到做这种事的地步？
            AddTranslation("How did I end up doing things like this?", "我何至为此等事？");
            // 来吧…
            AddTranslation("Let's do this...", "来吧……");
            // 赶紧了结这一切吧。
            AddTranslation("Let's get this over with.", "疾竟此事。");
            // 这下总算能睡一觉了。
            AddTranslation("Guess I can sleep now.", "今可一睡矣。");
            // 抱歉，我没能帮上忙。
            AddTranslation("Sorry I couldn't help.", "歉矣，未能有助。");
            // 为什么结局总是如此徒劳？
            AddTranslation("Why is the end always futile?", "何为终局恒徒劳？");
            // …我只想快点结束这一切。
            AddTranslation("...I just wanna end this quickly.", "……我但欲速终其事。");
            // 我能退出吗？
            AddTranslation("Can I opt out?", "我可退乎？");
            // 离开也是一种选择吗？
            AddTranslation("Is leaving an option?", "去亦可乎？");
            // 选谁都无所谓。
            AddTranslation("Choose whoever.", "择谁皆可。");
            // 悉听尊便，主管。
            AddTranslation("At your discretion, manager.", "惟主事所断。");
            // 为什么要做这么多试炼？
            AddTranslation("Why with all the tests?", "何试之多也？");
            // 额...
            AddTranslation("Ugh...", "唉……");

            // Tiphereth_talk
            // 赶紧解决这家伙吧。
            AddTranslation("Let's deal with this guy quickly.", "速治此人。");
            // 当初就不该多管闲事。
            AddTranslation("Should've stayed out of the way.", "本不当多事。");
            // 你还没打赢他？
            AddTranslation("You still haven't beat him?", "汝犹未胜之乎？");
            // 这里闻着一股子后巷的味道。
            AddTranslation("It smells like the Backstreets here.", "此间有后巷之气。");
            // 至少他的行动还算有迹可循。
            AddTranslation("At least his actions are predictable.", "至少其行尚可测。");
            // 快点。
            AddTranslation("Quickly now.", "疾。");
            // 看来下一个遭殃的就是我们了。
            AddTranslation("Guess we're next on the chopping block.", "看，我曹乃为俎上者矣。");
            // 那些刀刃看着很锋利，小心点。
            AddTranslation("Those knives look sharp. Careful.", "彼刃甚利，慎之。");
            // 把这些毛皮攥紧了。
            AddTranslation("Hold onto those pelts now.", "执此裘革。");
            // 主管，交给我们就好。
            AddTranslation("We've got this manager.", "主事，付我曹即可。");
            // 别忘了，还有我们帮你。
            AddTranslation("Don't forget, you have us to help.", "毋忘我曹在侧。");
            // 还差一个敌人要解决。
            AddTranslation("One more foe to beat.", "复有一敌待除。");
            // 认真的？
            AddTranslation("Seriously?", "果真？");
            // 我从来就没喜欢过海盗。
            AddTranslation("Never was that into pirates.", "我素不喜海盗。");
            // 这家伙的准头简直烂透了。
            AddTranslation("This guy can't aim at all.", "此人无的。");
            // 这玩意儿也太大了……
            AddTranslation("It's massive...", "此物太巨……");
            // 但愿你心里有数
            AddTranslation("I hope you know", "愿汝自知");
            // 自己在做什么。
            AddTranslation("what you're doing.", "所为为何。");
            // 把头护好，主管。
            AddTranslation("Keep your head on tight, manager.", "护汝首，主事。");
            // 这关不好过啊。
            AddTranslation("This'll be tough.", "此关难矣。");
            // 我们肯定能撑过去的。
            AddTranslation("We'll make it out for sure.", "我曹必能济之。");
            // 快选我们中的一个。
            AddTranslation("Hurry and pick one of us.", "速择我曹一人。");
            // 别让我们久等。
            AddTranslation("Don't keep up waiting.", "毋使我曹久待。");
            // 坐稳了，主管。
            AddTranslation("Buckle up manager.", "坐稳矣，主事。");
            // 相信我们。
            AddTranslation("Have faith.", "信我曹。");
            // 你不是一个人在战斗。
            AddTranslation("You're not fighting alone.", "汝非独战。");
            // 计划赶不上变化。
            AddTranslation("You can't plan forever.", "筹画无穷终无益。");
            // 该动手了。
            AddTranslation("Now's the time for action.", "今其动手矣。");
            // 你知道该做什么，对吗？
            AddTranslation("You know what to do, right?", "汝知所为，对乎？");
            // 我们不能让大家都丧命于此。
            AddTranslation("We can't let everyone die here.", "我曹不可令众皆死于此。");
            // 你以为我自己搞不定？
            AddTranslation("Think I can't do this myself?", "谓我不能自办乎？");
            // 不错。
            AddTranslation("Not bad.", "善。");
            // 但愿这玩意儿能派上用场。
            AddTranslation("This better be useful.", "愿此物有用。");
            // 我太慢了…
            AddTranslation("I was too slow...", "我太缓矣……");
            // 冲啊！
            AddTranslation("Push forward!", "前！");
            // 别太得意忘形。
            AddTranslation("Don't get cocky.", "毋骄。");
            // 我还能战斗！
            AddTranslation("I can still fight!", "我犹能战！");
            // …抱歉
            AddTranslation("...Sorry", "……歉");
            // 你把我们带到这儿来干什么？
            AddTranslation("Why'd you bring us here?", "汝何携我曹至此？");
            // 不。
            AddTranslation("No.", "不。");
            // 你敢试试？
            AddTranslation("Don't you dare.", "汝敢！");
            // 暂时的喘息？
            AddTranslation("A respite?", "一息之休乎？");
            // 自己决定。
            AddTranslation("Decide for yourself.", "汝自决之。");
            // 好好利用这次机会。
            AddTranslation("Make good use of this.", "善用此机。");
            // 选那个最需要的人。
            AddTranslation("Choose someone that needs it.", "择其最需者。");
            // 一场试炼？
            AddTranslation("A trial?", "一试乎？");
            // 比这更糟的我们都挺过来了。
            AddTranslation("We've gone through worse.", "更难者我曹亦尝之。");
            // 我能把握住。
            AddTranslation("I can handle it.", "我能当之。");
            // 这场我稳赢。
            AddTranslation("I'll win this for sure.", "此战我必胜。");
            // 你会一如既往，做得很好。
            AddTranslation("You'll do fine, like always.", "汝将如常而善。");
            // 我们开始吧。
            AddTranslation("Here we go.", "其始矣。");
            // 这地方可真诡异…
            AddTranslation("What a strange place...", "此地甚怪……");
            // 开工了。
            AddTranslation("Time to work.", "其作矣。");
            // 我们全力以赴吧。
            AddTranslation("Let's do our best.", "我曹尽力。");

            // WhiteNight
            // [c:bR]时机已然成熟，全新的世界即将来临。[c:]
            AddTranslation("[c:bR]The time has come. A new world will come.[c:]", "[c:bR]时既至，新世将至。[c:]");
            // [c:bR]吾即是死亡，亦是生机；既是深渊，亦是曙光。[c:]
            AddTranslation("[c:bR]I am death and life. Darkness and light.[c:]", "[c:bR]我即死与生、幽与明也。[c:]");
            // [c:bR]我不是曾选中你们十二人么？可你们当中，有一个魔鬼。[c:]
            AddTranslation("[c:bR]Have I not chosen you, the Twelve? Yet one of you is a devil.[c:]", "[c:bR]我非已择尔十二人乎？然其中一人为鬼。[c:]");
            // [c:bR]非我准许，你们谁也别想离开我之身侧。[c:]
            AddTranslation("[c:bR]None of you can leave my side until I permit you.[c:]", "[c:bR]非我许之，尔无一人得离我侧。[c:]");
            // [c:bR]安心吧，没有任何灾祸能侵扰你们。[c:]
            AddTranslation("[c:bR]Be at ease. No calamity shall be able to trouble you.[c:]", "[c:bR]安之，灾不加尔。[c:]");
            // [c:bR]我不会离开你们，直至完成我的使命。[c:]
            AddTranslation("[c:bR]I shall not leave thee until I have completed my mission.[c:]", "[c:bR]我不离尔，至我使命既成。[c:]");
            // [c:bR]你们都做了些什么？[c:]
            AddTranslation("[c:bR]What did you do?[c:]", "[c:bR]尔何为哉？[c:]");

            // Yesod_talk
            // 别被他的年纪蒙骗了
            AddTranslation("Don't let his age lull you into", "毋以其老而自安。");
            // 这会让你们陷入致命的松懈。
            AddTranslation("a false sense of security.", "此足使汝致命之弛。");
            // 那把镐子刃口锋利，提高警惕。
            AddTranslation("That pickaxe is sharp. Stay vigilant.", "彼镐甚利，宜警。");
            // 别在这儿浪费时间了。
            AddTranslation("Let's not waste any time.", "毋虚时。");
            // 别让这股气味麻痹了你们的神志。
            AddTranslation("Don't let the smell dull your mind.", "毋使此气钝汝心。");
            // 注意他的钩子，每次出手都能精准命中目标。
            AddTranslation("His hook always seems to hit its mark.", "慎其钩，出必中的。");
            // 该怎么处理，我相信你心里有数。
            AddTranslation("I'm sure you know how to deal with it.", "当何以处之，汝宜自知。");
            // 这玩意儿，实在让人舒服不起来...
            AddTranslation("This isn't particularly pleasant...", "此物殊不可喜……");
            // 先把方案敲定，然后立刻执行。
            AddTranslation("Come up with a plan, then execute it.", "先定其计，而后行之。");
            // 主管，别让这寒意麻痹了您的判断力。
            AddTranslation("Don't let the cold cloud your senses, manager.", "主事，毋使寒钝汝断。");
            // 仓促行事，只会得不偿失。
            AddTranslation("Hasty actions will bring more harm than good.", "遽行多害。");
            // 必须先做出周全的判断
            AddTranslation("We must make sound judgements", "须先为善断");
            // 在我们行动之前。
            AddTranslation("before rushing forward.", "而后前。");
            // 把我们之前积累的经验都用上。
            AddTranslation("Use what we've learned until now.", "尽用吾曹前所学");
            // 拿下它。
            AddTranslation("to take him down.", "以毙之。");
            // 把这当成你的最终考核。
            AddTranslation("Consider this your final test.", "视此为汝终试。");
            // 一只骷髅？这可是头一回见。
            AddTranslation("A skeleton? That's new.", "枯骨乎？此新矣。");
            // 看样子，他那帮跟班还有被策反的余地。
            AddTranslation("His crew seems persuadable.", "其党似可说。");
            // 说实话，这可算不上什么亮眼的表现。
            AddTranslation("Can't say I'm impressed.", "不足观也。");
            // 别被这阵仗吓住了。
            AddTranslation("Don't be intimidated.", "毋为之慑。");
            // 您得妥善调配好手下的造物，
            AddTranslation("Manage your creatures wisely,", "汝须善调诸物，");
            // 务必维持持续火力输出。
            AddTranslation("and maintain constant fire.", "而火力不断。");
            // 它的那些伎俩，我们现在都摸透了。
            AddTranslation("We know its tricks now.", "其技我曹今皆悉矣。");
            // 我们已经掌握了主动权。
            AddTranslation("We are at an advantage.", "我曹据上风。");
            // 这时候可别乱了阵脚。
            AddTranslation("Don't lose your cool now.", "毋乱于此时。");
            // 莽撞冲锋绝非有效的作战方式。
            AddTranslation("Recklessly charging is not an effecient combat method.", "莽进非善战法。");
            // 当务之急是尽快结束这场战斗。
            AddTranslation("We must prioritise concluding this fight quickly.", "务在速竟此战。");
            // 想必你已做好应对任何结果的准备。
            AddTranslation("I take it you're prepared for any outcome.", "想汝已备诸变。");
            // 眼下这种局面，
            AddTranslation("In a situation such as this,", "如此局中，");
            // 我们必须保持冷静，做出稳妥的决断。
            AddTranslation("we must be calm and make sound judgements.", "我曹须冷静而善断。");
            // 我当恪尽职守，不负所托。
            AddTranslation("I will fulfill my responsibility.", "我将尽我之责。");
            // 我会坦然接受这一切。
            AddTranslation("I accept this with grace.", "我安受之。");
            // 咳。
            AddTranslation("Kh.", "咳。");
            // 不必在意我。
            AddTranslation("Pay no mind to me.", "毋顾我。");
            // 专心盯着目标。
            AddTranslation("Focus on the goal.", "专志其的。");
            // 若是没有出手的时机，
            AddTranslation("If there's no opportunity to strike,", "若无击机，");
            // 我们便自己创造。
            AddTranslation("we'll simply make one.", "则自造之。");
            // 快些结束这一切。
            AddTranslation("Let's end this quickly.", "速竟此事。");
            // 非常好。
            AddTranslation("Very well.", "善。");
            // 不要莽撞地勉强自己。
            AddTranslation("Let's not push ourselves too carelessly.", "毋轻自困。");
            // 我不想再浪费分毫时间。
            AddTranslation("I don't want to waste any time.", "我不欲更费时。");
            // 无需对我抱有同情。
            AddTranslation("There is no need to pity me.", "毋怜我。");
            // 我看不清前方的路。
            AddTranslation("I couldn't see the path ahead.", "我不见前路。");
            // 我做错了什么？
            AddTranslation("What did I do wrong?", "我何所失？");
            // 这全然是我的过错。
            AddTranslation("It's entirely my fault.", "此皆我过。");
            // 这实在算不上什么乐事。
            AddTranslation("This isn't particularly delightful.", "此殊非可乐。");
            // 此番牺牲，绝不能白费。
            AddTranslation("This death must not be in vain.", "此死不可徒然。");
            // 或许，我也只能接受这样的结局了。
            AddTranslation("I suppose I should just accept this.", "殆我惟受之耳。");
            // 坦白说，
            AddTranslation("Frankly,", "坦言之，");
            // 我厌恶自己如今对死亡的麻木不仁。
            AddTranslation("I dislike how numb I've become to death.", "我恶今之习死。");
            // 我相信你会做出正确的选择。
            AddTranslation("I trust you will choose correctly.", "我信汝能择其正。");
            // 理智看待此事。
            AddTranslation("Be logical about this.", "以理处之。");
            // 看来，这是一场试炼。
            AddTranslation("It seems to be a test of some kind.", "视之若一试。");
            // 稍有不慎，就可能酿成滔天大祸。
            AddTranslation("A single mistake could cause disaster.", "一失则祸大。");
            // 我们每一步都需审慎而行。
            AddTranslation("We must always proceed with discretion.", "每步皆当审。");

            // 部分印记、说明补充
            // 你获得一张 “单次召回”，使用它能将己方场上的任意一张卡牌取回手中。
            AddTranslation("A Single Recall is created in your hand. A Single Recall can return a card on your side of the board to your hand.", "汝手生一“单召”。“单召”能返汝侧局上一牌于手。");
            // 回收一张已使用的卡牌至手牌，其重新上场所需费用变为[c:bR]骨币[c:]。
            AddTranslation("This will let you return a played card to your hand. Returned cards will cost [c:bR]Bones[c:] to replay.", "此可返一既陈之牌于手。所返之牌，再陈则费[c:bR]骨[c:]。");
            // 你手中生成一张 “全部召回”，使用时将己方场上所有卡牌收回手牌。
            AddTranslation("A Total Recall is created in your hand. A Total Recall will return all cards on your side of the board to your hand.", "汝手生一“皆召”。“皆召”尽返汝侧局上诸牌于手。");
            // 将己方场上所有卡牌收回手牌。其重新上场所需费用变为[c:bR]骨币[c:]。
            AddTranslation("This will return all your cards to your hand. Returned cards will cost [c:bR]Bones[c:] to replay.", "此可尽返汝诸牌于手。所返之牌，再陈则费[c:bR]骨[c:]。");
            // 公正
            AddTranslation("Justitia", "义断");
            // 审判鸟所瞄准的非地形卡牌，无论剩余体力多少均会被直接杀死。审判鸟不会受到尖刺铠甲、惩罚者这类印记的影响。
            AddTranslation("Non-Terrain cards targeted by Judgement Bird are killed regardless of Health. Judgement Bird is not affected by abilities like Sharp and Punisher.", "谳鸟所指之非地形牌，无论命多少，皆立死。谳鸟不受利棘、罚者等技之效。");
            // 以爱憎之名
            AddTranslation("In the Name of Love and Hate", "以爱憎之名");
            // 当己方阵亡卡牌比敌方多出2张，或敌方阵亡卡牌比己方多出2张时，魔法少女将触发变身，随后移动至阵亡卡牌更多的战场一侧。
            AddTranslation("When 2 more ally cards have died than opposing cards or vice versa, Magical Girl will transform then move to the side of the board that lost more cards.", "当友方死牌较敌多二，若敌较友多二，术少女易形，而移向死牌较多之一侧。");
            // 魔法少女
            AddTranslation("Magical Girls", "诸术少女");
            // 当4名魔法少女及其任意进化形态全部处于同一侧战场时，持牌人将获得一张特殊卡牌。
            AddTranslation("Gain a special card when all 4 Magical Girls or their evolutions are on the same side of the board.", "四术少女或其进形，若尽在局之一侧，则其主持得一异牌。");
            // 拟态
            AddTranslation("Mimicry", "拟态");
            // 一无所有在自身被击杀时，将显露其真实形态。
            AddTranslation("Nothing There reveals itself on death.", "无有死时，乃露其真形。");
            // 粉红
            AddTranslation("Pink", "绯");
            // 当3张友方卡牌阵亡时，深黯“军团”将触发形态转换。
            AddTranslation("Army in Pink will transform when 3 ally cards die.", "绯军于友牌死三时易形。");
            // 汲取
            AddTranslation("Sap", "汲");
            // 每当巨树汁液被献祭，执行献祭的卡牌发生爆炸的概率将逐步提升。
            AddTranslation("Whenever Giant Tree Sap is sacrificed, there is an increasing chance the sacrificing card will explode.", "巨树液凡见祀，则受祀之牌爆之几率渐增。");
            // 微笑
            AddTranslation("Smile", "笑");
            // 微笑的尸山每击杀1张卡牌，便会成长为更强形态；自身死亡时，若条件允许则退回到上一形态。
            AddTranslation("Mountain of Smiling Bodies grows into a stronger forme whenever killing a card. Upon dying, revert to a previous forme if possible.", "笑尸山凡杀一牌，则长为更强之形；其死时，若可，则反其前形。");
            // 星之声
            AddTranslation("Sound of a Star", "星声");
            // 若敌方已无可攻击目标，碧蓝新星将直接对所有单位格发起攻击。
            AddTranslation("If there are no cards on the opposing side that can be attacked, Blue Star strikes all slots directly.", "敌侧若无可攻之牌，则青星直击诸位。");
            // 盈泪之剑
            AddTranslation("The Sword Sharpened with Tears", "泪淬之剑");
            // 绝望骑士与愤怒侍从，若相邻卡牌被消灭，便会触发形态转变。
            AddTranslation("Knight of Despair and Servant of Wrath will transform when an adjacent card dies.", "绝望骑者与忿侍，若邻牌死，则易形。");
            // 牧神的午后
            AddTranslation("Syrinx", "牧神笛");
            // 无名怪婴在累计完成六次献祭后，将触发形态转变。
            AddTranslation("Nameless Fetus transforms when sacrificed six times.", "无名胎凡见祀六，则易形。");
            // 归巢本能
            AddTranslation("The Homing Instinct", "归巢性");
            // 当使用“归家的路途”时，你手中获得一张“胆小的猫咪”。[define:wstl_scaredyCat]
            AddTranslation("When The Road Home is played, create a Scaredy Cat in your hand. [define:wstl_scaredyCat]", "归途既陈，则汝手生一“怯猫”。[define:wstl_scaredyCat]");
            // 三只鸟
            AddTranslation("Three Birds", "三鸟");
            // 当惩戒鸟、审判鸟与大鸟处于战场同一侧时，你将获得一张特殊卡牌。
            AddTranslation("Gain a special card when Punishing Bird, Judgement Bird, and Big Bird are on the same side of the board.", "罚鸟、谳鸟、大鸟若同在局一侧，则汝得一异牌。");
            // 今日表达
            AddTranslation("Today's Expression", "今容");
            // 当抽到“今天也很害羞”时，该卡牌将触发形态转换。
            AddTranslation("Today's Shy Look changes forme when drawn.", "今羞既引，则易形。");
            // 断腕之刃
            AddTranslation("Wrist Cutter", "断腕刃");
            // 每当卡牌被献祭时，血浴缸就会发生改变。
            AddTranslation("Bloodbath transforms whenever a card is sacrificed.", "血浴凡有牌见祀，则变。");
            // 黄砖之路
            AddTranslation("Yellow Brick Road", "黄砖路");
            // 当奥兹玛、归家的路途、热心的樵夫、索求智慧的稻草人处于同一侧战场时，立即获得一张特殊卡牌。
            AddTranslation("Gain a special card when Ozma, The Road Home, Warm-Hearted Woodsman, and Scarecrow Searching for Wisdom are all on the same side of the board.", "奥兹玛、归途、热肠樵者、求智稻人若同在一侧，则即得一异牌。");
            // 阴云怪僧
            AddTranslation("Clouded Monk", "阴云僧");
            // 附魔
            AddTranslation("Enchanted", "附魔");
            // 此卡牌将锁定带有光耀印记的目标，攻击时不对其造成任何伤害，且攻击后自身消亡。于持有者下一回合开始时，移除1层此效果。
            AddTranslation("This card will target cards with the Dazzling sigil, dealing no damage to them and dying after attacking. At the start of the owner's next turn, lose 1 stack of this effect.", "此牌专指有耀印之牌，击之不伤，而攻后自死。其主次合始，去此效一层。");
            // 罪
            AddTranslation("Sin", "罪");
            // 此卡牌对任一单位造成伤害时，向目标转移1层罪。
            AddTranslation("When this card deals damage to another creature, transfer 1 Sin to that card.", "此牌伤他物时，以罪一授之。");
            // WhistleWind的脑叶公司模组
            AddTranslation("WhistleWind Lobotomy Mod", "WhistleWind 脑叶补缀");
            // 暮光穿行
            AddTranslation("Through the Twilight", "穿暮");
            // 于末日中求生，讨伐巨兽。
            AddTranslation("Survive the apocalypse and defeat the Beast.", "历末世而毙巨兽。");
            // 都市之垢
            AddTranslation("Impuritas Civitatis", "都市垢");
            // 在Sephirot选择节点与Angela见面。
            AddTranslation("Meet Angela at a Sephirot choice node.", "于 Sephirot 择点见安吉拉。");
            // 集结黑森林守护者。
            AddTranslation("Gather the guardians of the Black Forest.", "集黑林之守者。");
            // 满堂红
            AddTranslation("Full House", "满堂");
            // 集结所有魔法少女。
            AddTranslation("Bring all of the magical girls together.", "会诸术少女。");
            // 使一众失散已久的友人重聚（绿野仙踪）。
            AddTranslation("Reunite a group of long-lost friends.", "使久失之友复会。");
            // 祝福
            AddTranslation("Blessing", "祐");
            // 你见证了他的到来。
            AddTranslation("You witnessed His coming.", "汝见其来。");
            // 没有恶，善就不能存在。
            AddTranslation("Good cannot exist without evil.", "无恶则善不立。");
            // 你的野兽腹中，传来一阵诡异的咕噜声。
            AddTranslation("A strange gurgling sound comes from your beast's stomach.", "汝兽腹中，有异声咕然。");
            // 那位Sephirah同意了，而其余众人则各奔前路。
            AddTranslation("The Sephirah agrees, and the others continue their separate way.", "其 Sephirah 诺，而余者各行。");
            // 在他们临走之前，他们承诺会和你再次碰面。
            AddTranslation("Before they go, they promise to see you again.", "临去，皆诺复见汝。");
            // 你可邀请[c:bR]1[c:]人加入你的队伍同行，其余人则会自行离去。
            AddTranslation("You may ask [c:bR]1[c:] to join you. The others will continue on their own.", "汝可邀[c:bR]1[c:]人偕行。余者自去。");
            // 设备运作已被不明因素阻断，此状态下无法执行逃脱操作。
            AddTranslation("Something prevents its function. You cannot escape this one.", "有物沮其机用，今不得遁。");
            // 是我将你逼入了绝境？还是说，我只是让你觉得索然无味？
            AddTranslation("Have I backed you into a corner? Or am I simply boring you?", "我已逼汝穷乎？抑但使汝厌乎？");
            // 想来此事无关紧要，我会应你所求。
            AddTranslation("I suppose it doesn't matter. I will honour your request.", "然此无足论，我将成汝之请。");
            // 你可没那么容易脱身。
            AddTranslation("You cannot escape so easily.", "汝不易遁也。");
            // 神力灌注入你队伍中的野兽，使其力量陡增。
            AddTranslation("Divine power infuses the beasts in your caravan, empowering them.", "神力注汝旅兽，使其益强。");
            // [c:bR]不允许你拒绝我。[c:]
            AddTranslation("[c:bR]Do not deny me.[c:]", "[c:bR]毋拒我。[c:]");
            // 一套共计[summary]的专属聚焦异想体及相关现象的专题纪要。
            AddTranslation("A set of [summary] exclusively featuring abnormalities and related phenomena.", "一套[summary]，专取异想体及其相关之异象。");
            // 异想体头目
            AddTranslation("Abnormal Bosses", "异魁");
            // 常规头目战中，头目将会化用异想体的力量进行战斗。
            AddTranslation("Vanilla bosses will play Abnormalities during their battles.", "常魁战中，魁将用异想体而战。");
            // 异变遭遇
            AddTranslation("Abnormal Encounters", "异遇");
            // 所有常规战斗敌方将仅使用异想体卡牌。
            AddTranslation("All regular battles will only use abnormality cards.", "诸常战，敌惟用异想体牌。");
            // 天启之子
            AddTranslation("Start with a Beast", "始携兽");
            // 将终末鸟加入你的初始牌组。
            AddTranslation("Start your run with Apocalypse Bird in your deck.", "以终鸟入汝初牌列而始局。");
            // 稀有之旅
            AddTranslation("Better Rare Chances", "罕牌易见");
            // 稀有卡更有可能出现在异想体选择节点。
            AddTranslation("Rare cards are more likely to appear at abnormal choice nodes.", "异想体择点更易见罕牌。");
            // 终末天启
            AddTranslation("Final Apocalypse", "终末天启");
            // 最终头目将由终末之兽替代莱西。
            AddTranslation("Leshy is replaced as the final boss of the run with the Beast.", "局终之魁，以彼兽易莱西。");
            // 末日降临
            AddTranslation("Final Coming", "末临");
            // 白夜头目强度提升，且必定登场。
            AddTranslation("The Saviour boss will be stronger and guaranteed to appear.", "救主魁益强，且必见。");
            // 最后的狂笑
            AddTranslation("Final Laugh", "终末狂笑");
            // 最终头目将由弄臣替代莱西。
            AddTranslation("Leshy is replaced as the final boss of the run with the Fool.", "局终之魁，以弄臣易莱西。");
            // 终末诡谋
            AddTranslation("Final Trick", "终诡");
            // 说谎的大人头目强度提升，且必定登场。
            AddTranslation("The Adult boss will be stronger and guaranteed to appear.", "诳长魁益强，且必见。");
            // 以愚启战
            AddTranslation("Start with a Fool", "始携愚者");
            // 将虚无弄臣加入你的初始牌组。
            AddTranslation("Start your run with Jester of Nihil in your deck.", "以虚弄臣入汝初牌列而始局。");
            // 谎言之始
            AddTranslation("Start with a Liar", "始携诳者");
            // 将说谎的大人加入你的初始牌组。
            AddTranslation("Start your run with Adult Who Tells Lies in your deck.", "以言诳之长者入汝初牌列而始局。");
            // 创迹者
            AddTranslation("Miracle Worker", "奇迹者");
            // 莱西将以疫医应战，警惕时钟。
            AddTranslation("Leshy will play Plague Doctor against you. Beware the Clock.", "莱西将以疫医敌汝。慎钟。");
            // [c:bR]走得太快，来的太早。[c:]
            AddTranslation("[c:bR]Too fast. Too soon.[c:]", "[c:bR]太遽。太早。[c:]");
            // 你的旅途，终至这片阴暗压抑的森林。
            AddTranslation("Your journey has brought here, to a dark, oppressive forest.", "汝行至此，至一幽闇压郁之林。");
            // 头顶的天空是一片墨色虚无，看不见半点星辰。
            AddTranslation("The sky above you is an inky void, empty of even a single star.", "汝上之天，墨虚也，无一星。");
            // 一声骇人的咆哮震得你骨头发麻，一股寒意瞬间攫住全身。
            AddTranslation("A horrible roar rattles your bones, and a fearful chill overcomes you.", "恶吼震汝骨，而寒慄遍身。");
            // 黑森林的深处，藏着一头怪物。
            AddTranslation("Somewhere beyond the dark trees, there's a monster.", "暗木之外，有一怪焉。");
            // [c:bR]黑森林深处的怪物。[c:]
            AddTranslation("[c:bR]A monster in the Black Forest.[c:]", "[c:bR]黑林之怪。[c:]");
            // 你的旅途，终至这片陌生却又熟悉的森林。
            AddTranslation("Your journey has brought here, to an unknown yet familiar forest.", "汝行至此，至一林，虽陌而若识。");
            // 你知道，黑森林深处藏着一头怪物。
            AddTranslation("Somewhere beyond the dark trees, you know, there's a monster.", "汝知暗木之外，有一怪焉。");
            // 混蛋！我的驯鹿！
            AddTranslation("Dag nab it! My reindeer!", "恶哉！我之驯鹿！");
            // 可爱的小家伙
            AddTranslation("Cute Lil Guy", "小可人");
            // [creature]不会死亡，而是进入倒地状态。倒地生物在特定条件下将处于无敌状态。
            AddTranslation("[creature] will enter a downed state instead of dying. Downed creatures are invulnerable under special conditions.", "[creature]不死，而入偃地之状。偃地之物，于特定之时不受伤。");
            // 击杀场上的白夜与所有使徒，随后造成 33 点直接伤害。
            AddTranslation("Kill WhiteNight and all Apostles on the board then deal 33 direct damage.", "杀局上白夜与诸使徒，而直伤三十三。");
            // 战斗结束时，此卡牌会随机标记若干带颜色的目标区域，将于下一回合对这些区域发起攻击。红色：此卡牌伤害翻倍；白色：此卡牌伤害减半，并恢复等同于自身威力的生命值；黄色：无特殊效果。
            AddTranslation("At the end of combat, this card will mark random spaces with coloured targets, then attack those spaces on its next turn. Red: this card's damage is doubled; White: this card's damage is halved and it heals equal to its Power; Yellow: no special effect.", "战终，此牌偶标诸色的位，次合攻之。赤：此牌伤倍；白：此牌伤半，而复命等于其威；黄：无异效。");
            // 每3回合切换一次生效鸟蛋效果。最终阶段时，此印记将改变运作方式。对手卡牌可能在回合结束时移动。此卡牌的生命值不会低于90/60/30点。
            AddTranslation("Every 3 turns, change the active egg effect. On the final phase, this sigil changes behaviour. Opponent cards may move at the end of the turn. This card cannot go below 90/60/30 Health.", "每三合更一蛋效。终阶段，此印易其行。敌牌或于合终移动。此牌命不下于90/60/30。");
            // 持牌人的回合结束时，此卡牌将根据本回合受到的伤害量，对持牌人造成等量的直接伤害。
            AddTranslation("At the end of the owner's turn, deal direct damage to the owner proportional to how much damage this card received during the turn.", "持牌者合终，此牌随今合所受之伤数，直伤其主。");
            // 吞噬它们！
            AddTranslation("Eat 'em!", "吞之！");
            // 瓶中单次召回
            AddTranslation("Single Recall Bottle", "瓶中单召");
            // 瓶中全部召回
            AddTranslation("Total Recall Bottle", "瓶中皆召");
            // 黄昏将至...
            AddTranslation("Twilight falls...", "暮坠……");
            // 开端始于终局。
            AddTranslation("The beginning at the end.", "终中之始。");
            // 终局即是开端。
            AddTranslation("The end at the beginning.", "始中之终。");
            // 万物皆为平等，万物皆归于其位。
            AddTranslation("Everything is equal. Everything is as it should be.", "万物齐同，万物各安其所。");
        }

    }

    public class TVFsBossesMod
    {
        public static void RegisterTranslations()
        {
            // 虽然这里空无一人，但有一些祭品摆在你面前。
            AddTranslation("Though there was no one in sight, some offerings were laid out before you.", "虽不见人，而有数献陈于前。");
            // 附近不再有[c:bR]木雕师[c:]了。
            AddTranslation("There was no [c:bR]Woodcarver[c:] nearby.", "近旁无[c:bR]刻木妪[c:]。");
            // 尽管如此，她的图腾部件仍然存在。
            AddTranslation("Still, her totem pieces remained.", "然其神偶诸件犹存。");
            // 那个年老的[c:bR]木雕师[c:]已经不见了。
            AddTranslation("The old [c:bR]Woodcarver[c:] was nowhere to be found.", "老[c:bR]刻木妪[c:]无所在矣。");
            // 她曾经坐过的那根木凳旁还遗留着她的祭品。
            AddTranslation("Her carvings remained by the log she once sat upon.", "其所刻之偶，犹在其旧坐之木旁。");
            // [c:bR]木雕师[c:]从灌木丛中走了出来。
            AddTranslation("The [c:bR]Woodcarver[c:] emerged from the thicket.", "[c:bR]刻木妪[c:]自丛薄间出。");
            // 她的脸看起来比平时更严肃了。
            AddTranslation("Her face looked somehow more stern than usual.", "其容较常尤肃。");
            // 一位老妇人走近了。
            AddTranslation("An ancient woman approached.", "一老妪前来。");
            // 她看起来对你非常不满。
            AddTranslation("She looked intensely displeased with you.", "其意甚不悦汝。");
            // 附近的树枝沙沙作响，[c:bR]木雕师[c:]露出面容。
            AddTranslation("Nearby branches rustled as The [c:bR]Woodcarver[c:] revealed herself.", "枝摇而[c:bR]刻木妪[c:]见。");
            // 这次她没有拿出祭品。
            AddTranslation("She had no offerings this time.", "此次其无献。");
            // [c:bR]离开。[c:]
            AddTranslation("[c:bR]Leave.[c:]", "[c:bR]去。[c:]");
            // 往回走。
            AddTranslation("Turn back.", "返。");
            // 你还没准备好。
            AddTranslation("You are not prepared.", "汝未备。");
            // 木雕师头目
            AddTranslation("Woodcarver Boss", "刻木妪魁");
            // 矿工头目战被木雕师所替换了。
            AddTranslation("The Prospector is replaced as the boss of the Woodlands.", "木野之魁，采夫为刻木妪所易。");
            // 你发现自己身处一片茂密且刺鼻的蘑菇林中。
            AddTranslation("You found yourself among a grove of thick and pungent mushrooms.", "汝处一蕈林，厚而气辛。");
            // 曾经的手术台被遗弃了。
            AddTranslation("The operating table lay abandoned.", "手术案既弃。");
            // [c:bR]菌学家[c:]从一个巨大的蘑菇后面走了出来。
            AddTranslation("The [c:bR]Mycologists[c:] stepped out from behind an enormous mushroom.", "[c:bR]蕈家[c:]自巨蕈后出。");
            // 其中一个看起来很焦虑，但另一个表情非常严肃。
            AddTranslation("One of them looked anxious, but the other bore a very serious expression.", "其一色忧，其一色严。");
            // 你眯起眼睛，透过厚厚的孢子云看到一个人影。
            AddTranslation("You squinted to see a figure through the thick cloud of spores.", "汝眇目而透厚蕈霭，见一人影。");
            // [c:bR]菌学家[c:]共用的身体摆出了威胁的姿势。
            AddTranslation("The [c:bR]Mycologists[c:]' shared body was posed in a threatening stance.", "[c:bR]蕈家[c:]共身，作威势而立。");
            // [c:bR]菌学家[c:]每次呼吸都显得更加疯狂。
            AddTranslation("The [c:bR]Mycologists[c:] appeared more crazed with each breath they took.", "[c:bR]蕈家[c:]每一息愈狂。");
            // 很明显，他们不仅仅想在你的造物身上进行实验。
            AddTranslation("It was clear they wanted to experiment on more than just your creatures.", "显然彼所欲试者，不独汝物。");
            // [size:3]这样就足够了。[size:]
            AddTranslation("[size:3]It will suffice.[size:]", "[size:3]其足矣。[size:]");
            // [size:3]为了我们的实验，就是如此。[size:]
            AddTranslation("[size:3]For our experiments, yes.[size:]", "[size:3]于我试，然。[size:]");
            // [size:3]别担心，我们会有一个备用计划。[size:]
            AddTranslation("[size:3]Do not worry. I have a backup plan.[size:]", "[size:3]毋忧，我有后计。[size:]");
            // [size:3]这样的结果令人满意。[size:]
            AddTranslation("[size:3]Satisfactory results.[size:]", "[size:3]其果可也。[size:]");
            // 但…但是只有一个挑战者？
            AddTranslation("B- But there is only one challenger?", "然仅一角者乎？");
            // 我……我们需要你的身体？
            AddTranslation("We... We need your body?", "我……我曹须汝身乎？");
            // 你…你不会……把你的身体献给我们做实验吧？
            AddTranslation("Y- You will... not submit your body for our experiments?", "汝……不肯以身付我曹之试乎？");
            // 菌学家头目
            AddTranslation("Mycologists Boss", "蕈家魁");
            // 钓鱼人头目战被菌学家所替换了。
            AddTranslation("The Angler is replaced as the boss of the Wetlands.", "泽地之魁，渔父为蕈家所易。");
            // 实验体
            AddTranslation("Experiment", "试体");
            // 非常好。
            AddTranslation("GOOD.", "善。");
        }

    }


    public class ZephtSunMod
    {
        public static void RegisterTranslations()
        {
            // Card
            // 调试阳光
            AddTranslation("DebugSun", "试日芒");
            // 阳光：
            AddTranslation("Sun: ", "日芒：");

            // Challenge
            // 夜幕降临
            AddTranslation("Night time", "夜至");
            // 你将无法从天空中获取阳光。
            AddTranslation("You will no longer get passive sun falling from the sky.", "自天而坠之日芒，汝不复得之。");

            // Ability
            // 阳光激励
            AddTranslation("SunBoost", "增晖");
            // 当[creature]被放置时，持牌人会得到一定数量的阳光。
            AddTranslation("When [creature] is placed on the board, the owner will gain sun.", "[creature]既置于局，持者得日芒。");
            // 明智地使用应急物资。
            AddTranslation("Wise use of emergency supplies.", "急储善用。");
            // 阳光杀戮
            AddTranslation("SunKill", "杀取晖");
            // 当[creature]击败另一张卡牌时，另一张卡牌将掉落阳光。
            AddTranslation("When [creature] defeats another card, the other card will drop sun.", "[creature]既败他牌，其牌堕日芒。");
            // 将你的敌人重新转化为营养。
            AddTranslation("Recycle your enemies back into nutrients", "反汝敌而归养。");
            // 阳光生产
            AddTranslation("SunMaker 1", "生晖一");
            // 在持牌人的回合结束时，若[creature]在玩家一侧，它将生产1个阳光。
            AddTranslation("At the end of the owner's turn, [creature] will produce 1 sun, if it belongs to the player.", "持者合终，若[creature]在玩家一侧，则生一日芒。");
            // 每一点都很重要
            AddTranslation("Every little bit counts", "纤芒亦数。");
            // 双重生产
            AddTranslation("SunMaker 2", "生晖二");
            // 在持牌人的回合结束时，若[creature]在玩家一侧，它将生产2个阳光。
            AddTranslation("At the end of the owner's turn, [creature] will produce 2 sun, if it belongs to the player.", "持者合终，若[creature]在玩家一侧，则生二日芒。");
            // 要是月亮这么有用就好了
            AddTranslation("If only the moon was this useful", "月若如是之用可矣。");
            // 三重生产
            AddTranslation("SunMaker 3", "生晖三");
            // 在持牌人的回合结束时，若[creature]在玩家一侧，它将生产3个阳光。
            AddTranslation("At the end of the owner's turn, [creature] will produce 3 sun, if it belongs to the player.", "持者合终，若[creature]在玩家一侧，则生三日芒。");
            // 太阳的力量，在你的掌心
            AddTranslation("The power of the sun, in the palm of your hand", "日之力，在汝掌中。");
            // 阳光生产
            AddTranslation("SunMaker", "生晖");
            // 在持牌人的回合结束时，若[creature]在玩家一侧，它将生产X个阳光。有些牌比其他牌产生更多的阳光。
            AddTranslation("At the end of the owner's turn, [creature] will produce X sun, if it belongs to the player. Some cards produce more sun than others.", "持者合终，若[creature]在玩家一侧，则生X日芒。诸牌所生，多少不同。");

            // ShowThenClear
            // 你没有足够的阳光。
            AddTranslation("You dont have enough sun for that one", "汝之日芒不足。");
        }

    }

    public class PlantsVSZombiesMod
    {
        public static void RegisterTranslations()
        {
            // Card
            // 豌豆射手
            AddTranslation("Peashooter", "豌豆射手");
            // 双发射手
            AddTranslation("Repeater", "重射手");
            // 落叶堆
            AddTranslation("Leaflitter", "落叶聚");
            // 一种通常用来抵御亡灵的植物。
            AddTranslation("A plant commonly used to fend off the undead", "常以御死者之一草。");
            // 三线射手
            AddTranslation("Threepeater", "三线射手");
            // 是比豌豆射手更强大版本。
            AddTranslation("A more powerful version of the iconic peashooter", "乃豌豆射手之益强者。");
            // 它们说三个头总比一个头好。
            AddTranslation("they say 3 heads are better than one", "人云三首胜一首。");
            // 仙人掌
            AddTranslation("Cactus", "仙人掌");
            // 尽量不要被其戳伤。
            AddTranslation("Try not to prick yourself on it", "毋自触其刺。");
            // 尖刺碎片
            AddTranslation("Splinters", "棘屑");
            // 导向蓟
            AddTranslation("Homing Thistle", "逐的蓟");
            // 这株植物能轻易地追踪目标。
            AddTranslation("This one tracks down its target with ease", "此物寻的甚易。");
            // 猫尾草
            AddTranslation("Cattail", "香蒲");
            // 喵~
            AddTranslation("Nyah~", "喵~");
            // 大嘴花
            AddTranslation("Chomper", "噬花");
            // 没有吠叫，只会咬人。
            AddTranslation("No bark and all bite", "不吠而惟噬。");
            // 星星果
            AddTranslation("Starfruit", "星果");
            // 令人惊讶的是，没有火球。
            AddTranslation("Surprisingly not a ball of fire", "异哉，其非火丸。");
            // 回旋镖射手
            AddTranslation("Bloomerang", "回旋花");
            // 别上当，如果你扔出回旋镖，它就不会回来了。
            AddTranslation("Don't be deceived, it won't just return if you throw it away", "毋为所欺，掷之则不徒复。");
            // 菜问
            AddTranslation("bonk choy", "菜问");
            // 毋庸置疑，充满活力。
            AddTranslation("A feisty one for sure", "此物诚悍。");
            // 充能柚子
            AddTranslation("Citron", "香橼");
            // 如果你能负担得起放置它，它的热情一定会帮助你。
            AddTranslation("If you can afford to play it, it's zest is bound to aid you", "汝苟能置之，其烈必佐汝。");
            // 红针花
            AddTranslation("Red Stinger", "红针花");
            // 如果你想充分发挥它的潜力，就要对其进行战略性站位。
            AddTranslation("Position it strategically if you want to use its full potential", "欲尽其用，宜审其位。");
            // 钢地刺
            AddTranslation("Spikerock", "钢地刺");
            // 地刺
            AddTranslation("Spikeweed", "地刺");
            // 你会把地刺放在那里，作为那些敢于接近它的人的陷阱吗？
            AddTranslation("Will you lay the spikeweed as a trap for those who dare approach it?", "汝其布地刺，以阱敢近者乎？");
            // 任何试图践踏它的人都会遭到严厉的惩罚。
            AddTranslation("Anybody who attempts to trample it will meet a sharp fate.", "凡欲蹂之者，必逢其锐。");
            // 旋转洋蓟
            AddTranslation("Artichoke", "洋蓟");
            // 这架无人机经历了一些战争。
            AddTranslation("This drone has seen some warfare", "此机素历战阵。");
            // 蜜蜂射手
            AddTranslation("Beeshooter", "蜂射手");
            // 根据所有已知的航空定律，蜜蜂不可能飞。
            AddTranslation("According to all known laws of aviation, there is no way a bee should be able to fly", "按飞行诸法，蜂本不宜能飞。");
            // 小喷菇
            AddTranslation("Puffshroom", "喷菇");
            // 它可能不是很强大，但它可以让你摆脱困境。
            AddTranslation("It might not be very powerful, but it can get you out of a pinch", "其力虽微，亦足解汝急。");
            // 海蘑菇
            AddTranslation("Seashroom", "海菇");
            // 只是一个小蘑菇，坐在水面上。
            AddTranslation("Just a little mushroom, sitting on the water", "特一小菇，踞于水上。");
            // 胆小菇
            AddTranslation("Scaredyshroom", "怯菇");
            // 有些人可能会认为这是一个懦夫的战术。
            AddTranslation("Some may consider this one a coward for its tactics", "或有以其术为怯者。");
            // 烟雾孢子
            AddTranslation("Fume", "烟孢");
            // 大喷菇
            AddTranslation("Fumeshroom", "大喷菇");
            // 它的烟雾可以击中许多敌人。
            AddTranslation("Its fumes can hit many foes", "其烟可中众敌。");
            // 孢子菇
            AddTranslation("Sporeshroom", "孢菇");
            // 将分而治之付诸实践。
            AddTranslation("Put divide and conquer into practice", "行分而治之。");
            // 向日葵
            AddTranslation("Sunflower", "日葵");
            // 它们可以为整个植物军队生产阳光。
            AddTranslation("These can power entire infantries", "此物可资众草之师以日芒。");
            // 双子向日葵
            AddTranslation("Twin Sunflower", "双生日葵");
            // 真正伟大的供能植物。
            AddTranslation("Truly a great powerplant", "诚大供能之草也。");
            // 阳光菇
            AddTranslation("SunShroom", "晖菇");
            // 给阳光菇一些时间来充分发挥其潜力。
            AddTranslation("allow the sunshroom some time to reach its full potential", "姑假晖菇以时，使尽其材。");
            // 金蟾菇
            AddTranslation("ToadStool", "蟾菇");
            // 一种冰冷的真菌，真奇怪。
            AddTranslation("A frogish fungus, how curious", "蛙然之菌，异哉。");
            // 阳光豆
            AddTranslation("Sun bean", "晖豆");
            // 你会投资阳光豆吗？
            AddTranslation("will you invest in the sun bean?", "汝其殖于晖豆乎？");
            // 坚果墙
            AddTranslation("Wallnut", "坚果垣");
            // 多么标志性的防线啊。
            AddTranslation("What an iconic line of defence", "诚标志之防行也。");
            // 高坚果
            AddTranslation("Tallnut", "高坚果");
            // 几乎没有什么能越过这一关。
            AddTranslation("Near nothing can get past this one", "几无有能逾此者。");
            // 榴莲
            AddTranslation("Endurian", "榴莲");
            // 想穿过它的外壳不会很愉快。
            AddTranslation("It's outer shell wont be so enjoyable to get through", "欲穿其甲，可不易也。");
            // 大蒜
            AddTranslation("Garlic", "大蒜");
            // 用大蒜的臭味控制即将到来的袭击。
            AddTranslation("Control the upcoming onslaughts with the Garlic's stench.", "以大蒜之臭气御即将之冲击。");
            // 全息坚果
            AddTranslation("Infi-nut", "全息坚果");
            // 打败这个可没那么简单。
            AddTranslation("Defeating this one isn't so simple", "克此物，非易事也。");
            // 土豆地雷
            AddTranslation("Potato Mine", "土豆地雷");
            // 一个小但有潜在危险的土豆。
            AddTranslation("A small but potentially dangerous spud", "小小之薯，然潜危不可小觑。");
            // 樱桃炸弹
            AddTranslation("Cherry Bomb", "樱桃炸弹");
            // 它可能很甜，但你不应该低估它。
            AddTranslation("It may be sweet but you shouldnt underestimate it", "虽甜，然不可轻视之。");
            // 火爆辣椒
            AddTranslation("Jalapeno", "火爆辣椒");
            // 我可不想吃这玩意。
            AddTranslation("I would not want to eat that", "余可不愿食此物。");
            // 毁灭菇
            AddTranslation("DoomShroom", "毁灭菇");
            // 不可忽视的力量。
            AddTranslation("A force to be reckoned with", "不可轻忽之力。");
            // 火炬树桩
            AddTranslation("Torchwood", "火炬树桩");
            // 它可以增强盟友的力量。
            AddTranslation("It can boost it's allies' power", "能增盟军之威。");
            // 磁力菇
            AddTranslation("MagnetShroom", "磁力菇");
            // 削弱敌人以帮助其盟友。
            AddTranslation("Weakens the enemy to aid its allies", "削敌以助盟军。");
            // 魅惑菇
            AddTranslation("Hypnoshroom", "魅惑菇");
            // 敌人的敌人就是朋友。
            AddTranslation("One mans foe is another mans friend", "彼之仇者，此之友也。");
            // 黄金叶
            AddTranslation("Gold Leaf", "黄金叶");
            // 翻开新的一页挫败对手的计划。
            AddTranslation("Foil your opponents' plans by turning over a new leaf", "翻开新叶，挫败敌手之谋。");
            // 南瓜头
            AddTranslation("Pumpkin", "南瓜");
            // 用这个简单的技巧强化你所有的牌。
            AddTranslation("Fortify all of your cards with this one simple trick", "以此一简法，增固乃诸牌。");
            // 逃脱树根
            AddTranslation("Escape Root", "逃脱树根");
            // 允许其他卡免费地逃到安全地带。
            AddTranslation("Allows other cards the freedom of escaping to safety", "使他牌得自由逸于安全之所。");
            // 咖啡豆
            AddTranslation("Coffee bean", "咖啡豆");
            // 它可以为植物提供能量，释放更多潜力。
            AddTranslation("It can energise plants and unlock further potential", "能为草木注能，释放更深之潜力。");
            // 幼芽
            AddTranslation("Sprout", "幼芽");
            // 但一个简单的芽，它会长成什么？没人知道，潜力无限。
            AddTranslation("But a simple sprout, what will it grow into? nobody knows, Limitless potential", "不过一幼芽，将长成何物？无人知也，潜力无量。");
            // 一件普通的棕色外套，渴望大脑。
            AddTranslation("A common browncoat, hungry for brains", "一寻常之棕袍者，嗜食脑髓。");
            // 路障僵尸
            AddTranslation("Conehead", "路障僵尸");
            // 一件配备路障的棕色外套僵尸。
            AddTranslation("A browncoat that equipped itself with road work equipment", "以路障为盔之棕袍僵尸。");
            // 铁桶僵尸
            AddTranslation("Buckethead", "铁桶僵尸");
            // 想想头盔能提供这么多保护。
            AddTranslation("To think headgear could provide so much protection", "头盔竟能供如许之护，可叹。");
            // 旗子僵尸
            AddTranslation("Flag Zombie", "旗子僵尸");
            // 一个真正的领导者，号召盟友作战。
            AddTranslation("A true leader, calling in allies for combat", "真正之领袖，号召盟军入战。");
            // 潜水僵尸
            AddTranslation("Snorkel", "潜水僵尸");
            // 潜入深海，出来大嚼一口。
            AddTranslation("Dives in the deep and emerges for a munch", "潜游深处，复出大嚼。");
            // 铁栅门僵尸
            AddTranslation("Screen Door", "铁栅门僵尸");
            // 我更喜欢结实的木门。
            AddTranslation("I much prefer doors of sturdy wood", "余更偏好坚木之门。");
            // 玩偶匣僵尸
            AddTranslation("Jack in a box", "玩偶匣僵尸");
            // 这首歌用如此简单的旋律带来了紧张感。
            AddTranslation("This one brings tension with such a simple melody", "以简单曲调带来张力。");
            // 弹坑
            AddTranslation("Crater", "弹坑");
            // 不过是个洞。
            AddTranslation("Just a hole", "不过一坑耳。");
            // 森林的循环
            AddTranslation("The cycle of the forest", "林木之循环");
            // 蘑菇块
            AddTranslation("Shroom Chunksr", "蘑菇块");
            // 蘑菇的碎块
            AddTranslation("Chunks of shrooms", "蘑菇之碎块");
            // 果壳的碎屑
            AddTranslation("Shards of shells", "壳之碎屑");
            // 僵尸的断手
            AddTranslation("Zombie Arm", "僵尸断臂");
            // 一定是僵尸掉了这个。
            AddTranslation("A zombie must have dropped this", "必为僵尸所遗落。");
            // 迷途猫蕊
            AddTranslation("Stray Cat", "迷途猫蕊");
            // 真奇怪。我不认识这玩意。
            AddTranslation("How bizarre.. i don't recognise that one", "怪哉……余不识此物。");
            // 安息猫蕊
            AddTranslation("Stray Cat Requiem", "安息猫蕊");
            // 调试器
            AddTranslation("Debugger", "调试器");
            // 超调试器
            AddTranslation("Debuggest", "超调试器");

            // Starter
            // 植物大战僵尸
            AddTranslation("Plants vs Zombies", "草木战僵尸");
            // 原始种子
            AddTranslation("The original seeds", "原种");
            // 午夜员工
            AddTranslation("The midnight crew", "夜半众");
            // 禅境花园
            AddTranslation("The Zen Garden", "禅园");

            // Ability
            // 附加状态
            AddTranslation("Add Stats", "益数");
            // 当[creature]被放置时，它的生命、攻击和其他印记将被添加到持牌人一侧的每一张非地形卡上。然后此牌将被销毁。[creature]不能用于印记转移或篝火。
            AddTranslation("When [creature] is played, its health, attack, and other sigils will be added to every other non terrain card on your side of the board. Then this card will perish. Cards bearing this sigil cannot be used in sigil transfers or campfires.", "[creature]既陈，其命、威与余印契皆加于汝侧诸非地形牌。既而此牌死。负此印契之牌，不得用于转印与营火。");
            // 团队合作的力量
            AddTranslation("The power of teamwork", "协力之功。");
            // 附加对手状态
            AddTranslation("Add Stats Opponent", "益敌数");
            // 当[creature]被放置时，它的生命、攻击和其他印记将被添加到持牌人对手一侧的每一张非地形卡上。然后此牌将被销毁。[creature]不能用于印记转移或篝火。
            AddTranslation("When [creature] is played, its health, attack, and other sigils will be added to every card on the opposing side of the board. Then this card will perish. Cards bearing this sigil cannot be used in sigil transfers or campfires.", "[creature]既陈，其命、威与余印契皆加于敌侧诸牌。既而此牌死。负此印契之牌，不得用于转印与营火。");
            // 消灭你的敌人
            AddTranslation("Blight your foes", "殃汝敌。");
            // 装甲破坏者
            AddTranslation("Armor breaker", "破甲");
            // 当放置[creature]时，其将移除所有对手卡牌的防御型印记。
            AddTranslation("When [creature] is played, it removes all defense sigils from all of the opposing cards.", "[creature]既陈，尽去敌牌诸御印。");
            // 破甲是一种很好的进攻方式
            AddTranslation("Removing defense is a great offense", "去其御，善攻也。");
            // 末日使者
            AddTranslation("DoomBringer", "赍末");
            // 持牌人的结束时，[creature]将爆炸，对对手的所有卡牌造成7点伤害，对所有持牌人的卡牌造成1点伤害。
            AddTranslation("At the end of the owner's turn, [creature] will explode and deal 7 damage to all of the opponent's cards, along with 1 damage to all of the owners cards.", "持者合终，[creature]爆，伤敌诸牌七，兼伤其主诸牌一。");
            // 只有毁灭才会随之而来。
            AddTranslation("Only destruction lays in its wake", "其后惟毁。");
            // 逐渐消失
            AddTranslation("Fade Away", "渐灭");
            // 在持牌人的结束时，[creature]将受到1点伤害。
            AddTranslation("At the end of the owner's turn, [creature] will take 1 damage.", "持者合终，[creature]受一伤。");
            // 没有什么是永恒的
            AddTranslation("Nothing can last forever", "无有能久者。");
            // 头脑冷静
            AddTranslation("Hard Headed", "坚首");
            // 当[creature]受到攻击时，受到的伤害将减少2。然后，此印记将被移除。
            AddTranslation("When [creature] is attacked, the damage taken will be reduced by 2. Then this sigil will be removed.", "[creature]见攻，则所受之伤减二。既而去此印契。");
            // 头盔在防护方面出奇地优秀。
            AddTranslation("Headwear is surprisingly good at negating wounds", "首具御伤，异乎其善。");
            // 魅惑师
            AddTranslation("Hypnotist", "惑心");
            // 当[creature]被击败时，杀死它的卡牌会移动到它的位置。
            AddTranslation("When [creature] gets defeated, its killer will move to take its place.", "[creature]既败，杀之者移而据其处。");
            // 想想背叛这么容易发生。
            AddTranslation("To think that betrayal can happen so easily", "叛乃如此易生。");
            // 穿透打击
            AddTranslation("Pierce", "贯");
            // 在攻击之前，[creature]会先攻击对方队列中的卡牌，同时也会使其护甲印记失效。
            AddTranslation("Before attacking, [creature] attacks the given card in the opposing queue, it also nullifies the Armored sigil.", "将攻之前，[creature]先击敌列所指之牌，且废其坚甲印契。");
            // 躲在后面并不能保护你
            AddTranslation("Hiding in the back doesn't protect you here", "匿于后，不足自全。");
            // 火爆之辣
            AddTranslation("Spicy", "辛爆");
            // 在持牌人的回合结束时，[creature]将爆炸并对对位卡牌和其后方卡牌造成4点伤害。带有此印记的卡牌不能用于印记转移或篝火。
            AddTranslation("At the end of the owner's turn, [creature] will explode and deal 4 damage to the opposing card and to the card on the opposing backline. Cards bearing this sigil cannot be used in sigil transfers or campfires.", "持者合终，[creature]爆，伤其对位之牌与其后列之牌各四。负此印契之牌，不得用于转印与营火。");
            // 我从来都不太喜欢香料
            AddTranslation("I've never been too fond of spice", "我素不甚好辛。");
            // 孢子生殖
            AddTranslation("Spore Spreader", "散孢");
            // 如果[creature]击败另一张牌，你将获得一张[creature]的副本。
            AddTranslation("If [creature] defeats another card, a copy of itself will be returned to your hand.", "[creature]若败他牌，则一其副本归汝手。");
            // 这些孢子会传播多少？
            AddTranslation("just how much will these spores spread?", "此孢所散几何？");
            // 土豆泥
            AddTranslation("Spudow", "薯爆");
            // 当[creature]被击败时，它会对对位卡牌造成4点伤害。
            AddTranslation("When [creature] gets defeated, it deals 4 damage to the opposing card.", "[creature]既败，则伤其对位之牌四。");
            // 在土豆地里一定要小心脚下
            AddTranslation("Always watch your step in a potato field", "行薯畦间，常慎乃步。");
            // 芬芳
            AddTranslation("Sweet", "甘爆");
            // 在持牌人的回合结束时，[creature]将爆炸并对其周围3个敌方槽位中的卡牌造成3点伤害，然后对相邻插槽中的卡牌造成1点伤害。带有此印记的卡牌不能用于印记转移或篝火。
            AddTranslation("At the end of the owner's turn, [creature] will explode and deal 3 damage to the cards in the 3 enemy slots around it, then deal 1 damage to the cards in your adjacent slots. Cards bearing this sigil cannot be used in sigil transfers or campfires.", "持者合终，[creature]爆，伤其四遭三敌位之牌各三，复伤汝相邻位之牌各一。负此印契之牌，不得用于转印与营火。");
            // 也许比预期的更尖刻。
            AddTranslation("Maybe there's a bit more tartness than anticipated", "或其酸厉过所期。");
            // 胆小
            AddTranslation("Scaredy", "怯");
            // [creature]在面对攻击力大于0的对手卡牌时，会失去1点攻击力，但会获得1点生命值，直至对位卡牌离开。
            AddTranslation("[creature] loses 1 attack but gains 1 health when against an opposing card whose attack is greater than 0, unless the opposing card retreats too.", "[creature]当敌对之牌威大于零而与之相直，则失一威而得一命；彼牌若退，则止。");
            // 他们称之为战术撤退
            AddTranslation("They call it a tactical retreat", "人谓之权退。");
            // 僵尸号召
            AddTranslation("Zombie Caller", "召尸");
            // 当[creature]被放置时，将在其两侧空位上生成僵尸，尽管它可能有头饰。[define:zep_pvz_zombie]
            AddTranslation("When [creature] is played, A zombie gets played on each empty adjacent space, though it may have headgear. [define:zep_pvz_zombie]", "[creature]既陈，则两旁空处各生一尸；其尸或有首具。[define:zep_pvz_zombie]");
            // 一大波僵尸即将来袭！
            AddTranslation("A huge wave of zombies is approaching", "大群尸将至！");
            // 蘑菇力量
            AddTranslation("Shrooms", "蕈数");
            // 此印记表示的值将等于持牌人一侧的蘑菇数量。
            AddTranslation("The value represented with this sigil will be equal to the number of mushrooms that the owner has on their side of the table.", "此印所表之数，如其主持侧诸蕈之数。");
        }

    }

    public class SmallTweakHydraMod
    {
        public static void RegisterTranslations()
        {
            // [creature]在抽取时的孵化条件如下：你的牌组中的造物的生命和力量包含5个不同的数字，且有至少来自5个不同族群的造物各一张（所有带有此印记的卡牌将不会纳入此印记的计算）。
            AddTranslation("A card bearing this Sigil hatches when drawn if 5 unique numbers are in the Health of creatures in your deck, and in their Power, and if there is a creature of 5 unique tribes in your deck. [This Excludes all cards bearing this sigil]", "负此印契之牌，引而孚之：若汝牌列中诸物之命有五异数，威亦有五异数，又有五异族之物各一。〔凡负此印契者，不豫其数。〕");
        }

    }


    public class MoreItemsMod
    {
        public static void RegisterTranslations()
        {
            // 全场脆骨
            AddTranslation("All Brittle", "尽脆骨");
            // 全场刺甲
            AddTranslation("All Sharp", "尽利棘");
            // 场地上的所有卡牌获得脆骨印记。
            AddTranslation("All cards on the board gain Brittle", "局上诸牌皆得脆骨印契。");
            // 场地上的所有卡牌获得尖刺铠甲印记。
            AddTranslation("All cards on the board gain Sharp", "局上诸牌皆得利棘印契。");
            // 全场兵分
            AddTranslation("All Split Strike", "尽歧击");
            // 场地上的所有卡牌获得兵分两路印记。
            AddTranslation("All cards on the board gain Split Strike", "局上诸牌皆得歧击印契。");
            // 打乱印记
            AddTranslation("Shuffle Sigils", "乱印契");
            // 删除场上所有造物的印记并将其添加到随机的卡牌上。
            AddTranslation("All sigils on the board are removed and added to a random card", "尽去局上诸牌之印契，而悉归于一偶牌。");
            // 禁止游泳
            AddTranslation("No Waterbourne", "禁潜");
            // 将所有对方正在潜水的造物翻面，并移除其水袭印记。
            AddTranslation("All my cards on the board with Submerge are revealed and the sigil removed", "我局上诸有潜印者，皆出之于表，而去其印契。");
            // 热辣鲜肉
            AddTranslation("Hot Meat", "燠肉");
            // 在篝火旁使用此物品将使您的造物在该次事件不被幸存者杀死。
            AddTranslation("Using this item at the campfire will save your card from being destroyed for a single turn.", "若于营火用此物，则汝牌于此一遭不为余生者所杀。");
            // 用一桶鱼饵填满场上所有空位，它的气味让人难以忍受。
            AddTranslation("Places Bait Buckets on all empty spaces. The smell is overwhelming.", "诸空位皆置饵桶，其臭难胜。");
            // 炸弹夫人的遥控器
            AddTranslation("Mrs. Bomb's Remote", "弹夫人之遥器");
            // 在场地的所有空位上填满炸弹机器人。老实说，这很烦人。
            AddTranslation("Places Explode Bots on all empty spaces. Pretty annoying honestly.", "诸空位皆置爆机，诚烦人也。");
            // 炸弹夫人的遥控器。使用此道具，炸弹机器人就会填满场上的所有空位。
            AddTranslation("Mrs. Bomb's Remote. Click that thing and Explode Bots will drop in every open space.", "弹夫人之遥器。按之，则爆机尽坠诸空位。");
            // 将最后一张丢失的友方造物卡牌退还给您。
            AddTranslation("Returns the last friendly card that perished card to your hand", "使最后死去之友牌归汝手。");
            // 菌学家之锯
            AddTranslation("Mycologist Saw", "蕈家锯");
            // 将你这边的两张卡牌合并为一张。
            AddTranslation("Combine 2 cards on your side of the board to become one.", "并汝侧二牌为一。");
            // 如果我曾经“看到”过一个，那就是暂时的可憎之物。
            AddTranslation("A temporary abomination if I ever 'saw' one.", "我若曾“锯”得一憎物，此其暂者也。");
            // 幸存者
            AddTranslation("Survivor", "余生者");
            // 在场上选择你的一张卡牌，则该牌有概率被摧毁或增强。
            AddTranslation("Choose a card on the board to have a chance to either be destroyed or buffed.", "择局上一牌，使其或毁或益。");
            // 牙齿罐子
            AddTranslation("Teeth Jar", "齿罂");
            // 为你的货币碗中增加10颗牙齿，这不会影响你的天平。
            AddTranslation("Adds 10 teeth to your currency bowl. Does not get added to your scales.", "益齿十于汝财盂，不加于衡。");
            // 神秘卡包
            AddTranslation("Card Pack", "牌韬");
            // 在你的手中添加5张随机卡牌。
            AddTranslation("Adds 5 random cards to your hand.", "益汝手以五偶牌。");
            // 所以这就是为什么我的骡子回来的时间不多了。
            AddTranslation("So that's why my pack mules are coming back short.", "怪道我驮韬之骡，归来常少。");
            // 血肉蛋糕
            AddTranslation("Meat Cake", "肉糕");
            // 如果你在一场战斗中失败了，会重新点燃你的蜡烛。在头目战期间不起作用。
            AddTranslation("Relights a candle if you have lost a battle. Does not work during boss battles.", "汝若败于一战，则更燃一烛。魁战中无效。");
            // 万一你改变主意。
            AddTranslation("In case you change your mind", "倘汝易志。");
            // 陷阱
            AddTranslation("Trap", "阱");
            // 在你的手中生成一些毛皮。
            AddTranslation("Adds a rabbit and pelts to your hand.", "益汝手以一兔与诸革。");
            // 金矿镐
            AddTranslation("Pick Axe", "矿镐");
            // 敲击对方场上的所有卡牌并使它们变成金矿。
            AddTranslation("All my cards on the board are replaced with a gold nugget", "我局上诸牌皆易为金块。");
            // 自从我制作它的那天起，它就一直很锋利。
            AddTranslation("Still sharp since the day i crafted it", "自我铸之日，其锋未衰。");
            // 野兽相机
            AddTranslation("Camera", "影器");
            // 在场上复制一张你选择的卡牌，并将其添加到你的牌组中。
            AddTranslation("Take a picture of a card on the board and add it to your deck", "取局上一牌之影，而纳于汝牌列。");
            // 我的备用相机，请明智地使用。
            AddTranslation("My spare camera, use it wisely.", "我之副影器，善用之。");
            // 那造物的神秘力量把幸存者吓跑了。
            AddTranslation("The mystical power of that item scared the survivors away.", "彼物之玄力，惊走余生者。");
            // 愿你延续他们的传统
            AddTranslation("May you continue their legacy", "愿汝续其绪。");
        }

    }


    public class DinoMod
    {
        public static void RegisterTranslations()
        {
            // 钉头龙
            AddTranslation("Akainacephalus", "钉头龙");
            // 一只蛮横的野兽。其他造物对它外壳的首次攻击，它将完全无视。
            AddTranslation("A brutish beast. The first attacks to it's shell it will completely disregard.", "此兽悍。凡首攻其壳者，皆为其尽忽。");
            // 阿马加龙
            AddTranslation("Amalgasaur", "阿马加龙");
            // 不断变化的阿马加龙。它永远无法决定自己的真实属性。
            AddTranslation("The Ever-Changing amalgasaur. It can never decide on its true stats.", "阿马加龙，常变不居，终不能定其真数。");
            // 琥珀
            AddTranslation("Amber", "琥珀");
            // 一颗古老的琥珀…
            AddTranslation("An ancient amber..", "古琥珀也……");
            // 远古壁虎
            AddTranslation("Ancient Geck", "古壁虎");
            // 哇哦…拍拍手！
            AddTranslation("Wow.. CLap.CLap.Calp!", "噫……鼓掌！鼓掌！");
            // 小行星
            AddTranslation("Asteroid", "星石");
            // 一个完整的场地清理者，但要小心。使用一次后就会崩溃。
            AddTranslation("A full board clear, but be careful. It crashes after 1 use.", "可尽清一局，然宜慎之。一用而后毁。");
            // 破碎药瓶
            AddTranslation("Broken Vial", "破罂");
            // 哦，你弄碎了这个。
            AddTranslation("Oops. You bwoke it.", "噫，汝碎之矣。");
            // 雷龙
            AddTranslation("Brontosaurus", "雷龙");
            // 瘦长的雷龙。它的脖子伸得很高，可以捕捉到半空中的飞行生物。
            AddTranslation("The lanky Brontosaurus. It's neck streches so high up, it can catch airborne creatures in mid-air.", "雷龙脩长，其颈上伸甚高，能于空中攫翔物。");
            // 星陨之时
            AddTranslation("Asteroid Crashsite", "星陨之地");
            // 雷龙DJ手
            AddTranslation("DJ Bronto", "雷龙乐工");
            // 化石
            AddTranslation("Fossil", "化石");
            // 一块早已被遗忘的恐龙化石。它正在慢慢瓦解。
            AddTranslation("A dinosaur fossil long forgotten. It's slowly falling apart.", "久见遗忘之龙石，今徐徐离解。");
            // 冰封霸王龙
            AddTranslation("Frozen T-Rex", "冰封暴龙");
            // 它的身躯已然冰封。你可能会后悔释放它。
            AddTranslation("It's frozen. You may regret releasing it.", "其身已冰。汝释之，或将悔焉。");
            // 鬼灵恐龙
            AddTranslation("Ghost Dinosaur", "鬼龙");
            // 一个被困在凡间的鬼魂，永远在涉水。
            AddTranslation("A ghost, stuck in the mortal realm, forever wadnering.", "一鬼滞于尘世，永为游荡。");
            // 印度尼西亚龙
            AddTranslation("Indominus", "狂暴龙");
            // 长身雷龙
            AddTranslation("Long Bronto", "长雷龙");
            // 巨齿鲨
            AddTranslation("Megalodon", "巨齿鲨");
            // 即使是大白鲨，在面对这种恐怖造物时也会为之颤抖…
            AddTranslation("Even the great white shivers when confronted by this horror..", "虽大白鲨，见此怖物亦栗……");
            // 独爪龙
            AddTranslation("Mononykus", "独爪龙");
            // 多奇怪的生物啊……
            AddTranslation("What a weird looking creature..", "此物貌何异也……");
            // 鳞翅目
            AddTranslation("Lepidoptera", "鳞翅");
            // 一只虚弱的飞蛾。也许你能找到一种方法来给予它力量？
            AddTranslation("A feeble moth. Maybe you can find a way to power it up?", "一弱蛾耳。汝或能求其所以益之乎？");
            // 雷龙脖子
            AddTranslation("Bronto Neck", "雷龙颈");
            // 昆虫脖子
            AddTranslation("Insect Neck", "虫颈");
            // 羽毛脖子
            AddTranslation("Feathered Neck", "羽颈");
            // 毛茸茸的脖子
            AddTranslation("Furry Neck", "毛颈");
            // 鳞状脖子
            AddTranslation("Scaly Neck", "鳞颈");
            // 脖子
            AddTranslation("Neck", "颈");
            // 幻龙
            AddTranslation("Notosaurus", "幻龙");
            // 这幻龙，是一种巨大的潜水猛兽。
            AddTranslation("The Notosaurus, a giant swimming beast.", "幻龙者，巨而善游之兽也。");
            // 副栉龙
            AddTranslation("Parasaurolophus", "副栉龙");
            // 副栉龙。这头野兽召唤盟友帮助自卫。
            AddTranslation("The Parasaurolophus. This beast calls its allies to help defend itself.", "副栉龙，能呼其侣以卫己。");
            // 翼龙
            AddTranslation("Pterodactyl", "翼龙");
            // 翼龙，一种可怕的飞行野兽。它以最高的速度俯冲下来捕食猎物。
            AddTranslation("The Pterodactyl, a fearsome flying beast. It swoops down on its prey with maximum efficiency.", "翼龙，怖人之翔兽也。其下搏猎物，捷甚。");
            // 迅猛幼龙
            AddTranslation("Raptor Hatchling", "迅猛幼龙");
            // 一只虚弱的恐龙幼崽。一定要保护它。
            AddTranslation("A weak dinosaur hatchling. Make sure to protect it.", "一弱龙雏也，宜善护之。");
            // 罗克斯
            AddTranslation("Rox", "罗克斯");
            // 多么奇特的生物啊……
            AddTranslation("What a curious creature..", "此物何其奇也……");
            // 不死迅猛龙
            AddTranslation("Undead Raptor", "不死迅猛龙");
            // 不死迅猛龙。它设法活了下来，但只活了一段时间。
            AddTranslation("The Undead Velociraptor. It manages to stay alive, but only for a while.", "不死迅猛龙，虽得苟活，然不能久。");
            // 利齿迅猛龙
            AddTranslation("Spiked Raptor", "棘迅猛龙");
            // 棘龙
            AddTranslation("Spinosaurus", "棘龙");
            // 棘龙。这种野兽在水中和陆地上都很敏捷。
            AddTranslation("The Spinosaurus. This beast is agile in water, and on land.", "棘龙于水陆皆捷。");
            // 神秘的蛋
            AddTranslation("Mysterious Egg", "玄卵");
            // 我其实不知道里面有什么…
            AddTranslation("I don't actually know whats in it..", "我实不知其中何有……");
            // 泰茜
            AddTranslation("Tessie", "泰茜");
            // 一种来自冰冻荒地的生物…
            AddTranslation("A creature originating from a frozen wasteland..", "一物出于冰荒……");
            // 霸王龙
            AddTranslation("T-rex", "暴龙");
            // 三角龙
            AddTranslation("Triceratops", "三角龙");
            // 强大的三角龙。它在1次命中后从防守转向进攻。
            AddTranslation("The mighty Triceratops. It turns from defense, to offense after 1 hit.", "三角龙强，一受击则由守转攻。");
            // 伶盗龙
            AddTranslation("Velociraptor", "伶盗龙");
            // 伶盗龙，一种飞行敏捷的野兽。
            AddTranslation("The Velociraptor, a flighty, agile beast.", "伶盗龙，轻躁而捷之兽也。");
            // 奇怪的药瓶
            AddTranslation("Strange Vial", "异罂");
            // 一种邪恶的液体。在适当的条件下，它可以进化成可怕的野兽。
            AddTranslation("A demonic fluid in a vile. Under the right conditions it can evolve into a horryfying beast.", "罂中有妖液，得其宜则化为怖兽。");
            // 呼朋引伴
            AddTranslation("Call Allies", "呼朋");
            // 当[creature]被打出时，它将在相邻空位复制两个与其相同的造物。
            AddTranslation("When a card bearing this sigil is played, it will summon allies adjacent of where the card is placed.", "负此印契之牌既陈，则其旁相邻之位召其侣。");
            // 恐龙模组卡包
            AddTranslation("Dino-Mod Card Pack", "恐龙牌韬");
            // 将愚蠢的恐龙和史前野兽添加到游戏中！
            AddTranslation("Adds silly dinos and prehistoric beasts to the game!", "益以群龙与史前诸兽于戏中！");
            // 未知孵化
            AddTranslation("Unknown Hatchling", "未知雏");
            // 在回合结束时，[creature]有机会孵化成随机的恐龙。
            AddTranslation("At the end of the turn, a card bearing this sigil has a chance to hatch into a random Dinosaur.", "合终，负此印契之牌或孚为一偶龙。");
            // 摇摇欲坠
            AddTranslation("Crumbling", "崩朽");
            // 在回合结束时，[creature]将产生1根骨头，但将失去1点生命值。
            AddTranslation("At the end of the turn, a card bearing this sigil will create 1 bone, but will lose 1 health.", "合终，负此印契之牌生一骨，而失一命。");
            // 恐吓咆哮
            AddTranslation("Roar of Terror", "恐吼");
            // 与[creature]对抗的造物力量将被设置为1。
            AddTranslation("The creature opposing the bearer of this sigil will have its damage set to 1.", "与负此印契者相对之物，其威定为一。");
            // 伸展运动
            AddTranslation("Stretching", "伸颈");
            // 持牌人的回合结束时，[creature]会按印记标注的方向移动，并伸展它的脖子。
            AddTranslation("At the end of the turn, a card bearing this sigil will move, and stretch it's neck.", "合终，负此印契之牌将移，而伸其颈。");
            // 实验药瓶
            AddTranslation("Experimental Vial", "试罂");
            // 当[creature]死亡时，它将变成怪物。
            AddTranslation("When a card bearing this sigil dies, it will transform into a monster.", "负此印契之牌死，则化为怪。");
            // 恐龙模组
            AddTranslation("DinoMod", "恐龙补缀");
        }

    }


