    public class SmallTweakBorneMod
    {
        public static void RegisterTranslations()
        {
            // [creature]带有该印记的卡牌将直接攻击一名敌人，即使其对面有其他造物也无妨，除非该造物也有此印记。
            AddTranslation("[creature] will strike an opponent directly, even if there is a creature opposing it, unless the creature has this sigil.", "[creature]虽有物当之，亦直击敌主；彼物若亦负此印契，则否。");
            // [creature]在对手的回合潜入水下，其潜水时，敌对造物会直接攻击其主人，除非该造物也有此印记。
            AddTranslation("[creature] submerges itself during its opponent's turn. While submerged, opposing creatures attack its owner directly, unless that creature has this sigil.", "[creature]于敌合自潜。其既潜，则敌物直击其主；彼物若亦负此印契，则否。");
        }

    }


    public class TooManySigilsMod
    {
        public static void RegisterTranslations()
        {
            // 蚂蚁减法
            AddTranslation("Ants Minus", "减蚁");
            // 此印记代表的数值等于场上蚂蚁的数量，减去这张牌。
            AddTranslation("This cards power is equal to the amount of Ant's on field, minus this one.", "此牌之威，如局上蚁数，减此一牌。");
            // 当[creature]受到伤害时，它通常只受到原来一半的伤害。
            AddTranslation("When this card is damaged, It takes half the Damage it would normally.", "此牌受伤，则所受减其半。");
            // 钟压机
            AddTranslation("Bell Presser", "击钟");
            // 此印记代表的数值等于铃铛被敲响的次数。
            AddTranslation("This cards power is equal to the amount of times the bell has been rung.", "此牌之威，如钟既鸣之数。");
            // 借来的时间
            AddTranslation("Borrowed Time", "假时");
            // 带有该印记的卡牌如果及时阵亡，它冰封禁锢的造物将被召唤；否则下回合开始时（幼雏印记触发的时间），其将召唤一个损坏的版本。
            AddTranslation("When this card perishes its Icecube is summoned if done in time, or else if over the EvolveTurns a corrupt version will be summoned.", "此牌死而时未后，则其冰块所藏之物见召；若过孚时，则召其坏体。");
            // 内心之币
            AddTranslation("Coins Within", "藏箔");
            // 当带有该印记的卡牌被击中时，只要它仍存活，其就会为持牌人提供1枚货币。
            AddTranslation("When this card is struck it provides 1 foil to its owner, as long as it lives anyway.", "此牌见击而不死，则予其主一箔。");
            // 修养
            AddTranslation("Covalesce", "养");
            // 带有该印记的卡牌如果在你的回合结束时仍然存活，则该牌获得1点生命值。
            AddTranslation("If a card bearing this sigil is alive during your endstep, This card gains 1 health.", "负此印契之牌若至汝合终尚生，则得一命。");
            // 死亡包裹
            AddTranslation("Dead Pack", "死馈");
            // 当带有该印记的卡牌阵亡时，它会向其所有者提供1个物品道具。
            AddTranslation("When a card bearing this sigil perishes, it provides 1 Item to its owner.", "负此印契之牌死，则予其主一物。");
            // 如鱼离水
            AddTranslation("Fish Out Of Water", "离水鱼");
            // 回合结束时，带有该印记的卡牌状态会从空袭和水袭之间互相切换，依此类推。如果两者都不存在，则将从水袭状态开始。
            AddTranslation("At the end of the turn, this card switches from having Airborne to Waterborne and so on. If neither are present will start with Waterborne.", "合终，此牌于空袭与潜间更相易之。若二者俱无，则始于潜。");
            // 获得一节电池
            AddTranslation("Gain One Battery", "得一电匣");
            // 当带有该印记的卡牌被打出时，持牌人获得1点最大能量。
            AddTranslation("When a card bearing this sigil is played, the owner gains one Max Energy.", "负此印契之牌既陈，则其主得一能极。");
            // 获得两节电池
            AddTranslation("Gain Two Batteries", "得二电匣");
            // 当带有该印记的卡牌被打出时，持牌人获得2点最大能量。
            AddTranslation("When a card bearing this sigil is played, the owner gains two Max Energy.", "负此印契之牌既陈，则其主得二能极。");
            // 获得三节电池
            AddTranslation("Gain Three Batteries", "得三电匣");
            // 当带有该印记的卡牌被打出时，持牌人获得3点最大能量。
            AddTranslation("When a card bearing this sigil is played, the owner gains three Max Energy.", "负此印契之牌既陈，则其主得三能极。");
            // 获得四节电池
            AddTranslation("Gain Four Batteries", "得四电匣");
            // 当带有该印记的卡牌被打出时，持牌人获得4点最大能量。
            AddTranslation("When a card bearing this sigil is played, the owner gains four Max Energy.", "负此印契之牌既陈，则其主得四能极。");
            // 获得五节电池
            AddTranslation("Gain Five Batteries", "得五电匣");
            // 当带有该印记的卡牌被打出时，持牌人获得5点最大能量。
            AddTranslation("When a card bearing this sigil is played, the owner gains five Max Energy.", "负此印契之牌既陈，则其主得五能极。");
            // 获得六节电池
            AddTranslation("Gain Six Batteries", "得六电匣");
            // 当带有该印记的卡牌被打出时，持牌人获得6点最大能量。
            AddTranslation("When a card bearing this sigil is played, the owner gains six Max Energy.", "负此印契之牌既陈，则其主得六能极。");
            // 心锁
            AddTranslation("Heart Locked", "心锁");
            // 当带有该印记的卡牌受到伤害时，其只会受到1点伤害。
            AddTranslation("When a card bearing this sigil is damaged, It only takes 1 Damage.", "负此印契之牌受伤，则止受一伤。");
            // 当带有该印记的卡牌受伤时，你手中会获得一张卡牌。
            AddTranslation("When a card bearing this sigil is damaged, a card is added to your hand.", "负此印契之牌受伤，则汝手得一牌。");
            // 带有该印记的卡牌若在你的回合结束时仍在场上，则你一侧的随机空位会生成一张卡牌。
            AddTranslation("If a card bearing this sigil is on the field during your endstep, a card is launched to one of your empty spaces.", "负此印契之牌若至汝合终在场，则汝侧一空位生一牌。");
            // 失去一节电池
            AddTranslation("Lose One Battery", "失一电匣");
            // 当带有该印记的卡牌被打出时，持牌人失去1点最大能量。
            AddTranslation("When a card bearing this sigil is played, the owner loses one Max Energy.", "负此印契之牌既陈，则其主失一能极。");
            // 失去两节电池
            AddTranslation("Lose Two Batteries", "失二电匣");
            // 当带有该印记的卡牌被打出时，持牌人失去2点最大能量。
            AddTranslation("When a card bearing this sigil is played, the owner loses two Max Energy.", "负此印契之牌既陈，则其主失二能极。");
            // 失去三节电池
            AddTranslation("Lose Three Batteries", "失三电匣");
            // 当带有该印记的卡牌被打出时，持牌人失去3点最大能量。
            AddTranslation("When a card bearing this sigil is played, the owner loses three Max Energy.", "负此印契之牌既陈，则其主失三能极。");
            // 失去四节电池
            AddTranslation("Lose Four Batteries", "失四电匣");
            // 当带有该印记的卡牌被打出时，持牌人失去4点最大能量。
            AddTranslation("When a card bearing this sigil is played, the owner loses four Max Energy.", "负此印契之牌既陈，则其主失四能极。");
            // 失去五节电池
            AddTranslation("Lose Five Batteries", "失五电匣");
            // 当带有该印记的卡牌被打出时，持牌人失去5点最大能量。
            AddTranslation("When a card bearing this sigil is played, the owner loses five Max Energy.", "负此印契之牌既陈，则其主失五能极。");
            // 失去六节电池
            AddTranslation("Lose Six Batteries", "失六电匣");
            // 当带有该印记的卡牌被打出时，持牌人失去6点最大能量。
            AddTranslation("When a card bearing this sigil is played, the owner loses six Max Energy.", "负此印契之牌既陈，则其主失六能极。");
            // 概率死触
            AddTranslation("One Fourth Chance Instakill", "四分一死触");
            // 当带有该印记的卡牌受到攻击时，攻击者有四分之一的几率阵亡。
            AddTranslation("When this card would be attacked, there is a 25% chance that the striker perishes.", "此牌将受攻时，攻者四分之一而死。");
            // 腐烂
            AddTranslation("Rotting", "朽");
            // 持牌人的回合结束时，若带有该印记的卡牌仍然存活在场，其会失去1点力量和1点生命值。
            AddTranslation("If a card bearing this sigil is alive during your endstep, this card loses 1 power and 1 health.", "负此印契之牌若至汝合终尚生，则失一威一命。");
            // 在持牌人的回合结束时，带有该印记的卡牌将按照印记标注的方向移动，并在其原来的位置创造另一个造物。
            AddTranslation("If a card bearing this sigil is on field during your endstep, this card moves in the direction inscribed in the sigil, and a card is played in its previous space.", "负此印契之牌若至汝合终在场，则循印所书之向而移，且其故处生一物。");
            // 当带有该印记的卡牌受到伤害时，其会少受1点伤害。
            AddTranslation("When a card bearing this sigil is damaged, It takes 1 less Damage.", "负此印契之牌受伤，则所受少一。");
            // 寻宝者
            AddTranslation("Treasure Tracker", "寻宝");
            // 在持牌人的回合结束时，带有该印记的卡牌将为持牌人提供1枚货币。
            AddTranslation("At The end of the Owners turn, this card will provide the owner with 1 foil.", "持者合终，此牌予其主一箔。");
        }

    }


    public class PizzaTowerCardsMod
    {
