            AddTranslation("Flying Anchovi", "飞鳀");
            // 一只会飞的鱼，真可笑。
            AddTranslation("A flying fish, how ridiculous.", "一飞鱼耳，诚可哂也。");
            // 坏老鼠
            AddTranslation("Bad Rat", "恶鼠");
            // 一只坏老鼠。不，不是那种。
            AddTranslation("A bad rat. No, not that kind.", "一恶鼠也。否，非彼种也。");
            // 匪徒鸡
            AddTranslation("Bandit Chicken", "寇鸡");
            // 速度快，和酱汁很配。
            AddTranslation("Speedy and goes well with sauce.", "捷，而宜佐酱。");
            // 披萨盒哥布林
