            // 奶酪怪
            AddTranslation("Cheese Monster", "酪怪");
            // 担架。
            AddTranslation("The Stretcher.", "牵伸者。");
            // 蘑菇怪
            AddTranslation("Mushroom Monster", "蕈怪");
            // 别出声。
            AddTranslation("Don't Make a Sound.", "毋作声。");
            // 菠萝怪
            AddTranslation("Pineapple Monster", "菠怪");
            // 香肠怪
            AddTranslation("Sausage Monster", "肠怪");
            // 番茄怪
            AddTranslation("Tomato Monster", "茄怪");
            // 斯蒂克先生
            AddTranslation("Mr. Stick", "斯蒂克");
            // 一个发明家和一个推销员，这两个特征意味着贪婪
            AddTranslation("An inventor and a salesman, two traits that spell greed", "为匠又为贾，此二端足征其贪。");
            // 噪音
            AddTranslation("The Noise", "噪君");
            // 一阵令人难以忍受的噪音，尽管他确实有诡计
