            AddTranslation("Noise Bomb", "噪爆");
            // 危险，但可能有用。
            AddTranslation("Dangerous, but can be useful.", "虽危，亦或可用。");
            // 噪音榛子
            AddTranslation("Noisette", "诺伊塞特");
            // 噪音的女友也经营着一家咖啡馆
            AddTranslation("The girlfriend of The Noise, also runs a cafe", "噪君之侣，亦营一啜馆。");
            // 嘈杂
            AddTranslation("Noisey", "噪徒");
            // 不能攻击，但可以当墙用。
            AddTranslation("Can't attack, but can be used as a wall.", "不能攻，然可为垣。");
            // 橄榄骑兵
            AddTranslation("Olive Trooper", "橄榄兵");
            // 外来入侵物种。
            AddTranslation("An invasive, alien species.", "外来侵物也。");
            // 剑客潘瑟
            AddTranslation("Pencer", "剑客潘瑟");
            // 试图表现得高尚，但实际上只是个懦夫。
            AddTranslation("Tries to act noble, but is really just a coward.", "自矜高贵，实乃懦夫耳。");
            // 辣肠哥布林
            AddTranslation("Pepperoni Goblin", "辣肠哥布林");
            // 令人烦恼。
            AddTranslation("An annoyance.", "令人烦扰之物。");
            // 辣肠哥布林蝙蝠
            AddTranslation("Pepperoni Goblin Bat", "辣肠哥布林蝙蝠");
            // 很烦人，但现在它会飞了。
            AddTranslation("An annoyance, but now it flys.", "令人烦扰，今能飞矣。");
            // 甜椒人
            AddTranslation("Pepperman", "甜椒人");
            // 一个艺术家和自恋者，但很坚强
            AddTranslation("An artist and a narcissist, but strong", "艺术家兼自恋者，然强健有力。");
            // 佩皮机器人
            AddTranslation("Peppibot", "佩皮机人");
            // 一个偏执厨师的机器人复制品。
            AddTranslation("A robotic replication of a paranoid chef.", "一偏执厨师之机人摹器。");
            // 佩皮诺
            AddTranslation("Peppino", "佩皮诺");
            // 偏执狂，随时准备把任何东西砸到地上
            AddTranslation("Paranoid and ready to pound anything into the ground", "偏执多疑，随时欲将万物击入地下。");
            // 佩皮诺克隆体
            AddTranslation("Peppino Clone", "佩皮诺摹器");
            // 一个偏执厨师的不完美复制品。
            AddTranslation("An imperfect clone of a paranoid chef.", "一偏执厨师之不完善摹器。");
            // 大柱子约翰
            AddTranslation("Pillar John", "大柱子约翰");
            // 结构完整性很重要，这个非常乐意提供
            AddTranslation("Structural integrity is important, and this one is more than happy to supply", "结构之完整至为紧要，而此物乐于供之。");
            // 酷菠萝
            AddTranslation("Pineacool", "酷菠萝");
            // 这是一个很酷的客户。
            AddTranslation("That's one cool customer.", "此颇为酷炫之货色。");
            // 披萨脸
            AddTranslation("Pizza Face", "披萨脸");
            // 披萨塔的统治者，强大而迅捷
            AddTranslation("The ruler of the Pizza Tower, powerful and fast", "披萨塔之主，强大而迅捷。");
            // 比萨塔的统治者，强大而保守秘密。如果它能进化的话
            AddTranslation("The ruler of the Pizza Tower, powerful and holding a secret if it can evolve", "披萨塔之主也，强而怀秘；若其得孚，则然。");
            // 破碎披萨脸
            AddTranslation("Broken Pizza Face", "残披萨脸");
            // 披萨塔的破碎统治者
            AddTranslation("The broken ruler of the Pizza Tower", "披萨塔之残主。");
            // 齿轮
            AddTranslation("Gear", "机轮");
            // 披萨头
            AddTranslation("Pizza Head", "披萨头");
            // 披萨塔的统治者，强大而...愚蠢
            AddTranslation("The ruler of the Pizza Tower, powerful and... goofy", "披萨塔之主也，强而……愚。");
            // 披萨塔的统治者，强大、愚蠢、愤怒
            AddTranslation("The ruler of the Pizza Tower, powerful, goofy, and angry", "披萨塔之主也，强、愚而怒。");
            // 披萨法师
            AddTranslation("Pizzard", "披萨巫");
            // 一个神秘的巫师...我拿错牌了吗？
            AddTranslation("A mystical wizard... did I grab the wrong deck?", "一玄巫也……我其取错牌列乎？");
            // 披萨蛞蝓
            AddTranslation("Pizza Slug", "披萨蛞蝓");
            // 一个来自猪城的脾气暴躁的吸食者。
            AddTranslation("A cranky smoker from the Pig City.", "一出于豕城而性躁之烟徒也。");
            // 披萨兵
            AddTranslation("Pizza Soldier", "披萨兵");
            // 准备打仗的应征入伍者。
            AddTranslation("A conscript, ready for war.", "一征卒，备战者也。");
            // 冻披萨
            AddTranslation("Pizzice", "冻披萨");
            // 冰封的披萨。
            AddTranslation("Frozen pizza.", "冰披萨也。");
            // 牧场射手
            AddTranslation("Ranch Shooter", "庄射手");
            // 容易受惊，容易触发。
            AddTranslation("Easily spooked and trigger happy.", "易惊而轻发。");
            // 刺尼克
            AddTranslation("Snick", "斯尼克");
            // 一只失业的豪猪正在举办游戏博览会
            AddTranslation("An out of work porcupine running a game expo", "一失业之豪猪，而主游戏之会。");
            // 邪刺尼克
            AddTranslation("Snick.EXE", "邪斯尼克");
            // 嗯……奇怪。我不记得了。
            AddTranslation("Hmm... odd. I don't remember that one.", "嗯……异哉。我不忆此物。");
            // 雪人
            AddTranslation("Snowman", "雪人");
            // 不能攻击，但它的鼻子远非无害的胡萝卜。
            AddTranslation("Can't attack, but it's nose is far from a harmless carrot.", "不能攻，然其鼻绝非无害之胡芦菔。");
            // 塔品豆
            AddTranslation("Toppins", "塔品豆");
            // 可爱又美味
            AddTranslation("Adorable and delicious", "可爱而甘美。");
            // 宝箱男
            AddTranslation("Treasure Chest Guy", "宝匮翁");
            // 不会攻击，但可以提供一些有用的资源。
            AddTranslation("Won't attack, but can provide some useful resources.", "不能攻，然可供有用之资。");
            // 幽浮橄榄怪
            AddTranslation("UFOlive", "飞盘橄榄怪");
            // 治安猎手
            AddTranslation("Vigilante", "义巡者");
            // 为正义而战的奶酪泥
            AddTranslation("A cheese slime fighting for justice", "为义而斗之酪泥。");
            // 雪茄肠哥
            AddTranslation("Weenie", "肠仔");
            // 小香肠。
            AddTranslation("Weenie.", "小肠也。");
        }

    }


    public class InGameCardCreatorMod
    {
        public static void RegisterTranslations()
        {
            // 您已进入[c:bR]卡牌创建[c:]模式。
            AddTranslation("You entered the [c:bR]card creation[c:] mode.", "汝既入[c:bR]造牌[c:]之式。");
            // 看来你正常落败了。
            AddTranslation("It appears that you lost normally.", "观汝所败，常也。");
            // 只有有价值的挑战者才能访问卡牌创建器。
            AddTranslation("Only worthy challengers may access the Card Creator.", "惟可取之角者，乃得入造牌器。");
            // 再试一次，但这次记得要正常打开密室门。
            AddTranslation("Try again, but this time open the backroom door normally.", "更试之，此番当以常法启后室之门。");
            // 当前卡牌
            AddTranslation("current card", "今牌");
            // 你应该赐予其一个名字。
            AddTranslation("You should give it a name.", "宜名之。");
            // 请输入对其的描述。
            AddTranslation("Please type the description.", "请书其叙。");
            // 是时候让你回去了。
            AddTranslation("It is time for you to return.", "汝当归矣。");
            // 正在加载卡面图片。
            AddTranslation("Loading portraits.", "方载牌像。");
            // 上一页
            AddTranslation("previous page", "前页");
            // 下一页
            AddTranslation("next page", "后页");
            // 然后是另一项。这次我将写入它的[c:bR]力量[c:]。
            AddTranslation("And another. This time I will use its [c:bR]power[c:].", "复有一项，此番我将取其[c:bR]威[c:]。");
            // 选择卡牌的[c:bR]复杂程度[c:]。这将决定它在教程中何时解锁。
            AddTranslation("Choose the [c:bR]complexity[c:] of card. This determines when it is unlocked in the tutorial.", "择牌之[c:bR]繁简[c:]。此定其于教次中何时而解。");
            // 免费
            AddTranslation("free", "无费");
            // 请从中选择一张卡牌来抽取[c:bR]成本[c:]。
            AddTranslation("Please, choose a card to draw the [c:bR]cost[c:] from.", "请择一牌，以取其[c:bR]费[c:]。");
            // 你想添加另一种[c:bR]成本[c:]吗？
            AddTranslation("Do you want to add another [c:bR]cost[c:]?", "汝欲更益一[c:bR]费[c:]乎？");
            // 选择它将成长为哪张卡牌。
            AddTranslation("Choose which card it will evolve into.", "择其所将孚为何牌。");
            // 选择其死亡后将生成哪张卡牌。
            AddTranslation("Choose which card it will create upon death.", "择其死后所生为何牌。");
            // 这张牌需要[c:bR]多少回合[c:]才能成长？
            AddTranslation("[c:bR]How many turns[c:] should it take for this card to evolve?", "此牌须[c:bR]几合[c:]而孚？");
            // 然后是另一项。这次我将写入它的[c:bR]生命[c:]。
            AddTranslation("And another. This time I will use its [c:bR]health[c:].", "复有一项，此番我将取其[c:bR]命[c:]。");
            // 常规
            AddTranslation("regular", "常");
            // 稀有
