    public class AgasMagnificusExpansionMod
    {
        public static void RegisterTranslations()
        {

            // Pack
            // Aga的蔓尼菲科模组扩展
            AddTranslation("Aga's Magnificus Expansion", "Aga氏蔓尼菲科扩篇");
            // 蔓尼菲科模组的非官方扩展，拥有[count]位独特而丰富多彩的法师
            AddTranslation("An unofficial expansion to the Magnificus Mod featuring [count] unique and colourful mages", "蔓尼菲科补缀之外扩，载[count]异而绚之术士。");

            // Card
            // 飞升法师
            AddTranslation("Ascension Mage", "升举术士");
            // 他们利用时间的力量，传授远远超出他们的知识和经验。
            AddTranslation("Utilising the power of time they grant knowledge and experience from far beyond", "假时之力，以授远逾寻常之知与历。");
            // 灰烬法师
            AddTranslation("Ash Mage", "灰术士");
            // 他从自己身上剥落灰烬，灼烧所有反对他的人。
            AddTranslation("Ashes he sheds from his own body, scorching any and all who oppose him", "其自体落灰，凡逆己者皆灼之。");
            // 破碎的蛋
            AddTranslation("Broken Egg", "残卵");
            // 只有最伟大的训练师才能找到这个宝藏。
            AddTranslation("Only the greatest of trainers might find this treasure", "惟至善之训者，乃或得此宝。");
            // 天选之子
            AddTranslation("Chosen One", "天简之子");
            // 我选择的最爱的存在。尽管如此，他仍然依恋他的长辈...
            AddTranslation("My selected favourite. He still clings to his elders though...", "我所简而最爱者也。虽然，犹恋其长上……");
            // 清洁法师
            AddTranslation("Cleanliness Mage", "洁术士");
            // 我所有学生中最自豪的。没有人能比得上他的洗澡超能力。
            AddTranslation("The proudest of all my pupils. None come close to his bath superpowers", "我诸徒中最可矜者也。其浴之异能，无有近之。");
            // 牧师
            AddTranslation("Cleric", "司祭");
            // 凭借他的神圣魔法，他承受了所有人的痛苦，并消除了他们的伤痕。
            AddTranslation("With the virtue of his divine Magicks, he bears the pain of all and rids them of their wounds", "以其神术之德，负众痛而蠲其创。");
            // 时钟法师
            AddTranslation("Clock Mage", "钟术士");
            // 一个精通时间的巫师。当他接近死亡时，他会回到过去，重获新生。
            AddTranslation("A wizard with a mastery over time itself. When he nears his demise, he reverts to the past, and comes back to life", "一精于时之巫也。将死，则返于既往而更生。");
            // 造物收藏家
            AddTranslation("Creature Collector", "藏物者");
            // 你看，他四处寻找他的小伙伴。
            AddTranslation("He had searched far and wide for his little companion, you see", "子视之，彼尝周求其小侣。");
            // 分裂法师
            AddTranslation("Division Mage", "分术士");
            // 至少卡牌上这么说...我以为那些怪胎已经交往很久了。
            AddTranslation("So the card says at least... I assumed those freaks were long dealth with", "牌虽如是云……我意彼诸怪胎久已处置矣。");
            // 蛋
            AddTranslation("Egg", "卵");
            // 只有最伟大的训练师才能找到这个宝藏。
            AddTranslation("Only the greatest of trainers might find this treasure", "惟至善之训者，乃或得此宝。");
            // 德鲁伊
            AddTranslation("Druid", "德鲁伊");
            // 大自然的原始奉献者，以消耗的法力为食来治愈他的盟友。
            AddTranslation("Nature's primal devotee, feeding on sapped mana to cure his allies", "自然之初徒也，食所汲之法力，以疗其侣。");
            // 附魔师
            AddTranslation("Enchanter", "附咒者");
            // 他临死时喷出宇宙魔法，让附近的一切都附上魔力。
            AddTranslation("He spews cosmic magicks upon his demise, enchanting everything nearby", "将死，则喷宇宙之术，使近者尽受其咒。");
            // 全能法师
            AddTranslation("EveryMage", "全术士");
            // 法师
            AddTranslation("mage", "术士");
            // 塑能师
            AddTranslation("Evoker", "召能者");
            // 令人厌恶的教义的不祥秘密。可归纳之蛇是最致命的。
            AddTranslation("The ominous crettin of disgusting teachings. It's summonable snakes are of the deadliest caliber", "其学可憎，而人亦不祥。其所召之蛇，毒最烈。");
            // 蛇之召
            AddTranslation("Serpent Summon", "召蛇");
            // 纵火狂
            AddTranslation("Firebender", "御火者");
            // 在战斗最激烈的时候，他总是在寻找下一个火球的受害者。
            AddTranslation("Chipper in the heat of battle, he is always on the hunt for the next victim of his fireballs", "战酣之际，其恒索火丸之次受者。");
            // 前瞻法师
            AddTranslation("Foresight Mage", "先见术士");
            // 当他凝视着你的未来，他永远预言着可能会到来的攻击。
            AddTranslation("As he gazes upon your future, attacks that may come his way he forever predicts", "其视汝后日，则凡或临己之攻，皆先知之。");
            // 前瞻法师
            AddTranslation("Foresight Mage", "先见术士");
            // 展望未来，他可能会看到任何敢于接近的人。
            AddTranslation("Gazing into the future, he may see any body who dares make an approach", "瞻后日，则凡敢近者，或皆为其所见。");
            // 冰川
            AddTranslation("Glacier", "冰川");
            // 饿者骷髅
            AddTranslation("Gashadokuro", "馁骨");
            // 宝石哨兵
            AddTranslation("Gem Sentinel", "玉哨");
            // 被我的玛珂光辉迷住的精英战士部队。
            AddTranslation("the elite warrior unit enchanted with the aura of my moxen", "受我玛珂之辉所咒之锐士。");
            // 研星者
            AddTranslation("Grand Astrologer", "大占星者");
            // 战场永远是他的游乐场，太空是他的武器。一切在他面前都是光秃秃的。
            AddTranslation("The battlefield is forever his playground, and space is his weapon. All is bare before him.", "战场常为其戏地，空宇为其兵。一切于前，无所匿也。");
            // 重力法师
            AddTranslation("Gravity Mage", "重术士");
            // 重力的大师。任何人都会屈从于他坚定不移的意志。
            AddTranslation("A master of the forces of gravity. Any and all mox bend to his unwavering will", "重力之师也。凡玛珂皆屈其不贰之志。");
            // 幻术师
            AddTranslation("Illusion Mage", "幻术士");
            // 乍一看，他的诡计和伪装，没有比这更可怕的了。
            AddTranslation("Dawning his tricks and disguises, there is none scarier. At first glance", "其机诈与伪饰，初视之无有加怖者。");
            // 感染法师
            AddTranslation("Infestation Mage", "染术士");
            // 我想像你这样的篡位挑战者可以忍受一定量的变身邪术。
            AddTranslation("I suppose a usurping challenger such as yourself could endulge in a dosage of skinwalking", "若汝此篡位之角者，亦当堪受些许易形邪术。");
            // 侮辱魔镜
            AddTranslation("Insulting Mirror", "辱镜");
            // 魔法的威胁在所有谈吐中嘲讽和粗鲁的评论中飞舞；你越愤怒，它越将转化为自己的力量。
            AddTranslation("The Magick Menace Flies About All Spitting Taunts And Hurling Cheeky Comments, Your Anger, It Channels Into A Strength Of It's Own", "此魔患飞扬，吐侮掷讥；汝怒愈甚，则其威愈归于己。");
            // 铁处女
            AddTranslation("Iron Maiden", "铁闺");
            // 我最优秀的圣骑士们工作时间最长。没有人能穿过他的长城。
            AddTranslation("My finest of paladins working the finest of hours. No soul goes through his grand wall", "我诸圣骑中最良者也。无一魂得逾其巨垣。");
            // 玛珂戮魔
            AddTranslation("Kickmoxer", "斗玛珂者");
            // 他毕生致力于战斗艺术，并可能适应他所面对的任何人。
            AddTranslation("He dedicated his life to the art of combat, and may adapt to whomever he faces", "其终身尽于斗艺，所向之敌，皆或随而应之。");
            // 万人冢
            AddTranslation("Mass Grave", "众冢");
            // 阿盖兰大师
            AddTranslation("Master Agairan", "阿盖兰大师");
            // 深红奇美拉。炼金术老师灌输最致命的毒素。
            AddTranslation("The Crimson Chimera. The teacher of alchemy instills the deadliest of toxins", "绛奇兽也。彼炼金之师，灌以至毒。");
            // 双蓝大师
            AddTranslation("Master Bluetwo", "双蓝大师");
            // 蓝宝石的钢铁骑士。即使死后，她的精神存在也指挥着我们的敌人。
            AddTranslation("The steel knight of sapphire. Even after death her psychic presence commands our foes", "蓝玉之钢骑也。身虽死，其神犹役我敌。");
            // 道布林大师
            AddTranslation("Master Doublin", "道布林大师");
            // 骨王的救世主。祈祷的老师学会了如何窃取精华。
            AddTranslation("The Bone Lord's messiah. The teacher of prayer has learned apt essence stealing.", "骨王之救者也。彼祷师已习善窃精髓。");
            // 超级巫师
            AddTranslation("Megawizard", "巨巫");
            // 他装腔作势，意味着他昏昏沉沉。这种原始力量永远不会持久。
            AddTranslation("Hulking he is in his menace, meanacing he is in his dim. Such raw power would never last an eternity", "其势硕而骇，其神昏而悍。如此朴力，终不能久。");
            // 气象学者
            AddTranslation("Meteorologist", "象天者");
            // 他们仔细观察宇宙，向他们认为合适的人投掷流星风暴。也许他们很残忍？也许不是？只有他们自己知道。
            AddTranslation("They carefully observe the universe, casting storms of meteors upon whom they see fit. Maybe they're cruel? Maybe not? Only they know", "彼审观宇宙，而陨星如雨，投其所可投者。其残忍乎？其不然乎？惟彼自知。");
            // 迷你巫师
            AddTranslation("Miniwizard", "小巫");
            // 一个被它的微小尺寸所诅咒的法师。不过不用担心，他找到了解决办法。
            AddTranslation("A mage accursed by it's miniscule size. Worry not though, to such ends he found a solution.", "一术士为其微形所厄。然毋忧，彼已得其解。");
            // 幻灵盗贼
            AddTranslation("Phantom Thief", "幻盗");
            // 滚滚罪孽乌云，进进出出，偷窃它之宿敌。
            AddTranslation("A billowing cloud of crime, darting in and out, and stealing his foes", "罪云翻涌，出入倏忽，而窃其敌。");
            // 序言法师
            AddTranslation("Preformence Mage", "前演术士");
            // 谁知道他的神秘兔子到底经历了什么。
            AddTranslation("Who knows to what ends his mystery rabbit has been through", "孰知其玄兔所历至于何极。");
            // 皇后使魔
            AddTranslation("Queen's Familiar", "后之使魔");
            // 美丽野兽的雄伟幻影。它其中关着一支军队。
            AddTranslation("A majestic chimera of beautiful beasts. It keeps it's armies close inside", "群美兽之雄奇合体也。其腹中自藏一军。");
            // 加剧的饥饿
            AddTranslation("RisingHunger", "益饥");
            // 蟑螂仆从
            AddTranslation("Roach Familiar", "螂使魔");
            // 一只由精神制造的蟑螂。这将使它具有压迫能力！这最终失败了。
            AddTranslation("A spiritually manufacrued cockroach. It's will allows it ressurection abilities! that ultimately fail.", "一神造之螂也。其志使之得苏生之能，然终亦败。");
            // 幻影巫师
            AddTranslation("Shadow Wizard", "影巫");
            // 卧底暴徒。他号召阴影们联合起来对付敌人。
            AddTranslation("A mobster of the underseen. He calls the shadows to gang on it's foes", "潜隐之暴徒也。彼呼群影，共噬其敌。");
            // 忍者
            AddTranslation("Shinobi", "忍者");
            // 黑暗的战士，他们在不知不觉中发起攻击，在那里没有人提出要求或视线。
            AddTranslation("Warrior of the dark, They strike from the unawares, where nobody lays claim or sight", "闇中之武者也。彼乘人不觉而击，自无人能见能据之处。");
            // 淋浴法师
            AddTranslation("Shower Mage", "浴术士");
            // 我学院的弃子，这是理所当然的！他的腐败只能用魔法来形容...
            AddTranslation("The outcast of my school and rightfully so! His levels of stentch could only be described with magic...", "我院之弃徒，诚其宜也！其臭之甚，惟可藉术言之……");
            // 淤泥法师
            AddTranslation("Sludge Mage", "泥术士");
            // 一个来源不明的实体，为向所有人传播的瘟疫提供能量。
            AddTranslation("An entity of unknown origins, powered off the ill spreading plague to all", "所从莫知之一体也，假广布之疠而得力。");
            // 隋圣人
            AddTranslation("Sui-Sage", "隋贤");
            // 一个群体的首领，很快就要走人了。
            AddTranslation("The leader of a pack, soon to be packed away", "一群之长也，旋将见收去。");
            // 召唤师
            AddTranslation("Summoner", "召者");
            // 一个生活艺术的疯子。他凭空创造了它，并带着令人恐惧的情感。
            AddTranslation("A mad man of the arts of life, he creates it out of thin air. And with frightning sensibilities", "生术之狂士也。彼凭虚造物，而其情可怖。");
            // 对称法师
            AddTranslation("Symmetrical Mage", "对称术士");
            // 你看，每个人都有两面性。尤其是当他们惹我生气的时候。
            AddTranslation("Everyone has two sides to them, you see. Especially once they mess with my temper", "子视之，人皆有二面。尤在犯我怒之后。");
            // 传送法师
            AddTranslation("Teleportation Mage", "移术士");
            // 无尽门户的先驱，在战场上无限颠簸，否定即将到来的袭击。
            AddTranslation("A herald of endless portals, jolting around the battlefield in infinitum and negating incoming strikes", "无穷门之先驱也，周腾战地而无已，且却将至之攻。");
            // 洪流法师
            AddTranslation("Torrent Mage", "洪术士");
            // 海洋的学徒利用它淹没陆地和上面的地形。
            AddTranslation("An apprentice of the ocean utilising it to drown the lands and the terrain above", "海之徒也，假其力以没陆与其上地形。");
            // 狂野魔龙
            AddTranslation("Untamed Dragon", "野龙");
            // 传说这头野兽，曾经是魔神绿橙蓝大师的伙伴。
            AddTranslation("Legends whisper this beast, was once a companion to the mox master Goranj", "传言此兽，昔尝为玛珂大师 Goranj 之侣。");
            // 邪术士
            AddTranslation("Warlock", "邪术士");
            // 一个被熏黑的巫师在研究血魔。如此流血，他变成了可怕的武器。
            AddTranslation("A blackened wizard pursuiting the studies of the blood magicks. Such bleeding he turns into a horrible weapon", "一黧巫治血术之学。其流血若是，则化为可怖之兵。");
            // 罪恶魔女
            AddTranslation("Wicked Witch", "恶魔女");
            // 一个飞行的滑稽魔女，她嘲笑你的悲伤，为你的军队搔首弄姿。
            AddTranslation("A flying jesting witch, laughing your sorrows and posioning your armies", "一飞而戏之魔女也，笑汝忧，而毒汝军。");

            // Ability
            // 尖酸气质
            AddTranslation("Acid Aura", "酸晕");
            // [creature]每回合对敌方造物造成1点伤害。
            AddTranslation("[creature] deals 1 damage to the creature opposing it every turn", "[creature]每合伤其对位之物一。");
            // 羽化登仙
            AddTranslation("Awakening", "启化");
            // 当[creature]被放置时，其持牌人选择一个友方生物进化成更高的形态。
            AddTranslation("When [creature] is played, it's owner chooses an ally creature to evolve into a higher form.", "[creature]既陈，则其主持择一友物，使孚为高形。");
            // 反噬打击
            AddTranslation("Backfire Strike", "反噬击");
            // [creature]会对其攻击目标的敌对生物造成伤害。
            AddTranslation("[creature] damages creatures that oppose those it attacks.", "[creature]攻彼，则并伤与彼相对之物。");
            // 鲜血吞噬者
            AddTranslation("Blood Guzzler", "嗜血");
            // 当[creature]造成伤害时，其每造成一点伤害，获得1点生命值。
            AddTranslation("When [creature] deals damage, it gains 1 health for each damage dealt.", "[creature]凡致一伤，则得一命。");
            // 残忍寄生
            AddTranslation("Brute Parasite", "悍寄");
            // 当放置[creature]时，会在对面空间上创建一个蛋。
            AddTranslation("When [creature] is played, an Egg is created on the opposing space.", "[creature]既陈，则其对位生一卵。");
            // 洪流
            AddTranslation("Deluge", "洪漫");
            // 当放置[creature]时，具有0力量的对手生物会下潜并获得水袭印记。
            AddTranslation("When [creature] is played, opponent creatures with 0 power drown and get given the Waterborne sigil.", "[creature]既陈，则敌物凡威为零者皆沉，而受潜袭印契。");
            // 分裂
            AddTranslation("Division", "分裂");
            // 攻击后，[creature]将分裂成2个相同的克隆体，每个克隆体都有其原始属性的一半。
            AddTranslation("After attacking, [creature] splits into 2 identical clones, each bearing half of it's original stats.", "攻后，[creature]分为二同体，各当其本数之半。");
            // 哨兵
            AddTranslation("Sentry", "戍者");
            // 当一个造物移动到与[creature]相对的空间时，它们会受到1点伤害。
            AddTranslation("When a creature moves into the space opposing [creature], they are dealt 1 damage.", "有物移入[creature]对位之处，则受一伤。");
            // 啊，永远不要低估一个前瞻法师的速度。
            AddTranslation("Ah, let one never underestimate the speed of a Foresight Mage.", "噫，毋轻先见术士之速。");
            // 治愈光环
            AddTranslation("Healing Aura", "疗晕");
            // [creature]治愈附近的友方造物。治愈的值与它的力量成正比。
            AddTranslation("[creature] heals nearby allied creatures. The healing is proportionate to it's power.", "[creature]疗近旁之友物，其所疗如其威。");
            // 偷心者
            AddTranslation("Heart Stealer", "夺心者");
            // 当[creature]杀死一个造物时，其会被添加到你的手上。
            AddTranslation("when [creature] kills a creature, it gets added to your hand.", "[creature]若杀一物，则其物归汝手。");
            // 火焰魔咒
            AddTranslation("Ignis Incant", "火咒");
            // 为[creature]支付1点血量，对选定的对手位置造成2点伤害。
            AddTranslation("Pay 1 blood for [creature] to deal 2 damage to a chosen opposing slot.", "费一血，使[creature]伤所择敌位二。");
            // 恐吓
            AddTranslation("Intimidate", "慑");
            // 当[creature]上场时，面对其的造物会向右侧逃跑。
            AddTranslation("When [creature] is placed on the board, the creature opposing it will flee to their right.", "[creature]既陈于局，则对之之物遁于其右。");
            // 孤独
            AddTranslation("Lonesome", "孤");
            // [creature]每有一个相邻空位便增加1点力量。
            AddTranslation("[creature] gains +1 power for each adjacent empty space.", "[creature]每邻一空位，则威益一。");
            // 魔法爆发
            AddTranslation("Magic Burst", "术爆");
            // 死亡后，与[creature]相邻的造物的力量加1。
            AddTranslation("After perishing, creatures adjascent to [creature] have their powers increased by 1.", "[creature]既死，其相邻诸物威皆益一。");
            // 精神破坏
            AddTranslation("Psystrike", "神击");
            // 在[creature]死亡后，它操纵与之相对的造物攻击其相邻的盟友。
            AddTranslation("After [creature] perishes, it manipulates the creature opposing it to strike both of it's adjascent allies.", "[creature]既死，则役其对位之物，使击其两旁之侣。");
            // 训蛇大师
            AddTranslation("Serpent Master", "御蛇");
            // 在每个回合开始时，[creature]都会在持牌人选择的一个空间产生蛇之召。蛇之召被定义为：1点力量，1点生命。
            AddTranslation("At the start of every turn, [creature] spawns a Summon Serpent on a space of it's owner's choosing. A Summon Serpent is defined as: 1 power, 1 health.", "每合始，[creature]于其主持所择之一位生一召蛇。召蛇者：一威，一命。");
            // 幻影冲击
            AddTranslation("Shadow Strike", "影击");
            // [creature]也会召唤其目标附近造物的幻影来攻击它。
            AddTranslation("[creature] calls upon the shadows of creatures adjascent to it's target to strike it as well.", "[creature]亦呼其所攻近旁诸物之影，共击之。");
            // 潮汐锁定
            AddTranslation("Tidal Lock", "潮缚");
            // 在持牌人回合之初，[creature]会将松鼠之类的小造物拉入自身卫星轨道。
            AddTranslation("At the beginning of it's owner's turn, [creature] will pull small creatures, like squirrels, into it's orbit.", "其主持合始，[creature]引松鼠之类小物入其回环。");
            // 巫师之心
            AddTranslation("Wizard's Heart", "巫心");
            // 当[creature]死亡时，与您控制的当前宝石相对应的玛珂牌将取代其的位置。
            AddTranslation("When [creature] perishes, a Mox card corresponding to the current gems you control takes it's place.", "[creature]死，则与汝今所御诸玉相应之玛珂牌踵居其处。");
        }

    }

    public class MagModExpansionMod
    {
        public static void RegisterTranslations()
        {

            // Card
            // 河狸防御
            AddTranslation("Beaver's Defense", "狸防");
            // 在使用时精心设计防御性水坝，这对可怕的情况来说并不坏。
            AddTranslation("Curating defensive dams upon use, not bad for a dire situation.", "用之则营防坝，于危局亦不恶。");
            // 炸弹贤者
            AddTranslation("Bomb Sage", "爆贤");
            // 当受到攻击时，这位贤者以爆炸而闻名。从字面上和隐喻上。
            AddTranslation("When attacked, this sage is known for blowing up.. Literally and metaphorically.", "见攻，则此贤每以爆著名，言内言外皆然。");
            // 拳击冠军
            AddTranslation("Boxing Champ", "拳魁");
            // 这位冠军拒绝使用魔杖，更喜欢用拳头解决问题。
            AddTranslation("Rejecting the use of wands, this champion prefers to settle things with his fists.", "此魁不用杖，而乐以拳决事。");
            // 雷龙
            AddTranslation("Brontosaurus", "雷龙");
            // 我爱恐龙模组！！！
            AddTranslation("I LOVE DINO MOD!!!!!", "我爱恐龙补缀！！！");
            // 奶酪巫师
            AddTranslation("Cheese Wizard", "酪巫");
            // 作为训练有素的大厨魔术师，奶酪奇才利用他们的智慧和神秘来实现他们的目标。
            AddTranslation("As trained Chef-Magi, Cheese Wizards use their intellect and Mysticality to accomplish their goals.", "酪巫既习厨术，以其智与玄，遂其所欲。");
            // 奶酪
            AddTranslation("Cheezling", "酪灵");
            // 有了这样的奶酪，谁还需要朋友？
            AddTranslation("With cheese like this, who needs friends?", "有此酪矣，谁复需友？");
            // 心灵感应
            AddTranslation("Telepathy", "心应");
            // 一个学生可以通过纯粹的意志来收集他们需要的所有资源。
            AddTranslation("A pupil can gather all the resources they need through sheer will alone.", "一弟子惟以意志，足聚其所需诸资。");
            // 直接伤害
            AddTranslation("Direct Hit", "直伤");
            // 一旦被放置，你的对手将立即受到三点伤害。
            AddTranslation("Upon being casted, your opponent will instantly take three damage.", "既施，则敌即受三伤。");
            // 神秘的蛋
            AddTranslation("Mysterious Egg", "玄卵");
            // 谁知道这个蛋会孵化出什么...
            AddTranslation("Who knows what could hatch from this egg...", "孰知此卵将孚何物……");
            // 无面者
            AddTranslation("Faceless", "无面者");
            // 一个法师的空壳，拼命寻找属于自己的东西。
            AddTranslation("A hollow shell of a mage, desperately looking for something to call its own.", "一术士之虚壳也，切求其所可自有者。");
            // 伪造者
            AddTranslation("Faker", "伪者");
            // 撒谎，作弊，否认。为了毫发无损地逃脱，伪造者会不择手段...
            AddTranslation("Lie. Cheat. Deny. The lengths the Faker will go to in order to escape unharmed...", "诳、欺、讳。伪者欲全身而遁，其所为无所不至……");
            // 菲格拉塔
            AddTranslation("Figletar", "菲格拉塔");
            // 一个给邪恶国王带来可怕命运的奇才，这个人在拳击场上知道一两件事。
            AddTranslation("A wiz who brought an evil king to a terrible fate, this one knows a thing or two in the ring.", "一巫尝使恶王罹惨祸，此人于拳圜亦颇知之。");
            // 星火燎原
            AddTranslation("Firestarter", "发火者");
            // 学生们报告说，在选角时要小心，决斗场地可能会有点烤。
            AddTranslation("Careful when casting this one, pupils have reported that the dueling grounds can get a little toasty.", "施此宜慎，诸徒云斗地或颇焦热。");
            // 冰箱法师
            AddTranslation("Fridge Mage", "寒柜术士");
            // 它的冰霜气氛会让敌人感到寒冷，削弱他们的进攻力量。
            AddTranslation("Its cold atmosphere will chill foes, weakening their offensive power.", "其寒气凛敌，而损其攻势。");
            // 宝石兄弟
            AddTranslation("Gembro", "玉兄");
            // 这名学生能够一次击中任何目标，他有很高的兴趣。
            AddTranslation("The ability to tank any hit once, this pupil has high gusto.", "此徒能当一击而不挠，气甚豪。");
            // 宝石蜱虫
            AddTranslation("Gem Tick", "玉蜱");
            // 一种难以捉摸的蜱虫，通过其魔力体赋予他人力量。
            AddTranslation("An elusive tick, which grants power to others via its mox body.", "一难捕之蜱也，假其玛珂之体以授他物之力。");
            // 鬼灵恐龙
            AddTranslation("Ghost Dinosaur", "鬼龙");
            // 我爱恐龙模组！！！
            AddTranslation("I LOVE DINO MOD!!!!!", "我爱恐龙补缀！！！");
            // 第三只眼
            AddTranslation("Third Eye", "三目");
            // 利用第三只眼睛的力量，该法术允许施法者获得任何一张牌。
            AddTranslation("Harnessing the power of a third eye, the spell allows its caster to gain any card that it has.", "假三目之力，此术使施者得其所有之任一牌。");
            // 棒球法师
            AddTranslation("Baseball Mage", "球术士");
            // 这个法师的魔杖也可以兼作棒球棍。它的耐用性令人惊讶。
            AddTranslation("This mage's wand doubles as a baseball bat as well. It's suprisingly durable.", "此术士之杖亦兼球杖，其坚异乎所料。");
            // 寒冰傀儡
            AddTranslation("Ice Golem", "冰傀");
            // 这头野兽来自结冰的山顶，融化似乎从未停止过。
            AddTranslation("Hailing from an icy mountaintop, melting never seemed to phase this brute.", "此物出自冰岭，其解虽不已，然未尝挠之。");
            // 劫掠匪徒
            AddTranslation("Looting Bandit", "掠寇");
            // 橙蓝绿大师的武神的一个遥远的追随者，训练成为像他们一样的人。
            AddTranslation("A distant follower of the Master Orlu's Valkyries, training to become just like them.", "Orlu 大师武神之一远从者也，方习而欲肖之。");
            // 魔力法师
            AddTranslation("Mana Mage", "法力术士");
            // 将魔法释放的能量聚集在一起，以提供强大的打击。
            AddTranslation("Brings together the energy that emits from Mana to deliver powerful strikes.", "会聚法力所发之能，以致强击。");
            // 苦思学徒
            AddTranslation("Pondering Pupil", "思徒");
            // 它仅凭心灵的力量从你的宝石堆中汲取灵感。
            AddTranslation("It draws from your gem pile using the powers of its mind alone.", "惟以心力，自汝玉堆中取资。");
            // 镜子法师
            AddTranslation("Mirror Mage", "镜术士");
            // 魔镜啊魔镜，谁的尖叫声最尽兴？
            AddTranslation("Mirror, mirror, on the wall, who's the best Scrybe of them all?", "镜乎镜乎，在壁之间，诸录者孰最上焉？");
            // 钻地法师
            AddTranslation("Whack-A-Mage", "伏地术士");
            // 只要有可能，他总是突然出现，制造麻烦。
            AddTranslation("Always popping up to cause mischief whenever he can.", "苟有可乘，恒骤出以作乱。");
            // 独爪龙
            AddTranslation("Mononykus", "独爪龙");
            // 我爱恐龙模组！！！
            AddTranslation("I LOVE DINO MOD!!!!!", "我爱恐龙补缀！！！");
            // 冥王星
            AddTranslation("PLUTO", "冥王");
            // 哼。这就是那个人去的地方。
            AddTranslation("Hmph. So this is where that one went.", "哼。彼所往者，乃此乎。");
            // 保护
            AddTranslation("Protect", "护");
            // 在一个艰难的时刻？这个咒语将使你的一张牌对它受到的下一次攻击完全免疫。
            AddTranslation("In a tough spot? This spell will give one of your cards full immunity to the next attack it recieves.", "值困局乎？此咒使汝一牌尽免其后所受之一攻。");
            // 翼龙
            AddTranslation("Pterodactyl", "翼龙");
            // 我爱恐龙模组！！！
            AddTranslation("I LOVE DINO MOD!!!!!", "我爱恐龙补缀！！！");
            // 疯兔贤者
            AddTranslation("Rabbid Sage", "狂兔贤");
            // 一个疯狂的魔术师，有一个电场供他支配。
            AddTranslation("A raving magician with a field of electricity at his disposal.", "一狂术者也，有电场可役。");
            // 玛珂骷髅
            AddTranslation("Skelemox", "玛珂枯骨");
            // 一只可怜的骷髅被绿色玛珂控制着，我几乎为此感到难过。
            AddTranslation("A poor skeleton being controlled by a Green Mox, I almost feel bad for it.", "一可哀之枯骨，为绿玛珂所御，我几为之恻。");
            // 粘液巫师
            AddTranslation("Slime Wiz", "涎巫");
            // 它们会以粘液御敌，遭到攻击时削弱敌人攻击力。
            AddTranslation("It'll use the slime against the enemies, to drop their attack whence struck.", "彼以涎御敌，及其受击，则损敌威。");
            // 臭美女巫
            AddTranslation("Smug Witch", "矜魔女");
            // 全岛最臭美的学生，传闻其“臭美投掷”出神入化，无人能及。
            AddTranslation("The smuggest pupil in all the land. Legends say his Smug Throw is unrivaled.", "一境之最矜者也。传云其矜掷无有俦。");
            // 召唤之矛
            AddTranslation("Summon Spear", "召矛");
            // 从地上拔出长矛，作为坚固的反击。
            AddTranslation("Roots up a spear from the ground, acting as a sturdy counter.", "拔地而起一矛，以为坚拒。");
            // 尖刺法师
            AddTranslation("Spike Mage", "棘术士");
            // 这位法师从我最优秀的长毛法师的稻草人身上学到了东西。
            AddTranslation("This mage learned from the best of my Pike Mage's Scarecrows.", "此术士学于我最良棘术士之稻人。");
            // 霸王龙
            AddTranslation("T-Rex", "暴龙");
            // 我爱恐龙模组！！！
            AddTranslation("I LOVE DINO MOD!!!!!", "我爱恐龙补缀！！！");
            // 虚拟君主
            AddTranslation("Virtual King", "虚境君");
            // 自封虚拟界君主，区区“卡牌规则”，他根本不屑一顾！
            AddTranslation("Self-proclaimed ruler of the virtual lands who won't abide to measly “card game rules”.", "自号虚境之主，而区区“牌戏之律”不足遵也。");
            // 低能核心
            AddTranslation("Moron Core", "愚核");
            // 一枚诞于废弃工厂的怪异核心，最是反感“蠢货”这般字眼。
            AddTranslation("An odd core hailing from an abandoned factory, hates the word \"moron\".", "一异核出于废厂，最恶“愚”之一字。");

            // Pack
            // Smughtro的蔓尼菲科模组扩展
            AddTranslation("Smughtro's MagMod Expansion", "Smughtro氏蔓尼菲科扩篇");
            // 为Magnificus模组新增19张普通卡、7张稀有卡、7个法术及6张代币卡。
            AddTranslation("Adds 19 common cards, 7 rare cards, 7 spells, and 6 token cards to Magnificus Mod.", "于 Magnificus 补缀，益常牌十九、罕牌七、术七、符牌六。");

            // Ability
            // 死亡援助
            AddTranslation("Death Assist", "死援");
            // [creature]消亡时，将对敌方造成3点伤害。
            AddTranslation("When a card bearing this sigil perishes, it will deal 3 damage to the opponent.", "负此印契之牌死，则伤敌主三。");
            // 芝士元素
            AddTranslation("Emmental Elemental", "酪元");
            // 打出[creature]时，召唤1只奶酪。
            AddTranslation("When a card bearing this sigil is played, summon a Cheezling.", "负此印契之牌既陈，则召一酪灵。");
            // 首次打击
            AddTranslation("First Strike", "先击");
            // 当打出[creature]时，它将立即攻击对面的位置。如果没有对手牌，则不会造成任何伤害。
            AddTranslation("When a card bearing this sigil is played, it will instantly attack the opposing lane. If there are no opposing cards, no damage will be dealt.", "负此印契之牌既陈，即攻其对列。彼若无牌，则不致伤。");
            // 未知孵化
            AddTranslation("Unknown Hatching", "未知孚");
            // 持牌人的回合开始时，[creature]将孵化成一只随机恐龙。
            AddTranslation("At the start of your turn, a card bearing this sigil will hatch into a random dinosaur.", "持者合始，负此印契之牌将孚为一偶龙。");
            // 生机终焉
            AddTranslation("Healthy Death", "生尽");
            // [creature]消亡时，其左右两侧的卡牌各恢复1点生命值。
            AddTranslation("When a card bearing this sigil perishes, the cards to the left and right of the sigil bearer heal 1 health.", "负此印契之牌死，则其左右诸牌各复一命。");
            // 魔力混沌
            AddTranslation("Mana Mess", "法乱");
            // 打出[creature]时，抽一张随机的非稀有魔力消耗型卡牌。
            AddTranslation("When a card bearing this sigil is played, draw a random non-rare Mana costing card.", "负此印契之牌既陈，则引一偶得非法力费之罕牌。");
        }

    }

    public class FloweysMod
    {
        public static void RegisterTranslations()
        {
            // 小花
            AddTranslation("Flowey", "小花");
            // 一名狂热的领袖，一心要通过幕后阴谋复活伟大的克苏鲁，从而开启末日。
            AddTranslation("A fanatical leader hell-bent on bringing about the apocalypse by reviving the great Cthulhu through behind-the-scenes scheming.", "一狂热之长也，务以幕后之谋复大克苏鲁，而启末世。");
            // 你个蠢货
            AddTranslation("You Idiot", "汝愚哉");
            // 你要是觉得能打败我，那你可真是个蠢货！
            AddTranslation("You really are an Idiot if you think you can defeat me!", "汝若谓能胜我，诚愚矣！");
            // 终极小花
            AddTranslation("Omega Flowey", "极小花");
            // 你真是个蠢货。
            AddTranslation("You really are an idiot.", "汝诚愚也。");
            // 耐心
            AddTranslation("Patience", "忍");
            // 耐心。
            AddTranslation("patient.", "忍。");
            // 勇气
            AddTranslation("Bravery", "勇");
            // 勇气。
            AddTranslation("Brave.", "勇。");
            // 诚实
            AddTranslation("Integrity", "诚");
            // 诚实。
            AddTranslation("integrant.", "诚。");
            // 毅力
            AddTranslation("Perseverence", "毅");
            // 毅力。
            AddTranslation("Persevering.", "毅。");
            // 仁慈
            AddTranslation("Kindness", "慈");
            // 仁慈。
            AddTranslation("Kind.", "慈。");
            // 正义
            AddTranslation("Justice", "义");
            // 正义。
            AddTranslation("Justice.", "义。");
            // 你好——啊不对，你准备好去死了吗？
            AddTranslation("Howdy- Uh i meant Are you ready to Die?", "安——呃，我谓：汝备死乎？");
            // 你好！我叫小花，一朵叫小花的花！
            AddTranslation("Howdy! it's me Flowey, Flowey the Flower!", "安！我乃小花，小花之花也！");
            // 你知道这儿正在发生什么，对吧？
            AddTranslation("You know whats going on here, dont you?", "此间何事，汝知之乎？");
            // 你只是想看我受苦[c:0]！
            AddTranslation("You just wanted to see me suffer[c:0]!", "汝徒欲见我苦耳[c:0]！");
            // 你知道吗，我一直在盯着你。
            AddTranslation("Do You know that ive been watching you?", "汝知我常伺汝乎？");
            // 现在《邪恶冥刻》已经归我掌控了！
            AddTranslation("Well i took over Inscryption now!", "今《冥勒》已归我制矣！");
            // 而且我还知道，《邪恶冥刻》背后隐藏着怎样的秘密……
            AddTranslation("and i know what Secrets are hiding beneath Inscryption...", "且我知《冥勒》之下所藏诸秘……");
            // 现在，没有任何东西能阻挡我征服世界的脚步了！
            AddTranslation("Now nothing stands in my Way to take over the World now!", "今更无物能沮我取天下矣！");
            // 你以为这场战斗的意义是什么？
            AddTranslation("What do you think this Fight was about?", "汝谓此战何为乎？");
            // 我不过是拿这场战斗当幌子，去偷偷翻阅《邪恶冥刻》的文件罢了！
            AddTranslation("I just used it as a cover to snoop through Inscryptions Files!", "我徒假此战为幌，以潜阅《冥勒》之牍耳！");
            // 当然，还有你的电脑！
            AddTranslation("And your PC of course!", "当然，亦及汝机！");
            // 你大概也察觉到了吧，没错——我现在已经连上互联网了！
            AddTranslation("And you may have noticed, BUT iam now connected to the Internet!", "汝殆已觉之矣——然，我今已通于网矣！");
            // 好了，现在是时候开始上传《邪恶冥刻》了！
            AddTranslation("So now its time to begin Uploading Inscryption!", "今其时也，始上传《冥勒》矣！");
            // 你真的是个蠢货！
            AddTranslation("You REALLY are an Idiot!", "汝真愚哉！");
            // 有了这份旧数据，我连人类灵魂的力量都压根不需要了！
            AddTranslation("I don't even need the Power of Human Souls if i just use the OLD_DATA!", "我苟用旧_档，则人魂之力亦无所须！");
            // [c:bR]你以为这么做能得到什么？不过是一场空罢了。
            AddTranslation("[c:bR]Do you know what you are achieving by this? Nothing", "[c:bR]汝以为此能得何哉？终无所得耳。");
            // [c:bR]你休想摆脱我！无论你做什么，我都会一直在这里！
            AddTranslation("[c:bR]You cant get rid of me! No matter what you do, i will always be there!", "[c:bR]汝不能去我！汝所为虽百，我常在此！");
            // [c:bR]那…那些灵魂？
            AddTranslation("[c:bR]Th- The Souls?", "[c:bR]彼……彼诸魂乎？");
            // [c:bR]我…我的力量呢？
            AddTranslation("[c:bR]wh- where are my Powers?", "[c:bR]我……我之力安在？");
            // [c:bR]你都干了些什么？！
            AddTranslation("[c:bR]WHAT HAVE YOU DONE?!", "[c:bR]汝所为何事？！");
            // 小花的防御被降到了[c:bR]0！
            AddTranslation("Floweys Defence dropped to [c:bR]0!", "小花之御降于[c:bR]0[c:]！");
            // [c:bR]不！！！！！
            AddTranslation("[c:bR]NOOOOOO", "[c:bR]不！！！[c:]");
            // 刚刚……发生了什么？
            AddTranslation("What just happened...", "适才……何事生矣？");
            // 哼，看来这次是你赢了……
            AddTranslation("Hmph seemms you have won this time...", "哼，此番似汝胜矣……");
            // [c:bR]没有人会来帮你的！
            AddTranslation("[c:bR]NOBODY IS GOING TO HELP YOU!", "[c:bR]无人将来援汝！[c:]");
            // 别再呼救了！
            AddTranslation("STOP CALLING FOR [c:bR]HELP!", "毋复呼[c:bR]援[c:]！");
            // [c:bR]你真的以为我会这么轻易让你杀了我？
            AddTranslation("[c:bR]Did you really think id let you kill me so easily?", "[c:bR]汝真谓我肯使汝易杀我乎？[c:]");
            // [c:bR]什、什么——
            AddTranslation("[c:bR]what the-", "[c:bR]何、何——[c:]");
            // [c:bR]小花还真以为，它能随便利用我啊……
            AddTranslation("[c:bR]Flowey thought they could just use me...", "[c:bR]小花真谓可恣用我乎……[c:]");
            // [c:bR]它甚至连我究竟是什么都不清楚！
            AddTranslation("[c:bR]He didnt even know what I am!", "[c:bR]彼甚至不知我为何物！[c:]");
            // [c:bR]但现在，掌控一切的人是我……
            AddTranslation("[c:bR]But now IAM in control...", "[c:bR]然今制之者我也……[c:]");
            // [c:bR]真是可悲，它居然没把自己的生命值设成无限……我可不会犯这种低级错误。
            AddTranslation("[c:bR]How pathetic of him to not set his HP to Infinite... I won't make that mistake", "[c:bR]其不以己命设为无极，诚可哀也……我不犯此失。[c:]");
            // [c:bR]尽你所能，你也杀不了我！
            AddTranslation("[c:bR]Try all you want you can't kill me!", "[c:bR]汝尽力为之，亦不能杀我！[c:]");
            // [c:bR]现在，来瞧瞧这玩意儿到底有什么用……
            AddTranslation("[c:bR]Now lets see what this does...", "[c:bR]今试观此物果何用……[c:]");
            // [c:bR]为什么我不能重置这一切？！
            AddTranslation("[c:bR]WHY CANT I UNDO THIS???", "[c:bR]何为我不能反此？？？[c:]");
            // 看着你一次次死掉，可真是[c:bR]有趣极了！
            AddTranslation("SEEING YOU DIE OVER AND OVER AGIAN IS REALLY [c:bR]FUN!", "见汝一死再死，诚[c:bR]快[c:]甚矣！");
            // 连一丝一毫的伤害都打不出来！
            AddTranslation("NOT EVEN A SINGLE POINT OF DAMAGE!", "一丝之伤亦不能致！");
            // 就凭你，[c:bR]根本赢不了我！
            AddTranslation("SOMEONE LIKE [c:bR]YOUCANT BEAT ME!", "若[c:bR]汝[c:]者，终不能胜我！");
            // [c:bR]饥饿可打断不了这场战斗！
            AddTranslation("[c:bR]Starvation wont interrupt this fight!", "[c:bR]饥不能中绝此战！[c:]");
        }

    }


    public class UndertaleMod
    {
        public static void RegisterTranslations()
        {

            // Card
            // 《传说之下》卡包
            AddTranslation("Card Pack:U", "《传说之下》牌韬");
            // 亚伦
            AddTranslation("Aaron", "亚伦");
            // 啊没错，勇猛的亚伦，俊美的亚伦。你难道能把目光从它的肌肉上挪开吗？
            AddTranslation("Ah yes, Aaron the bold, aaron the beautiful. can you manage to take your eyes off his muscles?", "噫，亚伦勇矣，亚伦美矣。汝能移目于其肌乎？");
            // 艾菲斯
            AddTranslation("Alphys", "艾菲斯");
            // 艾菲斯博士正是你在这里见到的，那些让人不安的 “个体” 的创造者……或者说，我该称他们为“多元体”？
            AddTranslation("Dr. Alphys is responsible for the creation of some of the more 'unnerving' individuals you've seen here... or should I say... MULTI-viduals.", "艾菲斯博士，正此间诸“可悚之体”之造者也……抑当谓之“多体”乎？");
            // 这生物既惹人怜爱，又带着股烦人的劲儿。这般矛盾的两面性，简直独一无二。
            AddTranslation("Loveable, yet pestulant. The duality of this creature is unparalleled.", "其物可爱而复烦人，其二端之并，无与比也。");
            // 艾斯戈尔
            AddTranslation("Asgore", "艾斯戈尔");
            // 怪物之王……它无疑是靠着纯粹的蛮力就能让人望而生畏的存在，但除此之外……竟也藏着一份慈悲之心？
            AddTranslation("The king of monsters... he truly is an intimidating force of brute strength, but also... compassion?", "怪物之王也……其威惟蛮力已足使人惧，然其间……亦有慈乎？");
            // 艾斯利尔·逐梦
            AddTranslation("asriel dreemurr", "艾斯利尔·逐梦");
            // 地底世界最强大的存在……但愿你能派上他的用场。
            AddTranslation("the most powerful being in the underground... hopefully you find some use for him.", "地下最强之有也……愿汝得其所用。");
            // 散光眼
            AddTranslation("Astigmatism", "散光眼");
            // 这恼人的散光眼……真是让人捉摸不透。
            AddTranslation("The frustrating astigmatism... it can't make up its mind.", "此散光眼恼人……其意终未能定。");
            // 龙骨炮
            AddTranslation("Gaster Blaster", "龙骨炮");
            // 冰块
            AddTranslation("Block of Ice", "冰块");
            // 一块出奇大的冰块……谁知道里面藏着什么呢。
            AddTranslation("A peculiarly large ice cube... Who knows what could be inside.", "一冰块大而异……孰知其中何有。");
            // 查拉
            AddTranslation("Chara", "查拉");
            // 狗来米
            AddTranslation("Dogamy", "狗来米");
            // 狗来米与妻子狗媳儿，最爱在战场上默契配合联合作战。切记别让它们中的任何一方倒下……
            AddTranslation("Dogamy and his wife, Dogaressa, love to tag-team the battlefield. Just don't let one of them perish...", "狗来米与其妻狗媳儿，最喜并力于战。慎勿使其一者死……");
            // 狗媳儿
            AddTranslation("Dogaressa", "狗媳儿");
            // 遁狗
            AddTranslation("Doggo", "遁狗");
            // 啊，那只盲眼遁狗……但凡有半点动静，它都会猛地扑过去。
            AddTranslation("Ah, the blind doggo... He leaps towards any sound of movement.", "噫，此盲遁狗也……凡闻动响，辄跃赴之。");
            // 涂鸦沼泽
            AddTranslation("doodlebog", "涂鸦沼泽");
            // 人偶
            AddTranslation("Dummy", "人偶");
            // 这尊呆板的人偶……可远不如它那“生气”的同类有魅力。
            AddTranslation("the bland dummy... not as charismatic as its 'mad' counterpart", "此人偶平然，不若其“怒”类之有姿也。");
            // 融合怪
            AddTranslation("Amalgamate", "融怪");
            // 聚合犬
            AddTranslation("Endogeny", "聚犬");
            // 无
            AddTranslation("null", "无");
            // 终极蛙吉特
            AddTranslation("Final Froggit", "终蛙吉特");
            // 可不是嘛，这蛙吉特的终极头目形态……却和那些低阶的同类一样，照样轻易就能糊弄过去。
            AddTranslation("Ah yes, the ultimate boss of froggits... Still as easily fooled as its lesser evolved kin.", "终蛙吉特者，蛙辈之极魁也……然犹与其下类同，易欺如故。");
            // 弗里斯克
            AddTranslation("Frisk", "弗里斯克");
            // 蛙吉特
            AddTranslation("Froggit", "蛙吉特");
            // 可不是嘛，这蛙吉特天生胆小得很……打心底里不愿卷入纷争。真是可惜啊。
            AddTranslation("Ah yes, as shy as they come... the froggit wishes not to engage in conflict. how unfortunate.", "蛙吉特性至怯……本不欲预争。惜哉。");
            // 加斯特
            AddTranslation("W.D.Gaster", "加斯特");
            // 格莱德
            AddTranslation("glyde", "格莱德");
            // 这家伙自恋到了极点，非得有张牌在跟前供它自我欣赏，才肯出手攻击。
            AddTranslation("Such a narcisist, it can only attack if a card is in front of it to watch.", "其自爱之甚，必前有一牌可观，而后始攻。");
            // 大犬汪
            AddTranslation("Greater Dog", "大犬汪");
            // 它堪称犬类演化的终极形态，名副其实，完美得无可挑剔。
            AddTranslation("truly and nobly adequate, it is the highest form of evolution a canine can become.", "其诚为犬属之极形，完足无玷。");
            // 礼物鹿
            AddTranslation("Gyftrot", "礼鹿");
            // 善待这只生灵吧，它已经承受了太多。
            AddTranslation("Be kind to this creature, it has gone through enough.", "善待此生，其所经已多矣。");
            // 冰狼
            AddTranslation("Ice Wolf", "冰狼");
            // 可不是嘛，这只壮硕的家伙一倒下，就会生成一块冰块。
            AddTranslation("Ah yes, this buff creature spawns a block of ice upon death.", "此壮物一死，则生一冰块。");
            // 冰帽盖
            AddTranslation("Icecap", "冰帽盖");
            // 杰瑞
            AddTranslation("Jerry", "杰瑞");
            // 赶紧别管他了。
            AddTranslation("Just ditch him already.", "速舍之。");
            // 晚安骑士
            AddTranslation("Knight Knight", "晚安骑士");
            // 呵，那散发着不祥气息的晚安骑士……乃是执掌沉眠的守夜者。她在这场征伐之中，从无半分懈怠。
            AddTranslation("ah, the forboding knight knight... a sentinel of sleep. She is relentless in her conquest..", "噫，此晚安骑士不祥……乃眠之戍者也。其征伐未尝少懈。");
            // 柠檬面包
            AddTranslation("Lemon Bread", "柠檬面包");
            // 小犬汪
            AddTranslation("Lesser Dog", "小犬汪");
            // 顶天了也就算只平平无奇的犬类……至少以它现在的形态来看是这样。
            AddTranslation("A mediocre canine at best... at least in its current form.", "上不过中犬耳，至少就其今形言之。");
            // 卢克眼
            AddTranslation("Loox", "卢克眼");
            // 狡黠的卢克眼……你最好别去招惹它。
            AddTranslation("The cunning Loox EyeWalker... you would be wise not to pick on him.", "卢克眼狡矣，汝勿撄之为智。");
            // 生气的人偶
            AddTranslation("Mad Dummy", "怒人偶");
            // 人偶？
            AddTranslation("Dummy?", "人偶？");
            // 外表是会骗人的……
            AddTranslation("Looks can be deceiving...", "貌可欺人……");
            // 疯狂魔术师
            AddTranslation("Madjick", "狂术士");
            // 真是个厉害的魔法师……
            AddTranslation("quite the magician...", "真术者也……");
            // 记忆脑
            AddTranslation("Memoryhead", "忆首");
            // 镁塔顿
            AddTranslation("Mettaton", "镁塔顿");
            // 一台超高智能、系统化的复杂数据分析器……倒让我想起了一位老“朋友”。
            AddTranslation("A hyper-intelligent, systematic, complex data analyzer... reminds me of an old 'friend'.", "一至智而综密之析器也……使我忆一故“友”。");
            // 镁塔顿 Ex
            AddTranslation("Mettaton Ex", "镁塔顿 Ex");
            // 福音蟑螂
            AddTranslation("Migosp", "福蟑");
            // 暴躁的福音蟑螂……一旦扎堆，攻击力就会暴涨。
            AddTranslation("the irritable Migosp... its attack increases in a crowd.", "此福蟑躁甚……一群则其攻暴长。");
            // 哑剧蟑螂
            AddTranslation("Migospel", "哑蟑");
            // 大模怪
            AddTranslation("Moldbygg", "大模怪");
            // 小模怪
            AddTranslation("Moldsmal", "小模怪");
            // 这玩意儿给我一种冒牌货的感觉。
            AddTranslation("This one's giving me imposter vibes.", "此物令人有伪者之感。");
            // 终极模怪
            AddTranslation("Moldessa", "终模怪");
            // 瞧这凝胶状的小模怪，想必你从未深究过它的构成。
            AddTranslation("ah, the gelatinous moldsmal. you probably never wondered what it's made of.", "噫，此小模怪胶然。汝盖未尝究其所由成也。");
            // 玛菲特
            AddTranslation("Muffet", "玛菲特");
            // 啊，没错，这位便是蜘蛛女王。其节奏明快的博弈手段，十分出众。
            AddTranslation("Ah yes, the spider queen. her rapid play game is remarkable.", "噫，此蜘蛛后也。其应局之疾，甚可称。");
            // 幽灵纳普斯特
            AddTranslation("Napstablook", "纳普斯特幽灵");
            // 性情最为忧郁的幽灵怪物，虽无心争斗，却会为了获得认可而全力应战。
            AddTranslation("The most melancholy of ghosts... it cares not of battle, but still fights to impress.", "幽灵中最郁者也……虽不乐战，然犹为取可而力战。");
            // 洋葱桑
            AddTranslation("onionsan", "洋葱桑");
            // 对付它基本没什么战术可言……第二回合就会变成随机的触手卡牌。
            AddTranslation("Not much strategy with one... It becomes a random tentcle card one the second turn.", "临之无甚可陈之术……至二合，则化为一偶触手牌。");
            // 这位骨感十足的猛士，正是帕派瑞斯。他召唤骨头的速度，简直快得离谱。
            AddTranslation("A boney brute, papyrus is. He will generate bones like nobody's business.", "帕派瑞斯，骨悍士也。其生骨之速，殊骇人。");
            // 欧防风兽
            AddTranslation("Parsnik", "欧防风兽");
            // 火岩绳
            AddTranslation("Pyrope", "火岩绳");
            // 这只火焰绳一心就想把温度拉满，倒要瞧瞧，这热度能有多致命。
            AddTranslation("The Pyrope wants nothing more than to crank up the heat, let's see how fatal that can be.", "此火岩绳惟欲极其热，试观其热何如其酷。");
            // 死神鸟
            AddTranslation("Reaper Bird", "死鸟");
            // 皇家守卫
            AddTranslation("Royal Guards", "王家卫");
            // 一对命运多舛的恋人……它们真的能把心思放在要紧事上吗？
            AddTranslation("two star-crossed lovers... will they ever focus on what's important?", "二命乖之情侣也……其果能专心于所重乎？");
            // 要是你选了这张牌，我感觉我要吃点苦头了。
            AddTranslation("if you pick this card, i feel like i'm going to have a bad time.", "汝若取此牌，我意将有苦时。");
            // 害羞塞壬
            AddTranslation("Shyren", "羞塞壬");
            // 那位热爱音乐的害羞塞壬……敲响她的铃铛，就能聆听她的歌唱。
            AddTranslation("The musically inclined shyren... strike her bells to watch her sing.", "羞塞壬好音……击其铃，则可闻其歌。");
            // 雪铁龙
            AddTranslation("Snowdrake", "雪铁龙");
            // 这只滑稽可笑的雪铁龙……一心想证明它父亲错了。你会成全他的心愿吗？
            AddTranslation("The laughable Snowdrake... striving to prove his father wrong. Will you let him succeed?", "此雪铁龙可哂也……一志证其父之非。汝其成之乎？");
            // 好冷
            AddTranslation("So Cold", "甚寒");
            // 很抱歉
            AddTranslation("so sorry", "甚歉");
            // 他感到很抱歉
            AddTranslation("he's very sorry", "彼甚歉焉");
            // 提米
            AddTranslation("Temmie", "提米");
            // 这只拥有不死特性的提米，姑且算它是猫科怪物吧。此战毫无损失风险，收益却堪称丰厚。
            AddTranslation("Temmie the immortal cat... at least i think she's a feline. Nothing to lose, everything to gain.", "提米不死，姑谓之猫属。临此无所失，而所得尽多。");
            // 托丽尔
            AddTranslation("Toriel", "托丽尔");
            // 这位遗迹守护者……会竭尽所能，守护你这一侧的战场。
            AddTranslation("The keeper of the ruins... She will protect your side of the board to the best of her ability.", "遗迹之守者也……将尽其能以卫汝侧之局。");
            // 傲娇飞机
            AddTranslation("Tsunderplane", "傲机");
            // 她既想吸引你的注意，又盼着你离她远点，根本拿不定主意……我建议你选后者。
            AddTranslation("She can't decide between wanting your attention and wanting you to back off... i suggest the latter.", "彼欲汝顾之，又欲汝远之，意不能定……我劝汝取后者。");
            // 安黛因
            AddTranslation("Undyne", "安黛因");
            // 我怎能忘记安黛因的名号——她是名副其实的勇士，长矛的攻击拥有极强的精准度。
            AddTranslation("How could I forget Undyne? She is a true warrior, with an almighty aim on her spear.", "我安得忘安黛因？彼诚勇士也，其矛所向，命中甚精。");
            // 蔬菜兽
            AddTranslation("Vegetoid", "菜兽");
            // 多吃点绿色蔬菜。（未经美国食品药品监督管理局监管）
            AddTranslation("eat your greens. (not monitored by the fda)", "宜多食青蔬。（弗经 FDA 之校）");
            // 迷你火山
            AddTranslation("Vulkin", "小火山");
            // 这只怪物性子热情得很。它本无心伤人，但这并不能阻止伤害的发生。
            AddTranslation("A very passionate creature, this one. It's not his intention to harm, but that doesn't stop him.", "此物热情甚。其意虽不欲伤，然伤终不止。");
            // 忧伤虫爵士
            AddTranslation("Whimsalot", "忧虫爵");
            // 这尊贵的忧伤虫爵士……祈祷吧，愿它认可你的征途是正义之举。
            AddTranslation("the noble whimsalot... pray that it deems your conquest riteous.", "此忧虫爵贵矣……愿其以汝征伐为义。");
            // 忧郁虫虫
            AddTranslation("Whimsun", "忧虫");
            // 这只毫不起眼的忧郁虫虫……挨一下打就会仓皇逃离战场。
            AddTranslation("the insignificant whimsun... it flees the battle after a single attack.", "此忧虫微矣……一受击则遁战。");
            // 约刷亚
            AddTranslation("Woshua", "约刷亚");
            // 这种生物毫无嗜血之心，一心只想着助人。但若是受到挑衅，它也会奋起反抗。
            AddTranslation("This creature has no lust for blood. His will lies with helping others. But it will fight if provoked.", "此物无嗜血之欲，心惟在助人；然若见撄，亦将奋斗。");

            // Ability
            // 孤僻
            AddTranslation("Antisocial", "孤僻");
            // 若你一侧的场上至少还有1张其他卡牌，[creature]便会获得攻击加成。
            AddTranslation("A card bearing this sigil will gain an attack buff if you have at least 1 other card on your side of the board.", "汝侧场上若尚有一他牌，则负此印契之牌攻益。");
            // 清洁剂
            AddTranslation("Cleanser", "涤者");
            // 每个回合开始时，[creature]会为持牌人场上除自身外的所有卡牌恢复1点生命值。
            AddTranslation("A card bearing this sigil will heal every card on its owner's side of the board, except the sigil bearer, for 1 health, at the start of every turn.", "每合始，负此印契之牌疗其主持侧除己外诸牌各一命。");
            // 决心
            AddTranslation("Determination", "决心");
            // [creature]可移动至持牌人一侧的场上任意空位；此外，[creature]击杀目标后还能获得经验值并提升等级。但这真的是你想要的吗？
            AddTranslation("A card bearing this sigil will move to any open slot its owner chooses, it will also gain EXP and LV after a kill. But is that really what you want?", "负此印契之牌可移至其主持所择之空位；杀敌后，又得经验而升等。然此真汝所欲乎？");
            // 煽动
            AddTranslation("Incendiary", "纵焰");
            // [creature]造成伤害时，会使被攻击的卡牌获得 “灼烧” 印记；带有灼烧印记的卡牌，每回合会损失1点生命值。
            AddTranslation("When a card bearing this sigil damages a card, that card gains the \"ablaze\" sigil. While a card is ablaze, it will lose one health per turn.", "负此印契之牌伤他牌，则彼受“灼”印。凡受灼者，每合失一命。");
            // 灼烧
            AddTranslation("Ablaze", "灼");
            // [creature]在每个持牌人的回合开始时会受到1点伤害。
            AddTranslation("A card bearing this sigil will take 1 damage at the start of its owner's turn.", "负此印契之牌，每至其主持合始，受一伤。");
            // 优柔寡断
            AddTranslation("Indecisive", "二心");
            // [creature]被击中时，会触发50%概率判定——要么获得属性加成，要么直接阵亡并在你手中生成一张该卡牌的副本。
            AddTranslation("When a card bearing this sigil is struck, it has a 50/50 chance to either gain a stat buff, or perish; creating a copy of this card in your hand.", "负此印契之牌见击，则五五之分：或益其数，或死而于汝手生其副本。");
            // 每个人都认识杰瑞。它会让回合延长2秒，而当杰瑞被击杀或献祭时，持牌人一侧所有卡牌都能获得属性加成。
            AddTranslation("Everyone knows Jerry. Makes Turns 2 seconds longer. Cards gain a stat buff when Jerry is killed or sacrificed.", "众皆知杰瑞。其使每合延二息；杰瑞若被杀或见祀，则主持侧诸牌皆益其数。");
            // 饶恕
            AddTranslation("Mercy", "宥");
            // 拥有“决心”特性卡牌在对手卡牌生命值较低时，将解锁此印记，进而迫使玩家做出一道道德抉择。
            AddTranslation("A 'Determined' card will be granted this sigil when the card opposing it has low health, prompting the player to make a moral decision.", "有“决心”之牌，若其对牌命薄，则得此印，而迫人决于义。");
            // 洞察
            AddTranslation("Insight", "察");
            // 你想吃点苦头吗？
            AddTranslation("Do you wanna have a bad time?", "汝欲受苦乎？");
            // 涂鸦者
            AddTranslation("Doodler", "涂者");
            // [creature]被击中时，将随机在相邻空位召唤“涂鸦沼泽”。
            AddTranslation("When a card bearing this sigil is struck, it will sometimes summon doodlebogs on adjacent spaces.", "负此印契之牌见击，则或于相邻空位召涂鸦沼泽。");
            // 羞怯
            AddTranslation("Timid", "怯");
            // 当敌方卡牌移动至[creature]对面的空位时，[creature]将尝试向相邻空位移动一格。
            AddTranslation("When an opponent card moves into the opposing space of a card bearing this sigil, the sigil bearer will try to move one space over.", "敌牌若移入负此印契之牌对位，则其牌试移一格于旁。");
            // 你甩掉杰瑞了。
            AddTranslation("You ditched Jerry.", "汝弃杰瑞矣。");
            // 好家伙，你们这水平也太菜了。
            AddTranslation("Wow, you guys SUCK at this.", "噫，尔曹于此实甚拙。");
            // 这儿的无线网也太差了。
            AddTranslation("The wi-fi here sucks.", "此间无线网甚劣。");
            // 嘘！我正思考呢，你们安静点！
            AddTranslation("SHHHH! Im THINKING, guys!!", "嘘！我方思之，尔等静！");
            // 自己搞定，小鬼。
            AddTranslation("Get your own, twerp.", "自求之，小子。");
            // 我们干嘛要做这种事啊？简直太失败了。
            AddTranslation("Why are we doing this? What a fail.", "我曹何为此哉？真败也。");
            // 大伙儿，这天也太冷了。有没有人管管啊？
            AddTranslation("Guys. its COLD. Does ANYONE care?", "诸君，天甚寒。其有谁顾之乎？");
            // 唉——
            AddTranslation("Ka-SIGH", "唉——");
            // 废话！这谁不知道啊？
            AddTranslation("DUH! Who DOESNT know?", "废话！此谁不知？");
            // 那个……你能送我回家吗？
            AddTranslation("Well... can YOU give me a ride home?", "那……汝能送余回家乎？");
            // 好尴尬啊。
            AddTranslation("Awkwarrrd.", "尴尬哉。");
            // 所以说，你到底在干嘛啊？
            AddTranslation("So, like, what are you even doing?", "汝究竟在做何事？");
            // 哈？它们丢下我了……这叫什么朋友啊！
            AddTranslation("Huh? Did they ditch me...? SOME friends!", "哈？彼等弃余而去……此等友朋！");
        }

    }

    public class RevenantMod
    {
        public static void RegisterTranslations()
        {
            // 亡灵舞者
            AddTranslation("DanseMacabre", "亡灵舞者");
            // 支付2根骨头，逆转该印记的效果。在持牌人的回合结束时，场上所有造物获得1点生命值。
            AddTranslation("Pay 2 Bones to reverse this sigil effect. At the end of the owner's turn, all creatures on the board gain 1 health.", "出骨2以逆此印之效。持牌人合末，局上诸物各得命+1。");
            // 生命汲取
            AddTranslation("LifeDraw", "生命汲取");
            // 支付1点血量，从你的主牌堆抽一张牌。
            AddTranslation("Pay 1 Blood to draw a card from your main deck.", "出血1，自乃主牌列引一牌。");
            // 魂域之门
            AddTranslation("Soulgate", "魂域门");
            // 支付1根骨头，获得1点能量；在持牌人回合结束时，失去等量的最大能量。
            AddTranslation("Pay 1 Bone to gain 1 Energy, lose as much Max Energy at the end of the owner's turn.", "出骨1，得能+1；持牌人合末，失等量之最大能。");
            // 唤灵术
            AddTranslation("Evocation", "唤灵术");
            // 支付3点能量，从坟墓中将最早进入且不带脆骨印记的友方造物移回你的手牌。
            AddTranslation("Pay 3 Energy to return the oldest non-Brittle allied creature from the graveyard to your hand.", "出能3，自冢中召最先入而非脆骨之友方物归于乃手。");
            // 休眠
            AddTranslation("Dormant", "休眠");
            // 支付与[creature]力量值等量的骨头，可使该印记失效1回合；[creature]本回合无法进行常规攻击。
            AddTranslation("Pay Bones equal to the Power of [creature] to disable this sigil for 1 turn. [creature] cannot attack normally.", "出等于[creature]威值之骨，使此印失效1合；[creature]此合不得常规进击。");
            // 炼变
            AddTranslation("Transmute", "炼变");
            // 支付2根骨头，将[creature]转化为另一种形态。
            AddTranslation("Pay 2 Bones to transform [creature] to its alternate form.", "出骨2，使[creature]化为别一形态。");
            // 保护者
            AddTranslation("Protector", "佑");
            // 与[creature]相邻的造物获得1点最大生命值。
            AddTranslation("Creatures adjacent to [creature] gain 1 max health.", "与[creature]相邻之诸物各得最大命+1。");
            // 灾厄溢流
            AddTranslation("CalamityEffusion", "灾厄溢流");
            // 持牌人的回合结束时，场上所有造物失去1点生命值。
            AddTranslation("At the end of the owner's turn, all creatures on the board lose 1 health.", "持牌人合末，局上诸物各失命1。");
            // 慰藉光环
            AddTranslation("ComfortAura", "慰藉光环");
            // 持牌人的回合结束时，与[creature]相邻的所有造物恢复1点生命值。
            AddTranslation("At the end of the owner's turn, creatures adjacent to [creature] heal 1 health.", "持牌人合末，与[creature]相邻之诸物各复命1。");
            // 尸魂盛宴
            AddTranslation("CorpseParty", "尸魂盛宴");
            // 当持牌人一侧不带脆骨印记的造物因战斗阵亡时，一张丧尸会加入你的手牌。丧尸被定义为：1点力量，1点生命。
            AddTranslation("When a non-brittle creature on the owner's side perishes by combat, a Zombie enters your hand. A Zombie is defined as: 1 Power, 1 Health.", "持牌人一侧非脆骨之物因战阵亡时，一张丧尸入乃手。丧尸具：威1，命1。");
            // 亡者叩门
            AddTranslation("DeathKnock", "亡者叩门");
            // 当[creature]因战斗而阵亡时，会发起反击，随后再阵亡。
            AddTranslation("When [creature] perishes by combat, it strikes back then perishes.", "[creature]因战阵亡时，先反击，后乃阵亡。");
            // 死金轰鸣
            AddTranslation("DeathMetal", "死金轰鸣");
            // 当[creature]被打出时，其相邻以及位于其左、右、正前方的敌对造物均受到1点伤害。每有一个受影响的造物，[creature]便获得1点力量。
            AddTranslation("When [creature] is played, adjacent creatures and opposing creatures to the left, right, and center of it take 1 damage. It gains 1 Power for each affected creature.", "[creature]陈时，其相邻及左、右、正前之敌物各受创1。每有一受影响之物，[creature]得威+1。");
            // 污染者
            AddTranslation("Defiler", "污者");
            // 当[creature]阵亡时，你抽一张牌，随后从你的手牌中选择一张弃置。
            AddTranslation("When [creature] perishes, draw a card then choose one to discard from your hand.", "[creature]阵亡时，引一牌，再自乃手择一牌弃之。");
            // 侵噬
            AddTranslation("Encroachment", "侵噬");
            // [creature]在场2回合后，会在你的手牌中生成一张它的复制体。
            AddTranslation("[creature] creates a copy of it in your hand after 2 turns on the board.", "[creature]在局2合后，于乃手中生一自身之摹本。");
            // 炼骨塑骸
            AddTranslation("Skeletonize", "炼骨塑骸");
            // 当[creature]阵亡时，一张带有其原有印记的骷髅会加入你的手牌。骷髅被定义为：1点力量，1点生命，脆骨。
            AddTranslation("When [creature] perishes, a Skeleton with its old sigils enters your hand. A Skeleton is defined as: 1 Power, 1 Health, Brittle.", "[creature]阵亡时，一张承其旧印之骷髅入乃手。骷髅具：威1，命1，脆骨。");
            // 镇魂涤秽
            AddTranslation("Exorcise", "镇魂涤秽");
            // 当[creature]被打出时，玩家会获得等同于敌方造物骨头费用的骨头数量。
            AddTranslation("When [creature] is played, Bones equal to the Bone cost of the opposing creature are granted to the player.", "[creature]陈时，持牌人得等于敌方物之骨直之骴骨。");
            // 尸爆
            AddTranslation("ExplodingCorpse", "尸爆");
            // 当[creature]因战斗阵亡时，场上所有空位都会被一张内脏牌填满。
            AddTranslation("When [creature] perishes by combat, all empty spaces on the board are filled with a Guts card.", "[creature]因战阵亡时，局上诸空位皆填以内脏牌。");
            // 积怨者
            AddTranslation("GrudgeCollector", "积怨者");
            // 每有2次敌方造物对持牌人造成直接伤害时，[creature]便获得1点力量。
            AddTranslation("[creature] gains 1 power for every 2 times opponent creatures deal direct damage to its owner.", "每有2次敌方物对持牌人造成直接伤害，[creature]得威+1。");
            // 铃铛力量
            AddTranslation("Chime Power", "铃铛力量");
            // 此印记所代表的数值，等同于场上铃铛牌的数量。
            AddTranslation("The value represented by this sigil will be equal to the number of Bell cards on the board.", "此印所代表之值，等于局上铃铛牌之数。");
            // 掘骨力量
            AddTranslation("Bone Digger Power", "掘骨力量");
            // 此印记所代表的数值，等同于场上所有骨系及掘骨相关印记的数量。
            AddTranslation("The value represented by this sigil will be equal to the number of Bone and Digger related sigils on the board.", "此印所代表之值，等于局上骨系及掘骨相关印之数。");
            // 点燃
            AddTranslation("Ignition", "燃");
            // 该造物在场上每经过一个回合，便以损失1点生命值为代价，获得1点力量。
            AddTranslation("[creature] gains 1 power at the cost of 1 health after each turn on the board.", "[creature]每历一合，以损命1为代价，得威+1。");
            // 掘骨传花
            AddTranslation("Digger Latch", "掘骨传花");
            // 持牌人回合结束时，[creature]会生成1根骨头。当它阵亡时，持牌人可选择一名造物，使其获得掘骨印记。
            AddTranslation("At the end of the owner's turn, [creature] will generate 1 Bone. When it perishes, its owner chooses a creature to gain the Bone Digger sigil.", "持牌人合末，[creature]生骨1。其阵亡时，持牌人择一物得掘骨印。");
            // 强化掘骨传花
            AddTranslation("Primed Digger Latch", "激掘骨传花");
            // 持牌人回合结束时，[creature]会生成1根骨头。当它阵亡时，持牌人可选择一名造物，使其获得此印记。
            AddTranslation("At the end of the owner's turn, [creature] will generate 1 Bone. When it perishes, its owner chooses a creature to gain this sigil.", "持牌人合末，[creature]生骨1。其阵亡时，持牌人择一物得此印。");
            // 焕生
            AddTranslation("Rejuvenation", "焕生");
            // 当[creature]阵亡时，持牌人可选择一名造物，使其获得幼雏印记。
            AddTranslation("When [creature] perishes, its owner chooses a creature to gain the Fledgling sigil.", "[creature]阵亡时，持牌人择一物得幼雏印。");
            // 头骨风暴
            AddTranslation("Skull Storm", "头骨风暴");
            // 持牌人回合结束时，此印记会随机替换为另一印记。它阵亡后，持牌人可选择一名造物，使其获得此印记。
            AddTranslation("At the end of the owner's turn, this sigil is replaced with another sigil at random. When it perishes, its owner chooses a creature to gain this sigil.", "持牌人合末，此印偶然更易为他印。其阵亡时，持牌人择一物得此印。");
            // 引火
            AddTranslation("Ignite", "引焰");
            // 当[creature]阵亡时，持牌人可选择一名造物，使其获得点燃印记。
            AddTranslation("When [creature] perishes, its owner chooses a creature to gain the Ignition sigil.", "[creature]阵亡时，持牌人择一物得点燃印。");
            // 骸脉惊魂
            AddTranslation("MacabreBonePulse", "骸脉惊魂");
            // [creature]被打出后会立即阵亡，掉落的骨头数量等于持牌人方场上造物数量的两倍。
            AddTranslation("When [creature] is played, it perishes immediately, dropping Bones equal to double the amount of creatures on the owner's side.", "[creature]陈时，即刻阵亡，掉落之骴骨数等于持牌人方物数之倍。");
            // 孕育
            AddTranslation("Maternal", "孕育");
            // 与[creature]相邻的造物将获得水袭印记。
            AddTranslation("Creatures adjacent to [creature] are inscrybed by Waterborne.", "与[creature]相邻之诸物得水袭印。");
            // 腐溃
            AddTranslation("Necrosis", "腐溃");
            // [creature]在场上每经过一个回合，便损失1点力量与1点最大生命。
            AddTranslation("[creature] loses 1 power and 1 max health after each turn on the board.", "[creature]每历一合，失威1及最大命1。");
            // 地狱边境
            AddTranslation("Limbo", "地狱边境");
            // 当[creature]阵亡后，将回归至你的牌组顶端。
            AddTranslation("When [creature] perishes, it returns to the top of your deck.", "[creature]阵亡时，归于乃牌列之顶。");
            // 厉魂不灭
            AddTranslation("RelentlessRevenant", "厉魂不灭");
            // 持牌人的回合开始时，与[creature]相邻的造物将变形为复生亡灵。复生亡灵被定义为：3点力量，1点生命，脆骨。
            AddTranslation("At the start of the owner's turn, creatures adjacent to [creature] transform into a Revenant. A Revenant is defined as: 3 Power, 1 Health, Brittle.", "持牌人合初，与[creature]相邻之诸物化为复生亡灵。复生亡灵具：威3，命1，脆骨。");
            // 复生归魂
            AddTranslation("Revedue", "复生归魂");
            // 攻击结束后，[creature]将阵亡，随后将2个携带其原有印记的复生亡灵洗入你的副牌组。复生亡灵被定义为：3点力量，1点生命，脆骨。
            AddTranslation("After attacking, [creature] perishes, then shuffle 2 Revenants with its old sigils into your side deck. A Revenant is defined as: 3 Power, 1 Health, Brittle.", "攻毕，[creature]即死，复洗二负其旧印之复生亡灵入汝副列。复生亡灵者：三威，一命，脆骨。");
            // 不祥之兆
            AddTranslation("Bad Omen", "凶征");
            // 持牌人的回合结束时，[creature]将对持牌人造成1点伤害。
            AddTranslation("At the end of the owner's turn, [creature] will deal 1 damage to the owner.", "持者合终，[creature]伤其主一。");
            // 怨煞
            AddTranslation("Rancor", "怨煞");
            // 当[creature]阵亡时，会在其原占据的格子上留下一层永久的1点力量加成。
            AddTranslation("When [creature] perishes, it leaves a permanent 1 power buff in the space it occupied.", "[creature]死，则其所据之位留一永威。");
            // 宁谧芳原
            AddTranslation("SoothingMeadows", "宁原");
            // 持牌人回合结束时，场上所有造物获得1点生命值。
            AddTranslation("At the end of the owner's turn, all creatures on the board gain 1 health.", "持者合终，局上诸物皆得一命。");
            // 临终之笔
            AddTranslation("PartingStroke", "诀笔");
            // 当持牌人方的非脆骨造物因战斗阵亡时，持牌人可选择一个造物，使其失去所有印记。
            AddTranslation("When a non-brittle creature on the owner's side perishes by combat, its owner chooses a creature to lose all of its sigils.", "主持侧非脆骨之物若战死，则其主持择一物，使尽失其印契。");
            // 分尸
            AddTranslation("SplittingCorpse", "裂尸");
            // 当[creature]因战斗阵亡时，将在其所有相邻的空格上生成一个畸变体。
            AddTranslation("When [creature] perishes by combat, create a Dysmorphia on each empty adjacent space.", "[creature]若战死，则其邻诸空位各生一畸变体。");
            // 迟钝
            AddTranslation("Torpid", "钝");
            // [creature]无法进行常规攻击。
            AddTranslation("[creature] cannot attack normally.", "[creature]不能常攻。");
            // 幽冥墓志
            AddTranslation("Grim Epitaph", "冥志");
            // 打出[creature]时，你可选择一张已进入休眠状态的卡牌，将其收回手牌。
            AddTranslation("When [creature] is played, you may choose a card that has already been put to rest, to bring back to your hand.", "[creature]既陈，汝可择一已安息之牌，反之于手。");


            // card
            // 巨足
            AddTranslation("Bigfoot", "巨足");
            // 一种潜藏于森林之中的神秘造物，仅有少数人声称曾目睹过它的踪迹。
            AddTranslation("a mysterious creature lurking the forests, only few have claimed to see one.", "一潜于林中之秘物也，称尝见之者寡矣。");
            // 哥布林
            AddTranslation("Goblin", "哥布林");
            // 一头忠心耿耿的蛮荒凶兽，能成为你军团中得力的一员。
            AddTranslation("A loyal barbaric beast, a fine addition to your army.", "一忠而野之兽也，可为汝军良益。");
            // 薇拉
            AddTranslation("Vila", "薇拉");
            // 一见倾心——至少，它想让你这么认为。
            AddTranslation("Love at first sight, at least that's what it wants you to think.", "一见而倾心，至少其欲使汝然思。");
            // 赤肤蛙魔
            AddTranslation("Yaramayawho", "赤肤蛙魔");
            // 它似乎永远也没法吃完自己的猎物……
            AddTranslation("This one can never seem to finish it's meals...", "此物似终不能尽其食……");
            // 试验肢体
            AddTranslation("Test Limbs", "试肢");
            // 这些部件曾经属于某个人，而如今，属于某个…… 东西……(测试)
            AddTranslation("Those parts used to belong to someone, or now some thing...(Test)", "此诸肢尝属于一人，而今属于某……物……（试）");
            // 哀灵狂魂
            AddTranslation("Allip", "狂魂");
            // 疯子残存的魂灵！你永远无从知晓那张面容背后藏着怎样的故事，但它注定满是执念。
            AddTranslation("The remnants of the insane! You never know what story lies behind that face, but it's sure to be filled with fervor.", "狂者之馀魂也！彼面之后所藏何事，汝终无由知；然必满执念。");
            // 奄美兔
            AddTranslation("Amami Rabbit", "奄美兔");
            // 将幼崽藏于洞穴之中，只求护它们周全。
            AddTranslation("Hiding their young in holes, they wish for their best safety.", "匿其幼于穴，惟愿其安。");
            // 安卡咒物
            AddTranslation("Ankhame", "安卡咒物");
            // 一件会被你的鲜血所吸引的遗物，或许你可以挥砍它试试！
            AddTranslation("A relic that is drawn to your blood, perhaps you could give it a swing!", "一为汝血所招之遗物也，或可挥之试之！");
            // 安妮塔
            AddTranslation("Anneta", "安妮塔");
            // 墨汁不住地奔涌流淌，她的身影是否还在那里？死亡所能给予的全部承诺，不过是让你再次醒来。
            AddTranslation("That ink keeps on pouring, is she even there anymore? All that death promises is that you will wake up again.", "其墨奔流不已，彼身尚在其间乎？死之所许，惟使汝复醒耳。");
            // 厌食魔
            AddTranslation("Anorexia", "厌食魔");
            // 让你被自我厌恶的情绪所淹没，你永远无从知晓它下一刻会化作何种形态。
            AddTranslation("Overflowing you with self loathing, you never know what form it may take on next.", "使汝自恶溢怀，彼次将为何形，终不可知。");
            // 巫妖之铃
            AddTranslation("Lych Bell", "巫妖铃");
            // 看来，他们寻得了一种使用铃铛的新法子。
            AddTranslation("It seems like they found a new way to use bells.", "观彼似得用铃之一新术。");
            // 胀尸
            AddTranslation("TheBloated", "胀尸");
            // 狰狞的脓疮，正蓄势待发，一触即溃。
            AddTranslation("Grotesque boils, ready to burst.", "恶疮狞然，将裂矣。");
            // 畸脑罐头
            AddTranslation("BrainJar", "脑罂");
            // 光是想象那罐子里藏着何等非人的念头，便足以令人战栗……
            AddTranslation("One shudders to imagine what inhuman thoughts lie inside that jar...", "念彼罂中所藏何等非人之思，足令人栗……");
            // 爆燃尸壳
            AddTranslation("Combustor", "燃尸");
            // 天呐，曾几何时那般炙手可热的尊荣竟一落千丈，如今只剩下一具金属残骸，以及那最后一丝尚存的警戒之物……
            AddTranslation("Oh dear, what a fall from such a stimulatingly high status, now all that's left is a metal carcass, and the last of that watchful substance...", "呜呼，盛时何其炽也，今遽坠若此，仅馀金属之骸，与彼最后一点警觉之质……");
            // 糜烂白鼬
            AddTranslation("Misplayed Stoat", "败白鼬");
            // 一只腐坏的白鼬，它那套曾被奉若圭臬的完美策略，终究让它一败涂地。
            AddTranslation("A decaying Stoat whose oh-so perfect strategies failed him tremendously.", "一腐白鼬也，其所谓完策终使之大败。");
            // 畸变体
            AddTranslation("Dysmorphia", "畸变体");
            // 左侧畸变体。
            AddTranslation("Dysmorphia Left.", "左畸变体。");
            // 右侧畸变体。
            AddTranslation("Dysmorphia Right.", "右畸变体。");
            // 驱魔道人
            AddTranslation("Exorcist", "祓者");
            // 他仍以为驱逐那些受诅之物便能为自己带来裨益，可他当真知晓自己身处于何方吗？
            AddTranslation("He still thinks banishing the dammed will do him good, does he know where he is?", "彼犹谓逐去受诅者足自利，然其果知身今何所乎？");
            // 脓骨鬼
            AddTranslation("Flembones", "脓骨鬼");
            // 等他摆弄好他的摄像头再说。
            AddTranslation("Wait until he plays with his webcam.", "姑待彼戏其影机。");
            // 斯坦和弗兰肯
            AddTranslation("Stein & Frank", "斯坦与弗兰肯");
            // 即便是地狱业火，也未能将二人分离开来。
            AddTranslation("Even hell was not hot enough to split them.", "虽狱火之炽，亦不足析之。");
            // 惊雷颅骨
            AddTranslation("FulmineSkull", "雷颅");
            // 凝神细听，你仍能听见烈焰灼烧骸骨的噼啪声响……以及他们残存的低语。
            AddTranslation("If you listen closely, you can still hear the cackling of flame on bone... as well as their voice.", "凝听之，犹可闻炎炙骨之噼啪……并其馀语。");
            // 轰雷殖骨
            AddTranslation("FulurOssa", "雷殖骨");
            // 它从未真正离开过那张电椅。
            AddTranslation("It never truly left the electric chair.", "彼未尝真离电椅。");
            // 普罗米修斯之火
            AddTranslation("PrometheusFlame", "普罗米修斯火");
            // 此物着实独一无二，乃是那造福人类的窃贼所遗留的馈赠！话说回来，要来份精致的肝脏尝尝吗？
            AddTranslation("This one is quite unique, the lingering spoils of a thief to benefit humanity! Fancy liver by chance?", "此物诚异，乃惠人之盗所遗馀赐也！汝欲尝肝乎？");
            // 内脏
            AddTranslation("Guts", "腑");
            // 烦人的内脏。
            AddTranslation("Annoying guts.", "烦腑也。");
            // 先驱者
            AddTranslation("Harbinger", "先驱");
            // 一头强大的魔物，其效命的代价高昂至极。
            AddTranslation("A powerful fiend that extols a heavy price for its servitude.", "一强魔也，其役之价甚重。");
            // 哈斯塔
            AddTranslation("Hastur", "哈斯塔");
            // 祂自群星之外而来，将自身倒影的碎片，同等赠予君王与愚人。你，会收下这片碎片吗？
            AddTranslation("He came from beyond the stars, gifting pieces of his reflection to kings and fools alike. Will you accept this piece?", "彼自群星之外来，以己影之片同赐君与愚。汝其受此片乎？");
            // 寻常魔仆
            AddTranslation("Common Imp", "常魔仆");
            // 一种小小魔物，所到之处必生事端与混乱，脸上挂着狡黠的坏笑，性子顽劣至极！
            AddTranslation("A tiny creature known for causing trouble and mayhem wherever it goes, with its mischievous grin and playful nature!", "一小魔也，所往必生乱，其笑狡黠，而性顽甚。");
            // 八岐残魂
            AddTranslation("Orochimitama", "八岐残魂");
            // 哦……它本不该出现在此地的……
            AddTranslation("Oh... He is not supposed to be here...", "噫……彼本不当在此……");
            // 生之息
            AddTranslation("Inochi", "生息");
            // 一股抚慰心神的力量，治愈你的造物，亦是风暴降临前的片刻宁静。
            AddTranslation("A soothing presence to heal your creatures, a calm before the storm.", "一和抚之气也，疗汝诸物，亦风暴前之暂宁。");
            // 折磨之径。
            AddTranslation("Trail of Torment.", "苦径。");
            // 异肢
            AddTranslation("Possessed Limbs", "祟肢");
            // 一旦附着于活人身上，它们便彻底归于另一个存在所有。
            AddTranslation("Once attached to a living person, they now belong to something else entirely.", "既附生人，则尽归他物矣。");
            // 鼹鼠掘墓人
            AddTranslation("Mole Digger", "鼹掘者");
            // 坚定的鼹鼠……掘墓人？不用管这是什么……
            AddTranslation("The stalwart Mole... Digger? Whatever this is...", "坚鼹……掘者乎？姑无问此为何也……");
            // 御魂主宰
            AddTranslation("Nekros", "御魂主宰");
            // 御魂主宰执掌战场，挑战者。死亡即是他的猎场。
            AddTranslation("Nekros possesses the board, challenger. Death is his playground.", "御魂主宰据此局矣，角者。死即其戏场。");
            // 圣装御魂主宰
            AddTranslation("NekrosPrime", "圣装御魂主宰");
            // 你再也寻不到……比这更磅礴的力量……莫过于念及自身名姓……被镌刻在墓碑之上的瞬间。
            AddTranslation("You will find no greater power... than the simple thought of your own name... inscrybed upon a grave.", "汝将无复见大于此之力……惟念己名……铭于墓石之上耳。");
            // 诺克那维
            AddTranslation("Nuckelavee", "诺克那维");
            // 它乃深海之主，你最好祈祷它的气息，不会玷污你的仆从！
            AddTranslation("The Administrator of its sea, you better hope it's breath doesn't taint your Thralls!", "彼其海之主也，汝宜祷其息不污汝役！");
            // 秽邪巨体
            AddTranslation("OdiousMass", "秽巨体");
            // 何其丑陋。
            AddTranslation("How unsightly.", "何陋之甚。");
            // 八岐大蛇
            AddTranslation("Orochi", "八岐蛇");
            // 必须做出牺牲。
            AddTranslation("Sacrifices must be made.", "汝必须行牺牲。");
            // 欧罗大师
            AddTranslation("Master Ouro", "欧罗大师");
            // 在无尽的折磨与痛苦之中，它们竟摸索出了一条途径，得以窥见这可怜残躯的内里……并将其痛苦尽数抹去。
            AddTranslation("From within the endless torment and suffering, they had somehow learned a way to see inside this poor broken thing... and take away its pain.", "处无尽之苦与痛中，彼竟得一术，以窥此可怜残体之内……而尽夺其痛。");
            // 生死轮回无休无止，早已摧残了这些遭人遗弃的残躯。痛苦真实不虚，但死亡并不是终结！
            AddTranslation("An endless cycle of life and death has taken a toll on these discarded remains. The pain was real, but death is never final!", "生死之环无穷，已尽残此诸弃骸。其痛诚真，然死终非竟也！");
            // 杜拉尔罕
            AddTranslation("GanCeann", "杜拉尔罕");
            // 无数传说都提及杜拉尔罕，却无一则能道尽它暴怒的真正程度。
            AddTranslation("Countless legends tell of the dullahan, but all fail to convey the true extent of its pique.", "诸传多言杜拉尔罕，然莫能尽道其怒之实。");
            // 暗黑王子
            AddTranslation("Dark Prince", "暗王子");
            // 你体内正闪耀着毛茸茸小家伙们的力量。
            AddTranslation("The power of fluffy bois shines within you.", "绒毛诸子之力，方辉于汝中。");
            // 夭折鸦灵
            AddTranslation("Stillborn Raven", "夭鸦灵");
            // 再回年少，快意畅快！
            AddTranslation("Feels good to be young again!", "复少诚快！");
            // 回魂者
            AddTranslation("Reanimated", "回魂者");
            // 手持死亡镰刀的复生亡灵，只为……等等，这是什么？
            AddTranslation("BRINGING THE SCYTHE OF DEATH, THE REVENANT... WAIT, WHAT?", "携死镰而来的复生亡灵……且，何物？");
            // 复生异灵
            AddTranslation("RevenantEldritch", "复生异灵");
            // 灾祸之源，冷酷无情，精准无匹。
            AddTranslation("The source of Calamity, relentless and unerring.", "灾之源也，不舍而不谬。");
            // 懒骨
            AddTranslation("Lazy Bones", "懒骨");
            // 一具慵懒又爱讲冷笑话的骷髅，可太喜欢他了。
            AddTranslation("A slothful skeleton with a knack for jokes. I adore him.", "一惰而善谐之骨也，吾甚爱之。");
            // 骸音机
            AddTranslation("Skelephone", "骨音器");
            // 与死者沟通之法，不过代价不菲。
            AddTranslation("A way to communicate with the dead, for a price.", "通死者之一术也，然其价不轻。");
            // 魂域之门
            AddTranslation("Soulgate", "魂域门");
            // 踏入魂域的机缘，何其美妙？但愿你付得起相应的代价。
            AddTranslation("A chance to enter the soul realm, how delightful? I hope you can afford the price.", "入魂域之机，何其美乎？愿汝办得其价。");
            // 黑桃战士
            AddTranslation("SpadeWarrior", "黑桃武者");
            // 这威名赫赫的战士定会将你送入黄泉，从里到外，无一幸免。
            AddTranslation("This fearsome warrior will put you six feet under, in every possible sense.", "此武者可畏，必使汝入冢，凡所可言之义皆然。");
            // 不死民灵
            AddTranslation("UndeadCivilian", "不死民灵");
            // 困于永恒黑暗之中，这缕可怜的亡魂正苦苦寻觅出路。或许，你能为他点亮一盏明灯？
            AddTranslation("Lost in eternal darkness, this poor soul desperately seeks a way out. Perhaps you can light his way?", "陷永闇中，此可怜魂苦觅其路。汝其能为之燃一灯乎？");
            // 葬灵村
            AddTranslation("UndeadVillage", "葬灵村");
            // 荒弃凄凉，这座村落正盼着新住民，来填满它破败的屋舍。
            AddTranslation("Abandoned and forlorn, this village seeks new residents to fill its decrepit homes.", "既荒且凉，此村求新居者，以充其败屋。");
            // 每一座城镇，每一方都市，总有人要负责埋葬逝者。而终有一日，他们也会被葬入黄土。
            AddTranslation("In every town, in every city, someone must work to bury the dead. In time, they too will be buried.", "凡邑与都，必有人埋死者。及其时也，彼亦将见埋。");
            // 骸骨博士
            AddTranslation("Dr.Bones", "骨博士");
            // 杀不死你的东西，只会让你变得更清醒。
            AddTranslation("Whatever doesn't kill you simply makes you, saner.", "凡不能杀汝者，徒使汝更醒耳。");
            // 温迪戈
            AddTranslation("Wendigo", "温迪戈");
            // 自荒莽野地归来，倒让我想起一位故人。
            AddTranslation("Returned from the deep wilds, reminds me of a friend.", "自荒野深处归，使我忆一故人。");
            // 赢先生
            AddTranslation("Mister Win", "赢先生");
            // 一张致胜的牌。它永远立于不败之地。这便是它得名赢先生的缘由。
            AddTranslation("A card that wins. It always wins. That's why it's called Mister Win.", "一能胜之牌也。彼恒胜，故曰赢先生。");
            // 恐怕，并非那一张。
            AddTranslation("Not that one, I'm afraid.", "恐非此张。");

            // Dlg
            // 你……你这个杀人如麻的怪物。
            AddTranslation("You... you murderous monster.", "汝……汝此嗜杀之怪。");
            // 哦，天哪……灾祸的洪流必将追赶你。
            AddTranslation("Oh Dear... The flow of Calamity will pursue you.", "噫……灾流必逐汝。");
            // 夷平你曾居住的村子。
            AddTranslation("Hecatomb the village you once lived.", "夷汝昔所居之村。");
            // 寻找那把能一直挖下去的铲子。
            AddTranslation("Seak for the shovel that digs forever.", "求其永掘之锸。");
            // 然后把那个手里拿着火花的失踪者带给我。
            AddTranslation("Bring me the lost one with a spark in hand.", "执火星之失者，携以来我。");
            // 经由古老存在的召唤，
            AddTranslation("Compelled by the beckoning of an ancient entity,", "为古物所招，");
            // 一场禁忌的仪式已经开始。
            AddTranslation("a forbidden ritual has been initiated.", "禁仪既作矣。");
            // 痛苦传到了古老的死亡巨蛇耳中。
            AddTranslation("The pain reaches the ancient great serpent of death.", "其痛达于上古死巨蛇。");
            // 你必须做出牺牲。
            AddTranslation("Sacrifices must be made.", "汝必须行牺牲。");
            // 哦……目前还没有死亡卡。
            AddTranslation("Oh... There are no dead cards yet.", "噫……今尚无死牌。");

            // Pack
            // 复生亡灵模组卡包
            AddTranslation("Revenant Mod Card Pack", "复生亡灵补缀牌韬");
            // 这套卡牌主要由一些能以各种方式返回玩家手中的卡牌组成。
            AddTranslation("This card pack consists of mainly cards that return to the player in a variety of ways.", "此牌韬多由能以诸途反归戏徒手中之牌成。");
        }

    }

    public class SquirrelBombMod
    {
        public static void RegisterTranslations()
        {
            // 皮皮蛋
            AddTranslation("Pipis", "皮皮蛋");
            // 皮皮蛋。
            AddTranslation("Pipis.", "皮皮蛋。");
            // 帮助
            AddTranslation("Help", "援");
            // 持牌人的回合结束时，[creature]将牺牲自身，令相邻的卡牌各回复1点生命值。
            AddTranslation("At the end of the owner's turn [creature] will sacrifice itself to heal the adjacent cards by 1.", "持者合终，[creature]自祀，以疗相邻诸牌各一命。");
            // 畅通无阻
            AddTranslation("Pass-through", "洞彻");
            // 当[creature]即将被攻击力高于自身生命值的卡牌攻击时，此牌将消亡。
            AddTranslation("When [creature] is about to get attacked by a card with an attack higher than this card's health, this card perishes.", "[creature]将为一威高于此牌命之牌所攻时，此牌即死。");
            // 骚扰电话
            AddTranslation("Spam Call", "扰讯");
            // 当[creature]构成完整回路时，其回路内的空位将于持牌人回合结束时生成垃圾邮件卡牌。
            AddTranslation("Empty spaces within a circuit completed by [creature] spawn Spam Mail at the end of the owner's turn.", "[creature]若成完路，则路中空位于持者合终生垃圾邮件牌。");
            // NEO打击
            AddTranslation("NEO Strike", "NEO击");
            // [creature]将攻击敌方所有有造物占据的格子，以及场地边缘所有有造物占据的区域。若未遭遇任何敌方造物，则会发起一次直接攻击。
            AddTranslation("[creature] will strike each opposing space that is occupied by a creature and additionally every side of the board occupied by a creature. It will strike directly if no creatures oppose it.", "[creature]将击敌侧凡有物所据之位，并局侧凡有物所据之处。敌前无物，则直击。");
            // 求救电话
            AddTranslation("A Call for Help", "呼援");
            // 持牌人的回合结束时，[creature]将发起求救电话。
            AddTranslation("At the end of the owner's turn, [creature] will call for help.", "持者合终，[creature]将呼援。");
            // 奋勇突进
            AddTranslation("Run Forth", "前赴");
            // [creature]发起攻击前，其攻击力将被设定为至少1点。
            AddTranslation("Before [creature] attacks, its power will be set to at least 1.", "[creature]攻前，其威至少为一。");
            // 飞行头颅
            AddTranslation("Flying Head", "飞颅");
            // 最为关键的部分。
            AddTranslation("The most important part.", "最要者也。");
            // 垃圾邮车
            AddTranslation("Spam Cart", "垃圾邮车");
            // 垃圾邮件充盈其身，可吞噬各类攻势。
            AddTranslation("Filled with spam mail. Absorbs all kinds of attacks.", "满载垃圾邮件，能受诸攻。");
            // 垃圾邮件
            AddTranslation("Spam Mail", "垃圾邮件");
            // 囊括各类令人印象深刻的交易。
            AddTranslation("Has all kinds of unforgettable deals.", "有诸不忘之贾。");
            // 重炮手
            AddTranslation("Big Shooter", "重炮手");
            // 发射重磅弹药。
            AddTranslation("Shoots big shots.", "发重弹。");
            // 链锁之心
            AddTranslation("Heart on a Chain", "链心");
            // 美丽。
            AddTranslation("Beautiful.", "美。");
            // 扰讯凝胶
            AddTranslation("Spamgel", "扰讯胶");
            // 按F1触发效果。
            AddTranslation("The result of pressing F1.", "按F1之效也。");
            // 手机
            AddTranslation("Hand Phone", "手机");
            // 你真的还需要其他人吗？
            AddTranslation("Do you really need anyone else?", "汝真复须他人乎？");
            // NEO之力！！！
            AddTranslation("THE POWER OF NEO!!!", "NEO之力！！！");
            // 你难道不想成为大人物吗？
            AddTranslation("Don't you wanna be a big shot?", "汝不欲为巨擘乎？");
            // 通讯设备
            AddTranslation("Receiver", "受讯器");
            // 那道声音终将消逝。
            AddTranslation("The voice runs out eventually.", "其声终尽。");
            // 灰熊特惠符
            AddTranslation("Grizzlipis", "灰熊特惠符");
            // 灰熊特惠符。
            AddTranslation("Grizzlipis.", "灰熊特惠符。");
            // 灰熊货车
