            // 我们会收拾掉那些[_spamton_0,蠢货]还有[_spamton_0,家伙]
            AddTranslation("WE'LL TURN THOSE [_spamton_0,SCHMOES] AND [_spamton_0,DAVES]", "我将使彼[_spamton_0,庸徒]与[_spamton_0,家伙]");
            // 变成[_spamton_0,玫瑰坟墓]
