            AddTranslation("[_spamton_1,ROYAL]?", "[_spamton_1,罗亚尔]？");
            // 罗亚尔是[_spamton_0,什么]？罗亚尔是[_spamton_0,谁]？
            AddTranslation("ROYAL [_spamton_0,WHAT]? ROYAL [_spamton_0,WHO]?", "罗亚尔乃[_spamton_0,何]？罗亚尔乃[_spamton_0,谁]？");
            // [_spamton_0,谁/什么/何时/为什么/怎么]是[_spamton_0,罗亚尔]?
            AddTranslation("[_spamton_0,WHO/WHAT/WHEN/WHY/HOW] IS [_spamton_0,ROYAL]?", "[_spamton_0,谁/何/何时/何故/何如]为[_spamton_0,罗亚尔]？");
            // 你太可悲了
            AddTranslation("YOU'RE SO PATHETIC", "汝甚可哀");
            // 隔着一张[_spamton_0,纸牌]，嘀嘀咕咕说着些莫名其妙的胡话
            AddTranslation("MUMBLING NONSENSE WORDS THROUGH A [_spamton_0,PLAYING CARD]", "隔一[_spamton_0,牌]而喃无义之辞");
            // 你真以为自己能[_spamton_0,躲过]那场[_spamton_0,无可避免、步步紧逼]的末日吗？
            AddTranslation("DO YOU THINK YOU CAN [_spamton_0,AVOID] YOUR [_spamton_0,UNAVOIDABLE, QUICKLY APPROACHING] DEMISE?", "汝谓可[_spamton_0,避]汝[_spamton_0,不可避、方迫]之亡乎？");
            // [_spamton_0,就在那儿]
            AddTranslation("[_spamton_0,THERE]", "[_spamton_0,彼处]");
            // 没了你的[_spamton_0,通讯设备]，你又能怎么办？？
            AddTranslation("WHAT ARE YOU GONNA DO WITHOUT YOUR [_spamton_0,COMMUNICATION DEVICE]???", "无汝[_spamton_0,通器]，汝将若何？？？");
            // 等等，难道只有[_spamton_0,我一个人]这么觉得吗？
            AddTranslation("WAIT IS IT JUST [_spamton_0,ME]", "且，独[_spamton_0,我]然思乎");
            // 还是说，听着像是有一艘[_spamton_0,船]正朝着[_spamton_0,我们]这边驶来？？
            AddTranslation("OR DOES IT SOUND LIKE A [_spamton_0,SHIP] IS COMING [_spamton_0,OUR] WAY??", "抑若一[_spamton_0,舟]正向[_spamton_0,我等]来乎？？");
            // 估计只是[_spamton_0,无关紧要]的[_spamton_0,半价清仓]玩意儿罢了。
            AddTranslation("IT'S PROBABLY [_spamton_0,NOTHING] [_spamton_0,AT HALF PRICE]", "殆不过[_spamton_0,无物]之[_spamton_0,半价]耳。");
            // 估计只是我[_spamton_0,脑子里]、[_spamton_0,耳朵里]的幻听罢了。
            AddTranslation("IT'S PROBABLY JUST A SOUND IN MY [_spamton_0,HEAD], IN MY [_spamton_0,EARS]", "殆特我[_spamton_0,首]中、[_spamton_0,耳]中之妄闻耳。");
            // 一艘[_spamton_0,船]怎么可能塞得进这么个狭小的[_spamton_0,出售小屋]里？
            AddTranslation("THERE'S NO WAY A [_spamton_0,SHIP] COULD FIT IN THIS LITTLE [_spamton_0,CABIN FOR SALE]", "一[_spamton_0,舟]安得纳于此小[_spamton_0,鬻庐]中乎？");
            // 你永远都打不败——
            AddTranslation("YOU WILL NEVER DEFEAT-", "汝终不能败——");
            // 向你的[_spamton_0,亲友]说[_spamton_0,永别]吧
            AddTranslation("SAY [_spamton_0,GOODBYE] [_spamton_0,TO YOUR FRIENDS AND FAMILY]", "向汝[_spamton_0,亲友]告[_spamton_0,别]罢");
            // 那股[_spamton_0,NEO之力]，根本不是你能招架得住的
            AddTranslation("THE [_spamton_0,POWER OF NEO] WAS TOO MUCH FOR YOU", "[_spamton_0,NEO之力]，非汝所能当也");
            // 机密
            AddTranslation("CONFIDENTIAL", "机密");
            // 被一个弱不禁风的人类打败了……
            AddTranslation("DEFEATED BY A WEAKLING HUMAN...", "竟为孱人所败……");
            // 不！！！！！！
            AddTranslation("NOOOOOOOOOOOOOOO!!!!!!", "不！！！！！！");
        }

    }


