    public class LegendsFromTheDarknessMod
    {
        public static void RegisterTranslations()
        {
            // 来自黑暗的传说
            AddTranslation("Legends From The Darkness", "闇中诸传");
            // 一套约[count]张的卡牌合集，内容随机收录各类动物、神话角色与都市传说相关形象。
            AddTranslation("A collection of around [count] cards consisting of a random assortment of animals, myths and urban legends.", "约[count]牌之汇也，杂收诸兽、神话与都邑异谈。");
            // 鲭鲨
            AddTranslation("Mako Shark", "鲭鲨");
            // 迅捷的鲭鲨，敏捷的海洋掠食者。
            AddTranslation("The swift Mako, an agile sea predator.", "鲭鲨迅捷，海中捷猎也。");
            // 强壮的美洲狮，凶猛的生灵。
            AddTranslation("The robust Puma, a fierce creature.", "美洲狮壮而猛也。");
            // 贪婪生物产下的可怖后裔。
            AddTranslation("A hideous offspring of a voracious creature.", "饕物所产之丑裔。");
            // 阿维佐特尔
            AddTranslation("Ahuizotl", "阿维佐特尔");
            // 一种奇特的生物。我好奇那条尾巴是否有特殊之处。
            AddTranslation("A peculiar creature. I wonder if that tail is special.", "异物也，不知其尾有奇乎。");
            // 阿维佐特尔之尾
            AddTranslation("Ahuizotl Tail", "阿维佐特尔尾");
            // 潜藏在阴郁水域之中，凶猛的短吻鳄会逼近胆敢靠前的生灵。
            AddTranslation("Hiding in dismal waters, the ferocious alligator approaches those who dare get close.", "匿于惨水，猛鳄逼近敢前之物。");
            // 鮟鱇鱼
            AddTranslation("Angler Fish", "鮟鱇");
            // 别让那迷人的光芒欺骗了你。
            AddTranslation("Don't let that glamorous shine decieve you.", "毋为其妍辉所欺。");
            // 蚁狮
            AddTranslation("Antlion", "蚁狮");
            // 自动机器人
            AddTranslation("Automaton", "自机");
            // 这台锈蚀机械外露的电线，会电击所有胆敢进犯的敌人。
            AddTranslation("The rusted machine's exposed wires shock any would-be aggressor", "彼锈机露线，凡欲犯者皆为所电。");
            // 拥有再生能力的海洋掠食者，这永恒的幼体若真的成熟，将会发生什么？
            AddTranslation("the regenerative sea predator, what would happen if the eternal juvenile were to reach maturity?", "彼能再生之海猎，若永幼者竟至于成，将若何？");
            // 甲虫
            AddTranslation("Beetle", "甲虫");
            // 甲虫那无可匹敌的力量，能将其他造物击飞。
            AddTranslation("The unsurpassable strength of the beetle knocks creatures away.", "甲虫之力莫逾，能击却诸物。");
            // 臃肿者
            AddTranslation("Bloater", "胀者");
            // 对这个特殊的存在而言，是一场不幸的殒命。
            AddTranslation("An unfortunate demise to this particular being.", "于此物则为不祥之殒。");
            // 蚺
            AddTranslation("Boa", "蚺");
            // 绞杀的蚺蛇缠住猎物，绝不松脱。
            AddTranslation("The constricting Boa ensnares its prey and won't let go.", "蚺既缠其禽，终不释。");
            // 投弹虫
            AddTranslation("Bombardier", "投弹虫");
            // 这只怪异的甲虫携带着剧毒喷雾，会向攻击者反击。
            AddTranslation("Armed with a noxious spray, this odd beetle retaliates against its aggressors.", "此异甲虫挟毒雾，凡犯之者皆受其报。");
            // 布拉西
            AddTranslation("Braxie", "布拉西");
            // 游荡的布拉西散发着可怕的恶臭，削弱它遇到的一切威胁。
            AddTranslation("The wandering Braxie's horrid stench weakens any threat it encounters.", "游布拉西之恶臭，凡所遇威胁皆衰。");
            // 非洲水牛
            AddTranslation("Cape Buffalo", "海角水牛");
            // 复仇的野牛，攻击它将会是个可悲的决定。
            AddTranslation("The Vengeful Buffalo, attacking it is a woeful decision.", "复仇之牛，攻之甚悔。");
            // 薮犬
            AddTranslation("Bush Dog", "薮犬");
            // 曾被认为已灭绝，这种诡秘的薮犬通常成群出没。
            AddTranslation("Thought to be extinct, the Illusive Bush Dog is normally found in packs.", "昔以为绝，薮犬诡行，常群见之。");
            // 卡德霍
            AddTranslation("Cadejo", "卡德霍");
            // 受命运无常所缚，你的守护者要么仁慈，要么邪恶。
            AddTranslation("Bound to chance, your guardian will be either benign or maleficent.", "系于偶，汝守者或善或恶。");
            // 卡马佐茨
            AddTranslation("Camazotz", "卡马佐茨");
            // 冥界诸主的仆从，与黑暗、死亡……以及“献祭”相连。
            AddTranslation("A servant to the lords of the underworld, associated with darkness, death... and 'sacrifice'.", "冥府诸主之仆也，与闇、死……及“祀”相属。");
            // 骆驼的“唾沫”足以让大多数攻击者失明。
            AddTranslation("The \"spit\" of the camel is enough to blind most aggressors.", "驼“唾”足使多犯者盲。");
            // 木蠹蛾
            AddTranslation("Carpenter Moth", "木蠹蛾");
            // 足智多谋的木蠹蛾，能从石头中榨出血液。
            AddTranslation("The resourceful carpenter, able to draw blood from stone.", "此蠹善营，能凿石取血。");
            // 鲜有生灵能追上这迅捷的猎豹。
            AddTranslation("few are able to catch the nimble cheetah.", "鲜有能及捷豹者。");
            // 这不起眼的小鸡，其肉对大多数生物而言都极具滋补。
            AddTranslation("The humble chicken, its meat is nourishing for most creatures.", "鸡虽微，其肉多能养诸物。");
            // 卓柏卡布拉
            AddTranslation("Chupacabra", "卓柏卡布拉");
            // 可怕的卓柏卡布拉。它觊觎着你的家畜。
            AddTranslation("the horrid chupacabra. It hungers for your livestock.", "卓柏卡布拉甚可畏，饥于汝牲畜。");
            // 这烦人的蝉，用响亮的鸣叫声召唤同类。
            AddTranslation("The ever-bothersome cicada, using its loud buzzing to summon its kin.", "蝉恒聒耳，以其大鸣召同类。");
            // 布料
            AddTranslation("Cloth", "布");
            // 神秘莫测的云豹。猫科动物中缺失的一环。
            AddTranslation("the mystifying Clouded Leopard. The missing link between the cat family.", "云豹神诡，猫属所缺之一环。");
            // 雪茄达摩鲨
            AddTranslation("Cookiecutter", "达摩鲨");
            // 螃蟹
            AddTranslation("Crab", "蟹");
            // 身披甲壳的甲壳动物。螃蟹的硬壳能为它抵挡致命一击。
            AddTranslation("an armored crustacean. The crab's carapace covers it from fatal blows.", "披甲之介也，蟹壳能蔽其致命之击。");
            // 箭毒蛙
            AddTranslation("Dart Frog", "箭毒蛙");
            // 攻击这种生物绝非明智之举。
            AddTranslation("It is Ill-advised to attack this creature.", "攻此物者非智也。");
            // 土堆
            AddTranslation("Dirt Pile", "土堆");
            // 多尔胡
            AddTranslation("Dobhar-chu", "多尔胡");
            // 水獭之王。多尔胡需要进食来成长。
            AddTranslation("the king of the otters. The Dobhar-chu requires sustenance to grow.", "水獭之王也，多尔胡须食以长。");
            // 威严的雄鹰，天空中敏锐的守护者。
            AddTranslation("The onerous eagle, a keen guard of the sky. ", "雄鹰威然，为天之敏卫。");
            // 这样一种生物，究竟是如何学会将电能当作武器的？
            AddTranslation("How did such a creature learn to use electricity as a weapon?", "如此之物，何以学电为兵乎？");
            // 苏醒丧尸
            AddTranslation("Emerging Zombie", "起尸");
            // 活泼矫健的游隼，渴望以极速发起攻击。
            AddTranslation("The sprightly falcon, eager to attack in a breakneck pace", "鹘轻捷，欲疾击。");
            // 栖于树上的渔貂。
            AddTranslation("The arboreal Fisher Cat", "栖木之渔貂。");
            // 渔貂
            AddTranslation("Fisher Cat", "渔貂");
            // 赤狐，生来便具狡诈之性。
            AddTranslation("The red fox, born with a deceitful nature.", "赤狐，生而狡。");
            // 石像鬼
            AddTranslation("Gargoyle", "石像鬼");
            // 一头可怖的人造凶兽，人类难道就毫无底线吗？
            AddTranslation("A horrid man-made beast, does humanity know no limit?", "人所造之怪兽，可畏；人其无极乎？");
            // 由阵亡将士之魂高耸集结而成的存在，自灵魂纯粹的恨意中苏醒。
            AddTranslation("The towering culmination of spirits of fallen soldiers, risen from pure hatred in their souls.", "阵没之士魂积而高起，纯出于其魂之恨。");
            // 缟灵猫
            AddTranslation("Genet", "缟灵猫");
            // 身形纤细的缟灵猫能悄悄溜过空袭造物。
            AddTranslation("The slender Genet can sneak past airborne creatures.", "缟灵猫纤，能潜过空袭之物。");
            // 巨型龙虾
            AddTranslation("Giant Lobster", "巨龙虾");
            // 永恒的寿命，会令生物发生可怕的异变。
            AddTranslation("An eternal lifespan can lead to dire changes in a creature.", "永寿足致物之巨变。");
            // 哥布林
            AddTranslation("Goblin", "哥布林");
            // 永远饥肠辘辘的贪婪小恶魔。他会给你一件物品……但代价必不可少。
            AddTranslation("The ever-hungry imp of greed. He shall give you an item... But not without a cost.", "贪饕之小魔，恒饥；彼将予汝一器……然非无直。");
            // 鹅
            AddTranslation("Goose", "鹅");
            // 这只虚张声势的鹅，极少有造物能拆穿它的把戏。
            AddTranslation("The phoney goose. Rarely will a creature call its bluff.", "诈鹅也，鲜有物能发其诈。");
            // 巫骸
            AddTranslation("Haggard", "巫骸");
            // 这令人憎恶的巫骸，是一头丑陋臃肿的卑劣凶兽。
            AddTranslation("the abominable Haggard, a wretched hulking beast.", "巫骸可憎，丑而巨之兽也。");
            // 锤头鲨
            AddTranslation("Hammerhead", "锤鲨");
