            AddTranslation("\"It's all about the sport\" he claims, though his true intentions still remain a mystery.", "“但为戏耳。”其自言如是，然其真意犹未可知。");
            // 狩猎宝典
            AddTranslation("The Hunter's Bible", "猎者经");
            // 鬣蜥
