            AddTranslation("[e:3]does he just", "[e:3]彼常");
            // [e:3]干这种事吗？
            AddTranslation("[e:3]do this regularly?", "[e:3]为此乎？");
            // 忠告，
            AddTranslation("word of advice,", "一言相告，");
            // 除非你拥有
            AddTranslation("unless you got", "若汝无");
            // 不死之虫印记的卡牌，
            AddTranslation("something like unkillable..", "“不死”之类……");
            // [e:2]尽量别在
            AddTranslation("[e:2]try not to waste", "[e:2]莫");
            // 第一回合浪费你的好牌。
            AddTranslation("your good cards in phase 1.", "于首段费汝善牌。");
            // [e:3]又是这家伙……
            AddTranslation("[e:3]This guy again...", "[e:3]又此人……");
            // 你大概知道
            AddTranslation("you probably know", "汝盖已知");
            // 老规矩了。
            AddTranslation("the drill by now.", "其常矣。");
            // [e:2]天啊……
            AddTranslation("[e:2]God...", "[e:2]天……");
            // [e:2]这地方臭得像死尸一样。
            AddTranslation("[e:2]it reeks like death.", "[e:2]臭若死尸。");
            // [e:3]别告诉我那些
            AddTranslation("[e:3]don't tell me those", "[e:3]毋告我彼");
            // [e:3]是真的死鱼。
            AddTranslation("[e:3]are real dead fish.", "[e:3]果真死鱼。");
            // 又是这个头目……
            AddTranslation("This boss again...", "又此魁……");
            // [e:2]很好……
            AddTranslation("[e:2]great....", "[e:2]善……");
            // 你懂的，
            AddTranslation("you know the drill,", "汝知其常，");
            // 使用松鼠
            AddTranslation("throw a squirrel", "投一松鼠");
            // 或其他东西
            AddTranslation("or something when", "或他物，于彼");
            // 当他出鱼钩的时候。
            AddTranslation("he takes out the hook.", "出钩之时。");
            // [e:2]知道了知道了……
            AddTranslation("[e:2]yadda yadda..,", "[e:2]知矣知矣……");
            // 你不会有事的。
            AddTranslation("you should be fine.", "汝当无患。");
            // 我是真的烦透这家伙了。
            AddTranslation("I'm honestly sick of this one.", "我诚厌此人矣。");
            // [e:4] 猎人，对吗？[w:2]
            AddTranslation("[e:4] Trapper, huh? [w:2]", "[e:4] 猎夫乎？[w:2]");
            // [e:3]我有一种不好的预感。
            AddTranslation("[e:3]I got a bad feeling about this.", "[e:3]我有不祥之感。");
            // 赶紧了结这一切吧。
            AddTranslation("let's get this over with.", "速毕此事罢。");
            // 又是猎人，
            AddTranslation("trapper again,", "又猎夫，");
            // [e:2]很好……
            AddTranslation("[e:2]great...", "[e:2]善……");
            // [e:4]哈……
            AddTranslation("[e:4]huh...", "[e:4]咦……");
            // 这些毛皮看着或许有用。
            AddTranslation("these pelts might seem helpful.", "此诸革似可为助。");
            // [e:2]让我们了结它。
            AddTranslation("[e:2]let's end this.", "[e:2]了此罢。");
            // 我们终于到地方了……
            AddTranslation("we're finally here..", "我等终至此矣……");
            // 你可以的，兄弟。
            AddTranslation("You got this, man.", "汝能之，子。");
            // [e:1] 我相信你。
            AddTranslation("[e:1] I believe in you.", "[e:1] 我信汝。");
            // [e:2] 天哪，我快吐了
            AddTranslation("[e:2] god I'm sick", "[e:2] 天，我厌");
            // 受够这家伙了。
            AddTranslation("[e:2]of this guy.", "[e:2]此人久矣。");
            // 求你赢下这局。
            AddTranslation("please win.", "愿汝胜之。");
            // 这次我感觉
            AddTranslation("I'm feeling", "我今");
            // 挺乐观的。
            AddTranslation("optimistic this time.", "颇乐观。");
            // [e:1] 我觉得你能行。
            AddTranslation("[e:1] I think you got this.", "[e:1] 我谓汝能之。");
            // 磷火
            AddTranslation("Wisp", "燐火");
            // 纯火之灵，其中一类需凭燃料方能成长。
            AddTranslation("a spirit of pure fire, one of which requires fuel to grow.", "纯火之灵也，其一须藉薪而长。");
            // 修洛特
            AddTranslation("Xolotl", "修洛特");
            // 那邪恶的薄暮之神，曾被放逐至孱弱的两栖身躯之中，现已挣脱远古枷锁，再度苏醒。
            AddTranslation("The sinister god of twilight, banished into the bodies of meager amphibians, has risen from his ancient shackles.", "邪暮之神，昔谪于孱弱两栖之躯，今已脱古桎而起。");
            // 斑马
            AddTranslation("Zebra", "斑马");
            // 这只刻毒的斑马，会不惜一切代价杀死任何企图伤害它的存在。
            AddTranslation("The vitriolic zebra will stop at nothing to kill whatever is there to harm it.", "斑马刻毒，将不惜一切以杀害之者。");
            // 冷酷的丧尸，一个受罚的灵魂，被迫永世徘徊。
            AddTranslation("The grim zombie, a punished soul forced to wander for eternity.", "丧尸阴惨，一受罚之魂，迫而永徊。");
            // 帝企鹅
            AddTranslation("Emporer Penguin", "帝企鹅");
            // 云豹
            AddTranslation("Clouded Leopard", "云豹");

            // sigils
            // 顶级掠食者
            AddTranslation("Apex Predator", "魁猎");
            // 献祭2张牌，使[creature]的攻击力+1。
            AddTranslation("Sacrifice 2 cards to boost [creature]'s attack by 1.", "祀二牌，使[creature]威加一。");
            // 骨冲留冢
            AddTranslation("Bonepile Strafe", "遗骨徙");
            // 持牌人的回合结束时，[creature]会向印记标注方向移动，并在原地留下一堆骨头。
            AddTranslation("At the end of the turn, [creature] will move, leaving a pile of bones in it's place.", "合终，[creature]将徙，遗一堆骨于故处。");
            // 持牌人的回合结束时，[creature]会向印记标注方向移动，并在原地留下一堆骨头。
            AddTranslation("At the end of the turn, the sigil bearer will move, leaving a pile of bones in it's place.", "合终，负此印者将徙，遗一堆骨于故处。");
            // 当放置[creature]时，获得一张橡果卡牌，橡果具有：1点生命，幼雏。
            AddTranslation("Upon placing the sigil bearer, draw an acorn. An acorn is defined as: 1 health, fledgling.", "负此印者既陈，引一橡实。橡实者：一命，幼雏。");
            // 对手回合结束时，[creature]所在的区域会被尸潮替换。
            AddTranslation("at the end of the enemy's turn, the card owner's board is fully replaced with a 'the horde'.", "敌合终，主持一侧尽易为“尸潮”。");
            // 当[creature]被放置时，持牌人一侧的剩余空位将被蝉群填满。
            AddTranslation("Summons a cicada swarm on the owner's board, placing cicada cards on their side wherever it can.", "既陈，则主持一侧凡可置处皆满以蝉群。");
            // 温迪戈伏击
            AddTranslation("Wendigo's Ambush", "温迪戈伏袭");
            // 在我的回合结束时，温迪戈将会移到你的场上。
            AddTranslation("The wendigo will move to your board at the end of my turn.", "我合终，温迪戈将徙于汝局。");
            // 背负如此众多的骸骨，乃是沉重的负担。
            AddTranslation("A heavy burden to carry all those bones.", "负此众骨，担甚重也。");
            // 一个可怜的灵魂，唤醒了那头巨兽。
            AddTranslation("A poor soul has awakened the beast.", "可怜之魂醒此兽矣。");
            // 猛禽
            AddTranslation("Bird of Prey", "攫禽");
            // 每当[creature]宣告攻击时，所有被其击中的空袭卡牌各受到1点伤害，并使其空袭印记失效。
            AddTranslation("Flying cards struck by [creature] will take 1 damage each time it declares an attack, and renders their wings useless.", "凡为[creature]所击之空袭牌，每其宣攻，各受伤一，且其翼俱废。");
            // 每当[creature]宣告攻击时，所有被其击中的空袭卡牌各受到1点伤害，并使其空袭印记失效。
            AddTranslation("Flying cards struck by the sigil bearer will take 1 damage each time it declares an attack, and renders their wings useless.", "凡为负此印者所击之空袭牌，每其宣攻，各受伤一，且其翼俱废。");
            // 苍穹哨卫，镇锁长空。
            AddTranslation("A sentry of the skies, keeping things grounded.", "天哨也，使众不飞。");
            // 唤犬术
            AddTranslation("Dog Summon", "唤犬");
            // 放置[creature]时，其将会移动至相邻的空位，并在原地留下一只寻血猎犬。
            AddTranslation("The sigil bearer will move to an empty adjacent slot and leave a bloodhound.", "负此印者将徙于相邻空位，而遗一寻血犬。");
            // 她看上去不美吗？
            AddTranslation("doesn't she look beautiful?", "彼不美乎？");
            // 真是急躁……
            AddTranslation("So impatient....", "何其躁也……");
            // 感染
            AddTranslation("Infested", "寄染");
            // 当[creature]受到攻击时，将一只寄生虫加入你的手牌。
            AddTranslation("When [creature] is struck, draw a parasite into your hand.", "[creature]见击，则引一寄虫入手。");
            // 宿主是仍活着，还是仅仅被操控着？最好别知晓答案。
            AddTranslation("is the host alive or merely being puppeted? Best not to know.", "宿主尚生，抑徒为所御乎？毋知为善。");
            // 尖啸之吼
            AddTranslation("Shrieker's call", "啸者之呼");
            // 对手回合结束时，[creature]所在的区域会被尸潮替换。
            AddTranslation("When the opponent's turn ends, [creature]'s board is replaced with a zombie horde.", "敌合终，[creature]所在一侧易为尸潮。");
            // 痛苦的尖啸响彻四方。
            AddTranslation("A painful screech is echoed throughout.", "苦啸四彻。");

            // encounters
            // 驯鹿
            AddTranslation("Caribou", "驯鹿");
            // 爱波瑞吉
            AddTranslation("Alebrije", "爱波瑞吉");
            // 食蚁兽
            AddTranslation("Anteater", "食蚁兽");
            // 凯门鳄
            AddTranslation("Caiman", "凯门鳄");
            // 小驯鹿
            AddTranslation("Caribou Fawn", "驯鹿子");
            // 神鹫
            AddTranslation("Condor", "神鹫");
            // 龙虾哥斯拉
            AddTranslation("Lobsterzilla", "龙虾哥斯拉");
            // 长颈鹿
            AddTranslation("Giraffe", "长颈鹿");
            // 财宝堆
            AddTranslation("Gold Pile", "金堆");
            // 漏泄者
            AddTranslation("Leaker", "漏者");
            // 弥诺陶洛斯
            AddTranslation("Minotaur", "弥诺陶洛斯");
            // 死神
            AddTranslation("Reaper", "死神");
            // 犀牛
            AddTranslation("Rhino", "犀");
            // 尖啸者
            AddTranslation("Shrieker", "啸者");
            // 最好在它发出尖啸前将其击倒。
            AddTranslation("it's best to take it down before it launches its cry.", "宜先击之，毋使其发啸。");
            // 石墙
            AddTranslation("Stone Wall", "石垣");
            // 荆棘
            AddTranslation("Brambles", "荆棘");
            // 来自黑暗的传说：遭遇战
            AddTranslation("Legends From The Darkness: Encounters", "闇中诸传：遭遇");
            // 为《来自黑暗的传说》打造的持续更新内容包，旨在为游戏新增遭遇战。
            AddTranslation("an Ever-expanding content pack for LFTD, meant to add battle encounters to the game.", "为 LFTD 所作之续拓牌韬也，以增遭遇于此戏。");
        }

    }

    public class GarethMod
    {
        public static void RegisterTranslations()
        {
            // 加雷斯的模组
            AddTranslation("Gareth's Mod", "Gareth氏补缀");
            // 由Gareth48制作、Plutraser绘制插画的第一章补充卡包。新增26张卡牌与7种特殊印记，设计风格完美融入原版《邪恶冥刻》的体系。
            AddTranslation("A part 1 booster pack created by Gareth48 and illustrated by Plutraser. Adds [count] cards and 7 sigils designed to fit right into vanilla Inscryption.", "Gareth48作之、Plutraser绘之第一章补牌韬。增[count]牌与七印契，其制可径入原本《冥锲》。");
            // 加雷斯48
            AddTranslation("Gareth48", "Gareth48");
            // 抱歉，无法这样做
            AddTranslation("Sorry, can't do that", "歉，不能然。");
            // 他这……是在做什么？
            AddTranslation("Whats... he doing here?", "彼……何为在此？");
            // 皮行者
            AddTranslation("Skinwalker", "皮行者");
            // 神秘的皮行者。它会模仿被其击杀的第一个生物的身份。
            AddTranslation("The enigmatic skinwalker. It mimics the identity of the first creature it slays.", "皮行者玄异，摹其所杀之首物之形名。");
            // 受伤的动物
            AddTranslation("Wounded Animal", "伤兽");
            // 饥饿捕食者的轻易目标。
            AddTranslation("An easy target for hungry predators.", "饥兽之易禽。");
            // 旅鼠
            AddTranslation("Lemming", "旅鼠");
            // 多疑的旅鼠。体质脆弱，是许多动物眼中的美味点心。
            AddTranslation("The paranoid lemming. Fragile and a favorite treat among many animals.", "多疑之旅鼠，躯脆而为诸兽所甘食。");
            // 树精
            AddTranslation("Treant", "树灵");
            // 这只造物是怎么来到这里的？
            AddTranslation("How did this creature get here?", "此物何以来此？");
            // 障碍
            AddTranslation("Snag", "枝障");
            // 树苗
            AddTranslation("Sapling", "苗木");
            // 假以时日，再渺小的树苗也会长成巨大、威严的障碍。
            AddTranslation("With time, even the smallest sapling becomes a massive, imposing obstacle.", "假以时日，微苗亦成巨而可畏之障。");
            // 牛椋鸟
            AddTranslation("Oxpecker", "牛椋鸟");
            // 备受喜爱的牛椋鸟。这是一只能与最凶猛的敌人化敌为友的造物。
            AddTranslation("The adored Oxpecker. A bird capable of befriending even the fiercest of foes.", "牛椋鸟见爱，虽至猛之敌亦能与之为友。");
            // 健壮的大象。性情温顺，却并不弱小。
            AddTranslation("The sturdy elephant. Friendly but not weak.", "象壮而驯，然非弱也。");
            // 狂笑的鬣狗。它总有一名盟友潜伏在阴影之中。
            AddTranslation("The cackling hyena. It always has an ally lurking in the shadows.", "鬣狗笑啸，恒有一盟友伏于影中。");
            // 好斗的黑豹。从不会在战斗中退缩。
            AddTranslation("The aggressive panther. Never one to back down from a fight.", "黑豹好斗，未尝退于战。");
            // 黑豹幼崽
            AddTranslation("Panther Cub", "豹幼");
            // 年幼的黑豹。即便此刻，它的警惕也从未动摇。
            AddTranslation("The young panther. Even now its caution is unwavering", "豹幼虽少，其警未尝弛。");
            // 袋獾
            AddTranslation("Tasmanian Devil", "袋獾");
            // 凶残的袋獾。一种凶猛且食欲旺盛的食肉造物。
            AddTranslation("The vicious Tasmanian devil. A fierce carnivore with a voracious appetite.", "袋獾凶甚，肉食而饕。");
            // 射水鱼
            AddTranslation("Archerfish", "射水鱼");
            // 射水鱼是出色的射手，能用水箭将空中的昆虫射落。
            AddTranslation("The archerfish, an excellent marksman, known to shoot bugs out of the air with a blast of water.", "射水鱼善中的，以水矢射空中之虫。");
            // 长戟大兜虫
            AddTranslation("Hercules Beetle", "长戟大兜虫");
            // 力大无穷的长戟大兜虫。它能搬动比自身大上数倍的造物。
            AddTranslation("The forceful Hercules beetle. It can move creatures many times its size.", "长戟大兜虫力强，能移大于己数倍之物。");
            // 魔像
            AddTranslation("Golem", "魔像");
            // 古老的魔像。束缚它的魔法古老却强大，死亡后会再度重塑。
            AddTranslation("An ancient golem. The magic that binds it is old but powerful. It will reform after death.", "古魔像也，缚之之术旧而强，死后复成。");
            // 令人敬畏的雄狮。定能带领你的造物走向胜利。
            AddTranslation("The awe-inspiring lion. Sure to lead your creatures to victory.", "雄狮可畏，必能率汝诸物以胜。");
            // 幼狮
            AddTranslation("Juvenile Lion", "幼狮");
            // 狮崽
            AddTranslation("Lion Cub", "狮崽");
            // 如王子般的狮崽。假以时日，它必将成为狮群之王。
            AddTranslation("The princely lion cub. Given time it will become the king of its pride.", "狮崽若王子，假以时日，必为其群之王。");
            // 水虎鱼
            AddTranslation("Piranha", "水虎鱼");
            // 凶猛的水虎鱼。成群结队时能在瞬间吞噬任何活物。
            AddTranslation("The ferocious piranha. Schools can devour any living thing in seconds.", "水虎鱼猛，群至则顷刻食尽生物。");
            // 隐秘的花豹。猎物察觉时，往往已来不及逃脱。
            AddTranslation("The stealthy leopard. Invisible to its prey until it's too late.", "豹潜，及禽觉之，则已晚矣。");
            // 杀手蜂群
            AddTranslation("Killer Bee Swarm", "杀蜂群");
            // 凶残的杀手蜂。反抗得越激烈，蜂群就越多。
            AddTranslation("The vicious killer bee. The more one fights the more will swarm.", "杀蜂甚凶，愈拒愈集。");
            // 贪婪的野猪。它的饥饿永无止境，会不断吞食，直到一切化为乌有。
            AddTranslation("The ravenous pig. Its hunger is insatiable, it will eat and eat until nothing remains.", "豕饕，食无厌，噬噬至无馀。");
            // 獾
            AddTranslation("Badger", "獾");
            // 惹人厌的獾。迅猛出击，随即退回阴影之中。
            AddTranslation("The bothersome badger. Quick to strike and retreat back into the shadows.", "獾可厌，疾击而复退于影。");
            // 短尾猫
            AddTranslation("Bobcat", "短尾猫");
            // 狡诈的短尾猫。勇于捍卫领地，也懂得何时撤退。
            AddTranslation("The wily bobcat. Unafraid to defend its territory but smart enough to know when to retreat.", "短尾猫狡，敢卫其地，亦知何时退。");
            // 迅捷的蜻蜓。如此疾速的昆虫，鲜有能击中者。
            AddTranslation("The hasty dragonfly. Few can hit an insect this fast.", "蜻蜓甚迅，鲜有能中之者。");
            // 盟友
            AddTranslation("Allies", "盟友");
            // 当[creature]阵亡时，一名随机盟友会暂时加入你的手牌，为其复仇。
            AddTranslation("When a creature bearing this sigil dies, a random ally will temporarily join your hand to avenge it.", "负此印者死，则一偶得之盟友暂入汝手，以复其仇。");
            // 似乎有造物为了向盟友复仇而来。
            AddTranslation("It seems a creature has come to avenge the passing of its ally.", "似有一物为复其盟友之仇而来。");
            // 精髓窃取
            AddTranslation("Essence Steal", "夺精");
            // 当[creature]击杀另一造物时，其会变身为它的完美复制体。
            AddTranslation("When a creature bearing this sigil kills another, it transforms into an exact copy of it.", "负此印者杀他物，则化为其全肖。");
            // 你的造物击杀了我的造物，现在它将化作后者的仿制品。
            AddTranslation("Your creature has slain mine, and will now become an imitation of it.", "汝物既杀我物，今将化肖彼。");
            // [creature]攻击后，由持牌人选择一个空格，该造物便会移动至该处。
            AddTranslation("After a creature bearing this sigil attacks the user chooses a space. The creature will move to that space.", "负此印者攻后，持者择一位，其物徙焉。");
            // 它在攻击后撤退了，或许是在重整力量，准备再次突袭。
            AddTranslation("It retreated after it struck, perhaps it's regathering its strength for another strike.", "既击而退，殆将聚力以再袭。");
            // 饥饿
            AddTranslation("Hungry", "饕");
            // 当放置[creature]时，选择另一个友方造物将其吞噬。被吞噬造物的生命与力量会加在[creature]身上。
            AddTranslation("When a creature bearing this sigil is played, choose another friendly creature to eat. The eaten creature will have its health and power added to the creature bearing this sigil.", "负此印者既陈，择一友物而食之。所食者之命与威，加于此物。");
            // 看来吞噬另一具造物，让你的造物变得更强大了。
            AddTranslation("It seems eating another creature has caused yours to grow stronger.", "食他物，似使汝物益强。");
            // 推挤
            AddTranslation("Shove", "推");
            // 当放置[creature]时，会向前移动至正对的位置。挡路的造物会被朝同一方向推动。
            AddTranslation("When a creature bearing this sigil is played, it will move up to the space opposing it. Creatures that are in the way will be pushed in the same direction.", "负此印者既陈，将进至其所对之位。碍路之物，皆同向为之所推。");
            // 你的盟友也太反复无常了。
            AddTranslation("You have such fickle allies.", "汝盟友反覆若此。");
            // 冷傲
            AddTranslation("Standoffish", "倨");
            // 当[creature]有敌对的造物时，[creature]获得两点攻击力。
            AddTranslation("As long as a creature bearing this sigil is opposed by another, it has +2 attack.", "负此印者对敌时，威加二。");
            // 鲜美可食
            AddTranslation("Tasty", "可食");
            // 当[creature]阵亡时，会有一只随机造物出现并将其吞噬。
            AddTranslation("When a creature bearing this sigil dies, a random creature shows up to devour it.", "负此印者死，则一偶物见而食之。");
            // 你的造物会拼尽一切战斗，直到再无敌人。
            AddTranslation("Your creature will fight with all it has until none oppose it.", "汝物将尽力而战，至无敌对者。");
            // 看来又有一只造物前来觅食了，生命的循环仍在继续。
            AddTranslation("It seems that another animal has come to feed. The cycle of life continues.", "又有一物来食，生之循环不息。");
            // 真奇怪，我好像……不记得这只造物了。
            AddTranslation("Curious, I don't seem to remember this creature...", "怪哉，我似不忆此物……");
        }

    }


    public class LifeCostAPIMod
    {
        public static void RegisterTranslations()
        {
            // 莱克
            AddTranslation("Leck", "莱克");
            // 迷途之兽，形如牙齿，仅因错误出现。
            AddTranslation("The Lost Beast, in the shape of a tooth, showing up only in error.", "迷兽也，形若齿，仅以误而见。");
            // 梅克
            AddTranslation("Meck", "梅克");
            // 泰克
            AddTranslation("Teck", "泰克");
            // 你没有足够的[c:bG]生命[c:]或[c:gray]箔片[c:]来打出这张牌。对对手造成伤害以获得更多[c:bG]生命[c:]。
            AddTranslation("You do not have enough [c:bG]Life[c:] or [c:gray]Foils[c:] to play that. Damage your opponent to gain more [c:bG]Life[c:].", "汝[c:bG]生命[c:]或[c:gray]箔[c:]不足，不得陈此。伤汝敌以益[c:bG]生命[c:]。");
            // 你的天平上没有足够的[c:bG]生命[c:]来打出这张牌。对对手造成伤害以获得更多[c:bG]生命[c:]。
            AddTranslation("You do not have enough [c:bG]Life[c:] on your scales to play that. Damage your opponent to gain more [c:bG]Life[c:].", "汝衡上[c:bG]生命[c:]不足，不得陈此。伤敌以益[c:bG]生命[c:]。");
            // 你没有足够的[c:gray]箔片[c:]来打出这张牌。你可以通过造成过量伤害来获得[c:gray]箔片[c:]。
            AddTranslation("You do not have enough [c:gray]Foils[c:] to play that. You gain [c:gray]Foils[c:] by dealing overkill damage.", "汝[c:gray]箔[c:]不足，不得陈此。行溢伤以得[c:gray]箔[c:]。");
            // 最大能量豪赌
            AddTranslation("Max Energy Gamble", "极能豪赌");
            // 消耗6点能量，在目标一侧的天平上放置0至3点伤害。
            AddTranslation("Pay 6 energy to put 0 to 3 damage on someone's side of the scale", "输六能，于一侧衡上置零至三伤。");
            // 掷骰子
            AddTranslation("Die Roll", "掷骰");
            // 以钱换血
            AddTranslation("Money for Blood", "以财市血");
            // 支付5点生命/箔片，随机将0至6点属性增幅分配到各项属性上。
            AddTranslation("Pay 5 Life/Foils to gain between 0 and 6 increase in stats, distributed randomly", "出五生命/箔，随机分零至六之数于诸数上。");
            // 唱一遍，再一遍，掷出骰子搏个变！
            AddTranslation("Sing it once, Sing it twice, take a chance and roll the dice!", "歌一再歌，掷骰以试命！");
            // 现金转换器
            AddTranslation("Cash Converter", "财易器");
            // 支付4枚箔片，在对手一侧的天平上放置1点伤害。
            AddTranslation("Pay 4 foils to put 1 damage on your opponent's side of the scale", "出四箔，于敌侧之衡置伤一。");
            // 生命转换器
            AddTranslation("Life Converter", "命易器");
            // 支付2点生命，获得1枚箔片。
            AddTranslation("Pay 2 life to gain 1 foils", "出二命，得一箔。");
            // 吸血之力
            AddTranslation("Vamperic Strength", "饮血之力");
            // 支付3点生命，使[creature]的攻击力和生命值各+1。
            AddTranslation("Pay 3 life to increase the power and health of this card by 1", "出三命，使此牌威与命各加一。");
            // 以血换钱
            AddTranslation("Blood for money", "以血市财");
            // 自残可提升力量。
            AddTranslation("Hurting oneself can lead to an increase in strength.", "自伤可益威。");
            // 贪婪之力
            AddTranslation("Greedy Strength", "贪力");
            // 支付5点货币，使[creature]的攻击力和生命值各+1。
            AddTranslation("Pay 5 currency to increase the power and health of this card by 1", "出五货，使此牌威与命各加一。");
            // 侵蚀一切触碰之物的水洼。
            AddTranslation("A puddle that errods all that touches it.", "一洼蚀凡所触者。");
            // 可受雇执行多种任务。
            AddTranslation("One can be hired to do many tasks", "可雇以任众事。");
        }

    }


    public class EriCardExpansionMod
    {
        public static void RegisterTranslations()
        {
            // 熊崽
            AddTranslation("Young Bear", "熊子");
            // 一只年幼的灰熊，已足够强壮可以自保。
            AddTranslation("A young grizzly, old enough to defend itself.", "幼灰熊也，已足自卫。");
            // 乌鸦
            AddTranslation("Crow", "乌鸦");
            // 不祥之鸦，死亡的预兆
            AddTranslation("The ominous crow, an omen of death", "不祥之鸦，死之征也。");
            // 电鳗，会电击目标身旁的造物。
            AddTranslation("The Electric Eel, it will shock the creatures next to its target", "电鳗，将电其所中者之旁物。");
            // 骷髅麋鹿
            AddTranslation("Elk Skeleton", "麋骸");
            // 这么矮？奇怪。
            AddTranslation("A short one? Strange", "短如是乎？怪哉。");
            // 马来蚁
            AddTranslation("Malaysian Ant", "马来蚁");
            // 马来蚁，会为保护巢穴自爆。
            AddTranslation("The Malaysian Ant, it will explode to protect the nest", "马来蚁，将为护巢而自爆。");
            // “笨重” 之鸟
            AddTranslation("'Heavy' Bird", "“重”鸟");
            // 真搞不懂这玩意儿居然还能飞。
            AddTranslation("I'm not sure how that one can still fly", "我不知彼何以尚能飞。");
            // 烹饪时通常要放大量大蒜，但这次我们用一头就够了。
            AddTranslation("In cooking, always use much garlic. But one should be sufficient for our purposes.", "烹鲜恒多用蒜，然于此一头足矣。");
            // 腐烂的大蒜
            AddTranslation("Rotting Garlic", "腐蒜");
            // 巨蛭
            AddTranslation("Giant Leech", "巨蛭");
            // 令人憎恶的害虫，会汲取敌人的生命力。
            AddTranslation("A nasty vermin, it will drain the lifeforce of it's foes", "恶虫也，将吸敌之生气。");
            // 大猩猩
            AddTranslation("Gorilla", "猩猩");
            // 强壮的大猩猩，将会带领你的队伍。
            AddTranslation("The powerful gorilla, it will lead your team", "猩猩强，将率汝伍。");
            // 俯冲鹰
            AddTranslation("Diving Hawk", "俯鹰");
            // 威严的雄鹰，捕猎着它的猎物。
            AddTranslation("The majestic hawk, hunting its prey", "鹰威而俯猎其禽。");
            // 翱翔鹰
            AddTranslation("Soaring Hawk", "翔鹰");
            // 威严的雄鹰，在天空中翱翔。
            AddTranslation("The majestic hawk, soaring in the sky", "鹰威而翔于天。");
            // 刺猬
            AddTranslation("Hedgehog", "猬");
            // 啊，这只聪慧的刺猬，总能迅速逃离危险。
            AddTranslation("Ah, the wise hedgehog. Swift to escape danger.", "猬亦智，避危甚疾。");
            // 凶猛的蜜獾，受到攻击时会变得更强。
            AddTranslation("The ferocious Honey Badger, it will grows stronger when attacked", "蜜獾猛，见攻则益强。");
            // 别小瞧这只食腐者的威力。
            AddTranslation("Don't underestimate the might of this scavenger", "毋轻此食腐者之威。");
            // 螳螂卵
            AddTranslation("Mantis Egg", "螳卵");
            // 假以时日，这枚卵会孵化成一只强悍的螳螂。
            AddTranslation("With time this egg will become a powerful mantis", "假以时日，此卵将成强螳。");
            // 对于一个向他人学唱曲调的家伙来说，这名字再合适不过了。
            AddTranslation("A fitting name, for one who learns its song from others.", "其名甚称，盖学歌于人者也。");
            // 真菌人
            AddTranslation("Myconid", "菌人");
            // 极易被激怒的真菌人，没人摸得透它们的底细。
            AddTranslation("The easily annoyed myconid, not quite sure what they're about", "菌人易怒，莫测其情。");
            // 橡树
            AddTranslation("Oak Tree", "橡");
            // 章鱼
            AddTranslation("Octopus", "章鱼");
            // 老山羊
            AddTranslation("Old Goat", "老羊");
            // 成神的山羊。这头早该被献祭了。
            AddTranslation("The apotheosized Goat. This one is long due for a sacrifice.", "神化之羊，此物久当受祀矣。");
            // 枭熊
            AddTranslation("Owlbear", "枭熊");
            // 凶猛的枭熊，会在敌阵中横冲直撞。
            AddTranslation("The savage Owlbear, it will rampage through its opponents.", "枭熊猛，将横突于敌阵。");
            // 枭猫
            AddTranslation("Owlcat", "枭猫");
            // 半猫半鸮……说到底就是个畸变怪物。
            AddTranslation("Half cat, half owl... an aberation really.", "半猫半枭，诚异孽也。");
            // 枭史莱姆
            AddTranslation("Owlslime", "枭涎");
            // 天啊……这只猫头鹰到底遭遇了什么？
            AddTranslation("Oh no... what happenned to that owl?", "呜呼……彼鸮何遭此乎？");
            // 鸭嘴兽
            AddTranslation("Platypus", "鸭嘴兽");
            // 它就是只鸭嘴兽。它们本来就不怎么动弹。
            AddTranslation("He's a platypus. They don't do much.", "彼特鸭嘴兽耳，本无多为。");
            // 真是令人惋惜的命运。但或许，他还有几分用处。
            AddTranslation("A regrettable fate. But perhaps he may be of some use, yet.", "命可惋也，然或尚可少用。");
            // 山谷浣熊
            AddTranslation("Valley Raccoon", "谷浣熊");
            // 这只阴险狡诈的浣熊，会借力打力，用对手的优势反过来对付他们。
            AddTranslation("The conniving raccoon, it will use the strenghts of his opponent against them", "浣熊狡，将因敌之强而反制之。");
            // 巨角羊
            AddTranslation("Big Horn", "巨角羊");
            // 这头威猛的公羊会扫清挡在你路上的一切障碍。
            AddTranslation("The powerful ram will clear most things standing in your way", "角羊强，凡当汝路者多为之扫除。");
            // 骷髅鼠
            AddTranslation("Rat Skeleton", "鼠骸");
            // 一具老鼠残骸……在资源极度匮乏时，根本没得挑。
            AddTranslation("The remnant of a rat... Can't be picky when you're starving for ressources", "鼠之馀骸耳。资穷而饥时，不得择也。");
            // 红狐狸
            AddTranslation("Red Fox", "赤狐");
            // 红狐狸，是温顺兔子心中的恐惧之源。
            AddTranslation("The red fox, a source of terror to the meek rabbit", "赤狐，柔兔之所畏。");
            // 巨型犀牛，它的冲锋势不可挡。
            AddTranslation("The massive Rhinoceros, nothing will stop its charge", "巨犀之冲，无可止者。");
            // 环尾狐猴
            AddTranslation("Ring-Tailed Lemur", "环尾狐猴");
            // 它就爱扭来扭去。
            AddTranslation("He likes to move it.", "彼乐于动之。");
            // 蜂皇浆
            AddTranslation("Royal Jelly", "王浆");
            // 这罐甜浆既招蚂蚁，也引蜜蜂。
            AddTranslation("This sweet jar attract both ants and bees", "此甘浆之罂，蚁与蜂皆集焉。");
            // 海獭
            AddTranslation("Sea Otter", "海獭");
            // 狡猾的海獭，会潜入水下猎杀水生生物。
            AddTranslation("The cunning sea otter, it will dive to kill submerged creature", "海獭狡，将潜而杀水伏之物。");
            // 蛇鹫
            AddTranslation("Secretary Bird", "蛇鹫");
            // 这只蛇鹫，唯有在不敌对手时才会振翅逃离。
            AddTranslation("This secretary bird, it will only fly away when outmatched", "蛇鹫，不敌乃飞遁。");
            // 绵羊
            AddTranslation("Sheep", "绵羊");
            // 你打算拿一群羊做什么？
            AddTranslation("What do you intend to do with a flock of sheep", "汝将群羊何用？");
            // 蜗牛
            AddTranslation("Snail", "蜗");
            // 一只蜗牛，安稳地待在壳里。
            AddTranslation("A snail, safe in its shell", "蜗居壳中，自保焉。");
            // 镰猛蚁
            AddTranslation("Sniper Ant", "狙蚁");
            // 小小的神射手，远比看上去更危险。
            AddTranslation("A small sharpshooter, more dangerous than it appears", "小射者也，危过其貌。");
            // 顽强的刺蜥，与之对抗的生物必须保持警惕。
            AddTranslation("The resistant thorny devil, creature fighting it should be wary", "棘蜥韧，与之斗者宜慎。");
            // 松露猪
            AddTranslation("Truffle Hog", "松露豕");
            // 一只贪恋隐秘珍馐的美味野兽。
            AddTranslation("A tasty beast obsessed with hidden treasures.", "可食之兽，嗜隐珍馐。");
            // 兀鹫
            AddTranslation("Griffon Vulture", "兀鹫");
            // 兀鹫会以你的尸体为食，但不会在此久留。
            AddTranslation("The Griffon Vulture will feed on your dead but will not stick around", "兀鹫食汝尸，而不久留。");
            // 海象
            AddTranslation("Walrus", "海象");
            // 庞大的海象，是极具领地意识的猛兽。
            AddTranslation("The massive walrus, a very territorial beast", "海象巨，而重其地。");
            // 疣猪
            AddTranslation("Warthog", "疣猪");
            // 白狼
            AddTranslation("White Wolf", "白狼");
            // 极地白狼，血腥味会让狼群变得更强。
            AddTranslation("The arctic white wolf, the smell of blood will strengthen the pack", "极北白狼，血腥之气益其群。");
            // 骷髅狼
            AddTranslation("Wolf Skeleton", "狼骸");
            // 这匹狼即便化作此般形态，依旧凶险如昔。
            AddTranslation("The wolf is as dangerous in this form as it used to be", "狼虽如此形，犹凶如故。");
            // 蚁尸壳
            AddTranslation("Ant Husk", "蚁壳");
            // 一具蚂蚁的空壳，它们的奉献当真永无止境。
            AddTranslation("The husk of an ant, their dedication truly know no bounds", "蚁之壳也，其奉诚无穷。");
            // 筑巢蚁
            AddTranslation("Nest Worker", "巢工蚁");
            // 执着不休的工蚁，守护着自己的巢穴。
            AddTranslation("The unrelenting ant worker, taking care of its nest", "工蚁不息，护其巢。");
            // 真是只可爱的小生灵。
            AddTranslation("Such a cute little critter", "诚可爱之小物。");
            // 幼熊
            AddTranslation("Bear Cub", "熊幼");
            // 假以时日，这幼崽终将成长为一头威猛的巨兽。
            AddTranslation("With time, this young one may grow into a powerful beast.", "假以时日，此幼可成长为巨兽。");
            // 骷髅熊
            AddTranslation("Bear Skeleton", "熊骸");
            // 一种不该存在于世的恐怖生物。
            AddTranslation("A terrible creature that shouldn't allow to be.", "不当有之可怖之物。");
            // 鸣钟卫士
            AddTranslation("Bell Warrior", "铃武者");
            // 一个难缠的小斗士。
            AddTranslation("A tricky little fighter.", "黠小斗者。");
            // 骷髅鸟
            AddTranslation("Bird Skeleton", "鸟骸");
            // 飞鸟残骸，再无翱翔之日。
            AddTranslation("The remnant of a bird, no longer will it fly", "鸟之馀骸，再不能飞。");
            // 骸骨图腾
            AddTranslation("Bone Totem", "骨偶");
            // 一尊敬献死亡与重生的神龛。
            AddTranslation("An idol dedicated to death and rebirth", "奉死与重生之偶。");
            // 水牛
            AddTranslation("Buffalo", "水牛");
            // 这头巨型水牛，登场时会猛冲撞开对手。
            AddTranslation("The massive buffalo, it will tackle its opponent out of the way when played", "巨牛既陈，则冲其敌使辟路。");
            // 卷尾猴
            AddTranslation("Capuchin", "卷尾猴");
            // 敏捷的卷尾猴，会闪避来袭的攻击。
            AddTranslation("The agile capucin, it will avoid incomming attack", "卷尾猴敏，能避来攻。");
            // 腐食蚁
            AddTranslation("Carrion Ant", "腐蚁");
            // 它们会啃得尸体只剩白骨，活物也一样。
            AddTranslation("They'll strip a dead body clean. Or a live one.", "彼将食尸以尽骨，活物亦然。");
            // 腐食蚁群
            AddTranslation("Carrion Swarm", "腐蚁群");
            // 坚韧的螃蟹，坚硬的外壳会减轻它受到的所有伤害。
            AddTranslation("The resilient crab. It’s hard shell will lessen any damage it takes.", "蟹韧，其坚壳损所受诸伤。");
            // 短吻鳄
            AddTranslation("Gator", "短吻鳄");
            // 潜伏在湿地中的最凶险猛兽。
            AddTranslation("The most dangerous beast lurking the wetlands", "伏于湿泽之至凶兽。");
        }

    }


    public class TheBeastBossBattleMod
    {
        public static void RegisterTranslations()
        {
            // 出来吧，被祂的光芒所救赎！
            AddTranslation("Come forth and be saved by his light!", "出而蒙其光之救！");
            // 你背弃了祂的教诲？令人作呕！
            AddTranslation("You forgo his teachings? Disgusting!", "汝弃其诲乎？可恶！");
            // 突然间，天穹裂开，一道白色光柱降临大地，将众娼妓之母劈得粉碎，血湖也随之沸腾翻滚。
            AddTranslation("Suddenly, the sky above cracked open, and a white beam of light reached down into the Earth, smiting the Mother of Harlots asunder and setting the blood lake to a boil.", "倏然天裂，白光下烛于地，击众娼之母为两，而血湖沸焉。");
            // 啊，可怜又无知的异端……你把我们所有人都推向了毁灭！我此刻已经能听见他们降临的声音了……！
            AddTranslation("Ah, poor, ignorant heretic...you have doomed us all! I can hear their arrival at this moment...!", "呜呼，可怜而愚之异端……汝已使我等尽陷于亡！我今已闻其来矣……！");
            // 不,我绝不允许你就这样窃取上帝的力量。要么面对我，要么去死。
            AddTranslation("No. I won't allow you just take God's power like that. Face it or die.", "不。吾必不许汝若是窃上帝之力。面我，否则死。");
            // 你打得很好……但你还需要更多力量……与信仰……才能战胜这场试炼。
            AddTranslation("You fought well... But you will need more strenght... and faith... if you want to overcome the challenge. Goodbye for now.", "汝战善矣……然若欲胜此试，还须更多之力……与信……今且别。");
            // 你准备好忏悔你的罪孽了吗？
            AddTranslation("Are you ready to confess your sins?", "汝备忏其罪乎？");
            // 看吧！天启即将降临！
            AddTranslation("Behold! The apocalypse is imminent!", "视之！末劫将至！");
            // 看来你是真的想让故事以这种方式收场，对吧。好吧。
            AddTranslation("So you really want this story to end this way, don't you. Right then.", "汝果欲此事如是而终乎。然则如汝意。");
            // 大地之腹震颤不止，饥荒随之降临，它是纷争与毁灭的使者。
            AddTranslation("And the belly of the earth quivered, and so came forth Famine, bringer of strife and ruin.", "地腹震而饥荒出，斗毁之使也。");
            // 继而降临的是瘟疫，它是灾病的使者，病痛的亵渎者。
            AddTranslation("And henceforth came Pestilence, bringer of the plagues, desecrator of the ill.", "继而瘟疫至，众疠之使，病者之渎者。");
            // 战争骑士骑乘战马，肆意狂乱地大步前行。他对自己狂躁本性所招致的、无可避免的自我毁灭一无所知，一如那些毫无意义地自相争斗的生灵。
            AddTranslation("War, atop his steed, strode with wild abandon. He knew not the inevitable self-destruction his manic nature brought, just as those who meaninglessly conflict themselves.", "战乘其马，纵而前；彼不知其狂性所致之自灭必然，犹若徒自相争者。");
            // 最终，死亡骑着苍白战马降临。终末之终，救赎与惩戒的使者——亡者的收割者。
            AddTranslation("Finally, upon his pale horse, arrived Death. The ending of endings, the bringer of salvation and damnation - the reaper of the deceased.", "终焉，死乘其苍马而至。终之终也，救与罚之使——收亡者者。");
            // 正如先兆所示，众娼妓之母已然降临，而她的先驱者们早已提前殒灭。
            AddTranslation("And so arrives the Mother of Harlots, as forewarned, and as preceded by the untimely deaths of her harbingers.", "众娼之母遂至，如前所戒，亦继其先驱夭殒之后。");
            // 忏悔
            AddTranslation("Repentance", "悔");
            // 莱西被本次通关的最终BOSS替换。真是亵渎神灵！
            AddTranslation("Leshy is replaced as the final boss of the run. Blasphemy!", "莱西为此局终魁所易。渎神哉！");
            // 地狱打击
            AddTranslation("Hell Strike", "狱击");
            // [creature]仅攻击中间两个位置上的卡牌。若目标牌位置为空，伤害将转移至对手。
            AddTranslation("[creature] will attack only cards in the two middle slots. If a targeted slot is empty, the damage will be redirected to the opponent.", "[creature]惟攻中二位之牌。所指位若空，则伤转及敌。");
            // 钟乳石
            AddTranslation("Stalactites", "钟乳石");
            // 每偶数回合开始时，对手场上随机一张卡牌受到5点伤害；若该效果击杀此卡牌，则在其位置生成一枚钟乳石。
            AddTranslation("At the start of every second turn, a random card on the opponent's side will take 5 damage. If this effect kills that card, a Stalactite is created in its place.", "每二合之始，敌侧偶一牌受伤五；若由此死，则其处生一钟乳石。");
            // 轰炸机
            AddTranslation("Bomber", "轰者");
            // 当此造物激活时，对对手场上随机一张卡牌造成4点伤害；若无目标可选中，则直接对对手造成伤害。
            AddTranslation("When this card becomes active, it will deal 4 damage to a random card on the opponent's side. if there are no cards to target, it will deal damage directly", "此牌既动，则伤敌侧偶一牌四；若无所指，则直伤敌。");
            // 天堂福音
            AddTranslation("Christian Broadcast", "天国福音");
            // 虚伪教条
            AddTranslation("Domga", "伪条");
            // 脂肪
            AddTranslation("fat", "脂");
            // 挺进地牢困难模式
            AddTranslation("enter the gungeon hardmode", "挺进地牢难局");
            // 邪恶冥刻之饥饿
            AddTranslation("starvation from inscryption", "《冥锲》之饥");
            // 萨布斯清仓
            AddTranslation("Sabs Undersale", "萨布斯贱售");
            // 众娼妓之母
            AddTranslation("The Mother of Harlots", "众娼之母");
            // 等等，你到底是怎么让它进化成这样的？
            AddTranslation("wait how did you even get this to evolve", "且，汝竟何以使此进化如是？");
            // 等等，卧槽？？？这野兽不是应该加1点攻击力吗？搞什么啊？？？
            AddTranslation("wait what the fuck??? wasnt beast supposed to gain +1 attack?? what????", "且，何也？？野兽不当但增一威乎？？？");
            // 这跟预想的完全不一样啊。
            AddTranslation("this isnt going as planned", "此非所料也。");
            // 你这蠢货。你以为我会让你提前跳过这场战斗？直面你的罪孽吧，懦夫！
            AddTranslation("You fool. You think I will allow you to skip this battle earlier? Face your sins, you coward!", "愚哉！汝谓我早先会容汝跳此战乎？面汝诸罪罢，懦夫！");
            // 钟乳石
            AddTranslation("Stalactite", "钟乳石");
        }

    }


    public class FiveNightsAtInscryptionMod
    {
        public static void RegisterTranslations()
        {
            // 你没有足够的[c:bB]残响[c:]来召唤该造物。
            AddTranslation("You don't have enough [c:bB]Remnant [c:]to play that creature.", "汝[c:bB]馀响[c:]不足，不得陈此物。");
            // 你以为你能跳过这场战斗吗？
            AddTranslation("You think you can skip this fight?", "汝谓可逾此战乎？");
            // 你以为你能躲开这场战斗？来与我一战，懦夫！
            AddTranslation("You think you can skip this fight? Face Me, you coward!", "汝谓可逾此战乎？懦夫，来面对我！");
            // 你的牌组暂时还不会枯竭……
            AddTranslation("Your Deck won't starve just yet...", "汝牌列姑未至饥……");
            // 欢迎...
            AddTranslation("Welcome...", "欢迎……");
            // 不必担心有人会打扰我们……
            AddTranslation("Don't worry about someone interrupting us...", "毋忧有人扰我等……");
            // 五夜后宫成就
            AddTranslation("Fnai Achievements", "五夜功成录");
            // 重新开始
            AddTranslation("Restart", "复始");
            // 重启游戏并清除游戏内的病毒。
            AddTranslation("Restart the game and get rid of the Virus inside of the Game.", "复启此戏，而去其内之病毒。");
            // 寻阱客的诡计
            AddTranslation("Trapfinder's Trick", "寻阱客之谋");
            // 试图跳过对抗病毒战斗的部分环节。
            AddTranslation("Try to skip Parts of the fight against the Virus.", "试逾御病毒之战之一部。");
            // 夜间诡谲
            AddTranslation("Quirky at night", "夜诡");
            // 目睹玩偶们在夜间变得诡谲怪异。
            AddTranslation("Witness Animatronics getting quirky at night.", "见玩偶夜而诡。");
            // 杀毒软件
            AddTranslation("Antivirus", "杀毒");
            // 击败肆虐游戏的病毒。
            AddTranslation("Defeat The Virus plagueing the Game.", "败肆虐此戏之病毒。");
            // 连接已终止
            AddTranslation("Connection Terminated", "连绝");
            // 将你的整个场地付之一炬。
            AddTranslation("Set your entire side ablaze.", "尽焚汝之一侧。");
            // 异域黄油
            AddTranslation("Exotic Butters", "异黄油");
            // 攒满偷窃电池的上限，并让手持装置发起攻击。
            AddTranslation("Reach the maximum amount of stolen batteries and make Hand unit attack.", "满所窃电池之数，而使手元机攻击。");
            // 可怖之惧
            AddTranslation("The Horror", "可怖");
            // 在费斯熊惊魂餐厅中活下来，抵御与弹簧陷阱的对决。
            AddTranslation("Survive the Fight against Springtrap in Fazbears Fright.", "于费熊惊馆中，抗弹簧陷阱而生。");
            // 寻回之魂
            AddTranslation("Found Soul", "归魂");
            // 将被虚空梦魇偷走的灵魂归还给你。
            AddTranslation("Return the Soul stolen by Glitchtrap to you.", "使为 Glitchtrap 所窃之魂反归于汝。");
            // 噬能水蛭
            AddTranslation("Powerleech", "噬能蛭");
            // 获得你的第一枚失窃电池。
            AddTranslation("Obtain your first Stolen Battery.", "得汝首枚窃电匣。");
            // 经典
            AddTranslation("Classical", "古式");
            // 集齐所有经典玩偶。
            AddTranslation("Obtain all Classic Animatronics.", "尽得诸经典玩偶。");
            // 翻新款
            AddTranslation("Refurbished", "新修");
            // 集齐所有玩具系列玩偶。
            AddTranslation("Obtain all Toy Animatronics.", "尽得诸玩具玩偶。");
            // 集齐所有凋零版玩偶。
            AddTranslation("Obtain all Withered Animatronics.", "尽得诸凋残玩偶。");
            // 集齐所有幻影玩偶。
            AddTranslation("Obtain all Phantom Animatronics.", "尽得诸幻影玩偶。");
            // 梦魇版
            AddTranslation("Nighmarish", "梦魇");
            // 集齐所有梦魇玩偶。
            AddTranslation("Obtain all Nightmare Animatronics.", "尽得诸梦魇玩偶。");
            // 杀戮机器人
            AddTranslation("Killer Robots", "杀机人");
            // 集齐所有欢乐时光玩偶。
            AddTranslation("Obtain all Funtime Animatronics.", "尽得诸欢时玩偶。");
            // 最后的残响
            AddTranslation("The Last Remnants", "末馀响");
            // 集齐所有废弃玩偶。
            AddTranslation("Obtain all Scrap Animatronics.", "尽得诸废玩偶。");
            // 谋杀者的遗泽
            AddTranslation("Murderers Legacy", "杀者遗业");
            // 集齐阿夫顿的所有形态。
            AddTranslation("Obtain all of Aftons forms.", "尽得阿夫顿诸形。");
            // 化身
            AddTranslation("Incarnation", "化身");
            // 当[creature]死亡时，该造物将会变为另一张卡牌，并加入你的手牌。
            AddTranslation("Upon Death, [creature] will transform into another Card and will be added to your Hand.", "既死，[creature]将化为他牌而入汝手。");
            // 易怒天性
            AddTranslation("Anger Issues", "怒性");
            // 当[creature]死亡时，将对所有敌方卡牌造成1点伤害。
            AddTranslation("On Death: [creature] will deal 1 damage to every opposing card.", "既死，[creature]将伤敌侧诸牌各一。");
            // 宝贝
            AddTranslation("Baby", "婴");
            // ...至终皆是败者。
            AddTranslation("...A failure to the end.", "……终其末皆败者。");
            // 芭洛拉
            AddTranslation("Ballora", "芭洛拉");
            // 一位熟悉的造物。她每一次的行动方式都不尽相同。
            AddTranslation("A familiar creation. She will move differently each time.", "熟悉之作也，其行每次各异。");
            // 气球男孩
            AddTranslation("Balloon Boy", "气球童");
            // 彻头彻尾的惹人厌烦之徒，窃取本不属于它的东西。
            AddTranslation("An annoyance to the core, it takes that which it doesn't deserve.", "厌极之徒，窃其所不当得者。");
            // 邦邦
            AddTranslation("Bon Bon", "邦邦");
            // 邦妮特
            AddTranslation("Bonnet", "邦妮特");
            // 邦尼跳
            AddTranslation("Bonnie Jump", "邦尼跃");
            // 消耗1点能量，将[creature]移至己方任意空位。
            AddTranslation("Pay 1 Energy to move [creature] to any free Slot on your side.", "输一能，移[creature]于汝侧任一空位。");
            // 邦尼兔
            AddTranslation("Bonnie the Bunny", "邦尼兔");
            // 费斯熊乐队的吉他手，常被误认成紫色。
            AddTranslation("The guitarist of the Fazbear Band, constantly mistaken to be purple.", "费熊乐队之操琴者，恒为人误以为紫。");
            // 求你了，除掉这头畸形怪物吧。
            AddTranslation("Kill this abomination, please.", "愿杀此异孽。");
            // 迷失之魂
            AddTranslation("Lost Soul", "迷魂");
            // 桶头鲍勃
            AddTranslation("Bucket Bob", "桶鲍勃");
            // 你将他放下后四周毫无动静。片刻之后，脚下有异动悄然浮现，一股能量缓缓渗入你的掌心。
            AddTranslation("You set him down and nothing happens. Then, something stirs beneath your feet. You feel the energy seep into your hands.", "汝置之而寂然无事。俄而足下有物动，一股能渗入汝手。");
            // 回合结束时：[creature]将受到1点伤害。
            AddTranslation("On Turn End: [creature] will take 1 damage.", "合终，[creature]受伤一。");
            // 小鸡奇卡
            AddTranslation("Chica the Chicken", "奇卡鸡");
            // 费斯熊乐队的和声歌手，请注意它并非鸭子。
            AddTranslation("The backup singer of the Fazbear Band, however she is not a duck.", "费熊乐队之和歌者，然非鸭也。");
            // 幽闭之影
            AddTranslation("Closeted", "伏匿");
            // 若[creature]连续2回合未被阻挡，获得2点力量。
            AddTranslation("[creature] will get +2/0 after 2 turns of being unopposed.", "[creature]若二合无对，则威加二。");
            // 幽影魔躯
            AddTranslation("Ghastly Body", "鬼躯");
            // 回合开始时，[creature]将失去1点生命值。
            AddTranslation("Start Of Turn: [creature] will loose 1 Health.", "合始，[creature]失一命。");
            // 残破躯壳
            AddTranslation("Damaged", "残壳");
            // 受到攻击时，[creature]对攻击者造成等额伤害。
            AddTranslation("When struck, [creature] will damage the striker with equal damage.", "见击，[creature]以等伤反之。");
            // 内骨骼 01
            AddTranslation("Endo 01", "内骼01");
            // 一具无外皮的骨架。一具无用且脆弱不堪的躯壳。
            AddTranslation("A suitless skeleton. A useless, easily broken husk.", "无衣之骨架。无用而易碎之壳。");
            // 内骨骼 02
            AddTranslation("Endo 02", "内骼02");
            // 一具无外皮的骨架。一具更为可靠的躯壳。
            AddTranslation("A suitless skeleton. A more reliable husk.", "无衣之骨架。较可信之壳。");
            // 内骨军团
            AddTranslation("Endo Army", "内骼军");
            // 当放置[creature]时，其将在己方所有空位生成自身的复制体。
            AddTranslation("On Play: [creature] will create multiples of itself in every free slot on [creature]'s side.", "[creature]既陈，于己侧诸空位皆生其类。");
            // 虚无残响
            AddTranslation("No Remnant", "无馀响");
            // [creature]死亡时，其不会掉落任何残响。
            AddTranslation("On Death: [creature] will not give any Remnant.", "[creature]既死，不遗馀响。");
            // 残响转换器
            AddTranslation("Remnant Converter", "馀响易器");
            // [creature]将2点能量转化为1点残响。
            AddTranslation("[creature] will convert 2 Energy into 1 Remnant.", "[creature]以二能易一馀响。");
            // 恩纳德
            AddTranslation("Ennard", "恩纳德");
            // 缝合一体，融为独一存在……这话听着甚是耳熟。
            AddTranslation("Stitched together to make one being...that sounds familiar.", "缝合为一……此语甚熟。");
            // 合众聚合
            AddTranslation("Union", "合众");
            // 其他卡牌死亡时，[creature]获得1点生命值。
            AddTranslation("On other Cards Death: [creature] will gain 1 Health.", "他牌死时，[creature]得一命。");
            // 腐兔
            AddTranslation("Malhare", "腐兔");
            // 我总会归来！
            AddTranslation("I always come back!", "我恒归来！");
            // 狐媚之钩
            AddTranslation("Foxys Hook", "霍斯之钩");
            // [creature]会持续移动直至碰到障碍物，沿途攻击每一个敌方格子。
            AddTranslation("[creature] will move until it reaches something, attacking every opposing slot on its way.", "[creature]徙行至有所触，途所对诸位皆攻之。");
            // 海盗霍斯
            AddTranslation("Foxy the Pirate", "海盗霍斯");
            // 一处旁支景点，拥有迅猛的冲刺与极具杀伤力的铁钩。
            AddTranslation("A side attraction, with a fast sprint and a rather deadly hook.", "旁出之一景也，冲疾而钩甚杀。");
            // 小弗莱迪
            AddTranslation("Freddle", "小弗莱迪");
            // 恐惧的造物。一张张尖利牙齿的小巧面容，在黑暗中朝你咧嘴狞笑。
            AddTranslation("A creation of fear. Tiny sharp-toothed faces grin up at you from the dark.", "恐所生之物。细小利齿之面，自暗中向汝狞笑。");
            // 迷你弗莱迪群
            AddTranslation("Freddles", "小弗莱迪群");
            // 放置[creature]时，召唤3只迷你弗莱迪，并将其洗入你的己方牌组。
            AddTranslation("On Play: [creature] will spawn 3 Freddles and shuffles them into your side deck.", "[creature]既陈，生三小弗莱迪，并洗入汝副牌列。");
            // 弗莱迪・费斯贝尔
            AddTranslation("Freddy Fazbear", "弗莱迪・费斯贝尔");
            // 费斯贝尔乐队的冠名主角与领袖。独一无二的弗莱迪・费斯贝尔！
            AddTranslation("The namesake and leader of the Fazbear Band. The one, the only, Freddy Fazbear!", "费斯贝尔乐队之名主与领。独一之弗莱迪・费斯贝尔！");
            // 弗莱迪头套
            AddTranslation("Freddy Mask", "弗莱迪面");
            // 降低所有卡牌1点攻击力，无法对部分电子玩偶生效。
            AddTranslation("Reduces all Cards Attack by 1, cannot be used on some Animatronics.", "降诸牌威一，然数玩偶不可用。");
            // 唔……这头套，能够阻拦部分电子玩偶发起攻击……
            AddTranslation("Hmm... The Mask, it prevents some Animatronics from attacking...", "唔……此面能止数玩偶之攻……");
            // 欢乐时光霍斯
            AddTranslation("Funtime Foxy", "欢时霍斯");
            // 似曾相识的造物。无人能挡其前路。
            AddTranslation("A familiar creation. Nothing can stand in their way.", "熟悉之作。无物能当其前。");
            // 欢乐时光弗莱迪
            AddTranslation("Funtime Freddy", "欢时弗莱迪");
            // 似曾相识的造物。他的搭档邦邦，也会随他一同发起攻击。
            AddTranslation("A familiar creation. His Companion, Bon Bon, also attacks with him.", "熟悉之作。其侣邦邦，亦与之俱攻。");
            // 残响收集者
            AddTranslation("Remnant Collector", "聚馀响者");
            // 放置[creature]时，持牌人获得1点残响。
            AddTranslation("On Play: Gain 1 Remnant.", "既陈，得馀响一。");
            // 黄金弗莱迪
            AddTranslation("Golden Freddy", "金弗莱迪");
            // ……我不太看好这家伙的样子。
            AddTranslation("...I don't like the look of this one.", "……我不喜其状。");
            // 手持终端
            AddTranslation("Hand Unit", "手元机");
            // 我看懂了你想要选择的内容，并将为你自动更正。感谢你选择手持终端。
            AddTranslation("I see what you were trying to choose and I will auto correct it for you. Thank you for choosing Hand Unit.", "我见汝所欲择者，且为汝自正之。谢汝择手元机。");
            // 最后遗愿
            AddTranslation("Last Will", "末愿");
            // [creature]消亡时，给予持牌人2点残响。
            AddTranslation("On Death: [creature] will give you 2 Remnant.", "[creature]既亡，予汝馀响二。");
            // 莱夫蒂
            AddTranslation("Lefty", "莱夫蒂");
            // 一个用以收容某种极其棘手之物的容器。
            AddTranslation("A container for something far more troublesome.", "为容更难制之物者。");
            // 洛比特
            AddTranslation("Lolbit", "洛比特");
            // 系统出现技术故障，请稍候。
            AddTranslation("TECHNICAL DIFFICULTIES. PLEASE STAND BY.", "机术有艰，请姑待。");
            // 曼果冲刺
            AddTranslation("Mangle Strafe", "曼果徙");
            // 持牌人的回合结束时，[creature]会沿印记方向移动，并留下一堆金属丝线，金属丝线具有：0点力量，1点生命，尖刺铠甲。
            AddTranslation("At the end of the Owners turn a [creature] will move in the Sigil Direction and leave behind a pile of Wire(0/1,Sharp Quills).", "持者合终，[creature]循印所指而徙，遗一堆金属丝于后。金属丝者：零威，一命，利棘。");
            // 模仿者
            AddTranslation("Mimic", "摹者");
            // 迷你瑞娜
            AddTranslation("Minireena", "迷你瑞娜");
            // 熔火弗莱迪
            AddTranslation("Molten Freddy", "熔弗莱迪");
            // 一团肆意抽打周遭所有事物的金属丝线聚合体。
            AddTranslation("A mass of wires lashing out at everything in reach.", "诸线聚为一团，鞭击所及诸物。");
            // 万事通先生
            AddTranslation("Mr Can Do", "万事先生");
            // 一具带着空洞笑容的锈蚀铁桶。它平日里并无异动，可若是为其注入足够能量，便会吐出些有用的东西。这过程透着一股……诡异违和感。
            AddTranslation("A rusted can with a vacant smile. It doesn't do much, but if you feed it enough power, it coughs up something useful. The process seems... unnatural.", "锈桶含空笑。平日无为；若饲以足能，则吐可用之物。其状似甚诡。");
            // 抱抱先生
            AddTranslation("Mr Hugs", "抱抱先生");
            // 一台……吸尘器？它缓缓挪动，行经之处留下一股怪异且久久不散的气息。
            AddTranslation("A... Vaccuum? It shuffles along, leaving a strange, lingering presence in its wake", "一……吸尘器乎？其徐徐而行，身后遗一怪气，久而不散。");
            // 梦魇
            AddTranslation("Nightmare", "梦魇");
            // 恐怖之影。它从你心底深藏的恐惧中汲取力量。
            AddTranslation("A shadow of terror. It draws power from the fears you hold close to yourself.", "恐影也，自汝心所藏之惧取力。");
            // 梦魇邦尼
            AddTranslation("Nightmare Bonnie", "梦魇邦尼");
            // 由恐惧孕育的造物。他静立等候，纹丝不动。纵使闭上双眼，你也深知他就在那里。
            AddTranslation("A creation of fear. He waits in silence, unmoving. You know he's there, even when you close your Eyes.", "恐所生之物。彼默立以待，虽闭目，汝亦知其在彼。");
            // 梦魇奇卡
            AddTranslation("Nightmare Chica", "梦魇奇卡");
            // 由恐惧造就的造物。她那空洞大张的嘴本不该张到这般夸张的程度。她发出的声响既不属于人类，也不属于机械——而是全然异样的存在。
            AddTranslation("A creation of fear. Her gaping, hollow maw shouldn't be able to open that wide. The Noise she makes is neither human nor mechanical -it's something else entirely.", "恐所造之物。其虚颔大张，不当至是。其声非人非机，乃别物也。");
            // 梦魇霍斯
            AddTranslation("Nightmare Foxy", "梦魇霍斯");
            // 由恐惧衍生的造物。他潜伏在视野边缘。你漠视他的时间越久，他便愈发逼近。待到发难之时，便再无反应之机。
            AddTranslation("A creation of fear. He lurks just out of sight. The longer you ignore him, the closer he gets. When he strikes, there won't be time to react.", "恐所生之物。潜于所视之外。汝愈忽之，彼愈逼近。及其发难，无以应之。");
            // 梦魇弗雷德熊
            AddTranslation("Nightmare Fredbear", "梦魇弗雷德熊");
            // 由恐惧催生的恐怖造物。它对铃声有着极致的敏感。
            AddTranslation("A creation of terror. It is incredibly sensitive to the sounds of ringing.", "恐所生之怪，对铃声至敏。");
            // 梦魇弗莱迪
            AddTranslation("Nightmare Freddy", "梦魇弗莱迪");
            // 由恐惧而生的造物。他从不孤身一人。他的小家伙们早已在暗处等候着你。
            AddTranslation("A creation of fear. He is never alone. His little ones are already waiting for you.", "恐所生之物。彼未尝独行，其小者已先待汝。");
            // 头号箱
            AddTranslation("No1 Crate", "头号箱");
            // 放置时，木箱微微震颤。内里之物蠢蠢欲动，将力量赋予身旁一切。若付代价，它能做得更多。
            AddTranslation("The crate shudders when placed. Whatever's inside shifts, lending its strength to whatever stands beside it. For a price, it does even more.", "箱既置则微颤。内物移荡，以其力益旁物。若出直，则所能更多。");
            // 锅头斯坦
            AddTranslation("Pan Stan", "锅斯坦");
            // 金属撞击的声响在它崩解后久久回荡。即便已然碎裂，残片依旧散发着某种异样气息。
            AddTranslation("The sound of clanging metal echoes long after he falls apart. Yet, teh pieces still radiate something.", "金铁之声，虽其崩散后犹久回。然其碎片尚吐异气。");
            // 派对赠品
            AddTranslation("Party Favors", "宴赠");
            // 持牌人的回合结束时，[creature]为相邻卡牌回复等同于其攻击力的生命值。
            AddTranslation("On Turn End: [creature] heals cards adjacent to it equal to its Attack.", "持者合终，[creature]疗相邻诸牌，数如其威。");
            // 幻影奇卡
            AddTranslation("Phantom Chica", "幻奇卡");
            // 往昔的残魂虚影。它每次仅能短暂现世，与现世产生片刻交集。
            AddTranslation("A remnant of the past. It can interact with this world for mere moments at a time.", "往日之馀影。每次仅暂现于世而已。");
            // 幻影霍斯
            AddTranslation("Phantom Foxy", "幻霍斯");
            // 往昔残影，利爪依旧致命。却只能驻留片刻光阴。
            AddTranslation("A remnant of the past, its hook is still deadly. But it can only stay for a short time.", "往日之馀影，其钩犹杀，然留世惟顷刻。");
            // 幻影弗莱迪
            AddTranslation("Phantom Freddy", "幻弗莱迪");
            // 往昔的残影，酷爱阅读同人小说。
            AddTranslation("A remnant of the past, loves to read fanfiction.", "往日之馀影，喜读旁传。");
            // 幻影曼果
            AddTranslation("Phantom Mangle", "幻曼果");
            // 往昔的残痕。你能感受到它遗落的能量正不断弥散。
            AddTranslation("A remnant of the past. You can feel the seeping Energy it leaves behind.", "往日之馀影。其遗之能，汝可觉其渗焉。");
            // 幻影傀儡
            AddTranslation("Phantom Puppet", "幻傀儡");
            // 往昔残影，如今已不再超度亡魂。
            AddTranslation("a remnant of the past, it now no longer revives dead souls.", "往日之馀影，今不复起亡魂。");
            // 波波炸弹
            AddTranslation("Pop-Pop", "波波");
            // 对所有卡牌造成 1 点伤害。
            AddTranslation("Deals 1 Damage to all Cards.", "伤诸牌各一。");
            // 嗯……某个游戏里的造物，看起来马上就要爆炸了！
            AddTranslation("Hmm... a Creature from some Game... It looks like it will blow up soon!", "唔……他戏之物乎……观其将爆。");
            // 残魂奔涌
            AddTranslation("Remnant Surge", "馀响涌");
            // 消耗所有能量，每消耗2点能量，[creature]获得1点攻击力，仅存在一回合。
            AddTranslation("[creature] will get +1 Attack for 2 Remnant.", "每二馀响，[creature]威加一。");
            // 傀儡
            AddTranslation("The Puppet", "傀儡");
            // 你听见八音盒悠远的旋律。一股诡秘的气息萦绕不散，它牵动着迷途与被遗忘之人的心弦…… 赠予他们一次重来的机会。
            AddTranslation("You hear the distant melody of a music box. A sprrpwful presence lingers, its strings pulling at the lost and forgotten... offering them one more chance.", "汝闻八音匣之远调。一股幽然之气久留，其丝牵及迷失与见遗者……予之一再试之机。");
            // 傀儡师
            AddTranslation("Puppeter", "傀儡师");
            // 放置[creature]时，抽取邦邦或邦尼特其中一张。
            AddTranslation("On Play: [creature] will draw either Bon Bon or Bonnet.", "既陈，引邦邦或邦妮特之一。");
            // 傀师之偶
            AddTranslation("Puppeteers Puppet", "傀师之偶");
            // 回合结束时，[creature]将与欢乐时光弗莱迪进行登场合体。
            AddTranslation("On Turn End: [creature] will combine with Funtime Freddy On Play.", "合终，[creature]将与欢时弗莱迪合为一体。");
            // 其他卡牌死亡时，[creature]可在友方造物将死之际，将其以弱化形态复活。
            AddTranslation("On Other Card Death: [creature] will ressurect friendly creatures in a weaker state when they perish.", "他牌死时，[creature]能使友物以弱形复起。");
            // 彩虹
            AddTranslation("Rainbow", "彩虹");
            // 退出键
            AddTranslation("Escape key", "退键");
            // [creature]将抽取一张随机卡牌。
            AddTranslation("[creature] will draw a random card.", "[creature]将引一偶牌。");
            // 抽取[creature]时，随机选定一项冲刺能力，作为舞蹈编排的效果。
            AddTranslation("On Drawn: [creature] Chooses a random Strafe Ability as part of the Choreography.", "[creature]既引，则偶择一徙行印技为其舞式之一。");
            // 残响引者
            AddTranslation("Remnant Drawer", "引馀响者");
            // 当[creature]上场时，从你的牌库抽一张牌（拥有2点残响时额外抽一张牌）。
            AddTranslation("On Play: [creature] will draw a card from your Deck (Draw an additional Card for 2 Remnant).", "既陈，自汝牌列引一牌（有二馀响则又引一牌）。");
            // 残响共鸣
            AddTranslation("Remnant Sharer", "馀响同分");
            // [creature]在场时，能让你从自己的卡牌中获得残响。
            AddTranslation("[creature] will allow you to gain Remnant from your own Cards.", "[creature]在局，则汝可自汝之牌得馀响。");
            // 残响辅抽者
            AddTranslation("Remnant Side Drawer", "副引馀响者");
            // 当[creature]消亡时，从你的副牌堆抽一张牌（拥有2点残响时额外抽一张牌）。
            AddTranslation("On Death: [creature] will draw a card from your Side Deck (Draw an additional Card for 2 Remnant).", "[creature]既亡，自汝副牌列引一牌（有二馀响则又引一牌）。");
            // 残响生成器
            AddTranslation("Remnant Spawner", "生馀响者");
            // 当[creature]消亡时，消耗2点残响，将其自身检索入手牌。
            AddTranslation("On Death: [creature] will draw itself in exchange for 2 Remnant.", "[creature]既亡，出二馀响，而反引其身。");
            // 劣质主机
            AddTranslation("Bad Pc", "弊机");
            // 取消对小屋做出的所有改动
            AddTranslation("Disables the changes made to the Cabin", "罢庐中诸变。");
            // 绞碎机
            AddTranslation("Scooper", "绞机");
            // 持牌人的回合结束时，[creature]有1/10的几率直接消灭敌方卡牌。
            AddTranslation("On Turn End: [creature] has a 1/10 chance to instantly kill the opposing Card.", "合终，[creature]有什一之几可立杀所对之牌。");
            // 废弃玩偶
            AddTranslation("Scrap Baby", "废婴");
            // ……一场畸形秀。当心她那只攫取利爪。
            AddTranslation(" ...A freakshow. Mind her grasping claw.", "……异形之戏也。慎其攫爪。");
            // 暗影邦尼
            AddTranslation("Shadow Bonnie", "影邦尼");
            // 暗影弗莱迪
            AddTranslation("Shadow Freddy", "影弗莱迪");
            // 好戏开场
            AddTranslation("Showtime", "开演");
            // 被抽到时，[creature]的能量消耗变为1至6点随机数值。
            AddTranslation("On Drawn: [creature] will have its energy cost randomized from 1 - 6.", "既引，[creature]之能耗偶为一至六。");
            // 灵魂
            AddTranslation("Soul", "魂");
            // 曾为凡人之躯，如今只剩残响与痛苦的傀儡。
            AddTranslation("Once a human being, now only a tool of Remnant and Agony.", "昔为人，今惟馀响与苦痛之具耳。");
            // 野兽冥刻者
            AddTranslation("Scrybe of Beasts", "兽司锲");
            // 死亡冥刻者
            AddTranslation("Scrybe of Death", "死司锲");
            // 魔法冥刻者
            AddTranslation("Scrybe of Magik", "术司锲");
            // 科技冥刻者
            AddTranslation("Scrybe of Technology", "机司锲");
            // 弹簧陷阱
            AddTranslation("Springtrap", "弹簧陷阱");
            // 一名被困在自己造物之中的凶手。
            AddTranslation("A murderer trapped in his own creation.", "一凶徒，自陷其所造者中。");
            // 静电杂音
            AddTranslation("Static", "静噪");
            // [creature]将激怒敌方单位，使其无法发起攻击。
            AddTranslation("[creature] Irritates the Opponent, making it unable to attack.", "[creature]激恼其敌，使不能攻。");
            // 填充物
            AddTranslation("Stuffed", "填物");
            // 戴夫
            AddTranslation("Dave", "戴夫");
            // ……这家伙是怎么来到这里的？
            AddTranslation("... How did this guy get here?", "……此人何以来此？");
            // 燃烧残骸
            AddTranslation("Burning Debris", "焚骸");
            // 费斯熊惊魂屋的燃烧残骸
            AddTranslation("Burning Debris of Fazbears Fright", "费熊惊馆之焚骸");
            // 噬咬事件
            AddTranslation("The Bite", "咬祸");
            // 当[creature]受到伤害时，持牌人获得1点残响。
            AddTranslation("On Take Damage: [creature] will give 1 Remnant.", "[creature]受伤，则予一馀响。");
            // 曼果
            AddTranslation("The Mangle", "曼果");
            // 他总是不断碎裂瓦解，而她却能一次次重塑自身。
            AddTranslation("He constantly falls apart, but she keeps putting herself back together.", "彼恒自解，而她又恒自缀。");
            // 玩具邦尼
            AddTranslation("Toy Bonnie", "玩具邦尼");
            // 这是 “全新升级版” 邦尼。你得先为它充能，才能发挥作用。
            AddTranslation("The 'New and Improved' Bonnie. You'll need to charge it to get any use.", "“新而更良”之邦尼。欲得其用，须先充能。");
            // 玩具奇卡
            AddTranslation("ToyChica", "玩具奇卡");
            // “全新升级版” 奇卡。它拥有过剩的能量。
            AddTranslation("The 'New and Improved' Chica. It has an excess amount of energy.", "“新而更良”之奇卡。其能甚有馀。");
            // 玩具弗莱迪
            AddTranslation("Toy Freddy", "玩具弗莱迪");
            // “全新升级版” 弗莱迪。一个脾气暴躁的硬核玩家。
            AddTranslation("The 'New And Improved' Freddy. A true xXGamerXx with anger issues.", "“新而更良”之弗莱迪。真戏徒也，而性甚躁。");
            // 持牌人的回合结束时，[creature]将敌方卡牌吞噬入自身。
            AddTranslation("On Turn End: [creature] will capture the opposing Card in itself.", "持者合终，[creature]吞所对之牌于其内。");
            // 金属丝线
            AddTranslation("Wire Pile", "金属丝堆");
            // 凋零邦尼
            AddTranslation("Withered Bonnie", "凋邦尼");
            // 邦尼的破损版本。性情乖戾暴躁，出手凶狠且极具破坏力。
            AddTranslation("A broken down version of Bonnie. Erratic, violent, and has a mean punch.", "邦尼之残形。乖戾而暴，其击甚猛。");
            // 凋零奇卡
            AddTranslation("Withered Chica", "凋奇卡");
            // 奇卡的破损形态。外露的电线让它的触碰足以致命，性格也和其他玩偶一样喜怒无常。
            AddTranslation("A broken down version of Chica. Its touch is deadly, due to its exposed wirings. Just as erratic as the others.", "奇卡之残形。其线外露，故触之致命；其性亦如他偶之乖戾。");
            // 凋零霍斯
            AddTranslation("Withered Foxy", "凋霍斯");
            // 霍斯的破损版本。极易动怒，也常常四处游荡。小心它的铁钩，依旧锋利无比。
            AddTranslation("A broken down version of Foxy. Easily angered, but also spends a good amount of its time roaming. Mind its hook, it's still just as sharp.", "霍斯之残形。易怒，然亦多时游行。慎其钩，犹利如故。");
            // 凋零弗莱迪
            AddTranslation("Withered Freddy", "凋弗莱迪");
            // 弗莱迪的破损版本。性情乖戾无常，会攻击任何触碰它的事物。
            AddTranslation(" A broken down version of Freddy. It's erratic, and will attack anything that touches it.", "弗莱迪之残形。乖戾无常，凡触之者皆攻。");
            // 你是第一名
            AddTranslation("You are Number One", "汝为第一");
            // 持牌人的回合结束时，[creature]为左侧卡牌赋予1点力量。额外效果：若持牌人拥有1点残响，同时为右侧卡牌也赋予1点力量。
            AddTranslation("On Turn End: [creature] will give the Card to its left +1/0 (Additionally: If you have 1 Remnant also give the Card to its right +1/0).", "持者合终，[creature]益左牌一威；若主持有一馀响，亦益右牌一威。");
            // 邪恶冥刻：玩具熊的五夜后宫
            AddTranslation("Five Nights at Inscryption", "《冥锲》五夜");
            // 该卡包包含一众玩具熊的五夜后宫主题卡牌，涵盖从弗莱迪费斯熊到弹簧陷阱的各类角色。
            AddTranslation("This card pack contains a bunch of FNAF themed Cards, from Freddy Fazbear to Springtrap.", "此牌韬收诸五夜题牌，自弗莱迪费熊至弹簧陷阱，皆在焉。");
            // 让我们享受这场对决。
            AddTranslation("Let us enjoy this Fight.", "吾等且享此战。");
            // [c:bR]因为这将会是你的最后一战。
            AddTranslation("[c:bR]As it will be your last.", "[c:bR]此乃汝之末战也。");
            // 我明白了……
            AddTranslation("I see...", "余明矣……");
            // 看来你所有的卡牌都开始倒戈相向了！
            AddTranslation("Seems like all your cards are turning against you!", "观汝诸牌，竟皆叛汝！");
            // 这耗时太久了。
            AddTranslation("This is taking too long.", "此拖延过久矣。");
            // 终于，又一个受害者……
            AddTranslation("Finally, another Victim...", "终于，又一禽……");
            // 你真以为我会让你赢得这么轻松？
            AddTranslation("Do you seriously think id let you win that easily?", "汝真以为余当使汝轻得胜乎？");
            // 这绝不会是我……的结局。
            AddTranslation("₮Ⱨł₴ ₩łⱠⱠ ₦Ø₮ ฿Ɇ ⱧØ₩ ł Đł-", "余之……结局……断不当如此……");
            // 好好困在这里享受吧。
            AddTranslation("Have fun being stuck here.", "困于此地，好自娱乐。");
            // 你……究竟做了什么？
            AddTranslation("₩-Ⱨ₳₮ Ⱨ₳-VɆ ɎØɄ ĐØ₦-Ɇ?", "汝……究竟何为？");
            // 你真以为我会放任你这种蠢货通关游戏？
            AddTranslation("Did you really think i'd let a moron like you reach the end of the game?", "汝真以为余当放任如汝此愚货通至戏局之末乎？");
            // 哈哈！很意外吧？
            AddTranslation("Ha ha! Surprised?", "哈哈！意外乎？");
            // 是啊，你真以为我会让你这种蠢货打到游戏结局吗？
            AddTranslation("Yeah, did you really think I'd let a moron like you reach the end of the game?", "是哉，汝真以为余当让如汝此愚货及戏局之末乎？");
            // 哼！
            AddTranslation("Pshaw!", "哼！");
            // 你真是个愚蠢的蠢货。
            AddTranslation("You stupid idiotic moron.", "汝真愚蠢至极。");
            // 现在，失陪一下，我需要几个回合来蓄力我的彩虹加农炮。
            AddTranslation("Now, if you'll excuse me, I need a few turns to charge my rainbow cannon.", "失陪，余需数合以蓄余之虹炮。");
            // 是的。
            AddTranslation("Yeah.", "然也。");
            // 在那之后，游戏就结束了。
            AddTranslation("After that, it'll be game over.", "于此之后，游戏便终。");
            // 那就乖乖等着被狠狠击溃吧！
            AddTranslation("So sit back and prepare to get rekt!", "乃安坐，备受挫！");
            // 你作弊了！
            AddTranslation("You cheated!", "汝行诈！");
