            AddTranslation("Besides, didn't your mommy ever tell you that you can't kill a rainbow?! ", "再者，汝母未尝告汝，虹不可杀乎？！");
            // 下次你在天上看到彩虹，那就是我，要找上门来了……
            AddTranslation("The next time you see a rainbow in the sky that is me, comin' to your houuusssseee.... ", "汝下次于天上见虹，即余也，将临汝门……");
            // 只剩三分钟了，你这个蠢货！
            AddTranslation("Just 3 minutes left, you moron!", "仅余三分，汝此愚货！");
            // 还剩两分钟，我的彩虹加农炮就要准备好了！
            AddTranslation("Just 2 minutes left, then my rainbow cannon will be ready!", "尚余两分，余之虹炮即将就绪！");
            // 还剩一分钟，你这个笨蛋！
            AddTranslation("1 minute left, you stupid idiot!", "尚余一分，汝此蠢货！");
            // 准备迎接彩虹超载！！！！
            AddTranslation("Prepare for rainbow overload!!!!", "备受虹之超载！！！！");
            // 哇哦，我是在嘲笑你，可不是跟你一起笑。
            AddTranslation("Awww, I'm laughing at you, not with you.", "嘻，余是笑汝，非与汝同笑。");
            // 呃，能不能好好玩？
            AddTranslation("Um, learn to play?", "呃，且习如何玩乎？");
            // 哈哈！你太菜了。
            AddTranslation("Ha ha! You suck.", "哈哈！汝太差矣。");
            // 菜鸟！
            AddTranslation("SKRUB!", "菜鸟！");
            // 菜鸟，菜鸟，菜鸟！！
            AddTranslation("Noobie Boobie Noobie!!", "菜鸟，菜鸟，菜鸟！！");
            // 好好练练技术，再来跟我叫板吧。
            AddTranslation("Get some skills and call me in the morning.", "习好技艺，来晨再战。");
            // 愚蠢。
            AddTranslation("Dumba**.", "愚蠢。");
            // 太可悲了，简直滑稽可笑。
            AddTranslation("So sad it's hilarious.", "悲哀至令人发笑。");
            // 哇！ 真是个白痴。
            AddTranslation("Wow! What a moron.", "噫！此真愚货。");
            // 哎呀！小孩子逞强玩游戏的样子也太可爱了吧！
            AddTranslation("Awwww! It's so cute when kids try to play games!", "哎！孩童逞强玩戏，可爱至哉！");
            // 打扰一下，你这是第一次玩电子游戏吗？
            AddTranslation("Excuse me, is this your first time playing a video game?", "打扰，此乃汝初次玩电戏乎？");
            // 你好啊，老朋友
            AddTranslation("Hello Old Sport", "汝好，旧友");
            // 你肯定就是那个新手吧
            AddTranslation("You must be the newbie", "汝必乃那新来者");
            // 我们去掐死一些“小猫”吧
            AddTranslation("Lets strangle some kiddens.", "吾等且去掐些\"小鬼\"罢。");
            // 搭配香肠
            AddTranslation("with sausages", "以香肠");
            // 你觉得在弗莱迪这里过得怎么样？
            AddTranslation("How do you like it here at Freddy's?", "汝于弗雷迪处觉如何？");
            // 我可不会那么做。
            AddTranslation("wouldn't have done that.", "余不会如是为之。");
            // 让我活下去。
            AddTranslation("Keep me alive.", "使余存活。");
            // ...当然。
            AddTranslation("...sure.", "……自是。");
            // 胡说八道！
            AddTranslation("Bullshit!", "妄言！");
            // 我将要...
            AddTranslation("I Will stran...", "余将掐……");
            // 好吧，小家伙，
            AddTranslation("Well kid,", "好，小儿，");
            // 我有一个商业提议。
            AddTranslation("I have a business proposition.", "余有一事相商。");
            // 那是我。
            AddTranslation("It's me.", "乃余也。");
            // 我仍然想要
            AddTranslation("I still want", "余仍欲");
            // 去杀死一些
            AddTranslation("to kill some", "戮些");
            // 小家伙
            AddTranslation("kiddens", "小鬼辈");
            // 别献祭我！
            AddTranslation("Dont sacrifice me!", "莫祀我！");
            // 哦。
            AddTranslation("Ow.", "哦。");
            // 停下！
            AddTranslation("Stop that.", "止！");
            // 哎呦。
            AddTranslation("Ouch.", "哎呦。");
            // 这是...
            AddTranslation("It's...", "乃……");
            // 它...
            AddTranslation("him...", "彼……");
            // 赶紧把他打败就行了
            AddTranslation("Just defeat him already", "速挫之可也");
            // 胸怀大志！
            AddTranslation("Dream big!", "志当高远！");
            // 想个更好的苔藓。
            AddTranslation(" Think of better Moss.", " 思其更佳之苔。");
            // 何等荣幸
            AddTranslation("What an honor", "何其荣也");
            // 祝你好运。
            AddTranslation("Good luck.", "祝汝好运。");
            // 祝你好运...
            AddTranslation("Good luck...", "祝汝好运……");
            // 祝你好运！
            AddTranslation("Good luck!", "祝汝好运！");
            // 祈求好运
            AddTranslation("Fingers crossed", "但祈好运");
            // [c:bR]直到永远。
            AddTranslation("[c:bR]Forever.", "[c:bR]至永远。");
            // 你没有足够的[c:bB]残响[c:]来使用这个能力！
            AddTranslation("You don't have enough [c:bB]Remnant [c:]to use this ability!", "汝[c:bB]馀响[c:]不足，无以用此技！");
            // 你没有足够的[c:bB]能量[c:]来使用这个能力！
            AddTranslation("You don't have enough [c:bB]Energy [c:]to use this ability!", "汝[c:bB]能[c:]不足，无以用此技！");
            // 再美好的事物也无法永恒。
            AddTranslation("Nothing beautiful can last.", "世无永恒之美。");
            // 不！我还没准备好死去。
            AddTranslation("No! I'm not ready to die yet.", "不！余未就死。");
            // 我必须……还要……
            AddTranslation("I must... still...", "余须……仍须……");
            // 和你握手……
            AddTranslation("Shake your hand...", "与汝握手……");
            // 你没有足够的能量。
            AddTranslation("You don't have enough Energy.", "汝能不足。");
            // 你可以为自己制作一张新卡牌。
            AddTranslation("You may make a new Card for yourself.", "汝可为己造一新牌。");
            // 从中选择一个吧。
            AddTranslation("Choose one of these.", "自此中择一。");
            // ……没有？
            AddTranslation("...Nothing?", "……无？");
            // 你想给你的卡牌命名为什么？
            AddTranslation("What would you like to name your Card?", "汝欲为汝之牌命以何名？");
            // 你卡牌的灵魂已被转移
            AddTranslation("Your card's souls have been transfereed", "汝牌之魂已移转");
            // 我允许你交换两张卡牌的灵魂……
            AddTranslation("I will let you swap the souls of 2 cards...", "余允汝易二牌之魂……");
            // 当你伫立在燃烧的建筑中，一个熟悉的身影正在等着你……
            AddTranslation("As you stand in the burning Building, a familiar Figure awaits you...", "当汝立于燃楼之中，一熟悉之形候汝……");
            // [c:bR]他[c:]不会轻易放过你。
            AddTranslation("[c:bR]He [c:]will not let you go that easily.", "[c:bR]彼[c:]不会轻放汝。");
            // 这座建筑此刻崩塌得愈发严重了！
            AddTranslation("The Building appears to fall apart even more now!", "此楼此刻崩颓愈甚！");
            // [c:bR]他[c:]看起来比之前更加愤怒了！
            AddTranslation("[c:bR]He [c:] appears even more angry than before!", "[c:bR]彼[c:]比前更怒！");
            // 有人想见你……
            AddTranslation("Someone wants to see you...", "有人欲见汝……");
            // 能量吞噬者
            AddTranslation("PowerSink", "噬能者");
            // 此印记代表的数值等同于你场上被窃取的电池数量。
            AddTranslation("The value represented with this sigil is equal to the number of stolen Batteries on your side.", "此印所表之数，如汝方被窃电匣之数。");
